// ═══════════════════════════════════════════════════════════════
// SHARED GEOMETRY & MATERIAL CACHE
// ═══════════════════════════════════════════════════════════════
const _boxGeo = new THREE.BoxGeometry(1,1,1);
const _sphereGeo = new THREE.SphereGeometry(0.5, 8, 6);
const _cylGeo = new THREE.CylinderGeometry(0.5, 0.5, 1, 8);
const _coneGeo = new THREE.ConeGeometry(0.5, 1, 8);
const _matCache = {};

function getMat(color, opts) {
  const key = color + (opts ? JSON.stringify(opts) : '');
  if (!_matCache[key]) {
    _matCache[key] = new THREE.MeshLambertMaterial({ color, flatShading: true, ...opts });
  }
  // Keep the cache as a template only. Every mesh gets its own material
  // instance so runtime color/opacity/emissive changes on one object cannot
  // bleed into another object that started with the same color.
  return _matCache[key].clone();
}

function vox(w, h, d, color) {
  const m = new THREE.Mesh(_boxGeo, getMat(color));
  m.scale.set(w, h, d);
  m.castShadow = true;
  m.receiveShadow = true;
  return m;
}

function posVox(x, y, z, w, h, d, color) {
  const m = vox(w, h, d, color);
  m.position.set(x, y, z);
  return m;
}

// Per-item furniture voxel merging: collapse the ~30 static posVox boxes that
// make up each furniture item into 1 mesh per material color. The item stays
// a normal Group (selection / dragging / view-mode logic unchanged) and no
// re-bake is needed on edit. Flip this flag to disable.
const FURNITURE_VOXEL_MERGE = true;

function mergeFurnitureItemVoxels(item) {
  if (!FURNITURE_VOXEL_MERGE || !item?.isObject3D) return item;
  // Items whose child meshes are recolored/animated at runtime keep originals.
  if (item.userData?.arcadeFeedbackParts) return item;
  if (item.userData?.furnitureVoxelsMerged) return item;

  item.updateMatrixWorld(true);
  const itemInv = item.matrixWorld.clone().invert();

  // Only plain static posVox boxes are eligible: shared unit BoxGeometry,
  // untextured Lambert material, no name, empty userData. This now walks
  // descendants so nested static details like desk chairs and keycaps merge
  // too, while named/runtime meshes remain independent.
  const candidates = [];
  item.traverse(child => {
    if (child === item) return;
    if (!child.isMesh || child.geometry !== _boxGeo) return;
    const mat = child.material;
    if (!mat || Array.isArray(mat) || !mat.isMeshLambertMaterial || mat.map) return;
    if (!child.visible || child.name) return;
    if (child.userData && Object.keys(child.userData).length > 0) return;
    candidates.push(child);
  });
  if (candidates.length < 2) return item;

  // Group by material signature so each merged mesh keeps an exact look.
  const groups = new Map();
  for (const mesh of candidates) {
    const mat = mesh.material;
    const key = mat.color.getHex() + '|' + mat.emissive.getHex() + '|' +
      (mat.transparent ? 1 : 0) + '|' + mat.opacity + '|' +
      (mesh.castShadow ? 1 : 0) + (mesh.receiveShadow ? 1 : 0);
    if (!groups.has(key)) groups.set(key, []);
    groups.get(key).push(mesh);
  }

  let mergedAny = false;
  const relMatrix = new THREE.Matrix4();
  for (const meshes of groups.values()) {
    if (meshes.length < 2) continue; // leave singletons untouched
    const positionArrays = [];
    const normalArrays = [];
    let vertexCount = 0;
    for (const mesh of meshes) {
      mesh.updateMatrixWorld(true);
      const geo = mesh.geometry.toNonIndexed();
      geo.deleteAttribute('uv');
      relMatrix.copy(itemInv).multiply(mesh.matrixWorld);
      geo.applyMatrix4(relMatrix); // bake transform relative to furniture root
      positionArrays.push(geo.getAttribute('position').array);
      normalArrays.push(geo.getAttribute('normal').array);
      vertexCount += geo.getAttribute('position').count;
      geo.dispose();
    }
    const posArr = new Float32Array(vertexCount * 3);
    const normArr = new Float32Array(vertexCount * 3);
    let offset = 0;
    for (let i = 0; i < positionArrays.length; i++) {
      posArr.set(positionArrays[i], offset);
      normArr.set(normalArrays[i], offset);
      offset += positionArrays[i].length;
    }
    const geometry = new THREE.BufferGeometry();
    geometry.setAttribute('position', new THREE.BufferAttribute(posArr, 3));
    geometry.setAttribute('normal', new THREE.BufferAttribute(normArr, 3));
    const sample = meshes[0];
    const mergedMesh = new THREE.Mesh(geometry, sample.material);
    mergedMesh.castShadow = sample.castShadow;
    mergedMesh.receiveShadow = sample.receiveShadow;
    mergedMesh.userData.mergedFurnitureVoxels = meshes.length;
    for (const mesh of meshes) mesh.parent?.remove(mesh);
    item.add(mergedMesh);
    mergedAny = true;
  }
  if (mergedAny) item.userData.furnitureVoxelsMerged = true;
  return item;
}

// Optimization 08: merge static world geometry (chunk decorations) into a few
// meshes per material. Safe because decor chunks are fully rebuilt (not
// individually mutated) on any change, physics colliders are independent of
// the visual meshes, and decoration erase works from placedDecorations data,
// not mesh raycasts. Flag allows instant rollback.
const STATIC_DECOR_MERGE = true;

function mergeStaticGroupMeshes(rootGroup) {
  if (!STATIC_DECOR_MERGE || !rootGroup?.isObject3D) return rootGroup;
  rootGroup.updateMatrixWorld(true);
  const rootInv = rootGroup.matrixWorld.clone().invert();

  // Collect plain static meshes: untextured Lambert, unnamed, no userData flags.
  const candidates = [];
  rootGroup.traverse(obj => {
    if (!obj.isMesh || !obj.visible || obj.name) return;
    if (obj.userData && Object.keys(obj.userData).length > 0) return;
    const mat = obj.material;
    if (!mat || Array.isArray(mat) || !mat.isMeshLambertMaterial || mat.map) return;
    candidates.push(obj);
  });
  if (candidates.length < 2) return rootGroup;

  const groups = new Map();
  for (const mesh of candidates) {
    const mat = mesh.material;
    const key = mat.color.getHex() + '|' + mat.emissive.getHex() + '|' +
      (mat.transparent ? 1 : 0) + '|' + mat.opacity + '|' +
      (mesh.castShadow ? 1 : 0) + (mesh.receiveShadow ? 1 : 0);
    if (!groups.has(key)) groups.set(key, []);
    groups.get(key).push(mesh);
  }

  const relMatrix = new THREE.Matrix4();
  for (const meshes of groups.values()) {
    if (meshes.length < 2) continue; // singletons stay as-is
    const positionArrays = [];
    const normalArrays = [];
    let vertexCount = 0;
    for (const mesh of meshes) {
      const geo = mesh.geometry.toNonIndexed();
      if (geo.getAttribute('uv')) geo.deleteAttribute('uv');
      relMatrix.copy(rootInv).multiply(mesh.matrixWorld);
      geo.applyMatrix4(relMatrix); // bake transform relative to chunk group
      positionArrays.push(geo.getAttribute('position').array);
      normalArrays.push(geo.getAttribute('normal').array);
      vertexCount += geo.getAttribute('position').count;
    }
    const posArr = new Float32Array(vertexCount * 3);
    const normArr = new Float32Array(vertexCount * 3);
    let offset = 0;
    for (let i = 0; i < positionArrays.length; i++) {
      posArr.set(positionArrays[i], offset);
      normArr.set(normalArrays[i], offset);
      offset += positionArrays[i].length;
    }
    const geometry = new THREE.BufferGeometry();
    geometry.setAttribute('position', new THREE.BufferAttribute(posArr, 3));
    geometry.setAttribute('normal', new THREE.BufferAttribute(normArr, 3));
    const sample = meshes[0];
    const mergedMesh = new THREE.Mesh(geometry, sample.material);
    mergedMesh.castShadow = sample.castShadow;
    mergedMesh.receiveShadow = sample.receiveShadow;
    mergedMesh.userData.mergedStaticMeshes = meshes.length;
    for (const mesh of meshes) mesh.parent?.remove(mesh);
    rootGroup.add(mergedMesh);
  }
  return rootGroup;
}

function sphere(r, color) {
  const m = new THREE.Mesh(_sphereGeo, getMat(color));
  m.scale.set(r*2, r*2, r*2);
  m.castShadow = true;
  return m;
}

function cyl(r, h, color) {
  const m = new THREE.Mesh(_cylGeo, getMat(color));
  m.scale.set(r*2, h, r*2);
  m.castShadow = true;
  return m;
}

function cone(r, h, color) {
  const m = new THREE.Mesh(_coneGeo, getMat(color));
  m.scale.set(r*2, h, r*2);
  m.castShadow = true;
  return m;
}

