function getAgentIdentityKeys(agent) {
  const keys = new Set();
  if (!agent) return keys;
  [agent.id, agent.statusKey, agent.name].forEach(value => {
    if (value != null && String(value).trim()) keys.add(String(value).trim());
  });
  return keys;
}

function doesDeskAssignmentMatchAgent(agent, assignedTo) {
  if (!agent || assignedTo == null) return false;
  return getAgentIdentityKeys(agent).has(String(assignedTo).trim());
}

function findAgentByAssignmentRef(assignedTo) {
  if (assignedTo == null) return null;
  return agentsList.find(agent => doesDeskAssignmentMatchAgent(agent, assignedTo)) || null;
}

function getDeskFurnitureEntries(building = null) {
  const entries = [];
  const source = building ? [[building.id, building]] : Array.from(buildingsMap.entries());
  for (const [, b] of source) {
    const furniture = b?.interior?.furniture || [];
    furniture.forEach((item, index) => {
      if (item?.type === 'desk') entries.push({ building: b, furniture: item, index });
    });
  }
  return entries;
}

function getAgentAssignedDesk(agent) {
  if (!agent) return null;
  return getDeskFurnitureEntries().find(entry => doesDeskAssignmentMatchAgent(agent, entry.furniture.assignedTo)) || null;
}

function clearAgentWorkSpotForDesk(buildingId, furnitureIndex) {
  agentsList.forEach(agent => {
    const spot = agent?._activeWorkSpot;
    const assigned = getAgentAssignedDesk(agent);
    const matchesActive = spot && spot.buildingId === buildingId && Number(spot.furnitureIndex) === Number(furnitureIndex);
    const matchesAssigned = assigned && assigned.building?.id === buildingId && Number(assigned.index) === Number(furnitureIndex);
    if (!matchesActive && !matchesAssigned) return;
    agent._activeWorkSpot = null;
    agent._deskFacingAngle = null;
    agent._atDesk = false;
    agent._stayTimer = 0;
    agent._wanderTimer = 0;
    if (agent._agentIntent?.object?.actionId === 'work.desk') releaseAgentIntent(agent, 'desk-rotated-refresh', { clearRoute: true, clearLifecycle: false });
  });
}

function clearAgentDeskAssignments(agentRef, exceptBuildingId = null, exceptIndex = null) {
  let changed = false;
  getDeskFurnitureEntries().forEach(entry => {
    if (exceptBuildingId === entry.building.id && exceptIndex === entry.index) return;
    if (!entry.furniture.assignedTo) return;
    const matches = typeof agentRef === 'object'
      ? doesDeskAssignmentMatchAgent(agentRef, entry.furniture.assignedTo)
      : String(entry.furniture.assignedTo).trim() === String(agentRef).trim();
    if (matches) {
      delete entry.furniture.assignedTo;
      persistBuilding(entry.building);
      changed = true;
    }
  });
  return changed;
}

function buildAgentAssignmentsPayload() {
  const payload = {};
  agentsList.forEach(agent => {
    const work = agent._workBuilding?.id || agent.workBuilding || null;
    const home = agent._homeBuilding?.id || agent.homeBuilding || null;
    if (work || home) payload[agent.id] = { work, home };
  });
  return payload;
}

function persistAgentAssignments() {
  if (isLicenseFeatureLocked('advancedEditor')) {
    showLicenseLockedToast('Agent assignments');
    return Promise.resolve({ ok: false, locked: true });
  }
  return fetch('/api/assignments', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(buildAgentAssignmentsPayload()),
  }).catch(() => {});
}

function applyAgentAssignment(agent, workBuildingId, homeBuildingId) {
  if (!agent) return;
  agent.workBuilding = workBuildingId || null;
  agent.homeBuilding = homeBuildingId || null;
  agent._workBuilding = workBuildingId ? (buildingsMap.get(workBuildingId) || null) : null;
  agent._homeBuilding = homeBuildingId ? (buildingsMap.get(homeBuildingId) || null) : null;
  agent._atDesk = false;
  agent._atDoor = false;
  agent._deskFacingAngle = null;
  agent._activeWorkSpot = null;
  agent._wanderTarget = null;
  agent._stayTimer = 0;
  agent._wanderTimer = 0;
}

function pointsMatch2D(a, b, epsilon = 0.01) {
  if (!a || !b) return false;
  return Math.abs(Number(a.x || 0) - Number(b.x || 0)) <= epsilon &&
    Math.abs(Number(a.y || 0) - Number(b.y || 0)) <= epsilon;
}

function pointDistance2D(a, b) {
  if (!a || !b) return Infinity;
  return Math.hypot((Number(a.x) || 0) - (Number(b.x) || 0), (Number(a.y) || 0) - (Number(b.y) || 0));
}

function getMovementInteriorBuildingAt(apiX, apiY) {
  if (!Number.isFinite(apiX) || !Number.isFinite(apiY)) return null;
  for (const building of buildingsMap.values()) {
    if (!building || building.type === 'park') continue;
    if (isPointInsideBuildingInterior(building, apiX, apiY, -0.15)) return building;
  }
  return null;
}

function getMovementParkAt(apiX, apiY) {
  if (!Number.isFinite(apiX) || !Number.isFinite(apiY)) return null;
  const scale = T / API_TILE;
  const worldX = apiX * scale;
  const worldZ = apiY * scale;
  for (const building of buildingsMap.values()) {
    if (!building || building.type !== 'park') continue;
    const bounds = getBuildingFootprintBounds(building, 0);
    if (worldX >= bounds.minX && worldX <= bounds.maxX && worldZ >= bounds.minZ && worldZ <= bounds.maxZ) {
      return building;
    }
  }
  return null;
}

function rotateLocalOffset(dx, dz, rotationDeg = 0) {
  const rad = ((rotationDeg || 0) * Math.PI) / 180;
  const cos = Math.cos(rad);
  const sin = Math.sin(rad);
  // Match Three.js positive Y rotation used by furniture meshes, so action
  // spots/chair seats follow the visible object instead of mirroring it.
  return {
    x: dx * cos + dz * sin,
    z: -dx * sin + dz * cos,
  };
}

function makePlacedObjectStableId(building, item = {}, { collection = 'furniture', index = 0, assetType = null } = {}) {
  const existing = item.objectInstanceId || item.instanceId || item.id;
  if (existing) return String(existing);
  const catalogKey = normalizeObjectCatalogId(assetType || item.catalogId || item.objectCatalogId || item.type) || String(assetType || item.type || 'object').replace(/[^a-zA-Z0-9_-]+/g, '-');
  const prefix = collection === 'outdoor-node' ? 'node' : 'furn';
  const nonce = `${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;
  return `${building?.id || 'building'}:${prefix}:${catalogKey || 'object'}:${Math.max(0, Number(index) || 0)}:${nonce}`;
}

function compactActionLocationTarget(location = {}) {
  const position = location.buildingLocal || location.position || {};
  return Object.freeze({
    spotId: location.id || null,
    interactionSpotId: location.id || null,
    activationSpotId: location.activationSpotId || location.id || null,
    coordinateSpace: 'building-local',
    x: Number.isFinite(position.x) ? position.x : 0,
    z: Number.isFinite(position.z) ? position.z : 0,
    floor: location.floor || 1,
    facing: location.facing || null,
  });
}

function materializeActionLocationsForPlacedObject(building, item, { collection = 'furniture', index = 0, assetType = null } = {}) {
  if (!building || !item || typeof item !== 'object') return false;
  if (isPlacedObjectContextHiddenOrDeleted(item)) {
    const hadTargets = Boolean(item.actionLocations || item.actionLocationIds || item.objectInstanceId);
    delete item.actionLocations;
    delete item.actionLocationIds;
    return hadTargets;
  }
  const stableId = makePlacedObjectStableId(building, item, { collection, index, assetType });
  let changed = false;
  if (item.objectInstanceId !== stableId) { item.objectInstanceId = stableId; changed = true; }
  if (!item.id) { item.id = stableId; changed = true; }
  const local = collection === 'outdoor-node' ? getOutdoorNodeLocalPoint(item, building) : { x: item.x, z: item.z };
  const resolved = resolvePlacedActionLocations({
    item: { ...item, id: stableId, objectInstanceId: stableId, type: assetType || item.type, x: local.x, z: local.z },
    building,
    index,
    registry: ACTION_LOCATION_REGISTRY,
    coordinateSpace: 'building-local',
    includeBuildingRotation: true,
  });
  const locations = (resolved.locations || []).map((location) => {
    const approach = location.approachSpotId
      ? resolved.locations.find(candidate => candidate.id === location.approachSpotId)
      : null;
    return {
      id: location.id,
      actionLocationId: `${stableId}:${location.id}`,
      objectInstanceId: stableId,
      objectCatalogId: resolved.profile?.objectCatalogId || item.objectCatalogId || null,
      catalogId: resolved.assetId || item.catalogId || item.type || null,
      interactionSpotId: location.id,
      activationSpotId: location.activationSpotId || location.id,
      actionId: location.actionId || null,
      roles: Array.isArray(location.roles) ? [...location.roles] : [],
      capacity: location.capacity || null,
      facing: location.facing || null,
      floor: location.floor || 1,
      coordinateSpace: 'building-local',
      offset: location.offset || null,
      buildingLocal: location.buildingLocal || location.position || null,
      world: location.world || null,
      actionTarget: compactActionLocationTarget(approach || location),
      activationTarget: compactActionLocationTarget(location),
      source: location.source || 'ACTION_LOCATION_REGISTRY',
    };
  });
  const previous = JSON.stringify(item.actionLocations || []);
  const next = JSON.stringify(locations);
  if (previous !== next) {
    item.actionLocations = locations;
    item.actionLocationIds = locations.map(location => location.actionLocationId);
    changed = true;
  }
  return changed;
}

function ensurePlacedObjectActionTargets(building, item, options = {}) {
  try {
    return materializeActionLocationsForPlacedObject(building, item, options);
  } catch (error) {
    console.warn('Could not materialize placed object action targets', options, error);
    return false;
  }
}

function ensureBuildingPlacedObjectActionTargets(building) {
  if (!building || typeof building !== 'object') return false;
  let changed = false;
  const furniture = building.interior?.furniture;
  if (Array.isArray(furniture)) {
    furniture.forEach((item, index) => {
      changed = ensurePlacedObjectActionTargets(building, item, { collection: 'furniture', index, assetType: item?.type }) || changed;
    });
  }
  const nodes = building.outdoorArea?.nodes;
  if (Array.isArray(nodes)) {
    nodes.forEach((node, index) => {
      const assetType = getOutdoorNodeAssetType(node) || node?.type || node?.catalogId || node?.objectCatalogId;
      changed = ensurePlacedObjectActionTargets(building, node, { collection: 'outdoor-node', index, assetType }) || changed;
    });
  }
  return changed;
}

function reconcileWorldActionsAfterObjectDeletion(deletedObject = {}, building = null) {
  const objectInstanceId = deletedObject?.objectInstanceId || deletedObject?.instanceId || deletedObject?.id || null;
  const targetLabel = objectInstanceId || `${building?.id || 'building'}:${deletedObject?.type || deletedObject?.catalogId || 'object'}`;
  fetch('/api/world-actions')
    .then(response => response.ok ? response.json() : null)
    .then(data => {
      window.__VWLastDeletedObjectActionLocationCleanup = {
        objectInstanceId,
        targetLabel,
        checkedAt: new Date().toISOString(),
        activeCount: Array.isArray(data?.active) ? data.active.length : null,
        historyCount: Array.isArray(data?.history) ? data.history.length : null,
      };
    })
    .catch(error => {
      window.__VWLastDeletedObjectActionLocationCleanup = { objectInstanceId, targetLabel, error: error?.message || String(error), checkedAt: new Date().toISOString() };
    });
}

function getFurnitureActionSpot(building, furniture, spotId = null) {
  if (!building || !furniture) return null;
  ensurePlacedObjectActionTargets(building, furniture, { collection: 'furniture', index: building?.interior?.furniture?.indexOf?.(furniture) ?? -1 });
  normalizeBuildingFloors(building);
  const spotList = FURNITURE_INTERACTION_SPOTS[furniture.type] || null;
  const spot = spotId && spotList
    ? spotList.find(entry => entry.id === spotId)
    : (spotList?.find(entry => entry.id === 'approach') || spotList?.[0] || ACTION_SPOTS[furniture.type]);
  if (!spot) return null;
  const offset = rotateLocalOffset(spot.dx || 0, spot.dz || 0, furniture.rotation || 0);
  const rawLocalX = furniture.x + offset.x;
  const rawLocalZ = furniture.z + offset.z;
  const margin = 0.35;
  const localX = Math.max(margin, Math.min((building.widthTiles || 25) - margin, rawLocalX));
  const localZ = Math.max(margin, Math.min((building.heightTiles || 17) - margin, rawLocalZ));
  const targetWorld = getBuildingWorldPoint(building, localX, localZ);
  const deskWorld = getBuildingWorldPoint(building, furniture.x, furniture.z);
  const apiX = targetWorld.x * API_TILE;
  const apiZ = targetWorld.z * API_TILE;
  const deskApiX = deskWorld.x * API_TILE;
  const deskApiZ = deskWorld.z * API_TILE;
  const screenFacingAngle = furniture.type === 'desk'
    ? getFurnitureForwardFacingAngle(building, furniture, { localX, localZ }, 'south')
    : null;
  return {
    building,
    furniture,
    spotId: spot.id || 'default',
    action: spot.action || null,
    facing: spot.facing || null,
    floor: getFurnitureFloor(furniture),
    localX,
    localZ,
    apiX,
    apiZ,
    deskApiX,
    deskApiZ,
    faceAngle: screenFacingAngle ?? Math.atan2(deskApiX - apiX, deskApiZ - apiZ),
    clampedFrom: (Math.abs(rawLocalX - localX) > 0.001 || Math.abs(rawLocalZ - localZ) > 0.001) ? { localX: rawLocalX, localZ: rawLocalZ } : null,
  };
}

function getFurnitureActionSpotAtDebugPoint(building, furniture, spotId = null) {
  if (!building || !furniture) return null;
  ensurePlacedObjectActionTargets(building, furniture, { collection: 'furniture', index: building?.interior?.furniture?.indexOf?.(furniture) ?? -1 });
  normalizeBuildingFloors(building);
  const spotList = FURNITURE_INTERACTION_SPOTS[furniture.type] || null;
  const spot = spotId && spotList
    ? spotList.find(entry => entry.id === spotId)
    : (spotList?.find(entry => entry.id === 'approach') || spotList?.[0] || ACTION_SPOTS[furniture.type]);
  if (!spot) return null;
  const local = getActionDebugSpotLocal(furniture, spot);
  const targetWorld = getBuildingWorldPoint(building, local.x, local.z);
  const objectWorld = getBuildingWorldPoint(building, furniture.x, furniture.z);
  const apiX = targetWorld.x * API_TILE;
  const apiZ = targetWorld.z * API_TILE;
  const deskApiX = objectWorld.x * API_TILE;
  const deskApiZ = objectWorld.z * API_TILE;
  return {
    building,
    furniture,
    spotId: spot.id || 'default',
    action: spot.action || null,
    facing: spot.facing || null,
    floor: getFurnitureFloor(furniture),
    localX: local.x,
    localZ: local.z,
    apiX,
    apiZ,
    deskApiX,
    deskApiZ,
    faceAngle: Math.atan2(deskApiX - apiX, deskApiZ - apiZ),
    clampedFrom: null,
    matchesDebugPoint: true,
  };
}

function getFurnitureForwardFacingAngle(building, furniture, spot = null, facing = 'north') {
  if (!building || !furniture) return null;
  const baseLocalX = Number.isFinite(spot?.localX) ? spot.localX : (Number(furniture.x) || 0);
  const baseLocalZ = Number.isFinite(spot?.localZ) ? spot.localZ : (Number(furniture.z) || 0);
  const key = String(facing || spot?.facing || 'north').toLowerCase();
  const localFacing = key === 'south' ? { x: 0, z: -1 }
    : key === 'east' ? { x: 1, z: 0 }
    : key === 'west' ? { x: -1, z: 0 }
    : { x: 0, z: 1 };
  const rotatedFacing = rotateLocalOffset(localFacing.x, localFacing.z, furniture.rotation || 0);
  const from = getBuildingWorldPoint(building, baseLocalX, baseLocalZ);
  const to = getBuildingWorldPoint(building, baseLocalX + rotatedFacing.x, baseLocalZ + rotatedFacing.z);
  return Math.atan2((to.x - from.x) * API_TILE, (to.z - from.z) * API_TILE);
}

const DEFAULT_OBJECT_QUEUE_SPACING_TILES = 0.8;

function isQueueActionDebugSpot(spot = {}) {
  const roles = Array.isArray(spot.roles) ? spot.roles.map(role => String(role || '').toLowerCase()) : [];
  const id = String(spot.id || spot.spotId || '').toLowerCase();
  const capacityKind = String(spot.capacityKind || spot.kind || spot.capacity?.kind || '').toLowerCase();
  return capacityKind === 'queue' || roles.some(role => ['queue', 'wait', 'wait-turn', 'approach', 'clearance'].includes(role)) || id.includes('queue') || id.includes('wait');
}

function isExplicitObjectServiceQueueEnabled(value) {
  if (value === true) return true;
  return ['queue', 'service-queue', 'required-queue', 'first-come-first-served'].includes(String(value || '').toLowerCase());
}

function isExplicitObjectServiceQueueDisabled(value) {
  if (value === false) return true;
  return ['optional', 'skip-if-occupied', 'exclusive-skip', 'none', 'off', 'disabled'].includes(String(value || '').toLowerCase());
}

function getAuthoredObjectQueueLocations(queueDef = {}, furniture = {}) {
  queueDef = queueDef || {};
  furniture = furniture || {};
  const queueConfig = queueDef.queueConfig || furniture.queueConfig || furniture.serviceQueue || null;
  const raw = Array.isArray(queueDef.queueLocations) ? queueDef.queueLocations
    : Array.isArray(queueDef.queuePositions) ? queueDef.queuePositions
    : Array.isArray(queueDef.queuePoints) ? queueDef.queuePoints
    : Array.isArray(queueConfig?.locations) ? queueConfig.locations
    : Array.isArray(queueConfig?.positions) ? queueConfig.positions
    : Array.isArray(queueConfig?.points) ? queueConfig.points
    : Array.isArray(furniture.queueLocations) ? furniture.queueLocations
    : Array.isArray(furniture.queuePositions) ? furniture.queuePositions
    : Array.isArray(furniture.queuePoints) ? furniture.queuePoints
    : [];
  return raw.map((spot, index) => ({
    ...spot,
    id: spot.id || spot.spotId || spot.slotId || `${queueDef.id || queueDef.spotId || 'queue'}:${index}`,
    spotId: spot.spotId || spot.id || spot.slotId || `${queueDef.id || queueDef.spotId || 'queue'}:${index}`,
    slotId: spot.slotId || spot.spotId || spot.id || `${queueDef.id || queueDef.spotId || 'queue'}:${index}`,
    queueIndex: Math.max(0, Math.floor(Number(spot.queueIndex ?? spot.index ?? index) || 0)),
  })).sort((a, b) => a.queueIndex - b.queueIndex || String(a.id || '').localeCompare(String(b.id || '')));
}

function serviceQueueSpotOptIn(spot = {}, furniture = {}) {
  const explicit = furniture?.queuePolicy ?? furniture?.usePolicy ?? furniture?.occupancyPolicy ?? furniture?.servicePolicy ?? furniture?.queueAddon;
  if (isExplicitObjectServiceQueueDisabled(explicit) || furniture?.queue === false || furniture?.serviceQueue === false) return false;
  if (isExplicitObjectServiceQueueEnabled(explicit) || furniture?.queue === true || furniture?.serviceQueue === true || furniture?.queueConfig) return isQueueActionDebugSpot(spot);
  return Boolean(spot.serviceQueue === true || spot.queueAddon === true || isExplicitObjectServiceQueueEnabled(spot.queuePolicy) || getAuthoredObjectQueueLocations(spot, furniture).length);
}

function getScriptedServiceQueueDefinitionsForFurniture(furniture = {}) {
  if (!furniture) return [];
  const spots = FURNITURE_INTERACTION_SPOTS[furniture?.type] || [];
  const configured = spots.filter(spot => isQueueActionDebugSpot(spot) && serviceQueueSpotOptIn(spot, furniture));
  if (configured.length) return configured;
  const explicit = furniture?.queuePolicy ?? furniture?.usePolicy ?? furniture?.occupancyPolicy ?? furniture?.servicePolicy ?? furniture?.queueAddon;
  const authoredQueueLocations = getAuthoredObjectQueueLocations({ id: 'queue', spotId: 'queue' }, furniture);
  if ((isExplicitObjectServiceQueueEnabled(explicit) || furniture?.queue === true || furniture?.serviceQueue === true || furniture?.queueConfig) && authoredQueueLocations.length) {
    return [{ id: 'queue', spotId: 'queue', dx: 0, dz: DEFAULT_OBJECT_QUEUE_SPACING_TILES, action: 'planning.schedule', roles: ['queue'], capacityKind: 'queue', serviceQueue: true, queueLocations: authoredQueueLocations }];
  }
  return [];
}

function resolveFurnitureSpotApiPoint(building, furniture, spot = {}) {
  if (!building || !furniture || !spot) return null;
  normalizeBuildingFloors(building);
  const offset = rotateLocalOffset(Number(spot.dx ?? spot.x ?? spot.offset?.x ?? 0), Number(spot.dz ?? spot.z ?? spot.y ?? spot.offset?.z ?? 0), furniture.rotation || 0);
  const rawLocalX = Number(furniture.x || 0) + offset.x;
  const rawLocalZ = Number(furniture.z || 0) + offset.z;
  const margin = 0.35;
  const localX = Math.max(margin, Math.min((building.widthTiles || 25) - margin, rawLocalX));
  const localZ = Math.max(margin, Math.min((building.heightTiles || 17) - margin, rawLocalZ));
  const world = getBuildingWorldPoint(building, localX, localZ);
  return { localX, localZ, apiX: world.x * API_TILE, apiZ: world.z * API_TILE, floor: getFurnitureFloor(furniture) };
}

function getActionDebugSpotColor(spot = {}, generatedQueue = false) {
  if (generatedQueue) return 0xff1744;
  if (isQueueActionDebugSpot(spot)) return 0xffa000;
  const roles = Array.isArray(spot.roles) ? spot.roles.map(role => String(role || '').toLowerCase()) : [];
  if (roles.some(role => ['seat', 'sit', 'social', 'talk', 'gather'].includes(role))) return 0x2979ff;
  return 0x00e676;
}

function getActionDebugSpotLocal(item = {}, spot = {}) {
  const offset = rotateLocalOffset(
    Number(spot.dx ?? spot.offset?.x ?? spot.x ?? 0),
    Number(spot.dz ?? spot.offset?.z ?? spot.z ?? spot.y ?? 0),
    Number(item.rotation || 0)
  );
  return {
    x: Number(item.x || 0) + offset.x,
    z: Number(item.z || 0) + offset.z,
  };
}

function getPrimaryActionDebugSpot(spots = [], queueSpot = null) {
  const scored = spots
    .filter(spot => spot && spot !== queueSpot && !isQueueActionDebugSpot(spot))
    .map(spot => {
      const roles = Array.isArray(spot.roles) ? spot.roles.map(role => String(role || '').toLowerCase()) : [];
      const id = String(spot.id || spot.spotId || '').toLowerCase();
      let score = 0;
      for (const role of roles) {
        if (['use', 'standing-use', 'active-use', 'retrieve', 'order', 'checkout', 'customer', 'service'].includes(role)) score += 8;
        if (['seat', 'social', 'talk', 'gather'].includes(role)) score += 3;
      }
      for (const token of ['use', 'front', 'customer', 'order', 'retrieve', 'active']) {
        if (id.includes(token)) score += 2;
      }
      return { spot, score };
    })
    .sort((a, b) => b.score - a.score);
  return scored[0]?.spot || spots.find(spot => spot && spot !== queueSpot) || null;
}

function makeActionDebugLabelSprite(label) {
  const text = String(label || '').trim() || 'spot';
  const canvas = document.createElement('canvas');
  canvas.width = 1024;
  canvas.height = 128;
  const ctx = canvas.getContext('2d');
  const maxTextWidth = canvas.width - 56;
  let fontSize = 38;
  do {
    ctx.font = `bold ${fontSize}px "Press Start 2P", monospace`;
    if (ctx.measureText(text).width <= maxTextWidth || fontSize <= 24) break;
    fontSize -= 2;
  } while (fontSize > 24);

  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  ctx.strokeStyle = '#000';
  ctx.lineJoin = 'round';
  ctx.lineWidth = Math.max(8, Math.round(fontSize * 0.22));
  ctx.strokeText(text, canvas.width / 2, canvas.height / 2);
  ctx.fillStyle = '#ffd600';
  ctx.fillText(text, canvas.width / 2, canvas.height / 2);

  const texture = new THREE.CanvasTexture(canvas);
  texture.needsUpdate = true;
  const material = new THREE.SpriteMaterial({
    map: texture,
    transparent: true,
    depthTest: false,
    depthWrite: false,
  });
  const sprite = new THREE.Sprite(material);
  sprite.userData.actionDebugLabel = true;
  sprite.userData.actionDebugLabelText = text;
  sprite.userData.actionDebugLabelScale = {
    width: Math.max(2.0, Math.min(4.4, 1.35 + text.length * 0.18)),
    height: 0.52,
  };
  return sprite;
}

function addActionDebugMarker(parent, { x, z, y = 0.28, label, color = 0x00e676, radius = 0.18, generatedQueue = false, opacity = null } = {}) {
  if (!parent || !Number.isFinite(Number(x)) || !Number.isFinite(Number(z))) return null;
  const group = new THREE.Group();
  group.name = `objectActionPointMarker_${label || 'spot'}`;
  group.position.set(Number(x) * T, y, Number(z) * T);
  const ringGeo = new THREE.RingGeometry(radius * 0.62, radius, 24);
  const ringMat = new THREE.MeshBasicMaterial({
    color,
    transparent: true,
    opacity: Number.isFinite(Number(opacity)) ? Math.max(0.1, Math.min(1, Number(opacity))) : (generatedQueue ? 0.96 : 0.82),
    side: THREE.DoubleSide,
    depthTest: false,
    depthWrite: false,
  });
  const ring = new THREE.Mesh(ringGeo, ringMat);
  ring.rotation.x = -Math.PI / 2;
  ring.renderOrder = 1008;
  group.add(ring);

  const center = sphere(generatedQueue ? 0.055 : 0.04, color);
  center.position.y = 0.025;
  center.material.depthTest = false;
  center.material.depthWrite = false;
  center.renderOrder = 1009;
  group.add(center);

  if (label) {
    const text = makeActionDebugLabelSprite(label);
    const labelScale = text.userData.actionDebugLabelScale || { width: 1.45, height: 0.36 };
    text.position.set(0, generatedQueue ? 0.62 : 0.66, 0);
    text.scale.set(
      generatedQueue ? Math.max(1.1, labelScale.width * 0.72) : labelScale.width,
      generatedQueue ? Math.max(0.34, labelScale.height * 0.72) : labelScale.height,
      1,
    );
    text.renderOrder = 1010;
    if (text.material) {
      text.material.depthTest = false;
      text.material.depthWrite = false;
    }
    group.add(text);
  }
  parent.add(group);
  return group;
}

function getLiveScriptedServiceQueueReservationsForDebug(item = {}) {
  const store = item?._scriptedServiceQueueStore || null;
  if (!store || !Array.isArray(store.reservations)) return [];
  return normalizeScriptedServiceQueueReservations(store);
}

function getActiveServiceQueueDebugPointCount(item = {}, queueSpot = null) {
  if (!isScriptedServiceQueueFurniture(item)) return null;
  if (!isScriptedServiceObjectUnavailableForQueue(item)) return 0;
  const queueLength = getLiveScriptedServiceQueueReservationsForDebug(item).length;
  const maxPoints = getScriptedServiceQueueMaxPoints(item, queueSpot?.id || queueSpot?.spotId || 'queue');
  return Math.max(0, Math.min(maxPoints, queueLength + 1));
}

function addGeneratedQueueDebugMarkers(parent, item = {}, spots = [], queueSpot = null, floorY = 0, options = {}) {
  if (!parent || !item || !queueSpot) return;
  const primarySpot = getPrimaryActionDebugSpot(spots, queueSpot);
  if (!primarySpot) return;
  const primaryLocal = getActionDebugSpotLocal(item, primarySpot);
  const queueLocal = getActionDebugSpotLocal(item, queueSpot);
  const dx = queueLocal.x - primaryLocal.x;
  const dz = queueLocal.z - primaryLocal.z;
  const len = Math.hypot(dx, dz) || 1;
  const lineX = dx / len;
  const lineZ = dz / len;
  const capacity = typeof queueSpot.capacity === 'number' ? queueSpot.capacity : Number(queueSpot.capacity?.maxAgents || 0);
  const authoredQueueLocations = getAuthoredObjectQueueLocations(queueSpot, item);
  const maxPoints = Math.max(1, Math.floor(Number((queueSpot.queueMaxPoints ?? queueSpot.maxQueuePoints ?? queueSpot.queueCapacity ?? capacity) || authoredQueueLocations.length || 3)));
  const activePointCount = Number.isFinite(Number(options.activePointCount)) ? Math.max(0, Math.min(maxPoints, Math.floor(Number(options.activePointCount)))) : maxPoints;
  const visiblePointCount = options.showInactivePoints === true ? maxPoints : activePointCount;
  if (visiblePointCount <= 0) return;
  const spacing = Number(queueSpot.queueSpacingTiles ?? queueSpot.spacingTiles ?? DEFAULT_OBJECT_QUEUE_SPACING_TILES) || DEFAULT_OBJECT_QUEUE_SPACING_TILES;
  if (authoredQueueLocations.length) {
    for (let index = 0; index < visiblePointCount; index++) {
      const authored = authoredQueueLocations[index];
      if (!authored) break;
      const local = getActionDebugSpotLocal(item, authored);
      const active = index < activePointCount;
      addActionDebugMarker(parent, {
        x: local.x,
        z: local.z,
        y: floorY + 0.075 + index * 0.006,
        label: String(authored.label || authored.queueLabel || index + 1),
        color: active ? 0xff1744 : 0x9aa0a6,
        radius: active ? 0.2 : 0.16,
        generatedQueue: true,
        opacity: active ? 0.96 : 0.38,
      });
    }
    return;
  }
  for (let index = 0; index < visiblePointCount; index++) {
    const active = index < activePointCount;
    addActionDebugMarker(parent, {
      x: primaryLocal.x + lineX * spacing * (index + 1),
      z: primaryLocal.z + lineZ * spacing * (index + 1),
      y: floorY + 0.075 + index * 0.006,
      label: String(index + 1),
      color: active ? 0xff1744 : 0x9aa0a6,
      radius: active ? 0.2 : 0.16,
      generatedQueue: true,
      opacity: active ? 0.96 : 0.38,
    });
  }
}

function addObjectActionPointDebugOverlays(group, building) {
  if (!group || !building) return null;
  const previous = group.getObjectByName('objectActionPointDebugOverlay');
  if (previous) group.remove(previous);
  if (!_objectActionPointDebugEnabled) return null;
  const overlay = new THREE.Group();
  overlay.name = 'objectActionPointDebugOverlay';
  overlay.visible = true;
  normalizeBuildingFloors(building);

  const furniture = building.interior?.furniture || [];
  for (const item of furniture) {
    if (!item || !FURNITURE_INTERACTION_SPOTS[item.type]?.length) continue;
    const floor = getFurnitureFloor(item);
    if (isBuildingFloorFocusActive(building) && floor !== getActiveBuildingFloor(building)) continue;
    const floorY = getInteriorFloorSurfaceY(building, floor);
    const spots = FURNITURE_INTERACTION_SPOTS[item.type] || [];
    const serviceQueueFurniture = isScriptedServiceQueueFurniture(item);
    for (const spot of spots) {
      const local = getActionDebugSpotLocal(item, spot);
      const queueLike = isQueueActionDebugSpot(spot);
      const serviceQueueSpot = serviceQueueFurniture && serviceQueueSpotOptIn(spot, item);
      if (queueLike && serviceQueueSpot) {
        addGeneratedQueueDebugMarkers(overlay, item, spots, spot, floorY, {
          activePointCount: getActiveServiceQueueDebugPointCount(item, spot),
          showInactivePoints: true,
        });
        continue;
      }
      addActionDebugMarker(overlay, {
        x: local.x,
        z: local.z,
        y: floorY + 0.055,
        label: spot.id || spot.spotId || spot.action || 'spot',
        color: getActionDebugSpotColor(spot),
        radius: queueLike ? 0.16 : 0.13,
      });
      if (queueLike) addGeneratedQueueDebugMarkers(overlay, item, spots, spot, floorY);
    }
  }

  const nodes = getNormalizedOutdoorAreaNodes(building).nodes || [];
  for (const node of nodes) {
    const type = getOutdoorNodeAssetType(node);
    const spots = FURNITURE_INTERACTION_SPOTS[type] || [];
    if (!spots.length) continue;
    const local = getOutdoorNodeLocalPoint(node, building);
    const item = { ...node, type, x: local.x, z: local.z, rotation: node.rotation || 0 };
    const floorY = PARK_GRASS_SURFACE_Y + 0.04;
    for (const spot of spots) {
      const spotLocal = getActionDebugSpotLocal(item, spot);
      const queueLike = isQueueActionDebugSpot(spot);
      addActionDebugMarker(overlay, {
        x: spotLocal.x,
        z: spotLocal.z,
        y: floorY + 0.055,
        label: spot.id || spot.spotId || 'spot',
        color: getActionDebugSpotColor(spot),
        radius: queueLike ? 0.16 : 0.13,
      });
      if (queueLike) addGeneratedQueueDebugMarkers(overlay, item, spots, spot, floorY);
    }
  }

  group.add(overlay);
  return overlay;
}

