        slotId: isSeat ? 'swing-seat-1' : def.slotId,
        activationSpotId: isSeat ? 'seat-use' : def.activationSpotId,
        approachSpotId: isSeat ? 'approach-front' : def.approachSpotId,
        actionId: actionId || def.action,
