        approachRadius: Math.max(3, Number(def.approachRadius || 3) * API_TILE),
        activationRadius: Math.max(9, Number(def.activationRadius || 9) * API_TILE),
        snapRadius: Math.max(9, Number(def.snapRadius || 9) * API_TILE),
