  const actionId = idleActivity.actionId || idleActivity.action || (isWaitTurn ? 'life.waitTurnAtPlaygroundSwing' : 'life.swingOnPlaygroundSwing');
  const slotId = idleActivity.activeUseSlotId || idleActivity.slotId || 'swing-seat-1';
  const candidate = !isWaitTurn ? getPlaygroundSwingActiveUseCandidate(building, swing, idleActivity.outdoorNodeId ?? idleActivity.furnitureIndex, actionId) : null;
