const WORK_DESK_DOCK_SNAP_RADIUS = Math.max(18, API_TILE * 0.75);
const WORK_DESK_IDLE_SEATED_RADIUS = Math.max(22, API_TILE * 0.85);
const POST_DRINK_DESK_RELEASE_MS = 12000;

function getMonotonicNowMs() {
  return (typeof performance !== 'undefined' && typeof performance.now === 'function') ? performance.now() : Date.now();
}

function isPostDrinkDeskReleaseActive(agent) {
  const until = Number(agent?._postDrinkDeskReleaseUntil || 0);
  if (!agent || until <= 0) return false;
  if (until <= getMonotonicNowMs()) {
    agent._postDrinkDeskReleaseUntil = 0;
    agent._postDrinkDeskReleaseKind = null;
    return false;
  }
  return true;
}

function releaseAgentFromDrinkDeskConsume(agent, drinkKind = 'drink') {
  if (!agent) return false;
  agent._postDrinkDeskReleaseUntil = getMonotonicNowMs() + POST_DRINK_DESK_RELEASE_MS;
  agent._postDrinkDeskReleaseKind = drinkKind;
  agent._atDesk = false;
  agent._activeWorkSpot = null;
  agent._isReturningToDesk = false;
  agent._forceIdleDeskReturn = false;
  agent._deskIdleHoldUntil = null;
  agent._stayTimer = 0;
  agent._wanderTarget = null;
  agent._waypointPath = null;
  agent._waypointPathTarget = null;
  agent._waypointPathIdx = 0;
  agent._doorTransition = null;
  clearDynamicInteriorRoutingForAgent(agent.id);
  clearDynamicExteriorRoutingForAgent(agent.id);
  return true;
}

function getAgentWorkTarget(agent) {
  if (!agent) return null;

  const assignedDesk = getAgentAssignedDesk(agent);
  if (assignedDesk) {
    const spot = getFurnitureActionSpot(assignedDesk.building, assignedDesk.furniture);
    if (spot) return { ...spot, kind: 'desk-assigned', furnitureIndex: assignedDesk.index, buildingId: assignedDesk.building.id };
  }

  const workBuilding = agent._workBuilding || (agent.workBuilding ? buildingsMap.get(agent.workBuilding) : null);
  if (!workBuilding) return null;

  const openDesks = getDeskFurnitureEntries(workBuilding).filter(entry => !entry.furniture.assignedTo);
  if (openDesks.length > 0) {
    const unassignedWorkers = agentsList.filter(other => {
      const otherDesk = getAgentAssignedDesk(other);
      const otherWorkBuilding = otherDesk?.building || other._workBuilding || (other.workBuilding ? buildingsMap.get(other.workBuilding) : null);
      return otherWorkBuilding?.id === workBuilding.id && !otherDesk;
    });
    const fallbackIndex = Math.max(0, unassignedWorkers.findIndex(other => other.id === agent.id));
    const deskEntry = openDesks[fallbackIndex % openDesks.length];
    const spot = getFurnitureActionSpot(deskEntry.building, deskEntry.furniture);
    if (spot) return { ...spot, kind: 'desk-open', furnitureIndex: deskEntry.index, buildingId: deskEntry.building.id };
  }

  // Do not fabricate legacy fallback work coordinates.
  // Working animation/movement should only attach to real desk work spots.
  return null;
}

function getBuildingInteriorWorkArrivalTarget(building) {
  if (!building || building.type === 'park') return null;
  return getBuildingInteriorAnchorTarget(building, {
    preferredTypes: ['desk', 'standingDesk', 'receptionDesk', 'officeChair', 'meetingTable', 'whiteboard'],
    targetKind: 'work-building-interior',
    actionId: 'work.arrive-inside',
  });
}

function getBuildingInteriorAnchorTarget(building, { preferredTypes = [], targetKind = 'building-interior-anchor', actionId = null } = {}) {
  if (!building || building.type === 'park') return null;
  const furniture = Array.isArray(building.interior?.furniture) ? building.interior.furniture : [];
  const preferredSet = new Set(preferredTypes.filter(Boolean));
  const ordered = [
    ...furniture.map((item, index) => ({ item, index, preferred: preferredSet.has(item?.type) })).filter(entry => entry.preferred),
    ...furniture.map((item, index) => ({ item, index, preferred: false })).filter(entry => !preferredSet.size || !preferredSet.has(entry.item?.type)),
  ];
  for (const { item, index } of ordered) {
    if (!item || item.enabled === false || item.deleted || item.removed) continue;
    const spot = getFurnitureActionSpot(building, item);
    if (!spot || !Number.isFinite(spot.apiX) || !Number.isFinite(spot.apiZ)) continue;
    return {
      x: spot.apiX,
      y: spot.apiZ,
      floor: spot.floor || item.floor || 1,
      buildingId: building.id || null,
      furnitureIndex: index,
      objectType: item.type || null,
      spotId: spot.spotId || null,
      interactionSpotId: spot.spotId || null,
      targetKind,
      actionId,
    };
  }
  const points = getBuildingDoorTransitionPointsAPI(building);
  if (points?.inside && Number.isFinite(points.inside.x) && Number.isFinite(points.inside.y)) {
    return {
      x: points.inside.x,
      y: points.inside.y,
      floor: 1,
      buildingId: building.id || null,
      targetKind,
      actionId,
      source: 'door-interior',
    };
  }
  return null;
}

function getAgentWorkArrivalTarget(agent) {
  const workTarget = getAgentWorkTarget(agent);
  if (workTarget?.building) {
    return {
      target: {
        x: workTarget.apiX,
        y: workTarget.apiZ,
        floor: workTarget.floor,
        targetKind: 'work-desk',
        buildingId: workTarget.building.id || workTarget.buildingId || null,
        furnitureIndex: workTarget.furnitureIndex ?? null,
        spotId: workTarget.spotId || null,
        interactionSpotId: workTarget.spotId || null,
        actionId: 'work.desk',
      },
      building: workTarget.building,
      floor: workTarget.floor,
      workTarget,
    };
  }
  const workBuilding = agent?._workBuilding || (agent?.workBuilding ? buildingsMap.get(agent.workBuilding) : null) || null;
  const interiorTarget = getBuildingInteriorWorkArrivalTarget(workBuilding);
  return interiorTarget && workBuilding
    ? { target: interiorTarget, building: workBuilding, floor: interiorTarget.floor, workTarget: null }
    : null;
}

