function isRecognizedIdleActivityKind(kind) {
  const text = String(kind || '');
  return RECOGNIZED_IDLE_ACTIVITY_PREFIXES.some(prefix => text.startsWith(prefix));
}

function isCommittedObjectApproachActivity(agent = null) {
  const activity = agent?._idleActivity || null;
  const intent = agent?._agentIntent || null;
  const target = agent?._wanderTarget || intent?.target || null;
  const object = intent?.object || {};
  const activityPhase = String(activity?.phase || '').toLowerCase();
  const intentPhase = String(intent?.phase || '').toLowerCase();
  const targetKind = String(target?.targetKind || target?.routeMode || '').toLowerCase();
  const hasObjectLifecycle = Boolean(
    activity &&
    (
      activity.isServiceQueueWait === true ||
      activity.buildingId ||
      activity.furnitureIndex != null ||
      activity.objectId ||
      activity.reservationId ||
      activity.activeUseId ||
      activity.actionId ||
      activity.action
    )
  );
  const hasIntentObject = Boolean(
    isAgentIntentActive(intent) &&
    object.type !== 'none' &&
    (
      object.buildingId ||
      object.furnitureIndex != null ||
      object.id ||
      object.objectType ||
      object.actionId ||
      object.reservationId ||
      object.activeUseId
    )
  );
  const hasObjectTarget = targetKind === 'placed-object' || targetKind.includes('object') || targetKind.includes('servicequeueslot');
  return Boolean(
    (activityPhase === 'approach' || intentPhase === 'approach' || hasObjectTarget) &&
    (hasObjectLifecycle || hasIntentObject || hasObjectTarget)
  );
}

function shouldPreserveCommittedObjectTargetDuringStuckRecovery(agent = null) {
  return isCommittedObjectApproachActivity(agent);
}

function getLocalIdleActivityConfig(furnitureType) {
  return LOCAL_IDLE_FURNITURE_ACTIVITY_CONFIG[furnitureType] || null;
}

function getFurnitureSeatSurfaceLift(furnitureType) {
  // Reference local seated lift for a normal 0.8-scale agent. The character
  // animator converts this to each agent's own local lift so the hips/butt land
  // on the same cushion surface instead of using one fixed local elevation for
  // short/tall agents.
  if (furnitureType === 'armchair') return 1.84;
  if (['couch', 'sectionalSofa', 'loveseat'].includes(furnitureType)) return 1.52;
  if (['hallwayBench', 'parkBench', 'smallCafeTable', 'outdoorCafeTable', 'picnicTable', 'smallRoundMeetingTable'].includes(furnitureType)) return 1.34;
  // Bar stools are counter-height: lift the seated pose to the visible top seat
  // surface instead of the lower cushion/body center so agents do not sink into it.
  if (furnitureType === 'barStool') return 4.2;
  return 1.20;
}

function getLocalIdleSeatReservationPlan(building, furniture, furnitureIndex, agent, activity = null) {
  if (!building || !furniture || !agent) return null;
  const type = furniture.type;
  let candidates = [];
  let store = null;
  let occupiedSeatIds = new Set();
  let objectKey = null;
  let defaultApproachSpotId = null;
  const actionId = activity?.action || ACTION_SPOTS[type]?.action || activity?.kind || `life.use${type}`;
  if (type === 'chair') {
    objectKey = getChairObjectKey(building.id || 'unknown-building', furnitureIndex);
    store = getChairObjectUseSeatStore(furniture);
    const locations = (FURNITURE_INTERACTION_SPOTS.chair || []).map(def => {
      const spot = getFurnitureActionSpot(building, furniture, def.id);
      return spot ? { ...def, actionId: def.action || actionId, activationSpotId: def.id, position: { x: spot.apiX, z: spot.apiZ } } : null;
    }).filter(Boolean);
    candidates = listObjectUseSeatCandidates({ locations, activationSpots: locations, objectKey, objectType: 'chair', actionId });
    occupiedSeatIds = getChairActiveReservationSeatIds(furniture, building.id, furnitureIndex);
  } else if (type === 'couch') {
    objectKey = getCouchObjectKey(building.id || 'unknown-building', furnitureIndex);
    store = getCouchObjectUseSeatStore(furniture);
    candidates = getCouchSeatCandidates(building, furniture, furnitureIndex, { actionId });
    occupiedSeatIds = getActiveCouchReservationSeatIds(furniture, building.id, furnitureIndex);
    defaultApproachSpotId = 'talk-front';
  } else if (type === 'sectionalSofa') {
    objectKey = getSectionalSofaObjectKey(building.id || 'unknown-building', furnitureIndex);
    store = getSectionalSofaObjectUseSeatStore(furniture);
    candidates = getSectionalSofaSeatCandidates(building, furniture, furnitureIndex, { actionId });
    occupiedSeatIds = getActiveSectionalSofaReservationSeatIds(furniture, building.id, furnitureIndex);
  } else if (type === 'loveseat') {
    objectKey = getLoveseatObjectKey(building.id || 'unknown-building', furnitureIndex);
    store = getLoveseatObjectUseSeatStore(furniture);
    candidates = getLoveseatSeatCandidates(building, furniture, furnitureIndex, { actionId });
    occupiedSeatIds = getActiveLoveseatReservationSeatIds(furniture, building.id, furnitureIndex);
  } else if (type === 'armchair') {
    objectKey = getArmchairObjectKey(building.id || 'unknown-building', furnitureIndex);
    store = getArmchairObjectUseSeatStore(furniture);
    candidates = getArmchairSeatCandidates(building, furniture, furnitureIndex, { actionId });
    occupiedSeatIds = getActiveArmchairReservationSeatIds(furniture, building.id, furnitureIndex);
    defaultApproachSpotId = 'approach-front';
  } else if (type === 'hallwayBench') {
    objectKey = getHallwayBenchObjectKey(building.id || 'unknown-building', furnitureIndex);
    store = getHallwayBenchObjectUseSeatStore(furniture);
    candidates = getHallwayBenchSeatCandidates(building, furniture, furnitureIndex, { actionId });
    occupiedSeatIds = getActiveHallwayBenchReservationSeatIds(furniture, building.id, furnitureIndex);
    defaultApproachSpotId = 'approach-front';
  } else if (type === 'barStool' || type === 'diningChair' || type === 'patioChair') {
    const config = getSingleSeatChairConfig(type);
    objectKey = config?.objectKeyFn?.(building.id || 'unknown-building', furnitureIndex) || null;
    store = config?.storeFn?.(furniture) || null;
    candidates = getSingleSeatChairSeatCandidates(building, furniture, furnitureIndex, { actionId });
    occupiedSeatIds = getActiveSingleSeatChairReservationSeatIds(furniture, building.id, furnitureIndex, type);
    defaultApproachSpotId = config?.approachSpotId || 'approach-front';
  } else if (getTableSeatingConfig(type)) {
    const config = getTableSeatingConfig(type);
    objectKey = config.objectKeyFn(building.id || 'unknown-building', furnitureIndex);
    store = config.storeFn(furniture);
    candidates = getTableSeatCandidates(building, furniture, furnitureIndex, { actionId });
    occupiedSeatIds = getActiveTableSeatReservationSeatIds(furniture, building.id, furnitureIndex, type);
  } else {
    return null;
  }
  if (!store || !candidates.length) return null;
  const reservationResult = chooseAndReserveObjectUseSeat(store, candidates, {
    agentId: agent.id || agent.name || 'agent',
    agentPosition: { x: agent.x || 0, z: agent.y || 0 },
    actionId,
    occupiedSeatIds,
    reservationId: `idle-seat:${objectKey}:${agent.id || agent.name || 'agent'}:${Date.now()}`,
  });
  if (!reservationResult.ok) return null;
  const selectedSeat = reservationResult.seat;
  const seatSpot = getFurnitureActionSpot(building, furniture, selectedSeat.seatId || selectedSeat.activationSpotId);
  const approachSpotId = selectedSeat.approachSpotId || defaultApproachSpotId || selectedSeat.seatId;
  const approachSpot = approachSpotId ? getFurnitureActionSpot(building, furniture, approachSpotId) : null;
  if (!seatSpot) {
    releaseObjectUseSeatReservation(store, { reservationId: reservationResult.reservation.id, agentId: agent.id || agent.name || 'agent', seatId: selectedSeat.seatId, terminalState: 'failed', reason: 'missing-idle-seat-spot' });
    return null;
  }
  const facing = seatSpot.facing || selectedSeat.facing || 'north';
  const faceAngle = getTableSeatingConfig(type)
    ? seatSpot.faceAngle
    : (getFurnitureForwardFacingAngle(building, furniture, seatSpot, facing) ?? seatSpot.faceAngle);
  return {
    targetSpot: approachSpot || seatSpot,
    seatSpot,
    approachSpot,
    selectedSeat,
    reservation: reservationResult.reservation,
    objectKey,
    actionId,
    faceAngle,
    seatSurfaceLift: getFurnitureSeatSurfaceLift(type),
    routeApproachTarget: approachSpot ? { x: approachSpot.apiX, y: approachSpot.apiZ, floor: approachSpot.floor, spotId: approachSpot.spotId } : null,
  };
}

function randomRangeMs(range, fallback = 7000 + Math.random() * 12000) {
  if (!Array.isArray(range) || range.length < 2) return fallback;
  return range[0] + Math.random() * (range[1] - range[0]);
}

function getLocalIdleFurnitureTargets(building, agent = null) {
  if (!building) return [];
  const furniture = building?.interior?.furniture || [];
  const targets = [];
  const activeFloor = agent && isPointInsideBuildingInterior(building, agent.x, agent.y, -0.15)
    ? getAgentFloor(agent, building)
    : getActiveBuildingFloor(building);
  furniture.forEach((item, index) => {
    if (!item || getFurnitureFloor(item) !== activeFloor || !LOCAL_IDLE_FURNITURE_TYPES.has(item.type) || !ACTION_SPOTS[item.type]) return;
    const activity = getLocalIdleActivityConfig(item.type);
    if (!activity) return; // Only autonomous-pick furniture that has a real arrival/use behavior wired.
    const spot = getFurnitureActionSpot(building, item, activity.spotId || null);
    // Keep the live furniture object reference here. Seat reservation stores live
    // on the furniture itself; cloning it lets two agents reserve the same real
    // seat before either one arrives and activates the actual object state.
    if (spot) targets.push({ ...spot, furniture: item, furnitureIndex: index, kind: activity?.kind || `idle-${item.type}`, activity });
  });
  return targets;
}

function isLocalIdleTargetClaimed(building, target, agent = null) {
  if (!building || !target) return false;
  const buildingId = building.id || null;
  const furnitureIndex = target.furnitureIndex ?? target.furniture?._index ?? null;
  const furniture = target.furniture || (furnitureIndex != null ? building.interior?.furniture?.[furnitureIndex] : null);
  const isServiceQueueObject = isScriptedServiceQueueFurniture(furniture);
  const objectIds = new Set([`${buildingId}:${furnitureIndex}`, furniture?.id, furniture?.objectInstanceId, furniture?.instanceId].filter(Boolean).map(String));
  const spotIds = new Set([target.spotId, target.id, target.activity?.spotId, furniture?.reservation?.spotId, furniture?.reservation?.slotId, furniture?.reservation?.seatId].filter(Boolean).map(String));
  const activeAgentId = furniture?.activeUse?.agentId || furniture?.reservation?.agentId || null;
  if (activeAgentId && String(activeAgentId) !== String(agent?.id || agent?.name || '') && (!isServiceQueueObject || isScriptedServiceObjectActivelyUsed(furniture))) return true;
  const activeState = String(furniture?.activeUse?.state || furniture?.reservation?.status || '').toLowerCase();
  if (isServiceQueueObject) {
    if (isScriptedServiceObjectActivelyUsed(furniture)) return true;
  } else if (['held', 'reserved', 'route_pending', 'routing', 'arrived', 'active', 'using', 'in_progress'].includes(activeState)) return true;
  for (const other of agentsList || []) {
    if (!other || other === agent || getAgentDebugId(other) === getAgentDebugId(agent)) continue;
    const idle = other._idleActivity || null;
    const intent = other._agentIntent || null;
    const intentObject = intent?.object || null;
    const otherBuildingId = idle?.buildingId || intentObject?.buildingId || other._targetBuilding?.id || null;
    const otherFurnitureIndex = idle?.furnitureIndex ?? intentObject?.furnitureIndex ?? null;
    const otherObjectIds = [idle?.objectId, intentObject?.id, intentObject?.objectId, `${otherBuildingId}:${otherFurnitureIndex}`].filter(Boolean).map(String);
    const objectMatches = otherBuildingId === buildingId && (Number(otherFurnitureIndex) === Number(furnitureIndex) || otherObjectIds.some(id => objectIds.has(id)));
    const otherSpotIds = [idle?.spotId, idle?.slotId, idle?.seatId, intentObject?.spotId, intentObject?.slotId, intentObject?.seatId, intentObject?.interactionSpotId].filter(Boolean).map(String);
    const spotMatches = !spotIds.size || otherSpotIds.some(id => spotIds.has(id));
    const targetMatches = other._wanderTarget && Math.hypot((other._wanderTarget.x || 0) - target.apiX, (other._wanderTarget.y || 0) - target.apiZ) <= API_TILE * 0.45;
    if ((objectMatches && spotMatches) || targetMatches) return true;
  }
  return false;
}

function markLocalIdleTargetHeld(building, target, agent, activity = null) {
  const furniture = target?.furniture || (target?.furnitureIndex != null ? building?.interior?.furniture?.[target.furnitureIndex] : null);
  if (!building || !furniture) return;
  if (isScriptedServiceQueueFurniture(furniture)) return;
  furniture.reservation = {
    ...(furniture.reservation || {}),
    id: furniture.reservation?.id || `idle-local:${building.id || 'building'}:${target.furnitureIndex ?? 'object'}:${target.spotId || activity?.spotId || 'spot'}:${agent?.id || agent?.name || 'agent'}:${Date.now()}`,
    agentId: agent?.id || agent?.name || 'agent',
    actionId: target.action || activity?.action || null,
    spotId: target.spotId || activity?.spotId || null,
    slotId: target.spotId || activity?.spotId || null,
    status: 'held',
    sourceKind: 'agent-scripted-mode',
    behaviorCategory: 'local-idle',
  };
  furniture.activeUse = { ...(furniture.activeUse || {}), state: 'reserved', mode: activity?.mode || activity?.kind || target.kind || 'idle-local', actionId: target.action || activity?.action || null, agentId: agent?.id || null, interactionSpotId: target.spotId || activity?.spotId || null };
}

function getNearbyIdleConversationCandidate(agent, anchorBuilding = null, maxDist = API_TILE * 6) {
  let best = null;
  let bestDist = Infinity;
  for (const other of agentsList) {
    if (!other || other === agent || !other._group3d) continue;
    if (isWorkPresenceStatus(other.status) || other._atDesk) continue;
    if (other._tagState?.playing || other._onBreak || other._curInteraction) continue;
    if (other._wanderTarget) continue;
    const otherBuilding = getMovementInteriorBuildingAt(other.x, other.y) || other._currentBuilding || null;
    if (anchorBuilding && otherBuilding?.id !== anchorBuilding.id) continue;
    const dist = Math.hypot(agent.x - other.x, agent.y - other.y);
    if (dist < API_TILE * 1.2 || dist > maxDist) continue;
    if (dist < bestDist) {
      best = other;
      bestDist = dist;
    }
  }
  return best ? { agent: best, dist: bestDist } : null;
}

function buildIdleApproachPoint(agent, targetAgent, desiredDist = API_TILE * 1.35) {
  const dx = agent.x - targetAgent.x;
  const dy = agent.y - targetAgent.y;
  const len = Math.hypot(dx, dy) || 1;
  return {
    x: targetAgent.x + (dx / len) * desiredDist,
    y: targetAgent.y + (dy / len) * desiredDist,
  };
}

function buildReachableAgentApproachPoint(agent, targetAgent, building = null, desiredDist = API_TILE * 1.35) {
  const base = buildIdleApproachPoint(agent, targetAgent, desiredDist);
  if (!building || building.type === 'park') return base;
  const baseAngle = Math.atan2((agent.y || 0) - (targetAgent.y || 0), (agent.x || 0) - (targetAgent.x || 0));
  const angleOffsets = [0, Math.PI / 4, -Math.PI / 4, Math.PI / 2, -Math.PI / 2, Math.PI, Math.PI * 0.75, -Math.PI * 0.75];
  const floor = getAgentFloor(agent, building);
  const candidates = angleOffsets.map(offset => {
    const angle = baseAngle + offset;
    return {
      x: (targetAgent.x || 0) + Math.cos(angle) * desiredDist,
      y: (targetAgent.y || 0) + Math.sin(angle) * desiredDist,
      floor,
      buildingFloor: floor,
    };
  });
  let best = null;
  for (const candidate of candidates) {
    const resolved = resolveInteriorTargetReachability(getFloorScopedBuilding(building, floor), candidate, { debug: false });
    const point = resolved?.target || candidate;
    const distFromAgent = Math.hypot((agent.x || 0) - point.x, (agent.y || 0) - point.y);
    const distFromTarget = Math.hypot((targetAgent.x || 0) - point.x, (targetAgent.y || 0) - point.y);
    if (distFromTarget < API_TILE * 0.85) continue;
    const score = distFromAgent + (resolved?.adjusted ? API_TILE * 0.9 : 0) + Math.abs(distFromTarget - desiredDist) * 0.35;
    if (!best || score < best.score) best = { point, score };
  }
  return best?.point || base;
}

function collectScriptedSeatReservationsForResolver(buildingList = []) {
  const reservations = [];
  for (const building of buildingList || []) {
    for (const furniture of (building?.interior?.furniture || [])) {
      if (!furniture) continue;
      reservations.push(...(getObjectUseSeatStoreForFurniture(furniture).reservations || []));
      const standingReservations = scriptedStandingObjectUseStoreForFurniture(furniture)?.reservations || [];
      // SERVICE_QUEUE_SPEC.md: claim phase counts as busy — feed claimed-or-active
      // reservations to the resolver so contenders queue instead of double-booking.
      // Orphan guard: if the furniture itself is FREE (no claim/active use), any
      // live standing entry is a stale leftover from a missed release — prune it
      // instead of feeding it, otherwise a free machine looks busy forever.
      if (isScriptedServiceQueueFurniture(furniture)) {
        if (isScriptedServiceObjectUnavailableForQueue(furniture)) {
          reservations.push(...standingReservations.filter(reservation => isScriptedServiceReservationClaimedOrActive(furniture, reservation)));
        } else if (standingReservations.length) {
          pruneInactiveScriptedServiceObjectUseReservations(furniture);
        }
      } else {
        reservations.push(...standingReservations);
      }
      reservations.push(...(scriptedActiveObjectUseStoreForFurniture(furniture)?.reservations || []));
    }
  }
  return reservations;
}

function isScriptedServiceQueueFurniture(furniture = {}) {
  return getScriptedServiceQueueDefinitionsForFurniture(furniture).length > 0;
}

function isManualDropStandingDrinkMachine(furniture = {}) {
  return furniture?.type === 'waterCooler' || furniture?.type === 'coffeeMachine' || furniture?.type === 'countertopCoffeeMachine' || furniture?.type === 'microwave';
}

function isManualDropStandingServiceMachine(furniture = {}) {
  return isManualDropStandingDrinkMachine(furniture) || furniture?.type === 'vending';
}

function isScriptedServiceObjectActivelyUsed(furniture = {}, reservation = null) {
  const activeStates = new Set(['active', 'using', 'in_progress', 'dispensing', 'brewing', 'heating', 'serving', 'ordering', 'docked']);
  const reservationState = String(reservation?.state || reservation?.status || furniture.reservation?.state || furniture.reservation?.status || '').toLowerCase();
  const activeUseState = String(furniture.activeUse?.state || '').toLowerCase();
  const activeSlots = Object.values(furniture.activeUse?.activeSlots || {});
  if (activeStates.has(reservationState) || activeStates.has(activeUseState)) return true;
  return activeSlots.some(slot => {
    const slotState = String(slot?.state || slot?.status || '').toLowerCase();
    return activeStates.has(slotState) || (!slotState && activeStates.has(activeUseState) && slot?.agentId);
  });
}

function isScriptedServiceObjectQueueHeadClaimed(furniture = {}) {
  return Boolean(
    isScriptedServiceQueueFurniture(furniture) &&
    furniture.activeUse?.queueFrontPromoted === true &&
    ['route_pending', 'routing', 'arrived', 'reserved', 'held'].includes(String(furniture.activeUse?.state || '').toLowerCase()) &&
    furniture.activeUse?.agentId
  );
}

function isScriptedServiceObjectRoutePendingClaimed(furniture = {}) {
  return Boolean(
    isScriptedServiceQueueFurniture(furniture) &&
    furniture.activeUse?.autonomousRoutePendingClaim === true &&
    ['route_pending', 'routing', 'arrived', 'reserved', 'held'].includes(String(furniture.activeUse?.state || '').toLowerCase()) &&
    furniture.activeUse?.agentId
  );
}

// SERVICE_QUEUE_SPEC.md — normative claim/use cycle words.
// Claimed-only states mark phase 1 (CLAIM): an agent owns the object but is
// still walking to it. Per spec the claim phase counts as busy.
const SERVICE_QUEUE_CLAIMED_ONLY_STATES = new Set(['held', 'reserved', 'pending', 'route_pending', 'routing', 'arrived', 'approach', 'queued']);
// Stale-claim guard: a claim that never progressed to ARRIVE within this window
// stops blocking the object (prevents abandoned-claim deadlock). Arriving agents
// re-reserve, and any contender that walked up meanwhile is queued by the
// arrival door, so expiry is safe.
const SERVICE_QUEUE_CLAIM_TTL_MS = 45000;

function isScriptedServiceObjectClaimPhase(furniture = {}, nowMs = Date.now()) {
  for (const record of [furniture.reservation, furniture.activeUse]) {
    if (!record?.agentId) continue;
    const state = String(record.state || record.status || '').toLowerCase();
    if (!SERVICE_QUEUE_CLAIMED_ONLY_STATES.has(state)) continue;
    const createdAtMs = Number(record.createdAtMs || record.updatedAtMs || 0);
    if (!createdAtMs || nowMs - createdAtMs <= SERVICE_QUEUE_CLAIM_TTL_MS) return true;
  }
  return false;
}

// Reservation-level claimed-or-active check for resolver feeds.
function isScriptedServiceReservationClaimedOrActive(furniture, reservation, nowMs = Date.now()) {
  if (isScriptedServiceObjectActivelyUsed(furniture, reservation)) return true;
  const state = String(reservation?.state || reservation?.status || '').toLowerCase();
  if (!SERVICE_QUEUE_CLAIMED_ONLY_STATES.has(state)) return false;
  const createdAtMs = Number(reservation?.createdAtMs || reservation?.updatedAtMs || 0);
  return !createdAtMs || nowMs - createdAtMs <= SERVICE_QUEUE_CLAIM_TTL_MS;
}

function isScriptedServiceObjectUnavailableForQueue(furniture = {}) {
  return isScriptedServiceObjectActivelyUsed(furniture) || isScriptedServiceObjectClaimPhase(furniture) || isScriptedServiceObjectQueueHeadClaimed(furniture) || isScriptedServiceObjectRoutePendingClaimed(furniture);
}

function getLiveScriptedServiceQueueReservationsForManualDrop(furniture = {}, { excludeAgentId = null } = {}) {
  const store = furniture?._scriptedServiceQueueStore || null;
  if (!store || !Array.isArray(store.reservations)) return [];
  const excluded = excludeAgentId == null ? null : String(excludeAgentId);
  return normalizeScriptedServiceQueueReservations(store).filter(reservation => {
    if (!reservation?.agentId) return false;
    return !excluded || String(reservation.agentId) !== excluded;
  });
}

function isScriptedServiceObjectClaimedForManualQueue(furniture = {}) {
  if (!isScriptedServiceQueueFurniture(furniture)) return false;
  if (isScriptedServiceObjectUnavailableForQueue(furniture)) return true;
  if (getLiveScriptedServiceQueueReservationsForManualDrop(furniture).length) return true;
  const claimedStates = new Set(['held', 'reserved', 'route_pending', 'routing', 'arrived', 'queued', 'active', 'using', 'in_progress', 'dispensing', 'brewing', 'in-use', 'in_use']);
  const activeUseState = String(furniture.activeUse?.state || '').toLowerCase();
  const reservationState = String(furniture.reservation?.state || furniture.reservation?.status || '').toLowerCase();
  const activeUseAgentId = furniture.activeUse?.agentId || null;
  const reservationAgentId = furniture.reservation?.agentId || null;
  if (activeUseAgentId && claimedStates.has(activeUseState)) return true;
  if (reservationAgentId && claimedStates.has(reservationState)) return true;
  for (const [key, value] of Object.entries(furniture)) {
    if (!value || typeof value !== 'object' || Array.isArray(value) || !key.endsWith('State')) continue;
    const stateStatus = String(value.status || value.state || '').toLowerCase();
    if (claimedStates.has(stateStatus)) return true;
    if ((value.activeSlotIds || value.reservedSlotIds || value.activeSeatIds || value.reservedSeatIds || []).length) return true;
  }
  const store = scriptedStandingObjectUseStoreForFurniture(furniture);
  return (store?.reservations || []).some(reservation => {
    const state = String(reservation?.state || reservation?.status || '').toLowerCase();
    return reservation?.agentId && claimedStates.has(state);
  });
}

function pruneInactiveScriptedServiceObjectUseReservations(furniture = null) {
  if (!isScriptedServiceQueueFurniture(furniture) || isScriptedServiceObjectUnavailableForQueue(furniture)) return { pruned: 0 };
  // The object is FREE at the furniture level (no claim, no active use). Every
  // legitimate live use mirrors into furniture.reservation/activeUse, so any
  // remaining live standing-store entry here is an orphan from a missed release.
  // Stale 'active' orphans previously survived this prune and made the resolver
  // treat a free machine as busy forever (agents queued at an empty machine).
  const store = scriptedStandingObjectUseStoreForFurniture(furniture);
  const before = Array.isArray(store?.reservations) ? store.reservations.length : 0;
  if (store?.reservations) {
    store.reservations = [];
  }
  const activeStates = new Set(['active', 'using', 'in_progress', 'dispensing', 'brewing', 'heating', 'serving', 'ordering', 'docked']);
  const reservationState = String(furniture.reservation?.state || furniture.reservation?.status || '').toLowerCase();
  if (furniture.reservation && !activeStates.has(reservationState)) furniture.reservation = null;
  if (furniture.activeUse && !activeStates.has(String(furniture.activeUse.state || '').toLowerCase())) {
    furniture.activeUse = clearCompletedObjectAssignmentMarkers(furniture, furniture.activeUse, { state: 'complete', mode: furniture.activeUse.mode || 'ready', reason: 'service-object-not-active-prune' });
  }
  return { pruned: Math.max(0, before - (store?.reservations?.length || 0)) };
}

function agentHasMatchingServiceObjectActivity(agentId, buildingId, furnitureIndex, { kindPrefix = '', includeQueue = false } = {}) {
  if (!agentId || buildingId == null || furnitureIndex == null) return false;
  const expectedAgentId = String(agentId);
  return agentsList.some(agent => {
    if (!agent || String(getAgentDebugId(agent)) !== expectedAgentId) return false;
    const activity = agent._idleActivity || null;
    if (!activity || activity.buildingId !== buildingId || Number(activity.furnitureIndex) !== Number(furnitureIndex)) return false;
    const kind = String(activity.kind || '');
    return Boolean((kindPrefix && kind.startsWith(kindPrefix)) || (includeQueue && kind.startsWith('service-queue-')));
  });
}

function releaseStaleStandingUseEntriesForServiceObject(store, buildingId, furnitureIndex, { kindPrefix = '', reason = 'stale-service-object-entry' } = {}) {
  if (!Array.isArray(store?.reservations)) return 0;
  const terminal = new Set(['released', 'complete', 'completed', 'cancelled', 'failed']);
  let released = 0;
  store.reservations = store.reservations.map(entry => {
    const state = String(entry?.state || entry?.status || '').toLowerCase();
    if (!entry || terminal.has(state)) return entry;
    if (agentHasMatchingServiceObjectActivity(entry.agentId, buildingId, furnitureIndex, { kindPrefix, includeQueue: false })) return entry;
    released++;
    return {
      ...entry,
      state: 'released',
      status: 'released',
      activeUse: { ...(entry.activeUse || {}), state: 'released', releasedBy: reason },
      releaseReason: reason,
      releasedAtMs: Date.now(),
      updatedAtMs: Date.now(),
    };
  });
  return released;
}

function pruneStaleVendingMachineRuntimeState(buildingId, furnitureIndex, machine = null) {
  if (!machine || machine.type !== 'vending') return { pruned: 0, reset: false };
  const nowMs = Date.now();
  let pruned = 0;
  const store = scriptedStandingObjectUseStoreForFurniture(machine);
  pruned += releaseStaleStandingUseEntriesForServiceObject(store, buildingId, furnitureIndex, {
    kindPrefix: 'vending-machine-',
    reason: 'stale-vending-standing-use',
  });
  const minClaimAgeMs = 1500;
  const claimIsOldEnough = record => {
    const createdAtMs = Number(record?.createdAtMs || record?.updatedAtMs || record?.startedAtMs || 0);
    return !createdAtMs || nowMs - createdAtMs >= minClaimAgeMs;
  };
  const reservationAgentId = machine.reservation?.agentId || null;
  if (machine.reservation && claimIsOldEnough(machine.reservation) && !agentHasMatchingServiceObjectActivity(reservationAgentId, buildingId, furnitureIndex, { kindPrefix: 'vending-machine-', includeQueue: false })) {
    machine.reservation = null;
    pruned++;
  }
  const activeUseAgentId = machine.activeUse?.agentId || null;
  if (machine.activeUse && claimIsOldEnough(machine.activeUse) && !agentHasMatchingServiceObjectActivity(activeUseAgentId, buildingId, furnitureIndex, { kindPrefix: 'vending-machine-', includeQueue: false })) {
    machine.activeUse = clearCompletedObjectAssignmentMarkers(machine, machine.activeUse, {
      state: 'complete',
      mode: machine.activeUse.mode || 'ready',
      reason: 'stale-vending-active-use',
    });
    pruned++;
  }
  const queueCount = normalizeScriptedServiceQueueReservations(machine._scriptedServiceQueueStore || null).length;
  const hasVendingAgent = agentsList.some(agent => {
    const activity = agent?._idleActivity || null;
    return activity?.buildingId === buildingId &&
      Number(activity.furnitureIndex) === Number(furnitureIndex) &&
      String(activity.kind || '').startsWith('vending-machine-');
  });
  const hasLiveClaim = Boolean(machine.reservation?.agentId || (machine.activeUse?.agentId && String(machine.activeUse?.state || '').toLowerCase() !== 'complete'));
  const shouldResetVendingState = !hasVendingAgent && !hasLiveClaim && queueCount === 0;
  if (shouldResetVendingState && machine.vendingState && machine.vendingState.status !== 'stocked') {
    machine.vendingState = {
      ...(machine.vendingState || {}),
      status: 'stocked',
      activeSlotIds: [],
      reservedSlotIds: [],
      reachableUseFrontSpot: true,
      persistentFurniture: true,
      lastCleanupReason: 'stale-vending-runtime-prune',
    };
    pruned++;
    return { pruned, reset: true };
  }
  return { pruned, reset: false };
}

function getScriptedServicePrimaryUseSlotId(furniture = {}) {
  const config = getStandingUseMachineConfig(furniture?.type);
  if (config?.slotId) return config.slotId;
  const spots = FURNITURE_INTERACTION_SPOTS[furniture?.type] || [];
  const primary = getPrimaryActionDebugSpot(spots, spots.find(spot => isQueueActionDebugSpot(spot)));
  return primary?.standingUseSlotId || primary?.activationSpotId || primary?.id || 'use-front';
}

function collectScriptedOccupiedSeatIdsForResolver(buildingList = [], { excludeAgent = null } = {}) {
  const occupied = [];
  const buildingIds = new Set((buildingList || []).map(building => building?.id).filter(Boolean));
  const resolverBuildingsById = new Map((buildingList || []).map(building => [building?.id, building]).filter(([id]) => id));
  for (const building of buildingList || []) {
    for (const [index, furniture] of (building?.interior?.furniture || []).entries()) {
      if (!furniture) continue;
      const objectKey = furniture.id || furniture.instanceId || furniture.objectInstanceId || `${building.id}:${index}`;
      const serviceQueueFurniture = isScriptedServiceQueueFurniture(furniture);
      const serviceObjectClaimed = serviceQueueFurniture && isScriptedServiceObjectUnavailableForQueue(furniture);
      Object.keys(furniture.activeUse?.activeSeats || {}).forEach(seatId => occupied.push({ objectKey, seatId }));
      Object.keys(furniture.activeUse?.activeSlots || {}).forEach(slotId => {
        if (!serviceQueueFurniture || serviceObjectClaimed) occupied.push({ objectKey, slotId });
      });
      const seatId = furniture.reservation?.seatId || furniture.reservation?.spotId || furniture.activeUse?.interactionSpotId || null;
      if (seatId && (!serviceQueueFurniture || serviceObjectClaimed)) occupied.push({ objectKey, seatId, slotId: seatId, spotId: seatId, interactionSpotId: seatId });
      const slotId = furniture.reservation?.activeUseSlotId || furniture.reservation?.slotId || furniture.reservation?.standingUseSlotId || furniture.activeUse?.activeUseSlotId || null;
      if (slotId && (!serviceQueueFurniture || serviceObjectClaimed)) occupied.push({ objectKey, slotId, spotId: slotId, interactionSpotId: slotId });
      const liveQueueReservations = (furniture._scriptedServiceQueueStore?.reservations || [])
        .filter(queueReservation => queueReservation && !['released', 'cancelled', 'complete', 'failed'].includes(String(queueReservation.state || queueReservation.status || '').toLowerCase()));
      if (liveQueueReservations.length && serviceQueueFurniture && !serviceObjectClaimed) {
        promoteScriptedServiceQueueFrontIfReady(building, index, 'resolver-free-service-object-promote-front');
        continue;
      }
      if (liveQueueReservations.length && serviceQueueFurniture && serviceObjectClaimed) {
        const primarySlotId = getScriptedServicePrimaryUseSlotId(furniture);
        occupied.push({ objectKey, slotId: primarySlotId, spotId: primarySlotId, interactionSpotId: primarySlotId, capacityKey: primarySlotId, source: 'service-queue-priority' });
      }
      for (const queueReservation of liveQueueReservations) {
        const queueSpotId = queueReservation.queueSpotId || queueReservation.spotId || queueReservation.slotId || 'queue-wait';
        occupied.push({ objectKey, slotId: `${queueSpotId}:${queueReservation.queueIndex || 0}`, spotId: queueSpotId, interactionSpotId: queueSpotId, capacityKey: queueSpotId, source: 'service-queue-reservation' });
      }
    }
  }
  for (const other of agentsList || []) {
    if (!other || other === excludeAgent || getAgentDebugId(other) === getAgentDebugId(excludeAgent)) continue;
    const intent = other._agentIntent || null;
    const idle = other._idleActivity || null;
    const object = intent?.object || null;
    const buildingId = object?.buildingId || idle?.buildingId || other._targetBuilding?.id || null;
    if (buildingIds.size && buildingId && !buildingIds.has(buildingId)) continue;
    const furnitureIndex = object?.furnitureIndex ?? idle?.furnitureIndex ?? null;
    if (furnitureIndex == null || !buildingId) continue;
    const objectKey = object?.id || idle?.objectId || `${buildingId}:${furnitureIndex}`;
    const targetBuilding = resolverBuildingsById.get(buildingId) || buildingsMap.get(buildingId) || null;
    const targetFurniture = targetBuilding?.interior?.furniture?.[furnitureIndex] || null;
    if (!targetFurniture) continue;
    if (isScriptedServiceQueueFurniture(targetFurniture)) continue;
    const spotId = object?.spotId || object?.slotId || idle?.spotId || idle?.slotId || null;
    const seatId = object?.seatId || spotId;
    const slotId = object?.slotId || spotId;
    if (spotId || seatId || slotId) occupied.push({ objectKey, spotId, interactionSpotId: spotId, seatId, slotId, capacityKey: object?.capacityKey || idle?.capacityKey || null, source: 'agent-intent-or-idle-target' });
  }
  return occupied;
}

const SCRIPTED_BEHAVIOR_FALLBACK_CONSTANTS = Object.freeze({
  objectCooldownMs: 240000,
  categoryCooldownMs: 180000,
  failedTargetThrottleMs: 90000,
  serviceQueueCooldownMs: 90000,
  workReturnDeskChance: 0.28,
  queueingCategories: Object.freeze(['snack-drink']),
});

// Pass 1 idle-autonomy rebalance: the desk is one optional destination among
// many for idle agents, not a magnet they snap back to after every activity.
const IDLE_POST_ACTIVITY_DESK_RETURN_CHANCE = 0.15;
const IDLE_DESK_VISIT_CHANCE = 0.08;

function rollIdleDeskReturnAfterActivity(workTarget) {
  return !!workTarget && Math.random() < IDLE_POST_ACTIVITY_DESK_RETURN_CHANCE;
}

function hasRecentScriptedCategoryUse(agent, category, nowMs = Date.now()) {
  const memory = agent?._scriptedBehaviorMemory;
  return (memory?.recentCategories || []).some(entry =>
    String(entry.category || '') === category &&
    nowMs - Number(entry.lastUsedAtMs || 0) < SCRIPTED_BEHAVIOR_FALLBACK_CONSTANTS.categoryCooldownMs);
}

const SCRIPTED_IDLE_PULSE_RULES = Object.freeze({
  initialDelayMs: Object.freeze([60_000, 120_000]),
  retryDelayMs: Object.freeze([10_000, 25_000]),
  categoryWeights: Object.freeze({
    'snack-drink': 24,
    socialize: 18,
    rest: 16,
    'browse-read': 16,
    play: 12,
    wander: 8,
    'work-return': 6,
  }),
  objectTypes: Object.freeze({
    rest: Object.freeze(['couch', 'sectionalSofa', 'loveseat', 'armchair', 'hallwayBench', 'smallCafeTable', 'patioTable', 'smallRoundMeetingTable', 'chair', 'officeChair']),
    'snack-drink': Object.freeze(['waterCooler', 'countertopCoffeeMachine', 'vending', 'fridge', 'microwave', 'cafeCounter', 'counter', 'kitchenIsland', 'pantryShelf', 'displayCase']),
    'browse-read': Object.freeze(['bookshelf', 'bulletinBoard', 'menuBoard', 'whiteboard', 'wallArt', 'shopShelf', 'supplyCabinet', 'medicalSupplyCabinet', 'pantryShelf', 'displayCase', 'displayMannequin', 'tvStand', 'mirror', 'storageBoxes', 'serverRack', 'toolCart', 'workbench']),
    play: Object.freeze(['pingpong', 'poolTable', 'arcadeMachine', 'gamingStation', 'treadmill', 'trainingMat', 'gymBench', 'dumbbellRack']),
  }),
});

// Temporary experiment: make idle behavior feel closer to Virtual Office while
// preserving Virtual World's routing, floors, AgentIntent, and object-use gates.
const VO_STYLE_IDLE_TEST = true;
const VO_STYLE_IDLE_PULSE_RULES = Object.freeze({
  initialDelayMs: Object.freeze([8_000, 20_000]),
  retryDelayMs: Object.freeze([3_000, 8_000]),
  categoryWeights: Object.freeze({
    'snack-drink': 30,
    socialize: 26,
    rest: 24,
    'browse-read': 22,
    play: 18,
    wander: 16,
    'work-return': 3,
  }),
  objectTypes: SCRIPTED_IDLE_PULSE_RULES.objectTypes,
});

const AGENT_SCRIPTED_IDLE_GATE_RULES = Object.freeze({
  recentProductiveWindowMs: 10 * 60 * 1000,
  mediumIdleWindowMs: 25 * 60 * 1000,
  shortOutdoorRecentChanceCap: 0,
  shortOutdoorMediumChanceCap: 0.08,
  shortOutdoorLongChanceCap: 0.26,
  socialRecentChanceCap: 0.03,
  socialMediumChanceCap: 0.16,
  socialLongChanceCap: 0.38,
  wanderRecentChanceCap: 0.02,
  wanderMediumChanceCap: 0.12,
  wanderLongChanceCap: 0.30,
});

function clearCompletedObjectAssignmentMarkers(object, activeUse = {}, { activeSlots = null, agent = null, action = null, state = 'complete', mode = null, reason = null } = {}) {
  if (object?.state?.reservation) delete object.state.reservation;
  const next = {
    ...(activeUse || {}),
    state,
    ...(mode !== null ? { mode } : {}),
    ...(activeSlots !== null ? { activeSlots } : {}),
    lastAgentId: agent?.id || null,
    lastAction: action || activeUse?.actionId || activeUse?.lastAction || null,
    ...(reason ? { releasedBy: reason } : {}),
    completedAt: new Date().toISOString(),
  };
  delete next.agentId;
  delete next.reservationId;
  delete next.activeUseSlotId;
  delete next.docked;
  return next;
}

function clearTransientObjectAssignmentState(object) {
  if (!object || typeof object !== 'object') return false;
  let changed = false;
  const deleteKey = (key) => {
    if (Object.prototype.hasOwnProperty.call(object, key)) {
      delete object[key];
      changed = true;
    }
  };
  for (const key of [
    'reservation',
    'activeUse',
    'objectUseSeat',
    'objectUseStanding',
    'objectUseActive',
    'objectUseSeatReservations',
    'objectUseStandingReservations',
    'objectUseActiveReservations',
    '_scriptedObjectUseStore',
    '_scriptedServiceQueueStore',
  ]) deleteKey(key);
  if (object.state?.reservation) {
    delete object.state.reservation;
    changed = true;
  }
  for (const [key, value] of Object.entries(object)) {
    if (!value || typeof value !== 'object' || Array.isArray(value) || !key.endsWith('State')) continue;
    for (const listKey of ['activeSlotIds', 'reservedSlotIds', 'activeSeatIds', 'reservedSeatIds']) {
      if (Array.isArray(value[listKey]) && value[listKey].length) {
        value[listKey] = [];
        changed = true;
      }
    }
    const status = String(value.status || '').toLowerCase();
    if (['reserved', 'active', 'playing', 'occupied', 'queued', 'in-use', 'in_use'].includes(status)) {
      value.status = value.readyStatus || value.openStatus || 'ready';
      changed = true;
    }
    if (value.agentId || value.reservedAgentId || value.activeAgentId) {
      delete value.agentId;
      delete value.reservedAgentId;
      delete value.activeAgentId;
      changed = true;
    }
  }
  return changed;
}

function clearBuildingTransientObjectAssignments(building) {
  if (!building || typeof building !== 'object') return false;
  let changed = false;
  for (const furniture of building.interior?.furniture || []) {
    if (clearTransientObjectAssignmentState(furniture)) changed = true;
  }
  for (const node of building.outdoorArea?.nodes || building.outdoorNodes || []) {
    if (clearTransientObjectAssignmentState(node)) changed = true;
  }
  return changed;
}

function markAgentScriptedMeaningfulActivity(agent, kind = 'meaningful-action', nowMs = Date.now()) {
  if (!agent) return;
  agent._lastMeaningfulActionAtMs = nowMs;
  agent._lastTaskCompletedAtMs = nowMs;
  if (['work', 'desk-work', 'productive-work', 'working-status'].includes(kind)) agent._lastWorkActivityAtMs = nowMs;
  agent._idleSinceAtMs = null;
}

function updateAgentScriptedActivityTelemetry(agent, nowMs = Date.now()) {
  if (!agent) return;
  if (isWorkPresenceStatus(agent.status) || agent._atDesk || agent._activeWorkSpot) {
    agent._lastMeaningfulActionAtMs = nowMs;
    agent._lastWorkActivityAtMs = nowMs;
    agent._idleSinceAtMs = null;
    return;
  }
  const activeIntent = agent._agentIntent || null;
  const busy = Boolean(agent._wanderTarget || agent._idleActivity || agent._curInteraction || agent._curiosityTarget || (activeIntent && isAgentIntentActive(activeIntent)));
  if (busy) {
    agent._idleSinceAtMs = null;
    return;
  }
  if (isIdlePresenceStatus(agent.status) || !agent.status) {
    if (!agent._idleSinceAtMs) agent._idleSinceAtMs = nowMs;
  } else {
    agent._idleSinceAtMs = null;
  }
}

function getAgentScriptedIdleDecisionContext(agent, options = {}) {
  const nowMs = Number(options.nowMs || Date.now());
  const workTarget = options.workTarget === undefined ? getAgentWorkTarget(agent) : options.workTarget;
  const currentBuilding = options.currentBuilding === undefined ? (getMovementInteriorBuildingAt(agent?.x, agent?.y) || agent?._currentBuilding || null) : options.currentBuilding;
  const workBuilding = workTarget?.building || agent?._workBuilding || null;
  const msSinceMeaningfulWork = Number.isFinite(Number(agent?._lastMeaningfulActionAtMs)) ? nowMs - Number(agent._lastMeaningfulActionAtMs) : null;
  const idleDurationMs = Number.isFinite(Number(agent?._idleSinceAtMs)) ? Math.max(0, nowMs - Number(agent._idleSinceAtMs)) : 0;
  return {
    nowMs,
    agentId: getAgentDebugId(agent),
    behaviorSourceKind: options.behaviorSourceKind || 'agent-scripted-mode',
    schedulePhase: options.schedulePhase || agent?._schedPhase || 'idle',
    currentBuildingId: currentBuilding?.id || null,
    workBuildingId: workBuilding?.id || null,
    homeBuildingId: agent?.homeBuildingId || agent?._homeBuilding?.id || null,
    isInsideBuilding: Boolean(currentBuilding && currentBuilding.type !== 'park' && isPointInsideBuildingInterior(currentBuilding, agent?.x, agent?.y, -0.15)),
    isAtOrNearAssignedWorkSpot: Boolean(workTarget && Math.hypot((agent?.x || 0) - workTarget.apiX, (agent?.y || 0) - workTarget.apiZ) <= API_TILE * 1.6),
    recentlyProductive: msSinceMeaningfulWork != null && msSinceMeaningfulWork < AGENT_SCRIPTED_IDLE_GATE_RULES.recentProductiveWindowMs,
    msSinceMeaningfulWork,
    idleDurationMs,
    hasIndoorCandidates: Boolean(options.hasIndoorCandidates),
    hasServiceNeed: Boolean(options.hasServiceNeed),
    hasOutdoorNeed: Boolean(options.hasOutdoorNeed),
  };
}

function evaluateAgentScriptedIdleDecisionGate(agent, options = {}) {
  const context = getAgentScriptedIdleDecisionContext(agent, options);
  const blockedFamilies = [];
  const allowedFamilies = new Set(['inside-object', 'service-queue', 'inside-social', 'desk-return', 'wait']);
  const phase = String(context.schedulePhase || '').toLowerCase();
  const longIdle = context.idleDurationMs >= AGENT_SCRIPTED_IDLE_GATE_RULES.mediumIdleWindowMs || (context.msSinceMeaningfulWork != null && context.msSinceMeaningfulWork >= AGENT_SCRIPTED_IDLE_GATE_RULES.mediumIdleWindowMs);
  const mediumIdle = !longIdle && (context.idleDurationMs >= AGENT_SCRIPTED_IDLE_GATE_RULES.recentProductiveWindowMs || (context.msSinceMeaningfulWork != null && context.msSinceMeaningfulWork >= AGENT_SCRIPTED_IDLE_GATE_RULES.recentProductiveWindowMs));
  let outdoorChanceCap = AGENT_SCRIPTED_IDLE_GATE_RULES.wanderMediumChanceCap;
  if (phase.includes('social')) outdoorChanceCap = context.recentlyProductive ? AGENT_SCRIPTED_IDLE_GATE_RULES.socialRecentChanceCap : (longIdle ? AGENT_SCRIPTED_IDLE_GATE_RULES.socialLongChanceCap : AGENT_SCRIPTED_IDLE_GATE_RULES.socialMediumChanceCap);
  else if (phase.includes('short-outside')) outdoorChanceCap = context.recentlyProductive ? AGENT_SCRIPTED_IDLE_GATE_RULES.shortOutdoorRecentChanceCap : (longIdle ? AGENT_SCRIPTED_IDLE_GATE_RULES.shortOutdoorLongChanceCap : AGENT_SCRIPTED_IDLE_GATE_RULES.shortOutdoorMediumChanceCap);
  else outdoorChanceCap = context.recentlyProductive ? AGENT_SCRIPTED_IDLE_GATE_RULES.wanderRecentChanceCap : (longIdle ? AGENT_SCRIPTED_IDLE_GATE_RULES.wanderLongChanceCap : AGENT_SCRIPTED_IDLE_GATE_RULES.wanderMediumChanceCap);

  if (context.recentlyProductive && !options.explicitOutdoorNeed) {
    outdoorChanceCap = Math.min(outdoorChanceCap, AGENT_SCRIPTED_IDLE_GATE_RULES.wanderRecentChanceCap);
    blockedFamilies.push({ family: 'outdoor-object', reason: 'recent-productive-activity' }, { family: 'outdoor-wander', reason: 'recent-productive-activity' });
  }
  if (context.hasIndoorCandidates && !longIdle) {
    outdoorChanceCap = Math.min(outdoorChanceCap, 0.08);
    blockedFamilies.push({ family: 'outdoor-object', reason: 'indoor-candidates-first' });
  }
  const roll = Number.isFinite(Number(options.roll)) ? Number(options.roll) : Math.random();
  const outdoorAllowed = roll < outdoorChanceCap;
  if (outdoorAllowed) {
    allowedFamilies.add('short-outside-break');
    allowedFamilies.add('outdoor-object');
    allowedFamilies.add('outdoor-wander');
  } else {
    blockedFamilies.push({ family: 'outdoor-wander', reason: 'outside-chance-cap-not-met' });
  }
  return {
    allowedFamilies: [...allowedFamilies],
    blockedFamilies,
    outdoorAllowed,
    outdoorChanceCap,
    preferredBuildingId: context.currentBuildingId || context.workBuildingId || null,
    debugReason: context.recentlyProductive
      ? `stayed-inside: worked ${Math.max(0, Math.round((context.msSinceMeaningfulWork || 0) / 60000))}m ago`
      : (outdoorAllowed ? `outdoor-allowed: ${phase || 'idle'} chance ${outdoorChanceCap.toFixed(2)}` : `stayed-inside: ${phase || 'idle'} chance ${outdoorChanceCap.toFixed(2)} not met`),
    context,
  };
}

function agentScriptedGateAllowsFamily(gate, family) {
  return Boolean(gate?.allowedFamilies?.includes(family));
}

function getAgentScriptedMemory(agent) {
  if (!agent._scriptedBehaviorMemory) {
    agent._scriptedBehaviorMemory = { recentCategories: [], recentObjects: [], failedTargets: [] };
  }
  return agent._scriptedBehaviorMemory;
}

function getAgentScriptedBehaviorPreferences(agent, defaults = {}) {
  const raw = agent?.scriptedBehaviorPreferences || agent?.behaviorPreferences || agent?.preferences || {};
  return {
    ...defaults,
    preferredCategories: raw.preferredCategories || raw.categories || defaults.preferredCategories || [],
    avoidCategories: raw.avoidCategories || raw.avoidedCategories || defaults.avoidCategories || [],
    objectTypes: raw.preferredObjectTypes || raw.objectTypes || defaults.objectTypes || [],
    preferredObjectTypes: raw.preferredObjectTypes || raw.objectTypes || defaults.preferredObjectTypes || defaults.objectTypes || [],
    preferredObjectIds: raw.preferredObjectIds || raw.objectIds || defaults.preferredObjectIds || [],
    avoidObjectIds: raw.avoidObjectIds || defaults.avoidObjectIds || [],
    preferredBuildingIds: raw.preferredBuildingIds || raw.buildingIds || defaults.preferredBuildingIds || [],
    objectCooldownMs: Number(raw.objectCooldownMs || defaults.objectCooldownMs || SCRIPTED_BEHAVIOR_FALLBACK_CONSTANTS.objectCooldownMs),
  };
}

function markAgentScriptedChoice(agent, category, destination = null, nowMs = Date.now()) {
  const memory = getAgentScriptedMemory(agent);
  if (category) memory.recentCategories = [{ category, lastUsedAtMs: nowMs }, ...(memory.recentCategories || []).filter(entry => entry.category !== category)].slice(0, 12);
  const objectId = destination?.objectId || destination?.target?.id || null;
  if (objectId) memory.recentObjects = [{ objectId, lastUsedAtMs: nowMs }, ...(memory.recentObjects || []).filter(entry => String(entry.objectId) !== String(objectId))].slice(0, 24);
}

function getScriptedServiceObjectKey(building = null, furnitureIndex = null, furniture = null) {
  if (!building || furnitureIndex == null) return null;
  return furniture?.id || furniture?.instanceId || furniture?.objectInstanceId || `${building.id}:${furnitureIndex}`;
}

function markAgentScriptedServiceUseComplete(agent, building = null, furnitureIndex = null, furniture = null, nowMs = Date.now()) {
  if (!agent || !building || furnitureIndex == null) return;
  const objectId = getScriptedServiceObjectKey(building, furnitureIndex, furniture || building.interior?.furniture?.[furnitureIndex]);
  if (!objectId) return;
  const memory = getAgentScriptedMemory(agent);
  memory.recentObjects = [{ objectId, lastUsedAtMs: nowMs }, ...(memory.recentObjects || []).filter(entry => String(entry.objectId) !== String(objectId))].slice(0, 24);
  if (!agent._scriptedServiceQueueCooldowns || typeof agent._scriptedServiceQueueCooldowns !== 'object') agent._scriptedServiceQueueCooldowns = {};
  agent._scriptedServiceQueueCooldowns[objectId] = nowMs + SCRIPTED_BEHAVIOR_FALLBACK_CONSTANTS.serviceQueueCooldownMs;
}

function collectBlockedScriptedServiceObjectIds(agent, buildingList = [], nowMs = Date.now()) {
  const blocked = [];
  const cooldowns = agent?._scriptedServiceQueueCooldowns || {};
  for (const building of buildingList || []) {
    for (const [index, furniture] of (building?.interior?.furniture || []).entries()) {
      const objectId = getScriptedServiceObjectKey(building, index, furniture);
      if (objectId && Number(cooldowns[objectId] || 0) > nowMs) blocked.push(objectId);
    }
  }
  return blocked;
}

function markAgentScriptedTargetFailure(agent, destination = null, reason = 'scripted-target-failed', nowMs = Date.now()) {
  const objectId = destination?.objectId || destination?.target?.id || null;
  if (!objectId) return;
  const memory = getAgentScriptedMemory(agent);
  memory.failedTargets = [{ objectId, lastFailedAtMs: nowMs, reason }, ...(memory.failedTargets || []).filter(entry => String(entry.objectId) !== String(objectId))].slice(0, 24);
}

function getAgentScriptedResolverState(agent) {
  const memory = getAgentScriptedMemory(agent);
  return {
    recentCategories: memory.recentCategories || [],
    recentObjects: memory.recentObjects || [],
    failedTargets: memory.failedTargets || [],
  };
}

function randomRangeFromPair(range, fallback = 0) {
  const min = Number(Array.isArray(range) ? range[0] : fallback) || 0;
  const max = Number(Array.isArray(range) ? range[1] : min) || min;
  return min + Math.random() * Math.max(0, max - min);
}

function getActiveScriptedIdlePulseRules() {
  return VO_STYLE_IDLE_TEST ? VO_STYLE_IDLE_PULSE_RULES : SCRIPTED_IDLE_PULSE_RULES;
}

function getVOStyleIdleIndoorWanderTarget(agent, building) {
  if (!agent || !building) return null;
  const floor = getAgentFloor(agent, building);
  for (let attempt = 0; attempt < 16; attempt++) {
    const angle = Math.random() * Math.PI * 2;
    const dist = API_TILE * (1.4 + Math.random() * 4.2);
    const x = (Number(agent.x) || 0) + Math.cos(angle) * dist;
    const y = (Number(agent.y) || 0) + Math.sin(angle) * dist;
    if (isPointInsideBuildingInterior(building, x, y, -0.2)) {
      return { x, y, floor, buildingFloor: floor, buildingId: building.id || null, targetKind: 'vo-style-idle-wander' };
    }
  }
  const door = getBuildingDoorPosAPI(building);
  if (door) return { x: door.x, y: door.y, floor, buildingFloor: floor, buildingId: building.id || null, targetKind: 'vo-style-idle-wander' };
  return null;
}

function resetAgentScriptedIdlePulseTimer(agent, delayRange = getActiveScriptedIdlePulseRules().initialDelayMs, nowMs = Date.now()) {
  if (!agent) return null;
  const delayMs = randomRangeFromPair(delayRange, 60_000);
  agent._nextScriptedIdlePulseAtMs = nowMs + delayMs;
  agent._lastScriptedIdlePulseDelayMs = delayMs;
  return agent._nextScriptedIdlePulseAtMs;
}

// ── Needs/personality-driven idle autonomy (v2) ───────────────────────────
// Idle category selection is driven by per-agent need meters
// (thirst/hunger/energy/social/boredom) and 3 personality traits
// (outgoing/curious/easygoing) via the trait matrices in
// agent-needs-personality.mjs. Satisfaction follows each object's `satisfies`
// contract (resolveObjectSatisfies), not activity-name matching.
// Old static-weight behavior stays one flag away.
const NEEDS_DRIVEN_IDLE = true;
const NEEDS_DRIFT_TICK_MS = 1000;
const SCRIPTED_DECISION_OBJECT_SCAN_LIMIT = 5;

function getAgentNeedsState(agent) {
  if (!agent._needs || !agent._needs.values) agent._needs = createNeedsState(Date.now(), agent.id || agent.name || '');
  return migrateNeedsState(agent._needs);
}

function getAgentPersonality(agent) {
  if (agent._personality) return agent._personality;
  const saved = agent.personality || agent._profilePersonality || null;
  agent._personality = saved ? clampPersonality(saved) : seededDefaultPersonality(agent.id || agent.name || '');
  agent._personalitySource = saved ? 'profile' : 'seeded-default';
  return agent._personality;
}

function setAgentPersonality(agent, raw) {
  agent._personality = clampPersonality(raw);
  agent._personalitySource = 'profile';
  return agent._personality;
}

// Resolve the placed furniture item an idle activity is using, so satisfaction
// can follow the object's `satisfies` contract (SERVICE_QUEUE_SPEC sibling rule:
// objects declare what they do; the runtime never guesses from names).
function needsActivityObjectInfo(activity = null) {
  if (!activity) return { objectType: null, item: null };
  const temporaryItem = activity.temporaryItem || activity.carriedItem || null;
  if (temporaryItem && (Array.isArray(temporaryItem.satisfies) || Array.isArray(temporaryItem.lifecycle?.satisfies))) {
    return { objectType: temporaryItem.sourceFurnitureType || temporaryItem.objectType || activity.furnitureType || activity.objectType || null, item: temporaryItem };
  }
  const objectType = activity.furnitureType || activity.objectType || null;
  const building = activity.buildingId ? buildingsMap.get(activity.buildingId) : null;
  const item = building && activity.furnitureIndex != null ? (building.interior?.furniture?.[activity.furnitureIndex] || null) : null;
  return { objectType: objectType || item?.type || null, item };
}

// Per-frame: drift needs + watch for activity completion to satisfy them.
function updateAgentNeedsRuntime(agent, dtMs, nowMs = Date.now()) {
  if (!NEEDS_DRIVEN_IDLE || !agent) return;
  const state = getAgentNeedsState(agent);
  agent._needsDriftAccumMs = (agent._needsDriftAccumMs || 0) + dtMs;
  if (agent._needsDriftAccumMs >= NEEDS_DRIFT_TICK_MS) {
    const accumulated = agent._needsDriftAccumMs;
    agent._needsDriftAccumMs = 0;
    const moving = !!agent._wanderTarget;
    const nearAgents = !!(agent._socialState || agent._idleActivity?.kind === 'scripted-socialize' || agent._meetingId);
    updateNeedsDrift(state, accumulated, { moving, nearAgents, personality: getAgentPersonality(agent) });
  }
  // Completion watcher: activity ended this frame -> satisfy what the used
  // OBJECT declares (per-object satisfies contract; category fallback).
  const currentActivity = agent._idleActivity || null;
  const currentKind = currentActivity?.kind || null;
  const tracked = agent._needsTrackedActivity || null;
  if (currentKind) {
    const { objectType, item } = needsActivityObjectInfo(currentActivity);
    const category = currentActivity._needCategory || currentActivity.behaviorCategory || null;
    const satisfies = resolveObjectSatisfies(objectType, item) || (category ? needsForCategory(category) : null);
    if (satisfies?.length) {
      agent._needsTrackedActivity = { kind: currentKind, category, objectType, satisfies };
    }
  } else if (tracked) {
    satisfyNeedsForActivity(state, { category: tracked.category, objectType: tracked.objectType, item: { satisfies: tracked.satisfies }, nowMs });
    agent._lastSatisfiedNeedInfo = { ...tracked, atMs: nowMs };
    agent._needsTrackedActivity = null;
  }
}

function chooseScriptedIdlePulseCategory(agent, nowMs = Date.now()) {
  const scriptedState = getAgentScriptedResolverState(agent);
  const recentCategories = new Set((scriptedState.recentCategories || [])
    .filter(entry => nowMs - Number(entry.lastUsedAtMs || 0) < SCRIPTED_BEHAVIOR_FALLBACK_CONSTANTS.categoryCooldownMs)
    .map(entry => String(entry.category || '')));
  if (NEEDS_DRIVEN_IDLE) {
    return chooseNeedDrivenCategory(getAgentNeedsState(agent), getAgentPersonality(agent), { recentCategories });
  }
  const entries = Object.entries(getActiveScriptedIdlePulseRules().categoryWeights)
    .map(([category, weight]) => ({ category, weight: recentCategories.has(category) ? weight * 0.35 : weight }))
    .filter(entry => entry.weight > 0);
  const total = entries.reduce((sum, entry) => sum + entry.weight, 0);
  let roll = Math.random() * total;
  for (const entry of entries) {
    roll -= entry.weight;
    if (roll <= 0) return entry.category;
  }
  return entries[0]?.category || 'work-return';
}

// Need-aware fallback order: categories sorted by current desire instead of
// the old fixed list that always tried snack-drink first.
function getScriptedIdlePulseCategoryOrder(agent, nowMs = Date.now()) {
  const first = chooseScriptedIdlePulseCategory(agent, nowMs);
  if (!NEEDS_DRIVEN_IDLE) {
    return VO_STYLE_IDLE_TEST
      ? [first, 'snack-drink', 'socialize', 'rest', 'browse-read', 'play', 'wander', 'work-return']
      : [first, 'snack-drink', 'browse-read', 'rest', 'play', 'socialize', 'work-return'];
  }
  const scriptedState = getAgentScriptedResolverState(agent);
  const recentCategories = new Set((scriptedState.recentCategories || [])
    .filter(entry => nowMs - Number(entry.lastUsedAtMs || 0) < SCRIPTED_BEHAVIOR_FALLBACK_CONSTANTS.categoryCooldownMs)
    .map(entry => String(entry.category || '')));
  const state = getAgentNeedsState(agent);
  const personality = getAgentPersonality(agent);
  // Rank fallback categories by the served needs' levels (max of multi-need
  // categories like snack-drink) using the same v2 multi-need contract as the
  // weighted roll, so fallbacks chase the same desires the roll does.
  const ranked = ['snack-drink', 'socialize', 'rest', 'browse-read', 'play', 'wander']
    .map(category => {
      const served = needsForCategory(category) || [];
      const level = served.length ? Math.max(...served.map(need => Number(state.values?.[need] || 0))) : 0;
      let score = served.length ? level : 3;
      if (recentCategories.has(category)) score *= 0.35;
      return { category, score };
    })
    .sort((a, b) => b.score - a.score)
    .map(entry => entry.category);
  return [first, ...ranked, 'wander', 'work-return'];
}

function getScriptedStandingActivityMode(activity = {}, category = null, objectType = null) {
  if (activity.mode) return activity.mode;
  if (category === 'browse-read') return activity.kind?.includes('read') ? 'read' : (activity.kind?.includes('inspect') ? 'inspect' : 'browse');
  if (objectType === 'cafeCounter' || objectType === 'foodTruckCounter' || objectType === 'checkoutCounter' || objectType === 'checkoutRegister') return 'customer';
  if (objectType === 'kitchenIsland' || objectType === 'counter') return 'use';
  return 'use';
}

function getScriptedResolverAgentSnapshot(agent, anchorBuilding = null) {
  return {
    ...agent,
    buildingId: anchorBuilding?.id || agent?.buildingId || agent?._currentBuilding?.id || null,
    floor: getAgentFloor(agent, anchorBuilding),
    // The resolver works in world-tile coordinates; runtime movement uses API pixels.
    x: (Number(agent?.x) || 0) / API_TILE,
    z: (Number(agent?.y) || 0) / API_TILE,
  };
}

function getScriptedResolverAgentList(agents = [], anchorBuilding = null) {
  return (agents || []).map(agent => getScriptedResolverAgentSnapshot(agent, anchorBuilding));
}

function getScriptedDecisionCategoryNeeds(category) {
  return needsForCategory(category) || [];
}

function getScriptedDecisionNeedLevel(agent, need) {
  const values = getAgentNeedsState(agent)?.values || {};
  return Number(values?.[need] || 0) || 0;
}

function getScriptedDecisionObjectType(item = {}) {
  return normalizeObjectCatalogId(item.catalogId || item.objectCatalogId || item.type || item.assetId) || item.type || item.assetId || 'unknown';
}

function getScriptedDecisionObjectNeeds(item = {}) {
  const type = getScriptedDecisionObjectType(item);
  return resolveObjectSatisfies(type, item) || [];
}

function getScriptedDecisionObjectWorldPoint(building = null, item = {}) {
  if (!building || !item) return null;
  const localX = Number(item.x ?? item.localX ?? item.position?.x);
  const localZ = Number(item.z ?? item.y ?? item.localZ ?? item.position?.z ?? item.position?.y);
  if (!Number.isFinite(localX) || !Number.isFinite(localZ)) return null;
  try {
    const world = getBuildingWorldPoint(building, localX, localZ);
    return { x: Number(world?.x ?? localX), y: Number(world?.z ?? world?.y ?? localZ) };
  } catch (error) {
    return { x: localX, y: localZ };
  }
}

function scoreScriptedDecisionObject({ agent, building, item, index, category, preferredTypes, nowMs }) {
  if (!item) return null;
  const type = getScriptedDecisionObjectType(item);
  const preferred = !preferredTypes?.size || preferredTypes.has(type) || preferredTypes.has(item.type) || preferredTypes.has(item.catalogId);
  const categoryNeeds = getScriptedDecisionCategoryNeeds(category);
  const objectNeeds = getScriptedDecisionObjectNeeds(item);
  const needMatches = !categoryNeeds.length || objectNeeds.some(need => categoryNeeds.includes(need));
  if (!preferred && !needMatches) return null;

  const objectId = item.id || item.instanceId || item.objectInstanceId || `${building?.id || 'building'}:${index}`;
  const recentObjects = getAgentScriptedResolverState(agent).recentObjects || [];
  const recentlyUsed = recentObjects.some(entry =>
    String(entry.objectId || entry.id || entry.key || '') === String(objectId) &&
    nowMs - Number(entry.lastUsedAtMs || entry.atMs || 0) < SCRIPTED_BEHAVIOR_FALLBACK_CONSTANTS.objectCooldownMs);
  const failedTargets = getAgentScriptedResolverState(agent).failedTargets || [];
  const recentlyFailed = failedTargets.some(entry =>
    String(entry.objectId || entry.id || entry.key || '') === String(objectId) &&
    nowMs - Number(entry.lastFailedAtMs || entry.failedAtMs || entry.atMs || 0) < SCRIPTED_BEHAVIOR_FALLBACK_CONSTANTS.failedTargetThrottleMs);
  if (recentlyFailed) return null;

  const needScore = objectNeeds.length
    ? Math.max(...objectNeeds.map(need => getScriptedDecisionNeedLevel(agent, need)))
    : (categoryNeeds.length ? Math.max(...categoryNeeds.map(need => getScriptedDecisionNeedLevel(agent, need))) * 0.4 : 0);
  const point = getScriptedDecisionObjectWorldPoint(building, item);
  const distance = point ? Math.hypot((agent?.x || 0) - point.x, (agent?.y || 0) - point.y) : API_TILE * 10;
  const distanceScore = Math.max(0, 24 - distance / Math.max(1, API_TILE));
  const randomScore = Math.random() * 12;
  const typeScore = preferred ? 28 : 0;
  const needFitScore = needMatches ? 34 : 0;
  const recencyPenalty = recentlyUsed ? 18 : 0;
  return {
    index,
    item,
    type,
    objectId,
    score: needScore + distanceScore + randomScore + typeScore + needFitScore - recencyPenalty,
    debug: { needScore, distanceScore, randomScore, typeScore, needFitScore, recencyPenalty, objectNeeds },
  };
}

function makeFocusedScriptedResolverBuildings(agent, anchorBuilding, category, preferredObjectTypes = [], { limit = SCRIPTED_DECISION_OBJECT_SCAN_LIMIT, nowMs = Date.now() } = {}) {
  if (!NEEDS_DRIVEN_IDLE || !anchorBuilding || limit <= 0 || ['wander', 'work-return', 'sleep-home'].includes(category)) {
    return [anchorBuilding];
  }
  const furniture = anchorBuilding.interior?.furniture || [];
  if (furniture.length <= limit) return [anchorBuilding];
  const preferredTypes = new Set((preferredObjectTypes || []).map(type => normalizeObjectCatalogId(type) || type).filter(Boolean));
  const scored = furniture
    .map((item, index) => scoreScriptedDecisionObject({ agent, building: anchorBuilding, item, index, category, preferredTypes, nowMs }))
    .filter(Boolean)
    .sort((a, b) => b.score - a.score)
    .slice(0, limit);
  if (!scored.length) {
    agent._lastScriptedFocusedResolver = { category, limit, originalCount: furniture.length, focusedCount: 0, fallback: 'no-focused-candidates', atMs: nowMs };
    return [anchorBuilding];
  }
  const focusedFurniture = [];
  for (const entry of scored) focusedFurniture[entry.index] = entry.item;
  const focusedBuilding = {
    ...anchorBuilding,
    interior: { ...(anchorBuilding.interior || {}), furniture: focusedFurniture },
    furniture: focusedFurniture,
  };
  agent._lastScriptedFocusedResolver = {
    category,
    limit,
    originalCount: furniture.length,
    focusedCount: scored.length,
    candidates: scored.map(entry => ({
      index: entry.index,
      type: entry.type,
      objectId: entry.objectId,
      score: Number(entry.score.toFixed(2)),
      needs: entry.debug.objectNeeds,
    })),
    atMs: nowMs,
  };
  return [focusedBuilding];
}

function scriptedLocalPointToRuntimePoint(point = null, building = null) {
  if (!point || typeof point !== 'object') return point;
  const next = { ...point };
  const localX = Number(next.x);
  const localZ = Number(next.y ?? next.z);
  const bw = Number(building?.widthTiles || 25) || 25;
  const bd = Number(building?.heightTiles || 17) || 17;
  const baseX = Number(building?.worldX ?? building?.x ?? 0) || 0;
  const baseZ = Number(building?.worldY ?? building?.z ?? 0) || 0;
  const rot = ((Number(building?._rotation || 0) % 360) + 360) % 360;
  let worldX = localX;
  let worldZ = localZ;
  if (building && Number.isFinite(localX) && Number.isFinite(localZ)) {
    if (rot === 90) {
      worldX = baseX + bd - localZ;
      worldZ = baseZ + localX;
    } else if (rot === 180) {
      worldX = baseX + bw - localX;
      worldZ = baseZ + bd - localZ;
    } else if (rot === 270) {
      worldX = baseX + localZ;
      worldZ = baseZ + bw - localX;
    } else {
      worldX = baseX + localX;
      worldZ = baseZ + localZ;
    }
  }
  if (Number.isFinite(worldX)) next.x = worldX * API_TILE;
  if (Number.isFinite(worldZ)) {
    if ('z' in next && !('y' in next)) next.z = worldZ * API_TILE;
    else next.y = worldZ * API_TILE;
  }
  next.coordinateSpace = 'api-pixels';
  return next;
}

function scaleScriptedRuntimeSlot(slot = null, building = null) {
  if (!slot || typeof slot !== 'object') return slot;
  const next = { ...slot };
  for (const key of ['position', 'approachTarget', 'activationTarget']) {
    if (next[key]) next[key] = scriptedLocalPointToRuntimePoint(next[key], building);
  }
  for (const key of ['approachSpot', 'activationSpot']) {
    if (next[key]) next[key] = {
      ...next[key],
      position: scriptedLocalPointToRuntimePoint(next[key].position || next[key], building),
      world: scriptedLocalPointToRuntimePoint(next[key].world || null, building),
      buildingLocal: next[key].buildingLocal || null,
    };
  }
  return next;
}

function clampRuntimePointToBuilding(point = null, building = null) {
  if (!point || !building || !Number.isFinite(Number(point.x)) || !Number.isFinite(Number(point.y ?? point.z))) return point;
  const worldX = Number(point.x) / API_TILE;
  const worldZ = Number(point.y ?? point.z) / API_TILE;
  const bw = Number(building?.widthTiles || 25) || 25;
  const bd = Number(building?.heightTiles || 17) || 17;
  const baseX = Number(building?.worldX ?? building?.x ?? 0) || 0;
  const baseZ = Number(building?.worldY ?? building?.z ?? 0) || 0;
  const rot = ((Number(building?._rotation || 0) % 360) + 360) % 360;
  const relX = worldX - baseX;
  const relZ = worldZ - baseZ;
  let local = { x: relX, z: relZ };
  if (rot === 90) local = { x: relZ, z: bd - relX };
  else if (rot === 180) local = { x: bw - relX, z: bd - relZ };
  else if (rot === 270) local = { x: bw - relZ, z: relX };
  const margin = 0.35;
  const clampedLocal = {
    x: Math.max(margin, Math.min((building.widthTiles || 25) - margin, local.x)),
    z: Math.max(margin, Math.min((building.heightTiles || 17) - margin, local.z)),
  };
  if (Math.abs(clampedLocal.x - local.x) < 0.001 && Math.abs(clampedLocal.z - local.z) < 0.001) return point;
  const next = scriptedLocalPointToRuntimePoint({ ...point, x: clampedLocal.x, ...('z' in point && !('y' in point) ? { z: clampedLocal.z } : { y: clampedLocal.z }) }, building);
  next.clampedFrom = { x: point.x, y: point.y ?? point.z };
  return next;
}

function clampScriptedRuntimeSlot(slot = null, building = null) {
  if (!slot || typeof slot !== 'object') return slot;
  const next = { ...slot };
  for (const key of ['position', 'approachTarget', 'activationTarget']) {
    if (next[key]) next[key] = clampRuntimePointToBuilding(next[key], building);
  }
  for (const key of ['approachSpot', 'activationSpot']) {
    if (next[key]) next[key] = {
      ...next[key],
      position: clampRuntimePointToBuilding(next[key].position || null, building),
      world: clampRuntimePointToBuilding(next[key].world || null, building),
      buildingLocal: next[key].buildingLocal || null,
    };
  }
  return next;
}

function scaleScriptedDestinationForRuntime(destination = null, building = null) {
  if (!destination || destination.runtimeCoordinateSpace === 'api-pixels') return destination;
  const next = JSON.parse(JSON.stringify(destination));
  next.runtimeCoordinateSpace = 'api-pixels';
  if (next.spot) next.spot = clampRuntimePointToBuilding(scriptedLocalPointToRuntimePoint(next.spot, building), building);
  if (next.spot?.clampedFrom) return null;
  if (next.objectUseSlot) next.objectUseSlot = clampScriptedRuntimeSlot(scaleScriptedRuntimeSlot(next.objectUseSlot, building), building);
  if (next.objectUseSlot?.position?.clampedFrom || next.objectUseSlot?.approachSpot?.position?.clampedFrom || next.objectUseSlot?.activationSpot?.position?.clampedFrom) return null;
  if (next.objectUse?.slot) next.objectUse.slot = clampScriptedRuntimeSlot(scaleScriptedRuntimeSlot(next.objectUse.slot, building), building);
  if (next.objectUse?.slot?.position?.clampedFrom || next.objectUse?.slot?.approachSpot?.position?.clampedFrom || next.objectUse?.slot?.activationSpot?.position?.clampedFrom) return null;
  return next;
}

function createScriptedObjectUseForDestination(destination, activity = null) {
  if (!destination) return null;
  const slot = destination.objectUseSlot || destination.objectUse?.slot || null;
  if (destination.lifecycle === 'seat') {
    if (!slot?.seatId) return null;
    return {
      lifecycle: 'seat',
      slot,
      actionId: slot.actionId || activity?.action || destination.spot?.actionId || `scripted.${destination.category || 'rest'}`,
      activityKind: activity?.kind || null,
      animationId: activity?.animationId || null,
      dockSnapRadius: activity?.dockSnapRadius || 7,
      stayMs: randomRangeMs(activity?.stayMs, 10000 + Math.random() * 10000),
      seatSurfaceLift: getFurnitureSeatSurfaceLift(destination.objectType),
    };
  }
  if (destination.lifecycle === 'queue-wait') {
    const queueSpot = destination.spot || slot || null;
    if (!queueSpot) return null;
    const queueTargetId = queueSpot.slotId || queueSpot.spotId || 'queue-wait:0';
    const queueSpotId = queueSpot.queueSpotId || queueSpot.interactionSpotId || String(queueTargetId).replace(/:\d+$/, '') || 'queue-wait';
    return {
      lifecycle: 'queue',
      slot: {
        ...queueSpot,
        slotId: queueTargetId,
        queueSpotId,
        queueTargetId,
        activationSpotId: queueTargetId,
        position: { x: queueSpot.x, z: queueSpot.y ?? queueSpot.z, floor: queueSpot.floor || destination.floor || 1 },
      },
      actionId: activity?.action || destination.spot?.actionId || `scripted.${destination.category || 'service'}.queue`,
      activityKind: 'service-queue-wait',
      animationId: activity?.queueAnimationId || 'bus-stop-wait',
      dockSnapRadius: activity?.dockSnapRadius || 6,
      stayMs: 3500 + Math.random() * 2500,
    mode: 'queue-wait',
    queueUse: true,
    };
  }
  if (destination.lifecycle === 'standing') {
    if (!slot?.slotId && !slot?.activationSpotId) return null;
    return {
      lifecycle: 'standing',
      slot,
      actionId: slot.actionId || activity?.action || destination.spot?.actionId || `scripted.${destination.category || 'standing'}`,
      activityKind: activity?.kind || `${String(destination.objectType || 'object').replace(/([a-z])([A-Z])/g, '$1-$2').toLowerCase()}-${destination.category === 'browse-read' ? 'browse' : 'use'}`,
      animationId: activity?.animationId || slot.pose?.animationId || (destination.category === 'browse-read' ? 'inspect-browse' : null),
      dockSnapRadius: activity?.dockSnapRadius || slot.activation?.snapRadius || 6,
      stayMs: randomRangeMs(activity?.stayMs, slot.completion?.durationMs || 9000),
      mode: getScriptedStandingActivityMode(activity || {}, destination.category, destination.objectType),
      standingUse: true,
    };
  }
  return null;
}

function submitScriptedSeatingBehavior(agent, anchorBuilding, workTarget = null) {
  if (!agent || !anchorBuilding) return false;
  let buildingList = [anchorBuilding];
  const minuteOfDay = Math.floor((_gameHour || 12) * 60) % 1440;
  const scriptedState = getAgentScriptedResolverState(agent);
  const preferences = getAgentScriptedBehaviorPreferences(agent, { objectTypes: ['couch', 'loveseat', 'sectionalSofa', 'armchair', 'hallwayBench', 'smallCafeTable', 'outdoorCafeTable', 'picnicTable', 'patioTable', 'smallRoundMeetingTable', 'diningChair', 'patioChair'], objectCooldownMs: 180000 });
  const decision = selectScriptedBehaviorCategory({
    minuteOfDay,
    availableCategories: ['rest', 'socialize', 'work-return', 'wander'],
    candidateObjectByCategory: { rest: { objectId: anchorBuilding.id }, socialize: { objectId: anchorBuilding.id } },
    preferences,
    recentCategories: scriptedState.recentCategories,
    recentObjects: scriptedState.recentObjects,
  });
  if (!['rest', 'socialize'].includes(decision.category)) return false;
  buildingList = makeFocusedScriptedResolverBuildings(agent, anchorBuilding, decision.category, preferences.objectTypes || preferences.preferredObjectTypes || [], { nowMs: Date.now() });
  let destination = resolveBehaviorDestination({
    category: decision.category,
    agent: getScriptedResolverAgentSnapshot(agent, anchorBuilding),
    buildings: buildingList,
    agents: getScriptedResolverAgentList(agentsList, anchorBuilding),
    reservations: collectScriptedSeatReservationsForResolver(buildingList),
    occupiedSpots: collectScriptedOccupiedSeatIdsForResolver(buildingList, { excludeAgent: agent }),
    preferences,
    recentObjects: scriptedState.recentObjects,
    blockedObjectIds: collectBlockedScriptedServiceObjectIds(agent, buildingList),
    failedTargets: scriptedState.failedTargets,
    failedTargetThrottleMs: SCRIPTED_BEHAVIOR_FALLBACK_CONSTANTS.failedTargetThrottleMs,
    queueing: {},
    proximity: { socialMaxDistance: 5 },
    actionSpots: ACTION_SPOTS,
    interactionSpots: FURNITURE_INTERACTION_SPOTS,
  });
  destination = scaleScriptedDestinationForRuntime(destination, anchorBuilding);
  if (!destination?.ok || destination.target?.kind !== 'furniture') return false;
  const furniture = anchorBuilding.interior?.furniture?.[destination.target.furnitureIndex];
  const activity = getLocalIdleActivityConfig(furniture?.type) || null;
  const objectUse = createScriptedObjectUseForDestination(destination, activity);
  if (destination.lifecycle === 'seat' && !objectUse) return false;
  const proposal = createAgentScriptedBehaviorProposal(agent, {
    category: decision.category,
    destination,
    building: anchorBuilding,
    floor: destination.floor || getAgentFloor(agent, anchorBuilding),
    decision,
    reason: 'phase-4-task-10-scripted-seating-pass',
    objectUse,
  });
  const route = submitAgentScriptedBehaviorProposal(agent, proposal);
  if (route?.accepted === false) { markAgentScriptedTargetFailure(agent, destination, route.reason || 'agent-intent-rejected'); return false; }
  markAgentScriptedChoice(agent, decision.category, destination);
  if (agent._idleActivity && objectUse) {
    agent._idleActivity.kind = objectUse.activityKind || activity?.kind || agent._idleActivity.kind;
    agent._idleActivity.stayMs = objectUse.stayMs || decision.durationMs;
    agent._idleActivity.animationId = objectUse.animationId || activity?.animationId || null;
    agent._idleActivity.dockSnapRadius = objectUse.dockSnapRadius || activity?.dockSnapRadius || agent._idleActivity.dockSnapRadius || 7;
    agent._idleActivity.seatSurfaceLift = objectUse.seatSurfaceLift;
    agent._idleActivity.forceDeskReturn = rollIdleDeskReturnAfterActivity(workTarget);
  }
  agent._wanderTimer = 1000 + Math.random() * 1600;
  return true;
}

function submitScriptedStandingUseBehavior(agent, anchorBuilding, workTarget = null) {
  if (!agent || !anchorBuilding) return false;
  let buildingList = [anchorBuilding];
  const minuteOfDay = Math.floor((_gameHour || 12) * 60) % 1440;
  const scriptedState = getAgentScriptedResolverState(agent);
  const decision = selectScriptedBehaviorCategory({
    minuteOfDay,
    availableCategories: ['snack-drink', 'browse-read', 'wander', 'work-return'],
    candidateObjectByCategory: { 'snack-drink': { objectId: anchorBuilding.id }, 'browse-read': { objectId: anchorBuilding.id } },
    preferences: getAgentScriptedBehaviorPreferences(agent),
    recentCategories: scriptedState.recentCategories,
    recentObjects: scriptedState.recentObjects,
  });
  if (!['snack-drink', 'browse-read'].includes(decision.category)) return false;
  const preferredObjectTypes = decision.category === 'snack-drink'
    ? ['coffeeMachine', 'countertopCoffeeMachine', 'vending', 'fridge', 'microwave', 'cafeCounter', 'foodTruckCounter', 'coffeePickupShelf', 'counter', 'kitchenIsland', 'pantryShelf', 'displayCase']
    : ['bookshelf', 'shopShelf', 'pantryShelf', 'bulletinBoard', 'menuBoard', 'whiteboard', 'wallArt', 'supplyCabinet', 'medicalSupplyCabinet', 'storageBoxes', 'displayCase'];
  const preferences = getAgentScriptedBehaviorPreferences(agent, { objectTypes: preferredObjectTypes, objectCooldownMs: 120000 });
  buildingList = makeFocusedScriptedResolverBuildings(agent, anchorBuilding, decision.category, preferences.objectTypes || preferences.preferredObjectTypes || preferredObjectTypes, { nowMs: Date.now() });
  let destination = resolveBehaviorDestination({
    category: decision.category,
    agent: getScriptedResolverAgentSnapshot(agent, anchorBuilding),
    buildings: buildingList,
    agents: getScriptedResolverAgentList(agentsList, anchorBuilding),
    reservations: collectScriptedSeatReservationsForResolver(buildingList),
    occupiedSpots: collectScriptedOccupiedSeatIdsForResolver(buildingList, { excludeAgent: agent }),
    preferences,
    recentObjects: scriptedState.recentObjects,
    blockedObjectIds: collectBlockedScriptedServiceObjectIds(agent, buildingList),
    failedTargets: scriptedState.failedTargets,
    failedTargetThrottleMs: SCRIPTED_BEHAVIOR_FALLBACK_CONSTANTS.failedTargetThrottleMs,
    queueing: { default: true }, // SERVICE_QUEUE_SPEC.md: queueing is per-object capability, not per category
    actionSpots: ACTION_SPOTS,
    interactionSpots: FURNITURE_INTERACTION_SPOTS,
  });
  destination = scaleScriptedDestinationForRuntime(destination, anchorBuilding);
  if (!destination?.ok || destination.target?.kind !== 'furniture' || !['standing', 'queue-wait'].includes(destination.lifecycle)) return false;
  const furniture = anchorBuilding.interior?.furniture?.[destination.target.furnitureIndex];
  const activity = getLocalIdleActivityConfig(furniture?.type) || null;
  const objectUse = createScriptedObjectUseForDestination(destination, activity);
  if (['standing', 'queue-wait'].includes(destination.lifecycle) && !objectUse) return false;
  const proposal = createAgentScriptedBehaviorProposal(agent, {
    category: decision.category,
    destination,
    building: anchorBuilding,
    floor: destination.floor || getAgentFloor(agent, anchorBuilding),
    decision,
    reason: 'phase-4-task-11-scripted-standing-use-pass',
    objectUse,
  });
  const route = submitAgentScriptedBehaviorProposal(agent, proposal);
  if (route?.accepted === false) { markAgentScriptedTargetFailure(agent, destination, route.reason || 'agent-intent-rejected'); return false; }
  markAgentScriptedChoice(agent, decision.category, destination);
  if (agent._idleActivity && objectUse) {
    agent._idleActivity.kind = objectUse.activityKind || activity?.kind || agent._idleActivity.kind;
    agent._idleActivity.mode = objectUse.mode || agent._idleActivity.mode;
    agent._idleActivity.stayMs = objectUse.stayMs || decision.durationMs;
    agent._idleActivity.animationId = objectUse.animationId || activity?.animationId || null;
    agent._idleActivity.dockSnapRadius = objectUse.dockSnapRadius || activity?.dockSnapRadius || agent._idleActivity.dockSnapRadius || 6;
    agent._idleActivity.furnitureType = destination.objectType || furniture?.type || agent._idleActivity.furnitureType;
    agent._idleActivity.isServiceQueueWait = objectUse.lifecycle === 'queue';
    agent._idleActivity.queuedAtMs = objectUse.lifecycle === 'queue' ? (route.objectUse?.reservation?.queuedAtMs || Date.now()) : agent._idleActivity.queuedAtMs;
    agent._idleActivity.queueSpotId = objectUse.lifecycle === 'queue' ? (objectUse.slot?.queueSpotId || objectUse.slot?.slotId || null) : agent._idleActivity.queueSpotId;
    agent._idleActivity.activationSpotId = objectUse.slot?.activationSpotId || agent._idleActivity.activationSpotId;
    agent._idleActivity.approachSpotId = objectUse.slot?.approachSpotId || agent._idleActivity.approachSpotId;
    agent._idleActivity.activeUseSlotId = objectUse.slot?.slotId || agent._idleActivity.activeUseSlotId;
    agent._idleActivity.capacityKey = objectUse.slot?.capacityKey || agent._idleActivity.capacityKey;
    agent._idleActivity.faceAngle = objectUse.slot?.pose?.facingAngleRad ?? agent._idleActivity.faceAngle;
    agent._idleActivity.dockTarget = objectUse.slot?.activationSpot?.position ? { x: objectUse.slot.activationSpot.position.x, y: objectUse.slot.activationSpot.position.z } : agent._idleActivity.dockTarget;
    agent._idleActivity.forceDeskReturn = rollIdleDeskReturnAfterActivity(workTarget);
  }
  agent._wanderTimer = 1000 + Math.random() * 1600;
  return true;
}

function scriptedProximityCooldowns(agent) {
  if (!agent._scriptedProximityCooldowns) agent._scriptedProximityCooldowns = {};
  return agent._scriptedProximityCooldowns;
}

function scriptedProximityCooldownReady(agent, key, cooldownMs, nowMs = Date.now()) {
  const last = Number(scriptedProximityCooldowns(agent)[key] || 0);
  return !last || nowMs - last >= cooldownMs;
}

function markScriptedProximityCooldown(agent, key, nowMs = Date.now()) {
  scriptedProximityCooldowns(agent)[key] = nowMs;
}

function isAgentEligibleForScriptedProximity(agent, anchorBuilding = null, { allowIdleIntent = false } = {}) {
  if (!agent || isWorkPresenceStatus(agent.status) || agent._atDesk || agent._tagState?.playing || agent._curInteraction) return false;
  syncAgentIntentFromLifecycle(agent);
  const activeIntent = agent._agentIntent || null;
  if (isAgentIntentActive(activeIntent)) {
    const sourceKind = activeIntent.behavior?.behaviorSourceKind || activeIntent.behaviorSourceKind || null;
    if (activeIntent.priorityName === 'manual' || sourceKind === 'user') return false;
    if (sourceKind === 'agent-live-mode' || activeIntent.priorityName === 'explicit-object') return false;
    if (!allowIdleIntent && activeIntent.priorityName === 'idle') return false;
  }
  if (agent._idleActivity && !allowIdleIntent) return false;
  if (!anchorBuilding) return true;
  const currentBuilding = getMovementInteriorBuildingAt(agent.x, agent.y) || agent._currentBuilding || null;
  return currentBuilding?.id === anchorBuilding.id || isPointInsideBuildingInterior(anchorBuilding, agent.x, agent.y, -0.15);
}

function getScriptedProximityAgents(anchorBuilding, excludeAgent = null, options = {}) {
  return agentsList.filter(candidate => candidate && candidate !== excludeAgent && isAgentEligibleForScriptedProximity(candidate, anchorBuilding, options));
}

function createScriptedActiveObjectUseForDestination(destination, activity = null) {
  const slot = destination?.objectUseSlot || destination?.objectUse?.slot || null;
  if (!slot?.slotId && !slot?.activationSpotId) return null;
  return {
    lifecycle: 'active',
    slot,
    actionId: slot.actionId || activity?.action || destination?.spot?.actionId || `scripted.${destination?.category || 'play'}`,
    activityKind: activity?.kind || `${String(destination?.objectType || 'play-object').replace(/([a-z])([A-Z])/g, '$1-$2').toLowerCase()}-play`,
    animationId: activity?.animationId || slot.pose?.animationId || 'play-game',
    dockSnapRadius: activity?.dockSnapRadius || slot.activation?.snapRadius || 7,
    stayMs: randomRangeMs(activity?.stayMs, SCRIPTED_PROXIMITY_BEHAVIOR_RULES.pingPong.durationMs[0] + Math.random() * 8000),
    mode: destination?.objectType === 'pingpong' ? SCRIPTED_PROXIMITY_BEHAVIOR_RULES.pingPong.waitingState : 'scripted-play',
    activeUse: true,
  };
}

function scriptedPlayObjectTypes() {
  return ['pingpong', 'poolTable', 'arcadeMachine', 'gamingStation', 'playgroundSlide', 'playgroundSwing', 'outdoorExerciseStation', 'treadmill', 'trainingMat', 'gymBench'];
}

function submitScriptedPlayObjectBehavior(agent, anchorBuilding, workTarget = null, { preferredObjectTypes = scriptedPlayObjectTypes(), reason = 'phase-4-task-12-scripted-play-proximity-pass', availableAgents = null } = {}) {
  if (!agent || !anchorBuilding) return false;
  const buildingList = [anchorBuilding];
  const scriptedState = getAgentScriptedResolverState(agent);
  let destination = resolveBehaviorDestination({
    category: 'play',
    agent: getScriptedResolverAgentSnapshot(agent, anchorBuilding),
    buildings: buildingList,
    agents: getScriptedResolverAgentList(availableAgents || getScriptedProximityAgents(anchorBuilding, agent), anchorBuilding),
    reservations: collectScriptedSeatReservationsForResolver(buildingList),
    occupiedSpots: collectScriptedOccupiedSeatIdsForResolver(buildingList, { excludeAgent: agent }),
    preferences: getAgentScriptedBehaviorPreferences(agent, { objectTypes: preferredObjectTypes, objectCooldownMs: 120000 }),
    recentObjects: scriptedState.recentObjects,
    failedTargets: scriptedState.failedTargets,
    failedTargetThrottleMs: SCRIPTED_BEHAVIOR_FALLBACK_CONSTANTS.failedTargetThrottleMs,
    queueing: { default: true }, // SERVICE_QUEUE_SPEC.md: queueing is per-object capability, not per category
    actionSpots: ACTION_SPOTS,
    interactionSpots: FURNITURE_INTERACTION_SPOTS,
  });
  destination = scaleScriptedDestinationForRuntime(destination, anchorBuilding);
  if (!destination?.ok || destination.target?.kind !== 'furniture' || !['active', 'queue-wait'].includes(destination.lifecycle)) return false;
  const furniture = anchorBuilding.interior?.furniture?.[destination.target.furnitureIndex];
  const activity = getLocalIdleActivityConfig(furniture?.type) || null;
  // queue-wait destinations need the queue objectUse builder, not the active one
  // (SERVICE_QUEUE_SPEC.md queue formation rule 1).
  const objectUse = destination.lifecycle === 'queue-wait'
    ? createScriptedObjectUseForDestination(destination, activity)
    : createScriptedActiveObjectUseForDestination(destination, activity);
  if (!objectUse) return false;
  const proposal = createAgentScriptedBehaviorProposal(agent, {
    category: 'play',
    destination,
    building: anchorBuilding,
    floor: destination.floor || getAgentFloor(agent, anchorBuilding),
    decision: { category: 'play', probability: preferredObjectTypes.includes('pingpong') ? SCRIPTED_PROXIMITY_BEHAVIOR_RULES.pingPong.recruitmentChance : 1, durationMs: objectUse.stayMs },
    reason,
    objectUse,
  });
  const route = submitAgentScriptedBehaviorProposal(agent, proposal);
  if (route?.accepted === false) { markAgentScriptedTargetFailure(agent, destination, route.reason || 'agent-intent-rejected'); return false; }
  markAgentScriptedChoice(agent, 'play', destination);
  if (agent._idleActivity && objectUse) {
    agent._idleActivity.kind = objectUse.activityKind;
    agent._idleActivity.mode = objectUse.mode;
    agent._idleActivity.stayMs = objectUse.stayMs;
    agent._idleActivity.animationId = objectUse.animationId;
    agent._idleActivity.dockSnapRadius = objectUse.dockSnapRadius;
    agent._idleActivity.furnitureType = destination.objectType || furniture?.type || agent._idleActivity.furnitureType;
    agent._idleActivity.activationSpotId = objectUse.slot?.activationSpotId || agent._idleActivity.activationSpotId;
    agent._idleActivity.approachSpotId = objectUse.slot?.approachSpotId || agent._idleActivity.approachSpotId;
    agent._idleActivity.activeUseSlotId = objectUse.slot?.slotId || agent._idleActivity.activeUseSlotId;
    agent._idleActivity.capacityKey = objectUse.slot?.capacityKey || agent._idleActivity.capacityKey;
    agent._idleActivity.faceAngle = objectUse.slot?.pose?.facingAngleRad ?? agent._idleActivity.faceAngle;
    agent._idleActivity.forceDeskReturn = rollIdleDeskReturnAfterActivity(workTarget);
  }
  return { route, destination, furniture, objectUse };
}

function submitScriptedPingPongRecruitment(agent, anchorBuilding, workTarget = null, nowMs = Date.now()) {
  const rules = SCRIPTED_PROXIMITY_BEHAVIOR_RULES.pingPong;
  if (!isPingPongEligibleIdleAgent(agent) || !isAgentEligibleForScriptedProximity(agent, anchorBuilding) || !scriptedProximityCooldownReady(agent, 'pingPongRecruitment', rules.recruitmentCooldownMs, nowMs)) return false;
  if (Math.random() >= rules.recruitmentChance) return false;
  const partners = getScriptedProximityAgents(anchorBuilding, agent)
    .filter(other => isPingPongEligibleIdleAgent(other) && scriptedProximityCooldownReady(other, 'pingPongRecruitment', rules.recruitmentCooldownMs, nowMs))
    .filter(other => Math.hypot((agent.x || 0) - (other.x || 0), (agent.y || 0) - (other.y || 0)) <= rules.partnerSearchRadius)
    .sort((a, b) => Math.hypot((agent.x || 0) - (a.x || 0), (agent.y || 0) - (a.y || 0)) - Math.hypot((agent.x || 0) - (b.x || 0), (agent.y || 0) - (b.y || 0)));
  const partner = partners[0] || null;
  if (!partner) return false;
  const first = submitScriptedPlayObjectBehavior(agent, anchorBuilding, workTarget, { preferredObjectTypes: ['pingpong'], reason: 'phase-4-task-12-pingpong-waiting-state-recruitment' });
  if (!first?.route?.accepted || first.destination?.objectType !== 'pingpong') return false;
  markScriptedProximityCooldown(agent, 'pingPongRecruitment', nowMs);
  const second = submitScriptedPlayObjectBehavior(partner, anchorBuilding, null, { preferredObjectTypes: ['pingpong'], reason: 'phase-4-task-12-pingpong-partner-recruited', availableAgents: [agent] });
  if (second?.route?.accepted) {
    markScriptedProximityCooldown(partner, 'pingPongRecruitment', nowMs);
    const table = first.furniture;
    const furnitureIndex = first.destination?.target?.furnitureIndex ?? second.destination?.target?.furnitureIndex ?? null;
    if (table && furnitureIndex != null) {
      startPingPongMatchOnTable(anchorBuilding, table, furnitureIndex, agent, partner, {
        mode: rules.waitingState,
        stayMs: randomRangeMs(rules.durationMs),
        source: 'scripted-recruitment',
      });
    }
  }
  return { accepted: true, partnerAccepted: Boolean(second?.route?.accepted), first, second, rule: rules };
}

function submitScriptedConversationProximity(agent, anchorBuilding, workTarget = null, nowMs = Date.now()) {
  const rules = SCRIPTED_PROXIMITY_BEHAVIOR_RULES.conversation;
  if (!isAgentEligibleForScriptedProximity(agent, anchorBuilding) || !scriptedProximityCooldownReady(agent, 'conversation', rules.cooldownMs, nowMs)) return false;
  if (Math.random() >= rules.triggerChance) return false;
  const social = getScriptedProximityAgents(anchorBuilding, agent, { allowIdleIntent: true })
    .map(other => ({ agent: other, dist: Math.hypot((agent.x || 0) - (other.x || 0), (agent.y || 0) - (other.y || 0)) }))
    .filter(entry => entry.dist >= API_TILE * 1.2 && entry.dist <= rules.proximityRadius)
    .sort((a, b) => a.dist - b.dist)[0] || getNearbyIdleConversationCandidate(agent, anchorBuilding, rules.proximityRadius);
  if (!social?.agent || !isAgentEligibleForScriptedProximity(social.agent, anchorBuilding, { allowIdleIntent: true })) return false;
  const point = buildReachableAgentApproachPoint(agent, social.agent, anchorBuilding, API_TILE * 1.45);
  const destination = { ok: true, category: 'socialize', lifecycle: 'social-agent', target: { kind: 'agent', id: social.agent.id || social.agent.name, buildingId: anchorBuilding.id }, spot: { spotId: 'conversation-proximity', x: point.x, y: point.y, floor: getAgentFloor(agent, anchorBuilding) }, buildingId: anchorBuilding.id, floor: getAgentFloor(agent, anchorBuilding), fallbackReason: null };
  const proposal = createAgentScriptedBehaviorProposal(agent, { category: 'socialize', destination, building: anchorBuilding, reason: 'phase-4-task-12-conversation-proximity-trigger', decision: { category: 'socialize', probability: rules.triggerChance, durationMs: randomRangeMs(rules.durationMs) } });
  const route = submitAgentScriptedBehaviorProposal(agent, proposal);
  if (route?.accepted === false) return false;
  agent._idleActivity.kind = 'conversation-proximity';
  agent._idleActivity.stayMs = proposal.decision.durationMs;
  agent._idleActivity.targetAgentId = social.agent.id || social.agent.name || null;
  agent._idleActivity.forceDeskReturn = rollIdleDeskReturnAfterActivity(workTarget);
  markScriptedProximityCooldown(agent, 'conversation', nowMs);
  return { accepted: true, route, social, rule: rules };
}

function countScriptedSocialApproachers(buildingId, furnitureIndex) {
  return agentsList.filter(agent => agent?._idleActivity?.behaviorCategory === 'socialize' && agent._idleActivity?.buildingId === buildingId && agent._idleActivity?.furnitureIndex === furnitureIndex).length;
}

function resolveScriptedSocialApproachDestination(agent, anchorBuilding, nearbySeated, rules) {
  const seatedActivity = nearbySeated?._idleActivity || {};
  const furnitureIndex = seatedActivity.furnitureIndex ?? null;
  const furniture = furnitureIndex != null ? anchorBuilding?.interior?.furniture?.[furnitureIndex] || null : null;
  const socialTypes = new Set(['couch', 'loveseat', 'sectionalSofa', 'smallCafeTable', 'outdoorCafeTable', 'picnicTable', 'patioTable', 'smallRoundMeetingTable']);
  const occupiedSocialSpots = collectScriptedOccupiedSeatIdsForResolver([anchorBuilding], { excludeAgent: agent })
    .filter(entry => String(entry.objectKey || entry.objectId || '') === String(furniture?.id || `${anchorBuilding.id}:${furnitureIndex}`) || String(entry.objectKey || entry.objectId || '') === `${anchorBuilding.id}:${furnitureIndex}`)
    .map(entry => entry.spotId || entry.interactionSpotId || entry.seatId || entry.slotId)
    .filter(Boolean);
  if (furniture && socialTypes.has(furniture.type) && countScriptedSocialApproachers(anchorBuilding.id, furnitureIndex) < rules.maxApproachersPerObject) {
    for (const spotId of rules.sofaCafeSpotIds) {
      if (occupiedSocialSpots.includes(spotId)) continue;
      const spot = getFurnitureActionSpot(anchorBuilding, furniture, spotId);
      if (!spot || spot.clampedFrom) continue;
      return {
        ok: true,
        category: 'socialize',
        lifecycle: 'social-spot',
        target: { kind: 'furniture', id: furniture.id || `${anchorBuilding.id}:${furnitureIndex}`, buildingId: anchorBuilding.id, furnitureIndex, objectType: furniture.type, catalogId: furniture.catalogId || furniture.type },
        spot: { spotId: spot.spotId || spotId, interactionSpotId: spot.spotId || spotId, x: spot.apiX, y: spot.apiZ, floor: spot.floor || getAgentFloor(agent, anchorBuilding) },
        objectId: furniture.id || `${anchorBuilding.id}:${furnitureIndex}`,
        objectType: furniture.type,
        buildingId: anchorBuilding.id,
        floor: spot.floor || getAgentFloor(agent, anchorBuilding),
        queueingIntended: false,
        fallbackReason: null,
      };
    }
  }
  let destination = resolveBehaviorDestination({
    category: 'socialize',
    agent: getScriptedResolverAgentSnapshot(agent, anchorBuilding),
    buildings: [anchorBuilding],
    agents: [],
    reservations: collectScriptedSeatReservationsForResolver([anchorBuilding]),
    occupiedSpots: collectScriptedOccupiedSeatIdsForResolver([anchorBuilding], { excludeAgent: agent }),
    preferences: { objectTypes: ['couch', 'loveseat', 'sectionalSofa', 'smallCafeTable', 'outdoorCafeTable', 'picnicTable', 'patioTable', 'smallRoundMeetingTable'], objectCooldownMs: rules.cooldownMs },
    proximity: { socialMaxDistance: (rules.proximityRadius || API_TILE * 5) / API_TILE },
    actionSpots: ACTION_SPOTS,
    interactionSpots: FURNITURE_INTERACTION_SPOTS,
  });
  destination = scaleScriptedDestinationForRuntime(destination, anchorBuilding);
  return destination?.target?.kind === 'furniture' ? destination : null;
}

function submitScriptedSocialApproach(agent, anchorBuilding, workTarget = null, nowMs = Date.now()) {
  const rules = SCRIPTED_PROXIMITY_BEHAVIOR_RULES.socialApproach;
  if (!isAgentEligibleForScriptedProximity(agent, anchorBuilding) || !scriptedProximityCooldownReady(agent, 'socialApproach', rules.cooldownMs, nowMs)) return false;
  if (Math.random() >= rules.triggerChance) return false;
  const nearbySeated = agentsList.find(other => other && other !== agent && other._idleActivity && ['seat', 'sit', 'couch', 'sofa', 'cafe', 'table', 'conversation'].some(token => String(other._idleActivity.kind || other._idleActivity.furnitureType || '').toLowerCase().includes(token)) && isAgentEligibleForScriptedProximity(other, anchorBuilding, { allowIdleIntent: true }));
  if (!nearbySeated) return false;
  const destination = resolveScriptedSocialApproachDestination(agent, anchorBuilding, nearbySeated, rules);
  if (!destination?.ok || destination.target?.kind !== 'furniture') return false;
  if (countScriptedSocialApproachers(anchorBuilding.id, destination.target.furnitureIndex) >= rules.maxApproachersPerObject) return false;
  const proposal = createAgentScriptedBehaviorProposal(agent, { category: 'socialize', destination, building: anchorBuilding, reason: 'phase-4-task-12-sofa-cafe-social-approach', decision: { category: 'socialize', probability: rules.triggerChance, durationMs: randomRangeMs(rules.durationMs) } });
  const route = submitAgentScriptedBehaviorProposal(agent, proposal);
  if (route?.accepted === false) return false;
  agent._idleActivity.kind = 'social-approach';
  agent._idleActivity.stayMs = proposal.decision.durationMs;
  agent._idleActivity.targetAgentId = nearbySeated.id || nearbySeated.name || null;
  agent._idleActivity.socialCapacityMax = rules.maxApproachersPerObject;
  agent._idleActivity.forceDeskReturn = rollIdleDeskReturnAfterActivity(workTarget);
  markScriptedProximityCooldown(agent, 'socialApproach', nowMs);
  return { accepted: true, route, destination, rule: rules };
}

function submitScriptedGroupGathering(agent, anchorBuilding, workTarget = null, nowMs = Date.now()) {
  const rules = SCRIPTED_PROXIMITY_BEHAVIOR_RULES.groupGathering;
  if (!isAgentEligibleForScriptedProximity(agent, anchorBuilding) || !scriptedProximityCooldownReady(agent, 'groupGathering', rules.cooldownMs, nowMs)) return false;
  if (Math.random() >= rules.triggerChance) return false;
  const candidates = [agent, ...getScriptedProximityAgents(anchorBuilding, agent)].slice(0, rules.maxParticipants);
  if (candidates.length < rules.minParticipants) return false;
  const durationMs = randomRangeMs(rules.durationMs);
  const accepted = [];
  for (const member of candidates) {
    let destination = resolveBehaviorDestination({ category: 'socialize', agent: getScriptedResolverAgentSnapshot(member, anchorBuilding), buildings: [anchorBuilding], agents: getScriptedResolverAgentList(candidates, anchorBuilding), preferences: { objectTypes: ['fountain', 'gazeboPavilion', 'outdoorStage', 'meetingTable', 'smallRoundMeetingTable', 'couch', 'smallCafeTable'] }, actionSpots: ACTION_SPOTS, interactionSpots: FURNITURE_INTERACTION_SPOTS });
    destination = scaleScriptedDestinationForRuntime(destination, anchorBuilding);
    if (!destination?.ok) continue;
    const proposal = createAgentScriptedBehaviorProposal(member, { category: 'socialize', destination, building: anchorBuilding, reason: 'phase-4-task-12-group-gathering-admission', decision: { category: 'socialize', probability: rules.triggerChance, durationMs } });
    const route = submitAgentScriptedBehaviorProposal(member, proposal);
    if (route?.accepted === false) continue;
    member._idleActivity.kind = 'group-gathering';
    member._idleActivity.groupGatheringSize = candidates.length;
    member._idleActivity.stayMs = durationMs;
    member._idleActivity.forceDeskReturn = member === agent && rollIdleDeskReturnAfterActivity(workTarget);
    markScriptedProximityCooldown(member, 'groupGathering', nowMs);
    accepted.push({ member, route, destination });
  }
  return accepted.length >= rules.minParticipants ? { accepted: true, participants: accepted.length, rule: rules } : false;
}

function submitScriptedPlaySocialProximityBehavior(agent, anchorBuilding, workTarget = null, nowMs = Date.now()) {
  if (!agent || !anchorBuilding) return false;
  return submitScriptedPingPongRecruitment(agent, anchorBuilding, workTarget, nowMs)
    || submitScriptedConversationProximity(agent, anchorBuilding, workTarget, nowMs)
    || submitScriptedSocialApproach(agent, anchorBuilding, workTarget, nowMs)
    || submitScriptedGroupGathering(agent, anchorBuilding, workTarget, nowMs)
    || (Math.random() < 0.18 ? submitScriptedPlayObjectBehavior(agent, anchorBuilding, workTarget) : false);
}

function submitScriptedIdlePulseCategory(agent, category, anchorBuilding, workTarget = null, nowMs = Date.now()) {
  if (!agent || !anchorBuilding || !category) return false;
  if (category === 'socialize') {
    return submitScriptedPlaySocialProximityBehavior(agent, anchorBuilding, workTarget, nowMs)
      || submitScriptedIdlePulseCategory(agent, 'rest', anchorBuilding, workTarget, nowMs);
  }
  if (category === 'play') {
    return submitScriptedPlayObjectBehavior(agent, anchorBuilding, workTarget, {
      preferredObjectTypes: [...getActiveScriptedIdlePulseRules().objectTypes.play],
      reason: 'default-scripted-idle-pulse-play',
    });
  }
  if (category === 'wander') {
    if (VO_STYLE_IDLE_TEST) {
      const target = getVOStyleIdleIndoorWanderTarget(agent, anchorBuilding);
      if (target) {
        const route = setAgentTarget(agent, target, anchorBuilding, target.floor, {
          owner: 'idle', priorityName: 'idle', phase: 'routing',
          source: { family: 'vo-style-idle-test', functionName: 'submitScriptedIdlePulseCategory', taskRef: '2026-06-01-vo-style-idle-test' },
          debug: { label: 'idle:vo-style-wander', sourceSummary: 'VO-style idle test wander through Virtual World routing', lastDecisionReason: 'vo-style-idle-test-wander' },
        });
        if (route?.accepted !== false) {
          agent._idleActivity = {
            kind: 'vo-style-idle-wander',
            stayMs: 3500 + Math.random() * 7000,
            forceDeskReturn: rollIdleDeskReturnAfterActivity(workTarget),
          };
          agent._wanderTimer = 600 + Math.random() * 1200;
          markAgentScriptedChoice(agent, 'wander', target, nowMs);
          return { route, target, category: 'wander' };
        }
      }
    }
    agent._idleActivity = { kind: 'scripted-indoor-stretch', stayMs: 6000 + Math.random() * 10000, forceDeskReturn: rollIdleDeskReturnAfterActivity(workTarget) };
    agent._stayTimer = 4500 + Math.random() * 5500;
    markAgentScriptedChoice(agent, 'wander', null, nowMs);
    return true;
  }
  if (category === 'work-return' && workTarget) {
    const route = setAgentTarget(agent, { x: workTarget.apiX, y: workTarget.apiZ, floor: workTarget.floor, targetKind: 'work-desk', buildingId: workTarget.building?.id || workTarget.buildingId || null }, workTarget.building, workTarget.floor, {
      owner: 'idle', priorityName: 'idle', phase: 'routing',
      source: { family: 'default-scripted-idle-pulse', functionName: 'submitScriptedIdlePulseCategory', taskRef: 'phase-4-default-scripted-idle-pulse' },
      debug: { label: 'idle:desk-return', sourceSummary: 'default scripted idle pulse desk return', lastDecisionReason: 'scripted-idle-pulse-return' },
    });
    if (route?.accepted === false) return false;
    agent._idleActivity = { kind: 'desk-return', stayMs: 18000 + Math.random() * 18000, faceAngle: workTarget.faceAngle, clearDeskReturn: true, dockTarget: { x: workTarget.apiX, y: workTarget.apiZ }, dockSnapRadius: WORK_DESK_DOCK_SNAP_RADIUS };
    markAgentScriptedChoice(agent, 'work-return', null, nowMs);
    return true;
  }

  const objectTypes = getActiveScriptedIdlePulseRules().objectTypes[category] || [];
  const scriptedState = getAgentScriptedResolverState(agent);
  const buildingList = makeFocusedScriptedResolverBuildings(agent, anchorBuilding, category, objectTypes, { nowMs });
  let destination = resolveBehaviorDestination({
    category,
    agent: getScriptedResolverAgentSnapshot(agent, anchorBuilding),
    buildings: buildingList,
    agents: getScriptedResolverAgentList(agentsList, anchorBuilding),
    reservations: collectScriptedSeatReservationsForResolver(buildingList),
    occupiedSpots: collectScriptedOccupiedSeatIdsForResolver(buildingList, { excludeAgent: agent }),
    preferences: getAgentScriptedBehaviorPreferences(agent, { objectTypes: [...objectTypes], objectCooldownMs: 120000 }),
    recentObjects: scriptedState.recentObjects,
    failedTargets: scriptedState.failedTargets,
    failedTargetThrottleMs: SCRIPTED_BEHAVIOR_FALLBACK_CONSTANTS.failedTargetThrottleMs,
    queueing: { default: true }, // SERVICE_QUEUE_SPEC.md: queueing is per-object capability, not per category
    actionSpots: ACTION_SPOTS,
    interactionSpots: FURNITURE_INTERACTION_SPOTS,
  });
  destination = scaleScriptedDestinationForRuntime(destination, anchorBuilding);
  if (!destination?.ok || destination.target?.kind !== 'furniture') return false;
  const furniture = anchorBuilding.interior?.furniture?.[destination.target.furnitureIndex];
  const activity = getLocalIdleActivityConfig(furniture?.type) || null;
  const objectUse = destination.lifecycle === 'active'
    ? createScriptedActiveObjectUseForDestination(destination, activity)
    : createScriptedObjectUseForDestination(destination, activity);
  if (!objectUse) return false;
  objectUse.stayMs = category === 'browse-read'
    ? randomRangeMs(activity?.stayMs, 15000 + Math.random() * 30000)
    : (category === 'snack-drink'
      ? randomRangeMs(activity?.stayMs, 20000 + Math.random() * 40000)
      : (category === 'rest'
        ? randomRangeMs(activity?.stayMs, 20000 + Math.random() * 40000)
        : objectUse.stayMs));
  const proposal = createAgentScriptedBehaviorProposal(agent, {
    category,
    destination,
    building: anchorBuilding,
    floor: destination.floor || getAgentFloor(agent, anchorBuilding),
    decision: { category, selectedCategory: category, durationMs: objectUse.stayMs, behaviorProbabilityRoll: { tableVersion: 'default-scripted-idle-pulse/v1' } },
    reason: 'default-scripted-idle-pulse',
    objectUse,
  });
  const route = submitAgentScriptedBehaviorProposal(agent, proposal);
  if (route?.accepted === false) { markAgentScriptedTargetFailure(agent, destination, route.reason || 'scripted-idle-pulse-rejected'); return false; }
  markAgentScriptedChoice(agent, category, destination, nowMs);
  if (agent._idleActivity) {
    agent._idleActivity.forceDeskReturn = rollIdleDeskReturnAfterActivity(workTarget);
    agent._idleActivity.defaultScriptedIdlePulse = true;
    agent._idleActivity.stayMs = objectUse.stayMs;
  }
  return { route, destination, furniture, objectUse };
}

function maybeRunDefaultScriptedIdlePulse(agent, anchorBuilding, workTarget = null, nowMs = Date.now()) {
  if (!agent || !anchorBuilding || (!workTarget && !VO_STYLE_IDLE_TEST)) return false;
  if (agent._idleActivity || agent._wanderTarget || isAgentIntentActive(agent._agentIntent)) return false;
  const nearDesk = workTarget ? Math.hypot((agent.x || 0) - workTarget.apiX, (agent.y || 0) - workTarget.apiZ) <= WORK_DESK_IDLE_SEATED_RADIUS : false;
  if (workTarget && !agent._atDesk && !nearDesk && !VO_STYLE_IDLE_TEST) return false;
  const activeRules = getActiveScriptedIdlePulseRules();
  if (!agent._nextScriptedIdlePulseAtMs) resetAgentScriptedIdlePulseTimer(agent, activeRules.initialDelayMs, nowMs);
  if (nowMs < agent._nextScriptedIdlePulseAtMs) return false;
  const preferredOrder = getScriptedIdlePulseCategoryOrder(agent, nowMs);
  const tried = new Set();
  for (const category of preferredOrder) {
    if (tried.has(category)) continue;
    tried.add(category);
    const result = submitScriptedIdlePulseCategory(agent, category, anchorBuilding, workTarget, nowMs);
    if (result) {
      agent._atDesk = false;
      agent._isReturningToDesk = false;
      resetAgentScriptedIdlePulseTimer(agent, activeRules.initialDelayMs, nowMs);
      agent._lastScriptedIdlePulseCategory = category;
      // Tag the chosen activity with its need category so the needs runtime
      // satisfies the right meter on completion (kind prefixes vary widely).
      if (agent._idleActivity && !agent._idleActivity._needCategory) agent._idleActivity._needCategory = category;
      return result;
    }
  }
  resetAgentScriptedIdlePulseTimer(agent, activeRules.retryDelayMs, nowMs);
  return false;
}

function applyDeskProneIdlePlan(agent, setTarget) {
  if (!agent || !(agent.status === 'idle' || !agent.status)) return false;
  const activeIntent = agent._agentIntent || null;
  if (isAgentIntentActive(activeIntent) && ['manual', 'explicit-object'].includes(activeIntent.priorityName)) {
    agent._lastIdleDeskPlanBlocked = { reason: 'manual-or-explicit-object-active', activeIntentId: activeIntent.id || null, owner: activeIntent.owner || null, priorityName: activeIntent.priorityName || null, object: activeIntent.object || null, atMs: Date.now() };
    return false;
  }

  const requestIdleTarget = (target, building = null, floor = null, metadata = {}) => {
    const route = setAgentTarget(agent, target, building, floor || target?.floor || target?.buildingFloor || 1, {
      owner: 'idle',
      priorityName: 'idle',
      phase: 'routing',
      target,
      building,
      floor: floor || target?.floor || target?.buildingFloor || 1,
      source: {
        family: 'idle-planner',
        functionName: metadata.sourceFunction || 'applyDeskProneIdlePlan',
        taskRef: 'phase-3b.4-schedule-idle-gating',
      },
      debug: {
        label: `idle:${metadata.label || metadata.kind || 'local'}`,
        sourceSummary: metadata.sourceSummary || 'idle/local furniture movement handoff',
        lastDecisionReason: 'idle-intent-admitted',
      },
    });
    return route?.accepted === false ? route : (setTarget && route == null ? setTarget(agent, target, building, floor) : route);
  };
  const idleAccepted = (route) => route?.accepted !== false;

  const workTarget = getAgentWorkTarget(agent);
  const workBuilding = workTarget?.building || agent._workBuilding || null;
  const insideBuilding = getMovementInteriorBuildingAt(agent.x, agent.y) || null;
  const anchorBuilding = insideBuilding || workBuilding || null;
  const nearDesk = workTarget ? Math.hypot(agent.x - workTarget.apiX, agent.y - workTarget.apiZ) <= API_TILE * 1.6 : false;
  const indoorCandidateHint = Boolean(anchorBuilding && insideBuilding && (anchorBuilding.interior?.furniture || []).some(item => item && item.enabled !== false && !item.deleted && !item.removed));
  const idleGate = evaluateAgentScriptedIdleDecisionGate(agent, {
    schedulePhase: 'idle-local',
    currentBuilding: insideBuilding,
    workTarget,
    hasIndoorCandidates: indoorCandidateHint,
  });
  agent._lastScriptedIdleGate = idleGate;

  if (agent._forceIdleDeskReturn && workTarget) {
    const route = requestIdleTarget({ x: workTarget.apiX, y: workTarget.apiZ, floor: workTarget.floor }, insideBuilding || workBuilding || null, workTarget.floor, { kind: 'desk-return', label: 'desk-return' });
    if (!idleAccepted(route)) return false;
    agent._idleActivity = {
      kind: 'desk-return',
      stayMs: 18000 + Math.random() * 18000,
      faceAngle: workTarget.faceAngle,
      clearDeskReturn: true,
      dockTarget: { x: workTarget.apiX, y: workTarget.apiZ },
      dockSnapRadius: 8,
    };
    agent._wanderTimer = 1200 + Math.random() * 2400;
    return true;
  }

  const idlePulseResult = maybeRunDefaultScriptedIdlePulse(agent, anchorBuilding, workTarget, Date.now());
  if (idlePulseResult) return true;

  const deskHoldChance = VO_STYLE_IDLE_TEST ? 0.04 : 0.08;
  if (workTarget && (nearDesk || insideBuilding?.id === workBuilding?.id) && Math.random() < deskHoldChance) {
    agent._wanderTarget = null;
    agent._waypointPath = null;
    agent._waypointPathTarget = null;
    agent._idleActivity = null;
    agent._forceIdleDeskReturn = false;
    agent._stayTimer = 5000 + Math.random() * 9000;
    agent._wanderTimer = 2500 + Math.random() * 4500;
    if (agent._group3d && Number.isFinite(workTarget.faceAngle)) agent._group3d.rotation.y = workTarget.faceAngle;
    return true;
  }

  if (anchorBuilding && insideBuilding && submitScriptedPlaySocialProximityBehavior(agent, anchorBuilding, workTarget)) {
    return true;
  }

  const seatingChance = VO_STYLE_IDLE_TEST ? 0.90 : 0.72;
  if (anchorBuilding && insideBuilding && Math.random() < seatingChance && submitScriptedSeatingBehavior(agent, anchorBuilding, workTarget)) {
    return true;
  }

  const standingChance = VO_STYLE_IDLE_TEST ? 0.82 : 0.62;
  if (anchorBuilding && insideBuilding && Math.random() < standingChance && submitScriptedStandingUseBehavior(agent, anchorBuilding, workTarget)) {
    return true;
  }

  if (anchorBuilding && insideBuilding) {
    const localTargets = getLocalIdleFurnitureTargets(anchorBuilding, agent)
      .filter(spot => Math.hypot(agent.x - spot.apiX, agent.y - spot.apiZ) <= API_TILE * 7)
      .filter(spot => !isLocalIdleTargetClaimed(anchorBuilding, spot, agent));
    const localTargetChance = VO_STYLE_IDLE_TEST ? 0.88 : 0.55;
    if (localTargets.length > 0 && Math.random() < localTargetChance) {
      localTargets.sort((a, b) => Math.hypot(agent.x - a.apiX, agent.y - a.apiZ) - Math.hypot(agent.x - b.apiX, agent.y - b.apiZ));
      const pool = localTargets.slice(0, Math.min(3, localTargets.length));
      const seatingTypes = new Set(['chair', 'couch', 'sectionalSofa', 'loveseat', 'armchair', 'hallwayBench', 'diningChair', 'patioChair', 'smallCafeTable', 'outdoorCafeTable', 'picnicTable', 'smallRoundMeetingTable']);
      const shuffledPool = [...pool].sort(() => Math.random() - 0.5);
      let chosen = null;
      let activity = null;
      let seatPlan = null;
      for (const option of shuffledPool) {
        if (isLocalIdleTargetClaimed(anchorBuilding, option, agent)) continue;
        const optionRequiresSeatPlan = seatingTypes.has(option.furniture?.type);
        const optionActivity = option.activity || null;
        const optionSeatPlan = optionRequiresSeatPlan ? getLocalIdleSeatReservationPlan(anchorBuilding, option.furniture, (option.furnitureIndex ?? option.furniture?._index), agent, optionActivity) : null;
        if (optionRequiresSeatPlan && !optionSeatPlan) continue;
        chosen = option;
        activity = optionActivity;
        seatPlan = optionSeatPlan;
        break;
      }
      if (!chosen) return false;
      const routeSpot = seatPlan?.targetSpot || chosen;
      const route = requestIdleTarget({ x: routeSpot.apiX, y: routeSpot.apiZ, floor: routeSpot.floor }, anchorBuilding, routeSpot.floor, { kind: chosen.kind, label: 'local-furniture', sourceSummary: 'idle-local furniture picker movement handoff' });
      if (route?.accepted === false && seatPlan?.reservation) {
        releaseObjectUseSeatReservation(getObjectUseSeatStoreForFurniture(chosen.furniture), { reservationId: seatPlan.reservation.id, agentId: agent.id || agent.name || 'agent', seatId: seatPlan.selectedSeat.seatId, terminalState: 'cancelled', reason: 'idle-intent-rejected' });
      }
      if (!idleAccepted(route)) return false;
      const isTreadmillUse = chosen.furniture?.type === 'treadmill';
      const isTrainingMatUse = chosen.furniture?.type === 'trainingMat';
      const isGymBenchUse = chosen.furniture?.type === 'gymBench';
      const isOutdoorExerciseStationUse = chosen.furniture?.type === 'outdoorExerciseStation';
      const isArcadeMachineUse = chosen.furniture?.type === 'arcadeMachine';
      const activeUseActivationSpotId = isTreadmillUse ? (activity?.activationSpotId || 'train-belt') : (isTrainingMatUse ? (activity?.activationSpotId || 'use-mat') : (isGymBenchUse ? (activity?.activationSpotId || 'bench-use') : (isOutdoorExerciseStationUse ? (activity?.activationSpotId || 'practice-platform') : (isArcadeMachineUse ? (activity?.activationSpotId || 'play-front') : null))));
      const activeUseActivationSpot = activeUseActivationSpotId ? getFurnitureActionSpot(anchorBuilding, chosen.furniture, activeUseActivationSpotId) : null;
      const isActiveUseWithDock = isTreadmillUse || isTrainingMatUse || isGymBenchUse || isOutdoorExerciseStationUse || isArcadeMachineUse;
      const activeUseActionId = chosen.action || activity?.action || (isArcadeMachineUse ? 'life.playArcade' : (isTrainingMatUse ? 'training.stretchOnMat' : (isGymBenchUse ? 'training.useGymBench' : (isOutdoorExerciseStationUse ? 'training.trainAtOutdoorExerciseStation' : 'training.practice'))));
      let activeUseReservation = null;
      if (isTreadmillUse && activeUseActivationSpot) {
        const treadmillCandidate = getTreadmillActiveUseCandidate(anchorBuilding, chosen.furniture, (chosen.furnitureIndex ?? chosen.furniture?._index), activeUseActionId);
        const treadmillReserve = treadmillCandidate ? chooseAndReserveObjectUseActiveSlot(getTreadmillObjectUseActiveStore(chosen.furniture), [treadmillCandidate], {
          agentId: agent.id || agent.name || 'agent',
          agentPosition: { x: agent.x || 0, z: agent.y || 0 },
          actionId: activeUseActionId,
          reservationId: `reservation:${getTreadmillObjectKey(anchorBuilding.id, (chosen.furnitureIndex ?? chosen.furniture?._index))}:${agent.id || agent.name || 'agent'}:${Date.now()}`,
        }) : null;
        activeUseReservation = treadmillReserve?.ok ? treadmillReserve.reservation : null;
        chosen.furniture.reservation = { id: activeUseReservation?.id || null, agentId: agent.id || agent.name || 'agent', actionId: activeUseActionId, spotId: 'train-belt', activationSpotId: 'train-belt', approachSpotId: 'step-off', activeUseSlotId: activeUseReservation?.slotId || 'belt-1', status: 'held' };
        chosen.furniture.activeUse = { state: 'reserved', actionId: activeUseActionId, agentId: agent.id || null, interactionSpotId: 'train-belt', approachSpotId: 'step-off' };
        chosen.furniture.trainingMode = 'train';
      } else if (isTrainingMatUse && activeUseActivationSpot) {
        const matCandidate = getTrainingMatActiveUseCandidate(anchorBuilding, chosen.furniture, (chosen.furnitureIndex ?? chosen.furniture?._index), activeUseActionId);
        const matReserve = matCandidate ? chooseAndReserveObjectUseActiveSlot(getTrainingMatObjectUseActiveStore(chosen.furniture), [matCandidate], {
          agentId: agent.id || agent.name || 'agent',
          agentPosition: { x: agent.x || 0, z: agent.y || 0 },
          actionId: activeUseActionId,
          reservationId: `reservation:${getTrainingMatObjectKey(anchorBuilding.id, (chosen.furnitureIndex ?? chosen.furniture?._index))}:${agent.id || agent.name || 'agent'}:${Date.now()}`,
        }) : null;
        activeUseReservation = matReserve?.ok ? matReserve.reservation : null;
        chosen.furniture.reservation = { id: activeUseReservation?.id || null, agentId: agent.id || agent.name || 'agent', actionId: activeUseActionId, spotId: 'use-mat', activationSpotId: 'use-mat', approachSpotId: 'approach-front', activeUseSlotId: activeUseReservation?.slotId || 'mat-1', status: 'held' };
        chosen.furniture.activeUse = { state: 'reserved', actionId: activeUseActionId, agentId: agent.id || null, interactionSpotId: 'use-mat', approachSpotId: 'approach-front' };
        chosen.furniture.trainingMode = 'stretch';
      } else if (isGymBenchUse && activeUseActivationSpot) {
        const benchCandidate = getGymBenchActiveUseCandidate(anchorBuilding, chosen.furniture, (chosen.furnitureIndex ?? chosen.furniture?._index), activeUseActionId);
        const benchReserve = benchCandidate ? chooseAndReserveObjectUseActiveSlot(getGymBenchObjectUseActiveStore(chosen.furniture), [benchCandidate], {
          agentId: agent.id || agent.name || 'agent',
          agentPosition: { x: agent.x || 0, z: agent.y || 0 },
          actionId: activeUseActionId,
          reservationId: `reservation:${getGymBenchObjectKey(anchorBuilding.id, (chosen.furnitureIndex ?? chosen.furniture?._index))}:${agent.id || agent.name || 'agent'}:${Date.now()}`,
        }) : null;
        activeUseReservation = benchReserve?.ok ? benchReserve.reservation : null;
        chosen.furniture.reservation = { id: activeUseReservation?.id || null, agentId: agent.id || agent.name || 'agent', actionId: activeUseActionId, spotId: 'bench-use', activationSpotId: 'bench-use', approachSpotId: 'approach-front', activeUseSlotId: activeUseReservation?.slotId || 'bench-1', status: 'held' };
        chosen.furniture.activeUse = { state: 'reserved', actionId: activeUseActionId, agentId: agent.id || null, interactionSpotId: 'bench-use', approachSpotId: 'approach-front' };
        chosen.furniture.trainingMode = 'exercise';
      } else if (isOutdoorExerciseStationUse && activeUseActivationSpot) {
        const stationCandidate = getOutdoorExerciseStationActiveUseCandidate(anchorBuilding, chosen.furniture, (chosen.furnitureIndex ?? chosen.furniture?._index), activeUseActionId);
        const stationReserve = stationCandidate ? chooseAndReserveObjectUseActiveSlot(getOutdoorExerciseStationObjectUseActiveStore(chosen.furniture), [stationCandidate], {
          agentId: agent.id || agent.name || 'agent',
          agentPosition: { x: agent.x || 0, z: agent.y || 0 },
          actionId: activeUseActionId,
          reservationId: `reservation:${getOutdoorExerciseStationObjectKey(anchorBuilding.id, (chosen.furnitureIndex ?? chosen.furniture?._index))}:${agent.id || agent.name || 'agent'}:${Date.now()}`,
        }) : null;
        activeUseReservation = stationReserve?.ok ? stationReserve.reservation : null;
        chosen.furniture.reservation = { id: activeUseReservation?.id || null, agentId: agent.id || agent.name || 'agent', actionId: activeUseActionId, spotId: activeUseActivationSpotId, activationSpotId: activeUseActivationSpotId, approachSpotId: 'train-front', activeUseSlotId: activeUseReservation?.slotId || 'station-1', status: 'held' };
        chosen.furniture.activeUse = { state: 'reserved', actionId: activeUseActionId, agentId: agent.id || null, interactionSpotId: activeUseActivationSpotId, approachSpotId: 'train-front' };
        chosen.furniture.trainingMode = String(activeUseActionId).toLowerCase().includes('practice') ? 'practice' : 'train';
      } else if (isArcadeMachineUse && activeUseActivationSpot) {
        const arcadeCandidate = getArcadeMachineActiveUseCandidate(anchorBuilding, chosen.furniture, (chosen.furnitureIndex ?? chosen.furniture?._index), activeUseActionId);
        const arcadeReserve = arcadeCandidate ? chooseAndReserveObjectUseActiveSlot(getArcadeMachineObjectUseActiveStore(chosen.furniture), [arcadeCandidate], {
          agentId: agent.id || agent.name || 'agent',
          agentPosition: { x: agent.x || 0, z: agent.y || 0 },
          actionId: activeUseActionId,
          reservationId: `reservation:${getArcadeMachineObjectKey(anchorBuilding.id, (chosen.furnitureIndex ?? chosen.furniture?._index))}:${agent.id || agent.name || 'agent'}:${Date.now()}`,
        }) : null;
        activeUseReservation = arcadeReserve?.ok ? arcadeReserve.reservation : null;
        if (!activeUseReservation) return false;
        chosen.furniture.reservation = { id: activeUseReservation.id, agentId: agent.id || agent.name || 'agent', actionId: activeUseActionId, spotId: 'play-front', activationSpotId: 'play-front', approachSpotId: 'approach-front', activeUseSlotId: activeUseReservation.slotId || 'player-1', status: 'held' };
        chosen.furniture.activeUse = { state: 'reserved', mode: 'play', actionId: activeUseActionId, agentId: agent.id || null, interactionSpotId: 'play-front', approachSpotId: 'approach-front' };
        chosen.furniture.playMode = 'reserved';
        chosen.furniture.arcadeMachineState = { ...(chosen.furniture.arcadeMachineState || {}), status: 'reserved', screenMode: 'ready', reservedSlotIds: [activeUseReservation.slotId || 'player-1'], lastAction: activeUseActionId, persistentFurniture: true };
      }
      agent._idleActivity = {
        kind: activity?.kind || chosen.kind,
        phase: 'approach',
        stayMs: randomRangeMs(activity?.stayMs),
        faceAngle: seatPlan ? seatPlan.faceAngle : (isActiveUseWithDock && activeUseActivationSpot ? activeUseActivationSpot.faceAngle : chosen.faceAngle),
        forceDeskReturn: rollIdleDeskReturnAfterActivity(workTarget),
        dockTarget: seatPlan ? { x: seatPlan.seatSpot.apiX, y: seatPlan.seatSpot.apiZ } : (isActiveUseWithDock && activeUseActivationSpot ? { x: activeUseActivationSpot.apiX, y: activeUseActivationSpot.apiZ } : { x: chosen.apiX, y: chosen.apiZ }),
        routeApproachTarget: seatPlan?.routeApproachTarget || (isActiveUseWithDock ? { x: chosen.apiX, y: chosen.apiZ, floor: chosen.floor, spotId: chosen.spotId || (isTreadmillUse ? 'step-off' : (isOutdoorExerciseStationUse ? 'train-front' : 'approach-front')) } : null),
        dockSnapRadius: activity?.dockSnapRadius || 6,
        furnitureType: chosen.furniture?.type || null,
        furnitureIndex: (chosen.furnitureIndex ?? chosen.furniture?._index) ?? null,
        spotId: seatPlan?.selectedSeat?.seatId || (isTreadmillUse ? 'train-belt' : (isTrainingMatUse ? 'use-mat' : (isGymBenchUse ? 'bench-use' : (isOutdoorExerciseStationUse ? activeUseActivationSpotId : (isArcadeMachineUse ? 'play-front' : (chosen.spotId || activity?.spotId || null)))))),
        seatId: seatPlan?.selectedSeat?.seatId || null,
        activationSpotId: seatPlan?.selectedSeat?.activationSpotId || (isTreadmillUse ? 'train-belt' : (isTrainingMatUse ? 'use-mat' : (isGymBenchUse ? 'bench-use' : (isOutdoorExerciseStationUse ? activeUseActivationSpotId : (isArcadeMachineUse ? 'play-front' : (activity?.activationSpotId || null)))))),
        approachSpotId: seatPlan?.approachSpot?.spotId || seatPlan?.selectedSeat?.approachSpotId || (isActiveUseWithDock ? (chosen.spotId || (isTreadmillUse ? 'step-off' : (isOutdoorExerciseStationUse ? 'train-front' : 'approach-front'))) : null),
        dismountSpotId: chosen.furniture?.type === 'armchair' ? 'stand-front' : (getSingleSeatChairConfig(chosen.furniture?.type)?.dismountSpotId || null),
        activeUseSlotId: isTreadmillUse ? (activeUseReservation?.slotId || 'belt-1') : (isTrainingMatUse ? (activeUseReservation?.slotId || 'mat-1') : (isGymBenchUse ? (activeUseReservation?.slotId || 'bench-1') : (isOutdoorExerciseStationUse ? (activeUseReservation?.slotId || 'station-1') : (isArcadeMachineUse ? (activeUseReservation?.slotId || 'player-1') : null)))),
        reservationId: seatPlan?.reservation?.id || activeUseReservation?.id || null,
        objectKey: seatPlan?.objectKey || null,
        capacityKey: seatPlan?.reservation?.capacityKey || null,
        seatSurfaceLift: seatPlan?.seatSurfaceLift ?? null,
        action: seatPlan?.actionId || activeUseActionId,
        actionId: seatPlan?.actionId || activeUseActionId,
        animationId: activity?.animationId || null,
        lifecycle: { stationary: true, carryable: false, temporary: false },
      };
      agent._wanderTimer = 1200 + Math.random() * 2000;
      return true;
    }
  }

  if (VO_STYLE_IDLE_TEST && insideBuilding && anchorBuilding) {
    const wanderTarget = getVOStyleIdleIndoorWanderTarget(agent, anchorBuilding);
    if (wanderTarget) {
      const route = requestIdleTarget(wanderTarget, anchorBuilding, wanderTarget.floor, {
        kind: 'vo-style-idle-wander',
        label: 'vo-style-idle-wander',
        sourceSummary: 'VO-style idle fallback movement through Virtual World routing',
      });
      if (!idleAccepted(route)) return false;
      agent._idleActivity = {
        kind: 'vo-style-idle-wander',
        stayMs: 3500 + Math.random() * 7000,
        forceDeskReturn: rollIdleDeskReturnAfterActivity(workTarget),
      };
      agent._wanderTimer = 600 + Math.random() * 1200;
      return true;
    }
  }

  if (insideBuilding && workTarget && agentScriptedGateAllowsFamily(idleGate, 'short-outside-break') && Math.random() < Math.min(0.12, idleGate.outdoorChanceCap)) {
    const door = getBuildingDoorPosAPI(insideBuilding) || { x: agent.x, y: agent.y };
    const doorSW = getRandomSidewalkScheduleTargetNear(door.x + API_TILE * 3, door.y + API_TILE * 3, 18, 'short-outside-break-sidewalk');
    const route = requestIdleTarget(doorSW, insideBuilding, null, { kind: 'short-outside-break', label: 'short-outside-break', sourceSummary: idleGate.debugReason });
    if (!idleAccepted(route)) return false;
    agent._idleActivity = {
      kind: 'short-outside-break',
      stayMs: 4000 + Math.random() * 7000,
      forceDeskReturn: rollIdleDeskReturnAfterActivity(workTarget),
    };
    agent._wanderTimer = 1000 + Math.random() * 1800;
    return true;
  }

  // Desk visit is just another idle activity now: low chance, with the same
  // category cooldown other activities use, so it cannot repeat back-to-back.
  if (workTarget && Math.random() < IDLE_DESK_VISIT_CHANCE && !hasRecentScriptedCategoryUse(agent, 'work-return')) {
    const route = requestIdleTarget({ x: workTarget.apiX, y: workTarget.apiZ, floor: workTarget.floor }, insideBuilding || workBuilding || null, workTarget.floor, { kind: 'desk-return', label: 'desk-return' });
    if (!idleAccepted(route)) return false;
    agent._idleActivity = {
      kind: 'desk-return',
      stayMs: 15000 + Math.random() * 22000,
      faceAngle: workTarget.faceAngle,
      clearDeskReturn: true,
      dockTarget: { x: workTarget.apiX, y: workTarget.apiZ },
      dockSnapRadius: 8,
    };
    markAgentScriptedChoice(agent, 'work-return');
    agent._wanderTimer = 1500 + Math.random() * 2500;
    return true;
  }

  return false;
}

const WORK_PRESENCE_CLIENT_HOLD_MS = 18_000;

function normalizeLiveAgentStatus(statusValue) {
  const normalized = String(statusValue || '').trim().toLowerCase();
  if (!normalized) return '';
  if (['busy', 'thinking', 'processing', 'responding', 'running', 'reading', 'reading_file', 'reading-file', 'analyzing', 'planning', 'reasoning', 'inference', 'inferencing', 'generating', 'streaming', 'executing', 'command', 'command_output', 'tool', 'tool_start', 'running_command'].includes(normalized)) return 'working';
  if (normalized === 'available') return 'idle';
  return normalized;
}

function isWorkPresenceStatus(statusValue) {
  return ['working', 'finishing'].includes(normalizeLiveAgentStatus(statusValue));
}

function isIdlePresenceStatus(statusValue) {
  return ['idle', 'break'].includes(normalizeLiveAgentStatus(statusValue));
}

function presenceSnapshotAgeMs(snapshot = null, nowMs = performance.now()) {
  const rawUpdated = snapshot?.updated ?? snapshot?.updatedAt ?? snapshot?.timestamp ?? snapshot?.ts ?? null;
  if (rawUpdated == null || rawUpdated === '') return Infinity;
  const numeric = Number(rawUpdated);
  if (Number.isFinite(numeric)) {
    const epochMs = numeric > 1e12 ? numeric : numeric * 1000;
    return Math.max(0, Date.now() - epochMs);
  }
  const parsed = Date.parse(String(rawUpdated));
  if (Number.isFinite(parsed)) return Math.max(0, Date.now() - parsed);
  return Infinity;
}

function presenceSnapshotImpliesActiveWork(snapshot = null, rosterMatch = null) {
  const source = String(snapshot?.source ?? rosterMatch?.source ?? '').toLowerCase();
  const task = String(snapshot?.task ?? rosterMatch?.task ?? '').trim().toLowerCase();
  const runId = snapshot?.runId ?? rosterMatch?.runId ?? null;
  const freshSnapshot = presenceSnapshotAgeMs(snapshot ?? rosterMatch) <= WORK_PRESENCE_CLIENT_HOLD_MS * 2;
  if (!freshSnapshot) return false;
  if (runId && source !== 'finish-grace-expired' && source !== 'event-idle-timeout') return true;
  if (source.includes('tool') || source.includes('command') || source.includes('lifecycle') || source.includes('session') || source.includes('agent-')) return true;
  if (/\b(read|reading|process|processing|think|thinking|analyz|planning|reasoning|tool|exec|command|fetch|search|write|edit|patch|running|generating|responding|streaming)\b/.test(task)) return true;
  return false;
}

function applyWorkPresenceClientHold(agent, nextStatus, snapshot = null, rosterMatch = null, nowMs = performance.now()) {
  const normalizedNext = normalizeLiveAgentStatus(nextStatus) || 'offline';
  if (!agent) return normalizedNext;
  const hasFreshWorkSignal = isWorkPresenceStatus(normalizedNext) || presenceSnapshotImpliesActiveWork(snapshot, rosterMatch);
  const task = String(snapshot?.task ?? rosterMatch?.task ?? agent.task ?? '').trim();

  if (hasFreshWorkSignal) {
    agent._workPresenceHoldUntil = nowMs + WORK_PRESENCE_CLIENT_HOLD_MS;
    return 'working';
  }

  const previous = normalizeLiveAgentStatus(agent.status);
  const holdActive = Number.isFinite(agent._workPresenceHoldUntil) && nowMs < agent._workPresenceHoldUntil;
  const likelyTransientGap = isWorkPresenceStatus(previous) && holdActive && (!snapshot || task || normalizedNext === 'idle' || normalizedNext === 'offline');
  if (likelyTransientGap) return 'working';

  if (!isWorkPresenceStatus(normalizedNext)) agent._workPresenceHoldUntil = 0;
  return normalizedNext;
}

function getPresenceStateIcon(statusValue) {
  const status = normalizeLiveAgentStatus(statusValue);
  if (normalizeLiveAgentStatus(status) === 'working') return '🟢';
  if (status === 'finishing') return '🟩';
  if (status === 'meeting') return '🔵';
  if (status === 'idle') return '🟡';
  if (status === 'break') return '🟠';
  return '⚫';
}

function getLiveMeetingAgentIds(liveStatusMap = null) {
  const meetings = Array.isArray(liveStatusMap?._meetings) ? liveStatusMap._meetings : [];
  const ids = new Set();
  meetings.forEach(meeting => {
    const participants = Array.isArray(meeting?.participants) ? meeting.participants
      : Array.isArray(meeting?.agents) ? meeting.agents
      : Array.isArray(meeting?.agentIds) ? meeting.agentIds
      : [];
    participants.forEach(id => { if (id != null) ids.add(String(id)); });
  });
  return ids;
}

function getLiveMeetingForAgent(agent, liveStatusMap = null) {
  if (!agent || !liveStatusMap || typeof liveStatusMap !== 'object') return null;
  const keys = getAgentIdentityKeys(agent);
  const meetings = Array.isArray(liveStatusMap._meetings) ? liveStatusMap._meetings : [];
  return meetings.find(meeting => {
    const participants = Array.isArray(meeting?.participants) ? meeting.participants
      : Array.isArray(meeting?.agents) ? meeting.agents
      : Array.isArray(meeting?.agentIds) ? meeting.agentIds
      : [];
    return participants.some(id => keys.has(String(id)));
  }) || null;
}

function getLiveStatusSnapshotForAgent(agent, liveStatusMap = null) {
  if (!agent || !liveStatusMap || typeof liveStatusMap !== 'object') return null;
  for (const key of getAgentIdentityKeys(agent)) {
    const snapshot = liveStatusMap[key];
    if (snapshot && typeof snapshot === 'object') return snapshot;
  }
  return null;
}

function mergeLiveStatusIntoAgent(agent, liveStatusMap = null) {
  if (!agent) return agent;
  const mergedAgent = { ...agent };
  const snapshot = getLiveStatusSnapshotForAgent(mergedAgent, liveStatusMap);
  const normalizedFallbackStatus = normalizeLiveAgentStatus(mergedAgent.status);

  if (!snapshot) {
    mergedAgent.status = normalizedFallbackStatus || 'offline';
    return mergedAgent;
  }

  const normalizedLiveStatus = normalizeLiveAgentStatus(
    snapshot.state ?? snapshot.status ?? snapshot.presence ?? snapshot.activity
  );
  const meeting = getLiveMeetingForAgent(mergedAgent, liveStatusMap);

  mergedAgent.status = meeting ? 'meeting' : (normalizedLiveStatus || normalizedFallbackStatus || 'offline');
  if (typeof snapshot.task === 'string') mergedAgent.task = snapshot.task;
  if (meeting?.topic && !mergedAgent.task) mergedAgent.task = meeting.topic;
  if (snapshot.source) mergedAgent.presenceSource = snapshot.source;
  if (snapshot.updated != null) mergedAgent.presenceUpdated = snapshot.updated;
  if (snapshot.runId) mergedAgent.presenceRunId = snapshot.runId;
  return mergedAgent;
}

async function fetchAgentRosterWithLiveStatus() {
  const [rosterResponse, liveStatusResponse] = await Promise.all([
    fetch('/api/agents'),
    fetch('/api/status').catch(() => null),
  ]);

  const roster = await rosterResponse.json();
  let liveStatusMap = null;
  if (liveStatusResponse?.ok) {
    try {
      liveStatusMap = await liveStatusResponse.json();
    } catch (err) {
      console.warn('Could not parse /api/status response, falling back to /api/agents status only.', err);
    }
  }

  return Array.isArray(roster)
    ? roster.map(agent => mergeLiveStatusIntoAgent(agent, liveStatusMap))
    : [];
}

// Terrain paint preview highlight
let _terrainPreviewMesh = null;

// Weather particle system
let _rainParticles = null;
let _rainPositions = null;
let _rainInScene = false;

// LOD timer
let _lodTimer = 0;

// Smooth camera fly-to system
let _prevCamDist = 40;           // saved before entering building
let _camGoalTarget = new THREE.Vector3(0, 0, 0);
let _camGoalDist = 40;
let _camIsFlying = false;
// Current game hour (updated by updateDayNight, used by agent logic)
let _gameHour = 12;

// Real-time simulation — always 1x speed
const timeSpeed = 1;
