function setWorldTitleName(name = 'My Virtual World') {
  const title = document.getElementById('worldTitle');
  if (!title) return;
  title.innerHTML = '';
  const logo = document.createElement('img');
  logo.className = 'app-logo app-logo-topbar';
  logo.src = 'assets/logo-transparent.png';
  logo.alt = 'My Virtual World logo';
  const text = document.createElement('span');
  text.className = 'world-title-text';
  text.textContent = name || 'My Virtual World';
  title.append(logo, text);
}

function getWorldTitleName() {
  return document.querySelector('#worldTitle .world-title-text')?.textContent?.trim()
    || document.getElementById('worldTitle')?.textContent?.trim()
    || 'My Virtual World';
}

