// ═══════════════════════════════════════════════════════════════
// INIT
// ═══════════════════════════════════════════════════════════════
async function init() {
  scene = new THREE.Scene();
  scene.background = new THREE.Color(0x87ceeb); // sky blue

  // Large ground plane (green base so unloaded areas still look like grass)
  const groundGeo = new THREE.PlaneGeometry(2000, 2000);
  const groundMat = new THREE.MeshLambertMaterial({ color: 0x5a9e3a });
  const ground = new THREE.Mesh(groundGeo, groundMat);
  ground.rotation.x = -Math.PI / 2;
  ground.position.y = -0.01;
  ground.receiveShadow = true;
  scene.add(ground);
  scene.fog = new THREE.Fog(0xc9e8f7, 120, 400);

  const container = document.getElementById('pixiContainer');
  const aspect = container.clientWidth / container.clientHeight;
  const frustum = 24;
  camera = new THREE.OrthographicCamera(
    -frustum * aspect, frustum * aspect, frustum, -frustum, 0.0001, 500
  );
  updateCamera();

  renderer = new THREE.WebGLRenderer({ antialias: true, powerPreference: 'high-performance' });
  renderer.setSize(container.clientWidth, container.clientHeight);
  renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
  renderer.shadowMap.enabled = false; // disabled for performance (Crossy Road doesn't need complex shadows)
  renderer.shadowMap.type = THREE.PCFSoftShadowMap;
  container.appendChild(renderer.domElement);

  clock = new THREE.Clock();

  // Lighting — bright Crossy Road feel
  amb = new THREE.AmbientLight(0xffffff, 0.85); // brighter without shadows
  scene.add(amb);
  configureDynamicInteriorRouting({
    scene,
    apiToWorldScale: T / API_TILE,
    getInteriorBuildingAt: (apiX, apiY) => getMovementInteriorBuildingAt(apiX, apiY),
  });
  configureDynamicExteriorRouting({
    scene,
    apiToWorldScale: T / API_TILE,
    terrain: TERRAIN,
    getWorldTile: (wx, wz) => _getWorldTile(wx, wz),
    findNearestSidewalk: (wx, wz, radius) => _findNearestSidewalk(wx, wz, radius),
    pathfindSidewalk: (sx, sz, gx, gz) => _pathfindSidewalk(sx, sz, gx, gz),
    isCrosswalk: (wx, wz) => _isCrosswalk(wx, wz),
    getInteriorBuildingAt: (apiX, apiY) => getMovementInteriorBuildingAt(apiX, apiY),
    getParkAt: (apiX, apiY) => getMovementParkAt(apiX, apiY),
    getBuildingDoorSidewalkPos: (building) => getBuildingDoorSidewalkPos(building),
    getBuildingDoorPosAPI: (building) => getBuildingDoorPosAPI(building),
    getBuildingInteriorEntryPosAPI: (building) => getBuildingInteriorEntryPosAPI(building),
    getBuildingDoorwayPosAPI: (building) => getBuildingDoorwayPosAPI(building),
    getBuildingDoorwayReachApi: (building) => getBuildingDoorwayReachApi(building),
    getVehicles: () => vehiclesList,
    getSmartWaypoints: (ax, ay, tx, ty) => getSmartWaypoints(ax, ay, tx, ty),
    probeObstacleAtWorld: (worldX, worldZ, radius, options = {}) => probeObstacleAt(worldX, worldZ, radius, options),
    getAgentColliderHandle: (agentId) => getColliderHandle(`agent_${agentId}`),
  });

  sun = new THREE.DirectionalLight(0xfff8e7, 0.85);
  sun.position.set(40, 60, 30);
  sun.castShadow = true;
  sun.shadow.mapSize.set(1024, 1024); // reduced for performance
  sun.shadow.camera.left = -80;
  sun.shadow.camera.right = 80;
  sun.shadow.camera.top = 80;
  sun.shadow.camera.bottom = -80;
  sun.shadow.camera.far = 200;
  sun.shadow.bias = -0.001;
  scene.add(sun);

  hemi = new THREE.HemisphereLight(0x87ceeb, 0x6abf4b, 0.3);
  scene.add(hemi);

  // Groups
  terrainGroup = new THREE.Group();
  terrainGroup.name = 'terrainGroup';
  buildingGroup = new THREE.Group();
  buildingGroup.name = 'buildingGroup';
  agentGroup = new THREE.Group();
  agentGroup.name = 'agentGroup';
  decorGroup = new THREE.Group();
  decorGroup.name = 'decorGroup';
  scene.add(terrainGroup, buildingGroup, agentGroup, decorGroup);

  window.__vwBootStage = 'start physics';
  console.log('[VW init] start physics');
  setLoadingProgress(10, 'Initializing physics...', 'lstep-engine');
  await initPhysics();
  window.__vwBootStage = 'physics ready';
  console.log('[VW init] physics ready');
  
  setLoadingProgress(15, 'Setting up engine...', 'lstep-engine');
  initWeatherParticles();
  setupInput();
  setupToolbar();
  setupSidebar();
  setupBuildingModal();
  setupMiniMap();
  setupTimeSpeedControls();
  setupFurnitureCatalog();
  setupViewModeButtons();
  setupAgentIntentDebugReadout();
  applySavedMovementDebugOverlayPreference();
  applySavedObjectActionPointDebugPreference();
  completeLoadingStep('lstep-engine');

  window.__vwBootStage = 'load world meta';
  console.log('[VW init] load world meta');
  setLoadingProgress(30, 'Loading world data...', 'lstep-terrain');
  await loadWorldMeta();
  await loadPlacedDecorations();
  completeLoadingStep('lstep-terrain');
  window.__vwBootStage = 'world meta ready';
  console.log('[VW init] world meta ready');

  window.__vwBootStage = 'load buildings';
  console.log('[VW init] load buildings');
  setLoadingProgress(55, 'Loading buildings...', 'lstep-buildings');
  await loadBuildings();
  completeLoadingStep('lstep-buildings');
  window.__vwBootStage = 'buildings ready';
  console.log('[VW init] buildings ready', buildingsMap.size);

  window.__vwBootStage = 'load agents';
  console.log('[VW init] load agents');
  setLoadingProgress(75, 'Loading agents...', 'lstep-agents');
  await loadAgents();
  completeLoadingStep('lstep-agents');
  window.__vwBootStage = 'agents ready';
  console.log('[VW init] agents ready', agentsList.length);

  // Initialize 3D street system (must be before loadStreets)
  window.__vwBootStage = 'init street group';
  console.log('[VW init] init street group');
  initStreetGroup();

  window.__vwBootStage = 'load streets';
  console.log('[VW init] load streets');
  setLoadingProgress(85, 'Loading streets...');
  await loadStreets();
  window.__vwBootStage = 'streets ready';
  console.log('[VW init] streets ready');

  setLoadingProgress(90, 'Spawning world...');
  window.__vwBootStage = 'rebuild loaded chunks';
  console.log('[VW init] rebuild loaded chunks', loadedChunks.size);

  // Rebuild any existing chunks so building footprints cut through terrain
  // and street terrain painting is reflected
  for (const [, chunk] of loadedChunks) {
    rebuildChunk(chunk);
  }

  // Ambient life — birds (spawn immediately)
  window.__vwBootStage = 'spawn ambient';
  console.log('[VW init] spawn ambient');
  initBirds();
  initChatBubbles();

  // Streets are user-drawn — no hardcoded initial segments

  // Delay vehicle spawning until chunks are loaded (2 seconds after init)
  setTimeout(() => initVehicles(), 2000);

  // Feature 5: Minimap click-to-pan
  setupMiniMapClick();

  // World search
  setupWorldSearch();

  // Auto-generate default world only on very first run (never re-generates after user deletes buildings)
  if (buildingsMap.size === 0 && !(_worldMetaCache && _worldMetaCache.initialized)) {
    await autoGenerateDefaultWorld();
    // Rebuild affected chunks after road painting
    for (const [, chunk] of loadedChunks) {
      if (chunk.dirty) rebuildChunk(chunk);
    }
  }

  window.addEventListener('resize', onResize);
  window.__vwBootStage = 'start animate';
  console.log('[VW init] start animate');
  animate();

  // Feature 4: Hide loading screen
  window.__vwBootStage = 'hide loading screen';
  console.log('[VW init] hide loading screen');
  hideLoadingScreen();

  // Auto-fit camera to show all buildings on load
  setTimeout(() => zoomFitAll(), 500);

  showToast('🌍 My Virtual World loaded!', 'success');

  // Auto-save every 2 minutes (silent unless there were dirty chunks)
  setInterval(async () => {
    let hasDirty = false;
    for (const [, c] of loadedChunks) {
      if (c.dirty) { hasDirty = true; break; }
    }
    if (hasDirty) {
      await saveAll();
    }
  }, 120000);

  // Welcome tour (first visit only)
  startWelcomeTour();
}

// ═══════════════════════════════════════════════════════════════
// CAMERA
// ═══════════════════════════════════════════════════════════════
function getEffectiveCameraPlacementDistance(distance = camDist, options = {}) {
  const preset = CAM_PRESETS[_camPresetIdx] || {};
  let placementDistance = Math.max(distance, CAMERA_MIN_PHYSICAL_DISTANCE);

  if (preset.minCameraHeight && _camHeightFactor > 0.0001) {
    placementDistance = Math.max(placementDistance, preset.minCameraHeight / _camHeightFactor);
  }

  if (preset.minCameraHorizontal && _camHorizFactor > 0.01) {
    placementDistance = Math.max(placementDistance, preset.minCameraHorizontal / _camHorizFactor);
  }

  if (preset.name === 'Close-up' && options.viewport && _camHeightFactor > 0.0001) {
    // Close-up uses a shallow angle. When zoomed out, the lower edge of the
    // orthographic frustum can dip into the world even though the visual zoom is
    // correct. Move the physical camera farther along the same view ray only;
    // the ortho frustum stays the same size, so the camera view is preserved.
    const viewLen = Math.hypot(_camHeightFactor, _camHorizFactor);
    const cameraUpY = viewLen > 0.0001 ? _camHorizFactor / viewLen : 1;
    const bottomExtent = options.viewport.halfHeight * (1 - (options.frameBiasY || 0));
    const minDistanceForBottomClearance =
      ((bottomExtent * cameraUpY) + CAMERA_MIN_FRUSTUM_BOTTOM_CLEARANCE) / _camHeightFactor;
    placementDistance = Math.max(placementDistance, minDistanceForBottomClearance);
  }

  return placementDistance;
}

function updateCamera() {
  const d = camDist;
  const viewport = getCameraViewportMetrics(d);
  const frameBiasY = getEffectiveCameraFrameBiasY(d);
  const placementDistance = getEffectiveCameraPlacementDistance(d, { viewport, frameBiasY });
  camera.position.set(
    camTarget.x + Math.sin(camAngle) * placementDistance * _camHorizFactor,
    placementDistance * _camHeightFactor,
    camTarget.z + Math.cos(camAngle) * placementDistance * _camHorizFactor
  );
  camera.lookAt(camTarget);
  camera.left = -viewport.halfWidth;
  camera.right = viewport.halfWidth;
  camera.top = viewport.halfHeight * (1 + frameBiasY);
  camera.bottom = -viewport.halfHeight * (1 - frameBiasY);
  camera.updateProjectionMatrix();

  // Update sun shadow to follow camera
  if (sun) {
    const sunOffset = sun.userData?.vwOrbitOffset;
    if (sunOffset) {
      sun.position.set(camTarget.x + sunOffset.x, sunOffset.y, camTarget.z + sunOffset.z);
    } else {
      sun.position.set(camTarget.x + 40, 60, camTarget.z + 30);
    }
    sun.target.position.copy(camTarget);
    sun.shadow.camera.updateProjectionMatrix();
  }

  // UI
  const zl = document.getElementById('zoomLevel');
  if (zl) zl.textContent = (40 / camDist).toFixed(1) + 'x';
  const cd = document.getElementById('coordDisplay');
  if (cd) cd.textContent = `${Math.round(camTarget.x)}, ${Math.round(camTarget.z)}`;
}

function getEffectiveCameraFrameBiasY(distance = camDist) {
  let frameBiasY = _camFrameBiasY || 0;
  const presetName = CAM_PRESETS[_camPresetIdx]?.name || '';

  if (presetName === 'Close-up') {
    frameBiasY += Math.max(0, Math.min(0.18, (distance - 20) * 0.0045));
  } else if (presetName === 'Isometric') {
    frameBiasY += Math.max(0, Math.min(0.08, (18 - distance) * 0.01));
  }

  return Math.max(-0.35, Math.min(0.35, frameBiasY));
}

function resetCamera() {
  flyCameraTo(new THREE.Vector3(0, 0, 0), 40);
}

function getRendererViewportMetrics() {
  const container = document.getElementById('pixiContainer');
  const rect = renderer?.domElement?.getBoundingClientRect?.() || container?.getBoundingClientRect?.() || {
    left: 0,
    top: 0,
    width: container?.clientWidth || window.innerWidth || 1,
    height: container?.clientHeight || window.innerHeight || 1,
  };
  const width = Math.max(1, Math.round(rect.width || container?.clientWidth || 1));
  const height = Math.max(1, Math.round(rect.height || container?.clientHeight || 1));
  return {
    width,
    height,
    left: rect.left || 0,
    top: rect.top || 0,
  };
}

function getViewportCoverageScale(width, height, distance = camDist) {
  const widthScale = width / CAMERA_BASE_VIEWPORT.width;
  const heightScale = height / CAMERA_BASE_VIEWPORT.height;
  const dominantScale = Math.max(widthScale, heightScale);
  const responsiveScale = 1 + (dominantScale - 1) * 0.45;

  const closeRangeStart = 24;
  const closeRangeEnd = 10;
  const closeRange = closeRangeStart - closeRangeEnd;
  const closeT = closeRange > 0
    ? Math.max(0, Math.min(1, (closeRangeStart - distance) / closeRange))
    : 0;
  const dampedScale = responsiveScale + (1 - responsiveScale) * closeT;

  return Math.max(0.9, Math.min(1.28, dampedScale));
}

function getCameraViewportMetrics(distance = camDist) {
  const viewport = getRendererViewportMetrics();
  const aspect = viewport.width / viewport.height;
  const coverageScale = getViewportCoverageScale(viewport.width, viewport.height, distance);
  const halfHeight = distance * 0.55 * coverageScale;
  const halfWidth = halfHeight * aspect;
  return {
    ...viewport,
    aspect,
    coverageScale,
    halfWidth,
    halfHeight,
    worldWidth: halfWidth * 2,
    worldHeight: halfHeight * 2,
  };
}

// Zoom to fit all buildings in view (Z key)
function zoomFitAll() {
  if (buildingsMap.size === 0) {
    flyCameraTo(new THREE.Vector3(0, 0, 0), 40);
    showToast('No buildings to zoom to', 'warning');
    return;
  }
  let minX = Infinity, maxX = -Infinity, minZ = Infinity, maxZ = -Infinity;
  for (const [, b] of buildingsMap) {
    const bounds = getBuildingFootprintBounds(b, 0);
    minX = Math.min(minX, bounds.minX); maxX = Math.max(maxX, bounds.maxX);
    minZ = Math.min(minZ, bounds.minZ); maxZ = Math.max(maxZ, bounds.maxZ);
  }
  const cx = (minX + maxX) / 2;
  const cz = (minZ + maxZ) / 2;
  const span = Math.max(maxX - minX, maxZ - minZ);
  const dist = Math.max(20, span * 0.7);
  flyCameraTo(new THREE.Vector3(cx, 0, cz), dist);
  showToast('🔭 Zoomed to fit all buildings', 'success');
}

// Smoothly animate camera to a goal (lerp in animate loop)
function flyCameraTo(targetPos, targetDist) {
  _camGoalTarget.copy(targetPos);
  _camGoalDist = targetDist;
  _camIsFlying = true;
}

function updateSmoothCamera(dt) {
  let needsUpdate = false;

  // ── SMOOTH WASD/ARROW KEY MOVEMENT ──
  // Build input direction from held keys
  let inputX = 0, inputZ = 0;
  if (_keysDown.has('w') || _keysDown.has('arrowup'))    inputZ = -1;
  if (_keysDown.has('s') || _keysDown.has('arrowdown'))  inputZ =  1;
  if (_keysDown.has('a') || _keysDown.has('arrowleft'))  inputX = -1;
  if (_keysDown.has('d') || _keysDown.has('arrowright')) inputX =  1;

  const hasInput = inputX !== 0 || inputZ !== 0;

  if (hasInput) {
    // Cancel fly-to when user takes manual control
    _camIsFlying = false;

    // Normalize diagonal input so it doesn't go faster
    const len = Math.sqrt(inputX * inputX + inputZ * inputZ);
    if (len > 0) { inputX /= len; inputZ /= len; }

    // Scale speed by zoom level (further out = faster pan)
    const speedScale = camDist * 0.04;
    const accel = CAM_ACCEL * speedScale * dt;

    // Apply acceleration in camera-relative direction
    _camVelocity.x += inputX * accel;
    _camVelocity.z += inputZ * accel;

    // Clamp to max speed
    const speed = Math.sqrt(_camVelocity.x * _camVelocity.x + _camVelocity.z * _camVelocity.z);
    const maxSpd = CAM_MAX_SPEED * speedScale;
    if (speed > maxSpd) {
      _camVelocity.x *= maxSpd / speed;
      _camVelocity.z *= maxSpd / speed;
    }
  }

  // Apply friction (always, so camera decelerates smoothly when keys released)
  const frictionFactor = Math.max(0, 1 - CAM_FRICTION * dt);
  _camVelocity.x *= frictionFactor;
  _camVelocity.z *= frictionFactor;

  // Apply velocity to camera target (rotated by camera angle)
  const vMag = Math.sqrt(_camVelocity.x * _camVelocity.x + _camVelocity.z * _camVelocity.z);
  if (vMag > 0.001) {
    // Rotate input by camera angle so WASD moves relative to view direction
    const cosA = Math.cos(camAngle);
    const sinA = Math.sin(camAngle);
    const worldDX = _camVelocity.x * cosA + _camVelocity.z * sinA;
    const worldDZ = -_camVelocity.x * sinA + _camVelocity.z * cosA;
    camTarget.x += worldDX * dt;
    camTarget.z += worldDZ * dt;
    needsUpdate = true;
  } else {
    _camVelocity.set(0, 0, 0); // zero out tiny residual
  }

  // Smooth pan/zoom fly-to
  if (_camIsFlying) {
    const alpha = Math.min(1, dt * 6);
    camTarget.lerp(_camGoalTarget, alpha);
    camDist += (_camGoalDist - camDist) * alpha;
    needsUpdate = true;
    if (camTarget.distanceTo(_camGoalTarget) < 0.1 && Math.abs(camDist - _camGoalDist) < 0.1) {
      camTarget.copy(_camGoalTarget);
      camDist = _camGoalDist;
      _camIsFlying = false;
    }
  }

  // Smooth rotation
  if (_camRotating) {
    const diff = _camAngleTarget - camAngle;
    if (Math.abs(diff) < 0.005) {
      camAngle = _camAngleTarget;
      _camRotating = false;
    } else {
      camAngle += diff * Math.min(1, dt * 8);
    }
    needsUpdate = true;
  }

  if (needsUpdate) updateCamera();
}

// ═══════════════════════════════════════════════════════════════
// DAY / NIGHT CYCLE
// 1 real minute = 1 game hour (compressed 24-hr cycle)
// ═══════════════════════════════════════════════════════════════
const DAY_STATES = [
  // [gameHour, skyHex, ambHex, ambIntensity, sunHex, sunIntensity, sunElevation, fogHex]
  { h:  0, sky:0x0d1533, ambC:0x253060, ambI:0.35, sunC:0x4060b0, sunI:0.2,  sunElev:-0.3, fog:0x0d1533 }, // midnight — blue moonlight
  { h:  5, sky:0x1a2050, ambC:0x354070, ambI:0.4,  sunC:0x5070c0, sunI:0.25, sunElev:-0.1, fog:0x1a2050 }, // pre-dawn — blue hint
  { h:  6, sky:0xff9966, ambC:0xff9060, ambI:0.5,  sunC:0xffb060, sunI:0.6,  sunElev: 0.1, fog:0xffaa88 }, // dawn
  { h:  8, sky:0x87ceeb, ambC:0xfff0d0, ambI:0.75, sunC:0xfff5e0, sunI:0.8,  sunElev: 0.5, fog:0xc9e8f7 }, // morning
  { h: 12, sky:0x87ceeb, ambC:0xffffff, ambI:0.85, sunC:0xfff8e7, sunI:0.9,  sunElev: 1.0, fog:0xc9e8f7 }, // noon
  { h: 16, sky:0x87ceeb, ambC:0xfff0d0, ambI:0.75, sunC:0xfff5e0, sunI:0.8,  sunElev: 0.5, fog:0xc9e8f7 }, // afternoon
  { h: 18, sky:0xff7043, ambC:0xff6030, ambI:0.55, sunC:0xff8040, sunI:0.6,  sunElev: 0.1, fog:0xff9966 }, // dusk
  { h: 20, sky:0x152040, ambC:0x253060, ambI:0.35, sunC:0x4060b0, sunI:0.2,  sunElev:-0.2, fog:0x152040 }, // evening — blue tint
  { h: 22, sky:0x0d1533, ambC:0x253060, ambI:0.35, sunC:0x4060b0, sunI:0.2,  sunElev:-0.3, fog:0x0d1533 }, // night — blue moonlight
  { h: 24, sky:0x0d1533, ambC:0x253060, ambI:0.35, sunC:0x4060b0, sunI:0.2,  sunElev:-0.3, fog:0x0d1533 }, // midnight (wrap)
];

let _dayNightWindowLights = []; // building window meshes for night glow

function lerpHex(a, b, t) {
  const ca = new THREE.Color(a), cb = new THREE.Color(b);
  ca.lerp(cb, t);
  return ca;
}

// Accumulated time offset for speed control
// Initialize to current real-world time so game starts in sync
const _realTimeBase = (() => {
  const now = new Date();
  return now.getHours() + now.getMinutes() / 60 + now.getSeconds() / 3600;
})();
let _gameTimeAccum = _realTimeBase * 60; // convert hours to "game minutes" (1 game minute = 1 game hour at 1x)
let _gameTimeLast = null;

function applyDayNightState(gameHour) {
  _gameHour = gameHour;

  // Find surrounding states
  let a = DAY_STATES[DAY_STATES.length - 2], b = DAY_STATES[DAY_STATES.length - 1];
  for (let i = 0; i < DAY_STATES.length - 1; i++) {
    if (gameHour >= DAY_STATES[i].h && gameHour < DAY_STATES[i + 1].h) {
      a = DAY_STATES[i]; b = DAY_STATES[i + 1]; break;
    }
  }
  const t = (gameHour - a.h) / (b.h - a.h || 1);

  // Sky / fog
  const skyCol = lerpHex(a.sky, b.sky, t);
  scene.background = skyCol;
  if (scene.fog) scene.fog.color.copy(lerpHex(a.fog, b.fog, t));

  // Ambient
  if (amb) {
    amb.color.copy(lerpHex(a.ambC, b.ambC, t));
    amb.intensity = a.ambI + (b.ambI - a.ambI) * t;
  }

  // Sun (direction + colour)
  if (sun) {
    const elev = a.sunElev + (b.sunElev - a.sunElev) * t;
    const angle = ((gameHour - 6) / 12) * Math.PI; // arc east → west
    sun.color.copy(lerpHex(a.sunC, b.sunC, t));
    sun.intensity = a.sunI + (b.sunI - a.sunI) * t;
    sun.userData.vwOrbitOffset = new THREE.Vector3(
      Math.cos(angle) * 60,
      60 * Math.max(0.05, elev),
      Math.sin(angle) * 40
    );
    sun.position.set(
      camTarget.x + sun.userData.vwOrbitOffset.x,
      sun.userData.vwOrbitOffset.y,
      camTarget.z + sun.userData.vwOrbitOffset.z
    );
  }

  // Hemi sky colour
  if (hemi) {
    hemi.color.copy(lerpHex(a.sky, b.sky, t));
    hemi.intensity = 0.15 + (a.ambI + (b.ambI - a.ambI) * t) * 0.25;
  }

  // Building window glow at night
  const isNight = gameHour >= 20 || gameHour < 6;
  const winOpacity = isNight ? Math.min(1, (gameHour >= 20 ? (gameHour - 20) / 2 : (6 - gameHour) / 2) * 2) : 0;
  _dayNightWindowLights.forEach(m => {
    if (m.material) {
      m.material.emissiveIntensity = winOpacity * 0.9;
    }
  });
}

function updateDayNight() {
  if (!_dayNightCycleEnabled) {
    applyDayNightState(12);
    return;
  }

  // Game time: 1 real minute = 1 game hour (at 1x speed)
  // But we START synced to real clock, so at 1x speed, time drifts 60x faster.
  // To keep real-time sync at 1x, use real clock directly when timeSpeed === 1.
  const nowSec = performance.now() / 1000;
  if (_gameTimeLast === null) _gameTimeLast = nowSec;
  const dt = nowSec - _gameTimeLast;
  _gameTimeLast = nowSec;

  if (timeSpeed === 1) {
    // Real-time sync: game hour = real hour
    const now = new Date();
    const realHour = now.getHours() + now.getMinutes() / 60 + now.getSeconds() / 3600;
    _gameTimeAccum = realHour * 60;
  } else {
    // Accelerated or paused: advance manually
    _gameTimeAccum += dt * timeSpeed;
  }

  applyDayNightState((_gameTimeAccum / 60) % 24);
}

// Register a building window mesh for night-glow tracking
function registerWindowMesh(mesh) {
  mesh.material = mesh.material.clone();
  mesh.material.emissive = new THREE.Color(0xffee88);
  mesh.material.emissiveIntensity = 0;
  _dayNightWindowLights.push(mesh);
}

// ═══════════════════════════════════════════════════════════════
// WEATHER PARTICLE SYSTEM
// ═══════════════════════════════════════════════════════════════
function initWeatherParticles() {
  const COUNT = 2000;
  const geo = new THREE.BufferGeometry();
  const positions = new Float32Array(COUNT * 3);

  for (let i = 0; i < COUNT; i++) {
    positions[i * 3]     = (Math.random() - 0.5) * 80; // x spread
    positions[i * 3 + 1] = Math.random() * 20;          // y: 0-20
    positions[i * 3 + 2] = (Math.random() - 0.5) * 80; // z spread
  }

  geo.setAttribute('position', new THREE.BufferAttribute(positions, 3));

  const mat = new THREE.PointsMaterial({
    color: 0xc0e0ff,
    size: 0.25,
    transparent: true,
    opacity: 0.7,
    sizeAttenuation: true,
    depthWrite: false,
  });

  _rainParticles = new THREE.Points(geo, mat);
  _rainPositions = positions;
  // Don't add to scene yet — controlled by weather state
}

function updateWeatherParticles(dt) {
  if (!_rainParticles) return;

  if (!_weatherEnabled) {
    if (_rainInScene) {
      scene.remove(_rainParticles);
      _rainInScene = false;
    }
    return;
  }

  // Rain during afternoon OR randomly (20% chance per hour, checked at hour boundaries)
  const weatherHour = _dayNightCycleEnabled
    ? _gameHour
    : (() => {
        const now = new Date();
        return now.getHours() + now.getMinutes() / 60 + now.getSeconds() / 3600;
      })();
  const hourInt = Math.floor(weatherHour);
  const isRaining = (weatherHour >= 14 && weatherHour < 16) ||
                    (pseudoRandom(hourInt * 137 + 42) < 0.15 && weatherHour >= 8 && weatherHour < 20);

  if (isRaining && !_rainInScene) {
    scene.add(_rainParticles);
    _rainInScene = true;
  } else if (!isRaining && _rainInScene) {
    scene.remove(_rainParticles);
    _rainInScene = false;
  }

  if (!_rainInScene) return;

  // Update particle positions — fall down with slight wind tilt
  const fallSpeed = 12 * dt;
  const windX = 1.0 * dt;
  const COUNT = 2000;
  // Follow camera so rain always surrounds the player
  const cx = camTarget.x;
  const cz = camTarget.z;
  const viewport = getCameraViewportMetrics();
  // Scale particle spread to cover the actual visible viewport, not a fixed screen profile.
  const spreadX = Math.max(60, viewport.worldWidth * 1.15);
  const spreadZ = Math.max(60, viewport.worldHeight * 1.35);
  const halfSpreadX = spreadX / 2;
  const halfSpreadZ = spreadZ / 2;
  const maxHeight = Math.max(15, viewport.worldHeight * 0.6);

  for (let i = 0; i < COUNT; i++) {
    _rainPositions[i * 3]     += windX;
    _rainPositions[i * 3 + 1] -= fallSpeed;

    // Reset to top when particle hits ground
    if (_rainPositions[i * 3 + 1] < 0) {
      _rainPositions[i * 3]     = cx + (Math.random() - 0.5) * spreadX;
      _rainPositions[i * 3 + 1] = maxHeight * Math.random();
      _rainPositions[i * 3 + 2] = cz + (Math.random() - 0.5) * spreadZ;
    }

    // Re-anchor particles that drift too far from camera center
    const pdx = _rainPositions[i * 3] - cx;
    const pdz = _rainPositions[i * 3 + 2] - cz;
    if (Math.abs(pdx) > halfSpreadX || Math.abs(pdz) > halfSpreadZ) {
      _rainPositions[i * 3]     = cx + (Math.random() - 0.5) * spreadX;
      _rainPositions[i * 3 + 1] = maxHeight * Math.random();
      _rainPositions[i * 3 + 2] = cz + (Math.random() - 0.5) * spreadZ;
    }
  }

  // Scale particle size with zoom so rain stays visible at all distances
  _rainParticles.material.size = Math.max(0.15, 0.25 * (camDist / 40));
  _rainParticles.geometry.attributes.position.needsUpdate = true;
}

// ═══════════════════════════════════════════════════════════════
// FEATURE 4 — AGENT COUNT BADGES ON BUILDINGS
// ═══════════════════════════════════════════════════════════════
function updateAgentBadges() {
  const scale = T / API_TILE;
  for (const [, b] of buildingsMap) {
    if (!b._badgeSprite) continue;
    const bounds = getBuildingFootprintBounds(b, 0);
    const bx1 = bounds.minX, bx2 = bounds.maxX;
    const bz1 = bounds.minZ, bz2 = bounds.maxZ;
    let count = 0;
    agentsList.forEach(a => {
      const ax = a.x * scale, az = a.y * scale;
      if (ax >= bx1 && ax <= bx2 && az >= bz1 && az <= bz2) count++;
    });
    b._badgeSprite.visible = count > 0;
    if (count !== b._lastBadgeCount) {
      b._lastBadgeCount = count;
      updateBadgeSprite(b._badgeSprite, count);
    }
  }
}

// ═══════════════════════════════════════════════════════════════
// FEATURE 5 — WORLD STATS DISPLAY
// ═══════════════════════════════════════════════════════════════
function updateWorldStats() {
  const hEl = document.getElementById('statBuildings');
  const aEl = document.getElementById('statAgents');
  const tEl = document.getElementById('statTime');
  const nEl = document.getElementById('statWorldName');

  if (hEl) hEl.textContent = buildingsMap.size;
  if (aEl) {
    const working = agentsList.filter(a => normalizeLiveAgentStatus(a.status) === 'working').length;
    const finishing = agentsList.filter(a => a.status === 'finishing').length;
    const idle = agentsList.filter(a => a.status === 'idle').length;
    const onBreak = agentsList.filter(a => a.status === 'break').length;
    const meeting = agentsList.filter(a => a.status === 'meeting' || a._meetingId).length;
    const offline = agentsList.length - working - finishing - idle - onBreak - meeting;
    if (working > 0 || finishing > 0 || idle > 0 || onBreak > 0 || meeting > 0) {
      aEl.innerHTML = `${agentsList.length} <span style="font-size:9px;opacity:0.7">(🟢${working} 🟩${finishing} 🟡${idle} 🟠${onBreak} 🔵${meeting} ⚫${offline})</span>`;
    } else {
      aEl.textContent = agentsList.length;
    }
  }
  if (tEl) {
    const weatherIcon = _rainInScene ? ' 🌧️' : '';
    if (!_dayNightCycleEnabled) {
      tEl.innerHTML = `☀️ Static Day${weatherIcon}`;
    } else {
      const h = Math.floor(_gameHour);
      const m = Math.floor((_gameHour - h) * 60);
      const ampm = h >= 12 ? 'PM' : 'AM';
      const hh = h % 12 || 12;
      const isDay = h >= 6 && h < 18;
      const dayIcon = isDay ? '☀️' : '🌙';
      // Show real date when at 1x speed (synced to real clock)
      const now = new Date();
      const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
      const dayLabel = timeSpeed === 1
        ? `${dayNames[now.getDay()]} ${now.getMonth() + 1}/${now.getDate()}`
        : `Day ${Math.floor(_gameTimeAccum / (60 * 24)) + 1}`;
      tEl.innerHTML = `${dayIcon} ${dayLabel} &nbsp; ${hh}:${String(m).padStart(2, '0')} ${ampm}${weatherIcon}`;
    }
  }
  if (nEl) {
    nEl.textContent = getWorldTitleName();
  }
}

// ═══════════════════════════════════════════════════════════════
// ANIMATE
// ═══════════════════════════════════════════════════════════════
let _statsUpdateTimer = 0;
const MINIMAP_UPDATE_INTERVAL_SEC = 0.5; // PERF: full tile redraw is costly; 2Hz is plenty for a 200px overview map
let _miniMapUpdateTimer = MINIMAP_UPDATE_INTERVAL_SEC;

let _animErrorCount = 0;
function animate() {
  requestAnimationFrame(animate);
  try {
    const dt = Math.min(clock.getDelta(), 0.05);
    waterTick += dt;

    updateDayNight();
    updateSmoothCamera(dt);
    updateChunks();
    updateAgentAnimations(dt);
    updatePingPongGames(dt);
    updateTrafficLights(dt);
    updateVehicles(dt);
    
    // Step physics after all positions are updated
    if (isPhysicsReady()) stepPhysics(dt);
    updateBirds(dt);
    updateWaterAnimation();
    updateWeatherParticles(dt);
    updateBuildingSelectionOutline();
    updateAutoDoors(dt);
    updateDoorAnimations(dt);
    updateElevatorAnimations(dt);
    updateInteractiveFurnitureFeedback(dt);
    updateSurfacePlacementSlotHighlights(dt);
    _miniMapUpdateTimer += dt;
    if (_miniMapUpdateTimer >= MINIMAP_UPDATE_INTERVAL_SEC) {
      _miniMapUpdateTimer = 0;
      updateMiniMap();
    }

    // Feature 4 & 5: Update badges + stats every ~0.5s (not every frame)
    _statsUpdateTimer += dt;
    if (_statsUpdateTimer > 0.5) {
      _statsUpdateTimer = 0;
      updateAgentBadges();
      updateWorldStats();
      updateStatsPanel();
    }

    // LOD: check once per second
    _lodTimer += dt;
    if (_lodTimer >= 1.0) {
      _lodTimer = 0;
      updateBuildingLOD();
    }

    renderer.render(scene, camera);

    // Chat bubble/floating controls positions (must be after render so projection is current)
    updateChatBubblePositions();
    updateFloorControlPosition();

    // FPS
    fpsFrames++;
    const now = performance.now();
    if (now - fpsLast >= 1000) {
      fpsDisplay = fpsFrames;
      fpsFrames = 0;
      fpsLast = now;
      const el = document.getElementById('fpsDisplay');
      if (el) el.textContent = fpsDisplay + ' fps';
    }
    _animErrorCount = 0; // reset on successful frame
  } catch (err) {
    _animErrorCount++;
    if (_animErrorCount <= 3) {
      // Show toast on first few errors but keep rendering
      showToast('⚠️ Render error (continuing)', 'warning');
    }
    // Never stop the loop — rendering must survive individual errors
  }
}

function setMeshColor(mesh, color) {
  if (!mesh?.material?.color) return;
  mesh.material.color.setHex(color);
}

const _interactiveFurnitureFeedbackMeshes = new Set();

function isObjectAttachedToScene(object) {
  let current = object;
  while (current) {
    if (current === scene) return true;
    current = current.parent || null;
  }
  return false;
}

function registerInteractiveFurnitureFeedbackMesh(mesh) {
  if (!mesh?.userData?.arcadeFeedbackParts) return;
  _interactiveFurnitureFeedbackMeshes.add(mesh);
}

function updateArcadeMachineFeedback(mesh, furniture, dt) {
  const parts = mesh?.userData?.arcadeFeedbackParts;
  if (!parts || !furniture) return;
  const active = furniture.activeUse?.state === 'active' || furniture.arcadeMachineState?.status === 'playing' || furniture.playMode === 'playing';
  const reserved = !active && (furniture.activeUse?.state === 'reserved' || furniture.reservation?.status === 'held' || furniture.playMode === 'reserved');
  const t = performance.now() / 1000;
  const pulse = active ? (0.5 + Math.sin(t * 9.0) * 0.5) : (reserved ? (0.5 + Math.sin(t * 3.0) * 0.5) : (0.5 + Math.sin(t * 1.2) * 0.5));
  setMeshColor(parts.screenMesh, active ? 0x0b1120 : (reserved ? 0x172554 : 0x0f172a));
  setMeshColor(parts.screenGlowA, active ? (pulse > 0.5 ? 0x22d3ee : 0xf472b6) : (reserved ? 0x818cf8 : 0x22d3ee));
  setMeshColor(parts.screenGlowB, active ? (pulse > 0.5 ? 0xfacc15 : 0x22c55e) : (reserved ? 0x67e8f9 : 0xa78bfa));
  setMeshColor(parts.marqueeMesh, active ? (pulse > 0.5 ? 0xfef08a : 0x67e8f9) : 0xfef3c7);
  if (parts.joystickKnob) parts.joystickKnob.rotation.z = parts.baseJoystickRotationZ + (active ? Math.sin(t * 7.5) * 0.18 : 0);
  (parts.buttonMeshes || []).forEach((button, idx) => {
    const baseY = parts.baseButtonY?.[idx] ?? button.position.y;
    button.position.y = baseY + (active ? Math.max(0, Math.sin(t * 10 + idx * 1.7)) * 0.018 : 0);
  });
}

function updateInteractiveFurnitureFeedback(dt = 0) {
  if (!scene || !buildingsMap) return;
  for (const mesh of _interactiveFurnitureFeedbackMeshes) {
    if (!mesh?.userData?.arcadeFeedbackParts || !isObjectAttachedToScene(mesh)) {
      _interactiveFurnitureFeedbackMeshes.delete(mesh);
      continue;
    }
    const building = buildingsMap.get(mesh.userData.buildingId);
    const furniture = building?.interior?.furniture?.[mesh.userData.furnitureIndex];
    updateArcadeMachineFeedback(mesh, furniture, dt);
  }
}

// ═══════════════════════════════════════════════════════════════
// TERRAIN — CHUNK SYSTEM
// ═══════════════════════════════════════════════════════════════
function chunkKey(cx, cz) { return `${cx},${cz}`; }

// PERF: updateChunks only needs to do work when the camera target crosses a
// chunk boundary (or after an explicit chunk rebuild bumps the force flag).
let _lastChunkCx = null;
let _lastChunkCz = null;
let _chunksDirty = true;
function markChunksDirty() { _chunksDirty = true; }

function updateChunks() {
  const cx = Math.floor(camTarget.x / CHUNK_W);
  const cz = Math.floor(camTarget.z / CHUNK_W);
  if (!_chunksDirty && cx === _lastChunkCx && cz === _lastChunkCz) return;
  _lastChunkCx = cx;
  _lastChunkCz = cz;
  _chunksDirty = false;
  for (let dz = -LOAD_R; dz <= LOAD_R; dz++) {
    for (let dx = -LOAD_R; dx <= LOAD_R; dx++) {
      const key = chunkKey(cx + dx, cz + dz);
      if (!loadedChunks.has(key)) createChunk(cx + dx, cz + dz);
    }
  }
  for (const [key, c] of loadedChunks) {
    if (Math.max(Math.abs(c.cx - cx), Math.abs(c.cz - cz)) > LOAD_R + 2) {
      terrainGroup.remove(c.mesh);
      if (c.decors) decorGroup.remove(c.decors);
      c.mesh.geometry?.dispose();
      loadedChunks.delete(key);
    }
  }
}

function createChunk(cx, cz) {
  const key = chunkKey(cx, cz);
  if (loadedChunks.has(key)) return;
  const terrain = new Array(CHUNK * CHUNK).fill(TERRAIN.GRASS);
  const mesh = buildChunkMesh(terrain, cx, cz);
  terrainGroup.add(mesh);
  const decors = buildChunkDecorations(terrain, cx, cz);
  decorGroup.add(decors);
  const data = { cx, cz, terrain, mesh, decors, dirty: false };
  loadedChunks.set(key, data);

  fetchChunk(cx, cz).then(d => {
    if (d && d.terrain) {
      data.terrain = d.terrain;
      // Repaint street terrain on newly loaded chunks
      _repaintStreetTerrainForChunk(cx, cz);
      rebuildChunk(data);
    }
  });
}

function rebuildChunk(data) {
  terrainGroup.remove(data.mesh);
  data.mesh.geometry?.dispose();
  data.mesh = buildChunkMesh(data.terrain, data.cx, data.cz);
  terrainGroup.add(data.mesh);
  if (data.decors) decorGroup.remove(data.decors);
  data.decors = buildChunkDecorations(data.terrain, data.cx, data.cz);
  decorGroup.add(data.decors);
}

function buildChunkMesh(terrain, cx, cz) {
  const positions = [], normals = [], colors = [];
  const col = new THREE.Color();
  const tH = 0.2;

  for (let tz = 0; tz < CHUNK; tz++) {
    for (let tx = 0; tx < CHUNK; tx++) {
      const type = terrain[tz * CHUNK + tx] || TERRAIN.GRASS;
      const cols = T_COL[type] || T_COL[TERRAIN.GRASS];
      const v = ((tx + tz) % 2) + ((tx * 7 + tz * 13) % 2);
      col.setHex(cols[v % cols.length]);

      const x = cx * CHUNK_W + tx * T;
      const z = cz * CHUNK_W + tz * T;

      // Skip terrain tiles under buildings (building floor replaces them)
      if (isInsideBuildingFootprint(x + 0.5, z + 0.5, 0)) continue;

      // Slight height variation for grass — organic look
      const grassRng = pseudoRandom(cx * 997 + cz * 701 + tx * 31 + tz * 97);
      const grassBump = type === TERRAIN.GRASS ? (grassRng - 0.5) * 0.04 : 0;
      // Grass color patches — Perlin-like variation using low-frequency noise
      if (type === TERRAIN.GRASS) {
        const patchRng = pseudoRandom(Math.floor(x / 5) * 137 + Math.floor(z / 5) * 89);
        if (patchRng < 0.15) col.setHex(0x5cb85c); // lighter patch
        else if (patchRng > 0.85) col.setHex(0x4a8f3f); // darker patch
      }
      // Roads are slightly lower than sidewalks to create curb effect
      const roadDip = type === TERRAIN.ROAD ? -0.03 : (type === TERRAIN.PARKING ? -0.02 : 0);
      const y = type === TERRAIN.WATER ? -0.1 : grassBump + roadDip;

      // Top face
      addQuad(positions, normals, colors, col,
        x, y + tH, z, x + T, y + tH, z, x + T, y + tH, z + T, x, y + tH, z + T, 0, 1, 0);

      // Side faces removed for performance (top face only = 3x faster)

      // Road markings — use world-space coords for consistent pattern
      if (type === TERRAIN.ROAD) {
        // Check neighbours for road continuity
        const hasLeft  = tx > 0           && terrain[tz * CHUNK + tx - 1] === TERRAIN.ROAD;
        const hasRight = tx < CHUNK - 1   && terrain[tz * CHUNK + tx + 1] === TERRAIN.ROAD;
        const hasUp    = tz > 0           && terrain[(tz - 1) * CHUNK + tx] === TERRAIN.ROAD;
        const hasDown  = tz < CHUNK - 1   && terrain[(tz + 1) * CHUNK + tx] === TERRAIN.ROAD;
        const roadNeighbours = [hasLeft, hasRight, hasUp, hasDown].filter(Boolean).length;
        const isIntersection = roadNeighbours >= 2 && (hasLeft || hasRight) && (hasUp || hasDown);

        // World-space tile coords for consistent dash pattern
        const worldTX = cx * CHUNK + tx;
        const worldTZ = cz * CHUNK + tz;

        if (isIntersection) {
          // Intersections: no pavement markings; keep the road surface clear.
          // Just bare road surface
        } else {
          // 10-30 skip pattern: 1 tile dash, 3 tiles gap (using world coords for consistency)
          const isHorizontal = hasLeft || hasRight;
          const isVertical = hasUp || hasDown;

          if (isHorizontal && (worldTZ % 4 === 0)) {
            // Yellow center dash for horizontal road (runs along X axis)
            col.setHex(0xffd600);
            const dw = 0.7, dh = 0.15; // dash width along road, height across
            addQuad(positions, normals, colors, col,
              x + 0.15, tH + 0.012, z + 0.5 - dh/2,
              x + 0.15 + dw, tH + 0.012, z + 0.5 - dh/2,
              x + 0.15 + dw, tH + 0.012, z + 0.5 + dh/2,
              x + 0.15, tH + 0.012, z + 0.5 + dh/2, 0, 1, 0);
          } else if (isVertical && (worldTX % 4 === 0)) {
            // Yellow center dash for vertical road (runs along Z axis)
            col.setHex(0xffd600);
            const dw = 0.15, dh = 0.7;
            addQuad(positions, normals, colors, col,
              x + 0.5 - dw/2, tH + 0.012, z + 0.15,
              x + 0.5 + dw/2, tH + 0.012, z + 0.15,
              x + 0.5 + dw/2, tH + 0.012, z + 0.15 + dh,
              x + 0.5 - dw/2, tH + 0.012, z + 0.15 + dh, 0, 1, 0);
          }
        }
      }

      // Parking lines
      if (type === TERRAIN.PARKING && tx % 3 === 0) {
        col.setHex(0xeeeeee);
        addQuad(positions, normals, colors, col,
          x + 0.45, tH + 0.01, z, x + 0.55, tH + 0.01, z,
          x + 0.55, tH + 0.01, z + T, x + 0.45, tH + 0.01, z + T, 0, 1, 0);
      }

      // Terrain variety on grass: rocks (1%) and flowers (0.5%)
      // Skip decorations inside building footprints
      if (type === TERRAIN.GRASS && !isInsideBuildingFootprint(x, z, 0)) {
        const terrainRng = pseudoRandom(cx * 10007 + cz * 9001 + tx * 31 + tz * 97);
        if (terrainRng < 0.01) {
          // Small rock — dark gray tiny box (3 crossed quads)
          const rx = x + 0.3 + terrainRng * 0.4;
          const rz = z + 0.3 + pseudoRandom(terrainRng * 13) * 0.4;
          const rs = 0.12 + terrainRng * 0.1;
          col.setHex(0x666666);
          // Top face of rock
          addQuad(positions, normals, colors, col,
            rx, tH + rs, rz, rx + rs, tH + rs, rz,
            rx + rs, tH + rs, rz + rs, rx, tH + rs, rz + rs, 0, 1, 0);
          // Front face
          col.setHex(0x555555);
          addQuad(positions, normals, colors, col,
            rx, tH, rz + rs, rx + rs, tH, rz + rs,
            rx + rs, tH + rs, rz + rs, rx, tH + rs, rz + rs, 0, 0, 1);
        } else if (terrainRng < 0.015) {
          // Flower — tiny colored dot (cross of 2 quads)
          const flowerColors = [0xf44336, 0xffeb3b, 0x9c27b0, 0xffffff, 0xff69b4];
          const fRng = pseudoRandom(terrainRng * 997);
          col.setHex(flowerColors[Math.floor(fRng * flowerColors.length)]);
          const fx = x + 0.2 + fRng * 0.6;
          const fz = z + 0.2 + pseudoRandom(fRng * 7) * 0.6;
          const fs = 0.1;
          // Flat flower face (X quad)
          addQuad(positions, normals, colors, col,
            fx - fs, tH + 0.05, fz, fx + fs, tH + 0.05, fz,
            fx + fs, tH + 0.05, fz + fs * 0.5, fx - fs, tH + 0.05, fz + fs * 0.5, 0, 1, 0);
          // Green stem/center
          col.setHex(0x4caf50);
          addQuad(positions, normals, colors, col,
            fx, tH + 0.01, fz - fs * 0.5, fx + fs * 0.3, tH + 0.01, fz - fs * 0.5,
            fx + fs * 0.3, tH + 0.04, fz + fs, fx, tH + 0.04, fz + fs, 0, 1, 0);
        }
      }
    }
  }

  const geo = new THREE.BufferGeometry();
  geo.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
  geo.setAttribute('normal', new THREE.Float32BufferAttribute(normals, 3));
  geo.setAttribute('color', new THREE.Float32BufferAttribute(colors, 3));
  geo.computeBoundingSphere();

  const mat = new THREE.MeshLambertMaterial({ vertexColors: true, flatShading: true });
  const mesh = new THREE.Mesh(geo, mat);
  mesh.receiveShadow = true;
  return mesh;
}

function addQuad(pos, nor, col, color, x1,y1,z1, x2,y2,z2, x3,y3,z3, x4,y4,z4, nx,ny,nz) {
  pos.push(x1,y1,z1, x2,y2,z2, x3,y3,z3, x1,y1,z1, x3,y3,z3, x4,y4,z4);
  for (let i = 0; i < 6; i++) { nor.push(nx, ny, nz); col.push(color.r, color.g, color.b); }
}

// ═══════════════════════════════════════════════════════════════
// CHUNK DECORATIONS (trees, lampposts)
// ═══════════════════════════════════════════════════════════════
// Check if a world-space position is inside any building footprint (with padding)
function isInsideBuildingFootprint(wx, wz, padding) {
  const pad = padding || 1;
  for (const [, b] of buildingsMap) {
    const bounds = getBuildingFootprintBounds(b, pad);
    if (wx >= bounds.minX && wx <= bounds.maxX && wz >= bounds.minZ && wz <= bounds.maxZ) return true;
  }
  return false;
}

function buildChunkDecorations(terrain, cx, cz) {
  const g = new THREE.Group();
  const seed = cx * 1000 + cz;

  for (let tz = 0; tz < CHUNK; tz++) {
    for (let tx = 0; tx < CHUNK; tx++) {
      const type = terrain[tz * CHUNK + tx];
      const wx = cx * CHUNK_W + tx * T;
      const wz = cz * CHUNK_W + tz * T;
      const rng = pseudoRandom(seed + tx * 31 + tz * 97);

      // Trees on grass — skip tiles inside building footprints (reduced density for performance with larger trees)
      if (type === TERRAIN.GRASS && rng < 0.006) {
        if (!isInsideBuildingFootprint(wx, wz, 2)) {
          g.add(makeTree(wx + 0.5, wz + 0.5, rng));
          // Physics: add tree collider
          if (isPhysicsReady()) {
            addDecorationCollider(`tree_${cx}_${cz}_${tx}_${tz}`, 'tree', wx + 0.5, wz + 0.5);
          }
        }
      }

      // Small flowers/rocks on grass (skip building interiors)
      if (type === TERRAIN.GRASS && !isInsideBuildingFootprint(wx, wz, 1)) {
        const rng2 = pseudoRandom(seed + tx * 53 + tz * 139);
        if (rng2 < 0.002) {
          // Flower cluster
          const flowerColors = [0xff5252, 0xffeb3b, 0xff80ab, 0xb388ff, 0x80cbc4];
          const fc = flowerColors[Math.floor(rng2 * flowerColors.length * 333) % flowerColors.length];
          const flower = new THREE.Mesh(_sphereGeo, getMat(fc));
          flower.scale.set(0.08, 0.06, 0.08);
          flower.position.set(wx + 0.5, 0.03, wz + 0.5);
          g.add(flower);
        }
        if (rng2 > 0.995) {
          // Small rock
          const rock = new THREE.Mesh(_boxGeo, getMat(0x9e9e9e));
          rock.scale.set(0.12 + rng * 0.1, 0.06, 0.1 + rng * 0.08);
          rock.position.set(wx + 0.5, 0.03, wz + 0.5);
          rock.rotation.y = rng * Math.PI;
          g.add(rock);
        }
      }

      // Lampposts are now placed by the street light pole system (_rebuildStreetLightPoles)
      // No longer placed per-chunk on random sidewalk tiles
      if (false) {
      }
    }
  }

  // Render placed (user-added) decorations for this chunk — skip any on non-grass terrain (roads, sidewalks, etc.)
  const placedKey = chunkDecorationKey(cx, cz);
  const placed = placedDecorations.get(placedKey) || [];
  for (const pd of placed) {
    // Convert world position to local tile index to check terrain type
    const ptx = Math.floor((pd.wx - cx * CHUNK_W) / T);
    const ptz = Math.floor((pd.wz - cz * CHUNK_W) / T);
    if (ptx >= 0 && ptx < CHUNK && ptz >= 0 && ptz < CHUNK) {
      const pType = terrain[ptz * CHUNK + ptx];
      if (pType !== TERRAIN.GRASS && pType !== TERRAIN.DIRT) continue; // skip decorations on roads/sidewalks/water/etc
    }
    const placedDecorationMesh = makeDecoration(pd.type, pd.wx + 0.5, pd.wz + 0.5);
    placedDecorationMesh.userData.placedDecoration = { type: pd.type, wx: pd.wx, wz: pd.wz, chunkKey: placedKey };
    placedDecorationMesh.traverse(obj => {
      obj.userData = obj.userData || {};
      obj.userData.placedDecoration = { type: pd.type, wx: pd.wx, wz: pd.wz, chunkKey: placedKey };
    });
    g.add(placedDecorationMesh);
      // Physics: add placed decoration collider
      if (isPhysicsReady()) {
        addDecorationCollider(`pdecor_${cx}_${cz}_${pd.wx}_${pd.wz}`, pd.type, pd.wx + 0.5, pd.wz + 0.5);
      }
  }

  return mergeStaticGroupMeshes(g);
}

function pseudoRandom(s) {
  const x = Math.sin(s * 127.1 + 311.7) * 43758.5453;
  return x - Math.floor(x);
}

function makeTree(x, z, rng) {
  const g = new THREE.Group();
  const h = 0.8 + rng * 0.6; // base height (scaled up at end)
  // 5 tree variants for visual variety
  const treeType = Math.floor(rng * 500) % 5;

  // Leaf color variety
  const leafColors = [0x4caf50, 0x43a047, 0x66bb6a, 0x2e7d32, 0x81c784];
  const darkLeaf = [0x388e3c, 0x1b5e20, 0x558b2f, 0x33691e, 0x4caf50];
  const trunkColors = [0x8d6e63, 0x795548, 0x6d4c41, 0xa1887f, 0x5d4037];
  const lc = leafColors[treeType];
  const dlc = darkLeaf[treeType];
  const tc = trunkColors[treeType];

  if (treeType === 0) {
    // Pine tree — tall cone with 2-3 tiers
    const trunk = cyl(0.05, h * 0.7, tc);
    trunk.position.set(0, h * 0.35, 0);
    g.add(trunk);
    const c1 = cone(0.4, h * 0.5, lc);
    c1.position.set(0, h * 0.6 + 0.25, 0);
    g.add(c1);
    const c2 = cone(0.3, h * 0.4, dlc);
    c2.position.set(0, h * 0.85 + 0.25, 0);
    g.add(c2);
    if (h > 1.0) {
      const c3 = cone(0.2, h * 0.3, lc);
      c3.position.set(0, h * 1.05 + 0.25, 0);
      g.add(c3);
    }
  } else if (treeType === 1) {
    // Round deciduous tree — sphere canopy
    const trunk = cyl(0.08, h * 0.5, tc);
    trunk.position.set(0, h * 0.25, 0);
    g.add(trunk);
    const canopy = sphere(0.45 + rng * 0.15, lc);
    canopy.position.set(0, h * 0.55 + 0.3, 0);
    g.add(canopy);
  } else if (treeType === 2) {
    // Bushy tree — 3 overlapping spheres
    const trunk = cyl(0.06, h * 0.45, tc);
    trunk.position.set(0, h * 0.22, 0);
    g.add(trunk);
    const s1 = sphere(0.3, lc);
    s1.position.set(-0.12, h * 0.5 + 0.2, 0.08);
    g.add(s1);
    const s2 = sphere(0.35, dlc);
    s2.position.set(0.1, h * 0.55 + 0.25, -0.05);
    g.add(s2);
    const s3 = sphere(0.25, lc);
    s3.position.set(0, h * 0.65 + 0.3, 0.1);
    g.add(s3);
  } else if (treeType === 3) {
    // Cypress — tall and narrow
    const trunk = cyl(0.04, h * 0.8, tc);
    trunk.position.set(0, h * 0.4, 0);
    g.add(trunk);
    const canopy = cyl(0.15, h * 0.9, lc);
    canopy.position.set(0, h * 0.5 + 0.2, 0);
    g.add(canopy);
    // Pointy top
    const top = cone(0.12, h * 0.25, dlc);
    top.position.set(0, h * 0.95 + 0.25, 0);
    g.add(top);
  } else {
    // Palm tree — curved trunk + flat leaf clusters
    const trunk = cyl(0.045, h * 0.7, 0xa1887f);
    trunk.position.set(0, h * 0.35, 0);
    trunk.rotation.z = 0.05;
    g.add(trunk);
    // Coconut cluster
    const coconut = sphere(0.06, 0x8d6e63);
    coconut.position.set(0, h * 0.7 + 0.1, 0);
    g.add(coconut);
    // Palm fronds (4 flat ellipses radiating out)
    for (let i = 0; i < 4; i++) {
      const frond = new THREE.Mesh(_boxGeo, getMat(0x66bb6a));
      frond.scale.set(0.5, 0.03, 0.15);
      const angle = (i / 4) * Math.PI * 2;
      frond.position.set(Math.cos(angle) * 0.3, h * 0.72 + 0.1, Math.sin(angle) * 0.3);
      frond.rotation.y = angle;
      frond.rotation.z = -0.4;
      g.add(frond);
    }
  }

  // Scale up to be proportional to buildings (WALL_H=3.0, trees should be 2.5-5.0 tall)
  const baseScale = 2.5 + rng * 1.5; // 2.5x-4.0x base scale
  g.scale.setScalar(baseScale);
  g.position.set(x, 0, z);
  return g;
}

function makeLamppost(x, z) {
  const g = new THREE.Group();

  // Pole
  const pole = cyl(0.03, 2.5, 0x888888);
  pole.position.set(0, 1.25, 0);
  g.add(pole);

  // Lamp head
  const head = sphere(0.1, 0xffd600);
  head.position.set(0, 2.6, 0);
  g.add(head);

  // Emissive glow instead of PointLight (performance: no per-object lighting cost)
  head.material = new THREE.MeshLambertMaterial({ color: 0xffd600, emissive: 0xfff5e0, emissiveIntensity: 0.6, flatShading: true });

  g.position.set(x, 0, z);
  return g;
}

// ─── PLACEABLE DECORATION BUILDERS ───
function makeBench(x, z) {
  const g = new THREE.Group();
  // Seat
  g.add(posVox(0, 0.35, 0, 1.2, 0.08, 0.4, 0x8d6e63));
  // Back
  g.add(posVox(0, 0.65, -0.18, 1.2, 0.35, 0.07, 0x6d4c41));
  // Legs
  g.add(posVox(-0.5, 0.17, 0, 0.07, 0.3, 0.07, 0x5d4037));
  g.add(posVox(0.5, 0.17, 0, 0.07, 0.3, 0.07, 0x5d4037));
  g.position.set(x, 0, z);
  return g;
}

function makeFence(x, z) {
  const g = new THREE.Group();
  // Horizontal rails
  g.add(posVox(0, 0.7, 0, 1.0, 0.06, 0.06, 0xb0bec5));
  g.add(posVox(0, 0.35, 0, 1.0, 0.06, 0.06, 0xb0bec5));
  // Vertical posts
  for (let i = -2; i <= 2; i++) {
    g.add(posVox(i * 0.22, 0.55, 0, 0.05, 0.8, 0.05, 0xcfd8dc));
  }
  g.position.set(x, 0, z);
  return g;
}

function makeFountain(x, z) {
  const g = new THREE.Group();
  // Basin
  const basin = cyl(1.0, 0.35, 0xb0bec5);
  basin.position.set(0, 0.175, 0);
  g.add(basin);
  // Water inside basin
  const water = cyl(0.85, 0.2, 0x42a5f5);
  water.position.set(0, 0.28, 0);
  water.material = getMat(0x42a5f5, { transparent: true, opacity: 0.65 });
  g.add(water);
  // Center pillar
  const pillar = cyl(0.1, 0.8, 0x90a4ae);
  pillar.position.set(0, 0.55, 0);
  g.add(pillar);
  // Top sphere
  const top = sphere(0.15, 0x80cbc4);
  top.position.set(0, 0.98, 0);
  g.add(top);
  g.position.set(x, 0, z);
  return g;
}

function makeDecoration(type, x, z, rng) {
  rng = rng ?? pseudoRandom(x * 31.7 + z * 97.3 + 42);
  switch (type) {
    case 'tree':     return makeTree(x, z, rng);
    case 'bench':    return makeBench(x, z);
    case 'lamppost': return makeLamppost(x, z);
    case 'fence':    return makeFence(x, z);
    case 'fountain': return makeFountain(x, z);
    default:         return makeTree(x, z, rng);
  }
}

// Decoration ghost (translucent preview)
function makeDecorationGhost(type) {
  const g = makeDecoration(type, 0, 0);
  g.traverse(obj => {
    if (obj.isMesh) {
      obj.material = obj.material.clone();
      obj.material.transparent = true;
      obj.material.opacity = 0.4;
    }
  });
  return g;
}

// Store placed decorations per chunk (type + world coords)
function chunkDecorationKey(cx, cz) { return `decor_${cx},${cz}`; }
const placedDecorations = new Map(); // key → [{type,wx,wz}, ...]
let _placedDecorationsSaveTimer = null;

function normalizePlacedDecoration(decoration) {
  const type = decoration?.type;
  const wx = Number(decoration?.wx ?? decoration?.x);
  const wz = Number(decoration?.wz ?? decoration?.z);
  if (!type || !Number.isFinite(wx) || !Number.isFinite(wz)) return null;
  return { type, wx: Math.floor(wx), wz: Math.floor(wz) };
}

function serializePlacedDecorations() {
  const decorations = [];
  for (const [, list] of placedDecorations) {
    for (const decoration of list || []) {
      const normalized = normalizePlacedDecoration(decoration);
      if (normalized) decorations.push(normalized);
    }
  }
  decorations.sort((a, b) => (a.wz - b.wz) || (a.wx - b.wx) || String(a.type).localeCompare(String(b.type)));
  return decorations;
}

function setPlacedDecorationsFromList(list, { rebuild = true } = {}) {
  placedDecorations.clear();
  for (const item of list || []) {
    const decoration = normalizePlacedDecoration(item);
    if (!decoration) continue;
    const cx = Math.floor(decoration.wx / CHUNK_W);
    const cz = Math.floor(decoration.wz / CHUNK_W);
    const key = chunkDecorationKey(cx, cz);
    if (!placedDecorations.has(key)) placedDecorations.set(key, []);
    placedDecorations.get(key).push(decoration);
  }
  if (rebuild) {
    for (const [, chunk] of loadedChunks) rebuildChunkDecorations(chunk);
  }
}

async function loadPlacedDecorations() {
  try {
    const r = await fetch('/api/decorations');
    const list = await r.json();
    if (Array.isArray(list)) setPlacedDecorationsFromList(list, { rebuild: false });
  } catch (e) {
    console.warn('Failed to load decorations:', e);
  }
}

async function persistPlacedDecorationsNow() {
  if (isLicenseFeatureLocked('advancedEditor')) {
    showLicenseLockedToast('World decoration editing');
    return;
  }
  try {
    await fetch('/api/decorations', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(serializePlacedDecorations()),
    });
  } catch (e) {
    console.warn('Failed to save decorations:', e);
  }
}

function debounceSavePlacedDecorations() {
  if (_placedDecorationsSaveTimer) clearTimeout(_placedDecorationsSaveTimer);
  _placedDecorationsSaveTimer = setTimeout(() => {
    _placedDecorationsSaveTimer = null;
    persistPlacedDecorationsNow();
  }, 450);
}

function addPlacedDecoration(type, wx, wz, { persist = true } = {}) {
  const cx = Math.floor(wx / CHUNK_W);
  const cz = Math.floor(wz / CHUNK_W);
  const key = chunkDecorationKey(cx, cz);
  if (!placedDecorations.has(key)) placedDecorations.set(key, []);
  placedDecorations.get(key).push({ type, wx, wz });

  // Rebuild decoration layer for this chunk
  const chunkData = loadedChunks.get(chunkKey(cx, cz));
  if (chunkData) rebuildChunkDecorations(chunkData);
  if (persist) debounceSavePlacedDecorations();
}

function updateDecorationSelectionPanel() {
  const selectedText = document.getElementById('selectedDecorationText');
  const deleteBtn = document.getElementById('btn-deleteDecoration');
  if (selectedText) {
    if (_selectedPlacedDecoration) {
      const def = DECORATION_DEFS[_selectedPlacedDecoration.type];
      selectedText.textContent = `${def?.label || _selectedPlacedDecoration.type} at ${_selectedPlacedDecoration.wx}, ${_selectedPlacedDecoration.wz}`;
    } else {
      selectedText.textContent = 'No decoration selected';
    }
  }
  if (deleteBtn) deleteBtn.disabled = !_selectedPlacedDecoration;
}

function clearSelectedPlacedDecoration() {
  _selectedPlacedDecoration = null;
  if (_selectedDecorationHelper) {
    _selectedDecorationHelper.parent?.remove(_selectedDecorationHelper);
    _selectedDecorationHelper.geometry?.dispose?.();
    _selectedDecorationHelper.material?.dispose?.();
    _selectedDecorationHelper = null;
  }
  updateDecorationSelectionPanel();
}

function selectPlacedDecoration(meta) {
  const decoration = normalizePlacedDecoration(meta);
  if (!decoration) return false;
  _selectedPlacedDecoration = {
    ...decoration,
    chunkKey: meta.chunkKey || chunkDecorationKey(Math.floor(decoration.wx / CHUNK_W), Math.floor(decoration.wz / CHUNK_W)),
  };
  if (!_selectedDecorationHelper) {
    const geo = new THREE.RingGeometry(0.48, 0.62, 32);
    const mat = new THREE.MeshBasicMaterial({
      color: 0xffd600,
      transparent: true,
      opacity: 0.9,
      depthTest: false,
      side: THREE.DoubleSide,
    });
    _selectedDecorationHelper = new THREE.Mesh(geo, mat);
    _selectedDecorationHelper.name = '_selectedDecorationHelper';
    _selectedDecorationHelper.rotation.x = -Math.PI / 2;
    _selectedDecorationHelper.renderOrder = 1000;
    scene.add(_selectedDecorationHelper);
  }
  const radiusScale = decoration.type === 'fountain' ? 1.8 : (decoration.type === 'tree' ? 1.35 : 1);
  _selectedDecorationHelper.scale.setScalar(radiusScale);
  _selectedDecorationHelper.position.set(decoration.wx + 0.5, 0.06, decoration.wz + 0.5);
  updateDecorationSelectionPanel();
  showToast(`${DECORATION_DEFS[decoration.type]?.icon || '🪴'} Decoration selected`, 'info');
  return true;
}

function getPlacedDecorationHit(e) {
  if (!decorGroup) return null;
  const ray = getPointerRaycast(e);
  const selectable = [];
  decorGroup.traverse(obj => {
    if (obj.isMesh && obj.userData?.placedDecoration) selectable.push(obj);
  });
  if (!selectable.length) return null;
  const hits = ray.intersectObjects(selectable, false);
  if (!hits.length) return null;
  const meta = hits[0].object.userData?.placedDecoration;
  return meta ? { meta, hit: hits[0] } : null;
}

function deleteSelectedPlacedDecoration() {
  const selected = _selectedPlacedDecoration;
  if (!selected) {
    showToast('Select a decoration first', 'warning');
    return false;
  }
  const cx = Math.floor(selected.wx / CHUNK_W);
  const cz = Math.floor(selected.wz / CHUNK_W);
  const key = chunkDecorationKey(cx, cz);
  const list = placedDecorations.get(key) || [];
  const index = list.findIndex(pd => pd.type === selected.type && pd.wx === selected.wx && pd.wz === selected.wz);
  if (index < 0) {
    clearSelectedPlacedDecoration();
    showToast('Decoration was already gone', 'warning');
    return false;
  }
  list.splice(index, 1);
  if (list.length) placedDecorations.set(key, list);
  else placedDecorations.delete(key);
  removeBody(`pdecor_${cx}_${cz}_${selected.wx}_${selected.wz}`);
  const chunkData = loadedChunks.get(chunkKey(cx, cz));
  if (chunkData) rebuildChunkDecorations(chunkData);
  clearSelectedPlacedDecoration();
  debounceSavePlacedDecorations();
  showToast('🗑️ Decoration deleted', 'success');
  return true;
}

function rebuildChunkDecorations(data) {
  if (data.decors) decorGroup.remove(data.decors);
  data.decors = buildChunkDecorations(data.terrain, data.cx, data.cz);
  decorGroup.add(data.decors);
}

// ═══════════════════════════════════════════════════════════════
// WATER ANIMATION
// ═══════════════════════════════════════════════════════════════
function updateWaterAnimation() {
  // Bob each water-containing chunk mesh with a gentle sin wave.
  // For chunks that also have non-water tiles we apply a smaller offset
  // so roads/grass beside water still look reasonable.
  for (const [key, c] of loadedChunks) {
    const hasWater = c.terrain.includes(TERRAIN.WATER);
    const allWater = hasWater && c.terrain.every(t => t === TERRAIN.WATER);
    if (hasWater) {
      // Offset based on chunk position for variety
      const phase = (c.cx * 2.3 + c.cz * 1.7);
      const bobY = Math.sin(waterTick * 1.5 + phase) * 0.04;
      c.mesh.position.y = bobY;
    }
  }
}


// ── Multi-floor building helpers ─────────────────────────────
const FLOOR_HEIGHT = WALL_H - 0.02; // flush/very slightly overlapping stacked floors
const ELEVATOR_SIZE = T * 2.8; // intentionally wide enough for several agents
let _buildingFloorView = new Map(); // buildingId -> currently edited/viewed floor
let _hoveredExteriorFloor = null; // { buildingId, floor }
let _exteriorFloorHoverMeshes = [];

function tagExteriorWallMesh(mesh, building, floor) {
  if (!mesh || !building) return mesh;
  mesh.userData = {
    ...(mesh.userData || {}),
    buildingId: building.id,
    exteriorFloorPick: true,
    exteriorWall: true,
    floor: Math.max(1, Number(floor) || 1),
  };
  return mesh;
}

function tagExteriorFloorPickMesh(mesh, building, floor) {
  if (!mesh || !building) return mesh;
  mesh.userData = {
    ...(mesh.userData || {}),
    buildingId: building.id,
    exteriorFloorPick: true,
    floor: Math.max(1, Number(floor) || 1),
  };
  return mesh;
}

function normalizeBuildingFloors(building) {
  if (!building || building.type === 'park') return building;
  const count = Math.max(1, Number(building.floorCount || building.floors?.length || 1) || 1);
  building.floorCount = count;
  if (!Array.isArray(building.floors)) building.floors = [];
  for (let i = 1; i <= count; i++) {
    if (!building.floors[i - 1]) building.floors[i - 1] = { level: i, name: `Floor ${i}` };
    building.floors[i - 1].level = i;
    building.floors[i - 1].name = building.floors[i - 1].name || `Floor ${i}`;
  }
  building.floors.length = count;
  const bw = (building.widthTiles || 25) * T;
  const bd = (building.heightTiles || 17) * T;
  if (count > 1 && !building.elevator) {
    building.elevator = { x: Math.max(ELEVATOR_SIZE / 2 + 0.4, Math.min(bw - ELEVATOR_SIZE / 2 - 0.4, bw * 0.18)), z: Math.max(ELEVATOR_SIZE / 2 + 0.4, Math.min(bd - ELEVATOR_SIZE / 2 - 0.4, bd * 0.35)), width: ELEVATOR_SIZE, depth: ELEVATOR_SIZE };
  }
  if (building.elevator) {
    building.elevator.width = Number(building.elevator.width) || ELEVATOR_SIZE;
    building.elevator.depth = Number(building.elevator.depth) || ELEVATOR_SIZE;
    building.elevator.x = Math.max(building.elevator.width / 2 + 0.25, Math.min(bw - building.elevator.width / 2 - 0.25, Number(building.elevator.x) || bw * 0.18));
    building.elevator.z = Math.max(building.elevator.depth / 2 + 0.25, Math.min(bd - building.elevator.depth / 2 - 0.25, Number(building.elevator.z) || bd * 0.35));
  }
  return building;
}

function getBuildingFloorCount(building) {
  normalizeBuildingFloors(building);
  return Math.max(1, Number(building?.floorCount || 1) || 1);
}

function getFurnitureFloor(item) {
  return Math.max(1, Number(item?.floor || item?.buildingFloor || 1) || 1);
}

function getInteriorWallFloor(wall) {
  return Math.max(1, Number(wall?.floor || wall?.buildingFloor || 1) || 1);
}

function getActiveBuildingFloor(building) {
  if (!building) return 1;
  const requested = _buildingFloorView.get(building.id) || 1;
  return Math.max(1, Math.min(getBuildingFloorCount(building), requested));
}

function isBuildingFloorFocusActive(building) {
  return !!building && getBuildingFloorCount(building) > 1 && (selectedBuildingId === building.id || insideBuildingId === building.id);
}

function shouldRenderBuildingFloor(building, floor) {
  if (!isBuildingFloorFocusActive(building)) return true;
  // In focused multi-floor view, keep the active floor plus every lower
  // exterior shell/floor slab visible. This prevents upper floors from
  // looking like they are floating while still hiding floors above.
  return Math.max(1, Number(floor) || 1) <= getActiveBuildingFloor(building);
}

const INTERIOR_FLOOR_SURFACE_Y = 0.2;

function getRenderedFloorY(building, floor) {
  return (Math.max(1, Number(floor) || 1) - 1) * FLOOR_HEIGHT;
}

function getInteriorFloorSurfaceY(building, floor) {
  return getRenderedFloorY(building, floor) + INTERIOR_FLOOR_SURFACE_Y;
}

function focusCameraOnBuildingFloor(building, floor = null) {
  if (!building) return;
  const bounds = getBuildingFootprintBounds(building, 0);
  const bw = bounds.width;
  const bd = bounds.depth;
  const diag = Math.sqrt(bw * bw + bd * bd);
  const targetDist = Math.max(8, Math.min(diag * 0.65, 30));
  // Keep the normal camera pitch/angle when changing floors. The previous
  // version aimed the camera at the selected floor's Y height, which created
  // an unwanted vertical lean/rotation. Floor selection should re-center on
  // the building without changing the camera's vertical look angle.
  flyCameraTo(new THREE.Vector3(bounds.centerX, 0, bounds.centerZ), targetDist);
}

function setActiveBuildingFloor(building, floor) {
  if (!building) return;
  _buildingFloorView.set(building.id, Math.max(1, Math.min(getBuildingFloorCount(building), Number(floor) || 1)));
}

const ELEVATOR_INTERIOR_SLOT_OFFSETS = Object.freeze([
  Object.freeze({ x: -0.42, z: 0 }),
  Object.freeze({ x: 0.42, z: 0 }),
]);
const ELEVATOR_QUEUE_SPACING_TILES = 0.72;

function getElevatorApiPoint(building, slotIndex = null) {
  normalizeBuildingFloors(building);
  if (!building?.elevator) return null;
  const slot = Number.isInteger(slotIndex) ? ELEVATOR_INTERIOR_SLOT_OFFSETS[Math.max(0, Math.min(ELEVATOR_INTERIOR_SLOT_OFFSETS.length - 1, slotIndex))] : null;
  const world = getBuildingWorldPoint(building, building.elevator.x + (slot?.x || 0), building.elevator.z + (slot?.z || 0));
  return { x: world.x * API_TILE, y: world.z * API_TILE, elevatorSlotIndex: slotIndex };
}

function getElevatorQueueApiPoint(building, queueIndex = 0) {
  normalizeBuildingFloors(building);
  if (!building?.elevator) return null;
  const e = building.elevator;
  const bw = (building.widthTiles || 25) * T;
  const bd = (building.heightTiles || 17) * T;
  const localX = Math.max(0.55, Math.min(bw - 0.55, e.x));
  const baseZ = e.z + (Number(e.depth || ELEVATOR_SIZE) / 2) + 0.95 + Math.max(0, Number(queueIndex) || 0) * ELEVATOR_QUEUE_SPACING_TILES;
  const localZ = Math.max(0.55, Math.min(bd - 0.55, baseZ));
  const world = getBuildingWorldPoint(building, localX, localZ);
  return { x: world.x * API_TILE, y: world.z * API_TILE, elevatorQueueIndex: Math.max(0, Number(queueIndex) || 0) };
}

function isAgentAtElevatorBoardingPoint(agent, building, boardingTarget = null) {
  if (!agent || !building?.elevator) return false;
  const targets = [];
  if (boardingTarget) targets.push(boardingTarget);
  const center = getElevatorApiPoint(building);
  if (center) targets.push(center);
  for (let i = 0; i < ELEVATOR_INTERIOR_SLOT_OFFSETS.length; i++) {
    const slot = getElevatorApiPoint(building, i);
    if (slot) targets.push(slot);
  }
  const reach = API_TILE * 0.95;
  return targets.some(target => Math.hypot((agent.x || 0) - target.x, (agent.y || 0) - target.y) <= reach);
}

function getElevatorAccessPlan(agent, building, fromFloor, toFloor, finalTarget = null) {
  const buildingId = building?.id || null;
  if (!agent || !buildingId || !building?.elevator) return { mode: 'none', target: getElevatorApiPoint(building), slotIndex: null, queueIndex: null };
  const agentId = getAgentDebugId(agent);
  const currentTrip = agent._elevatorTrip?.buildingId === buildingId ? agent._elevatorTrip : null;
  const matchesTrip = (trip) => trip && trip.buildingId === buildingId && Math.max(1, Number(trip.fromFloor || 1) || 1) === fromFloor && Math.max(1, Number(trip.toFloor || 1) || 1) === toFloor;
  const occupiedSlots = new Set();
  const queue = [];
  for (const other of agentsList || []) {
    if (!other || other === agent) continue;
    const trip = other._elevatorTrip || null;
    if (!matchesTrip(trip)) continue;
    const otherId = getAgentDebugId(other);
    if (Number.isInteger(trip.slotIndex)) occupiedSlots.add(trip.slotIndex);
    else queue.push({ agent: other, agentId: otherId, queuedAtMs: Number(trip.queuedAtMs || trip.startedAtMs || 0) || 0 });
  }
  if (currentTrip && Number.isInteger(currentTrip.slotIndex) && !occupiedSlots.has(currentTrip.slotIndex)) {
    return { mode: 'board', target: getElevatorApiPoint(building, currentTrip.slotIndex), slotIndex: currentTrip.slotIndex, queueIndex: null };
  }
  const openSlots = ELEVATOR_INTERIOR_SLOT_OFFSETS.map((_, index) => index).filter(index => !occupiedSlots.has(index));
  const queuedAtMs = Number(currentTrip?.queuedAtMs || Date.now()) || Date.now();
  if (currentTrip && !Number.isInteger(currentTrip.slotIndex)) queue.push({ agent, agentId, queuedAtMs });
  queue.sort((a, b) => a.queuedAtMs - b.queuedAtMs || String(a.agentId).localeCompare(String(b.agentId)));
  const queueRank = queue.findIndex(entry => entry.agent === agent || entry.agentId === agentId);
  if (openSlots.length && (!currentTrip || queueRank < 0 || queueRank < openSlots.length)) {
    const slotIndex = openSlots[Math.max(0, queueRank < 0 ? 0 : queueRank)];
    return { mode: 'board', target: getElevatorApiPoint(building, slotIndex), slotIndex, queueIndex: null };
  }
  if (queueRank < 0) queue.push({ agent, agentId, queuedAtMs });
  queue.sort((a, b) => a.queuedAtMs - b.queuedAtMs || String(a.agentId).localeCompare(String(b.agentId)));
  const queueIndex = Math.max(0, queue.findIndex(entry => entry.agent === agent || entry.agentId === agentId) - openSlots.length);
  return { mode: 'queue', target: getElevatorQueueApiPoint(building, queueIndex), slotIndex: null, queueIndex, queuedAtMs };
}

function getElevatorExitApiPoint(building) {
  normalizeBuildingFloors(building);
  if (!building?.elevator) return null;
  const e = building.elevator;
  const bw = (building.widthTiles || 25) * T;
  const bd = (building.heightTiles || 17) * T;
  const localX = Math.max(0.55, Math.min(bw - 0.55, e.x));
  // Door is on the front/south side of the shaft; keep the exit point inside the footprint.
  const localZ = Math.max(0.55, Math.min(bd - 0.55, e.z + (Number(e.depth || ELEVATOR_SIZE) / 2) + 0.75));
  const world = getBuildingWorldPoint(building, localX, localZ);
  return { x: world.x * API_TILE, y: world.z * API_TILE };
}

function getFloorScopedBuilding(building, floor = 1) {
  if (!building || !building.interior?.furniture) return building;
  const routingFloor = Math.max(1, Number(floor || 1) || 1);
  return {
    ...building,
    _routingFloor: routingFloor,
    _routingFloorY: getRenderedFloorY(building, routingFloor),
    elevator: building.elevator ? { ...building.elevator } : null,
    interior: {
      ...(building.interior || {}),
      walls: (building.interior?.walls || []).filter(w => getInteriorWallFloor(w) === routingFloor),
      furniture: (building.interior.furniture || []).filter(f => getFurnitureFloor(f) === routingFloor),
    },
  };
}

function getAgentFloor(agent, building = null) {
  if (!agent) return 1;
  const activeBuilding = building || getMovementInteriorBuildingAt(agent.x, agent.y) || null;
  if (!activeBuilding || activeBuilding.type === 'park') return 1;
  // Floor state only applies after the agent is physically inside the footprint.
  // Outside agents must stay on ground floor and enter through the main door first.
  if (!isPointInsideBuildingInterior(activeBuilding, agent.x, agent.y, -0.15)) return 1;
  return Math.max(1, Number(agent._floor || 1) || 1);
}

const AGENT_INTENT_PRIORITY = Object.freeze({
  manual: 1000,
  'explicit-object': 900,
  'live-status': 800,
  recovery: 700,
  schedule: 500,
  idle: 300,
  'route-handoff': 100,
});

const AGENT_INTENT_DEFAULT_RELEASE_POLICY = Object.freeze({
  manual: 'manual-only',
  'explicit-object': 'on-object-complete',
  'live-status': 'on-route-clear',
  recovery: 'on-route-clear',
  schedule: 'on-arrival',
  idle: 'on-timeout',
  'route-handoff': 'on-route-clear',
});

const AGENT_INTENT_RELEASE_ALLOWED_BY = Object.freeze({
  manual: Object.freeze(['owner', 'cancel', 'agent-offline']),
  'explicit-object': Object.freeze(['owner', 'higher-priority', 'object-complete', 'cancel', 'timeout', 'route-failed', 'agent-offline']),
  'live-status': Object.freeze(['owner', 'higher-priority', 'same-owner-refresh', 'cancel', 'timeout', 'route-failed', 'agent-offline']),
  recovery: Object.freeze(['owner', 'higher-priority', 'same-owner-refresh', 'timeout', 'route-failed', 'agent-offline']),
  schedule: Object.freeze(['owner', 'higher-priority', 'same-owner-refresh', 'timeout', 'route-failed', 'agent-offline']),
  idle: Object.freeze(['owner', 'higher-priority', 'same-owner-refresh', 'timeout', 'route-failed', 'agent-offline']),
  'route-handoff': Object.freeze(['owner', 'higher-priority', 'same-owner-refresh', 'route-failed', 'agent-offline']),
});

const AGENT_INTENT_APPROACH_STALE_AFTER_MS = 45000;

const AGENT_INTENT_OWNER_TO_PRIORITY_NAME = Object.freeze({
  user: 'manual',
  manual: 'manual',
  verifier: 'manual',
  'world-action': 'explicit-object',
  'object-action': 'explicit-object',
  'live-status': 'live-status',
  work: 'live-status',
  meeting: 'live-status',
  recovery: 'recovery',
  schedule: 'schedule',
  idle: 'idle',
  'route-handoff': 'route-handoff',
});

let agentIntentSequence = 0;

function getAgentDebugId(agent) {
  return String(agent?.id || agent?.statusKey || agent?.name || 'agent');
}

function roundIntentNumber(value) {
  const n = Number(value);
  if (!Number.isFinite(n)) return null;
  return Math.round(n * 1000) / 1000;
}

function summarizeIntentTarget(target) {
  if (!target) return 'none';
  const parts = [];
  if (Number.isFinite(Number(target.x)) && Number.isFinite(Number(target.y))) parts.push(`x=${roundIntentNumber(target.x)},y=${roundIntentNumber(target.y)}`);
  if (target.floor != null) parts.push(`floor=${target.floor}`);
  if (target.buildingFloor != null && target.buildingFloor !== target.floor) parts.push(`buildingFloor=${target.buildingFloor}`);
  if (target.buildingId) parts.push(`building=${target.buildingId}`);
  if (target.spotId) parts.push(`spot=${target.spotId}`);
  if (target.routeMode) parts.push(`mode=${target.routeMode}`);
  return parts.length ? parts.join(' ') : 'target';
}

function summarizeIntentObject(object = null) {
  if (!object || object.type === 'none') return 'none';
  const parts = [object.type || 'object'];
  if (object.objectType) parts.push(object.objectType);
  if (object.id) parts.push(`id=${object.id}`);
  if (object.furnitureIndex != null) parts.push(`furnitureIndex=${object.furnitureIndex}`);
  if (object.actionId) parts.push(`action=${object.actionId}`);
  if (object.worldActionId) parts.push(`worldAction=${object.worldActionId}`);
  if (object.spotId) parts.push(`spot=${object.spotId}`);
  if (object.slotId) parts.push(`slot=${object.slotId}`);
  return parts.join(' ');
}

function inferAgentIntentTarget(target = null, building = null, floor = null) {
  const routeTarget = target || {};
  const buildingId = routeTarget.buildingId || routeTarget.targetBuildingId || building?.id || null;
  const spotId = routeTarget.spotId || routeTarget.interactionSpotId || routeTarget.activationSpotId || routeTarget.routeSpotId || null;
  return {
    x: Number.isFinite(Number(routeTarget.x)) ? Number(routeTarget.x) : null,
    y: Number.isFinite(Number(routeTarget.y)) ? Number(routeTarget.y) : null,
    floor: routeTarget.floor != null ? Math.max(1, Number(routeTarget.floor) || 1) : (floor != null ? Math.max(1, Number(floor) || 1) : null),
    buildingFloor: routeTarget.buildingFloor != null ? Math.max(1, Number(routeTarget.buildingFloor) || 1) : (floor != null ? Math.max(1, Number(floor) || 1) : null),
    buildingId,
    roomId: routeTarget.roomId || null,
    spotId,
    routeMode: routeTarget.routeMode || routeTarget.targetKind || routeTarget.routeHandoff?.mode || null,
  };
}

function inferAgentIntentObject(target = null, building = null) {
  const routeTarget = target || {};
  const objectId = routeTarget.objectInstanceId || routeTarget.objectId || routeTarget.nodeId || routeTarget.buildingTargetId || null;
  const objectType = routeTarget.catalogKey || routeTarget.catalogId || routeTarget.objectCatalogId || routeTarget.objectType || routeTarget.furnitureType || routeTarget.nodeType || null;
  const actionId = routeTarget.actionId || routeTarget.apiActionId || routeTarget.uiActionId || null;
  const worldActionId = routeTarget.worldActionId || routeTarget.routeHandoff?.worldActionId || null;
  const furnitureIndex = routeTarget.furnitureIndex ?? null;
  const spotId = routeTarget.spotId || routeTarget.interactionSpotId || routeTarget.activationSpotId || routeTarget.routeSpotId || null;
  const type = objectId || objectType || actionId || worldActionId || furnitureIndex != null
    ? (routeTarget.scope === 'outdoor' || routeTarget.targetKind === 'outdoor-node' ? 'outdoor-node' : 'furniture')
    : (building?.id && routeTarget.targetKind === 'building-interior-entry' ? 'building' : 'none');
  return {
    type,
    id: objectId,
    buildingId: routeTarget.buildingId || building?.id || null,
    furnitureIndex,
    objectType,
    actionId,
    worldActionId,
    spotId,
    slotId: routeTarget.slotId || routeTarget.seatId || null,
    reservationId: routeTarget.reservationId || null,
    activeUseId: routeTarget.activeUseId || null,
    preserveUntilRelease: Boolean(worldActionId || actionId || routeTarget.preserveUntilRelease),
  };
}

function normalizeAgentIntentBehaviorMetadata(options = {}, target = null, object = null) {
  const routeHandoff = options.routeHandoff || target?.routeHandoff || target?.route || null;
  const source = options.behavior || routeHandoff?.behavior || routeHandoff?.source?.behavior || target?.behavior || null;
  const behaviorSourceKind = options.behaviorSourceKind || source?.behaviorSourceKind || routeHandoff?.behaviorSourceKind || routeHandoff?.source?.behaviorSourceKind || target?.behaviorSourceKind || null;
  const behaviorMode = options.behaviorMode || source?.behaviorMode || routeHandoff?.behaviorMode || routeHandoff?.source?.behaviorMode || target?.behaviorMode || null;
  const behaviorSelectedCategory = options.behaviorCategory ?? source?.behaviorSelectedCategory ?? routeHandoff?.behaviorCategory ?? routeHandoff?.source?.behaviorCategory ?? target?.behaviorCategory ?? null;
  const behaviorSelectedObject = options.behaviorSelectedObject || source?.behaviorSelectedObject || routeHandoff?.source?.behavior?.behaviorSelectedObject || (object ? {
    kind: object.type || 'none',
    id: object.id || null,
    buildingId: object.buildingId || target?.buildingId || null,
    furnitureIndex: object.furnitureIndex ?? target?.furnitureIndex ?? null,
    catalogId: object.objectType || target?.catalogId || target?.catalogKey || null,
    objectType: object.objectType || target?.objectType || target?.catalogKey || null,
    nodeId: target?.nodeId || null,
  } : null);
  const behaviorSelectedSpot = options.behaviorSelectedSpot || source?.behaviorSelectedSpot || routeHandoff?.source?.behavior?.behaviorSelectedSpot || {
    spotId: object?.spotId || target?.spotId || target?.interactionSpotId || null,
    slotId: object?.slotId || target?.slotId || null,
    seatId: target?.seatId || null,
    interactionSpotId: target?.interactionSpotId || object?.spotId || null,
    x: Number.isFinite(Number(target?.x)) ? Number(target.x) : null,
    y: Number.isFinite(Number(target?.y)) ? Number(target.y) : null,
    floor: target?.floor ?? target?.buildingFloor ?? null,
  };
  return {
    behaviorSourceKind,
    behaviorMode,
    behaviorAuthority: options.behaviorAuthority ?? source?.behaviorAuthority ?? routeHandoff?.source?.behaviorAuthority ?? null,
    behaviorSelectedCategory,
    behaviorSelectedObject,
    behaviorSelectedSpot,
    behaviorProbabilityRoll: options.behaviorProbabilityRoll || source?.behaviorProbabilityRoll || null,
    behaviorFallbackReason: options.behaviorFallbackReason ?? source?.behaviorFallbackReason ?? null,
  };
}

function createAgentIntent(agent, options = {}) {
  const now = Date.now();
  const owner = options.owner || 'route-handoff';
  const priorityName = options.priorityName || AGENT_INTENT_OWNER_TO_PRIORITY_NAME[owner] || 'route-handoff';
  const target = inferAgentIntentTarget(options.target || null, options.building || null, options.floor ?? null);
  const object = { ...inferAgentIntentObject(options.target || null, options.building || null), ...(options.object || {}) };
  const behavior = normalizeAgentIntentBehaviorMetadata(options, options.target || null, object);
  const id = options.id || `intent:${getAgentDebugId(agent)}:${owner}:${now}:${++agentIntentSequence}`;
  const staleAfterMs = options.expires?.staleAfterMs ?? (priorityName === 'explicit-object' ? AGENT_INTENT_APPROACH_STALE_AFTER_MS : null);
  return {
    id,
    agentId: getAgentDebugId(agent),
    owner,
    priority: options.priority ?? AGENT_INTENT_PRIORITY[priorityName] ?? AGENT_INTENT_PRIORITY['route-handoff'],
    priorityName,
    target,
    object,
    phase: options.phase || 'routing',
    expires: {
      atMs: options.expires?.atMs ?? null,
      ttlMs: options.expires?.ttlMs ?? null,
      idleGraceMs: options.expires?.idleGraceMs ?? null,
      staleAfterMs,
    },
    release: {
      policy: options.release?.policy || AGENT_INTENT_DEFAULT_RELEASE_POLICY[priorityName] || 'on-route-clear',
      allowedBy: [...(options.release?.allowedBy || AGENT_INTENT_RELEASE_ALLOWED_BY[priorityName] || AGENT_INTENT_RELEASE_ALLOWED_BY['route-handoff'])],
      releaseObjectReservation: Boolean(options.release?.releaseObjectReservation ?? object?.preserveUntilRelease),
      releaseActiveUse: Boolean(options.release?.releaseActiveUse ?? object?.preserveUntilRelease),
      restorePreviousIntentId: options.release?.restorePreviousIntentId ?? null,
    },
    source: {
      family: options.source?.family || 'setAgentTarget',
      functionName: options.source?.functionName || 'setAgentTarget',
      file: 'src/client/js/main3d.js',
      line: options.source?.line ?? null,
      taskRef: options.source?.taskRef || 'phase-3b.1-agent-intent-debug-snapshot',
      behaviorSourceKind: behavior.behaviorSourceKind,
      behaviorMode: behavior.behaviorMode,
      behaviorAuthority: behavior.behaviorAuthority,
      behaviorCategory: behavior.behaviorSelectedCategory,
    },
    behavior,
    debug: {
      label: options.debug?.label || `${owner}:${priorityName}`,
      createdAtMs: now,
      updatedAtMs: now,
      admittedAtMs: options.debug?.admittedAtMs ?? now,
      blockedAtMs: options.debug?.blockedAtMs ?? null,
      releasedAtMs: options.debug?.releasedAtMs ?? null,
      parentIntentId: options.debug?.parentIntentId ?? null,
      previousIntentId: options.debug?.previousIntentId ?? agent?._agentIntent?.id ?? null,
      supersededByIntentId: options.debug?.supersededByIntentId ?? null,
      activeTargetSummary: summarizeIntentTarget(target),
      sourceSummary: options.debug?.sourceSummary || 'main3d.js#setAgentTarget',
      objectSummary: summarizeIntentObject(object),
      routeSummary: options.debug?.routeSummary || 'existing movement route executor handoff; no routing behavior changed',
      releaseSummary: options.debug?.releaseSummary || (AGENT_INTENT_DEFAULT_RELEASE_POLICY[priorityName] || 'on-route-clear'),
      releaseReason: options.debug?.releaseReason || null,
      staleTimeoutVisible: Boolean(options.debug?.staleTimeoutVisible || false),
      staleForMs: options.debug?.staleForMs ?? null,
      lastAdmissionDecision: options.debug?.lastAdmissionDecision || 'accepted',
      lastDecisionReason: options.debug?.lastDecisionReason || 'read-only-intent-metadata-stamped',
      behaviorSourceKind: behavior.behaviorSourceKind,
      behaviorMode: behavior.behaviorMode,
      behaviorAuthority: behavior.behaviorAuthority,
      behaviorSelectedCategory: behavior.behaviorSelectedCategory,
      behaviorSelectedObject: behavior.behaviorSelectedObject,
      behaviorSelectedSpot: behavior.behaviorSelectedSpot,
      behaviorProbabilityRoll: behavior.behaviorProbabilityRoll,
      behaviorFallbackReason: behavior.behaviorFallbackReason,
      blockedOverrides: Array.isArray(options.debug?.blockedOverrides) ? [...options.debug.blockedOverrides] : [],
      interruptedLowerLayer: options.debug?.interruptedLowerLayer || null,
      counters: {
        accepted: options.debug?.counters?.accepted ?? 1,
        refreshed: options.debug?.counters?.refreshed ?? 0,
        rejectedLowerPriority: options.debug?.counters?.rejectedLowerPriority ?? 0,
        rejectedIncompatibleEqualPriority: options.debug?.counters?.rejectedIncompatibleEqualPriority ?? 0,
        expired: options.debug?.counters?.expired ?? 0,
        released: options.debug?.counters?.released ?? 0,
        recoveryHandoffs: options.debug?.counters?.recoveryHandoffs ?? 0,
        routeHandoffs: options.debug?.counters?.routeHandoffs ?? 1,
      },
    },
  };
}

function attachAgentIntent(agent, options = {}) {
  if (!agent) return null;
  const intent = createAgentIntent(agent, options);
  agent._agentIntent = intent;
  return intent;
}

function isTerminalAgentIntentPhase(phase) {
  return ['complete', 'released', 'blocked', 'expired', 'cancelled', 'failed'].includes(String(phase || ''));
}

function isAgentIntentActive(intent) {
  return !!(intent && !isTerminalAgentIntentPhase(intent.phase));
}

function areAgentIntentObjectsCompatible(activeObject = {}, nextObject = {}) {
  const activeKeys = [activeObject.worldActionId, activeObject.id, activeObject.buildingId, activeObject.furnitureIndex, activeObject.objectType, activeObject.actionId, activeObject.spotId, activeObject.slotId]
    .filter(value => value !== null && value !== undefined && value !== '');
  const nextKeys = [nextObject.worldActionId, nextObject.id, nextObject.buildingId, nextObject.furnitureIndex, nextObject.objectType, nextObject.actionId, nextObject.spotId, nextObject.slotId]
    .filter(value => value !== null && value !== undefined && value !== '');
  if (!activeKeys.length || !nextKeys.length) return true;
  return activeKeys.some(value => nextKeys.includes(value));
}

function createRejectedIntentDebugEvent(activeIntent, attemptedIntent, reason = 'lower-priority-active-intent') {
  return {
    accepted: false,
    reason,
    activeIntentId: activeIntent?.id || null,
    activeOwner: activeIntent?.owner || null,
    activePriority: activeIntent?.priority ?? null,
    activeBehaviorSourceKind: activeIntent?.behavior?.behaviorSourceKind || activeIntent?.source?.behaviorSourceKind || null,
    attemptedBehaviorSourceKind: attemptedIntent?.behavior?.behaviorSourceKind || attemptedIntent?.source?.behaviorSourceKind || null,
    attemptedBehaviorMode: attemptedIntent?.behavior?.behaviorMode || attemptedIntent?.source?.behaviorMode || null,
    attemptedOwner: attemptedIntent?.owner || null,
    attemptedPriority: attemptedIntent?.priority ?? null,
    attemptedCategory: attemptedIntent?.behavior?.behaviorSelectedCategory ?? null,
    attemptedTarget: attemptedIntent?.target || null,
    attemptedObject: attemptedIntent?.behavior?.behaviorSelectedObject || attemptedIntent?.object || null,
    attemptedSpot: attemptedIntent?.behavior?.behaviorSelectedSpot || null,
    attemptedSource: attemptedIntent?.source || null,
    fallbackReason: attemptedIntent?.behavior?.behaviorFallbackReason || null,
    blockedAtMs: Date.now(),
  };
}

function recordAgentIntentBlockedOverride(agent, activeIntent, attemptedIntent, reason = 'lower-priority-active-intent') {
  if (!agent || !activeIntent) return null;
  const event = createRejectedIntentDebugEvent(activeIntent, attemptedIntent, reason);
  const debug = activeIntent.debug || (activeIntent.debug = {});
  debug.updatedAtMs = event.blockedAtMs;
  debug.blockedAtMs = event.blockedAtMs;
  debug.lastAdmissionDecision = 'rejected';
  debug.lastDecisionReason = reason;
  debug.blockedOverrides = [...(debug.blockedOverrides || []), event].slice(-12);
  debug.counters = {
    ...(debug.counters || {}),
    rejectedLowerPriority: Number(debug.counters?.rejectedLowerPriority || 0) + (reason === 'lower-priority-active-intent' ? 1 : 0),
    rejectedIncompatibleEqualPriority: Number(debug.counters?.rejectedIncompatibleEqualPriority || 0) + (reason === 'equal-priority-incompatible-active-intent' ? 1 : 0),
  };
  agent._lastBlockedIntentOverride = event;
  return event;
}

function admitAgentIntent(agent, options = {}) {
  syncAgentIntentFromLifecycle(agent);
  const attemptedIntent = createAgentIntent(agent, options);
  const activeIntent = agent?._agentIntent || null;
  if (!isAgentIntentActive(activeIntent)) return { accepted: true, attemptedIntent, activeIntent: null, reason: 'no-active-intent' };
  if ((attemptedIntent.priority || 0) > (activeIntent.priority || 0)) return { accepted: true, attemptedIntent, activeIntent, reason: 'higher-priority-intent' };
  const samePriority = (attemptedIntent.priority || 0) === (activeIntent.priority || 0);
  if (samePriority && attemptedIntent.owner === activeIntent.owner && areAgentIntentObjectsCompatible(activeIntent.object, attemptedIntent.object)) {
    attemptedIntent.id = activeIntent.id;
    attemptedIntent.debug = {
      ...(attemptedIntent.debug || {}),
      createdAtMs: activeIntent.debug?.createdAtMs || attemptedIntent.debug?.createdAtMs || Date.now(),
      previousIntentId: activeIntent.debug?.previousIntentId || null,
      blockedOverrides: [...(activeIntent.debug?.blockedOverrides || [])],
      counters: {
        ...(activeIntent.debug?.counters || {}),
        accepted: Number(activeIntent.debug?.counters?.accepted || 1),
        refreshed: Number(activeIntent.debug?.counters?.refreshed || 0) + 1,
      },
      lastAdmissionDecision: 'refreshed',
      lastDecisionReason: 'same-owner-compatible-refresh',
    };
    return { accepted: true, attemptedIntent, reason: 'same-owner-compatible-refresh' };
  }
  if (samePriority && activeIntent.priorityName === 'live-status' && attemptedIntent.priorityName === 'live-status') {
    attemptedIntent.debug = {
      ...(attemptedIntent.debug || {}),
      previousIntentId: activeIntent.id,
      blockedOverrides: [...(activeIntent.debug?.blockedOverrides || [])],
      counters: {
        ...(activeIntent.debug?.counters || {}),
        accepted: Number(activeIntent.debug?.counters?.accepted || 1) + 1,
      },
      lastAdmissionDecision: 'accepted',
      lastDecisionReason: 'live-status-owner-transition',
    };
    return { accepted: true, attemptedIntent, reason: 'live-status-owner-transition' };
  }
  if (!samePriority && (attemptedIntent.priority || 0) < (activeIntent.priority || 0)) {
    const blockedOverride = recordAgentIntentBlockedOverride(agent, activeIntent, attemptedIntent, 'lower-priority-active-intent');
    return { accepted: false, attemptedIntent, activeIntent, reason: 'lower-priority-active-intent', blockedOverride };
  }
  const reason = samePriority ? 'equal-priority-incompatible-active-intent' : 'lower-priority-active-intent';
  const blockedOverride = recordAgentIntentBlockedOverride(agent, activeIntent, attemptedIntent, reason);
  return { accepted: false, attemptedIntent, activeIntent, reason, blockedOverride };
}

function syncAgentIntentFromLifecycle(agent) {
  const intent = agent?._agentIntent || null;
  const idle = agent?._idleActivity || null;
  if (!isAgentIntentActive(intent) || !idle) return intent;
  if (intent.priorityName === 'explicit-object' || intent.owner === 'object-action' || intent.owner === 'world-action') {
    intent.phase = idle.phase || intent.phase;
    intent.object = {
      ...(intent.object || { type: 'furniture' }),
      buildingId: intent.object?.buildingId || idle.buildingId || null,
      furnitureIndex: intent.object?.furnitureIndex ?? idle.furnitureIndex ?? null,
      objectType: intent.object?.objectType || idle.furnitureType || null,
      actionId: intent.object?.actionId || idle.actionId || idle.action || null,
      worldActionId: intent.object?.worldActionId || idle.worldActionId || null,
      spotId: intent.object?.spotId || idle.spotId || idle.interactionSpotId || null,
      slotId: intent.object?.slotId || idle.slotId || idle.seatId || null,
      reservationId: intent.object?.reservationId || idle.reservationId || null,
      activeUseId: intent.object?.activeUseId || idle.activeUseId || null,
      preserveUntilRelease: true,
    };
    intent.debug = {
      ...(intent.debug || {}),
      updatedAtMs: Date.now(),
      objectSummary: summarizeIntentObject(intent.object),
      lastDecisionReason: 'explicit-object-lifecycle-synced',
    };
  }
  return intent;
}

function lifecycleMatchesAgentIntent(activity = null, intent = null) {
  if (!activity || !intent) return false;
  const object = intent.object || {};
  const sameWorldAction = object.worldActionId && activity.worldActionId && object.worldActionId === activity.worldActionId;
  const sameReservation = object.reservationId && activity.reservationId && object.reservationId === activity.reservationId;
  const sameActiveUse = object.activeUseId && activity.activeUseId && object.activeUseId === activity.activeUseId;
  const sameFurniture = object.buildingId && activity.buildingId && object.buildingId === activity.buildingId && object.furnitureIndex != null && Number(object.furnitureIndex) === Number(activity.furnitureIndex);
  const sameAction = object.actionId && (activity.actionId || activity.action) && object.actionId === (activity.actionId || activity.action);
  return Boolean(sameWorldAction || sameReservation || sameActiveUse || sameFurniture || sameAction);
}

function getAgentIntentTargetObject(intent = null) {
  const object = intent?.object || null;
  if (!object) return { exists: true, target: null, reason: 'no-object-target' };
  if (object.buildingId) {
    const building = buildingsMap.get(object.buildingId);
    if (!building) return { exists: false, target: null, reason: 'missing-building' };
    if (object.furnitureIndex != null) {
      const furniture = building?.interior?.furniture?.[object.furnitureIndex] || null;
      if (!furniture) return { exists: false, target: null, reason: 'missing-furniture' };
      return { exists: true, target: furniture, building, reason: 'furniture-found' };
    }
    if (object.id && object.type === 'outdoor-node') {
      const outdoor = getRawOutdoorNodeById(building, object.id) || null;
      if (!outdoor) return { exists: false, target: null, building, reason: 'missing-outdoor-node' };
      return { exists: true, target: outdoor, building, reason: 'outdoor-node-found' };
    }
    return { exists: true, target: building, building, reason: 'building-found' };
  }
  if (object.id && object.type === 'outdoor-node') {
    const worldObject = _worldObjects?.get?.(object.id) || null;
    if (!worldObject) return { exists: false, target: null, reason: 'missing-world-object' };
    return { exists: true, target: worldObject, reason: 'world-object-found' };
  }
  return { exists: true, target: null, reason: 'no-resolvable-object-target' };
}

function releaseObjectAssignmentForAgentIntent(agent, intent = null, reason = 'intent-released') {
  const object = intent?.object || null;
  if (!agent || !object || (!intent.release?.releaseObjectReservation && !intent.release?.releaseActiveUse && !object.preserveUntilRelease)) {
    return { released: false, reason: 'no-object-release-policy' };
  }
  const resolved = getAgentIntentTargetObject(intent);
  const target = resolved?.target || null;
  if (!target || (resolved.reason && String(resolved.reason).startsWith('missing'))) return { released: false, reason: resolved?.reason || 'missing-target' };
  const agentId = String(agent.id || agent.name || 'agent');
  const reservationId = object.reservationId || null;
  const activeUseId = object.activeUseId || null;
  const slotId = object.slotId || object.spotId || null;
  const actionId = object.actionId || null;
  let changed = false;
  const matches = (entry = {}) => {
    if (!entry) return false;
    return Boolean(
      (reservationId && String(entry.id || entry.reservationId || '') === String(reservationId)) ||
      (activeUseId && String(entry.id || entry.activeUseId || '') === String(activeUseId)) ||
      (slotId && String(entry.slotId || entry.seatId || entry.spotId || entry.interactionSpotId || '') === String(slotId) && (!entry.agentId || String(entry.agentId) === agentId)) ||
      (actionId && String(entry.actionId || entry.action || '') === String(actionId) && (!entry.agentId || String(entry.agentId) === agentId)) ||
      (entry.agentId && String(entry.agentId) === agentId)
    );
  };
  if (matches(target.reservation)) { target.reservation = null; changed = true; }
  if (matches(target.state?.reservation)) { delete target.state.reservation; changed = true; }
  for (const storeKey of ['objectUseSeat', 'objectUseStanding', 'objectUseActive', '_scriptedObjectUseStore', '_scriptedServiceQueueStore']) {
    const reservations = target[storeKey]?.reservations;
    if (!Array.isArray(reservations)) continue;
    target[storeKey].reservations = reservations.map(reservation => {
      if (matches(reservation) && !['released', 'complete', 'completed', 'cancelled', 'failed'].includes(String(reservation.state || reservation.status || '').toLowerCase())) {
        changed = true;
        return { ...reservation, state: 'released', status: 'released', releasedAtMs: Date.now(), releaseReason: reason };
      }
      return reservation;
    });
  }
  for (const listKey of ['objectUseSeatReservations', 'objectUseStandingReservations', 'objectUseActiveReservations']) {
    const reservations = target[listKey];
    if (!Array.isArray(reservations)) continue;
    target[listKey] = reservations.map(reservation => {
      if (matches(reservation) && !['released', 'complete', 'completed', 'cancelled', 'failed'].includes(String(reservation.state || reservation.status || '').toLowerCase())) {
        changed = true;
        return { ...reservation, state: 'released', status: 'released', releasedAtMs: Date.now(), releaseReason: reason };
      }
      return reservation;
    });
  }
  const activeUse = target.activeUse || null;
  if (activeUse) {
    const activeSeats = { ...(activeUse.activeSeats || {}) };
    const activeSlots = { ...(activeUse.activeSlots || {}) };
    let seatChanged = false;
    let slotChanged = false;
    for (const [key, value] of Object.entries(activeSeats)) {
      if (matches({ ...value, seatId: key, slotId: key })) { delete activeSeats[key]; seatChanged = true; }
    }
    for (const [key, value] of Object.entries(activeSlots)) {
      if (matches({ ...value, slotId: key, spotId: key })) { delete activeSlots[key]; slotChanged = true; }
    }
    if (seatChanged || slotChanged || matches(activeUse)) {
      const remainingSeats = Object.keys(activeSeats).length;
      const remainingSlots = Object.keys(activeSlots).length;
      if (remainingSeats || remainingSlots) {
        target.activeUse = { ...activeUse, activeSeats, activeSlots, state: 'active', lastReleasedAgentId: agentId, lastReleaseReason: reason };
      } else {
        target.activeUse = clearCompletedObjectAssignmentMarkers(target, activeUse, { state: 'idle', mode: activeUse.mode || 'open', activeSlots, agent, action: actionId || activeUse.actionId || activeUse.action || null, reason });
      }
      changed = true;
    }
  }
  if (changed) {
    if (target.type === 'arcadeMachine') target.playMode = 'ready';
    for (const [key, value] of Object.entries(target)) {
      if (!value || typeof value !== 'object' || Array.isArray(value) || !key.endsWith('State')) continue;
      for (const listKey of ['reservedSlotIds', 'activeSlotIds', 'reservedSeatIds', 'activeSeatIds']) {
        if (Array.isArray(value[listKey])) {
          const next = value[listKey].filter(id => String(id) !== String(slotId || ''));
          if (next.length !== value[listKey].length) { value[listKey] = next; }
        }
      }
      if (value.agentId && String(value.agentId) === agentId) delete value.agentId;
      if (value.reservedAgentId && String(value.reservedAgentId) === agentId) delete value.reservedAgentId;
      if (['reserved', 'active', 'playing', 'occupied', 'queued', 'in-use', 'in_use'].includes(String(value.status || '').toLowerCase())) value.status = 'ready';
    }
  }
  return { released: changed, reason: changed ? 'object-assignment-released' : 'no-matching-object-assignment', targetType: target.type || object.objectType || object.type || null };
}

function releaseAgentIntent(agent, reason = 'released', options = {}) {
  const intent = agent?._agentIntent || null;
  if (!agent || !isAgentIntentActive(intent)) return { released: false, reason: 'no-active-intent', intent: cloneAgentIntent(intent) };
  const allowedBy = intent.release?.allowedBy || [];
  const releaseBy = options.releaseBy || reason;
  if (allowedBy.length && !allowedBy.includes(releaseBy) && !allowedBy.includes(reason)) {
    return { released: false, reason: 'release-not-allowed', releaseBy, intent: cloneAgentIntent(intent) };
  }
  const now = Date.now();
  const terminalPhase = options.phase || (reason === 'timeout' ? 'expired' : (reason === 'cancel' ? 'cancelled' : (reason === 'route-failed' || reason === 'missing-target' ? 'failed' : 'released')));
  intent.phase = terminalPhase;
  intent.debug = {
    ...(intent.debug || {}),
    updatedAtMs: now,
    releasedAtMs: now,
    releaseReason: reason,
    staleTimeoutVisible: reason === 'timeout' || Boolean(intent.debug?.staleTimeoutVisible),
    staleForMs: options.staleForMs ?? intent.debug?.staleForMs ?? null,
    lastAdmissionDecision: 'released',
    lastDecisionReason: reason,
    releaseSummary: options.releaseSummary || `released by ${reason}`,
    counters: {
      ...(intent.debug?.counters || {}),
      released: Number(intent.debug?.counters?.released || 0) + 1,
      expired: Number(intent.debug?.counters?.expired || 0) + (reason === 'timeout' ? 1 : 0),
    },
  };
  const objectRelease = releaseObjectAssignmentForAgentIntent(agent, intent, reason);
  if (objectRelease.released) {
    intent.debug.objectAssignmentRelease = objectRelease;
    intent.debug.releaseSummary = `${intent.debug.releaseSummary}; object assignment released`;
  }
  if (options.clearRoute !== false) {
    agent._wanderTarget = null;
    agent._waypointPath = null;
    agent._waypointPathTarget = null;
    agent._waypointPathIdx = 0;
    agent._doorTransition = null;
    clearDynamicInteriorRoutingForAgent(agent.id);
    clearDynamicExteriorRoutingForAgent(agent.id);
  }
  if (options.clearLifecycle) agent._idleActivity = null;
  return { released: true, reason, phase: terminalPhase, intent: cloneAgentIntent(intent) };
}

function releaseObjectAssignmentForAgentActivity(agent, activity = null, reason = 'activity-interrupted') {
  if (!agent || !activity || activity.buildingId == null || activity.furnitureIndex == null) {
    return { released: false, reason: 'missing-agent-or-activity-target' };
  }
  const building = buildingsMap.get(activity.buildingId);
  const furniture = building?.interior?.furniture?.[activity.furnitureIndex] || null;
  if (!furniture) return { released: false, reason: 'missing-activity-furniture' };
  const objectType = activity.furnitureType || furniture.type || null;
  const actionId = activity.actionId || activity.action || furniture.reservation?.actionId || furniture.activeUse?.actionId || null;
  const fakeIntent = {
    object: {
      type: 'furniture',
      id: furniture.id || `${activity.buildingId}-${objectType || 'object'}-${activity.furnitureIndex}`,
      buildingId: activity.buildingId,
      furnitureIndex: activity.furnitureIndex,
      objectType,
      actionId,
      spotId: activity.spotId || activity.activationSpotId || activity.interactionSpotId || furniture.reservation?.spotId || furniture.activeUse?.interactionSpotId || null,
      slotId: activity.activeUseSlotId || activity.slotId || activity.seatId || activity.activationSpotId || activity.spotId || null,
      reservationId: activity.reservationId || furniture.reservation?.id || furniture.reservation?.reservationId || null,
      activeUseId: activity.activeUseId || furniture.activeUse?.id || null,
      preserveUntilRelease: true,
    },
    release: { releaseObjectReservation: true, releaseActiveUse: true },
  };
  return releaseObjectAssignmentForAgentIntent(agent, fakeIntent, reason);
}

function evaluateAgentIntentRelease(agent) {
  const intent = agent?._agentIntent || null;
  if (!isAgentIntentActive(intent)) return { released: false, reason: 'no-active-intent' };
  const activity = agent._idleActivity || null;
  const activityPhase = String(activity?.phase || '').toLowerCase();
  const matchesLifecycle = lifecycleMatchesAgentIntent(activity, intent);
  if (matchesLifecycle && ['complete', 'cancelled', 'canceled', 'failed'].includes(activityPhase)) {
    const reason = activityPhase === 'complete' ? 'object-complete' : (activityPhase.startsWith('cancel') ? 'cancel' : 'route-failed');
    return releaseAgentIntent(agent, reason, { releaseBy: reason, clearLifecycle: true, releaseSummary: `matching lifecycle ${activityPhase} released intent` });
  }
  syncAgentIntentFromLifecycle(agent);
  if ((intent.priorityName === 'explicit-object' || intent.release?.policy === 'on-object-complete') && !activity && !agent._wanderTarget) {
    return releaseAgentIntent(agent, 'object-complete', { releaseBy: 'object-complete', clearRoute: false, releaseSummary: 'object lifecycle and route are complete' });
  }
  if (intent.priorityName === 'explicit-object' || intent.release?.policy === 'on-object-complete') {
    const objectState = getAgentIntentTargetObject(intent);
    if (!objectState.exists) {
      return releaseAgentIntent(agent, 'missing-target', { releaseBy: 'route-failed', clearLifecycle: true, releaseSummary: objectState.reason });
    }
  }
  const staleAfterMs = Number(intent.expires?.staleAfterMs || 0) || 0;
  const createdAtMs = Number(intent.debug?.createdAtMs || 0) || 0;
  const now = Date.now();
  const isApproach = String(intent.phase || '').toLowerCase() === 'approach' || activityPhase === 'approach';
  if (staleAfterMs > 0 && createdAtMs > 0 && isApproach && now - createdAtMs >= staleAfterMs) {
    return releaseAgentIntent(agent, 'timeout', { releaseBy: 'timeout', clearLifecycle: true, staleForMs: now - createdAtMs, releaseSummary: `approach intent stale for ${now - createdAtMs}ms` });
  }
  return { released: false, reason: 'active' };
}

function getExplicitObjectActionMetadata(agent, target = null, building = null, metadata = {}) {
  const selected = metadata.furnitureIndex == null && _selectedFurniture?.buildingId === building?.id ? _selectedFurniture : null;
  const furnitureIndex = metadata.furnitureIndex ?? target?.furnitureIndex ?? selected?.index ?? null;
  const furniture = metadata.furniture || (building && furnitureIndex != null ? building.interior?.furniture?.[furnitureIndex] : null) || null;
  const buildingId = metadata.buildingId || target?.buildingId || building?.id || null;
  const objectType = metadata.objectType || target?.objectType || target?.catalogKey || target?.catalogId || furniture?.type || null;
  const actionId = metadata.actionId || target?.actionId || target?.apiActionId || target?.uiActionId || furniture?.reservation?.actionId || furniture?.activeUse?.actionId || `object-action:${objectType || 'object'}`;
  const objectId = metadata.objectId || target?.objectId || target?.objectInstanceId || (buildingId && objectType && furnitureIndex != null ? `${buildingId}-${objectType}-${furnitureIndex}` : null);
  const spotId = metadata.spotId || target?.spotId || target?.interactionSpotId || target?.activationSpotId || target?.routeSpotId || furniture?.reservation?.spotId || furniture?.activeUse?.interactionSpotId || null;
  const reservationId = metadata.reservationId || target?.reservationId || furniture?.reservation?.reservationId || furniture?.reservation?.id || (objectId ? `reservation:${objectId}:${actionId}:${getAgentDebugId(agent)}` : null);
  const activeUseId = metadata.activeUseId || target?.activeUseId || furniture?.activeUse?.id || (objectId ? `active-use:${objectId}:${actionId}:${getAgentDebugId(agent)}` : null);
  return { buildingId, furnitureIndex, furniture, objectType, actionId, objectId, spotId, reservationId, activeUseId };
}

function setAgentTargetForExplicitObjectAction(agent, target, building = null, floor = null, metadata = {}) {
  const objectMeta = getExplicitObjectActionMetadata(agent, target, building, metadata);
  const owner = metadata.owner || 'object-action';
  const priorityName = metadata.priorityName || (owner === 'user' || owner === 'manual' || owner === 'verifier' ? 'manual' : 'explicit-object');
  const enrichedTarget = {
    ...(target || {}),
    targetKind: target?.targetKind || metadata.targetKind || 'placed-object',
    buildingId: objectMeta.buildingId,
    furnitureIndex: objectMeta.furnitureIndex,
    objectId: objectMeta.objectId,
    objectInstanceId: target?.objectInstanceId || objectMeta.objectId,
    objectType: objectMeta.objectType,
    catalogKey: target?.catalogKey || objectMeta.objectType,
    actionId: objectMeta.actionId,
    spotId: objectMeta.spotId,
    interactionSpotId: target?.interactionSpotId || objectMeta.spotId,
    reservationId: objectMeta.reservationId,
    activeUseId: objectMeta.activeUseId,
    preserveUntilRelease: true,
  };
  return setAgentTarget(agent, enrichedTarget, building, floor, {
    owner,
    priorityName,
    phase: metadata.phase || 'approach',
    target: enrichedTarget,
    building,
    floor,
    object: {
      type: metadata.objectKind || (enrichedTarget.targetKind === 'outdoor-node' ? 'outdoor-node' : 'furniture'),
      id: objectMeta.objectId,
      buildingId: objectMeta.buildingId,
      furnitureIndex: objectMeta.furnitureIndex,
      objectType: objectMeta.objectType,
      actionId: objectMeta.actionId,
      worldActionId: metadata.worldActionId || target?.worldActionId || null,
      spotId: objectMeta.spotId,
      slotId: metadata.slotId || target?.slotId || target?.seatId || null,
      reservationId: objectMeta.reservationId,
      activeUseId: objectMeta.activeUseId,
      preserveUntilRelease: true,
    },
    release: { policy: priorityName === 'manual' ? 'manual-only' : 'on-object-complete', releaseObjectReservation: true, releaseActiveUse: true, ...(metadata.release || {}) },
    source: {
      family: metadata.sourceFamily || 'context-menu',
      functionName: metadata.sourceFunction || 'setAgentTargetForExplicitObjectAction',
      taskRef: metadata.taskRef || 'phase-3b.2-explicit-object-intent',
    },
    behaviorSourceKind: metadata.behaviorSourceKind,
    behaviorMode: metadata.behaviorMode,
    behaviorAuthority: metadata.behaviorAuthority,
    behaviorCategory: metadata.behaviorCategory,
    behaviorSelectedObject: metadata.behaviorSelectedObject,
    behaviorSelectedSpot: metadata.behaviorSelectedSpot,
    behaviorProbabilityRoll: metadata.behaviorProbabilityRoll,
    behaviorFallbackReason: metadata.behaviorFallbackReason,
    skipReachabilityAdjust: metadata.skipReachabilityAdjust === true || target?.skipReachabilityAdjust === true || target?.matchesDebugPoint === true,
    debug: {
      label: metadata.debugLabel || `${owner}:${objectMeta.actionId}`,
      sourceSummary: metadata.sourceSummary || 'explicit object action movement handoff',
      releaseSummary: 'on-object-complete; preserve reservation/activeUse until terminal release',
      lastDecisionReason: 'explicit-object-action-intent-admitted',
    },
  });
}

function setAgentTargetForLiveStatus(agent, target, building = null, floor = null, metadata = {}) {
  const statusKind = metadata.statusKind || metadata.owner || 'live-status';
  const owner = statusKind === 'work' || statusKind === 'meeting' ? statusKind : 'live-status';
  const objectType = metadata.objectType || target?.objectType || null;
  const enrichedTarget = {
    ...(target || {}),
    targetKind: target?.targetKind || metadata.targetKind || (owner === 'meeting' ? 'meeting-table' : 'work-desk'),
    buildingId: metadata.buildingId || target?.buildingId || building?.id || null,
    furnitureIndex: metadata.furnitureIndex ?? target?.furnitureIndex ?? null,
    objectType,
    catalogKey: target?.catalogKey || objectType,
    actionId: metadata.actionId || target?.actionId || (owner === 'meeting' ? 'planning.meeting' : 'work.desk'),
    spotId: metadata.spotId || target?.spotId || null,
    interactionSpotId: target?.interactionSpotId || metadata.spotId || target?.spotId || null,
  };
  return setAgentTarget(agent, enrichedTarget, building, floor, {
    owner,
    priorityName: 'live-status',
    phase: metadata.phase || 'routing',
    target: enrichedTarget,
    building,
    floor,
    object: {
      type: metadata.objectKind || (owner === 'meeting' || objectType ? 'furniture' : 'none'),
      id: metadata.objectId || target?.objectId || null,
      buildingId: enrichedTarget.buildingId,
      furnitureIndex: enrichedTarget.furnitureIndex,
      objectType,
      actionId: enrichedTarget.actionId,
      worldActionId: null,
      spotId: enrichedTarget.spotId,
      slotId: metadata.slotId || target?.slotId || target?.seatId || null,
      reservationId: null,
      activeUseId: null,
      preserveUntilRelease: false,
    },
    release: { policy: 'on-route-clear', releaseObjectReservation: false, releaseActiveUse: false },
    source: {
      family: metadata.sourceFamily || 'live-status-loop',
      functionName: metadata.sourceFunction || 'setAgentTargetForLiveStatus',
      taskRef: metadata.taskRef || 'phase-3b.3-live-status-work-meeting-intent',
    },
    behaviorSourceKind: metadata.behaviorSourceKind,
    behaviorMode: metadata.behaviorMode,
    behaviorAuthority: metadata.behaviorAuthority,
    behaviorCategory: metadata.behaviorCategory,
    behaviorSelectedObject: metadata.behaviorSelectedObject,
    behaviorSelectedSpot: metadata.behaviorSelectedSpot,
    behaviorProbabilityRoll: metadata.behaviorProbabilityRoll,
    behaviorFallbackReason: metadata.behaviorFallbackReason,
    debug: {
      label: `live-status:${owner}`,
      sourceSummary: metadata.sourceSummary || `live status ${owner} movement handoff`,
      releaseSummary: 'on-route-clear; live status route ownership only',
      lastDecisionReason: `live-status-${owner}-intent-admitted`,
    },
  });
}

function cloneAgentIntent(intent) {
  return intent ? JSON.parse(JSON.stringify(intent)) : null;
}

function cloneIntentHandoffPoint(point = null) {
  if (!point) return null;
  const cloned = {};
  for (const key of ['x', 'y', 'floor', 'buildingFloor']) {
    if (point[key] != null && Number.isFinite(Number(point[key]))) cloned[key] = Number(point[key]);
  }
  for (const key of ['buildingId', 'targetKind', 'routeMode', 'spotId', 'objectId', 'objectInstanceId', 'actionId']) {
    if (point[key] != null) cloned[key] = point[key];
  }
  return Object.keys(cloned).length ? cloned : null;
}

function pointsMatchIntentHandoffTarget(a = null, b = null) {
  if (!a || !b) return false;
  const ax = Number(a.x); const ay = Number(a.y);
  const bx = Number(b.x); const by = Number(b.y);
  if (!Number.isFinite(ax) || !Number.isFinite(ay) || !Number.isFinite(bx) || !Number.isFinite(by)) return false;
  const sameFloor = a.floor == null || b.floor == null || Math.max(1, Number(a.floor) || 1) === Math.max(1, Number(b.floor) || 1);
  return sameFloor && Math.abs(ax - bx) <= 0.001 && Math.abs(ay - by) <= 0.001;
}

function summarizeAgentRouteHandoff(agent, intent = null) {
  const doorTransition = agent?._doorTransition || null;
  const elevatorTrip = agent?._elevatorTrip || null;
  const active = Boolean(doorTransition?.phase || elevatorTrip);
  const originalIntentTarget = cloneIntentHandoffPoint(intent?.target || null);
  const doorFinalTarget = cloneIntentHandoffPoint(doorTransition?.finalTarget || null);
  const elevatorFinalTarget = cloneIntentHandoffPoint(elevatorTrip?.finalTarget || null);
  const expectedFinalTarget = doorFinalTarget || elevatorFinalTarget || originalIntentTarget;
  const targetPreservedDuringHandoff = !active || !expectedFinalTarget || !originalIntentTarget
    ? true
    : pointsMatchIntentHandoffTarget(originalIntentTarget, expectedFinalTarget);
  return Object.freeze({
    active,
    phase: elevatorTrip ? 'elevator-trip' : (doorTransition?.phase || null),
    doorTransition: doorTransition ? Object.freeze({
      active: Boolean(doorTransition.phase),
      phase: doorTransition.phase || null,
      buildingId: doorTransition.buildingId || null,
      reachApi: Number.isFinite(Number(doorTransition.reachApi)) ? Number(doorTransition.reachApi) : null,
      finalTarget: doorFinalTarget,
    }) : null,
    elevatorTrip: elevatorTrip ? Object.freeze({
      active: true,
      buildingId: elevatorTrip.buildingId || null,
      fromFloor: Math.max(1, Number(elevatorTrip.fromFloor || 1) || 1),
      toFloor: Math.max(1, Number(elevatorTrip.toFloor || 1) || 1),
      finalTarget: elevatorFinalTarget,
    }) : null,
    originalIntentTarget,
    currentRouteTarget: cloneIntentHandoffPoint(agent?._wanderTarget || null),
    targetPreservedDuringHandoff,
    summary: active
      ? `${elevatorTrip ? `elevator ${elevatorTrip.fromFloor || '?'}→${elevatorTrip.toFloor || '?'}` : `door ${doorTransition?.phase || 'transition'}`} while intent target stays ${summarizeIntentTarget(intent?.target || null)}`
      : 'no active door/elevator handoff',
  });
}

function getAgentIntentSnapshot(agent) {
  if (!agent) return null;
  evaluateAgentIntentRelease(agent);
  syncAgentIntentFromLifecycle(agent);
  const intent = cloneAgentIntent(agent._agentIntent) || createAgentIntent(agent, {
    id: `intent:${getAgentDebugId(agent)}:route-handoff:snapshot`,
    owner: 'route-handoff',
    priorityName: 'route-handoff',
    target: agent._wanderTarget || null,
    building: agent._targetBuilding || agent._currentBuilding || null,
    floor: agent._targetFloor || agent._floor || null,
    phase: agent._wanderTarget ? 'routing' : 'queued',
    debug: { lastAdmissionDecision: 'accepted', lastDecisionReason: agent._wanderTarget ? 'derived-from-current-route-state' : 'no-active-route-state' },
  });
  const idle = agent._idleActivity || null;
  if (idle) {
    intent.phase = idle.phase || intent.phase;
    intent.object = {
      ...(intent.object || { type: 'none' }),
      objectType: intent.object?.objectType || idle.furnitureType || null,
      furnitureIndex: intent.object?.furnitureIndex ?? idle.furnitureIndex ?? null,
      actionId: intent.object?.actionId || idle.action || null,
      spotId: intent.object?.spotId || idle.spotId || null,
      activeUseId: intent.object?.activeUseId || idle.activeUseId || null,
      reservationId: intent.object?.reservationId || idle.reservationId || null,
    };
    intent.debug.objectSummary = summarizeIntentObject(intent.object);
  }
  intent.debug.updatedAtMs = Date.now();
  intent.debug.activeTargetSummary = summarizeIntentTarget(intent.target);
  const handoff = summarizeAgentRouteHandoff(agent, intent);
  intent.debug.routeHandoff = handoff;
  intent.debug.doorTransitionPhase = handoff.doorTransition?.phase || null;
  intent.debug.elevatorTrip = handoff.elevatorTrip || null;
  intent.debug.targetPreservedDuringHandoff = handoff.targetPreservedDuringHandoff;
  const behaviorDebug = getBehaviorReadoutMetadataFromIntent(intent, agent);
  return Object.freeze({
    agentId: getAgentDebugId(agent),
    agentName: agent.name || null,
    status: agent.status || null,
    intent,
    owner: intent.owner,
    priority: intent.priority,
    priorityName: intent.priorityName,
    target: intent.target,
    phase: intent.phase,
    object: intent.object,
    handoff,
    source: intent.source,
    behavior: intent.behavior || null,
    behaviorSourceKind: behaviorDebug.behaviorSourceKind,
    behaviorMode: behaviorDebug.behaviorMode,
    behaviorSelectedCategory: behaviorDebug.selectedCategory,
    behaviorSelectedObject: behaviorDebug.selectedObject,
    behaviorSelectedSpot: behaviorDebug.selectedSpot,
    behaviorProbabilityRoll: behaviorDebug.probabilityRoll,
    behaviorFallbackReason: behaviorDebug.fallbackReason,
    blockedLowerLayerOverrides: behaviorDebug.blockedLowerLayerOverrides,
    blockedLowerLayerOverrideCount: behaviorDebug.blockedLowerLayerOverrideCount,
    agentLiveModeEnabled: behaviorDebug.agentLiveModeEnabled,
    behaviorDebug,
    release: intent.release,
    debug: intent.debug,
  });
}

function getAllAgentIntentSnapshots() {
  return agentsList.map(agent => getAgentIntentSnapshot(agent)).filter(Boolean);
}

function normalizeAgentLiveModeEnabled(agent = null) {
  return Boolean(agent?.agentLiveModeEnabled);
}

function getIntentReadoutFallbackClassification(intent = null) {
  const owner = intent?.owner || null;
  const priorityName = intent?.priorityName || null;
  const sourceSummary = String(intent?.debug?.sourceSummary || intent?.source?.summary || '').toLowerCase();
  const lastDecisionReason = intent?.debug?.lastDecisionReason || null;
  const routeHandoff = intent?.debug?.routeHandoff || null;

  if (owner === 'user' || priorityName === 'manual') {
    return { behaviorSourceKind: 'user', behaviorMode: 'user-directed', selectedCategory: 'manual-control', readoutStatus: 'ok' };
  }
  if (owner === 'live-status' || priorityName === 'live-status') {
    return { behaviorSourceKind: 'agent-live-mode', behaviorMode: 'live-status', selectedCategory: 'live-status', readoutStatus: 'ok' };
  }
  if (owner === 'schedule' || priorityName === 'schedule') {
    return { behaviorSourceKind: 'system-schedule', behaviorMode: 'schedule', selectedCategory: routeHandoff?.active ? 'route-handoff' : 'scheduled-destination', readoutStatus: 'ok' };
  }
  if (owner === 'route-handoff' || priorityName === 'route-handoff') {
    return { behaviorSourceKind: 'route-handoff', behaviorMode: 'movement-handoff', selectedCategory: routeHandoff?.active ? 'door-or-elevator' : 'route-state', readoutStatus: lastDecisionReason === 'no-active-route-state' ? 'inactive-route-snapshot' : 'ok' };
  }
  if (owner === 'idle' || priorityName === 'idle') {
    if (sourceSummary.includes('scripted') || sourceSummary.includes('proposal')) {
      return { behaviorSourceKind: 'agent-scripted-mode', behaviorMode: 'agent-scripted', selectedCategory: 'scripted-idle', readoutStatus: 'ok' };
    }
    if (sourceSummary.includes('furniture') || sourceSummary.includes('local')) {
      return { behaviorSourceKind: 'agent-scripted-mode', behaviorMode: 'legacy-local-idle', selectedCategory: 'local-furniture', readoutStatus: 'legacy' };
    }
    return { behaviorSourceKind: 'agent-scripted-mode', behaviorMode: 'legacy-idle', selectedCategory: 'idle', readoutStatus: 'legacy' };
  }
  return { behaviorSourceKind: 'system', behaviorMode: 'unclassified', selectedCategory: owner || priorityName || 'none', readoutStatus: 'needs-metadata' };
}

function getBehaviorReadoutMetadataFromIntent(intent = null, agent = null) {
  const behavior = intent?.behavior || {};
  const debug = intent?.debug || {};
  const source = intent?.source || {};
  const fallback = getIntentReadoutFallbackClassification(intent);
  const blockedOverrides = Array.isArray(debug.blockedOverrides) ? debug.blockedOverrides : [];
  const probabilityRoll = behavior.behaviorProbabilityRoll || debug.behaviorProbabilityRoll || null;
  const selectedObject = behavior.behaviorSelectedObject || debug.behaviorSelectedObject || intent?.object || null;
  const selectedSpot = behavior.behaviorSelectedSpot || debug.behaviorSelectedSpot || null;
  return Object.freeze({
    behaviorSourceKind: behavior.behaviorSourceKind || source.behaviorSourceKind || fallback.behaviorSourceKind,
    behaviorMode: behavior.behaviorMode || source.behaviorMode || fallback.behaviorMode,
    behaviorAuthority: behavior.behaviorAuthority ?? source.behaviorAuthority ?? null,
    selectedCategory: behavior.behaviorSelectedCategory ?? debug.behaviorSelectedCategory ?? source.behaviorCategory ?? fallback.selectedCategory,
    selectedObject,
    selectedSpot,
    probabilityRoll,
    deterministicReason: probabilityRoll?.deterministic ? 'deterministic scripted roll' : (probabilityRoll ? null : (debug.lastDecisionReason || fallback.readoutStatus || null)),
    fallbackReason: behavior.behaviorFallbackReason || debug.behaviorFallbackReason || null,
    readoutStatus: fallback.readoutStatus,
    readoutClassificationFallback: !(behavior.behaviorSourceKind || source.behaviorSourceKind),
    blockedLowerLayerOverrides: Object.freeze(blockedOverrides.map(entry => Object.freeze({ ...entry }))),
    blockedLowerLayerOverrideCount: blockedOverrides.length,
    agentLiveModeEnabled: normalizeAgentLiveModeEnabled(agent),
  });
}

const AGENT_INTENT_DEBUG_READOUT_STORAGE_KEY = 'vw.agentIntentDebugReadout.enabled';
const AGENT_INTENT_DEBUG_READOUT_SCOPE_STORAGE_KEY = 'vw.agentIntentDebugReadout.scope';
let agentIntentDebugReadoutEnabled = false;
let agentIntentDebugReadoutScope = 'all';
let agentIntentDebugReadoutTimer = null;

function getLatestIntentBlockedOverride(snapshot = null) {
  const overrides = snapshot?.debug?.blockedOverrides || snapshot?.intent?.debug?.blockedOverrides || [];
  return overrides.length ? overrides[overrides.length - 1] : (snapshot?.debug?.lastAdmissionDecision === 'rejected' ? (snapshot?.debug || null) : null);
}

function summarizeIntentDebugTargetForReadout(snapshot = null) {
  const target = snapshot?.target || snapshot?.intent?.target || null;
  if (!target) return 'none';
  const parts = [];
  if (Number.isFinite(Number(target.x)) && Number.isFinite(Number(target.y))) parts.push(`${roundIntentNumber(target.x)},${roundIntentNumber(target.y)}`);
  if (target.floor != null) parts.push(`f${target.floor}`);
  if (target.buildingId) parts.push(`b:${target.buildingId}`);
  if (target.spotId) parts.push(`spot:${target.spotId}`);
  return parts.length ? parts.join(' ') : summarizeIntentTarget(target);
}

function summarizeIntentDebugObjectForReadout(snapshot = null) {
  const object = snapshot?.behaviorDebug?.selectedObject || snapshot?.object || snapshot?.intent?.object || null;
  if (!object || object.type === 'none') return 'none';
  const ids = [];
  if (object.id) ids.push(`obj:${object.id}`);
  if (object.objectType) ids.push(`type:${object.objectType}`);
  if (object.catalogId) ids.push(`catalog:${object.catalogId}`);
  if (object.actionId) ids.push(`action:${object.actionId}`);
  if (object.worldActionId) ids.push(`world:${object.worldActionId}`);
  if (object.furnitureIndex != null) ids.push(`furn:${object.furnitureIndex}`);
  if (object.spotId) ids.push(`spot:${object.spotId}`);
  if (object.slotId) ids.push(`slot:${object.slotId}`);
  if (object.reservationId) ids.push(`res:${object.reservationId}`);
  return ids.length ? ids.join(' ') : summarizeIntentObject(object);
}

function summarizeBehaviorSpotForReadout(snapshot = null) {
  const spot = snapshot?.behaviorDebug?.selectedSpot || snapshot?.behaviorSelectedSpot || snapshot?.behavior?.behaviorSelectedSpot || null;
  if (!spot) return 'none';
  const parts = [];
  if (spot.spotId) parts.push(`spot:${spot.spotId}`);
  if (spot.slotId) parts.push(`slot:${spot.slotId}`);
  if (spot.seatId) parts.push(`seat:${spot.seatId}`);
  if (spot.interactionSpotId) parts.push(`int:${spot.interactionSpotId}`);
  if (Number.isFinite(Number(spot.x)) && Number.isFinite(Number(spot.y))) parts.push(`${roundIntentNumber(spot.x)},${roundIntentNumber(spot.y)}`);
  if (spot.floor != null) parts.push(`f${spot.floor}`);
  return parts.length ? parts.join(' ') : JSON.stringify(spot);
}

function summarizeBehaviorProbabilityForReadout(snapshot = null) {
  const roll = snapshot?.behaviorDebug?.probabilityRoll || snapshot?.behaviorProbabilityRoll || snapshot?.behavior?.behaviorProbabilityRoll || null;
  if (!roll) return snapshot?.behaviorDebug?.deterministicReason || 'none';
  const parts = [];
  if (Number.isFinite(Number(roll.roll))) parts.push(`roll ${roundIntentNumber(roll.roll)}`);
  if (Number.isFinite(Number(roll.weightedRoll))) parts.push(`weighted ${roundIntentNumber(roll.weightedRoll)}`);
  if (Number.isFinite(Number(roll.totalWeight))) parts.push(`total ${roundIntentNumber(roll.totalWeight)}`);
  if (roll.deterministic) parts.push('deterministic');
  return parts.length ? parts.join(' / ') : JSON.stringify(roll);
}

function getAgentIntentDebugReadoutSnapshots() {
  const all = getAllAgentIntentSnapshots();
  if (agentIntentDebugReadoutScope === 'selected' && selectedAgentId) {
    return all.filter(snapshot => snapshot.agentId === selectedAgentId);
  }
  return all;
}

function renderAgentIntentDebugReadout() {
  const panel = document.getElementById('agentIntentDebugReadout');
  const body = document.getElementById('agentIntentDebugBody');
  const scopeBtn = document.getElementById('agentIntentDebugScope');
  const toolbarBtn = document.getElementById('btn-agentIntentDebug');
  if (!panel || !body) return null;
  panel.hidden = !agentIntentDebugReadoutEnabled;
  toolbarBtn?.classList.toggle('active', agentIntentDebugReadoutEnabled);
  if (scopeBtn) scopeBtn.textContent = agentIntentDebugReadoutScope === 'selected' ? 'Selected' : 'All';
  if (!agentIntentDebugReadoutEnabled) return null;

  const snapshots = getAgentIntentDebugReadoutSnapshots();
  if (!snapshots.length) {
    body.innerHTML = `<div class="agent-intent-debug-empty">${agentIntentDebugReadoutScope === 'selected' ? 'No selected agent intent snapshot.' : 'No agent intent snapshots loaded.'}</div>`;
    return snapshots;
  }

  body.innerHTML = snapshots.map(snapshot => {
    const blocked = getLatestIntentBlockedOverride(snapshot);
    const owner = snapshot.owner || snapshot.intent?.owner || 'unknown';
    const priorityName = snapshot.priorityName || snapshot.intent?.priorityName || 'unknown';
    const priority = snapshot.priority ?? snapshot.intent?.priority ?? '—';
    const phase = snapshot.phase || snapshot.intent?.phase || 'queued';
    const target = summarizeIntentDebugTargetForReadout(snapshot);
    const object = summarizeIntentDebugObjectForReadout(snapshot);
    const behavior = snapshot.behaviorDebug || getBehaviorReadoutMetadataFromIntent(snapshot.intent || null, agentsList.find(agent => getAgentDebugId(agent) === snapshot.agentId));
    const behaviorSource = behavior.behaviorSourceKind || 'system';
    const behaviorMode = behavior.behaviorMode || 'unclassified';
    const selectedCategory = behavior.selectedCategory || 'none';
    const readoutStatus = behavior.readoutStatus || (behavior.readoutClassificationFallback ? 'derived-readout' : 'metadata');
    const selectedSpot = summarizeBehaviorSpotForReadout(snapshot);
    const probabilityText = summarizeBehaviorProbabilityForReadout(snapshot);
    const fallbackReason = behavior.fallbackReason || 'none';
    const blockedCount = behavior.blockedLowerLayerOverrideCount || 0;
    const blockedText = blocked
      ? `${blocked.attemptedBehaviorSourceKind || blocked.attemptedOwner || 'unknown'}(${blocked.attemptedPriority ?? '—'}) → ${blocked.activeBehaviorSourceKind || blocked.activeOwner || owner}(${blocked.activePriority ?? priority})`
      : 'none';
    const blockedReason = blocked?.reason || snapshot.debug?.lastDecisionReason || '';
    return `
      <div class="agent-intent-debug-row ${blocked ? 'intent-blocked' : ''}" data-agent-id="${escapeAttr(snapshot.agentId || '')}" data-intent-owner="${escapeAttr(owner)}" data-intent-priority="${escapeAttr(priority)}" data-intent-phase="${escapeAttr(phase)}" data-behavior-source-kind="${escapeAttr(behaviorSource)}" data-behavior-mode="${escapeAttr(behaviorMode)}" data-behavior-category="${escapeAttr(selectedCategory)}" data-readout-status="${escapeAttr(readoutStatus)}" data-agent-live-mode-enabled="${behavior.agentLiveModeEnabled ? 'true' : 'false'}" data-blocked-override="${blocked ? 'true' : 'false'}" data-blocked-lower-layer-count="${escapeAttr(blockedCount)}">
        <div>
          <div class="agent-intent-debug-agent">${escapeHtml(snapshot.agentName || snapshot.agentId || 'agent')}</div>
          <div class="agent-intent-debug-muted">${escapeHtml(snapshot.status || 'no status')}</div>
          <div class="agent-intent-debug-kv"><b>live</b> ${behavior.agentLiveModeEnabled ? 'enabled' : 'disabled'}</div>
        </div>
        <div>
          <span class="agent-intent-debug-pill">${escapeHtml(owner)}</span>
          <span class="agent-intent-debug-pill priority">${escapeHtml(priorityName)} ${escapeHtml(priority)}</span>
          <span class="agent-intent-debug-pill">${escapeHtml(behaviorSource)}</span>
          <div class="agent-intent-debug-kv"><b>mode</b> ${escapeHtml(behaviorMode)}</div>
          <div class="agent-intent-debug-kv"><b>phase</b> ${escapeHtml(phase)}</div>
          <div class="agent-intent-debug-kv"><b>readout</b> ${escapeHtml(readoutStatus)}</div>
        </div>
        <div class="agent-intent-debug-kv">
          <div><b>category</b> ${escapeHtml(selectedCategory)}</div>
          <div><b>target</b> ${escapeHtml(target)}</div>
          <div><b>object/action</b> ${escapeHtml(object)}</div>
          <div><b>spot</b> ${escapeHtml(selectedSpot)}</div>
        </div>
        <div class="agent-intent-debug-kv">
          <div><b>probability</b> ${escapeHtml(probabilityText)}</div>
          <div><b>fallback</b> ${escapeHtml(fallbackReason)}</div>
          ${blocked ? `<span class="agent-intent-debug-pill blocked">blocked lower layer ×${escapeHtml(blockedCount || 1)}</span>` : '<span class="agent-intent-debug-muted">no lower-layer block</span>'}
          <div>${escapeHtml(blockedText)}</div>
          ${blockedReason ? `<div>${escapeHtml(blockedReason)}</div>` : ''}
        </div>
      </div>
    `;
  }).join('');
  return snapshots;
}

function setAgentIntentDebugReadoutEnabled(enabled, options = {}) {
  agentIntentDebugReadoutEnabled = Boolean(enabled);
  if (options.scope === 'selected' || options.scope === 'all') agentIntentDebugReadoutScope = options.scope;
  try {
    localStorage.setItem(AGENT_INTENT_DEBUG_READOUT_STORAGE_KEY, agentIntentDebugReadoutEnabled ? '1' : '0');
    localStorage.setItem(AGENT_INTENT_DEBUG_READOUT_SCOPE_STORAGE_KEY, agentIntentDebugReadoutScope);
  } catch (_) {}
  renderAgentIntentDebugReadout();
  return agentIntentDebugReadoutEnabled;
}

function setupAgentIntentDebugReadout() {
  const panel = document.getElementById('agentIntentDebugReadout');
  const toggleBtn = document.getElementById('btn-agentIntentDebug');
  const closeBtn = document.getElementById('agentIntentDebugClose');
  const scopeBtn = document.getElementById('agentIntentDebugScope');
  if (!panel) return;
  try {
    agentIntentDebugReadoutEnabled = localStorage.getItem(AGENT_INTENT_DEBUG_READOUT_STORAGE_KEY) === '1';
    const savedScope = localStorage.getItem(AGENT_INTENT_DEBUG_READOUT_SCOPE_STORAGE_KEY);
    if (savedScope === 'selected' || savedScope === 'all') agentIntentDebugReadoutScope = savedScope;
  } catch (_) {}
  toggleBtn?.addEventListener('click', () => setAgentIntentDebugReadoutEnabled(!agentIntentDebugReadoutEnabled));
  closeBtn?.addEventListener('click', () => setAgentIntentDebugReadoutEnabled(false));
  scopeBtn?.addEventListener('click', () => {
    agentIntentDebugReadoutScope = agentIntentDebugReadoutScope === 'selected' ? 'all' : 'selected';
    setAgentIntentDebugReadoutEnabled(true, { scope: agentIntentDebugReadoutScope });
  });
  renderAgentIntentDebugReadout();
  if (!agentIntentDebugReadoutTimer) agentIntentDebugReadoutTimer = setInterval(renderAgentIntentDebugReadout, 1000);
}

