      target: { kind: 'furniture', id: 'task9-bench', buildingId: tempBuildingId, furnitureIndex: 0, objectType: 'parkBench', catalogId: 'parkBench' },
      spot: { spotId: 'approach-seat-a', seatId: 'seat-a', interactionSpotId: 'activation-seat-a', x: 10, y: 2, floor: 1 },
      objectId: 'task9-bench',
