      source: { family: 'phase4-task14-verifier', functionName: `verifyPhase4Task14.${sourceKind}`, taskRef: 'phase-4.task-14-debug-readout-controls' },
      behaviorSourceKind: sourceKind,
      behaviorMode: target.behaviorMode,
