function getBehaviorAuthorityRank(intent = null) {
  const sourceKind = intent?.behavior?.behaviorSourceKind || intent?.source?.behaviorSourceKind || null;
  if (sourceKind === 'user') return 1000;
  if (sourceKind === 'agent-live-mode') return intent?.priorityName === 'live-status' ? 800 : 900;
  if (sourceKind === 'system-schedule') return 500;
  if (sourceKind === 'agent-scripted-mode') return 300;
  return Number(intent?.priority || 0) || 0;
}

function isLowerBehaviorLayerInterrupt(activeIntent = null, attemptedIntent = null) {
  if (!activeIntent || !attemptedIntent) return false;
  return getBehaviorAuthorityRank(attemptedIntent) > getBehaviorAuthorityRank(activeIntent);
}

function releaseInterruptedLowerLayerIntentState(agent, activeIntent = null, attemptedIntent = null) {
  if (!agent || !isLowerBehaviorLayerInterrupt(activeIntent, attemptedIntent)) return { released: false, reason: 'not-lower-layer-interrupt' };
  const activeSource = activeIntent?.behavior?.behaviorSourceKind || activeIntent?.source?.behaviorSourceKind || null;
  const attemptedSource = attemptedIntent?.behavior?.behaviorSourceKind || attemptedIntent?.source?.behaviorSourceKind || null;
  if (attemptedSource !== 'user') return { released: false, reason: 'not-user-directed-interrupt', activeBehaviorSourceKind: activeSource, attemptedBehaviorSourceKind: attemptedSource };
  if (!['agent-live-mode', 'agent-scripted-mode', 'system-schedule'].includes(activeSource)) return { released: false, reason: 'active-source-not-interruptible-lower-layer', activeBehaviorSourceKind: activeSource, attemptedBehaviorSourceKind: attemptedSource };

  const activity = agent._idleActivity || null;
  const object = activeIntent.object || {};
  const buildingId = object.buildingId || activity?.buildingId || null;
  const furnitureIndex = object.furnitureIndex ?? activity?.furnitureIndex ?? null;
  const building = buildingId ? buildingsMap.get(buildingId) : null;
  const furniture = building && furnitureIndex != null ? building.interior?.furniture?.[furnitureIndex] || null : null;
  const agentId = getAgentDebugId(agent);
  const reservationMatches = !furniture?.reservation || !furniture.reservation.agentId || String(furniture.reservation.agentId) === agentId;
  const activeUseMatches = !furniture?.activeUse || !furniture.activeUse.agentId || String(furniture.activeUse.agentId) === agentId;
  const released = {
    released: true,
    reason: 'user-directed-override-released-lower-layer',
    activeIntentId: activeIntent.id || null,
    activeBehaviorSourceKind: activeSource,
    attemptedBehaviorSourceKind: attemptedSource,
    clearedIdleActivity: Boolean(activity),
    clearedReservation: false,
    clearedActiveUse: false,
    preservedReservation: false,
    preservedActiveUse: false,
  };

  if (furniture?.reservation && reservationMatches) {
    furniture.reservation = null;
    released.clearedReservation = true;
  } else if (furniture?.reservation) {
    released.preservedReservation = true;
  }
  if (furniture?.activeUse && activeUseMatches) {
    furniture.activeUse = { ...(furniture.activeUse || {}), state: 'interrupted', interruptedBy: 'user-directed-override', interruptedAtMs: Date.now(), previousAgentId: furniture.activeUse?.agentId || null };
    released.clearedActiveUse = true;
  } else if (furniture?.activeUse) {
    released.preservedActiveUse = true;
  }
  agent._idleActivity = null;
  return released;
}

function setAgentTarget(agent, target, building = null, floor = null) {
  const intentOptions = arguments[4] || {};
  const targetKind = String(target?.targetKind || '');
  const targetBuildingForAdjust = building || (target?.buildingId ? buildingsMap.get(target.buildingId) : null) || null;
  const canAdjustInteriorTarget = !!(
    intentOptions.skipReachabilityAdjust !== true &&
    targetBuildingForAdjust &&
    targetBuildingForAdjust.type !== 'park' &&
    target &&
    Number.isFinite(Number(target.x)) &&
    Number.isFinite(Number(target.y)) &&
    !['door-threshold', 'doorway', 'building-door-approach', 'elevator-pad', 'elevator-queue', 'outdoor-area-node', 'outdoor-area-action-location'].includes(targetKind)
  );
  if (canAdjustInteriorTarget) {
    const scopedBuilding = getFloorScopedBuilding(targetBuildingForAdjust, floor || target.floor || target.buildingFloor || 1);
    const reachability = resolveInteriorTargetReachability(scopedBuilding, target, { debug: false });
    if (reachability?.adjusted && reachability.target) {
      target = {
        ...reachability.target,
        originalTarget: target.originalTarget || { x: target.x, y: target.y, floor: target.floor || target.buildingFloor || floor || 1 },
        targetAdjusted: true,
        targetAdjustedReason: reachability.reason,
      };
      intentOptions.debug = {
        ...(intentOptions.debug || {}),
        targetAdjustedReason: reachability.reason,
        originalTarget: target.originalTarget,
      };
    }
  }
  const proposedIntentOptions = {
    owner: intentOptions.owner || 'route-handoff',
    priorityName: intentOptions.priorityName || AGENT_INTENT_OWNER_TO_PRIORITY_NAME[intentOptions.owner || 'route-handoff'] || 'route-handoff',
    target: intentOptions.target || target,
    building: intentOptions.building || building,
    floor: intentOptions.floor ?? floor,
    object: intentOptions.object || undefined,
    phase: intentOptions.phase || 'routing',
    expires: intentOptions.expires || undefined,
    release: intentOptions.release || undefined,
    source: intentOptions.source || { family: 'setAgentTarget', functionName: 'setAgentTarget' },
    behaviorSourceKind: intentOptions.behaviorSourceKind,
    behaviorMode: intentOptions.behaviorMode,
    behaviorAuthority: intentOptions.behaviorAuthority,
    behaviorCategory: intentOptions.behaviorCategory,
    behaviorSelectedObject: intentOptions.behaviorSelectedObject,
    behaviorSelectedSpot: intentOptions.behaviorSelectedSpot,
    behaviorProbabilityRoll: intentOptions.behaviorProbabilityRoll,
    behaviorFallbackReason: intentOptions.behaviorFallbackReason,
    debug: intentOptions.debug || undefined,
  };
  const admission = admitAgentIntent(agent, proposedIntentOptions);
  if (!admission.accepted) return admission;
  const interruptRelease = releaseInterruptedLowerLayerIntentState(agent, admission.activeIntent, admission.attemptedIntent);
  const nextDebug = admission.attemptedIntent?.debug || proposedIntentOptions.debug;
  if (interruptRelease?.released && nextDebug) nextDebug.interruptedLowerLayer = interruptRelease;
  attachAgentIntent(agent, {
    ...proposedIntentOptions,
    id: admission.attemptedIntent?.id,
    debug: nextDebug,
  });
  agent._wanderTarget = target;
  agent._waypointPath = null;
  agent._waypointPathTarget = null;
  agent._waypointPathIdx = 0;
  agent._targetBuilding = building || null;
  agent._currentBuilding = building || null;
  agent._targetFloor = Math.max(1, Number(floor || target?.floor || target?.buildingFloor || 1) || 1);
  agent._stayTimer = 0;
  agent._wanderTimer = 150;
  agent._forceIdleDeskReturn = false;
  agent._isReturningToDesk = false;
  agent._atDesk = false;
  agent._activeWorkSpot = null;
  const pendingTrip = agent._elevatorTrip || null;
  const pendingStillMatches = !!(
    pendingTrip &&
    (!building || pendingTrip.buildingId === building.id) &&
    pointsMatch2D(pendingTrip.finalTarget, target) &&
    Math.max(1, Number(pendingTrip.toFloor || 1) || 1) === agent._targetFloor
  );
  if (!pendingStillMatches) agent._elevatorTrip = null;
  return admission;
}

function freezeScriptedProposal(value) {
  if (!value || typeof value !== 'object' || Object.isFrozen(value)) return value;
  Object.freeze(value);
  for (const child of Object.values(value)) freezeScriptedProposal(child);
  return value;
}

function createAgentScriptedBehaviorProposal(agent, {
  category = 'wander',
  destination = null,
  target = null,
  building = null,
  floor = null,
  decision = null,
  reason = 'scripted-behavior-choice',
  objectUse = null,
  sourceKind = 'agent-scripted-mode',
  behaviorMode = 'agent-scripted',
  behaviorAuthority = 300,
  intentOwner = 'idle',
  intentPriorityName = 'idle',
  intentRelease = null,
} = {}) {
  const resolvedFloor = Math.max(1, Number(floor ?? destination?.floor ?? destination?.spot?.floor ?? target?.floor ?? 1) || 1);
  const resolvedBuilding = building || (destination?.buildingId ? buildingsMap.get(destination.buildingId) : null) || null;
  const spot = destination?.spot || {};
  const routeTarget = {
    ...(target || {}),
    x: Number.isFinite(Number(target?.x)) ? Number(target.x) : Number(spot.x ?? 0),
    y: Number.isFinite(Number(target?.y)) ? Number(target.y) : Number(spot.y ?? 0),
    floor: resolvedFloor,
    buildingFloor: resolvedFloor,
    buildingId: target?.buildingId || destination?.buildingId || resolvedBuilding?.id || null,
    targetKind: target?.targetKind || (destination?.target?.kind === 'furniture' ? 'placed-object' : 'scripted-world-point'),
    objectId: target?.objectId || destination?.objectId || destination?.target?.id || null,
    objectInstanceId: target?.objectInstanceId || destination?.objectId || destination?.target?.id || null,
    objectType: target?.objectType || destination?.objectType || destination?.target?.objectType || null,
    catalogKey: target?.catalogKey || destination?.target?.catalogId || destination?.objectType || null,
    furnitureIndex: target?.furnitureIndex ?? destination?.target?.furnitureIndex ?? null,
    spotId: target?.spotId || spot.spotId || null,
    interactionSpotId: target?.interactionSpotId || spot.interactionSpotId || spot.spotId || null,
    slotId: target?.slotId || spot.slotId || spot.seatId || null,
    seatId: target?.seatId || spot.seatId || null,
    actionId: target?.actionId || objectUse?.actionId || objectUse?.slot?.actionId || null,
    routeSpotRole: 'approachSpot',
  };
  return freezeScriptedProposal({
    version: 'agent-life-scripted-behavior-proposal/v1',
    sourceKind,
    behaviorMode,
    behaviorAuthority,
    intentOwner,
    intentPriorityName,
    intentRelease,
    category,
    agentId: getAgentDebugId(agent),
    reason,
    decision,
    destination,
    target: routeTarget,
    buildingId: routeTarget.buildingId,
    floor: resolvedFloor,
    objectUse,
    routeSemantics: Object.freeze({ routeUses: 'approachSpot', activationUses: 'activationSpot', preservesApproachVsActivation: true }),
  });
}

function scriptedStandingObjectUseStoreForFurniture(furniture) {
  if (!furniture) return null;
  if (getStandingUseMachineConfig(furniture.type)) return getStandingUseMachineStore(furniture);
  if (getBrowseStorageObjectConfig(furniture.type)) return getObjectUseStandingStoreForBrowseStorageObject(furniture);
  if (getReadInspectStandingObjectConfig(furniture.type)) return getObjectUseStandingStoreForReadInspectObject(furniture);
  if (['cafeCounter', 'foodTruckCounter', 'counter', 'kitchenIsland', 'checkoutCounter', 'checkoutRegister', 'coffeePickupShelf'].includes(furniture.type)) return getObjectUseStandingStoreForServiceSurface(furniture);
  if (!furniture._scriptedObjectUseStore) furniture._scriptedObjectUseStore = { reservations: [] };
  return furniture._scriptedObjectUseStore;
}

function scriptedActiveObjectUseStoreForFurniture(furniture) {
  if (!furniture) return null;
  if (furniture.type === 'treadmill') return getTreadmillObjectUseActiveStore(furniture);
  if (furniture.type === 'trainingMat') return getTrainingMatObjectUseActiveStore(furniture);
  if (furniture.type === 'gymBench') return getGymBenchObjectUseActiveStore(furniture);
  if (furniture.type === 'outdoorExerciseStation') return getOutdoorExerciseStationObjectUseActiveStore(furniture);
  if (furniture.type === 'playgroundSlide') return getPlaygroundSlideObjectUseActiveStore(furniture);
  if (furniture.type === 'playgroundSwing') return getPlaygroundSwingObjectUseActiveStore(furniture);
  if (!furniture.objectUseActiveReservations) furniture.objectUseActiveReservations = [];
  return { reservations: furniture.objectUseActiveReservations };
}

function scriptedProposalObjectUseStoreFor(building, furnitureIndex, lifecycle = null) {
  const furniture = building && furnitureIndex != null ? building.interior?.furniture?.[furnitureIndex] || null : null;
  if (!furniture) return null;
  if (lifecycle === 'seat') return { furniture, store: getObjectUseSeatStoreForFurniture(furniture) };
  if (lifecycle === 'standing') return { furniture, store: scriptedStandingObjectUseStoreForFurniture(furniture) };
  if (lifecycle === 'active') return { furniture, store: scriptedActiveObjectUseStoreForFurniture(furniture) };
  if (lifecycle === 'queue') {
    if (!furniture._scriptedServiceQueueStore) furniture._scriptedServiceQueueStore = { reservations: [] };
    return { furniture, store: furniture._scriptedServiceQueueStore };
  }
  if (!furniture._scriptedObjectUseStore) furniture._scriptedObjectUseStore = { reservations: [] };
  return { furniture, store: furniture._scriptedObjectUseStore };
}

function isLiveScriptedServiceQueueReservation(entry = null) {
  return Boolean(entry && !['released', 'cancelled', 'complete', 'failed'].includes(String(entry.state || entry.status || '').toLowerCase()));
}

function normalizeScriptedServiceQueueReservations(store) {
  if (!store || !Array.isArray(store.reservations)) return [];
  store.reservations = store.reservations
    .filter(isLiveScriptedServiceQueueReservation)
    .sort((a, b) => Number(a.queuePriority || 0) - Number(b.queuePriority || 0) || Number(a.queuedAtMs || 0) - Number(b.queuedAtMs || 0) || String(a.agentId || '').localeCompare(String(b.agentId || '')))
    .map((entry, index) => {
      const queueSpotId = String(entry.queueSpotId || entry.spotId || entry.slotId || 'queue').replace(/:\d+$/, '') || 'queue';
      const queueTargetId = `${queueSpotId}:${index}`;
      return { ...entry, queueSpotId, queueIndex: index, slotId: queueTargetId, queueTargetId, activationSpotId: queueTargetId };
    });
  return store.reservations;
}

function getScriptedServiceQueueDefinition(furniture = {}, preferredQueueSpotId = null) {
  const spots = getScriptedServiceQueueDefinitionsForFurniture(furniture);
  const preferredId = String(preferredQueueSpotId || '').replace(/:\d+$/, '');
  return spots.find(spot => preferredId && (spot.id === preferredId || spot.spotId === preferredId))
    || spots.find(spot => isQueueActionDebugSpot(spot))
    || null;
}

function getScriptedServiceQueueMaxPoints(furniture = {}, queueSpotId = null) {
  const queueDef = getScriptedServiceQueueDefinition(furniture, queueSpotId);
  const authoredQueueLocations = getAuthoredObjectQueueLocations(queueDef, furniture);
  const capacity = typeof queueDef?.capacity === 'number' ? queueDef.capacity : Number(queueDef?.capacity?.maxAgents || 0);
  return Math.max(1, Math.floor(Number(queueDef?.queueMaxPoints ?? queueDef?.maxQueuePoints ?? queueDef?.queueCapacity ?? capacity ?? authoredQueueLocations.length) || authoredQueueLocations.length || 3));
}

function getScriptedServiceQueueTarget(building = null, furniture = null, furnitureIndex = null, reservation = null) {
  if (!building || !furniture || !reservation) return null;
  const queueDef = getScriptedServiceQueueDefinition(furniture, reservation.queueSpotId);
  if (!queueDef) return null;
  const spots = FURNITURE_INTERACTION_SPOTS[furniture.type] || [];
  const primaryDef = getPrimaryActionDebugSpot(spots, queueDef);
  if (!primaryDef) return null;
  const primary = getFurnitureActionSpot(building, furniture, primaryDef.id || primaryDef.spotId);
  const queueAnchor = getFurnitureActionSpot(building, furniture, queueDef.id || queueDef.spotId) || resolveFurnitureSpotApiPoint(building, furniture, queueDef) || primary;
  if (!primary) return null;
  const queueIndex = Math.max(0, Number(reservation.queueIndex || 0) || 0);
  const queueTargetId = reservation.queueTargetId || reservation.slotId || `${reservation.queueSpotId || 'queue'}:${queueIndex}`;
  const authoredQueueLocation = getAuthoredObjectQueueLocations(queueDef, furniture).find(spot => Number(spot.queueIndex || 0) === queueIndex) || null;
  const authoredPoint = authoredQueueLocation ? resolveFurnitureSpotApiPoint(building, furniture, authoredQueueLocation) : null;
  if (authoredPoint) {
    const authoredTargetId = authoredQueueLocation.slotId || authoredQueueLocation.spotId || authoredQueueLocation.id || queueTargetId;
    return {
      x: Number(authoredPoint.apiX),
      y: Number(authoredPoint.apiZ),
      floor: reservation.floor || authoredPoint.floor || getFurnitureFloor(furniture),
      buildingFloor: reservation.floor || authoredPoint.floor || getFurnitureFloor(furniture),
      targetKind: 'placed-object',
      objectInstanceId: furniture.id || furniture.instanceId || `${building.id}-${furniture.type}-${furnitureIndex}`,
      objectId: furniture.id || `${building.id}:${furnitureIndex}`,
      catalogKey: furniture.catalogId || furniture.type,
      buildingId: building.id || null,
      furnitureIndex,
      objectType: furniture.type,
      scope: 'indoor',
      interactionSpotId: authoredTargetId,
      spotId: authoredTargetId,
      slotId: authoredTargetId,
      queueSpotId: reservation.queueSpotId || queueDef.id || queueDef.spotId || 'queue',
      queueIndex,
      authoredQueueLocation: true,
      actionId: reservation.actionId || queueDef.action || 'planning.schedule',
      routeOwner: 'main3d.js#service-queue-line',
      routeSpotRole: 'serviceQueueSlot',
    };
  }
  const dx = Number(queueAnchor?.apiX ?? primary.apiX) - Number(primary.apiX);
  const dz = Number(queueAnchor?.apiZ ?? primary.apiZ) - Number(primary.apiZ);
  const len = Math.hypot(dx, dz) || 1;
  const spacing = (Number(queueDef.queueSpacingTiles ?? queueDef.spacingTiles ?? DEFAULT_OBJECT_QUEUE_SPACING_TILES) || DEFAULT_OBJECT_QUEUE_SPACING_TILES) * API_TILE;
  return {
    x: Number(primary.apiX) + (dx / len) * spacing * (queueIndex + 1),
    y: Number(primary.apiZ) + (dz / len) * spacing * (queueIndex + 1),
    floor: reservation.floor || primary.floor || getFurnitureFloor(furniture),
    buildingFloor: reservation.floor || primary.floor || getFurnitureFloor(furniture),
    targetKind: 'placed-object',
    objectInstanceId: furniture.id || furniture.instanceId || `${building.id}-${furniture.type}-${furnitureIndex}`,
    objectId: furniture.id || `${building.id}:${furnitureIndex}`,
    catalogKey: furniture.catalogId || furniture.type,
    buildingId: building.id || null,
    furnitureIndex,
    objectType: furniture.type,
    scope: 'indoor',
    interactionSpotId: queueTargetId,
    spotId: queueTargetId,
    slotId: queueTargetId,
    queueSpotId: reservation.queueSpotId || 'queue',
    queueIndex,
    actionId: reservation.actionId || queueDef.action || 'planning.schedule',
    routeOwner: 'main3d.js#service-queue-line',
    routeSpotRole: 'serviceQueueSlot',
  };
}

function findScriptedServiceQueueAgent(reservation = null) {
  const agentId = String(reservation?.agentId || '');
  if (!agentId) return null;
  return agentsList.find(agent => getAgentDebugId(agent) === agentId) || null;
}

function retargetScriptedServiceQueueAgent(agent, building, furniture, furnitureIndex, reservation, reason = 'queue-shift') {
  if (!agent || !building || !furniture || !reservation) return false;
  const target = getScriptedServiceQueueTarget(building, furniture, furnitureIndex, reservation);
  if (!target) return false;
  const sourceKind = reservation.sourceKind || reservation.source || 'agent-scripted-mode';
  const manualQueue = String(sourceKind || '').startsWith('manual-drag-drop');
  const owner = manualQueue ? 'manual' : 'idle';
  const priorityName = manualQueue ? 'manual' : 'idle';
  const behaviorSourceKind = manualQueue ? 'user' : 'agent-scripted-mode';
  const behaviorMode = manualQueue ? 'user-directed' : 'agent-scripted';
  const behaviorAuthority = manualQueue ? AGENT_INTENT_PRIORITY.manual : 300;
  const route = setAgentTarget(agent, target, building, target.floor, {
    owner,
    priorityName,
    phase: 'approach',
    target,
    building,
    floor: target.floor,
    object: {
      type: 'furniture',
      id: target.objectInstanceId || target.objectId || null,
      buildingId: building.id || null,
      furnitureIndex,
      objectType: furniture.type || null,
      actionId: target.actionId || null,
      spotId: target.spotId || null,
      slotId: target.slotId || null,
      reservationId: reservation.id || null,
      preserveUntilRelease: false,
    },
    release: { policy: 'on-route-clear', releaseObjectReservation: false, releaseActiveUse: false, allowedBy: ['owner', 'route-failed', 'higher-priority', 'cancel', 'agent-offline'] },
    source: { family: behaviorSourceKind, functionName: 'retargetScriptedServiceQueueAgent', taskRef: 'service-queue-fcfs' },
    behaviorSourceKind,
    behaviorMode,
    behaviorAuthority,
    behaviorCategory: 'snack-drink',
    debug: { label: `service-queue:${reason}`, sourceSummary: 'service queue line slot retarget', queueIndex: reservation.queueIndex },
  });
  if (route?.accepted === false) return false;
  agent._idleActivity = {
    ...(agent._idleActivity || {}),
    kind: 'service-queue-wait',
    phase: 'approach',
    source: sourceKind,
    behaviorSourceKind,
    behaviorMode,
    behaviorCategory: 'snack-drink',
    buildingId: building.id || null,
    floor: target.floor,
    furnitureIndex,
    furnitureType: furniture.type || null,
    objectId: target.objectInstanceId || target.objectId || null,
    actionId: target.actionId || null,
    reservationId: reservation.id || null,
    spotId: target.spotId,
    slotId: target.slotId,
    activeUseSlotId: target.slotId,
    activationSpotId: target.slotId,
    queueSpotId: reservation.queueSpotId || target.queueSpotId,
    queueIndex: reservation.queueIndex || 0,
    queuedAtMs: reservation.queuedAtMs || Date.now(),
    isServiceQueueWait: true,
    mode: 'queue-wait',
    stayMs: 1200,
    dockSnapRadius: 6,
    animationId: 'bus-stop-wait',
    dockTarget: { x: target.x, y: target.y },
  };
  agent._wanderTimer = 120;
  return true;
}

function syncScriptedServiceQueueLine(building, furnitureIndex, reason = 'queue-sync', options = {}) {
  const access = scriptedProposalObjectUseStoreFor(building, furnitureIndex, 'queue');
  const furniture = access?.furniture || null;
  const store = access?.store || null;
  if (!building || !furniture || !store) return { synced: 0, reason: 'missing-queue-store' };
  const reservations = normalizeScriptedServiceQueueReservations(store);
  const queueableClaim = options.allowClaimedServiceObject === true && isScriptedServiceObjectClaimedForManualQueue(furniture);
  if (reservations.length && !isScriptedServiceObjectUnavailableForQueue(furniture) && !queueableClaim) {
    const promoted = promoteScriptedServiceQueueFrontIfReady(building, furnitureIndex, `${reason}:service-object-free-promote-front`);
    requestObjectActionPointDebugOverlayRefresh();
    return promoted;
  }
  let synced = 0;
  for (const reservation of reservations) {
    const agent = findScriptedServiceQueueAgent(reservation);
    if (agent && retargetScriptedServiceQueueAgent(agent, building, furniture, furnitureIndex, reservation, reason)) synced += 1;
  }
  requestObjectActionPointDebugOverlayRefresh();
  return { synced, queueLength: reservations.length };
}

function submitQueuedScriptedServiceObjectUse(agent, building, furnitureIndex, queueActivity = null) {
  const furniture = building?.interior?.furniture?.[furnitureIndex];
  if (!agent || !building || !furniture) return { accepted: false, reason: 'missing-service-use-target' };
  const machineConfig = getStandingUseMachineConfig(furniture?.type);
  const serviceSurface = !machineConfig && ['cafeCounter', 'foodTruckCounter', 'counter', 'kitchenIsland', 'checkoutCounter', 'checkoutRegister', 'coffeePickupShelf'].includes(furniture.type);
  const surfaceCandidates = serviceSurface
    ? getServiceSurfaceStandingUseCandidates({ building, surface: furniture, surfaceId: furnitureIndex, surfaceType: furniture.type, actionId: queueActivity?.actionId || queueActivity?.action })
    : [];
  const candidate = machineConfig
    ? getStandingUseMachineCandidate(building, furniture, furnitureIndex, machineConfig)
    : (surfaceCandidates.find(item => {
      const id = String(item.slotId || item.activationSpotId || '').toLowerCase();
      const roles = new Set(item.roles || []);
      return id.includes('customer') || id.includes('use') || id.includes('pickup') || roles.has('customer') || roles.has('order') || roles.has('checkout') || roles.has('surface');
    }) || surfaceCandidates[0] || null);
  const slotId = machineConfig?.slotId || candidate?.activationSpotId || candidate?.slotId || 'use-front';
  const actionId = queueActivity?.actionId || queueActivity?.action || machineConfig?.actionId || candidate?.actionId || `life.use.${furniture.type}`;
  const animationId = machineConfig?.animationId || candidate?.pose?.animationId || getLocalIdleActivityConfig(furniture.type)?.animationId || null;
  const mode = machineConfig?.mode || getScriptedStandingActivityMode(getLocalIdleActivityConfig(furniture.type) || {}, 'snack-drink', furniture.type);
  const spot = getFurnitureActionSpot(building, furniture, slotId) || getFurnitureActionSpot(building, furniture, candidate?.approachSpotId) || getFurnitureActionSpot(building, furniture);
  if (!candidate || !spot) return { accepted: false, reason: 'missing-service-use-spot' };
  const runtimeSlot = {
    ...candidate,
    position: { x: spot.apiX, z: spot.apiZ, floor: spot.floor },
    approachSpot: { ...(candidate.approachSpot || {}), position: { x: spot.apiX, z: spot.apiZ, floor: spot.floor } },
    activationSpot: { ...(candidate.activationSpot || {}), position: { x: spot.apiX, z: spot.apiZ, floor: spot.floor } },
    activationTarget: { x: spot.apiX, z: spot.apiZ, floor: spot.floor },
    approachTarget: { x: spot.apiX, z: spot.apiZ, floor: spot.floor },
    actionId,
  };
  const destination = {
    ok: true,
    runtimeCoordinateSpace: 'api-pixels',
    category: 'snack-drink',
    lifecycle: 'standing',
    target: {
      kind: 'furniture',
      id: furniture.id || `${building.id}:${furnitureIndex}`,
      buildingId: building.id || null,
      furnitureIndex,
      catalogId: furniture.catalogId || furniture.type,
      objectType: furniture.type,
    },
    spot: {
      spotId: slotId,
      slotId: runtimeSlot.slotId || slotId,
      interactionSpotId: runtimeSlot.activationSpotId || slotId,
      x: spot.apiX,
      y: spot.apiZ,
      floor: spot.floor || getFurnitureFloor(furniture),
    },
    objectId: furniture.id || `${building.id}:${furnitureIndex}`,
    objectType: furniture.type,
    buildingId: building.id || null,
    floor: spot.floor || getFurnitureFloor(furniture),
    objectUseSlot: runtimeSlot,
    objectUse: { lifecycle: 'standing', slot: runtimeSlot },
  };
  const activity = getLocalIdleActivityConfig(furniture.type) || { kind: `${String(furniture.type || 'service').replace(/([a-z])([A-Z])/g, '$1-$2').toLowerCase()}-use`, animationId, dockSnapRadius: 6, stayMs: machineConfig?.useDurationMs || 9000 };
  const objectUse = createScriptedObjectUseForDestination(destination, activity);
  if (!objectUse) return { accepted: false, reason: 'missing-promoted-object-use' };
  objectUse.promotedFromQueue = true;
  const sourceKind = queueActivity?.sourceKind || queueActivity?.source || 'agent-scripted-mode';
  const manualServiceUse = String(sourceKind || '').startsWith('manual-drag-drop');
  const behaviorSourceKind = manualServiceUse ? 'user' : 'agent-scripted-mode';
  const behaviorMode = manualServiceUse ? 'user-directed' : 'agent-scripted';
  const behaviorAuthority = manualServiceUse ? AGENT_INTENT_PRIORITY.manual : 300;
  const proposal = createAgentScriptedBehaviorProposal(agent, {
    category: 'snack-drink',
    destination,
    building,
    floor: destination.floor,
    decision: { category: 'snack-drink', selectedCategory: 'snack-drink', durationMs: objectUse.stayMs, behaviorProbabilityRoll: { tableVersion: 'service-queue-fcfs/v1' } },
    reason: 'service-queue-fcfs-promote-front',
    objectUse,
    sourceKind,
    behaviorMode,
    behaviorAuthority,
    intentOwner: manualServiceUse ? 'manual' : 'idle',
    intentPriorityName: manualServiceUse ? 'manual' : 'idle',
    intentRelease: manualServiceUse
      ? { policy: 'on-object-complete', releaseObjectReservation: true, releaseActiveUse: true, allowedBy: AGENT_INTENT_RELEASE_ALLOWED_BY['explicit-object'] }
      : null,
  });
  const route = submitAgentScriptedBehaviorProposal(agent, proposal);
  if (route?.accepted !== false && agent._idleActivity) {
    agent._idleActivity.kind = objectUse.activityKind || activity.kind || machineConfig?.kind || `${String(furniture.type || 'service').replace(/([a-z])([A-Z])/g, '$1-$2').toLowerCase()}-use`;
    agent._idleActivity.mode = objectUse.mode || mode;
    agent._idleActivity.stayMs = objectUse.stayMs || machineConfig?.useDurationMs || 9000;
    agent._idleActivity.animationId = objectUse.animationId || animationId;
    agent._idleActivity.dockSnapRadius = objectUse.dockSnapRadius || 6;
    agent._idleActivity.furnitureType = furniture.type;
    agent._idleActivity.isServiceQueueWait = false;
    agent._idleActivity.source = sourceKind;
    agent._idleActivity.behaviorSourceKind = behaviorSourceKind;
    agent._idleActivity.behaviorMode = behaviorMode;
    agent._idleActivity.activationSpotId = objectUse.slot?.activationSpotId || slotId;
    agent._idleActivity.approachSpotId = objectUse.slot?.approachSpotId || slotId;
    agent._idleActivity.activeUseSlotId = objectUse.slot?.slotId || slotId;
    agent._idleActivity.capacityKey = objectUse.slot?.capacityKey || agent._idleActivity.capacityKey;
    agent._idleActivity.faceAngle = spot.faceAngle ?? agent._idleActivity.faceAngle;
    agent._idleActivity.dockTarget = { x: spot.apiX, y: spot.apiZ };
  }
  return route;
}

function promoteScriptedServiceQueueFrontIfReady(building, furnitureIndex, reason = 'service-use-complete') {
  const access = scriptedProposalObjectUseStoreFor(building, furnitureIndex, 'queue');
  const furniture = access?.furniture || null;
  const store = access?.store || null;
  if (!building || !furniture || !store || isScriptedServiceObjectUnavailableForQueue(furniture)) {
    requestObjectActionPointDebugOverlayRefresh();
    return { promoted: false, reason: 'not-ready' };
  }
  const queue = normalizeScriptedServiceQueueReservations(store);
  const front = queue[0] || null;
  if (!front) {
    requestObjectActionPointDebugOverlayRefresh();
    return { promoted: false, reason: 'empty-queue' };
  }
  const agent = findScriptedServiceQueueAgent(front);
  if (!agent) {
    store.reservations = queue.slice(1);
    normalizeScriptedServiceQueueReservations(store);
    syncScriptedServiceQueueLine(building, furnitureIndex, `${reason}:missing-front-agent`);
    requestObjectActionPointDebugOverlayRefresh();
    return { promoted: false, reason: 'missing-front-agent' };
  }
  // SERVICE_QUEUE_SPEC.md: promotion must not dismiss waiters. Attempt the
  // machine handoff FIRST; only remove the front reservation once the agent
  // actually owns the object. On failure the agent keeps their queue slot.
  releaseAgentIntent(agent, 'queue-front-promoted', { releaseBy: 'owner', clearRoute: true, clearLifecycle: false, releaseSummary: 'front service queue agent promoted to object use' });
  agent._idleActivity = null;
  agent._schedPhase = 'service-queue-promoted';
  agent._wanderTimer = 120;
  const promoted = submitQueuedScriptedServiceObjectUse(agent, building, furnitureIndex, { ...front, buildingId: building.id, furnitureIndex, furnitureType: furniture.type });
  if (promoted?.accepted === false) {
    // Keep the front reservation; put the agent back on their queue slot so the
    // line survives a failed handoff instead of dissolving.
    retargetScriptedServiceQueueAgent(agent, building, furniture, furnitureIndex, front, `${reason}:promotion-failed-requeue`);
    requestObjectActionPointDebugOverlayRefresh();
    return { promoted: false, reason: promoted?.reason || 'promotion-route-rejected', agentId: getAgentDebugId(agent), route: promoted, requeued: true };
  }
  store.reservations = normalizeScriptedServiceQueueReservations(store).filter(entry => String(entry.agentId || '') !== String(getAgentDebugId(agent)));
  normalizeScriptedServiceQueueReservations(store);
  syncScriptedServiceQueueLine(building, furnitureIndex, `${reason}:front-promoted`);
  requestObjectActionPointDebugOverlayRefresh();
  return { promoted: true, reason: promoted?.reason || reason, agentId: getAgentDebugId(agent), route: promoted };
}

function advanceScriptedServiceQueueAfterUse(building, furnitureIndex, reason = 'service-use-complete') {
  return promoteScriptedServiceQueueFrontIfReady(building, furnitureIndex, reason);
}

function reserveScriptedServiceQueueSlot(store, objectUse, options = {}) {
  if (!store) return { ok: false, reason: 'missing-queue-store' };
  if (!Array.isArray(store.reservations)) store.reservations = [];
  const agentId = String(options.agentId || 'agent');
  const nowMs = Number(options.nowMs || Date.now());
  const live = normalizeScriptedServiceQueueReservations(store);
  const existing = live.find(entry => String(entry.agentId || '') === agentId);
  if (existing) return { ok: true, reservation: existing, reused: true };
  const manualServiceQueueInsertFront = options.insertAtFront === true;
  const minQueuedAtMs = live.reduce((min, entry) => Math.min(min, Number(entry.queuedAtMs || nowMs)), nowMs);
  const queuedAtMs = manualServiceQueueInsertFront ? minQueuedAtMs - 1 : Number(options.queuedAtMs || nowMs);
  const queueIndex = live.length;
  const queueSpotId = objectUse.slot?.queueSpotId || String(objectUse.slot?.slotId || 'queue').replace(/:\d+$/, '') || 'queue';
  const maxQueuePoints = Math.max(1, Math.floor(Number(objectUse.slot?.queueMaxPoints ?? objectUse.slot?.maxQueuePoints ?? objectUse.slot?.queueCapacity ?? objectUse.slot?.capacity ?? options.maxQueuePoints) || 3));
  if (queueIndex >= maxQueuePoints) return { ok: false, reason: 'queue-full', queueIndex, maxQueuePoints };
  const reservation = {
    id: options.reservationId || `queue:scripted:${agentId}:${queueSpotId}:${queuedAtMs}`,
    state: 'queued',
    status: 'queued',
    agentId,
    actionId: options.actionId || objectUse.actionId || null,
    slotId: `${queueSpotId}:${queueIndex}`,
    queueSpotId,
    activationSpotId: objectUse.slot?.activationSpotId || queueSpotId,
    queuedAtMs,
    queuePriority: manualServiceQueueInsertFront ? -1 : Number(options.queuePriority || objectUse.queuePriority || 0),
    queueIndex,
    capacityKind: 'queue',
    sourceKind: options.sourceKind || options.source || objectUse.sourceKind || 'agent-scripted-mode',
  };
  store.reservations = [...live, reservation];
  normalizeScriptedServiceQueueReservations(store);
  requestObjectActionPointDebugOverlayRefresh();
  return { ok: true, reservation: store.reservations.find(entry => entry.id === reservation.id) || reservation };
}

function releaseScriptedServiceQueueReservation(building, furnitureIndex, agent, reason = 'queue-released') {
  const access = scriptedProposalObjectUseStoreFor(building, furnitureIndex, 'queue');
  const store = access?.store || null;
  if (!store || !Array.isArray(store.reservations)) return { released: false, reason: 'missing-queue-store' };
  const agentId = String(getAgentDebugId(agent));
  const before = store.reservations.length;
  store.reservations = store.reservations
    .map(entry => String(entry.agentId || '') === agentId ? { ...entry, state: 'released', status: 'released', releasedAtMs: Date.now(), releaseReason: reason } : entry)
    .filter(isLiveScriptedServiceQueueReservation);
  normalizeScriptedServiceQueueReservations(store);
  syncScriptedServiceQueueLine(building, furnitureIndex, reason);
  requestObjectActionPointDebugOverlayRefresh();
  return { released: store.reservations.length !== before, reason };
}

function createScriptedServiceObjectRoutePendingClaim({ proposal, agent, furniture, objectUse, options }) {
  const agentId = options.agentId || getAgentDebugId(agent);
  const reservation = {
    id: options.reservationId,
    state: 'route_pending',
    status: 'route_pending',
    agentId,
    actionId: options.actionId,
    slotId: objectUse.slot?.slotId || objectUse.slot?.activationSpotId || proposal.target?.slotId || proposal.target?.spotId || null,
    standingUseSlotId: objectUse.slot?.standingUseSlotId || objectUse.slot?.slotId || null,
    activationSpotId: objectUse.slot?.activationSpotId || null,
    approachSpotId: objectUse.slot?.approachSpotId || null,
    capacityKey: objectUse.slot?.capacityKey || null,
    sourceKind: proposal.sourceKind || 'agent-scripted-mode',
    behaviorCategory: proposal.category,
    autonomousRoutePendingClaim: true,
    createdAtMs: options.nowMs,
  };
  const activeSlots = { ...(furniture.activeUse?.activeSlots || {}) };
  if (reservation.slotId) activeSlots[reservation.slotId] = {
    agentId,
    reservationId: reservation.id,
    actionId: reservation.actionId,
    state: 'route_pending',
    interactionSpotId: reservation.activationSpotId || reservation.slotId,
  };
  const activeUse = {
    id: options.objectUseId,
    reservationId: reservation.id,
    agentId,
    actionId: reservation.actionId,
    animationId: objectUse.animationId || null,
    mode: objectUse.mode || null,
    sourceKind: reservation.sourceKind,
    behaviorCategory: proposal.category,
    state: 'route_pending',
    lifecycle: objectUse.lifecycle,
    queueFrontPromoted: false,
    autonomousRoutePendingClaim: true,
    interactionSpotId: reservation.activationSpotId || proposal.target?.interactionSpotId || proposal.target?.spotId || null,
    approachSpotId: reservation.approachSpotId || objectUse.slot?.approachSpotId || null,
    activationSpotId: reservation.activationSpotId || objectUse.slot?.activationSpotId || null,
    activeUseSlotId: reservation.slotId,
    activeSlots,
    createdAtMs: options.nowMs,
  };
  furniture.reservation = reservation;
  furniture.activeUse = activeUse;
  return { reservation, activeUse, result: { ok: true, autonomousRoutePendingClaim: true } };
}

function reserveScriptedProposalObjectUseAfterAdmission(proposal, agent, building) {
  const objectUse = proposal?.objectUse || null;
  if (!objectUse || !building) return { ok: true, reservation: null, activeUse: null, reason: 'no-object-use' };
  const access = scriptedProposalObjectUseStoreFor(building, proposal.target?.furnitureIndex, objectUse.lifecycle);
  if (!access) return { ok: false, reason: 'missing-furniture-for-object-use' };
  const { furniture, store } = access;
  const options = {
    agentId: getAgentDebugId(agent),
    actionId: proposal.target?.actionId || objectUse.actionId || objectUse.slot?.actionId || `scripted.${proposal.category}`,
    reservationId: proposal.target?.reservationId || `res:scripted:${proposal.agentId}:${proposal.target?.objectInstanceId || proposal.target?.objectId}:${proposal.target?.slotId || proposal.target?.spotId}`,
    objectUseId: proposal.target?.activeUseId || `active:scripted:${proposal.agentId}:${proposal.target?.objectInstanceId || proposal.target?.objectId}:${proposal.target?.slotId || proposal.target?.spotId}`,
    nowMs: Date.now(),
  };
  if (objectUse.lifecycle === 'standing' && isScriptedServiceQueueFurniture(furniture) && !objectUse.promotedFromQueue) {
    const claim = createScriptedServiceObjectRoutePendingClaim({ proposal, agent, furniture, objectUse, options });
    requestObjectActionPointDebugOverlayRefresh();
    return { ok: true, reservation: claim.reservation, activeUse: claim.activeUse, result: claim.result };
  }
  let result = null;
  if (objectUse.lifecycle === 'seat') result = chooseAndReserveObjectUseSeat(store, [objectUse.slot], options);
  else if (objectUse.lifecycle === 'standing') result = chooseAndReserveObjectUseStandingSlot(store, [objectUse.slot], options);
  else if (objectUse.lifecycle === 'active') result = chooseAndReserveObjectUseActiveSlot(store, [objectUse.slot], options);
  else if (objectUse.lifecycle === 'queue') result = reserveScriptedServiceQueueSlot(store, objectUse, options);
  else return { ok: false, reason: 'unsupported-object-use-lifecycle' };
  if (!result?.ok) return { ok: false, reason: result?.reason || 'reservation-rejected', result };
  if (objectUse.lifecycle === 'queue') {
    const reservation = { ...result.reservation, status: result.reservation.state || 'queued', sourceKind: proposal.sourceKind || result.reservation.sourceKind || 'agent-scripted-mode', behaviorCategory: proposal.category };
    return { ok: true, reservation, activeUse: null, result };
  }
  const reservation = { ...result.reservation, status: result.reservation.state || 'held', sourceKind: proposal.sourceKind || result.reservation.sourceKind || 'agent-scripted-mode', behaviorCategory: proposal.category };
  const activeUse = {
    id: options.objectUseId,
    reservationId: reservation.id,
    agentId: getAgentDebugId(agent),
    actionId: options.actionId,
    animationId: objectUse.animationId || null,
    mode: objectUse.mode || null,
    sourceKind: proposal.sourceKind || 'agent-scripted-mode',
    behaviorCategory: proposal.category,
    state: 'route_pending',
    lifecycle: objectUse.lifecycle,
    queueFrontPromoted: objectUse.promotedFromQueue === true,
    interactionSpotId: reservation.activationSpotId || proposal.target?.interactionSpotId || proposal.target?.spotId || null,
    approachSpotId: reservation.approachSpotId || objectUse.slot?.approachSpotId || null,
    activationSpotId: reservation.activationSpotId || objectUse.slot?.activationSpotId || null,
    createdAtMs: options.nowMs,
  };
  furniture.reservation = reservation;
  furniture.activeUse = activeUse;
  return { ok: true, reservation, activeUse, result };
}

function submitAgentScriptedBehaviorProposal(agent, proposal) {
  if (!agent || !proposal?.target) return { accepted: false, reason: 'invalid-scripted-proposal', proposal };
  const building = proposal.buildingId ? buildingsMap.get(proposal.buildingId) : null;
  const target = { ...proposal.target };
  const objectUseIsQueue = proposal.objectUse?.lifecycle === 'queue';
  const intentOwner = proposal.intentOwner || 'idle';
  const intentPriorityName = proposal.intentPriorityName || AGENT_INTENT_OWNER_TO_PRIORITY_NAME[intentOwner] || 'idle';
  const behaviorSourceKind = String(proposal.sourceKind || '').startsWith('manual-drag-drop') ? 'user' : (proposal.sourceKind === 'agent-scripted-mode' ? 'agent-scripted-mode' : (proposal.sourceKind || 'agent-scripted-mode'));
  const behaviorMode = proposal.behaviorMode || (behaviorSourceKind === 'user' ? 'user-directed' : 'agent-scripted');
  const behaviorAuthority = proposal.behaviorAuthority ?? (intentPriorityName === 'manual' ? AGENT_INTENT_PRIORITY.manual : 300);
  const admission = setAgentTarget(agent, target, building, proposal.floor, {
    owner: intentOwner,
    priorityName: intentPriorityName,
    phase: 'approach',
    target,
    building,
    floor: proposal.floor,
    object: {
      type: target.targetKind === 'placed-object' ? 'furniture' : 'none',
      id: target.objectInstanceId || target.objectId || null,
      buildingId: target.buildingId || null,
      furnitureIndex: target.furnitureIndex ?? null,
      objectType: target.objectType || target.catalogKey || null,
      actionId: target.actionId || null,
      spotId: target.spotId || target.interactionSpotId || null,
      slotId: target.slotId || target.seatId || null,
      reservationId: target.reservationId || null,
      activeUseId: target.activeUseId || null,
      preserveUntilRelease: Boolean(proposal.objectUse && !objectUseIsQueue),
    },
    release: proposal.intentRelease || { policy: proposal.objectUse && !objectUseIsQueue ? 'on-object-complete' : 'on-route-clear', releaseObjectReservation: Boolean(proposal.objectUse && !objectUseIsQueue), releaseActiveUse: Boolean(proposal.objectUse && !objectUseIsQueue) },
    source: { family: behaviorSourceKind, functionName: 'submitAgentScriptedBehaviorProposal', taskRef: 'phase-4.task-9-scripted-mode-agent-intent-object-use' },
    behaviorSourceKind,
    behaviorMode,
    behaviorAuthority,
    behaviorCategory: proposal.category,
    behaviorSelectedObject: proposal.destination?.target || null,
    behaviorSelectedSpot: proposal.destination?.spot || null,
    behaviorProbabilityRoll: proposal.decision?.behaviorProbabilityRoll || null,
    behaviorFallbackReason: proposal.destination?.fallbackReason || null,
    debug: { label: `agent-scripted:${proposal.category}`, sourceSummary: 'scripted behavior proposal admitted before route/lifecycle mutation', lastDecisionReason: 'scripted-proposal-agent-intent-admitted' },
  });
  if (admission?.accepted === false) return { accepted: false, reason: admission.reason || 'agent-intent-rejected', proposal, admission };
  const objectUse = reserveScriptedProposalObjectUseAfterAdmission(proposal, agent, building);
  if (!objectUse.ok) {
    releaseAgentIntent(agent, 'object-use-reservation-rejected', { releaseBy: 'route-failed', clearRoute: true, clearLifecycle: true, releaseSummary: objectUse.reason });
    return { accepted: false, reason: objectUse.reason, proposal, admission, objectUse };
  }
  agent._idleActivity = {
    kind: proposal.objectUse?.activityKind || `scripted-${proposal.category}`,
    phase: 'approach',
    source: proposal.sourceKind || behaviorSourceKind,
    behaviorSourceKind,
    behaviorMode,
    behaviorCategory: proposal.category,
    buildingId: proposal.buildingId || null,
    floor: proposal.floor,
    furnitureIndex: target.furnitureIndex ?? null,
    furnitureType: target.objectType || null,
    objectId: target.objectInstanceId || target.objectId || null,
    actionId: target.actionId || null,
    reservationId: objectUse.reservation?.id || target.reservationId || null,
    activeUseId: objectUse.activeUse?.id || target.activeUseId || null,
    spotId: target.spotId || target.interactionSpotId || null,
    slotId: target.slotId || target.seatId || null,
    approachSpot: proposal.objectUse?.slot?.approachSpot || proposal.destination?.spot || null,
    activationSpot: proposal.objectUse?.slot?.activationSpot || null,
    routeSemantics: proposal.routeSemantics,
    stayMs: proposal.objectUse?.stayMs || proposal.decision?.durationMs || null,
    dockSnapRadius: proposal.objectUse?.dockSnapRadius || null,
    animationId: proposal.objectUse?.animationId || null,
    mode: proposal.objectUse?.mode || null,
    seatSurfaceLift: proposal.objectUse?.seatSurfaceLift ?? null,
  };
  return { accepted: true, reason: admission.reason || 'accepted', proposal, admission, objectUse, snapshot: getAgentIntentSnapshot(agent) };
}

function addElevatorMeshes(group, building, bw, bd) {
  normalizeBuildingFloors(building);
  building._elevatorDoors = [];
  if (!building?.elevator || getBuildingFloorCount(building) < 2) return;
  const e = building.elevator;
  const shaftMat = getMat(0x2f3438);
  const trimMat = getMat(0x8d969e);
  const doorMat = getMat(0x9aa0a6);
  for (let floor = 1; floor <= getBuildingFloorCount(building); floor++) {
    if (!shouldRenderBuildingFloor(building, floor)) continue;
    const y = getRenderedFloorY(building, floor);
    const pad = posVox(e.x, y + 0.08, e.z, e.width, 0.08, e.depth, 0x59636b);
    pad.name = `elevator-pad-f${floor}`;
    group.add(pad);
    const back = posVox(e.x, y + WALL_H * 0.5, e.z - e.depth / 2, e.width, WALL_H, 0.08, 0x2f3438);
    const left = posVox(e.x - e.width / 2, y + WALL_H * 0.5, e.z, 0.08, WALL_H, e.depth, 0x2f3438);
    const right = posVox(e.x + e.width / 2, y + WALL_H * 0.5, e.z, 0.08, WALL_H, e.depth, 0x2f3438);
    back.material = shaftMat; left.material = shaftMat; right.material = shaftMat;
    group.add(back, left, right);

    // Metallic sliding elevator doors. They split left/right when agents approach or exit.
    const doorGroup = new THREE.Group();
    doorGroup.name = `elevator-door-f${floor}`;
    doorGroup.position.set(e.x, y, e.z + e.depth / 2 + 0.045);
    const panelW = e.width * 0.51;
    const panelH = WALL_H * 0.78;
    const panelCenterY = WALL_H * 0.45;
    const leftDoor = posVox(-panelW / 2, panelCenterY, 0, panelW, panelH, 0.07, 0x9aa0a6);
    const rightDoor = posVox(panelW / 2, panelCenterY, 0, panelW, panelH, 0.07, 0x8b9298);
    leftDoor.material = doorMat;
    rightDoor.material = doorMat.clone();
    const header = posVox(0, WALL_H * 0.92, 0.01, e.width * 1.02, WALL_H * 0.16, 0.11, 0x717a82);
    const sill = posVox(0, 0.08, 0.012, e.width * 1.02, 0.12, 0.11, 0x717a82);
    const leftTrim = posVox(-e.width * 0.51, WALL_H * 0.5, 0.012, 0.12, WALL_H, 0.11, 0x717a82);
    const rightTrim = posVox(e.width * 0.51, WALL_H * 0.5, 0.012, 0.12, WALL_H, 0.11, 0x717a82);
    header.material = trimMat;
    sill.material = trimMat;
    leftTrim.material = trimMat;
    rightTrim.material = trimMat;
    doorGroup.add(leftDoor, rightDoor, header, sill, leftTrim, rightTrim);
    group.add(doorGroup);
    building._elevatorDoors.push({ floor, left: leftDoor, right: rightDoor, current: 0, target: 0, panelW, open: e.width * 0.28 });
  }
}

function updateElevatorAnimations(dt) {
  for (const building of buildingsMap.values()) {
    if (!building?._elevatorDoors?.length || !building.elevator) continue;
    const elevatorPoint = getElevatorApiPoint(building);
    if (!elevatorPoint) continue;
    for (const door of building._elevatorDoors) {
      const shouldOpen = agentsList.some(agent => {
        if (!agent || getAgentFloor(agent, building) !== door.floor) return false;
        const activeBuilding = getMovementInteriorBuildingAt(agent.x, agent.y) || null;
        if (activeBuilding?.id !== building.id) return false;
        const near = Math.hypot(agent.x - elevatorPoint.x, agent.y - elevatorPoint.y) <= API_TILE * 1.45;
        return near || agent._elevatorTrip?.buildingId === building.id;
      });
      door.target = shouldOpen ? door.open : 0;
      door.current += (door.target - door.current) * Math.min(1, dt * 8);
      if (door.left) door.left.position.x = -door.panelW / 2 - door.current;
      if (door.right) door.right.position.x = door.panelW / 2 + door.current;
    }
  }
}

// ═══════════════════════════════════════════════════════════════
// BUILDINGS (Full 3D — Crossy Road style)
// ═══════════════════════════════════════════════════════════════
function createBuilding3D(building) {
  normalizeBuildingFloors(building);
  invalidateDynamicInteriorRouting(building?.id || null);
  invalidateDynamicExteriorRouting();
  invalidateGroundIndex(); // PERF: building geometry/position/rotation changed
  const existing = building._group;
  if (existing) buildingGroup.remove(existing);

  const btype = building.type || 'office';
  const isPark = btype === 'park';
  const bw = (building.widthTiles || BUILDING_TYPES[btype]?.w || 25) * T;
  const bd = (building.heightTiles || BUILDING_TYPES[btype]?.h || 17) * T;
  const ext = building.exterior || {};

  // Feature 2: Slightly randomize wall color per building for variety
  let baseWallHex = ext.wallColor || '#78909c';
  if (!ext.wallColor) {
    // Derive a seeded variation from building id
    const seed = (building.id || 'x').split('').reduce((s, c) => s + c.charCodeAt(0), 0);
    const rng = pseudoRandom(seed);
    const baseCol = new THREE.Color(0x78909c);
    baseCol.r = Math.min(1, Math.max(0, baseCol.r + (rng - 0.5) * 0.15));
    baseCol.g = Math.min(1, Math.max(0, baseCol.g + (pseudoRandom(seed + 1) - 0.5) * 0.15));
    baseCol.b = Math.min(1, Math.max(0, baseCol.b + (pseudoRandom(seed + 2) - 0.5) * 0.15));
    baseWallHex = '#' + baseCol.getHexString();
  }
  const wallCol = parseColor(baseWallHex);
  const roofCol = parseColor(ext.roofColor || '#546e7a');
  const darkWall = new THREE.Color(wallCol).multiplyScalar(0.75).getHex();

  const group = new THREE.Group();
  group.userData = { buildingId: building.id };

  if (isPark) {
    building.doorSpec = null;
    building._doorSpec = null;
  }
  if (!isPark) {
    // Floors — all share the same footprint. Upper floors intentionally have no exterior doors.
    const floorColor = btype === 'store' ? 0xdcd0c4 : btype === 'home' ? 0xc8b89a : 0xd0d0d0;
    const floorCount = getBuildingFloorCount(building);
    const activeFloor = getActiveBuildingFloor(building);
    const floorFocusActive = isBuildingFloorFocusActive(building);
    for (let fl = 1; fl <= floorCount; fl++) {
      if (!shouldRenderBuildingFloor(building, fl)) continue;
      const y = getRenderedFloorY(building, fl);
      const floor = posVox(bw / 2, y + 0.12, bd / 2, bw, 0.15, bd, floorColor);
      floor.receiveShadow = true;
      floor.name = `floor-${fl}`;
      tagExteriorFloorPickMesh(floor, building, fl);
      group.add(floor);
      if (floorCount > 1) {
        const label = makeTextSprite(`F${fl}`, Math.min(6, bw));
        label.position.set(bw - 1.4, y + 0.55, 1.2);
        label.scale.set(0.9, 0.25, 1);
        group.add(label);
      }
    }

    const wt = 0.25;
    const doorOpeningW = T * 2.4;
    const doorH = WALL_H - 0.06;
    const doorLintelH = Math.max(0.08, WALL_H - doorH);
    const frontLeftW = (bw - doorOpeningW) / 2;
    const frontRightW = (bw - doorOpeningW) / 2;
    building.doorSpec = normalizeBuildingDoorSpec(building, building.doorSpec || building._doorSpec || {
      localCenterX: bw / 2,
      localThresholdZ: bd + wt / 2 + 0.01,
      localOutsideZ: bd + 0.2,
      localInteriorZ: Math.max(0.45, bd - 1.2),
      localDoorwayZ: Math.max(0.45, bd - Math.max(0.45, wt * 1.2)),
      doorwayReachWorld: Math.min(0.65, Math.max(0.4, doorOpeningW * 0.22)),
      openingWidth: doorOpeningW,
      wallThickness: wt,
    });
    building._doorSpec = building.doorSpec;

    if (!floorFocusActive || activeFloor >= 1) {
    // Front wall (south) — split around a tall door opening
    if (frontLeftW > 0.2) {
      const fwL = posVox(frontLeftW / 2, WALL_H / 2, bd + wt / 2, frontLeftW, WALL_H, wt, wallCol);
      fwL.name = 'wall-front';
      tagExteriorWallMesh(fwL, building, 1);
      group.add(fwL);
    }
    if (frontRightW > 0.2) {
      const fwR = posVox(bw - frontRightW / 2, WALL_H / 2, bd + wt / 2, frontRightW, WALL_H, wt, wallCol);
      fwR.name = 'wall-front';
      tagExteriorWallMesh(fwR, building, 1);
      group.add(fwR);
    }

    // Thin lintel above the doorway so the door reaches almost all the way to the roof
    const doorFrameTop = posVox(bw / 2, doorH + doorLintelH / 2, bd + wt / 2, doorOpeningW, doorLintelH, wt + 0.02, darkWall);
    doorFrameTop.name = 'wall-front';
    tagExteriorWallMesh(doorFrameTop, building, 1);
    group.add(doorFrameTop);
    // Back wall (north)
    const bw2 = posVox(bw / 2, WALL_H / 2, -wt / 2, bw + wt * 2, WALL_H, wt, darkWall);
    bw2.name = 'wall-back';
    tagExteriorWallMesh(bw2, building, 1);
    group.add(bw2);
    // Left wall (west), extend slightly to meet front/back walls flush at the corners
    const sideWallDepth = bd + wt * 2;
    const lw = posVox(-wt / 2, WALL_H / 2, bd / 2, wt, WALL_H, sideWallDepth, darkWall);
    lw.name = 'wall-left';
    tagExteriorWallMesh(lw, building, 1);
    group.add(lw);
    // Right wall (east), extend slightly to meet front/back walls flush at the corners
    const rw = posVox(bw + wt / 2, WALL_H / 2, bd / 2, wt, WALL_H, sideWallDepth, wallCol);
    rw.name = 'wall-right';
    tagExteriorWallMesh(rw, building, 1);
    group.add(rw);

    // Upper-floor exterior shells: same footprint, no exterior doors.
    for (let fl = 2; fl <= floorCount; fl++) {
      if (!shouldRenderBuildingFloor(building, fl)) continue;
      const y = getRenderedFloorY(building, fl);
      const upFront = posVox(bw / 2, y + WALL_H / 2, bd + wt / 2, bw + wt * 2, WALL_H, wt, wallCol);
      const upBack = posVox(bw / 2, y + WALL_H / 2, -wt / 2, bw + wt * 2, WALL_H, wt, darkWall);
      const upLeft = posVox(-wt / 2, y + WALL_H / 2, bd / 2, wt, WALL_H, sideWallDepth, darkWall);
      const upRight = posVox(bw + wt / 2, y + WALL_H / 2, bd / 2, wt, WALL_H, sideWallDepth, wallCol);
      upFront.name = `wall-front-f${fl}`; upBack.name = `wall-back-f${fl}`; upLeft.name = `wall-left-f${fl}`; upRight.name = `wall-right-f${fl}`;
      tagExteriorWallMesh(upFront, building, fl);
      tagExteriorWallMesh(upBack, building, fl);
      tagExteriorWallMesh(upLeft, building, fl);
      tagExteriorWallMesh(upRight, building, fl);
      group.add(upFront, upBack, upLeft, upRight);
    }

    // Roof — style depends on building type
    const roofMat = new THREE.MeshLambertMaterial({
      color: roofCol, flatShading: true, transparent: true, opacity: 0.35
    });

    let roof;
    if (btype === 'home') {
      // Pitched / gabled roof using a triangular prism BufferGeometry
      roof = makePitchedRoof(bw, bd, wt, roofCol);
      roof.name = 'roof';
      group.add(roof);
    } else {
      // Office and default: flat box roof
      roof = new THREE.Mesh(_boxGeo, roofMat);
      roof.scale.set(bw + wt * 2, 0.15, bd + wt * 2);
      roof.position.set(bw / 2, getRenderedFloorY(building, floorFocusActive ? activeFloor : floorCount) + WALL_H + 0.075, bd / 2);
      roof.receiveShadow = true;
      roof.name = 'roof';
      group.add(roof);
    }
    building._roof = roof;
    if (floorFocusActive && roof) roof.visible = false;

    // Store: signboard on front face
    if (btype === 'store') {
      // Signboard
      const signW = Math.min(bw * 0.7, 8);
      const signH = 0.8;
      const signMat = new THREE.MeshLambertMaterial({ color: parseColor(ext.wallColor || '#ff8f00'), flatShading: true });
      const sign = new THREE.Mesh(_boxGeo, signMat);
      sign.scale.set(signW, signH, 0.12);
      sign.position.set(bw / 2, WALL_H + signH / 2, bd + wt + 0.1);
      group.add(sign);
      // Sign text label
      const signLabel = makeTextSprite(building.name || 'Store', signW);
      signLabel.position.set(bw / 2, WALL_H + signH / 2 + 0.05, bd + wt + 0.22);
      group.add(signLabel);
    }

    // Door system — type based on building type
    // Stores/offices get glass sliding doors, homes get swivel wooden doors
    const doorType = (btype === 'store') ? 'sliding' : 'swivel';
    const dw = doorOpeningW / 2; // each panel = half the opening
    const dh = doorH;
    const doorZ = bd + wt / 2 + 0.01;
    
    if (doorType === 'sliding') {
      // ── GLASS SLIDING DOORS ──
      // Two glass panels that slide sideways into the wall
      const glassMat = getMat(0x90caf9, { transparent: true, opacity: 0.45 });
      const frameMat = getMat(0x78909c);
      
      // Left sliding panel (slides left to open)
      const leftSlide = new THREE.Group();
      leftSlide.name = 'doorSlideLeft';
      leftSlide.position.set(bw / 2 - dw / 2, 0, doorZ);
      // Glass pane
      const leftGlass = new THREE.Mesh(_boxGeo, glassMat);
      leftGlass.scale.set(dw - 0.04, dh, 0.06);
      leftGlass.position.set(0, dh / 2, 0);
      leftSlide.add(leftGlass);
      // Frame top
      leftSlide.add(posVox(0, dh, 0, dw, 0.06, 0.08, 0x78909c));
      // Frame bottom
      leftSlide.add(posVox(0, 0.03, 0, dw, 0.06, 0.08, 0x78909c));
      // Handle
      leftSlide.add(posVox(dw * 0.35, dh * 0.5, 0.05, 0.04, 0.3, 0.04, 0xb0bec5));
      group.add(leftSlide);
      
      // Right sliding panel (slides right to open)
      const rightSlide = new THREE.Group();
      rightSlide.name = 'doorSlideRight';
      rightSlide.position.set(bw / 2 + dw / 2, 0, doorZ);
      const rightGlass = new THREE.Mesh(_boxGeo, glassMat);
      rightGlass.scale.set(dw - 0.04, dh, 0.06);
      rightGlass.position.set(0, dh / 2, 0);
      rightSlide.add(rightGlass);
      rightSlide.add(posVox(0, dh, 0, dw, 0.06, 0.08, 0x78909c));
      rightSlide.add(posVox(0, 0.03, 0, dw, 0.06, 0.08, 0x78909c));
      rightSlide.add(posVox(-dw * 0.35, dh * 0.5, 0.05, 0.04, 0.3, 0.04, 0xb0bec5));
      group.add(rightSlide);
      
      // Track rail on ground
      group.add(posVox(bw / 2, 0.02, doorZ, doorOpeningW + 0.2, 0.03, 0.15, 0x78909c));
      
      building._doorType = 'sliding';
      
    } else {
      // ── SWIVEL WOODEN DOORS ──
      // Two panels with hinges on outer edges
      const leftDoorPivot = new THREE.Group();
      leftDoorPivot.name = 'doorPivotLeft';
      leftDoorPivot.position.set(bw / 2 - dw, 0, doorZ);
      const leftDoor = posVox(dw / 2, dh / 2, 0, dw, dh, wt + 0.02, 0x6d4c41);
      leftDoor.name = 'doorMeshL';
      leftDoorPivot.add(leftDoor);
      // Knob
      const knobL = new THREE.Mesh(_sphereGeo, getMat(0xffd600));
      knobL.scale.setScalar(0.06);
      knobL.position.set(dw * 0.85, dh * 0.5, wt / 2 + 0.04);
      leftDoorPivot.add(knobL);
      group.add(leftDoorPivot);
      
      const rightDoorPivot = new THREE.Group();
      rightDoorPivot.name = 'doorPivotRight';
      rightDoorPivot.position.set(bw / 2 + dw, 0, doorZ);
      const rightDoor = posVox(-dw / 2, dh / 2, 0, dw, dh, wt + 0.02, 0x6d4c41);
      rightDoor.name = 'doorMeshR';
      rightDoorPivot.add(rightDoor);
      const knobR = new THREE.Mesh(_sphereGeo, getMat(0xffd600));
      knobR.scale.setScalar(0.06);
      knobR.position.set(-dw * 0.85, dh * 0.5, wt / 2 + 0.04);
      rightDoorPivot.add(knobR);
      group.add(rightDoorPivot);
      
      building._doorType = 'swivel';
    }

    // Windows on front, keep them clearly away from the door opening
    const winCount = Math.max(2, Math.floor(bw / (T * 2)));
    const winSp = bw / (winCount + 1);
    const frontWindowW = T * 0.5;
    const frontWindowH = T * 0.4;
    const doorClearHalf = doorOpeningW / 2 + frontWindowW * 0.75;
    for (let i = 1; i <= winCount; i++) {
      const wx = i * winSp;
      if (Math.abs(wx - bw / 2) <= doorClearHalf) continue;
      const wm = posVox(wx, WALL_H * 0.65, bd + wt + 0.02, frontWindowW, frontWindowH, 0.05, 0x81d4fa);
      wm.name = 'window';
      group.add(wm);
      registerWindowMesh(wm);
    }
    // Windows on sides
    const sideWinCount = Math.max(1, Math.floor(bd / (T * 3)));
    for (let i = 1; i <= sideWinCount; i++) {
      const wz = i * (bd / (sideWinCount + 1));
      const wl = posVox(-wt - 0.02, WALL_H * 0.65, wz, 0.05, T * 0.4, T * 0.5, 0x81d4fa);
      const wr = posVox(bw + wt + 0.02, WALL_H * 0.65, wz, 0.05, T * 0.4, T * 0.5, 0x81d4fa);
      wl.name = 'window'; wr.name = 'window';
      group.add(wl); group.add(wr);
      registerWindowMesh(wl); registerWindowMesh(wr);
    }
    }


    // Roof always belongs to the current top floor. In focused floor view it stays hidden
    // so the active floor remains editable/visible, including after the top floor changes.
    if (!building._roof || building._roof.parent !== group) {
      const roofMat2 = new THREE.MeshLambertMaterial({ color: roofCol, flatShading: true, transparent: true, opacity: 0.35 });
      if (btype === 'home') {
        building._roof = makePitchedRoof(bw, bd, wt, roofCol);
        building._roof.name = 'roof';
      } else {
        building._roof = new THREE.Mesh(_boxGeo, roofMat2);
        building._roof.scale.set(bw + wt * 2, 0.15, bd + wt * 2);
        building._roof.receiveShadow = true;
        building._roof.name = 'roof';
      }
      group.add(building._roof);
    }
    if (building._roof) {
      const roofFloor = floorCount;
      if (btype === 'home') building._roof.position.y = getRenderedFloorY(building, roofFloor);
      else building._roof.position.set(bw / 2, getRenderedFloorY(building, roofFloor) + WALL_H + 0.075, bd / 2);
      building._roof.visible = !floorFocusActive;
    }

    // Elevator shaft/doors (shared location across all floors)
    addElevatorMeshes(group, building, bw, bd);

	    // Interior furniture
	    addBuildingFurniture(group, building, bw, bd);
	    addObjectActionPointDebugOverlays(group, building);

	  } else {
	    // Park/outside space — open resizable lawn + sidewalk apron. Trees and
	    // placeable objects render through outdoorArea.nodes, so fountains/benches/
	    // paths are user-placeable objects instead of stretched fixed park content.
	    addParkContent(group, bw, bd, building);
	    addObjectActionPointDebugOverlays(group, building);
	  }

  // Ground shadow/foundation under building (subtle dark plane)
  if (!isPark) {
    const shadowMat = new THREE.MeshLambertMaterial({
      color: 0x333333, transparent: true, opacity: 0.15, flatShading: true,
    });
    const shadow = new THREE.Mesh(_boxGeo, shadowMat);
    shadow.scale.set(bw + 2, 0.02, bd + 2);
    shadow.position.set(bw / 2, 0.01, bd / 2);
    shadow.receiveShadow = false;
    group.add(shadow);

    // Sidewalk border around building
    const swCol = 0xbbbbbb;
    const swW = 1.2;
    // South sidewalk (in front of door)
    group.add(posVox(bw / 2, 0.11, bd + swW / 2, bw + swW * 2, 0.05, swW, swCol));
    // West sidewalk
    group.add(posVox(-swW / 2, 0.11, bd / 2, swW, 0.05, bd, swCol));
    // East sidewalk
    group.add(posVox(bw + swW / 2, 0.11, bd / 2, swW, 0.05, bd, swCol));
    // North sidewalk
    group.add(posVox(bw / 2, 0.11, -swW / 2, bw + swW * 2, 0.05, swW, swCol));
  }

  // Name label
  const label = makeTextSprite(building.name || 'Building', bw);
  const buildingTopY = isPark ? 2.5 : (isBuildingFloorFocusActive(building) ? WALL_H + 1.5 : ((getBuildingFloorCount(building) - 1) * FLOOR_HEIGHT + WALL_H + 1.5));
  label.position.set(bw / 2, buildingTopY, bd / 2);
  group.add(label);

  // Feature 2: Outdoor benches — placed outside the front door (with physics colliders)
  if (!isPark) {
    const benchSeed = (building.id || '').split('').reduce((s, c) => s + c.charCodeAt(0), 1);
    const benchCount = 1 + Math.floor(pseudoRandom(benchSeed) * 2); // 1 or 2 benches
    for (let bi = 0; bi < benchCount; bi++) {
      const bx = bw * (0.3 + bi * 0.4);
      const bz = bd + 1.0 + bi * 0.2;
      const outdoor = makeBench(bx, bz);
      group.add(outdoor);
      // Physics: add collider for outdoor bench
      if (isPhysicsReady()) {
        const benchWorld = getBuildingWorldPoint(building, bx, bz);
        addDecorationCollider(`${building.id}_outdoor_bench_${bi}`, 'bench', benchWorld.x, benchWorld.z);
      }
    }
  }

  // Feature 4: Agent count badge above building
  const badgeSprite = makeBadgeSprite(0);
  badgeSprite.position.set(bw / 2, isPark ? 3.5 : buildingTopY + 1.0, bd / 2);
  badgeSprite.name = 'agentBadge';
  group.add(badgeSprite);
  building._badgeSprite = badgeSprite;

  const elevY = building._elevationY || 0;
  applyBuildingGroupTransform(group, building, building.worldX || 0, building.worldY || 0, elevY);
  buildingGroup.add(group);
  building._group = group;

  if (!isPark) {
    rebuildInteriorWalls(building);
  }

  if (building._signGroup) {
    buildingGroup.remove(building._signGroup);
    building._signGroup = null;
  }

  // Re-apply current view mode to newly created building
  if (typeof _buildingViewMode !== 'undefined') {
    applyBuildingViewMode(building, _buildingViewMode);
  }

  // Physics: add/update building collider (skip parks — they are open spaces accessible from any direction)
  if (isPhysicsReady()) {
    if (isPark) {
      // Parks are open outdoor spaces — no wall colliders.
      // Remove any existing wall collider for this park.
      removeBody(building.id);
      // Add colliders for park furniture (fountain, benches) so agents don't walk through them
      addParkFurnitureColliders(building);
    } else {
      addBuildingCollider(
        building.id,
        building.worldX || 0,
        building.worldY || 0,
        building.widthTiles || 25,
        building.heightTiles || 17,
        WALL_H,
        building._rotation || 0
      );
      // Add furniture colliders for the currently active floor inside the building
      addBuildingFurnitureColliders(building);
    }
  }
}

// ─── PITCHED ROOF for homes (triangular prism) ───
function makePitchedRoof(bw, bd, wt, roofCol) {
  const W = bw + wt * 2;
  const D = bd + wt * 2;
  const H = 1.4; // ridge height
  const y0 = WALL_H; // base of roof

  // Build a triangular prism: 2 triangular end faces + 2 slanted quad faces + bottom (open)
  // Vertices:
  // Bottom rect: 4 corners at y0
  // Ridge: 2 points at top center (y0 + H)
  const hW = W / 2;
  const hD = D / 2;

  // 0: -hW, y0,  hD  (front-left bottom)
  // 1:  hW, y0,  hD  (front-right bottom)
  // 2:  hW, y0, -hD  (back-right bottom)
  // 3: -hW, y0, -hD  (back-left bottom)
  // 4:   0, y0+H, hD (front ridge)
  // 5:   0, y0+H,-hD (back ridge)

  const verts = new Float32Array([
    -hW, y0,  hD,   // 0
     hW, y0,  hD,   // 1
     hW, y0, -hD,   // 2
    -hW, y0, -hD,   // 3
      0, y0+H, hD,  // 4
      0, y0+H,-hD,  // 5
  ]);

  // Faces (CCW from outside):
  // Left slope:  0,4,5, 0,5,3
  // Right slope: 1,2,5, 1,5,4
  // Front gable: 0,1,4
  // Back gable:  3,5,2
  const idx = new Uint16Array([
    0,4,5, 0,5,3,   // left slope
    1,5,2, 1,4,5,   // right slope (flip winding)
    0,1,4,          // front gable
    3,5,2,          // back gable
  ]);

  const geo = new THREE.BufferGeometry();
  geo.setAttribute('position', new THREE.BufferAttribute(verts, 3));
  geo.setIndex(new THREE.BufferAttribute(idx, 1));
  geo.computeVertexNormals();

  const mat = new THREE.MeshLambertMaterial({
    color: roofCol, flatShading: true, transparent: true, opacity: 0.45, side: THREE.DoubleSide
  });
  const mesh = new THREE.Mesh(geo, mat);
  mesh.position.set(bw / 2, 0, bd / 2); // offset to building center
  mesh.castShadow = true;
  return mesh;
}

function tagFurniture(item, type = null, meta = null) {
  mergeFurnitureItemVoxels(item);
  item.userData.furniture = true;
  if (type) item.userData.furnitureType = type;
  if (meta && typeof meta === 'object') Object.assign(item.userData, meta);
  registerInteractiveFurnitureFeedbackMesh(item);
  item.traverse(obj => {
    if (obj.userData?.pingPongRuntimeVisual) {
      obj.visible = false;
    }
    if (obj.isMesh) {
      obj.userData.furniture = true;
      if (type) obj.userData.furnitureType = type;
      if (meta && typeof meta === 'object') Object.assign(obj.userData, meta);
    }
  });
  return item;
}

function getObjectMinY(object) {
  if (!object) return 0;
  object.updateMatrixWorld(true);
  let minY = Infinity;
  object.traverse(child => {
    if (!child.isMesh || !child.geometry) return;
    if (!child.geometry.boundingBox) child.geometry.computeBoundingBox();
    const bounds = child.geometry.boundingBox?.clone();
    if (!bounds) return;
    bounds.applyMatrix4(child.matrixWorld);
    minY = Math.min(minY, bounds.min.y);
  });
  return Number.isFinite(minY) ? minY : object.position.y || 0;
}

function alignObjectBottomToY(object, targetY) {
  if (!object || !Number.isFinite(Number(targetY))) return object;
  const minY = getObjectMinY(object);
  object.position.y += Number(targetY) - minY;
  object.updateMatrixWorld(true);
  return object;
}

