  g.add(posVox(-0.13 * s, 0.96 * s, 0.24 * s, 0.105 * s, 0.07 * s, 0.04 * s, 0x60a5fa)); // cold button
  g.add(posVox(0.13 * s, 0.96 * s, 0.24 * s, 0.105 * s, 0.07 * s, 0.04 * s, 0xef4444)); // hot button
  g.add(posVox(0, 0.79 * s, 0.245 * s, 0.34 * s, 0.07 * s, 0.055 * s, 0x94a3b8)); // spout rail
  g.add(posVox(-0.08 * s, 0.70 * s, 0.27 * s, 0.04 * s, 0.14 * s, 0.04 * s, darkTrim)); // left spout
  g.add(posVox(0.08 * s, 0.70 * s, 0.27 * s, 0.04 * s, 0.14 * s, 0.04 * s, darkTrim)); // right spout
