  bottle.material = bottle.material.clone();
  bottle.material.transparent = true;
  bottle.material.opacity = 0.70;
  g.add(bottle);
  const bottleTop = cyl(0.25 * s, 0.10 * s, water);
  bottleTop.position.set(0, 1.79 * s, -0.02 * s);
  bottleTop.material = bottle.material;
  bottleTop.scale.z = 0.46 * s;
