  g.add(posVox(-0.16 * s, 1.43 * s, 0.28 * s, 0.11 * s, 0.38 * s, 0.035 * s, 0xbfdbfe)); // water highlight
  g.add(posVox(-0.27 * s, 0.11 * s, -0.15 * s, 0.09 * s, 0.11 * s, 0.09 * s, 0x111827)); // feet
  g.add(posVox(0.27 * s, 0.11 * s, -0.15 * s, 0.09 * s, 0.11 * s, 0.09 * s, 0x111827));
  g.position.set(x, 0, z);
