  const inset = 0xb7793b;
  const trim = 0x1f2937;
  const glass = 0x93c5fd;
  const handle = 0xfacc15;
  const open = item?.doorState?.open === true || item?.activeUse?.mode === 'open' || item?.activeUse?.mode === 'passing-through';
  const swing = open ? -0.72 : 0;

  // One stationary persistent Interior Door asset only. Frame, slab, inset
  // panels, hinge barrels, push plate, state strip, and handle are integrated
  // visual details on this same room-door object; no wall, window, room divider,
  // key, sign, or second asset is bundled here.
  g.add(posVox(0, 1.18 * s, -0.065 * s, 1.22 * s, 2.36 * s, 0.10 * s, frame));
  g.add(posVox(0, 2.40 * s, -0.06 * s, 1.34 * s, 0.16 * s, 0.16 * s, trim));
