  g.add(posVox(0, 0.06 * s, -0.04 * s, 1.30 * s, 0.12 * s, 0.18 * s, 0x4b5563));

  const slab = new THREE.Group();
  slab.name = open ? 'interior-door-slab-open' : 'interior-door-slab-closed';
  slab.rotation.y = swing;
  slab.add(posVox(0, 1.18 * s, 0, 1.00 * s, 2.16 * s, 0.09 * s, panel));
  slab.add(posVox(0, 1.74 * s, 0.052 * s, 0.68 * s, 0.64 * s, 0.026 * s, inset));
