  slab.add(posVox(0.36 * s, 1.20 * s, 0.08 * s, 0.055 * s, 0.10 * s, 0.055 * s, handle));
  slab.add(posVox(-0.42 * s, 1.20 * s, 0.08 * s, 0.16 * s, 0.34 * s, 0.026 * s, 0xd6d3d1));
  g.add(slab);
  [-0.72, 0, 0.72].forEach((hy) => g.add(posVox(-0.58 * s, (1.18 + hy) * s, 0.015 * s, 0.10 * s, 0.18 * s, 0.07 * s, 0x111827)));
  g.add(posVox(0.52 * s, 2.22 * s, 0.03 * s, 0.08 * s, 0.16 * s, 0.08 * s, open ? 0x22c55e : 0xef4444));
