function makeBookshelf(x, z, s) {
  const g = new THREE.Group();
  const woodDark = 0x4e342e;
  const woodMid = 0x6d4c41;
  const woodLight = 0xa9825a;
  const variant = Math.floor(pseudoRandom(x * 17 + z * 31) * 3);

  // One stationary persistent asset: Bookshelf Variants. The varied bays,
  // books, ladder rail, labels, and reading notes are visual detail attached
  // to this single shelf object; they are not separate bundled assets.
  g.add(posVox(0, 0.06 * s, 0.02 * s, 1.42 * s, 0.12 * s, 0.44 * s, woodDark));
  // Taller upper bay: the top shelf/cap is raised so tall randomized books stay
  // inside the bookshelf instead of poking through the top.
  g.add(posVox(0, 1.02 * s, -0.02 * s, 1.34 * s, 1.92 * s, 0.34 * s, woodMid));
  g.add(posVox(0, 2.04 * s, -0.02 * s, 1.46 * s, 0.16 * s, 0.42 * s, woodDark));
  g.add(posVox(-0.71 * s, 1.02 * s, -0.02 * s, 0.11 * s, 1.96 * s, 0.40 * s, woodDark));
  g.add(posVox(0.71 * s, 1.02 * s, -0.02 * s, 0.11 * s, 1.96 * s, 0.40 * s, woodDark));
  g.add(posVox(0, 1.02 * s, -0.21 * s, 1.24 * s, 1.74 * s, 0.055 * s, 0x3e2723));

  const dividers = variant === 1 ? [-0.26, 0.32] : (variant === 2 ? [0] : [-0.44, 0.44]);
  dividers.forEach((dx) => g.add(posVox(dx * s, 1.00 * s, 0.01 * s, 0.07 * s, 1.72 * s, 0.36 * s, woodDark)));
  const shelfYs = variant === 2 ? [0.48, 0.82, 1.18, 1.52] : [0.42, 0.78, 1.14, 1.50];
  shelfYs.forEach((sy) => {
    g.add(posVox(0, sy * s, 0.03 * s, 1.30 * s, 0.075 * s, 0.39 * s, woodDark));
    g.add(posVox(0, (sy + 0.035) * s, 0.22 * s, 1.20 * s, 0.025 * s, 0.04 * s, woodLight));
  });

  const bookColors = [0xb91c1c, 0x1d4ed8, 0x15803d, 0xf59e0b, 0x7c3aed, 0x0891b2, 0xf8fafc, 0xbe123c];
  let count = 0;
  shelfYs.forEach((sy, row) => {
    for (let i = 0; i < 7; i++) {
      const skip = (variant === 1 && row === 2 && i > 4) || (variant === 2 && row === 0 && i < 2);
      if (skip) continue;
      const bw = (0.07 + pseudoRandom(x + z + row * 19 + i * 7) * 0.035) * s;
      const bh = (0.18 + pseudoRandom(x * 3 + z + row * 11 + i * 5) * 0.16) * s;
      const bx = (-0.53 + i * 0.17 + (variant === 2 && row % 2 ? 0.04 : 0)) * s;
      const by = sy * s + 0.065 * s + bh / 2;
      const color = bookColors[(count + variant * 3) % bookColors.length];
      const book = posVox(bx, by, 0.17 * s, bw, bh, 0.16 * s, color);
      book.rotation.z = (pseudoRandom(i * 13 + row * 23 + variant) - 0.5) * 0.05;
      g.add(book);
      g.add(posVox(bx, by, 0.258 * s, Math.max(0.012 * s, bw * 0.35), bh * 0.78, 0.012 * s, 0xfef3c7));
      count++;
    }
  });

  // Variant-specific details stay within the shelf footprint and communicate
  // library/research use at agent scale without adding another placeable item.
  if (variant === 0) {
    g.add(posVox(-0.35 * s, 1.66 * s, 0.22 * s, 0.22 * s, 0.12 * s, 0.035 * s, 0xffd54f));
    g.add(posVox(0.28 * s, 0.62 * s, 0.235 * s, 0.34 * s, 0.035 * s, 0.16 * s, 0xfafafa));
  } else if (variant === 1) {
    g.add(posVox(0.60 * s, 0.88 * s, 0.28 * s, 0.055 * s, 1.30 * s, 0.055 * s, 0x8d6e63));
    g.add(posVox(0.50 * s, 0.52 * s, 0.29 * s, 0.24 * s, 0.045 * s, 0.045 * s, 0xa1887f));
    g.add(posVox(0.54 * s, 0.94 * s, 0.29 * s, 0.24 * s, 0.045 * s, 0.045 * s, 0xa1887f));
    g.add(posVox(0.58 * s, 1.36 * s, 0.29 * s, 0.24 * s, 0.045 * s, 0.045 * s, 0xa1887f));
  } else {
    g.add(posVox(-0.42 * s, 1.62 * s, 0.23 * s, 0.28 * s, 0.18 * s, 0.05 * s, 0x0f766e));
    g.add(posVox(0.42 * s, 0.58 * s, 0.235 * s, 0.30 * s, 0.11 * s, 0.14 * s, 0x78350f));
    g.add(posVox(0.42 * s, 0.68 * s, 0.245 * s, 0.22 * s, 0.035 * s, 0.12 * s, 0xfef3c7));
  }

  for (const [fx, fz] of [[-0.52, -0.18], [0.52, -0.18], [-0.52, 0.18], [0.52, 0.18]]) {
    g.add(posVox(fx * s, 0.04 * s, fz * s, 0.12 * s, 0.08 * s, 0.12 * s, 0x2b1b14));
  }
  g.position.set(x, 0, z);
  return g;
}

