function makeFountain3D(x, z, s = T) {
  const g = new THREE.Group();
  const stoneDark = 0x78909c;
  const stone = 0xb0bec5;
  const stoneLight = 0xd5e3e8;
  const waterBlue = 0x42a5f5;
  const sprayBlue = 0xb3e5fc;

  // One stationary persistent Fountain asset only. Basin, water surface,
  // center pedestal, upper bowl, spout, spray arcs, wet highlights, and plaza
  // edge tiles are integrated detail on this single outdoor focal-point record;
  // it does not bundle benches, plants, statues, or any other placeable asset.
  g.add(cyl(1.25 * s, 0.24 * s, stoneDark));
  g.children[g.children.length - 1].position.set(0, 0.12 * s, 0);
  g.add(cyl(1.12 * s, 0.38 * s, stone));
  g.children[g.children.length - 1].position.set(0, 0.31 * s, 0);
  g.add(cyl(1.00 * s, 0.08 * s, stoneLight));
  g.children[g.children.length - 1].position.set(0, 0.54 * s, 0);

  const water = cyl(0.92 * s, 0.08 * s, waterBlue);
  water.position.set(0, 0.59 * s, 0);
  water.material = getMat(waterBlue, { transparent: true, opacity: 0.58 });
  g.add(water);

  g.add(cyl(0.22 * s, 0.92 * s, stoneDark));
  g.children[g.children.length - 1].position.set(0, 0.98 * s, 0);
  g.add(cyl(0.50 * s, 0.14 * s, stone));
  g.children[g.children.length - 1].position.set(0, 1.48 * s, 0);
  const topWater = cyl(0.42 * s, 0.045 * s, waterBlue);
  topWater.position.set(0, 1.58 * s, 0);
  topWater.material = getMat(waterBlue, { transparent: true, opacity: 0.50 });
  g.add(topWater);
  const spout = sphere(0.10 * s, stoneLight);
  spout.position.set(0, 1.75 * s, 0);
  g.add(spout);

  [[0, 0.22], [Math.PI / 2, 0.18], [Math.PI, 0.22], [Math.PI * 1.5, 0.18]].forEach(([angle, lift], i) => {
    const bead = sphere(0.045 * s, sprayBlue);
    bead.material = getMat(sprayBlue, { transparent: true, opacity: 0.72 });
    bead.position.set(Math.cos(angle) * 0.42 * s, (1.46 + lift) * s, Math.sin(angle) * 0.42 * s);
    g.add(bead);
    const stream = posVox(Math.cos(angle) * 0.58 * s, 1.26 * s, Math.sin(angle) * 0.58 * s, 0.055 * s, 0.34 * s, 0.055 * s, sprayBlue);
    stream.material = getMat(sprayBlue, { transparent: true, opacity: 0.46 });
    stream.rotation.z = Math.sin(angle) * 0.18;
    stream.rotation.x = Math.cos(angle) * 0.18;
    g.add(stream);
  });

  [[-0.72, -0.72], [0.72, -0.72], [-0.72, 0.72], [0.72, 0.72]].forEach(([lx, lz]) => {
    g.add(posVox(lx * s, 0.045 * s, lz * s, 0.28 * s, 0.035 * s, 0.12 * s, stoneLight));
  });
  g.position.set(x, 0, z);
  return g;
}

