  g.add(posVox(0, 0.865 * s, 0, 0.035 * s, 0.018 * s, 1.02 * s, 0x7a4528));

  // Runner / centerpiece.
  g.add(posVox(0, 0.89 * s, 0, 0.28 * s, 0.025 * s, 0.96 * s, 0xf5efe4));
