function makeFloorLamp(x, z, s) {
  const g = new THREE.Group();
  const pole = cyl(0.025 * s, 2 * s, 0x666666);
  pole.position.set(0, 1 * s, 0);
  g.add(pole);
  const shadeMat = new THREE.MeshLambertMaterial({ color: 0xffd600, emissive: 0xfff5e6, emissiveIntensity: 0.5, flatShading: true });
  const shade = new THREE.Mesh(_coneGeo, shadeMat);
  shade.scale.set(0.4 * s, 0.2 * s, 0.4 * s);
  shade.position.set(0, 2.1 * s, 0);
  shade.rotation.x = Math.PI;
  shade.castShadow = true;
  g.add(shade);
  g.position.set(x, 0, z);
  return g;
}

