// AGENTS — Character creation delegated to agent-characters.js module
// ═══════════════════════════════════════════════════════════════
function createAgent3D(agent) {
  if (agent._group3d) {
    agentGroup.remove(agent._group3d);
    agent._group3d = null;
  }
  // Generate appearance using the new character module
  if (!agent._appearance) {
    agent._appearance = getAgentAppearance(agent.id || agent.name, agent.gender);
  }
  const a = agent._appearance;

  // Create the 3D character using the new character module
  const g = createAgentCharacter(agent);
  
  // Position in world
  const scale = T / API_TILE;
  g.position.set((agent.x || 0) * scale, 0, (agent.y || 0) * scale);
  if (agent._deskFacingAngle != null) g.rotation.y = agent._deskFacingAngle;
  agentGroup.add(g);
  agent._group3d = g;
  agent._tick = Math.floor(Math.random() * 1000);
  agent._wanderTimer = Math.random() * 3000;
  agent._wanderTarget = null;
  agent._currentBuilding = null;
  agent._stayTimer = 0;
  agent._homeX = agent.homeX || agent.x || 0;
  agent._homeY = agent.homeY || agent.y || 0;
  agent._breakSeed = Math.floor(Math.random() * 999);
  agent._onBreak = false;

  // Physics: add agent collider
  if (isPhysicsReady()) {
    addAgentCollider('agent_' + agent.id, (agent.x || 0) * scale, (agent.y || 0) * scale);
  }
}

