function setDragDropAgentPickerValue(furnitureType, agentId) {
  if (!agentId) return;
  const directIds = {
    armchair: 'armchairAgentSelect',
    barStool: 'barStoolAgentSelect',
    arcadeMachine: 'arcadeMachineAgentSelect',
  };
  const direct = directIds[furnitureType] ? document.getElementById(directIds[furnitureType]) : null;
  if (direct) direct.value = agentId;
  if (furnitureType === 'barberChair') {
    const picker = document.querySelector('[data-barber-chair-agent-picker="true"]');
    if (picker) picker.value = agentId;
  }
}

function startDraggedAgentStandingMachineUse(drop, agent) {
  const machine = drop?.furniture || null;
  const building = drop?.building || null;
  const config = getStandingUseMachineConfig(machine?.type);
  if (!agent || !building || !machine || !config) return { triggered: false, reason: 'not-standing-machine' };
  const spot = getFurnitureActionSpotAtDebugPoint(building, machine, config.slotId) || drop.spot || getFurnitureActionSpot(building, machine);
  if (!spot) return { triggered: false, reason: 'missing-standing-machine-spot' };
  const standingUse = reserveStandingUseMachineForAgent(machine, building, drop.index, agent, config, spot);
  const isWater = isWaterCoolerFurnitureType(machine.type);
  const isMicrowave = machine.type === 'microwave';
  const spawnedLabel = isWater ? 'Water Cup' : (machine.type === 'vending' ? 'Temporary Snack / Drink' : (machine.type === 'fridge' ? 'Temporary Snack / Food' : (isMicrowave ? 'Microwave Food' : 'Coffee Drink')));
  const spawnedItem = isMicrowave
    ? { label: 'Microwave Food', catalogId: 'temporaryFood', temporary: true, carryable: true, attachPoint: 'right-hand', itemPool: MICROWAVE_FOOD_ITEM_POOL.map(item => item.label), foodItems: MICROWAVE_FOOD_ITEM_POOL.map(item => ({ id: item.id, label: item.label, visualKind: item.visualKind })), validDropOff: MICROWAVE_FOOD_VALID_DROP_OFFS }
    : { label: spawnedLabel, catalogId: 'temporaryFood', temporary: true, carryable: true, attachPoint: 'right-hand', visualKind: isWater ? 'water' : (machine.type === 'countertopCoffeeMachine' ? 'coffee' : null), drinkKind: isWater ? 'water' : (machine.type === 'countertopCoffeeMachine' ? 'coffee' : null), validDropOff: ['desk', 'diningTable', 'smallCafeTable', 'outdoorCafeTable', 'picnicTable', 'patioTable', 'counter'] };
  agent._manualPlacementPreview = false;
  agent._manualPlacementLockUntil = performance.now() + Math.max(AGENT_MANUAL_PLACE_HOLD_MS, config.useDurationMs);
  const routeTarget = makeStandingMachineRouteTarget(building, machine, drop.index, spot, config, {
    reservationId: standingUse.reservation?.id || machine.reservation?.id || null,
  });
  setAgentTargetForExplicitObjectAction(agent, routeTarget, building, spot.floor, {
    owner: 'manual',
    priorityName: 'manual',
    phase: 'approach',
    buildingId: drop.buildingId,
    furnitureIndex: drop.index,
    furniture: machine,
    objectType: machine.type,
    actionId: config.actionId,
    spotId: spot.spotId,
    slotId: config.slotId,
    reservationId: routeTarget.reservationId,
    release: { policy: 'on-object-complete', releaseObjectReservation: true, releaseActiveUse: true, allowedBy: AGENT_INTENT_RELEASE_ALLOWED_BY['explicit-object'] },
    sourceFamily: 'manual-drag-drop',
    sourceFunction: 'startDraggedAgentStandingMachineUse',
    debugLabel: `manual-drop:${config.actionId}`,
    sourceSummary: 'manual agent drop directly activates exact standing machine use spot',
  });
  agent._idleActivity = {
    kind: config.kind,
    phase: 'approach',
    buildingId: drop.buildingId,
    furnitureIndex: drop.index,
    stayMs: config.useDurationMs,
    faceAngle: spot.faceAngle,
    dockTarget: { x: spot.apiX, y: spot.apiZ },
    dockSnapRadius: 7,
    furnitureType: machine.type,
    spotId: spot.spotId,
    activationSpotId: config.slotId,
    approachSpotId: config.slotId,
    activeUseSlotId: standingUse.slotId,
    reservationId: standingUse.reservation?.id || machine.reservation?.id || null,
    capacityKey: standingUse.capacityKey,
    mode: config.mode,
    action: config.actionId,
    actionId: config.actionId,
    animationId: config.animationId,
    standingUseActivated: false,
    source: 'manual-drag-drop-machine-use',
    behaviorSourceKind: 'user',
    behaviorMode: 'user-directed',
    routeApproachTarget: { x: spot.apiX, y: spot.apiZ, floor: spot.floor, spotId: spot.spotId, faceAngle: spot.faceAngle },
    lifecycle: { stationary: true, carryable: false, temporary: false, spawnsTemporary: true, standingUse: true, releaseOnCompletion: true },
    spawnedItem,
  };
  agent._stayTimer = 0;
  agent._wanderTimer = 150;
  agent._isRunning = false;
  if (Number.isFinite(Number(spot.faceAngle))) {
    agent._faceAngle = Number(spot.faceAngle);
    if (agent._group3d) agent._group3d.rotation.y = Number(spot.faceAngle);
  }
  requestObjectActionPointDebugOverlayRefresh();
  return { triggered: true, handler: 'startDraggedAgentStandingMachineUse', mode: config.mode, furnitureType: machine.type, directServiceUse: true, snapToUseSpot: true, actionId: config.actionId };
}

function getManualDrinkMachineDragDropIntentMetadata(drop, agent, config, spot) {
  const machine = drop?.furniture || null;
  const actionId = config?.actionId || spot?.action || machine?.activeUse?.actionId || machine?.reservation?.actionId || null;
  return {
    owner: 'manual',
    priorityName: 'manual',
    phase: 'approach',
    buildingId: drop?.buildingId || drop?.building?.id || null,
    furnitureIndex: drop?.index ?? null,
    furniture: machine,
    objectType: machine?.type || null,
    actionId,
    spotId: spot?.spotId || config?.slotId || null,
    release: { policy: 'on-object-complete', releaseObjectReservation: true, releaseActiveUse: true, allowedBy: AGENT_INTENT_RELEASE_ALLOWED_BY['explicit-object'] },
    sourceFamily: 'manual-drag-drop',
    sourceFunction: 'startDraggedAgentDrinkMachineViaFurnitureHandler',
    debugLabel: `manual-drop:${actionId || machine?.type || 'drink-machine'}`,
    sourceSummary: 'manual agent drop uses normal drink-machine furniture handler at exact standing use spot',
    behaviorSourceKind: 'user',
    behaviorMode: 'user-directed',
    behaviorAuthority: AGENT_INTENT_PRIORITY.manual,
    behaviorSelectedObject: machine?.type || null,
    behaviorSelectedSpot: spot?.spotId || config?.slotId || null,
    taskRef: 'manual-drag-drop-drink-machine-handler-intent',
  };
}

function startDraggedAgentDrinkMachineViaFurnitureHandler(drop, agent) {
  if (!agent || !drop?.furniture || !isManualDropStandingDrinkMachine(drop.furniture)) return { triggered: false, reason: 'not-manual-drink-machine' };
  const [fnName, mode] = DRAG_AGENT_FIRST_INTERACTION[drop.furniture.type] || [];
  const fn = fnName ? window[fnName] : null;
  if (typeof fn !== 'function') return { triggered: false, reason: 'missing-drink-machine-handler', handler: fnName || null };
  const config = getStandingUseMachineConfig(drop.furniture.type);
  const spot = config ? (getFurnitureActionSpot(drop.building, drop.furniture, config.slotId) || drop.spot || getFurnitureActionSpot(drop.building, drop.furniture)) : (drop.spot || null);
  const mesh = findFurnitureMesh(drop.buildingId, drop.index);
  _selectedFurniture = { buildingId: drop.buildingId, index: drop.index, mesh };
  fn(mode, agent.id, { intentMetadata: getManualDrinkMachineDragDropIntentMetadata(drop, agent, config, spot) });
  const activity = agent._idleActivity || null;
  const activityMatchesDrop = activity && activity.buildingId === drop.buildingId && Number(activity.furnitureIndex) === Number(drop.index);
  if (!activityMatchesDrop) {
    return { triggered: false, reason: 'drink-machine-handler-did-not-start-dragged-agent', handler: fnName, mode, furnitureType: drop.furniture.type };
  }
  activity.source = 'manual-drag-drop-machine-use';
  activity.behaviorSourceKind = 'user';
  activity.behaviorMode = 'user-directed';
  activity.dragDropUsesNormalFurnitureHandler = true;
  if (!activity.routeApproachTarget && drop.spot) {
    activity.routeApproachTarget = { x: drop.spot.apiX, y: drop.spot.apiZ, floor: drop.spot.floor, spotId: drop.spot.spotId, faceAngle: drop.spot.faceAngle };
  }
  return { triggered: true, handler: fnName, mode, furnitureType: drop.furniture.type, directServiceUse: true, snapToUseSpot: true, actionId: activity.actionId || activity.action || config?.actionId || drop.spot?.action || null, viaNormalFurnitureHandler: true };
}

function triggerDraggedAgentObjectInteraction(drop, agent) {
  if (!agent || !drop?.furniture) return { triggered: false, reason: 'unavailable' };
  if (!drop.available) {
    if (drop.queueable && isScriptedServiceQueueFurniture(drop.furniture)) {
      const queued = queueAgentForScriptedServiceObject(agent, drop.building, drop.index, 'manual-drag-drop-service-queue', { allowClaimedServiceObject: true, sourceKind: 'manual-drag-drop-service-queue', ignoreRecentCooldown: true });
      if (queued?.queued) {
        return { triggered: true, handler: 'queueAgentForScriptedServiceObject', mode: 'queue', furnitureType: drop.furniture.type, queued: true, queueIndex: queued.reservation?.queueIndex || 0 };
      }
      return { triggered: false, reason: queued?.reason || 'queue-rejected', handler: 'queueAgentForScriptedServiceObject', mode: 'queue', furnitureType: drop.furniture.type };
    }
    return { triggered: false, reason: drop.reason || 'unavailable' };
  }
  if (isScriptedServiceQueueFurniture(drop.furniture)) {
    const normalDrinkMachineUse = startDraggedAgentDrinkMachineViaFurnitureHandler(drop, agent);
    if (normalDrinkMachineUse.triggered) return normalDrinkMachineUse;
    const directStandingUse = startDraggedAgentStandingMachineUse(drop, agent);
    if (directStandingUse.triggered) return directStandingUse;
    if (directStandingUse.reason !== 'not-standing-machine') return directStandingUse;
    const direct = submitQueuedScriptedServiceObjectUse(agent, drop.building, drop.index, {
      buildingId: drop.buildingId,
      furnitureIndex: drop.index,
      furnitureType: drop.furniture.type,
      actionId: drop.spot?.action || null,
      source: 'manual-drag-drop-direct-service-use',
    });
    if (direct?.accepted !== false) {
      return { triggered: true, handler: 'submitQueuedScriptedServiceObjectUse', mode: 'direct-service-use', furnitureType: drop.furniture.type, directServiceUse: true };
    }
    return { triggered: false, reason: direct?.reason || 'direct-service-use-rejected', handler: 'submitQueuedScriptedServiceObjectUse', mode: 'direct-service-use', furnitureType: drop.furniture.type };
  }
  const [fnName, mode] = DRAG_AGENT_FIRST_INTERACTION[drop.furniture.type] || [];
  const fn = fnName ? window[fnName] : null;
  if (typeof fn !== 'function') return { triggered: false, reason: 'no-handler', furnitureType: drop.furniture.type };
  const mesh = findFurnitureMesh(drop.buildingId, drop.index);
  _selectedFurniture = { buildingId: drop.buildingId, index: drop.index, mesh };
  setDragDropAgentPickerValue(drop.furniture.type, agent.id);
  const selectedAgentTypes = new Set(['armchair', 'arcadeMachine', 'barberChair', 'accessoryDisplayStand']);
  if (drop.furniture.type === 'dumbbellRack') fn();
  else if (selectedAgentTypes.has(drop.furniture.type)) fn(mode, agent.id);
  else fn(mode);
  const activity = agent._idleActivity || null;
  const activityMatchesDrop = activity && activity.buildingId === drop.buildingId && Number(activity.furnitureIndex) === Number(drop.index);
  if (!activityMatchesDrop) {
    return { triggered: false, reason: 'handler-did-not-start-activity', handler: fnName, mode, furnitureType: drop.furniture.type };
  }
  return { triggered: true, handler: fnName, mode, furnitureType: drop.furniture.type };
}

function recordManualAgentObjectInteraction(drop, agent, trigger = null, snap = null) {
  if (typeof window === 'undefined') return null;
  const activity = agent?._idleActivity || null;
  const record = {
    at: new Date().toISOString(),
    agentId: agent?.id || null,
    agentName: agent?.name || null,
    buildingId: drop?.buildingId || null,
    furnitureIndex: drop?.index ?? null,
    furnitureType: drop?.furniture?.type || null,
    spotId: drop?.spot?.spotId || null,
    actionId: trigger?.actionId || activity?.actionId || activity?.action || drop?.spot?.action || null,
    handler: trigger?.handler || null,
    mode: trigger?.mode || null,
    triggered: trigger?.triggered === true,
    directServiceUse: trigger?.directServiceUse === true,
    queued: trigger?.queued === true,
    triggerReason: trigger?.reason || null,
    snapped: snap?.snapped === true,
    snappedSpotId: snap?.spotId || null,
    activatedManualUse: snap?.activatedManualUse === true,
    activityKind: activity?.kind || null,
    activityPhase: activity?.phase || null,
    activitySource: activity?.source || null,
    reservationId: activity?.reservationId || drop?.furniture?.reservation?.id || null,
    machineReservationStatus: drop?.furniture?.reservation?.status || null,
    machineActiveUseState: drop?.furniture?.activeUse?.state || null,
    stayTimer: Number.isFinite(Number(agent?._stayTimer)) ? Number(agent._stayTimer) : null,
    targetMatchesObject: Boolean(activity && drop && activity.buildingId === drop.buildingId && Number(activity.furnitureIndex) === Number(drop.index)),
  };
  window.__VWLastManualAgentObjectInteraction = record;
  if (!Array.isArray(window.__VWManualAgentObjectInteractionLog)) window.__VWManualAgentObjectInteractionLog = [];
  window.__VWManualAgentObjectInteractionLog.push(record);
  if (window.__VWManualAgentObjectInteractionLog.length > 25) window.__VWManualAgentObjectInteractionLog.splice(0, window.__VWManualAgentObjectInteractionLog.length - 25);
  return record;
}

function getDraggedDropInteractionFaceAngle(drop, agent = null) {
  const activity = agent?._idleActivity || null;
  const activityMatchesDrop = activity && drop && activity.buildingId === drop.buildingId && Number(activity.furnitureIndex) === Number(drop.index);
  if (activityMatchesDrop && Number.isFinite(Number(activity.faceAngle))) return Number(activity.faceAngle);
  if (drop?.building && drop?.furniture && drop?.spot) {
    const facing = drop.spot.facing || (FURNITURE_INTERACTION_SPOTS[drop.furniture.type] || []).find(spot => spot.id === drop.spot.spotId)?.facing || 'north';
    const computed = getFurnitureForwardFacingAngle(drop.building, drop.furniture, drop.spot, facing);
    if (Number.isFinite(Number(computed))) return Number(computed);
    if (Number.isFinite(Number(drop.spot.faceAngle))) return Number(drop.spot.faceAngle);
  }
  return null;
}

function applyDraggedDropInteractionFacing(drop, agent, reason = 'drag-drop-object-interaction') {
  const faceAngle = getDraggedDropInteractionFaceAngle(drop, agent);
  if (!agent || !Number.isFinite(Number(faceAngle))) return false;
  const normalized = Number(faceAngle);
  if (agent._group3d) agent._group3d.rotation.y = normalized;
  agent._faceAngle = normalized;
  agent._lastObjectInteractionFacing = { faceAngle: normalized, reason, buildingId: drop?.buildingId || null, furnitureIndex: drop?.index ?? null, spotId: drop?.spot?.spotId || null, atMs: Date.now() };
  const activity = agent._idleActivity || null;
  if (activity && drop && activity.buildingId === drop.buildingId && Number(activity.furnitureIndex) === Number(drop.index)) {
    activity.faceAngle = normalized;
    activity.facingLockedByInteractionDrop = true;
  }
  return true;
}

function activateSnappedManualStandingMachineDrop(drop, agent) {
  const activity = agent?._idleActivity || null;
  const machine = drop?.furniture || null;
  if (!agent || !drop || !activity || !machine) return false;
  if (activity.source !== 'manual-drag-drop-machine-use') return false;
  if (activity.buildingId !== drop.buildingId || Number(activity.furnitureIndex) !== Number(drop.index)) return false;
  const kind = String(activity.kind || '');
  if (!kind.startsWith('water-cooler-') && !kind.startsWith('coffee-machine-')) return false;
  if (activity.phase !== 'approach') return false;
  const config = getStandingUseMachineConfig(activity.furnitureType || machine.type);
  const nowMs = performance.now();
  const stayMs = Math.max(1, Number(activity.stayMs || config?.useDurationMs || 9000) || 9000);
  agent._wanderTarget = null;
  agent._stayTimer = stayMs;
  agent._wanderTimer = 0;
  agent._isRunning = false;
  activity.phase = 'active';
  activity.startedAt = activity.startedAt || nowMs;
  activity.activeStartedAt = nowMs;
  activity.endsAt = nowMs + stayMs;
  activateStandingUseMachineOnArrival(agent, activity);
  if (kind.startsWith('water-cooler-')) agent._schedPhase = 'water-cooler-dispense';
  else if (kind.startsWith('coffee-machine-')) agent._schedPhase = 'coffee-brew';
  requestObjectActionPointDebugOverlayRefresh();
  return true;
}

function snapDraggedAgentToStartedObjectApproach(drop, agent) {
  const activity = agent?._idleActivity || null;
  const activityMatchesDrop = activity && drop && activity.buildingId === drop.buildingId && Number(activity.furnitureIndex) === Number(drop.index);
  if (!activityMatchesDrop) return { snapped: false, reason: 'no-matching-activity' };
  const target = activity.routeApproachTarget || agent._wanderTarget || null;
  if (!target || !Number.isFinite(Number(target.x)) || !Number.isFinite(Number(target.y))) return { snapped: false, reason: 'missing-approach-target' };
  agent.x = Number(target.x);
  agent.y = Number(target.y);
  agent._floor = Math.max(1, Number(target.floor || activity.routeApproachTarget?.floor || agent._targetFloor || agent._floor || 1) || 1);
  agent._targetFloor = agent._floor;
  agent._currentBuilding = getMovementInteriorBuildingAt(agent.x, agent.y) || drop.building || null;
  agent._waypointPath = null;
  agent._waypointPathIdx = 0;
  agent._waypointPathTarget = null;
  agent._doorTransition = null;
  clearDynamicInteriorRoutingForAgent(agent.id);
  clearDynamicExteriorRoutingForAgent(agent.id);
  resetObstacleAvoidance(agent);
  agent._wanderTarget = { x: agent.x, y: agent.y, floor: agent._floor };
  agent._stayTimer = 0;
  agent._wanderTimer = 0;
  agent._isRunning = false;
  activity.dragDropSnappedToApproach = true;
  activity.dragDropSnapTarget = { x: agent.x, y: agent.y, floor: agent._floor, spotId: target.spotId || activity.approachSpotId || null };
  const faceAngle = Number.isFinite(Number(target.faceAngle)) ? Number(target.faceAngle) : getDraggedDropInteractionFaceAngle(drop, agent);
  if (Number.isFinite(Number(faceAngle))) {
    agent._faceAngle = Number(faceAngle);
    if (agent._group3d) agent._group3d.rotation.y = Number(faceAngle);
  }
  const scale = T / API_TILE;
  if (isPhysicsReady()) teleportAgent('agent_' + agent.id, agent.x * scale, getGroundY(agent.x * scale, agent.y * scale), agent.y * scale);
  const activatedManualUse = activateSnappedManualStandingMachineDrop(drop, agent);
  return { snapped: true, x: agent.x, y: agent.y, floor: agent._floor, spotId: activity.dragDropSnapTarget.spotId, activatedManualUse };
}

function updateDraggedAgentPreview(e) {
  if (!_draggedAgentState) return false;
  const agent = agentsList.find(a => a.id === _draggedAgentState.agentId) || null;
  if (!agent) return false;
  const hit = raycastGround(e);
  if (!hit) return false;
  const scale = T / API_TILE;
  agent.x = hit.x / scale;
  agent.y = hit.z / scale;
  agent._manualPlacementPreview = true;
  updateDraggedAgentInteractionHighlight(resolveDraggedAgentObjectHover(e));
  return true;
}

function startDraggedAgent(agent, e) {
  _pendingAgentPickup = null;
  _draggedAgentState = {
    agentId: agent.id,
    pointerId: e.pointerId,
    startedAt: performance.now(),
  };
  clearAgentTransientMovement(agent);
  agent._manualPlacementLockUntil = performance.now() + AGENT_MANUAL_PLACE_HOLD_MS;
  agent._stayTimer = AGENT_MANUAL_PLACE_HOLD_MS;
  agent._wanderTimer = 0;
  renderer.domElement.setPointerCapture(e.pointerId);
  updateDraggedAgentPreview(e);
  showToast(`🖐️ Dragging ${agent.emoji || '🤖'} ${agent.name || agent.id}`, 'warning');
}

function finalizeDraggedAgentPlacement(e) {
  if (!_draggedAgentState) return false;
  const drag = _draggedAgentState;
  _draggedAgentState = null;
  const agent = agentsList.find(a => a.id === drag.agentId) || null;
  if (!agent) return false;

  updateDraggedAgentPreview(e);
  const manualDrinkMachineDrop = resolveDraggedAgentManualDrinkMachineDrop(agent);
  const hoverDrop = _dragAgentObjectHover && (_dragAgentObjectHover.available || _dragAgentObjectHover.queueable) ? _dragAgentObjectHover : null;
  let objectDrop = manualDrinkMachineDrop || hoverDrop || resolveDraggedAgentNearbyServiceObjectDrop(agent);
  clearAgentTransientMovement(agent);
  objectDrop = refreshDraggedAgentObjectDropAfterMovementClear(objectDrop, agent);
  if (manualDrinkMachineDrop?.furniture && objectDrop?.furniture === manualDrinkMachineDrop.furniture) objectDrop = forceManualDrinkMachineDropAvailable(objectDrop, agent);
  const skipPreTriggerObjectSnap = objectDrop?.furniture && isManualDropStandingServiceMachine(objectDrop.furniture);
  if (!skipPreTriggerObjectSnap && objectDrop?.spot && objectDrop.available) {
    agent.x = objectDrop.spot.apiX;
    agent.y = objectDrop.spot.apiZ;
    agent._floor = Math.max(1, Number(objectDrop.spot.floor || agent._floor || 1) || 1);
    agent._targetFloor = agent._floor;
    if (Number.isFinite(objectDrop.spot.faceAngle) && agent._group3d) agent._group3d.rotation.y = objectDrop.spot.faceAngle;
  }
  agent._manualPlacementPreview = false;
  agent._manualPlacementLockUntil = performance.now() + AGENT_MANUAL_PLACE_HOLD_MS;
  agent._stayTimer = AGENT_MANUAL_PLACE_HOLD_MS;
  agent._wanderTimer = 0;
  agent._currentBuilding = getMovementInteriorBuildingAt(agent.x, agent.y) || null;

  const placementDrinkMachineDrop = resolveDraggedAgentManualDrinkMachineDropAfterPlacement(agent, objectDrop);
  if (placementDrinkMachineDrop && placementDrinkMachineDrop !== objectDrop) {
    objectDrop = placementDrinkMachineDrop;
    const skipPlacementPreTriggerObjectSnap = objectDrop?.furniture && isManualDropStandingServiceMachine(objectDrop.furniture);
    if (!skipPlacementPreTriggerObjectSnap && objectDrop.spot && objectDrop.available) {
      agent.x = objectDrop.spot.apiX;
      agent.y = objectDrop.spot.apiZ;
      agent._floor = Math.max(1, Number(objectDrop.spot.floor || agent._floor || 1) || 1);
      agent._targetFloor = agent._floor;
      if (Number.isFinite(objectDrop.spot.faceAngle) && agent._group3d) agent._group3d.rotation.y = objectDrop.spot.faceAngle;
      agent._currentBuilding = getMovementInteriorBuildingAt(agent.x, agent.y) || objectDrop.building || null;
    }
  }

  const scale = T / API_TILE;
  if (isPhysicsReady()) {
    teleportAgent('agent_' + agent.id, agent.x * scale, getGroundY(agent.x * scale, agent.y * scale), agent.y * scale);
  }

  const interactionTrigger = objectDrop ? triggerDraggedAgentObjectInteraction(objectDrop, agent) : null;
  const dropSnap = objectDrop && interactionTrigger?.triggered && (objectDrop.available || interactionTrigger?.queued === true) ? snapDraggedAgentToStartedObjectApproach(objectDrop, agent) : null;
  const interactionRecord = objectDrop ? recordManualAgentObjectInteraction(objectDrop, agent, interactionTrigger, dropSnap) : null;
  if (objectDrop && interactionTrigger?.triggered) {
    addActivityLog(`🖐️ ${agent.emoji || '🤖'} ${agent.name || agent.id} was dropped on ${objectDrop.furniture?.type || 'object'} ${objectDrop.spot.spotId}; ${interactionTrigger.queued ? `joined queue #${Number(interactionTrigger.queueIndex || 0) + 1}` : (interactionTrigger.directServiceUse ? `started ${interactionRecord?.actionId || 'direct service use'} via ${interactionTrigger.handler}` : `default object menu action started via ${interactionTrigger.handler}`)}${dropSnap?.snapped ? ` and snapped to ${dropSnap.spotId || 'approach'}` : ''}${dropSnap?.activatedManualUse ? '; active use started' : ''}`);
  } else {
    addActivityLog(`🖐️ ${agent.emoji || '🤖'} ${agent.name || agent.id} was repositioned${objectDrop ? ` to ${objectDrop.furniture?.type || 'object'} ${objectDrop.spot.spotId}` : ''}`);
    showToast(objectDrop
      ? `📍 Placed ${agent.emoji || '🤖'} ${agent.name || agent.id}${interactionTrigger?.reason ? ` (${interactionTrigger.reason})` : ''}`
      : `📍 Placed ${agent.emoji || '🤖'} ${agent.name || agent.id}`,
      'success');
  }
  clearDraggedAgentObjectHover();

  try {
    renderer.domElement.releasePointerCapture(drag.pointerId);
  } catch (_) { /* ignore */ }
  return true;
}

function raycastInteriorWall(e) {
  if (!insideBuildingId) return null;
  const b = buildingsMap.get(insideBuildingId);
  if (!b?._group) return null;
  const wallMeshes = [];
  const activeFloor = getActiveBuildingFloor(b);
  b._group.traverse(obj => {
    if (obj.isMesh && obj.userData?.interiorWall && Math.max(1, Number(obj.userData.floor || 1) || 1) === activeFloor) wallMeshes.push(obj);
  });
  if (wallMeshes.length === 0) return null;
  const activeRaycaster = getPointerRaycast(e);
  const hits = activeRaycaster.intersectObjects(wallMeshes, false);
  if (!hits.length) return null;
  const hit = hits[0];
  return {
    hit,
    wallIndex: hit.object?.userData?.wallIndex,
    buildingId: hit.object?.userData?.buildingId || b.id,
  };
}

function updateCoordDisplay(e) {
  const hit = raycastGround(e);
  if (hit) {
    const txt = `${Math.floor(hit.x)}, ${Math.floor(hit.z)}`;
    const cd = document.getElementById('coordDisplay');
    if (cd) cd.textContent = txt;
    const cd2 = document.getElementById('coordDisplay2');
    if (cd2) cd2.textContent = txt;
  }
}

function handleClick(e) {
  // First: raycaster check for agent meshes (more precise than proximity)
  const agentHit = getAgentHitFromPointer(e);
  if (agentHit?.agent) {
    openAgentPanel(agentHit.agent.id);
    return;
  }

  if (!placementMode && !decorationPlacementType && !_furniturePlacementType && editMode === 'world') {
    const decorHit = getPlacedDecorationHit(e);
    if (decorHit?.meta && selectPlacedDecoration(decorHit.meta)) return;
    clearSelectedPlacedDecoration();
  }

  // Outdoor node selection while editing parks/outside spaces. This lets users
  // click individual generated trees to select/delete them instead of selecting
  // the park footprint underneath.
  if (!placementMode && !decorationPlacementType && !_furniturePlacementType && editMode === 'buildings') {
    const objectRay = getPointerRaycast(e);
    const objectContext = resolveObjectContextTargetFromRay(objectRay);
    if (objectContext.target?.menuType === 'outdoor-node') {
      const { buildingId, nodeId } = parseOutdoorNodeTargetId(objectContext.target.targetId);
      const mesh = findOutdoorNodeMesh(buildingId, nodeId);
      const nodeIndex = Number.isInteger(Number(mesh?.userData?.outdoorNodeIndex)) ? Number(mesh.userData.outdoorNodeIndex) : undefined;
      if (mesh) _selectOutdoorNode(buildingId, nodeId, nodeIndex, mesh);
      registerActiveContextTarget(objectContext.target);
      showToast('🌲 Outdoor tree selected — right-click for actions/delete', 'success');
      return;
    }
  }

  // Exterior floor-wall selection: clicking a visible exterior floor band opens
  // directly to that floor. While inside a focused building this also allows
  // switching down to any lower visible floor; higher floors remain hidden and
  // therefore cannot be clicked/overlap the active floor.
  if (!placementMode && !decorationPlacementType && !_furniturePlacementType && (!editMode || editMode === 'buildings')) {
    const floorHit = getExteriorFloorWallHit(e);
    if (floorHit?.building && floorHit.building.type !== 'park') {
      if (insideBuildingId && floorHit.buildingId !== insideBuildingId) {
        exitBuilding(/*silent=*/true);
      }
      selectBuilding(floorHit.buildingId);
      setActiveBuildingFloor(floorHit.building, floorHit.floor);
      enterBuilding(floorHit.buildingId, floorHit.floor);
      clearExteriorFloorHover();
      return;
    }
  }

  const hit = raycastGround(e);
  if (!hit) return;

  if (_elevatorRelocateBuildingId) {
    if (commitElevatorRelocate(hit.x, hit.z)) return;
  }

  if (insideBuildingId && editMode === 'buildings') {
    const b = buildingsMap.get(insideBuildingId);
    if (b && b._group) {
      const wallHit = raycastInteriorWall(e);
      const hoveredWall = (wallHit && wallHit.wallIndex != null)
        ? { building: b, wallIndex: wallHit.wallIndex, distance: 0, point: wallHit.hit.point }
        : findInteriorWallFromWorldHit(hit);
      if (hoveredWall) {
        const wallIndex = hoveredWall.wallIndex;
        if (_interiorWallOpeningMode) {
          if (_interiorOpeningWallIndex == null) {
            _interiorOpeningWallIndex = wallIndex;
            _interiorWallStart = null;
            _selectInteriorWall(insideBuildingId, wallIndex);
            updateInteriorWallPreview(hit);
            const hint = document.getElementById('interiorWallHint');
            if (hint) hint.textContent = 'Wall selected. Click once to anchor the opening, then click again to confirm';
          } else if (_interiorOpeningWallIndex !== wallIndex) {
            _interiorOpeningWallIndex = wallIndex;
            _interiorWallStart = null;
            _selectInteriorWall(insideBuildingId, wallIndex);
            updateInteriorWallPreview(hit);
            const hint = document.getElementById('interiorWallHint');
            if (hint) hint.textContent = 'Switched wall. Click once to anchor the opening, then click again to confirm';
          } else if (!_interiorWallStart) {
            _interiorWallStart = getInteriorOpeningPoint(hit, wallIndex);
            updateInteriorWallPreview(hit);
            const hint = document.getElementById('interiorWallHint');
            if (hint) hint.textContent = 'Opening anchored. Move to size it, then click again to confirm';
          } else {
            updateInteriorWallPreview(hit);
            finalizeInteriorWallOpening(hit);
          }
          return;
        }
        _selectInteriorWall(insideBuildingId, wallIndex);
        return;
      }
    }
  }

  if (_interiorWallMode || _interiorWallOpeningMode) return;

  // Furniture selection (click on existing furniture inside building)
  if (insideBuildingId && editMode === 'buildings' && !_furniturePlacementType) {
    const clickRay = new THREE.Raycaster();
    const clickMouse2 = new THREE.Vector2(
      ((e.clientX - renderer.domElement.getBoundingClientRect().left) / renderer.domElement.getBoundingClientRect().width) * 2 - 1,
      -((e.clientY - renderer.domElement.getBoundingClientRect().top) / renderer.domElement.getBoundingClientRect().height) * 2 + 1
    );
    clickRay.setFromCamera(clickMouse2, camera);
    const b = buildingsMap.get(insideBuildingId);
    if (b && b._group) {
      const furnMeshes = [];
      b._group.traverse(obj => { if (obj.isMesh && obj.userData.furniture) furnMeshes.push(obj); });
      const hits = clickRay.intersectObjects(furnMeshes, false);
      if (hits.length > 0) {
        // Find which furniture group this mesh belongs to. Prefer metadata over
        // position matching so small/rotated furniture (like sinks) remains
        // selectable even when its visual bounds or floor offsets differ.
        let furnGroup = hits[0].object;
        while (furnGroup.parent && furnGroup.parent !== b._group) furnGroup = furnGroup.parent;
        const hitMeta = hits[0].object.userData || {};
        const groupMeta = furnGroup.userData || {};
        let fi = Number.isInteger(hitMeta.furnitureIndex) ? hitMeta.furnitureIndex : groupMeta.furnitureIndex;
        if (!Number.isInteger(fi) || !b.interior?.furniture?.[fi]) {
          const activeFloor = getActiveBuildingFloor(b);
          fi = (b.interior?.furniture || []).findIndex(f =>
            getFurnitureFloor(f) === activeFloor && Math.abs(f.x - furnGroup.position.x) < 0.5 && Math.abs(f.z - furnGroup.position.z) < 0.5
          );
        }
        if (fi >= 0) _selectFurniture(insideBuildingId, fi, furnGroup);
        return;
      } else {
        _deselectFurniture();
      }
    }
  }

  // Furniture placement inside buildings or selected outside spaces.
  if (_furniturePlacementType && editMode === 'buildings') {
    const b = getFurniturePlacementBuilding();
    if (b) {
      const local = getBuildingLocalPoint(b, hit.x, hit.z);
      const localX = local.x;
      const localZ = local.z;
      if (localX >= 0 && localX <= b.widthTiles * T && localZ >= 0 && localZ <= b.heightTiles * T) {
        placeFurnitureAt(hit.x, hit.z);
        return;
      }
    }
  }

  // Decoration placement?
  if (decorationPlacementType && editMode === 'world') {
    const wx = Math.floor(hit.x / T);
    const wz = Math.floor(hit.z / T);
    const tile = _getWorldTile(wx, wz);
    if (tile !== TERRAIN.GRASS && tile !== TERRAIN.DIRT) {
      showToast('🚫 Decorations can only be placed on grass or dirt terrain', 'error');
      return;
    }
    if (isInsideBuildingFootprint(wx, wz, 0)) {
      showToast('🚫 Decorations cannot be placed inside a building footprint', 'error');
      return;
    }
    addPlacedDecoration(decorationPlacementType, wx, wz);
    showToast(`${DECORATION_DEFS[decorationPlacementType]?.icon || '🌿'} Placed!`, 'success');
    return;
  }

  // Click agent? (fallback proximity for small/occluded agents)
  const scale = T / API_TILE;
  for (const agent of agentsList) {
    const ax = agent.x * scale, az = agent.y * scale;
    if (Math.abs(hit.x - ax) < 0.8 && Math.abs(hit.z - az) < 0.8) {
      showToast(`${agent.emoji || '🤖'} ${agent.name}: ${agent.status || 'offline'}${agent.task ? ' — ' + agent.task : ''}`);
      return;
    }
  }

  // Click building?
  for (const [id, bld] of buildingsMap) {
    const bounds = getBuildingFootprintBounds(bld, 0);
    if (hit.x >= bounds.minX && hit.x <= bounds.maxX && hit.z >= bounds.minZ && hit.z <= bounds.maxZ) {
      selectBuilding(id);
      if (editMode === 'buildings') {
        if (!isOutsideSpaceBuilding(bld) && insideBuildingId !== id) enterBuilding(id);
      } else if (!isOutsideSpaceBuilding(bld)) {
        enterBuilding(id);
      }
      return;
    }
  }

  if (insideBuildingId) exitBuilding();
  if (selectedBuildingId) deselectBuilding();
}

function paintTerrain(e) {
  const hit = raycastGround(e);
  if (!hit) return;

  const tx = Math.floor(hit.x / T);
  const tz = Math.floor(hit.z / T);
  const cx = Math.floor(tx / CHUNK);
  const cz = Math.floor(tz / CHUNK);
  const key = chunkKey(cx, cz);
  const chunk = loadedChunks.get(key);
  if (!chunk) return;

  const lx = ((tx % CHUNK) + CHUNK) % CHUNK;
  const lz = ((tz % CHUNK) + CHUNK) % CHUNK;
  const idx = lz * CHUNK + lx;
  if (chunk.terrain[idx] === selectedTerrain) return;

  // Push typed terrain undo (one entry per tile, deduplicated during paint drag)
  const oldType = chunk.terrain[idx];
  const lastU = undoStack.length > 0 ? undoStack[undoStack.length - 1] : null;
  const isDuplicate = lastU && lastU.type === 'terrain' && lastU.key === key && lastU.idx === idx;
  if (!isDuplicate) {
    pushUndo({ type: 'terrain', key, cx, cz, idx, oldType, newType: selectedTerrain });
  }

  chunk.terrain[idx] = selectedTerrain;
  chunk.dirty = true;

  // Remove any user-placed decorations on tiles painted as non-grass (road, sidewalk, water, etc.)
  if (selectedTerrain !== TERRAIN.GRASS && selectedTerrain !== TERRAIN.DIRT) {
    const pdKey = chunkDecorationKey(cx, cz);
    const pdList = placedDecorations.get(pdKey);
    if (pdList) {
      const tileWx = cx * CHUNK_W + lx * T;
      const tileWz = cz * CHUNK_W + lz * T;
      const filtered = pdList.filter(pd => {
        const pdTx = Math.floor((pd.wx - cx * CHUNK_W) / T);
        const pdTz = Math.floor((pd.wz - cz * CHUNK_W) / T);
        return pdTx !== lx || pdTz !== lz;
      });
      if (filtered.length !== pdList.length) {
        placedDecorations.set(pdKey, filtered);
        debounceSavePlacedDecorations();
      }
    }
  }

  // Auto-sidewalk: if painting road, add sidewalks on adjacent grass/dirt
  if (selectedTerrain === TERRAIN.ROAD) {
    const dirs = [[-1,0],[1,0],[0,-1],[0,1]];
    for (const [ddx, ddz] of dirs) {
      const nlx = lx + ddx, nlz = lz + ddz;
      if (nlx >= 0 && nlx < CHUNK && nlz >= 0 && nlz < CHUNK) {
        // Same chunk
        const ni = nlz * CHUNK + nlx;
        if (chunk.terrain[ni] === TERRAIN.GRASS || chunk.terrain[ni] === TERRAIN.DIRT) {
          chunk.terrain[ni] = TERRAIN.SIDEWALK;
        }
      } else {
        // Neighbour chunk
        const ncx = cx + (nlx < 0 ? -1 : nlx >= CHUNK ? 1 : 0);
        const ncz = cz + (nlz < 0 ? -1 : nlz >= CHUNK ? 1 : 0);
        const nChunk = loadedChunks.get(chunkKey(ncx, ncz));
        if (nChunk) {
          const nnlx = ((nlx % CHUNK) + CHUNK) % CHUNK;
          const nnlz = ((nlz % CHUNK) + CHUNK) % CHUNK;
          const ni = nnlz * CHUNK + nnlx;
          if (nChunk.terrain[ni] === TERRAIN.GRASS || nChunk.terrain[ni] === TERRAIN.DIRT) {
            nChunk.terrain[ni] = TERRAIN.SIDEWALK;
            nChunk.dirty = true;
            rebuildChunk(nChunk);
          }
        }
      }
    }
  }

  rebuildChunk(chunk);
}

function enterBuilding(id, floor = null) {
  const b = buildingsMap.get(id);
  if (!b) return;
  if (isOutsideSpaceBuilding(b)) {
    selectBuilding(id);
    document.getElementById('interiorWallTools')?.style.setProperty('display', 'none');
    showToast(`🌳 Selected outside space: ${b.name || 'Outside Space'}`, 'info');
    return;
  }
  if (insideBuildingId === id && floor == null) return;
  const requestedFloor = floor == null ? null : Math.max(1, Math.min(getBuildingFloorCount(b), Number(floor) || 1));
  if (insideBuildingId === id && requestedFloor != null) {
    setActiveBuildingFloor(b, requestedFloor);
    createBuilding3D(b);
    applyBuildingViewMode(b, getEffectiveBuildingViewMode(b));
    focusCameraOnBuildingFloor(b, requestedFloor);
    updateBuildingEditPanel(b);
    updateFloorControlPanel();
    showToast(`🏢 ${b.name}: Floor ${requestedFloor}`);
    return;
  }
  if (insideBuildingId) exitBuilding(/*silent=*/true);
  _prevCamDist = camDist; // save for restore on exit
  insideBuildingId = id;
  normalizeBuildingFloors(b);
  if (requestedFloor != null) setActiveBuildingFloor(b, requestedFloor);
  else if (!_buildingFloorView.has(id)) setActiveBuildingFloor(b, 1);
  // Rebuild to show only the active floor's editable furniture while preserving all floor shells/elevators.
  createBuilding3D(b);
  // Auto-open the exterior shell for the entered building, but keep interior walls visible.
  applyBuildingViewMode(b, getEffectiveBuildingViewMode(b));
  // Center on the active floor and zoom in to its footprint.
  focusCameraOnBuildingFloor(b, getActiveBuildingFloor(b));
  showToast(`🏢 Inside: ${b.name}${getBuildingFloorCount(b) > 1 ? ` — Floor ${getActiveBuildingFloor(b)}` : ''}`);
  // Switch sidebar to furniture tab if in buildings edit mode
  if (editMode === 'buildings') {
    if (typeof window._switchBuildingTab === 'function') window._switchBuildingTab('furniture');
  }
  document.getElementById('interiorWallTools')?.style.setProperty('display', editMode === 'buildings' ? 'block' : 'none');
  const hint = document.getElementById('interiorWallHint');
  if (hint) hint.textContent = 'Click + New Wall to start drawing';
}

function exitBuilding(silent) {
  if (!insideBuildingId) return;
  const b = buildingsMap.get(insideBuildingId);
  // Restore building to current global view mode
  if (b) applyBuildingViewMode(b, _buildingViewMode);
  insideBuildingId = null;
  if (b && selectedBuildingId !== b.id) createBuilding3D(b);
  // Restore previous camera distance with smooth transition
  flyCameraTo(camTarget.clone(), _prevCamDist);
  cancelFurniturePlacement();
  cancelInteriorWallPlacement();
  document.getElementById('interiorWallTools')?.style.setProperty('display', 'none');
  if (!silent) showToast('Exited building');
}

function clearSelectedBuildingHelper() {
  if (!selectedBuildingHelper) return;
  selectedBuildingHelper.parent?.remove(selectedBuildingHelper);
  selectedBuildingHelper.geometry?.dispose?.();
  selectedBuildingHelper.material?.dispose?.();
  selectedBuildingHelper = null;
}

function clearSelectedBuildingResizeHandles() {
  selectedBuildingResizeHandles.forEach(handle => {
    handle.parent?.remove(handle);
    handle.geometry?.dispose?.();
    handle.material?.dispose?.();
  });
  selectedBuildingResizeHandles = [];
  clearBuildingResizePreview();
}

function clearBuildingResizePreview() {
  if (selectedBuildingResizeHandles.length) setSelectedBuildingResizeHandlesColor(0x38bdf8);
  if (!_buildingResizePreview) return;
  _buildingResizePreview.parent?.remove(_buildingResizePreview);
  _buildingResizePreview.geometry?.dispose?.();
  _buildingResizePreview.material?.dispose?.();
  _buildingResizePreview = null;
}

function addSelectedBuildingResizeHandles(building) {
  if (!building?._group) return;
  const bw = (building.widthTiles || 25) * T;
  const bd = (building.heightTiles || 17) * T;
  const y = 0.18;
  const thickness = 0.34;
  const handleSpecs = [
    { side: 'north', cursor: 'ns-resize', x: bw / 2, z: -thickness, w: Math.max(1.2, bw - 0.8), d: thickness },
    { side: 'south', cursor: 'ns-resize', x: bw / 2, z: bd + thickness, w: Math.max(1.2, bw - 0.8), d: thickness },
    { side: 'west', cursor: 'ew-resize', x: -thickness, z: bd / 2, w: thickness, d: Math.max(1.2, bd - 0.8) },
    { side: 'east', cursor: 'ew-resize', x: bw + thickness, z: bd / 2, w: thickness, d: Math.max(1.2, bd - 0.8) },
  ];

  handleSpecs.forEach(spec => {
    const geo = new THREE.BoxGeometry(spec.w, 0.18, spec.d);
    const mat = new THREE.MeshBasicMaterial({
      color: 0x38bdf8,
      transparent: true,
      opacity: 0.78,
      depthWrite: false,
    });
    const handle = new THREE.Mesh(geo, mat);
    handle.name = `_buildingResizeHandle_${spec.side}`;
    handle.position.set(spec.x, y, spec.z);
    handle.renderOrder = 998;
    handle.userData.buildingResizeHandle = true;
    handle.userData.side = spec.side;
    handle.userData.cursor = spec.cursor;
    handle.userData.buildingId = building.id;
    building._group.add(handle);
    selectedBuildingResizeHandles.push(handle);
  });
}

function getBuildingResizeHandleHit(e) {
  if (editMode !== 'buildings' || !selectedBuildingResizeHandles.length) return null;
  const activeRaycaster = getPointerRaycast(e);
  const hits = activeRaycaster.intersectObjects(selectedBuildingResizeHandles, false);
  if (!hits.length) return null;
  const handle = hits[0].object;
  const buildingId = handle.userData?.buildingId;
  const building = buildingId ? buildingsMap.get(buildingId) : null;
  if (!building || building.id !== selectedBuildingId) return null;
  return { handle, building, side: handle.userData.side, hit: hits[0] };
}

function getResizeLocalBoundsForSide(building, side, hit) {
  const oldW = building.widthTiles || 25;
  const oldD = building.heightTiles || 17;
  const local = getBuildingLocalPoint(building, hit.x, hit.z);
  const edgeEpsilon = 1e-6;
  const clamp = (value, min, max) => Math.max(min, Math.min(max, value));
  const snapLeadingEdge = value => Math.ceil((value / T) - edgeEpsilon);
  const snapTrailingEdge = value => Math.floor((value / T) + edgeEpsilon);
  let left = 0;
  let top = 0;
  let right = oldW;
  let bottom = oldD;
  const minTiles = 5;
  const maxTiles = 80;

  if (side === 'east') right = clamp(snapTrailingEdge(local.x), minTiles, maxTiles);
  else if (side === 'west') left = clamp(snapLeadingEdge(local.x), oldW - maxTiles, oldW - minTiles);
  else if (side === 'south') bottom = clamp(snapTrailingEdge(local.z), minTiles, maxTiles);
  else if (side === 'north') top = clamp(snapLeadingEdge(local.z), oldD - maxTiles, oldD - minTiles);

  return {
    left,
    top,
    right,
    bottom,
    widthTiles: Math.max(minTiles, right - left),
    heightTiles: Math.max(minTiles, bottom - top),
    offsetX: left,
    offsetZ: top,
  };
}

function getBuildingAabbOriginForLocalBounds(building, bounds) {
  const points = [
    getBuildingWorldPoint(building, bounds.left * T, bounds.top * T),
    getBuildingWorldPoint(building, bounds.right * T, bounds.top * T),
    getBuildingWorldPoint(building, bounds.left * T, bounds.bottom * T),
    getBuildingWorldPoint(building, bounds.right * T, bounds.bottom * T),
  ];
  const minX = Math.min(...points.map(p => p.x));
  const minZ = Math.min(...points.map(p => p.z));
  return { worldX: Math.round(minX / T), worldY: Math.round(minZ / T) };
}

function setSelectedBuildingResizeHandlesColor(colorHex) {
  selectedBuildingResizeHandles.forEach(handle => {
    if (handle.material?.color) handle.material.color.setHex(colorHex);
  });
}

function flashSelectedBuildingResizeHandles(colorHex = 0xef4444, duration = 650) {
  setSelectedBuildingResizeHandlesColor(colorHex);
  setTimeout(() => {
    if (!_buildingResizeDrag) setSelectedBuildingResizeHandlesColor(0x38bdf8);
  }, duration);
}

function getBuildingResizeAabbTiles(building, bounds) {
  const rot = ((building?._rotation || 0) % 360 + 360) % 360;
  const swapped = rot === 90 || rot === 270;
  const origin = getBuildingAabbOriginForLocalBounds(building, bounds);
  return {
    x: origin.worldX,
    z: origin.worldY,
    w: swapped ? bounds.heightTiles : bounds.widthTiles,
    d: swapped ? bounds.widthTiles : bounds.heightTiles,
  };
}

function getTileRect(x, z, w, d) {
  return { minX: x, minZ: z, maxX: x + w, maxZ: z + d };
}

function rectsOverlap(a, b, epsilon = 0) {
  return a.minX < b.maxX - epsilon
    && a.maxX > b.minX + epsilon
    && a.minZ < b.maxZ - epsilon
    && a.maxZ > b.minZ + epsilon;
}

function rectContains(container, inner, epsilon = 0) {
  return inner.minX >= container.minX - epsilon
    && inner.maxX <= container.maxX + epsilon
    && inner.minZ >= container.minZ - epsilon
    && inner.maxZ <= container.maxZ + epsilon;
}

function rectIntersection(a, b) {
  if (!rectsOverlap(a, b)) return null;
  return {
    minX: Math.max(a.minX, b.minX),
    minZ: Math.max(a.minZ, b.minZ),
    maxX: Math.min(a.maxX, b.maxX),
    maxZ: Math.min(a.maxZ, b.maxZ),
  };
}

const RESIZE_COLLISION_EPSILON = 1e-5;

function getRectPositiveArea(rect) {
  return (rect.maxX - rect.minX) > RESIZE_COLLISION_EPSILON
    && (rect.maxZ - rect.minZ) > RESIZE_COLLISION_EPSILON;
}

function getRectAddedSegments(rect, oldRect) {
  const intersection = rectIntersection(rect, oldRect);
  if (!intersection) return [rect].filter(getRectPositiveArea);

  const segments = [];
  if (rect.minX < oldRect.minX - RESIZE_COLLISION_EPSILON) {
    segments.push({ minX: rect.minX, minZ: rect.minZ, maxX: Math.min(rect.maxX, oldRect.minX), maxZ: rect.maxZ });
  }
  if (rect.maxX > oldRect.maxX + RESIZE_COLLISION_EPSILON) {
    segments.push({ minX: Math.max(rect.minX, oldRect.maxX), minZ: rect.minZ, maxX: rect.maxX, maxZ: rect.maxZ });
  }

  const midMinX = Math.max(rect.minX, oldRect.minX);
  const midMaxX = Math.min(rect.maxX, oldRect.maxX);
  if (midMaxX - midMinX > RESIZE_COLLISION_EPSILON) {
    if (rect.minZ < oldRect.minZ - RESIZE_COLLISION_EPSILON) {
      segments.push({ minX: midMinX, minZ: rect.minZ, maxX: midMaxX, maxZ: Math.min(rect.maxZ, oldRect.minZ) });
    }
    if (rect.maxZ > oldRect.maxZ + RESIZE_COLLISION_EPSILON) {
      segments.push({ minX: midMinX, minZ: Math.max(rect.minZ, oldRect.maxZ), maxX: midMaxX, maxZ: rect.maxZ });
    }
  }

  return segments.filter(getRectPositiveArea);
}

function getBuildingResizeFootprintRect(building, bounds) {
  const box = getBuildingResizeAabbTiles(building, bounds);
  return getTileRect(box.x, box.z, box.w, box.d);
}

function getBuildingFootprintTileRect(building) {
  const bounds = getBuildingFootprintBounds(building, 0);
  return {
    minX: bounds.minX / T,
    minZ: bounds.minZ / T,
    maxX: bounds.maxX / T,
    maxZ: bounds.maxZ / T,
  };
}

function checkResizeBuildingOverlap(building, bounds) {
  const rect = getBuildingResizeFootprintRect(building, bounds);
  const oldRect = getBuildingFootprintTileRect(building);
  const addedSegments = getRectAddedSegments(rect, oldRect);
  if (!addedSegments.length) return { blocked: false };
  for (const [id, other] of buildingsMap) {
    if (id === building.id) continue;
    const otherRect = getBuildingFootprintTileRect(other);
    if (addedSegments.some(segment => rectsOverlap(segment, otherRect, RESIZE_COLLISION_EPSILON))) {
      return { blocked: true, buildingId: id };
    }
  }
  return { blocked: false };
}

function checkResizeRoadwayOverlap(building, bounds) {
  const rect = getBuildingResizeFootprintRect(building, bounds);
  const oldRect = getBuildingFootprintTileRect(building);
  const addedSegments = getRectAddedSegments(rect, oldRect);
  if (!addedSegments.length) return { blocked: false };

  for (const street of _streetSegments) {
    const streetRect = getStreetMeshTileRect(street);
    if (!streetRect) continue;
    if (addedSegments.some(segment => rectsOverlap(segment, streetRect, RESIZE_COLLISION_EPSILON))) {
      return { blocked: true, street };
    }
  }

  return { blocked: false };
}

function getStreetMeshTileRect(street) {
  if (!street) return null;
  if (street.mesh) {
    street.mesh.updateWorldMatrix?.(true, true);
    const box = new THREE.Box3().setFromObject(street.mesh);
    if (!box.isEmpty()) {
      return {
        minX: box.min.x / T,
        minZ: box.min.z / T,
        maxX: box.max.x / T,
        maxZ: box.max.z / T,
      };
    }
  }

  // Fallback mirrors the rendered street mesh dimensions, not terrain paint or
  // snap/detection buffers.
  if (street.type) {
    const cx = street.x1 + 0.5;
    const cz = street.z1 + 0.5;
    return { minX: cx - ST.HALF_W, minZ: cz - ST.HALF_W, maxX: cx + ST.HALF_W, maxZ: cz + ST.HALF_W };
  }

  const isH = Math.abs(street.x2 - street.x1) >= Math.abs(street.z2 - street.z1);
  const minX = Math.min(street.x1, street.x2);
  const maxX = Math.max(street.x1, street.x2) + 1;
  const minZ = Math.min(street.z1, street.z2);
  const maxZ = Math.max(street.z1, street.z2) + 1;
  if (isH) {
    const cz = street.z1 + 0.5;
    return { minX, minZ: cz - ST.HALF_W, maxX, maxZ: cz + ST.HALF_W };
  }
  const cx = street.x1 + 0.5;
  return { minX: cx - ST.HALF_W, minZ, maxX: cx + ST.HALF_W, maxZ };
}

function validateBuildingResizeFootprint(building, bounds) {
  if (checkResizeBuildingOverlap(building, bounds).blocked) {
    return { ok: false, reason: 'building-overlap', message: 'Resize blocked: another building is in the way.' };
  }
  const roadway = checkResizeRoadwayOverlap(building, bounds);
  if (roadway.blocked) {
    return { ok: false, reason: 'roadway-overlap', message: 'Resize blocked: footprint would cover a street.' };
  }
  return { ok: true };
}

function updateBuildingResizePreview(building, bounds, validation = { ok: true }) {
  if (!building?._group) return;
  if (!_buildingResizePreview) {
    const mat = new THREE.MeshBasicMaterial({
      color: 0xffd600,
      wireframe: true,
      transparent: true,
      opacity: 0.95,
      depthTest: false,
    });
    _buildingResizePreview = new THREE.Mesh(new THREE.BoxGeometry(1, WALL_H + 0.36, 1), mat);
    _buildingResizePreview.name = '_buildingResizePreview';
    _buildingResizePreview.renderOrder = 999;
    building._group.add(_buildingResizePreview);
  }
  const w = bounds.widthTiles * T;
  const d = bounds.heightTiles * T;
  _buildingResizePreview.geometry?.dispose?.();
  _buildingResizePreview.geometry = new THREE.BoxGeometry(w + 0.18, WALL_H + 0.36, d + 0.18);
  _buildingResizePreview.position.set((bounds.left * T) + w / 2, WALL_H / 2, (bounds.top * T) + d / 2);
  _buildingResizePreview.material?.color?.setHex(validation.ok ? 0xffd600 : 0xef4444);
  setSelectedBuildingResizeHandlesColor(validation.ok ? 0x38bdf8 : 0xef4444);
}

function shiftBuildingLocalContents(building, offsetX, offsetZ) {
  if (!offsetX && !offsetZ) return;
  const dx = offsetX * T;
  const dz = offsetZ * T;
  if (building.elevator) {
    building.elevator.x = Number(building.elevator.x || 0) - dx;
    building.elevator.z = Number(building.elevator.z || 0) - dz;
  }
  (building.interior?.furniture || []).forEach(item => {
    item.x = Number(item.x || 0) - dx;
    item.z = Number(item.z || 0) - dz;
  });
  (building.interior?.walls || []).forEach(wall => {
    wall.x1 = Number(wall.x1 || 0) - dx;
    wall.x2 = Number(wall.x2 || 0) - dx;
    wall.z1 = Number(wall.z1 || 0) - dz;
    wall.z2 = Number(wall.z2 || 0) - dz;
  });
  (building.outdoorArea?.nodes || []).forEach(node => {
    if (node.x != null) node.x = Number(node.x || 0) - dx;
    if (node.z != null) node.z = Number(node.z || 0) - dz;
    if (node.localX != null) node.localX = Number(node.localX || 0) - dx;
    if (node.localZ != null) node.localZ = Number(node.localZ || 0) - dz;
  });
}

function getResizeCollisionProbe(building, bounds) {
  const probe = {
    ...building,
    widthTiles: bounds.widthTiles,
    heightTiles: bounds.heightTiles,
    elevator: building.elevator ? { ...building.elevator } : null,
    interior: building.interior ? {
      ...building.interior,
      furniture: (building.interior.furniture || []).map(item => ({
        ...item,
        x: Number(item.x || 0) - bounds.offsetX * T,
        z: Number(item.z || 0) - bounds.offsetZ * T,
      })),
    } : building.interior,
  };
  return probe;
}

function applyBuildingResizeFootprint(building, bounds, { toast = true, recordUndo = true } = {}) {
  if (!building) return false;
  const oldW = building.widthTiles || 25;
  const oldD = building.heightTiles || 17;
  const newW = Math.max(5, Number(bounds.widthTiles || oldW) || oldW);
  const newD = Math.max(5, Number(bounds.heightTiles || oldD) || oldD);
  const offsetX = Number(bounds.offsetX || 0) || 0;
  const offsetZ = Number(bounds.offsetZ || 0) || 0;
  if (newW === oldW && newD === oldD && !offsetX && !offsetZ) return false;
  const oldFootprintBounds = getBuildingFootprintBounds(building, 0);
  const exteriorValidation = validateBuildingResizeFootprint(building, {
    ...bounds,
    widthTiles: newW,
    heightTiles: newD,
    offsetX,
    offsetZ,
  });
  if (!exteriorValidation.ok) {
    showToast(exteriorValidation.message || 'Resize blocked', 'error');
    flashSelectedBuildingResizeHandles(0xef4444);
    return false;
  }
  const before = recordUndo ? snapshotBuildingForUndo(building) : null;

  const shrinkingW = newW < oldW || offsetX > 0;
  const shrinkingD = newD < oldD || offsetZ > 0;
  if (shrinkingW || shrinkingD) {
    const probe = getResizeCollisionProbe(building, { ...bounds, widthTiles: newW, heightTiles: newD, offsetX, offsetZ });
    const movingSides = {
      minX: offsetX > 0,
      maxX: offsetX + newW < oldW,
      minZ: offsetZ > 0,
      maxZ: offsetZ + newD < oldD,
    };
    const { blocked, conflicting } = checkResizeFurnitureCollision(probe, newW, newD, movingSides);
    if (blocked) {
      showToast(`🚫 Interior object conflict, ${conflicting.length} furniture item${conflicting.length > 1 ? 's' : ''} would be outside walls`, 'error');
      highlightConflictingFurniture(building, conflicting);
      flashSelectedBuildingResizeHandles(0xef4444);
      return false;
    }
  }

  const origin = getBuildingAabbOriginForLocalBounds(building, { ...bounds, widthTiles: newW, heightTiles: newD });
  shiftBuildingLocalContents(building, offsetX, offsetZ);
  building.widthTiles = newW;
  building.heightTiles = newD;
  building.worldX = origin.worldX;
  building.worldY = origin.worldY;
  createBuilding3D(building);
  const resizeBounds = getBuildingFootprintBounds(building, 0);
  const bx1 = Math.floor(Math.min(oldFootprintBounds.minX, resizeBounds.minX) / CHUNK);
  const bz1 = Math.floor(Math.min(oldFootprintBounds.minZ, resizeBounds.minZ) / CHUNK);
  const bx2 = Math.floor(Math.max(oldFootprintBounds.maxX, resizeBounds.maxX) / CHUNK);
  const bz2 = Math.floor(Math.max(oldFootprintBounds.maxZ, resizeBounds.maxZ) / CHUNK);
  for (let ccx = bx1; ccx <= bx2; ccx++) {
    for (let ccz = bz1; ccz <= bz2; ccz++) {
      const chunk = loadedChunks.get(chunkKey(ccx, ccz));
      if (chunk) rebuildChunk(chunk);
    }
  }
  selectBuilding(building.id);
  persistBuilding(building);
  if (recordUndo) {
    pushUndo({
      type: 'buildingUpdate',
      buildingId: building.id,
      label: 'building resize',
      before,
      after: snapshotBuildingForUndo(building),
    });
  }
  if (toast) showToast(`📐 Resized: ${newW}×${newD}`, 'success');
  return true;
}

function getBuildingLocalPoint(building, worldX, worldZ) {
  const baseX = (building?.worldX || 0) * T;
  const baseZ = (building?.worldY || 0) * T;
  const bw = (building?.widthTiles || 25) * T;
  const bd = (building?.heightTiles || 17) * T;
  const rot = ((building?._rotation || 0) % 360 + 360) % 360;
  const relX = worldX - baseX;
  const relZ = worldZ - baseZ;

  if (rot === 90) {
    return { x: relZ, z: bd - relX };
  }
  if (rot === 180) {
    return { x: bw - relX, z: bd - relZ };
  }
  if (rot === 270) {
    return { x: bw - relZ, z: relX };
  }
  return { x: relX, z: relZ };
}

function getBuildingWorldPoint(building, localX, localZ) {
  const baseX = (building?.worldX || 0) * T;
  const baseZ = (building?.worldY || 0) * T;
  const bw = (building?.widthTiles || 25) * T;
  const bd = (building?.heightTiles || 17) * T;
  const rot = ((building?._rotation || 0) % 360 + 360) % 360;
  let x = baseX + localX;
  let z = baseZ + localZ;

  if (rot === 90) {
    x = baseX + bd - localZ;
    z = baseZ + localX;
  } else if (rot === 180) {
    x = baseX + bw - localX;
    z = baseZ + bd - localZ;
  } else if (rot === 270) {
    x = baseX + localZ;
    z = baseZ + bw - localX;
  }

  return {
    x,
    y: building?._elevationY || 0,
    z,
  };
}

function getBuildingDoorDirection(building) {
  const spec = getBuildingDoorSpec(building);
  const outside = getBuildingWorldPoint(building, spec.localCenterX, spec.localOutsideZ);
  const inside = getBuildingWorldPoint(building, spec.localCenterX, Math.max(0, spec.localOutsideZ - 1));
  const dx = (outside.x || 0) - (inside.x || 0);
  const dz = (outside.z || 0) - (inside.z || 0);
  const len = Math.hypot(dx, dz) || 1;
  return { x: dx / len, z: dz / len };
}

function getBuildingFootprintSize(building) {
  const rawW = (building?.widthTiles || 25) * T;
  const rawD = (building?.heightTiles || 17) * T;
  const rot = ((building?._rotation || 0) % 360 + 360) % 360;
  const swapped = rot === 90 || rot === 270;
  return {
    width: swapped ? rawD : rawW,
    depth: swapped ? rawW : rawD,
  };
}

function getBuildingFootprintBounds(building, padding = 0) {
  const { width, depth } = getBuildingFootprintSize(building);
  const pad = padding || 0;
  const minX = (building?.worldX || 0) * T - pad;
  const minZ = (building?.worldY || 0) * T - pad;
  return {
    minX,
    minZ,
    maxX: minX + width + pad * 2,
    maxZ: minZ + depth + pad * 2,
    width,
    depth,
    centerX: minX + (width + pad * 2) / 2,
    centerZ: minZ + (depth + pad * 2) / 2,
  };
}

function applyBuildingGroupTransform(group, building, worldX, worldZ, elevY = 0) {
  if (!group || !building) return;
  const bw = (building.widthTiles || 25) * T;
  const bd = (building.heightTiles || 17) * T;
  const rot = ((building._rotation || 0) % 360 + 360) % 360;
  group.rotation.y = -(rot * Math.PI / 180);
  let posX = worldX * T;
  let posZ = worldZ * T;
  if (rot === 90) posX += bd;
  else if (rot === 180) { posX += bw; posZ += bd; }
  else if (rot === 270) posZ += bw;
  group.position.set(posX, elevY, posZ);
}

function getObjectLocalBounds(root) {
  const bounds = new THREE.Box3();
  const invRoot = new THREE.Matrix4();
  const hasBounds = { value: false };
  root?.updateWorldMatrix?.(true, true);
  invRoot.copy(root.matrixWorld).invert();

  root?.traverse?.((obj) => {
    if (!obj.isMesh || obj === root || obj.name === '_furnitureSelectHelper' || !obj.geometry) return;
    if (!obj.geometry.boundingBox) obj.geometry.computeBoundingBox();
    const box = obj.geometry.boundingBox;
    if (!box) return;
    const corners = [
      new THREE.Vector3(box.min.x, box.min.y, box.min.z),
      new THREE.Vector3(box.min.x, box.min.y, box.max.z),
      new THREE.Vector3(box.min.x, box.max.y, box.min.z),
      new THREE.Vector3(box.min.x, box.max.y, box.max.z),
      new THREE.Vector3(box.max.x, box.min.y, box.min.z),
      new THREE.Vector3(box.max.x, box.min.y, box.max.z),
      new THREE.Vector3(box.max.x, box.max.y, box.min.z),
      new THREE.Vector3(box.max.x, box.max.y, box.max.z),
    ];
    for (const corner of corners) {
      corner.applyMatrix4(obj.matrixWorld).applyMatrix4(invRoot);
      bounds.expandByPoint(corner);
      hasBounds.value = true;
    }
  });

  return hasBounds.value ? bounds : null;
}

function updateFurnitureSelectionHelper(helper, mesh) {
  if (!helper || !mesh) return;
  const box = getObjectLocalBounds(mesh);
  if (!box) return;
  const size = box.getSize(new THREE.Vector3());
  const center = box.getCenter(new THREE.Vector3());
  helper.geometry?.dispose?.();
  helper.geometry = new THREE.BoxGeometry(size.x + 0.1, size.y + 0.1, size.z + 0.1);
  helper.position.copy(center);
}

 
// ── Floating selected-floor control ───────────────────────────
let _floorControlEl = null;
let _elevatorRelocateBuildingId = null;
let _elevatorRelocateGhost = null;

function ensureFloorControlEl() {
  if (_floorControlEl) return _floorControlEl;
  const el = document.createElement('div');
  el.id = 'buildingFloorControl';
  el.style.cssText = 'position:fixed;display:none;z-index:1100;transform:translate(-50%,-50%);padding:7px 8px;border:1px solid rgba(255,214,0,.55);border-radius:14px;background:rgba(15,18,32,.68);backdrop-filter:blur(8px);box-shadow:0 8px 24px rgba(0,0,0,.32);color:#fff;font-family:system-ui,sans-serif;font-size:12px;pointer-events:auto;min-width:76px;text-align:center;';
  el.innerHTML = `
    <button data-act="up" title="Floor up" style="width:100%;border:0;border-radius:8px;background:rgba(255,255,255,.14);color:#fff;cursor:pointer;padding:2px 0">▲</button>
    <div style="display:flex;align-items:center;justify-content:center;gap:3px;margin:4px 0">
      <input data-role="floor" type="number" min="1" value="1" style="width:34px;text-align:center;border:1px solid rgba(255,255,255,.25);border-radius:6px;background:rgba(0,0,0,.35);color:#fff;padding:2px 1px;font-size:12px">
      <span data-role="total" style="opacity:.85">/1</span>
    </div>
    <button data-act="down" title="Floor down" style="width:100%;border:0;border-radius:8px;background:rgba(255,255,255,.14);color:#fff;cursor:pointer;padding:2px 0">▼</button>
  `;
  el.addEventListener('click', (e) => {
    const btn = e.target.closest('[data-act]');
    if (!btn || !selectedBuildingId) return;
    const b = buildingsMap.get(selectedBuildingId);
    if (!b) return;
    const total = getBuildingFloorCount(b);
    const cur = getActiveBuildingFloor(b);
    if (btn.dataset.act === 'up') window._setBldFloor(selectedBuildingId, Math.min(total, cur + 1));
    if (btn.dataset.act === 'down') window._setBldFloor(selectedBuildingId, Math.max(1, cur - 1));
  });
  el.querySelector('[data-role="floor"]')?.addEventListener('change', (e) => {
    if (!selectedBuildingId) return;
    window._setBldFloor(selectedBuildingId, Number(e.target.value) || 1);
  });
  document.body.appendChild(el);
  _floorControlEl = el;
  return el;
}

function updateFloorControlPanel() {
  const el = ensureFloorControlEl();
  const b = selectedBuildingId ? buildingsMap.get(selectedBuildingId) : null;
  if (!b || isOutsideSpaceBuilding(b) || getBuildingFloorCount(b) < 2) {
    el.style.display = 'none';
    return;
  }
  const active = getActiveBuildingFloor(b);
  const total = getBuildingFloorCount(b);
  const input = el.querySelector('[data-role="floor"]');
  const totalEl = el.querySelector('[data-role="total"]');
  if (input) { input.max = String(total); input.value = String(active); }
  if (totalEl) totalEl.textContent = `/${total}`;
  el.style.display = 'block';
  updateFloorControlPosition();
}

function updateFloorControlPosition() {
  if (!_floorControlEl || _floorControlEl.style.display === 'none' || !selectedBuildingId) return;
  const b = buildingsMap.get(selectedBuildingId);
  if (!b) return;
  const door = getBuildingDoorPosAPI(b);
  const dir = getBuildingDoorDirection(b);
  const world = new THREE.Vector3((door.x / API_TILE) + dir.x * 1.6, 1.2, (door.y / API_TILE) + dir.z * 1.6);
  world.project(camera);
  const rect = renderer.domElement.getBoundingClientRect();
  _floorControlEl.style.left = `${rect.left + (world.x * 0.5 + 0.5) * rect.width}px`;
  _floorControlEl.style.top = `${rect.top + (-world.y * 0.5 + 0.5) * rect.height}px`;
}

function cancelElevatorRelocateMode() {
  _elevatorRelocateBuildingId = null;
  if (_elevatorRelocateGhost) { scene.remove(_elevatorRelocateGhost); _elevatorRelocateGhost = null; }
}

function updateElevatorRelocatePreview(worldX, worldZ) {
  const b = _elevatorRelocateBuildingId ? buildingsMap.get(_elevatorRelocateBuildingId) : null;
  if (!b) return;
  const local = getBuildingLocalPoint(b, worldX, worldZ);
  normalizeBuildingFloors(b);
  const bw = (b.widthTiles || 25) * T;
  const bd = (b.heightTiles || 17) * T;
  const x = Math.max(ELEVATOR_SIZE / 2 + 0.25, Math.min(bw - ELEVATOR_SIZE / 2 - 0.25, local.x));
  const z = Math.max(ELEVATOR_SIZE / 2 + 0.25, Math.min(bd - ELEVATOR_SIZE / 2 - 0.25, local.z));
  const world = getBuildingWorldPoint(b, x, z);
  if (!_elevatorRelocateGhost) {
    _elevatorRelocateGhost = new THREE.Group();
    _elevatorRelocateGhost.name = 'elevatorRelocateGhost';
    const base = posVox(0, 0.06, 0, ELEVATOR_SIZE, 0.12, ELEVATOR_SIZE, 0x59636b);
    const back = posVox(0, WALL_H * 0.5, -ELEVATOR_SIZE / 2, ELEVATOR_SIZE, WALL_H, 0.08, 0x2f3438);
    const left = posVox(-ELEVATOR_SIZE / 2, WALL_H * 0.5, 0, 0.08, WALL_H, ELEVATOR_SIZE, 0x2f3438);
    const right = posVox(ELEVATOR_SIZE / 2, WALL_H * 0.5, 0, 0.08, WALL_H, ELEVATOR_SIZE, 0x2f3438);
    const doorL = posVox(-ELEVATOR_SIZE * 0.255, WALL_H * 0.45, ELEVATOR_SIZE / 2 + 0.05, ELEVATOR_SIZE * 0.51, WALL_H * 0.78, 0.08, 0x9aa0a6);
    const doorR = posVox(ELEVATOR_SIZE * 0.255, WALL_H * 0.45, ELEVATOR_SIZE / 2 + 0.05, ELEVATOR_SIZE * 0.51, WALL_H * 0.78, 0.08, 0x8b9298);
    const ghostHeader = posVox(0, WALL_H * 0.92, ELEVATOR_SIZE / 2 + 0.055, ELEVATOR_SIZE * 1.02, WALL_H * 0.16, 0.1, 0x717a82);
    const ghostLeftTrim = posVox(-ELEVATOR_SIZE * 0.51, WALL_H * 0.5, ELEVATOR_SIZE / 2 + 0.055, 0.12, WALL_H, 0.1, 0x717a82);
    const ghostRightTrim = posVox(ELEVATOR_SIZE * 0.51, WALL_H * 0.5, ELEVATOR_SIZE / 2 + 0.055, 0.12, WALL_H, 0.1, 0x717a82);
    const outline = new THREE.Mesh(
      new THREE.BoxGeometry(ELEVATOR_SIZE + 0.16, WALL_H + 0.16, ELEVATOR_SIZE + 0.16),
      new THREE.MeshBasicMaterial({ color: 0xffd600, wireframe: true, transparent: true, opacity: 0.9, depthWrite: false })
    );
    outline.position.set(0, WALL_H / 2, 0);
    _elevatorRelocateGhost.add(base, back, left, right, doorL, doorR, ghostHeader, ghostLeftTrim, ghostRightTrim, outline);
    scene.add(_elevatorRelocateGhost);
  }
  _elevatorRelocateGhost.position.set(world.x, 0.28, world.z);
}

function commitElevatorRelocate(worldX, worldZ) {
  const b = _elevatorRelocateBuildingId ? buildingsMap.get(_elevatorRelocateBuildingId) : null;
  if (!b) return false;
  const local = getBuildingLocalPoint(b, worldX, worldZ);
  const bw = (b.widthTiles || 25) * T;
  const bd = (b.heightTiles || 17) * T;
  b.elevator = {
    ...(b.elevator || {}),
    x: Math.max(ELEVATOR_SIZE / 2 + 0.25, Math.min(bw - ELEVATOR_SIZE / 2 - 0.25, local.x)),
    z: Math.max(ELEVATOR_SIZE / 2 + 0.25, Math.min(bd - ELEVATOR_SIZE / 2 - 0.25, local.z)),
    width: ELEVATOR_SIZE,
    depth: ELEVATOR_SIZE,
  };
  normalizeBuildingFloors(b);
  cancelElevatorRelocateMode();
  createBuilding3D(b);
  selectBuilding(b.id);
  persistBuilding(b);
  showToast('🛗 Elevator moved on every floor', 'success');
  return true;
}

function selectBuilding(id) {
  const previousSelectedId = selectedBuildingId;
  clearSelectedBuildingHelper();
  clearSelectedBuildingResizeHandles();
  if (previousSelectedId && previousSelectedId !== id) {
    const prev = buildingsMap.get(previousSelectedId);
    if (prev) createBuilding3D(prev);
  }

  selectedBuildingId = id;
  const b = buildingsMap.get(id);
  if (!b) return;
  if (isOutsideSpaceBuilding(b)) {
    if (insideBuildingId) exitBuilding(/*silent=*/true);
    cancelInteriorWallPlacement();
    _deselectInteriorWall();
    document.getElementById('interiorWallTools')?.style.setProperty('display', 'none');
  }
  if (getBuildingFloorCount(b) > 1) createBuilding3D(b);

  // Draw glowing yellow outline around selected building in building-local space,
  // so it stays aligned after rotation.
  if (b._group) {
    const bw = b.widthTiles * T;
    const bd = b.heightTiles * T;
    const bh = WALL_H + 0.2;
    const outlineGeo = new THREE.BoxGeometry(bw + 0.3, bh + 0.3, bd + 0.3);
    const outlineMat = new THREE.MeshBasicMaterial({
      color: 0xffd600,
      wireframe: true,
      transparent: true,
      opacity: 0.7,
    });
    selectedBuildingHelper = new THREE.Mesh(outlineGeo, outlineMat);
    selectedBuildingHelper.position.set(bw / 2, bh / 2, bd / 2);
    b._group.add(selectedBuildingHelper);
    addSelectedBuildingResizeHandles(b);
  }

  showToast(`Selected: ${b.name}`, 'warning');
  updateBuildingEditPanel(b);
  updateFloorControlPanel();
}

function deselectBuilding() {
  const previousSelectedId = selectedBuildingId;
  clearSelectedBuildingHelper();
  clearSelectedBuildingResizeHandles();
  selectedBuildingId = null;
  clearExteriorFloorHover();
  if (previousSelectedId) {
    const previous = buildingsMap.get(previousSelectedId);
    if (previous) {
      // Rebuild after clearing selection so multi-floor focus turns off and
      // every floor returns under the currently selected view mode (solid,
      // no-roof, active-walls, or xray).
      createBuilding3D(previous);
      applyBuildingViewMode(previous, getEffectiveBuildingViewMode(previous));
    }
  }
  updateBuildingEditPanel(null);
  updateFloorControlPanel();
}

// Animate building selection outline (pulsing opacity)
function updateBuildingSelectionOutline() {
  if (selectedBuildingHelper && selectedBuildingHelper.material) {
    selectedBuildingHelper.material.opacity = 0.45 + Math.sin(performance.now() * 0.004) * 0.25;
  }
}

function clearExteriorFloorHover() {
  for (const mesh of _exteriorFloorHoverMeshes) {
    if (!mesh?.material) continue;
    if (mesh.userData?._hoverOriginalColor != null) mesh.material.color.setHex(mesh.userData._hoverOriginalColor);
    if (mesh.material.emissive && mesh.userData?._hoverOriginalEmissive != null) mesh.material.emissive.setHex(mesh.userData._hoverOriginalEmissive);
    if (mesh.userData?._hoverOriginalOpacity != null) {
      mesh.material.opacity = mesh.userData._hoverOriginalOpacity;
      mesh.material.transparent = mesh.userData._hoverOriginalTransparent || false;
    }
    mesh.material.needsUpdate = true;
  }
  _exteriorFloorHoverMeshes = [];
  _hoveredExteriorFloor = null;
}

function setExteriorFloorHover(buildingId, floor) {
  floor = Math.max(1, Number(floor) || 1);
  if (_hoveredExteriorFloor?.buildingId === buildingId && _hoveredExteriorFloor?.floor === floor) return;
  clearExteriorFloorHover();
  const b = buildingsMap.get(buildingId);
  if (!b?._group) return;
  if (!isExteriorFloorSelectable(b, buildingId, floor)) return;
  b._group.traverse(obj => {
    if (!obj.isMesh || !obj.userData?.exteriorFloorPick) return;
    if (Math.max(1, Number(obj.userData.floor || 1) || 1) !== floor) return;
    if (!obj.visible || !obj.material) return;
    if (!obj.userData._hoverMaterialCloned) {
      obj.material = obj.material.clone();
      obj.userData._hoverMaterialCloned = true;
    }
    obj.userData._hoverOriginalColor = obj.material.color?.getHex?.() ?? null;
    obj.userData._hoverOriginalEmissive = obj.material.emissive?.getHex?.() ?? null;
    obj.userData._hoverOriginalOpacity = obj.material.opacity;
    obj.userData._hoverOriginalTransparent = obj.material.transparent;
    obj.material.color.lerp(new THREE.Color(0xffd600), 0.42);
    if (obj.material.emissive) obj.material.emissive.setHex(0x5a4300);
    obj.material.transparent = true;
    obj.material.opacity = Math.max(0.86, obj.material.opacity || 1);
    obj.material.needsUpdate = true;
    _exteriorFloorHoverMeshes.push(obj);
  });
  _hoveredExteriorFloor = { buildingId, floor };
}

function isExteriorFloorSelectable(building, buildingId, floor) {
  if (!building) return false;
  const pickedFloor = Math.max(1, Number(floor) || 1);
  // When already focused inside this building, exterior floor picking is only
  // for moving down. The active floor should not advertise itself as a selectable
  // target, and higher floors are intentionally hidden by focus mode.
  if (insideBuildingId === buildingId) {
    return pickedFloor < getActiveBuildingFloor(building);
  }
  return true;
}

function getExteriorFloorWallHit(e) {
  if (!renderer || !camera) return null;
  const activeRaycaster = getPointerRaycast(e);
  const pickMeshes = [];
  buildingGroup.traverse(obj => {
    if (!obj.isMesh || !obj.userData?.exteriorFloorPick || !obj.visible) return;
    pickMeshes.push(obj);
  });
  if (!pickMeshes.length) return null;
  const hits = activeRaycaster.intersectObjects(pickMeshes, false);
  if (!hits.length) return null;
  const mesh = hits[0].object;
  const buildingId = mesh.userData?.buildingId || mesh.parent?.userData?.buildingId;
  const building = buildingId ? buildingsMap.get(buildingId) : null;
  if (!building) return null;
  const floor = Math.max(1, Number(mesh.userData?.floor || 1) || 1);
  // Important: do this after raycasting all visible floor pick meshes. The active
  // floor should block the ray, not be filtered out first; otherwise clicks pass
  // through it and accidentally select lower floors underneath.
  if (!isExteriorFloorSelectable(building, buildingId, floor)) return null;
  return {
    hit: hits[0],
    mesh,
    building,
    buildingId,
    floor,
  };
}

// ═══════════════════════════════════════════════════════════════
// LOD — LEVEL OF DETAIL (run once per second)
// ═══════════════════════════════════════════════════════════════
function updateBuildingLOD() {
  for (const [, b] of buildingsMap) {
    if (!b._group) continue;
    const bounds = getBuildingFootprintBounds(b, 0);
    const bCenterX = bounds.centerX;
    const bCenterZ = bounds.centerZ;

    // Distance from camera target (good approximation for isometric camera)
    const dx = bCenterX - camTarget.x;
    const dz = bCenterZ - camTarget.z;
    const dist = Math.sqrt(dx * dx + dz * dz);

    b._group.traverse(obj => {
      if (!obj.isMesh) return;
      if (obj.userData?.pingPongRuntimeVisual) {
        return;
      }
      const n = obj.name || '';
      const isFurniture = n.startsWith('furniture') || obj.userData.furniture;
      const isDoor = n === 'door' || obj.userData.door;
      const isStructural = n === 'roof' || n.startsWith('wall-') || n === 'window' || n === 'interior-wall';

      // Never touch structural elements (roof/walls/windows/interior walls) — view mode controls those
      if (isStructural) return;

      if (dist > 40) {
        if (isFurniture || isDoor) obj.visible = false;
      } else if (dist > 20) {
        if (isFurniture) obj.visible = true;
        if (isDoor) obj.visible = false;
      } else {
        obj.visible = true;
      }
    });
  }
}

// ═══════════════════════════════════════════════════════════════
// TOOLBAR & EDIT MODES
// ═══════════════════════════════════════════════════════════════
function getCurrentLicenseStatus() {
  return window.__VWLicense || window.__VWConfig?.license || null;
}

function isDemoLicenseActive() {
  const license = getCurrentLicenseStatus();
  return Boolean(license && license.trial !== false && !license.licensed);
}

function isLicenseFeatureLocked(feature = 'advancedEditor') {
  const license = getCurrentLicenseStatus();
  if (!license) return false;
  if (!isDemoLicenseActive()) return false;
  const limits = license.limits || {};
  return limits[feature] === false || feature === 'advancedEditor' || feature === 'editPanel';
}

function showLicenseLockedToast(feature = 'this feature') {
  showToast(`🔒 Demo mode: ${feature} requires a license key.`, 'warning');
}

function ensureEditorUnlocked(featureLabel = 'Editing') {
  if (!isLicenseFeatureLocked('advancedEditor')) return true;
  setEditMode(null, { silent: true, force: true });
  const leftSidebar = document.getElementById('leftSidebar');
  if (leftSidebar && !leftSidebar.classList.contains('left-sidebar-collapsed')) {
    leftSidebar.classList.add('left-sidebar-collapsed');
    updateMiniMapPosition();
  }
  showLicenseLockedToast(featureLabel);
  return false;
}

function setupToolbar() {
  const on = (id, fn) => document.getElementById(id)?.addEventListener('click', fn);

  on('btn-select', () => setEditMode(null));
  on('btn-mode-world', () => toggleEditMode('world'));
  on('btn-mode-roads', () => toggleEditMode('roads'));
  on('btn-mode-buildings', () => toggleEditMode('buildings'));
  on('btn-mode-outside', () => toggleEditMode('outside'));
  on('btn-undo', () => { if (ensureEditorUnlocked('Undo')) doUndo(); });
  on('btn-redo', () => { if (ensureEditorUnlocked('Redo')) doRedo(); });
  on('btn-save', () => { if (ensureEditorUnlocked('Saving edits')) saveAll(); });
  on('btn-help', () => { document.getElementById('shortcutsModal')?.classList.add('visible'); });
  on('btn-chatExpandAll', () => {
    if (typeof window._chatExpandAll === 'function') window._chatExpandAll();
    showToast('💬 Expanded all chat bubbles', 'info');
  });
  on('btn-chatMinimizeAll', () => {
    if (typeof window._chatMinimizeAll === 'function') window._chatMinimizeAll();
    showToast('💬 Minimized all chat bubbles', 'info');
  });
  // Defensive fallback: chat.js owns the real chat behavior, but if its toggle
  // listener fails or hasn't attached yet, keep the chat button from feeling dead.
  const chatToggle = document.getElementById('chat-toggle');
  chatToggle?.addEventListener('click', () => {
    const panel = document.getElementById('chat-panel');
    const wasOpen = panel?.classList.contains('open');
    setTimeout(() => {
      if (!panel || panel.classList.contains('open') !== wasOpen) return;
      const shouldOpen = !wasOpen;
      panel.classList.toggle('open', shouldOpen);
      chatToggle.classList.toggle('active', shouldOpen);
      chatToggle.style.display = shouldOpen ? 'none' : 'flex';
      document.getElementById('chat-exterior-tabs')?.classList.toggle('visible', shouldOpen);
      if (shouldOpen) panel.querySelector('.chat-input')?.focus();
    }, 80);
  });
  on('btn-settings', () => {
    syncMovementDebugOverlayUi();
    syncObjectActionPointDebugUi();
    document.getElementById('settingsModal').style.display = 'flex';
  });
  const movementDebugToggle = document.getElementById('setting-movementDebugOverlays');
  if (movementDebugToggle && !movementDebugToggle.dataset.bound) {
    movementDebugToggle.dataset.bound = '1';
    movementDebugToggle.addEventListener('change', () => {
      setMovementDebugOverlaysEnabled(movementDebugToggle.checked);
    });
  }
  const objectActionPointDebugToggle = document.getElementById('setting-objectActionPointDebug');
  if (objectActionPointDebugToggle && !objectActionPointDebugToggle.dataset.bound) {
    objectActionPointDebugToggle.dataset.bound = '1';
    objectActionPointDebugToggle.addEventListener('change', () => {
      setObjectActionPointDebugEnabled(objectActionPointDebugToggle.checked);
    });
  }
  on('btn-zoomIn', () => { camDist = Math.max(4.5, camDist * 0.7); updateCamera(); });
  on('btn-zoomOut', () => { camDist = Math.min(120, camDist * 1.3); updateCamera(); });
  on('btn-zoomReset', resetCamera);
  on('btn-rotateL', () => { _camAngleTarget -= Math.PI / 4; _camRotating = true; updateActiveWalls(); });
  on('btn-rotateR', () => { _camAngleTarget += Math.PI / 4; _camRotating = true; updateActiveWalls(); });

  // Build the decoration palette. Terrain constants and painting still exist
  // for road/pathing internals, but direct terrain UI is disabled because the
  // terrain swatches are not reliable enough for the main editor.
  buildTerrainPalette();
  buildRoadPalette();
}

function toggleGrid() {
  _gridVisible = !_gridVisible;
  if (_gridVisible) {
    if (!_gridHelper) {
      _gridHelper = new THREE.GridHelper(200, 200, 0x444444, 0x222222);
      _gridHelper.position.y = 0.02;
      _gridHelper.material.transparent = true;
      _gridHelper.material.opacity = 0.35;
    }
    scene.add(_gridHelper);
    showToast('⊞ Grid ON (G to toggle)', 'warning');
  } else {
    if (_gridHelper) scene.remove(_gridHelper);
    showToast('⊟ Grid OFF', 'warning');
  }
}

function toggleEditMode(modeName) {
  if (modeName && !ensureEditorUnlocked('Edit tools')) return;
  setEditMode(editMode === modeName ? null : modeName);
}

function setEditMode(m, options = {}) {
  if (m && isLicenseFeatureLocked('advancedEditor') && !options.force) {
    if (!options.silent) showLicenseLockedToast('Edit tools');
    m = null;
  }
  editMode = m;
  placementMode = null;
  if (renderer?.domElement && m !== 'buildings') renderer.domElement.style.cursor = '';
  if (placementGhost) { scene.remove(placementGhost); placementGhost = null; }
  cancelDecorationPlacement();
  // Clean up street snap ghost
  if (_streetSnapGhost) { scene.remove(_streetSnapGhost); _streetSnapGhost = null; _streetSnapTarget = null; }
  // Hide grid when leaving edit mode
  if (!m && _gridVisible) {
    _gridVisible = false;
    if (_gridHelper) scene.remove(_gridHelper);
  }

  document.querySelectorAll('.mode-btn').forEach(b => b.classList.remove('active'));
  document.getElementById('btn-select')?.classList.toggle('active', !m);
  if (m) document.getElementById(`btn-mode-${m}`)?.classList.add('active');

  // Show/hide edit sections in left sidebar
  document.getElementById('terrainPalette')?.classList.toggle('visible', m === 'world');
  document.getElementById('roadPalette')?.classList.toggle('visible', m === 'roads');
  document.getElementById('buildingEditPanel')?.classList.toggle('visible', m === 'buildings');
  document.getElementById('outsideSpaceEditPanel')?.classList.toggle('visible', m === 'outside');
  document.querySelectorAll('.edit-mode-group').forEach(group => {
    group.classList.toggle('open', group.dataset.mode === m);
  });

  // Do not auto-open the left edit sidebar. Mobile users found this intrusive;
  // the panel should only open/close from its explicit toggle.
  updateMiniMapPosition();
  // Cancel furniture placement if leaving buildings mode
  const selectedOutsideSpace = selectedBuildingId ? buildingsMap.get(selectedBuildingId) : null;
  const showFurniture = m === 'buildings' && (!!insideBuildingId || isOutsideSpaceBuilding(selectedOutsideSpace));
  if (!showFurniture) cancelFurniturePlacement();
  if (!(m === 'buildings' && insideBuildingId)) {
    cancelInteriorWallPlacement();
    _deselectInteriorWall();
  }
  const activeInteriorBuilding = insideBuildingId ? buildingsMap.get(insideBuildingId) : null;
  document.getElementById('interiorWallTools')?.style.setProperty('display', m === 'buildings' && !!activeInteriorBuilding && !isOutsideSpaceBuilding(activeInteriorBuilding) ? 'block' : 'none');

  if (m === 'roads') selectedTerrain = TERRAIN.ROAD;
  if (m === 'world') selectedTerrain = TERRAIN.GRASS;
  if (m !== 'world') clearSelectedPlacedDecoration();
  if (m && !options.silent) showToast(`Mode: ${m}`, 'warning');
}

function buildTerrainPalette() {
  const palette = document.getElementById('terrainPalette');
  if (!palette) return;
  palette.innerHTML = '';

  const decorLabel = document.createElement('div');
  decorLabel.className = 'palette-section-label';
  decorLabel.textContent = '🪴 Decorations';
  palette.appendChild(decorLabel);

  const decorRow = document.createElement('div');
  decorRow.style.cssText = 'display:flex;flex-wrap:wrap;gap:4px';
  Object.entries(DECORATION_DEFS).forEach(([type, def]) => {
    const btn = document.createElement('div');
    btn.className = 'terrain-swatch decor-btn';
    btn.style.cssText = 'background:#2d3a2e;min-width:52px;font-size:13px';
    btn.title = def.label;
    btn.innerHTML = `<span class="swatch-label">${def.icon} ${def.label.split(' ')[1]}</span>`;
    btn.dataset.decorType = type;
    btn.addEventListener('click', () => {
      if (decorationPlacementType === type) {
        // Toggle off
        cancelDecorationPlacement();
        btn.classList.remove('active');
      } else {
        cancelDecorationPlacement();
        decorationPlacementType = type;
        // Deselect other decoration buttons.
        palette.querySelectorAll('.terrain-swatch').forEach(s => s.classList.remove('active'));
        btn.classList.add('active');
        startDecorationPlacement(type);
      }
    });
    decorRow.appendChild(btn);
  });
  palette.appendChild(decorRow);

  const selectionCard = document.createElement('div');
  selectionCard.className = 'decoration-selection-card';
  selectionCard.innerHTML = `
    <div id="selectedDecorationText" class="palette-hint">No decoration selected</div>
    <button id="btn-deleteDecoration" class="sidebar-action-btn bld-edit-btn-danger" disabled>🗑️ Delete selected</button>
  `;
  palette.appendChild(selectionCard);
  selectionCard.querySelector('#btn-deleteDecoration')?.addEventListener('click', deleteSelectedPlacedDecoration);
  updateDecorationSelectionPanel();
}

function startDecorationPlacement(type) {
  cancelDecorationPlacement();
  clearSelectedPlacedDecoration();
  decorationPlacementType = type;
  decorationGhost = makeDecorationGhost(type);
  scene.add(decorationGhost);
  showToast(`🪴 Click terrain to place ${DECORATION_DEFS[type]?.label || type}`, 'warning');
}

function cancelDecorationPlacement() {
  decorationPlacementType = null;
  if (decorationGhost) { scene.remove(decorationGhost); decorationGhost = null; }
}

// ═══════════════════════════════════════════════════════════════
// STREET SYSTEM — 3D Road Meshes with Curb & Gutter
// ═══════════════════════════════════════════════════════════════
// Streets are stored as segments and rendered as 3D geometry.
// Cross-section (perpendicular): Sidewalk | Curb | Gutter | Lane | Center | Lane | Gutter | Curb | Sidewalk
// Heights: sidewalk=0.3, curb top=0.3, curb face=0.3→0.18, gutter=0.15, road=0.18

let _streetDrawStart = null;    // {x, z} world tile coords
let _streetDrawGhost = null;    // preview mesh
let _streetTool = 'line';       // 'line' | 'x-int' | 't-int' | 'right-turn' | 'left-turn' | 'erase'
let _streetPieceRotation = 0;   // 0, 90, 180, 270 — rotation for intersection/turn pieces
let _streetSnapGhost = null;    // ghost mesh for intersection/turn tool snap preview
let _streetSnapTarget = null;   // {x, z} snapped tile coords for intersection/turn
const _streetSegments = [];     // [{x1,z1,x2,z2,dir,mesh}, ...]
let _streetGroup = null;        // THREE.Group for all street meshes

// Street dimensions (in world units = tiles)
const ST = {
  SIDEWALK_W: 2.0,   // sidewalk width
  CURB_W: 0.3,       // curb width
  GUTTER_W: 0.35,    // gutter width
  LANE_W: 2.5,       // each travel lane (wider for car centering)
  CENTER_W: 0.3,     // center line area
  BASE: 0.2,         // base elevation (match terrain tH so road sits ON grass, not inside it)
  SIDEWALK_H: 0.18,  // sidewalk thickness (above base)
  ROAD_THICK: 0.08,  // road slab thickness
  GUTTER_DIP: 0.04,  // how far gutter dips below road
  CURB_RISE: 0.12,   // how far curb rises above road
};
// Total half-width: SIDEWALK + CURB + GUTTER + LANE + CENTER/2
ST.HALF_W = ST.SIDEWALK_W + ST.CURB_W + ST.GUTTER_W + ST.LANE_W + ST.CENTER_W / 2; // ~3.85
ST.FULL_W = ST.HALF_W * 2; // ~7.7 tiles total width

let _streetLampGroup = null;      // THREE.Group for street light poles
let _streetLampDebounce = null;   // debounce timer for light pole rebuild
let _streetLampPhysicsIds = [];   // physics collider IDs for street lamps (for cleanup)
const LAMP_SPACING = 8;           // tiles between light poles (equal spacing)

function initStreetGroup() {
  _streetGroup = new THREE.Group();
  _streetGroup.name = 'streets';
  scene.add(_streetGroup);

  _streetLampGroup = new THREE.Group();
  _streetLampGroup.name = 'streetLamps';
  scene.add(_streetLampGroup);

  _trafficLightGroup = new THREE.Group();
  _trafficLightGroup.name = 'trafficLights';
  scene.add(_trafficLightGroup);
}

/**
 * Rebuild all street light poles along sidewalks at equal spacing.
 * Called whenever street segments change (add/remove/connect).
 * Poles are placed on the sidewalk (offset from road center) at equal intervals.
 *
 * KEY: When segments connect or split, the pole spacing is recalculated per-chain
 * so poles are always equally spaced regardless of where segments were joined.
 * This prevents clusters of too-close poles or gaps of too-far poles at junctions.
 */
function _rebuildStreetLightPoles() {
  if (!_streetLampGroup) return;

  // Clear existing poles and their physics colliders
  while (_streetLampGroup.children.length > 0) {
    _streetLampGroup.remove(_streetLampGroup.children[0]);
  }
  for (const pid of _streetLampPhysicsIds) {
    removeBody(pid);
  }
  _streetLampPhysicsIds = [];

  // Step 1: Build connected chains of collinear segments.
  // Segments that share endpoints (directly or through intersections) and run
  // along the same axis form a single chain for pole spacing calculation.
  // This ensures that when segments get connected via intersections, the poles
  // are recalculated for the entire combined length — no clusters or gaps.
  const straightSegs = _streetSegments.filter(s => !s.type);
  if (straightSegs.length === 0) return;

  // Build a set of intersection positions for bridge-through detection
  const intersectionSet = new Set();
  for (const seg of _streetSegments) {
    if (seg.type) intersectionSet.add(`${seg.x1},${seg.z1}`);
  }

  // Build endpoint adjacency: group segments that connect end-to-end on same axis.
  // Also connect through intersection nodes — if two collinear segments have endpoints
  // near the same intersection, they belong to the same chain.
  const used = new Set();
  const chains = []; // each chain: { isH, fixedCoord, minV, maxV, totalLen }

  // Helper: check if two endpoints are connected (directly or through an intersection)
  const snapDist = Math.round(ST.HALF_W) + 2; // intersection bridge distance
  function endpointsConnect(ax, az, bx, bz) {
    // Direct endpoint match
    if (ax === bx && az === bz) return true;
    // Connected through a nearby intersection
    for (const iKey of intersectionSet) {
      const [ixs, izs] = iKey.split(',').map(Number);
      const dA = Math.abs(ax - ixs) + Math.abs(az - izs);
      const dB = Math.abs(bx - ixs) + Math.abs(bz - izs);
      if (dA <= snapDist && dB <= snapDist) return true;
    }
    return false;
  }

  for (let si = 0; si < straightSegs.length; si++) {
    if (used.has(si)) continue;
    const seg = straightSegs[si];
    const dx = seg.x2 - seg.x1;
    const dz = seg.z2 - seg.z1;
    const isH = Math.abs(dx) >= Math.abs(dz);

    // Collect all connected collinear segments into this chain via flood fill
    const chainIdxs = [si];
    used.add(si);
    let changed = true;
    while (changed) {
      changed = false;
      for (let sj = 0; sj < straightSegs.length; sj++) {
        if (used.has(sj)) continue;
        const s2 = straightSegs[sj];
        const d2x = s2.x2 - s2.x1;
        const d2z = s2.z2 - s2.z1;
        const isH2 = Math.abs(d2x) >= Math.abs(d2z);
        if (isH !== isH2) continue; // different axis

        // Check if s2 connects to any segment in the chain (directly or through intersection)
        let connects = false;
        for (const ci of chainIdxs) {
          const sc = straightSegs[ci];
          // Check all 4 endpoint pairs
          for (const [eax, eaz] of [[s2.x1, s2.z1], [s2.x2, s2.z2]]) {
            for (const [ebx, ebz] of [[sc.x1, sc.z1], [sc.x2, sc.z2]]) {
              if (endpointsConnect(eax, eaz, ebx, ebz)) {
                // For horizontal chains, verify same Z; for vertical, same X
                if (isH && Math.abs((s2.z1 + s2.z2) / 2 - (sc.z1 + sc.z2) / 2) < 2) { connects = true; }
                if (!isH && Math.abs((s2.x1 + s2.x2) / 2 - (sc.x1 + sc.x2) / 2) < 2) { connects = true; }
              }
              if (connects) break;
            }
            if (connects) break;
          }
          if (connects) break;
        }
        if (connects) {
          chainIdxs.push(sj);
          used.add(sj);
          changed = true;
        }
      }
    }

    // Collect all endpoints of this chain + any bridging intersections, find total extent
    let minV = Infinity, maxV = -Infinity;
    const fixedCoord = isH ? seg.z1 : seg.x1;
    for (const ci of chainIdxs) {
      const sc = straightSegs[ci];
      if (isH) {
        minV = Math.min(minV, sc.x1, sc.x2);
        maxV = Math.max(maxV, sc.x1, sc.x2);
      } else {
        minV = Math.min(minV, sc.z1, sc.z2);
        maxV = Math.max(maxV, sc.z1, sc.z2);
      }
    }
    // Extend through any intersections that bridge the chain endpoints
    for (const iKey of intersectionSet) {
      const [ixs, izs] = iKey.split(',').map(Number);
      if (isH) {
        if (Math.abs(izs - fixedCoord) < 2) {
          // Check if this intersection is near either end of the chain
          if (ixs >= minV - snapDist && ixs <= maxV + snapDist) {
            minV = Math.min(minV, ixs);
            maxV = Math.max(maxV, ixs);
          }
        }
      } else {
        if (Math.abs(ixs - fixedCoord) < 2) {
          if (izs >= minV - snapDist && izs <= maxV + snapDist) {
            minV = Math.min(minV, izs);
            maxV = Math.max(maxV, izs);
          }
        }
      }
    }
    chains.push({ isH, fixedCoord, minV, maxV, totalLen: maxV - minV });
  }

  // Step 2: For each chain, calculate equally-spaced pole positions
  const polePositions = [];
  const poleSet = new Set(); // dedup key
  const swOff = ST.LANE_W + ST.CENTER_W / 2 + ST.GUTTER_W + ST.CURB_W + ST.SIDEWALK_W / 2;

  for (const chain of chains) {
    if (chain.totalLen === 0) continue;

    // Calculate even spacing for the full chain length
    const numPoles = Math.max(1, Math.round(chain.totalLen / LAMP_SPACING));
    const actualSpacing = chain.totalLen / numPoles;

    for (let i = 0; i <= numPoles; i++) {
      const t = chain.minV + i * actualSpacing;
      const tileX = chain.isH ? t : chain.fixedCoord;
      const tileZ = chain.isH ? chain.fixedCoord : t;

      // World coords (center of tile)
      const wx = tileX * T + 0.5;
      const wz = tileZ * T + 0.5;

      // Place on both sides of sidewalk, staggered (alternate left/right)
      for (const side of [-1, 1]) {
        if ((i % 2 === 0) !== (side === 1)) continue;

        const poleX = chain.isH ? wx : wx + side * swOff;
        const poleZ = chain.isH ? wz + side * swOff : wz;

        // Round for dedup key
        const keyX = Math.round(poleX * 4) / 4;
        const keyZ = Math.round(poleZ * 4) / 4;
        const key = `${keyX},${keyZ}`;
        if (poleSet.has(key)) continue;
        poleSet.add(key);

        // Don't place inside building footprints
        if (isInsideBuildingFootprint(poleX / T, poleZ / T, 1)) continue;

        // Don't place inside intersection areas
        let inIntersection = false;
        for (const seg of _streetSegments) {
          if (!seg.type) continue;
          const ix = seg.x1 * T + 0.5, iz = seg.z1 * T + 0.5;
          if (Math.abs(poleX - ix) < ST.HALF_W && Math.abs(poleZ - iz) < ST.HALF_W) {
            inIntersection = true; break;
          }
        }
        if (inIntersection) continue;

        polePositions.push({ x: poleX, z: poleZ });
      }
    }
  }

  // Create lamp meshes on sidewalk surface with physics colliders
  for (let pi = 0; pi < polePositions.length; pi++) {
    const pos = polePositions[pi];
    const lamp = makeLamppost(pos.x, pos.z);
    lamp.position.y = ST.BASE + ST.SIDEWALK_H; // Sit on top of sidewalk surface
    _streetLampGroup.add(lamp);

    // Add physics collider for this lamp pole
    if (isPhysicsReady()) {
      const lampId = `streetlamp_${pi}_${Math.round(pos.x * 10)}_${Math.round(pos.z * 10)}`;
      addDecorationCollider(lampId, 'lamppost', pos.x, pos.z);
      _streetLampPhysicsIds.push(lampId);
    }
  }

  // Optimization 08: collapse all lamp poles/heads into a few merged meshes.
  // Safe: this group is fully cleared and rebuilt on any street change, and
  // lamp glow is static emissive material (no day/night material swapping).
  mergeStaticGroupMeshes(_streetLampGroup);
}

/**
 * Debounced rebuild of street light poles.
 * Called after any segment add/remove/change.
 */
function _debounceRebuildLamps() {
  if (_streetLampDebounce) clearTimeout(_streetLampDebounce);
  _streetLampDebounce = setTimeout(() => {
    _rebuildStreetLightPoles();
    _streetLampDebounce = null;
  }, 300);
}

/**
 * Find the nearest endpoint of any existing street segment.
 * "Endpoint" means either end (x1,z1) or (x2,z2) of a segment.
 * Returns {x, z, segIndex} or null if nothing within radius.
 */
/**
 * Find the nearest point on any street segment (endpoint OR middle).
 */
/**
 * Find the nearest street point: endpoints of segments AND intersection centers.
 * Also matches middle of segments (for placing intersections on existing roads).
 * Returns { x, z, onSegment, position }.
 */
function findNearestStreetPoint(wx, wz, radius) {
  const r = radius || 8;
  let bestX = wx, bestZ = wz, bestDist = Infinity;
  let onSegment = false, position = null;

  for (const seg of _streetSegments) {
    if (seg.type) {
      // Intersection center
      const d = Math.abs(wx - seg.x1) + Math.abs(wz - seg.z1);
      if (d < bestDist && d <= r) {
        bestDist = d; bestX = seg.x1; bestZ = seg.z1;
        onSegment = true; position = 'intersection';
      }
      continue;
    }

    // Check both endpoints first (priority snap targets)
    for (const [px, pz, pos] of [[seg.x1, seg.z1, 'start'], [seg.x2, seg.z2, 'end']]) {
      const d = Math.abs(wx - px) + Math.abs(wz - pz);
      if (d < bestDist && d <= r) {
        bestDist = d; bestX = px; bestZ = pz;
        onSegment = true; position = pos;
      }
    }

    // Also check middle of segment (for crossing existing roads)
    const isH = Math.abs(seg.x2 - seg.x1) >= Math.abs(seg.z2 - seg.z1);
    if (isH) {
      const minX = Math.min(seg.x1, seg.x2), maxX = Math.max(seg.x1, seg.x2);
      if (Math.abs(wz - seg.z1) <= 3 && wx > minX + 2 && wx < maxX - 2) {
        const cx = Math.round(wx);
        const d = Math.abs(wz - seg.z1) + Math.abs(wx - cx) * 0.5; // slight bias toward exact middle
        if (d < bestDist) {
          bestDist = d; bestX = cx; bestZ = seg.z1;
          onSegment = true; position = 'middle';
        }
      }
    } else {
      const minZ = Math.min(seg.z1, seg.z2), maxZ = Math.max(seg.z1, seg.z2);
      if (Math.abs(wx - seg.x1) <= 3 && wz > minZ + 2 && wz < maxZ - 2) {
        const cz = Math.round(wz);
        const d = Math.abs(wx - seg.x1) + Math.abs(wz - cz) * 0.5;
        if (d < bestDist) {
          bestDist = d; bestX = seg.x1; bestZ = cz;
          onSegment = true; position = 'middle';
        }
      }
    }
  }
  return { x: bestX, z: bestZ, onSegment, position };
}

/**
 * Find nearest segment endpoint or intersection center only (no middles).
 * Used for draw start/end snapping — snaps to EDGES, not centers of segments.
 */
function findNearestStreetEndpoint(wx, wz, radius) {
  const r = radius || 8;
  let bestX = null, bestZ = null, bestDist = Infinity;

  for (const seg of _streetSegments) {
    if (seg.type) {
      // Intersection center
      const d = Math.abs(wx - seg.x1) + Math.abs(wz - seg.z1);
      if (d < bestDist && d <= r) {
        bestDist = d; bestX = seg.x1; bestZ = seg.z1;
      }
      continue;
    }
    // Both endpoints
    for (const [px, pz] of [[seg.x1, seg.z1], [seg.x2, seg.z2]]) {
      const d = Math.abs(wx - px) + Math.abs(wz - pz);
      if (d < bestDist && d <= r) {
        bestDist = d; bestX = px; bestZ = pz;
      }
    }
  }
  return bestX !== null ? { x: bestX, z: bestZ, onSegment: true } : null;
}

function findStreetSnapPoint(wx, wz) {
  const p = findNearestStreetPoint(wx, wz, 10);
  const dir = detectRoadDirection(p.x, p.z);
  return { x: p.x, z: p.z, isHorizontal: dir.isHorizontal, onSegment: p.onSegment, position: p.position };
}

function detectRoadDirection(tx, tz) {
  let hSpan = 1, vSpan = 1, hx = tx;
  while (_getWorldTile(hx - 1, tz) === TERRAIN.ROAD) { hx--; hSpan++; }
  hx = tx;
  while (_getWorldTile(hx + 1, tz) === TERRAIN.ROAD) { hx++; hSpan++; }
  let vz = tz;
  while (_getWorldTile(tx, vz - 1) === TERRAIN.ROAD) { vz--; vSpan++; }
  vz = tz;
  while (_getWorldTile(tx, vz + 1) === TERRAIN.ROAD) { vz++; vSpan++; }
  return { isHorizontal: hSpan >= vSpan, hSpan, vSpan };
}

/**
 * Build a translucent ghost preview for an intersection/turn tool.
 * Snaps to nearest street endpoint.
 */
function buildStreetSnapGhost(tx, tz, type) {
  // Remove old ghost
  if (_streetSnapGhost) { scene.remove(_streetSnapGhost); _streetSnapGhost = null; }

  let ghost;
  if (type === 'x-int' || type === 't-int' || type === 'right-turn' || type === 'left-turn') {
    ghost = buildIntersectionMesh(0, 0, type, _streetPieceRotation);
  } else {
    return;
  }

  // Make translucent
  ghost.traverse(obj => {
    if (obj.isMesh) {
      obj.material = obj.material.clone();
      obj.material.transparent = true;
      obj.material.opacity = 0.35;
      obj.material.depthWrite = false;
    }
  });

  ghost.position.set(tx * T + 0.5, 0, tz * T + 0.5);
  scene.add(ghost);
  _streetSnapGhost = ghost;
  _streetSnapTarget = { x: tx, z: tz };
}

/**
 * Build a 3D street mesh for a segment from (x1,z1) to (x2,z2).
 * Orthogonal only — either horizontal (along X) or vertical (along Z).
 * All geometry sits ON TOP of the terrain (base = 0.2 = terrain tH).
 *
 * Includes end caps: at each end, sidewalk wraps around with curb + gutter
 * so standalone segments look complete and overlap with intersections is invisible.
 */
function buildStreetMesh(x1, z1, x2, z2) {
  const g = new THREE.Group();
  const dx = x2 - x1, dz = z2 - z1;
  const isH = Math.abs(dx) >= Math.abs(dz);
  const len = isH ? Math.abs(dx) : Math.abs(dz);
  if (len === 0) return g;

  const L = len * T;
  const segLen = L + T;
  const B = ST.BASE;
  const roadTop = B + ST.ROAD_THICK;
  const gutterOff = ST.LANE_W + ST.CENTER_W / 2 + ST.GUTTER_W / 2;
  const curbOff   = ST.LANE_W + ST.CENTER_W / 2 + ST.GUTTER_W + ST.CURB_W / 2;
  const swOff     = ST.LANE_W + ST.CENTER_W / 2 + ST.GUTTER_W + ST.CURB_W + ST.SIDEWALK_W / 2;
  const roadW     = ST.LANE_W * 2 + ST.CENTER_W;
  const curbH     = ST.ROAD_THICK + ST.CURB_RISE;
  const gutterH   = ST.ROAD_THICK - ST.GUTTER_DIP;
  const cx = (x1 + x2) / 2 * T + 0.5;
  const cz = (z1 + z2) / 2 * T + 0.5;

  function addBox(prim, y, cross, primLen, h, crossLen, color) {
    g.add(posVox(isH ? prim : cross, y, isH ? cross : prim,
      isH ? primLen : crossLen, h, isH ? crossLen : primLen, color));
  }

  // Road slab
  addBox(0, B + ST.ROAD_THICK / 2, 0, segLen, ST.ROAD_THICK, roadW, 0x2a2a2a);
  // Gutters
  for (const s of [-1, 1]) addBox(0, B + gutterH / 2, s * gutterOff, segLen, gutterH, ST.GUTTER_W, 0x1a1a1a);
  // Curbs
  for (const s of [-1, 1]) addBox(0, B + curbH / 2, s * curbOff, segLen, curbH, ST.CURB_W, 0x999999);
  // Sidewalks
  for (const s of [-1, 1]) {
    const sw = posVox(isH ? 0 : s * swOff, B + ST.SIDEWALK_H / 2, isH ? s * swOff : 0,
      isH ? segLen : ST.SIDEWALK_W, ST.SIDEWALK_H, isH ? ST.SIDEWALK_W : segLen, 0xb0b0b0);
    sw.receiveShadow = true;
    g.add(sw);
  }
  // Yellow center dashes
  const dashLen = 0.8 * T, totalStride = dashLen + 3 * T;
  for (let i = 0, n = Math.floor(L / totalStride) + 1; i < n; i++) {
    const off = -L / 2 + i * totalStride + dashLen / 2;
    if (off > L / 2) break;
    addBox(off, roadTop + 0.005, 0, dashLen, 0.01, 0.12, 0xffd600);
  }
  // White edge lines
  const edgeOff = ST.LANE_W + ST.CENTER_W / 2;
  for (const s of [-1, 1]) addBox(0, roadTop + 0.005, s * edgeOff, segLen, 0.01, 0.07, 0xffffff);

  g.position.set(cx, 0, cz);
  return mergeStaticGroupMeshes(g);
}

/**
 * Build intersection mesh. Uses openN/S/E/W bitmask directly (no rotation).
 * Open sides = street connects. Closed sides = sidewalk wall caps the dead end.
 * Pass openEdges = {n,s,e,w} booleans, or use type+rotation for legacy.
 */
function buildIntersectionMesh(ix, iz, type, rotation, openEdges) {
  const g = new THREE.Group();
  const B = ST.BASE;
  const gutterOff = ST.LANE_W + ST.CENTER_W / 2 + ST.GUTTER_W / 2;
  const curbOff   = ST.LANE_W + ST.CENTER_W / 2 + ST.GUTTER_W + ST.CURB_W / 2;
  const swOff     = ST.LANE_W + ST.CENTER_W / 2 + ST.GUTTER_W + ST.CURB_W + ST.SIDEWALK_W / 2;
  const curbH     = ST.ROAD_THICK + ST.CURB_RISE;
  const gutterH   = ST.ROAD_THICK - ST.GUTTER_DIP;
  const roadW     = ST.LANE_W * 2 + ST.CENTER_W;
  const size      = ST.FULL_W;
  const halfSize  = size / 2;

  // Determine open edges
  let oN = true, oS = true, oE = true, oW = true;
  if (openEdges) {
    oN = !!openEdges.n; oS = !!openEdges.s; oE = !!openEdges.e; oW = !!openEdges.w;
  } else {
    let baseN = true, baseS = true, baseE = true, baseW = true;
    if (type === 't-int')           { baseS = false; }
    else if (type === 'right-turn') { baseN = false; baseE = false; }
    else if (type === 'left-turn')  { baseN = false; baseW = false; }
    const edges = [baseN, baseE, baseS, baseW];
    const steps = ((rotation || 0) / 90) % 4;
    for (let i = 0; i < steps; i++) { edges.unshift(edges.pop()); }
    [oN, oE, oS, oW] = edges;
  }

  // Road surface — full intersection square
  const road = posVox(0, B + ST.ROAD_THICK / 2, 0, size, ST.ROAD_THICK, size, 0x2a2a2a);
  road.receiveShadow = true;
  g.add(road);

  // ── Build continuous sidewalk, curb, and gutter around the perimeter ──
  // Each side gets curb + gutter + sidewalk.
  // CLOSED sides: curb/gutter/sidewalk span the full side length (wall off the dead end).
  // OPEN sides: curb/gutter/sidewalk only on flanking areas (two pieces on each side of road opening).
  //   The connecting street segment overlaps into the intersection — its curb/gutter aligns with
  //   the perpendicular sides' curb/gutter, creating seamless L-joints at corners.

  const fullSideLen = size;         // full intersection side = FULL_W
  const roadHalf = roadW / 2;      // half the road opening width
  // Corner block inner edge (for sidewalk flanks)
  const cornerInner = swOff - ST.SIDEWALK_W / 2;
  // Sidewalk flank: short piece from road edge to corner block inner edge
  const swFlankLen = cornerInner - roadHalf;
  const swFlankCenter = roadHalf + swFlankLen / 2;
  // Curb/gutter flank: extend from road edge to intersection boundary for seamless overlap
  const cgFlankLen = halfSize - roadHalf;
  const cgFlankCenter = roadHalf + cgFlankLen / 2;

  // Helper: add curb + gutter + sidewalk for one side
  // axis: 'x' = side runs along X (N/S edges), 'z' = side runs along Z (E/W edges)
  // sign: -1 or +1 for which side
  // isOpen: whether a street connects on this side
  function addSideElements(axis, sign, isOpen) {
    const swP  = sign * swOff;
    const crbP = sign * curbOff;
    const gutP = sign * gutterOff;

    if (axis === 'x') {
      if (isOpen) {
        // Flanking pieces — curb/gutter extend to intersection edge for seamless connection
        for (const sx of [-1, 1]) {
          g.add(posVox(sx * swFlankCenter, B + ST.SIDEWALK_H / 2, swP, swFlankLen, ST.SIDEWALK_H, ST.SIDEWALK_W, 0xb0b0b0));
          g.add(posVox(sx * cgFlankCenter, B + curbH / 2, crbP, cgFlankLen, curbH, ST.CURB_W, 0x999999));
          g.add(posVox(sx * cgFlankCenter, B + gutterH / 2, gutP, cgFlankLen, gutterH, ST.GUTTER_W, 0x1a1a1a));
        }
        // Corner blocks
        g.add(posVox(-swOff, B + ST.SIDEWALK_H / 2, swP, ST.SIDEWALK_W, ST.SIDEWALK_H, ST.SIDEWALK_W, 0xb0b0b0));
        g.add(posVox( swOff, B + ST.SIDEWALK_H / 2, swP, ST.SIDEWALK_W, ST.SIDEWALK_H, ST.SIDEWALK_W, 0xb0b0b0));
      } else {
        // Closed: full sidewalk span + curb/gutter across road width
        g.add(posVox(0, B + ST.SIDEWALK_H / 2, swP, fullSideLen, ST.SIDEWALK_H, ST.SIDEWALK_W, 0xb0b0b0));
        g.add(posVox(0, B + curbH / 2, crbP, roadW, curbH, ST.CURB_W, 0x999999));
        g.add(posVox(0, B + gutterH / 2, gutP, roadW, gutterH, ST.GUTTER_W, 0x1a1a1a));
      }
    } else {
      if (isOpen) {
        for (const sz of [-1, 1]) {
          g.add(posVox(swP, B + ST.SIDEWALK_H / 2, sz * swFlankCenter, ST.SIDEWALK_W, ST.SIDEWALK_H, swFlankLen, 0xb0b0b0));
          g.add(posVox(crbP, B + curbH / 2, sz * cgFlankCenter, ST.CURB_W, curbH, cgFlankLen, 0x999999));
          g.add(posVox(gutP, B + gutterH / 2, sz * cgFlankCenter, ST.GUTTER_W, gutterH, cgFlankLen, 0x1a1a1a));
        }
        g.add(posVox(swP, B + ST.SIDEWALK_H / 2, -swOff, ST.SIDEWALK_W, ST.SIDEWALK_H, ST.SIDEWALK_W, 0xb0b0b0));
        g.add(posVox(swP, B + ST.SIDEWALK_H / 2,  swOff, ST.SIDEWALK_W, ST.SIDEWALK_H, ST.SIDEWALK_W, 0xb0b0b0));
      } else {
        g.add(posVox(swP, B + ST.SIDEWALK_H / 2, 0, ST.SIDEWALK_W, ST.SIDEWALK_H, fullSideLen, 0xb0b0b0));
        g.add(posVox(crbP, B + curbH / 2, 0, ST.CURB_W, curbH, roadW, 0x999999));
        g.add(posVox(gutP, B + gutterH / 2, 0, ST.GUTTER_W, gutterH, roadW, 0x1a1a1a));
      }
    }
  }

  addSideElements('x', -1, oN);  // North
  addSideElements('x',  1, oS);  // South
  addSideElements('z', -1, oW);  // West
  addSideElements('z',  1, oE);  // East

  // ── Crosswalks (zebra stripes) at each open edge ──
  // Each crosswalk is a band that spans the ROAD WIDTH (across the arm) and is
  // only ~1.6 units deep along the travel direction, sitting just outside the
  // central intersection square so the four crosswalks never overlap.
  const crosswalkY = B + ST.ROAD_THICK + 0.006;
  const stripeW = 0.35;     // width of each white stripe (across the road)
  const stripeGap = 0.30;   // gap between stripes
  const bandDepth = 1.05;   // crosswalk band depth (stripe length, along travel direction)
  const stripeSpan = roadW - 0.5; // usable span across the road (small margin from gutters)
  const numStripes = Math.max(2, Math.floor((stripeSpan + stripeGap) / (stripeW + stripeGap)));
  const stripesTotal = numStripes * stripeW + (numStripes - 1) * stripeGap;
  // Band center: just outside the central conflict square, fully on the intersection slab
  const crosswalkOffset = roadHalf + bandDepth / 2 + 0.1;

  function addCrosswalk(axis, sign, isOpen) {
    if (!isOpen) return;
    for (let i = 0; i < numStripes; i++) {
      const off = -stripesTotal / 2 + i * (stripeW + stripeGap) + stripeW / 2;
      if (axis === 'x') {
        // N/S arm — stripes arrayed across X, each stripe long along Z (traffic direction)
        g.add(posVox(off, crosswalkY, sign * crosswalkOffset, stripeW, 0.01, bandDepth, 0xffffff));
      } else {
        // E/W arm — stripes arrayed across Z, each stripe long along X
        g.add(posVox(sign * crosswalkOffset, crosswalkY, off, bandDepth, 0.01, stripeW, 0xffffff));
      }
    }
    // Stop line (thick white line where vehicles stop before the crosswalk)
    const stopLineOff = crosswalkOffset + bandDepth / 2 + 0.45;
    const laneHalfW = ST.LANE_W;
    if (axis === 'x') {
      g.add(posVox(0, crosswalkY, sign * stopLineOff, laneHalfW * 2, 0.01, 0.15, 0xffffff));
    } else {
      g.add(posVox(sign * stopLineOff, crosswalkY, 0, 0.15, 0.01, laneHalfW * 2, 0xffffff));
    }
  }

  addCrosswalk('x', -1, oN);
  addCrosswalk('x',  1, oS);
  addCrosswalk('z', -1, oW);
  addCrosswalk('z',  1, oE);

  g.position.set(ix * T + 0.5, 0, iz * T + 0.5);
  return mergeStaticGroupMeshes(g);
}

// ── Core: add a raw street segment (no auto-intersection) ────
function _addRawSegment(x1, z1, x2, z2) {
  if (x1 === x2 && z1 === z2) return null;
  const mesh = buildStreetMesh(x1, z1, x2, z2);
  _streetGroup.add(mesh);
  const seg = { x1, z1, x2, z2, mesh };
  _streetSegments.push(seg);
  invalidateGroundIndex(); // PERF: street layout changed
  _paintSegmentTerrain(x1, z1, x2, z2);
  _debounceSaveStreets();
  _debounceRebuildLamps();
  _debounceRebuildTrafficLights();
  return seg;
}

function _addRawIntersection(ix, iz, type, rotation, openEdges) {
  const mesh = buildIntersectionMesh(ix, iz, type, rotation || 0, openEdges);
  _streetGroup.add(mesh);
  const seg = { x1: ix, z1: iz, x2: ix, z2: iz, type, rotation: rotation || 0, openEdges, mesh };
  _streetSegments.push(seg);
  invalidateGroundIndex(); // PERF: street layout changed
  const R = Math.ceil(ST.HALF_W);
  const swR = R + 2; // sidewalk extends 2 tiles beyond road for better connectivity
  // Paint road tiles in the center, sidewalk tiles around the perimeter
  for (let dz = -swR; dz <= swR; dz++) {
    for (let dx = -swR; dx <= swR; dx++) {
      if (Math.abs(dx) <= R && Math.abs(dz) <= R) {
        _setWorldTile(ix + dx, iz + dz, TERRAIN.ROAD);
      } else {
        _setWorldTileIfGrass(ix + dx, iz + dz, TERRAIN.SIDEWALK);
      }
    }
  }
  _invalidateRoadGraph();
  _debounceSaveStreets();
  _debounceRebuildLamps();
  _debounceRebuildTrafficLights();
  return seg;
}

function _paintSegmentTerrain(x1, z1, x2, z2) {
  const dx = x2 - x1, dz = z2 - z1;
  const isH = Math.abs(dx) >= Math.abs(dz);
  const steps = Math.max(Math.abs(dx), Math.abs(dz));
  for (let i = 0; i <= steps; i++) {
    const t = steps === 0 ? 0 : i / steps;
    const wx = Math.round(x1 + dx * t);
    const wz = Math.round(z1 + dz * t);
    if (isH) {
      for (let d = -1; d <= 1; d++) _setWorldTile(wx, wz + d, TERRAIN.ROAD);
      // Sidewalk on both sides (2 tiles wide for walkability)
      for (let d = 2; d <= 3; d++) {
        _setWorldTileIfGrass(wx, wz - d, TERRAIN.SIDEWALK);
        _setWorldTileIfGrass(wx, wz + d, TERRAIN.SIDEWALK);
      }
    } else {
      for (let d = -1; d <= 1; d++) _setWorldTile(wx + d, wz, TERRAIN.ROAD);
      for (let d = 2; d <= 3; d++) {
        _setWorldTileIfGrass(wx - d, wz, TERRAIN.SIDEWALK);
        _setWorldTileIfGrass(wx + d, wz, TERRAIN.SIDEWALK);
      }
    }
  }

  // Paint corner sidewalk tiles at segment endpoints so sidewalks connect around turns
  // At each endpoint, fill the diagonal corner tiles (2x2 block) with sidewalk
  for (const [ex, ez] of [[x1, z1], [x2, z2]]) {
    for (let cdz = -3; cdz <= 3; cdz++) {
      for (let cdx = -3; cdx <= 3; cdx++) {
        // Fill corner areas: tiles that are outside the road strip but within sidewalk distance
        const tile = _getWorldTile(ex + cdx, ez + cdz);
        if (tile === TERRAIN.GRASS || tile === TERRAIN.DIRT) {
          const absX = Math.abs(cdx), absZ = Math.abs(cdz);
          // Diagonal corner fills: where one axis is sidewalk distance (2-3) and other is sidewalk distance (2-3)
          if (absX >= 2 && absX <= 3 && absZ >= 2 && absZ <= 3) {
            _setWorldTileIfGrass(ex + cdx, ez + cdz, TERRAIN.SIDEWALK);
          }
          // Also fill close-range corners (1 tile from road, 2-3 perpendicular)
          if ((absX <= 1 && absZ >= 2 && absZ <= 3) || (absZ <= 1 && absX >= 2 && absX <= 3)) {
            _setWorldTileIfGrass(ex + cdx, ez + cdz, TERRAIN.SIDEWALK);
          }
        }
      }
    }
  }

  _invalidateRoadGraph();
}

/**
 * Repaint street terrain for a specific chunk.
 * Called after a chunk loads from server to ensure road/sidewalk tiles are correct.
 */
function _repaintStreetTerrainForChunk(cx, cz) {
  if (_streetSegments.length === 0) return;
  const chunkMinX = cx * CHUNK, chunkMaxX = chunkMinX + CHUNK - 1;
  const chunkMinZ = cz * CHUNK, chunkMaxZ = chunkMinZ + CHUNK - 1;

  for (const seg of _streetSegments) {
    if (seg.type) {
      // Intersection — check if it overlaps this chunk
      const R = Math.ceil(ST.HALF_W) + 1;
      if (seg.x1 + R >= chunkMinX && seg.x1 - R <= chunkMaxX &&
          seg.z1 + R >= chunkMinZ && seg.z1 - R <= chunkMaxZ) {
        for (let dz = -R; dz <= R; dz++) {
          for (let dx = -R; dx <= R; dx++) {
            const wx = seg.x1 + dx, wz = seg.z1 + dz;
            if (wx >= chunkMinX && wx <= chunkMaxX && wz >= chunkMinZ && wz <= chunkMaxZ) {
              if (Math.abs(dx) <= R - 1 && Math.abs(dz) <= R - 1) {
                _setWorldTile(wx, wz, TERRAIN.ROAD);
              } else {
                _setWorldTileIfGrass(wx, wz, TERRAIN.SIDEWALK);
              }
            }
          }
        }
      }
    } else {
      // Segment — check if it overlaps this chunk
      const minX = Math.min(seg.x1, seg.x2) - 3;
      const maxX = Math.max(seg.x1, seg.x2) + 3;
      const minZ = Math.min(seg.z1, seg.z2) - 3;
      const maxZ = Math.max(seg.z1, seg.z2) + 3;
      if (maxX >= chunkMinX && minX <= chunkMaxX && maxZ >= chunkMinZ && minZ <= chunkMaxZ) {
        _paintSegmentTerrain(seg.x1, seg.z1, seg.x2, seg.z2);
      }
    }
  }
}

function _snapshotStreets() {
  return _streetSegments.map(s => ({
    x1: s.x1, z1: s.z1, x2: s.x2, z2: s.z2,
    type: s.type || null, rotation: s.rotation || 0,
    openEdges: s.openEdges || null,
  }));
}

function _restoreStreets(snapshot) {
  while (_streetSegments.length > 0) {
    const s = _streetSegments.pop();
    _streetGroup.remove(s.mesh);
  }
  invalidateGroundIndex(); // PERF: street layout changed
  for (const s of snapshot) {
    if (s.type) {
      _addRawIntersection(s.x1, s.z1, s.type, s.rotation || 0, s.openEdges || undefined);
    } else {
      _addRawSegment(s.x1, s.z1, s.x2, s.z2);
    }
  }
  for (const s of snapshot) {
    _rebuildNearChunks(s.x1, s.z1, 5);
  }
}

function _removeSegment(seg) {
  const idx = _streetSegments.indexOf(seg);
  if (idx >= 0) {
    _streetGroup.remove(seg.mesh);
    _streetSegments.splice(idx, 1);
    invalidateGroundIndex(); // PERF: street layout changed
    _invalidateRoadGraph();
    _debounceSaveStreets();
    _debounceRebuildLamps();
  _debounceRebuildTrafficLights();
  }
}

// ── Detection: is a tile on an existing street segment? ──────
function isOnStreetSegment(tx, tz) {
  for (const seg of _streetSegments) {
    if (seg.type) continue;
    const isH = Math.abs(seg.x2 - seg.x1) >= Math.abs(seg.z2 - seg.z1);
    const minX = Math.min(seg.x1, seg.x2), maxX = Math.max(seg.x1, seg.x2);
    const minZ = Math.min(seg.z1, seg.z2), maxZ = Math.max(seg.z1, seg.z2);
    if (isH) {
      if (Math.abs(tz - seg.z1) <= 2 && tx >= minX - 1 && tx <= maxX + 1) {
        if (Math.abs(tx - seg.x1) <= 1) return { seg, position: 'start' };
        if (Math.abs(tx - seg.x2) <= 1) return { seg, position: 'end' };
        return { seg, position: 'middle' };
      }
    } else {
      if (Math.abs(tx - seg.x1) <= 2 && tz >= minZ - 1 && tz <= maxZ + 1) {
        if (Math.abs(tz - seg.z1) <= 1) return { seg, position: 'start' };
        if (Math.abs(tz - seg.z2) <= 1) return { seg, position: 'end' };
        return { seg, position: 'middle' };
      }
    }
  }
  return null;
}

function _findIntersectionAt(tx, tz) {
  for (const seg of _streetSegments) {
    if (seg.type && Math.abs(seg.x1 - tx) <= 1 && Math.abs(seg.z1 - tz) <= 1) return seg;
  }
  return null;
}

/** Detect which directions have street segments connecting near (tx, tz). */
function _detectConnections(tx, tz) {
  const tol = Math.round(ST.HALF_W) + 2;
  const r = { n: false, s: false, e: false, w: false };
  for (const seg of _streetSegments) {
    if (seg.type) continue;
    for (const [px, pz] of [[seg.x1, seg.z1], [seg.x2, seg.z2]]) {
      const dx = px - tx, dz = pz - tz;
      if (dx > 0 && dx <= tol && Math.abs(dz) <= 1) r.e = true;
      if (dx < 0 && -dx <= tol && Math.abs(dz) <= 1) r.w = true;
      if (dz > 0 && dz <= tol && Math.abs(dx) <= 1) r.s = true;
      if (dz < 0 && -dz <= tol && Math.abs(dx) <= 1) r.n = true;
    }
  }
  return r;
}

/** Build/rebuild intersection at (ix,iz) using detected connections. */
function _rebuildIntersectionAt(ix, iz, extraConn) {
  const existing = _findIntersectionAt(ix, iz);
  if (existing) _removeSegment(existing);
  const conn = _detectConnections(ix, iz);
  if (extraConn) { for (const d of ['n','s','e','w']) if (extraConn[d]) conn[d] = true; }
  const count = [conn.n, conn.s, conn.e, conn.w].filter(Boolean).length;
  let type = 'x-int';
  if (count === 3) type = 't-int';
  else if (count <= 2 && !(conn.n && conn.s) && !(conn.e && conn.w)) type = 'right-turn';
  _addRawIntersection(ix, iz, type, 0, conn);
  _rebuildNearChunks(ix, iz, 5);
}

function splitStreetAt(tx, tz) {
  const hit = isOnStreetSegment(tx, tz);
  if (!hit || hit.position === 'start' || hit.position === 'end') return null;
  const seg = hit.seg;
  const isH = Math.abs(seg.x2 - seg.x1) >= Math.abs(seg.z2 - seg.z1);
  _removeSegment(seg);
  const gap = Math.round(ST.HALF_W);
  let seg1, seg2;
  if (isH) {
    const lo = Math.min(seg.x1, seg.x2), hi = Math.max(seg.x1, seg.x2);
    if (tx - gap - lo >= 2) seg1 = _addRawSegment(lo, seg.z1, tx - gap, seg.z1);
    if (hi - (tx + gap) >= 2) seg2 = _addRawSegment(tx + gap, seg.z1, hi, seg.z1);
  } else {
    const lo = Math.min(seg.z1, seg.z2), hi = Math.max(seg.z1, seg.z2);
    if (tz - gap - lo >= 2) seg1 = _addRawSegment(seg.x1, lo, seg.x1, tz - gap);
    if (hi - (tz + gap) >= 2) seg2 = _addRawSegment(seg.x1, tz + gap, seg.x1, hi);
  }
  return [seg1, seg2].filter(Boolean);
}

function placeIntersectionSmart(tx, tz, type, rotation) {
  const hit = isOnStreetSegment(tx, tz);
  if (hit && hit.position === 'middle') splitStreetAt(tx, tz);
  _rebuildIntersectionAt(tx, tz);
}

/**
 * Add a street segment with AUTOMATIC intersections.
 * - Draw across an existing street → 4-way intersection
 * - Draw up to an existing street → T-intersection  
 * - Connect perpendicular endpoints → turn
 */
/**
 * Find all points where a new segment (x1,z1)→(x2,z2) crosses existing segments.
 * Only detects perpendicular crossings (H crosses V or V crosses H).
 * Returns array of { crossX, crossZ, existingSeg }.
 */
function _findCrossings(x1, z1, x2, z2) {
  const newH = Math.abs(x2 - x1) >= Math.abs(z2 - z1);
  const crossings = [];
  
  for (const seg of _streetSegments) {
    if (seg.type) continue; // skip intersections
    const segH = Math.abs(seg.x2 - seg.x1) >= Math.abs(seg.z2 - seg.z1);
    
    // Only perpendicular crossings
    if (newH === segH) continue;
    
    if (newH) {
      // New is horizontal, existing is vertical
      // New runs along Z=z1 from x1→x2, existing runs along X=seg.x1 from seg.z1→seg.z2
      const crossX = seg.x1;
      const crossZ = z1;
      const newMinX = Math.min(x1, x2), newMaxX = Math.max(x1, x2);
      const segMinZ = Math.min(seg.z1, seg.z2), segMaxZ = Math.max(seg.z1, seg.z2);
      // Cross point must be inside BOTH segments (not at endpoints)
      if (crossX > newMinX + 1 && crossX < newMaxX - 1 &&
          crossZ > segMinZ + 1 && crossZ < segMaxZ - 1) {
        crossings.push({ crossX, crossZ, existingSeg: seg });
      }
    } else {
      // New is vertical, existing is horizontal
      const crossX = x1;
      const crossZ = seg.z1;
      const newMinZ = Math.min(z1, z2), newMaxZ = Math.max(z1, z2);
      const segMinX = Math.min(seg.x1, seg.x2), segMaxX = Math.max(seg.x1, seg.x2);
      if (crossZ > newMinZ + 1 && crossZ < newMaxZ - 1 &&
          crossX > segMinX + 1 && crossX < segMaxX - 1) {
        crossings.push({ crossX, crossZ, existingSeg: seg });
      }
    }
  }
  return crossings;
}

function addStreetSegment(x1, z1, x2, z2) {
  const isH = Math.abs(x2 - x1) >= Math.abs(z2 - z1);
  
  // Snap endpoints to nearby existing endpoints / intersection centers
  for (const seg of _streetSegments) {
    if (seg.type) {
      if (Math.abs(x1 - seg.x1) + Math.abs(z1 - seg.z1) <= 6) { x1 = seg.x1; z1 = seg.z1; }
      if (Math.abs(x2 - seg.x1) + Math.abs(z2 - seg.z1) <= 6) { x2 = seg.x1; z2 = seg.z1; }
    } else {
      for (const [sx, sz] of [[seg.x1, seg.z1], [seg.x2, seg.z2]]) {
        if (Math.abs(x1 - sx) + Math.abs(z1 - sz) <= 3) { x1 = sx; z1 = sz; }
        if (Math.abs(x2 - sx) + Math.abs(z2 - sz) <= 3) { x2 = sx; z2 = sz; }
      }
    }
  }
  
  // === AUTO-DETECT CROSSINGS ===
  // Find where this new segment crosses existing segments → 4-way intersections
  const crossings = _findCrossings(x1, z1, x2, z2);
  
  if (crossings.length > 0) {
    // Sort crossings by distance from start
    crossings.sort((a, b) => {
      const da = Math.abs(a.crossX - x1) + Math.abs(a.crossZ - z1);
      const db = Math.abs(b.crossX - x1) + Math.abs(b.crossZ - z1);
      return da - db;
    });
    
    // Split each crossed existing segment and place 4-way intersections
    for (const c of crossings) {
      // Split the existing segment at the crossing point
      const hit = isOnStreetSegment(c.crossX, c.crossZ);
      if (hit && hit.position === 'middle') {
        splitStreetAt(c.crossX, c.crossZ);
      }
      // Place 4-way intersection (all 4 edges open)
      _rebuildIntersectionAt(c.crossX, c.crossZ, { n: true, s: true, e: true, w: true });
    }
    
    // Now split the NEW segment at each crossing point too.
    // Normalize direction: always work lo→hi so gap offsets are consistent
    const gap = Math.round(ST.HALF_W);
    let startX = x1, startZ = z1, endX = x2, endZ = z2;
    if (isH && x1 > x2) { startX = x2; startZ = z2; endX = x1; endZ = z1; }
    if (!isH && z1 > z2) { startX = x2; startZ = z2; endX = x1; endZ = z1; }
    
    // Sort crossings in lo→hi order
    crossings.sort((a, b) => isH ? a.crossX - b.crossX : a.crossZ - b.crossZ);
    
    const pts = [{ x: startX, z: startZ }];
    for (const c of crossings) pts.push({ x: c.crossX, z: c.crossZ });
    pts.push({ x: endX, z: endZ });
    
    for (let i = 0; i < pts.length - 1; i++) {
      let sx = pts[i].x, sz = pts[i].z;
      let ex = pts[i + 1].x, ez = pts[i + 1].z;
      
      // Offset away from crossing points (always in positive direction since normalized)
      if (i > 0) { if (isH) sx += gap; else sz += gap; }
      if (i < pts.length - 2) { if (isH) ex -= gap; else ez -= gap; }
      
      const len = isH ? Math.abs(ex - sx) : Math.abs(ez - sz);
      if (len >= 2) {
        _addRawSegment(sx, sz, ex, ez);
      }
    }
    
    // Rebuild chunks around all crossing points
    for (const c of crossings) _rebuildNearChunks(c.crossX, c.crossZ, 5);
    _rebuildNearChunks(x1, z1, 5);
    _rebuildNearChunks(x2, z2, 5);
    return;
  }
  
  // === NO CROSSINGS — check endpoint connections ===
  function dirFrom(px, pz, ox, oz) {
    if (isH) return ox > px ? 'e' : 'w';
    return oz > pz ? 's' : 'n';
  }
  
  // Track whether intersections were placed at start/end so we can shorten the new segment
  let intAtStart = false, intAtEnd = false;
  const gap = Math.round(ST.HALF_W);
  
  // Helper: handle a connection point — auto-create intersection if needed
  // Returns true if an intersection was placed at this point.
  function _handleConnection(px, pz, towardX, towardZ) {
    const hit = isOnStreetSegment(px, pz);
    const existingInt = _findIntersectionAt(px, pz);
    
    if (hit && hit.position === 'middle') {
      // T-junction: endpoint hits middle of existing segment
      const eH = Math.abs(hit.seg.x2 - hit.seg.x1) >= Math.abs(hit.seg.z2 - hit.seg.z1);
      splitStreetAt(px, pz);
      const extra = { n: false, s: false, e: false, w: false };
      if (eH) { extra.e = true; extra.w = true; } else { extra.n = true; extra.s = true; }
      extra[dirFrom(px, pz, towardX, towardZ)] = true;
      _rebuildIntersectionAt(px, pz, extra);
      return true;
    } else if (hit && (hit.position === 'start' || hit.position === 'end')) {
      // Corner/turn: endpoint meets another segment's endpoint
      const eSeg = hit.seg;
      const eH = Math.abs(eSeg.x2 - eSeg.x1) >= Math.abs(eSeg.z2 - eSeg.z1);
      const atStart = hit.position === 'start';
      const eOtherX = atStart ? eSeg.x2 : eSeg.x1;
      const eOtherZ = atStart ? eSeg.z2 : eSeg.z1;
      const existDir = eH 
        ? (eOtherX > px ? 'e' : 'w')
        : (eOtherZ > pz ? 's' : 'n');
      const newDir = dirFrom(px, pz, towardX, towardZ);
      
      // Shorten the existing segment to make room for intersection
      _removeSegment(eSeg);
      if (eH) {
        const lo = Math.min(eSeg.x1, eSeg.x2), hi = Math.max(eSeg.x1, eSeg.x2);
        if (existDir === 'e' && hi - (px + gap) >= 2) _addRawSegment(px + gap, eSeg.z1, hi, eSeg.z1);
        if (existDir === 'w' && (px - gap) - lo >= 2) _addRawSegment(lo, eSeg.z1, px - gap, eSeg.z1);
      } else {
        const lo = Math.min(eSeg.z1, eSeg.z2), hi = Math.max(eSeg.z1, eSeg.z2);
        if (existDir === 's' && hi - (pz + gap) >= 2) _addRawSegment(eSeg.x1, pz + gap, eSeg.x1, hi);
        if (existDir === 'n' && (pz - gap) - lo >= 2) _addRawSegment(eSeg.x1, lo, eSeg.x1, pz - gap);
      }
      
      // Build intersection with both directions open
      const extra = { n: false, s: false, e: false, w: false };
      extra[existDir] = true;
      extra[newDir] = true;
      _rebuildIntersectionAt(px, pz, extra);
      return true;
    } else if (existingInt) {
      // Already an intersection here — rebuild to add new direction
      const ex = { n: false, s: false, e: false, w: false };
      ex[dirFrom(px, pz, towardX, towardZ)] = true;
      _rebuildIntersectionAt(px, pz, ex);
      return true;
    }
    return false;
  }
  
  // Process START point
  intAtStart = _handleConnection(x1, z1, x2, z2);
  // Process END point  
  intAtEnd = _handleConnection(x2, z2, x1, z1);
  
  // Shorten the new segment to make room for intersections at its endpoints
  let nx1 = x1, nz1 = z1, nx2 = x2, nz2 = z2;
  if (intAtStart) {
    if (isH) { nx1 = x1 + (x2 > x1 ? gap : -gap); }
    else     { nz1 = z1 + (z2 > z1 ? gap : -gap); }
  }
  if (intAtEnd) {
    if (isH) { nx2 = x2 + (x1 > x2 ? gap : -gap); }
    else     { nz2 = z2 + (z1 > z2 ? gap : -gap); }
  }
  
  const newLen = isH ? Math.abs(nx2 - nx1) : Math.abs(nz2 - nz1);
  if (newLen >= 2) {
    _addRawSegment(nx1, nz1, nx2, nz2);
  }
}

// Legacy wrapper
function addIntersectionPiece(ix, iz, type, rotation) {
  placeIntersectionSmart(ix, iz, type, rotation);
}


function eraseStreetAt(tx, tz) {
  // Find and remove any street segment that covers this tile
  let erased = false;
  for (let i = _streetSegments.length - 1; i >= 0; i--) {
    const seg = _streetSegments[i];
    const minX = Math.min(seg.x1, seg.x2) - 3;
    const maxX = Math.max(seg.x1, seg.x2) + 3;
    const minZ = Math.min(seg.z1, seg.z2) - 3;
    const maxZ = Math.max(seg.z1, seg.z2) + 3;
    if (tx >= minX && tx <= maxX && tz >= minZ && tz <= maxZ) {
      _streetGroup.remove(seg.mesh);
      _streetSegments.splice(i, 1);
      invalidateGroundIndex(); // PERF: street layout changed
      erased = true;
      // Clear terrain
      for (let z = minZ; z <= maxZ; z++) {
        for (let x = minX; x <= maxX; x++) {
          const t = _getWorldTile(x, z);
          if (t === TERRAIN.ROAD || t === TERRAIN.SIDEWALK) _setWorldTile(x, z, TERRAIN.GRASS);
        }
      }
    }
  }
  if (erased) {
    _invalidateRoadGraph();
    _debounceSaveStreets();
    _debounceRebuildLamps();
  _debounceRebuildTrafficLights();
  }
}

function _rebuildNearChunks(tx, tz, radius) {
  const r = radius || 3;
  for (let ccx = Math.floor((tx - r) / CHUNK); ccx <= Math.floor((tx + r) / CHUNK); ccx++) {
    for (let ccz = Math.floor((tz - r) / CHUNK); ccz <= Math.floor((tz + r) / CHUNK); ccz++) {
      const chunk = loadedChunks.get(chunkKey(ccx, ccz));
      if (chunk) rebuildChunk(chunk);
    }
  }
}

function _getWorldTile(wx, wz) {
  const cx = Math.floor(wx / CHUNK);
  const cz = Math.floor(wz / CHUNK);
  const chunk = loadedChunks.get(chunkKey(cx, cz));
  if (!chunk) return -1;
  const lx = ((wx % CHUNK) + CHUNK) % CHUNK;
  const lz = ((wz % CHUNK) + CHUNK) % CHUNK;
  return chunk.terrain[lz * CHUNK + lx];
}

function buildRoadPalette() {
  const container = document.getElementById('roadItems');
  if (!container) return;
  container.innerHTML = '';

  const tools = [
    { id: 'line',       label: 'Draw Street',    icon: '📏' },
    { id: 'erase',      label: 'Erase Road',     icon: '🗑️' },
  ];

  tools.forEach(tool => {
    const item = document.createElement('div');
    item.className = 'palette-item' + (tool.id === _streetTool ? ' active' : '');
    item.innerHTML = `${tool.icon} ${tool.label}`;
    item.addEventListener('click', () => {
      _streetTool = tool.id;
      _streetPieceRotation = 0; // reset rotation when switching tools
      container.querySelectorAll('.palette-item').forEach(i => i.classList.remove('active'));
      item.classList.add('active');
      const rotNote = (tool.id === 't-int' || tool.id === 'right-turn' || tool.id === 'left-turn') ? ' (R to rotate)' : '';
      showToast(`🛣️ Tool: ${tool.icon} ${tool.label}${rotNote}`, 'info');
    });
    container.appendChild(item);
  });
}

function getBuildingOccupants(b) {
  const scale = T / API_TILE;
  const bounds = getBuildingFootprintBounds(b, 0);
  const bx1 = bounds.minX, bx2 = bounds.maxX;
  const bz1 = bounds.minZ, bz2 = bounds.maxZ;
  return agentsList.filter(a => {
    const ax = a.x * scale, az = a.y * scale;
    return ax >= bx1 && ax <= bx2 && az >= bz1 && az <= bz2;
  });
}

function isOutsideSpaceBuilding(building) {
  if (!building) return false;
  return building.type === 'park' || building.type === 'outdoor' || Boolean(building.outdoorArea);
}

function updateBuildingEditPanel(b) {
  const content = document.getElementById('buildingEditContent');
  if (!content) return;
  if (!b) {
    content.innerHTML = '<p class="palette-hint">Click a building in the world to select it for editing</p>';
    return;
  }
  const isOutsideSpace = isOutsideSpaceBuilding(b);
  if (!isOutsideSpace) normalizeBuildingFloors(b);
  const activeFloor = isOutsideSpace ? 1 : getActiveBuildingFloor(b);
  const floorCount = isOutsideSpace ? 1 : getBuildingFloorCount(b);
  const elevatorLabel = !isOutsideSpace && b.elevator ? `${(b.elevator.x / T).toFixed(1)}, ${(b.elevator.z / T).toFixed(1)}` : 'Not placed';
  const typeLabel = BUILDING_TYPES[b.type]?.label || OUTSIDE_SPACE_TYPES[b.type]?.label || b.type || 'Building';
  const subjectLabel = isOutsideSpace ? 'Selected outside space' : 'Selected building';
  const subjectIcon = isOutsideSpace ? '🌳' : '📍';
  const floorStats = isOutsideSpace
    ? ''
    : `<div><span>Floors</span><strong>${floorCount}</strong></div>`;
  const floorElevatorControls = isOutsideSpace ? '' : `
      <div class="bld-edit-group">
        <div class="bld-edit-group-title">Floors / elevator</div>
        <label class="bld-edit-field">
          <span>Current floor</span>
          <select id="bldFloorSelect" onchange="window._setBldFloor('${b.id}', this.value)">
            ${Array.from({ length: floorCount }, (_, i) => `<option value="${i + 1}" ${activeFloor === i + 1 ? 'selected' : ''}>Floor ${i + 1}${i === 0 ? ' (exterior doors)' : ''}</option>`).join('')}
          </select>
        </label>
        <div class="palette-hint" style="margin:4px 0 8px">Elevator shaft: ${elevatorLabel}. Upper floors are reached only through this shared elevator.</div>
        <div class="bld-action-grid">
          <button class="bld-edit-btn bld-edit-btn-success" onclick="window._addBldFloor('${b.id}')">➕ Add floor</button>
          <button class="bld-edit-btn bld-edit-btn-danger" onclick="window._removeBldFloor('${b.id}')">➖ Remove top floor</button>
          <button class="bld-edit-btn" onclick="window._relocateElevator('${b.id}')">🛗 Relocate elevator</button>
        </div>
      </div>`;
  const interiorTip = !isOutsideSpace && insideBuildingId === b.id ? `
      <div class="bld-interior-tip">
        <strong>🧱 Interior tools active</strong>
        <span>Use “+ New Wall” below, then click start and end points inside the building.</span>
      </div>` : '';

  content.innerHTML = `
    <div class="bld-edit-card">
      <div class="bld-edit-hero">
        <div>
          <div class="bld-edit-kicker">${subjectLabel}</div>
          <h4>${subjectIcon} ${b.name}</h4>
        </div>
        <span class="bld-edit-type-pill">${typeLabel}</span>
      </div>

      <div class="bld-edit-stats">
        <div><span>Size</span><strong>${b.widthTiles}×${b.heightTiles}</strong></div>
        <div><span>Tiles</span><strong>${b.widthTiles * b.heightTiles}</strong></div>
        ${floorStats}
        <div><span>Position</span><strong>${b.worldX}, ${b.worldY}</strong></div>
      </div>

      <label class="bld-edit-field">
        <span>Theme</span>
        <select id="bldThemeSelect" onchange="window._changeTheme('${b.id}', this.value)">
          ${Object.entries(BUILDING_THEMES).map(([k, v]) =>
            `<option value="${k}" ${(b._currentTheme || 'modern') === k ? 'selected' : ''}>${v.label}</option>`
          ).join('')}
        </select>
      </label>

      ${floorElevatorControls}

      <div class="bld-edit-group">
        <div class="bld-edit-group-title">Resize footprint</div>
        <div class="bld-resize-grid">
          <button class="bld-edit-btn" onclick="window._resizeBld('${b.id}', -1, 0)" title="Narrower">↔ Width −</button>
          <button class="bld-edit-btn" onclick="window._resizeBld('${b.id}', 1, 0)" title="Wider">↔ Width +</button>
          <button class="bld-edit-btn" onclick="window._resizeBld('${b.id}', 0, -1)" title="Shallower">↕ Depth −</button>
          <button class="bld-edit-btn" onclick="window._resizeBld('${b.id}', 0, 1)" title="Deeper">↕ Depth +</button>
        </div>
      </div>

      <div class="bld-edit-group">
        <div class="bld-edit-group-title">Actions</div>
        <div class="bld-action-grid">
          <button class="bld-edit-btn bld-edit-btn-primary" onclick="window._moveBld('${b.id}')">📦 Move</button>
          <button class="bld-edit-btn bld-edit-btn-success" onclick="window._rotateBld('${b.id}')">🔄 Rotate</button>
          <button class="bld-edit-btn" onclick="window._renameBld('${b.id}')">✏️ Rename</button>
          <button class="bld-edit-btn" onclick="window._copyBld('${b.id}')">📋 Copy</button>
          <button class="bld-edit-btn bld-edit-btn-danger" onclick="window._deleteBld('${b.id}')">🗑️ Delete</button>
        </div>
      </div>

      ${interiorTip}
    </div>
  `;
}

window._copyBld = (id) => {
  const b = buildingsMap.get(id);
  if (!b) return;
  const copyData = {
    name: (b.name || 'Building') + ' (Copy)',
    type: b.type || 'office',
    widthTiles: b.widthTiles,
    heightTiles: b.heightTiles,
    floorCount: getBuildingFloorCount(b),
    floors: JSON.parse(JSON.stringify(b.floors || [])),
    elevator: b.elevator ? { ...b.elevator } : null,
    exterior: { ...(b.exterior || {}) },
  };
  // Copy full interior data so walls/furniture come along with the duplicate
  if (b.interior) {
    copyData._copyInterior = JSON.parse(JSON.stringify(b.interior));
  }
  closeBuildingModal?.();
  startPlacement(copyData);
  showToast(`📋 Copying: ${b.name} — click to place`, 'warning');
};


window._setBldFloor = (id, floor) => {
  const b = buildingsMap.get(id);
  if (!b || isOutsideSpaceBuilding(b)) return;
  setActiveBuildingFloor(b, floor);
  createBuilding3D(b);
  selectBuilding(id);
  focusCameraOnBuildingFloor(b);
  showToast(`Showing floor ${getActiveBuildingFloor(b)}`, 'info');
};

window._addBldFloor = (id) => {
  const b = buildingsMap.get(id);
  if (!b || isOutsideSpaceBuilding(b)) return;
  normalizeBuildingFloors(b);
  const wasSingle = getBuildingFloorCount(b) === 1;
  b.floorCount = getBuildingFloorCount(b) + 1;
  normalizeBuildingFloors(b);
  setActiveBuildingFloor(b, b.floorCount);
  createBuilding3D(b);
  selectBuilding(id);
  persistBuilding(b);
  showToast(wasSingle ? '🛗 Added floor and placed default elevator shaft. Use Relocate elevator if needed.' : `Added floor ${b.floorCount}`, 'success');
};

window._removeBldFloor = (id) => {
  const b = buildingsMap.get(id);
  if (!b || isOutsideSpaceBuilding(b)) return;
  normalizeBuildingFloors(b);
  const top = getBuildingFloorCount(b);
  if (top <= 1) { showToast('Ground floor cannot be removed', 'warning'); return; }
  const topItems = (b.interior?.furniture || []).filter(f => getFurnitureFloor(f) === top);
  if (topItems.length && !confirm(`Remove floor ${top} and delete ${topItems.length} item(s) on that floor?`)) return;
  if (b.interior?.furniture) b.interior.furniture = b.interior.furniture.filter(f => getFurnitureFloor(f) !== top);
  b.floorCount = top - 1;
  normalizeBuildingFloors(b);
  setActiveBuildingFloor(b, Math.min(getActiveBuildingFloor(b), b.floorCount));
  createBuilding3D(b);
  selectBuilding(id);
  persistBuilding(b);
  showToast(`Removed floor ${top}`, 'warning');
};

window._relocateElevator = (id) => {
  const b = buildingsMap.get(id);
  if (!b || isOutsideSpaceBuilding(b)) return;
  normalizeBuildingFloors(b);
  if (getBuildingFloorCount(b) < 2) { showToast('Add a second floor first; elevator is required for upper floors.', 'warning'); return; }
  selectedBuildingId = id;
  _elevatorRelocateBuildingId = id;
  if (b.elevator) {
    const world = getBuildingWorldPoint(b, b.elevator.x, b.elevator.z);
    updateElevatorRelocatePreview(world.x, world.z);
  }
  showToast('🛗 Move elevator: click the new shaft location inside the building footprint', 'warning');
};

function openBuildingEditorForBuilding(id) {
  if (!ensureEditorUnlocked('Building editing')) return;
  setEditMode('buildings');
  if (typeof window._switchBuildingTab === 'function') window._switchBuildingTab('building');

  const leftSidebar = document.getElementById('leftSidebar');
  if (leftSidebar?.classList.contains('left-sidebar-collapsed')) {
    leftSidebar.classList.remove('left-sidebar-collapsed');
    updateMiniMapPosition();
  }

  selectBuilding(id);
  document.getElementById('buildingEditPanel')?.scrollIntoView({ block: 'nearest' });
}

// ═══════════════════════════════════════════════════════════════
// SIDEBAR
// ═══════════════════════════════════════════════════════════════
function setupSidebar() {
  // Right sidebar (agents only)
  document.getElementById('btn-toggleSidebar')?.addEventListener('click', () => {
    const sidebar = document.getElementById('sidebar');
    sidebar.classList.toggle('sidebar-collapsed');
    updateZoomControlsPosition();
  });
  // New Building button (now in left sidebar)
  document.getElementById('btn-newBuilding')?.addEventListener('click', () => {
    if (!ensureEditorUnlocked('Building editing')) return;
    document.getElementById('buildingModal').style.display = 'flex';
  });
  document.getElementById('btn-newOutsideSpace')?.addEventListener('click', () => {
    if (!ensureEditorUnlocked('Outside space editing')) return;
    document.getElementById('outsideSpaceModal').style.display = 'flex';
  });
  // Left sidebar (edit tools)
  document.getElementById('btn-toggleLeftSidebar')?.addEventListener('click', () => {
    if (!ensureEditorUnlocked('Edit panel')) return;
    document.getElementById('leftSidebar').classList.toggle('left-sidebar-collapsed');
    updateMiniMapPosition();
  });
}

// Shift zoom/rotation controls + chat panel so they don't get covered by the right sidebar
function updateZoomControlsPosition() {
  const sidebar = document.getElementById('sidebar');
  const zoomControls = document.getElementById('zoomControls');
  const chatPanel = document.getElementById('chat-panel');
  if (!sidebar || !zoomControls) return;
  const isOpen = !sidebar.classList.contains('sidebar-collapsed');
  const sidebarWidth = parseInt(getComputedStyle(document.documentElement).getPropertyValue('--sidebar-width')) || 280;
  const rightOffset = isOpen ? sidebarWidth + 16 : 16;
  zoomControls.style.transition = 'right 0.25s ease';
  zoomControls.style.right = rightOffset + 'px';
  // Also shift chat panel so it stays next to the zoom controls
  if (chatPanel) {
    chatPanel.style.transition = 'right 0.3s ease';
    chatPanel.style.right = (rightOffset + 50) + 'px'; // offset from zoom controls column
  }
}

// Shift mini-map so it doesn't get covered by the left sidebar
function updateMiniMapPosition() {
  const leftSidebar = document.getElementById('leftSidebar');
  const miniMap = document.getElementById('miniMap');
  if (!leftSidebar || !miniMap) return;
  const isOpen = !leftSidebar.classList.contains('left-sidebar-collapsed');
  const leftSidebarWidth = 260; // matches CSS .left-sidebar width
  miniMap.style.transition = 'left 0.25s ease';
  miniMap.style.left = isOpen ? `${leftSidebarWidth + 16}px` : '16px';
}

function renderBuildingOccupantsList(b) {
  const occupants = getBuildingOccupants(b);
  if (!occupants.length) {
    return '<div class="building-occupants-empty">No occupants right now</div>';
  }
  return occupants.map(a => {
    const sc = getPresenceStateIcon(a.status);
    const label = `${a.emoji || '🤖'} ${a.name || a.id}`;
    return `<div class="building-occupant-item"><span>${escapeHtml(label)}</span><span>${sc} ${escapeHtml(a.status || 'offline')}</span></div>`;
  }).join('');
}

function updateBuildingList() {
  const buildingListEl = document.getElementById('buildingList');
  const outsideListEl = document.getElementById('outsideSpaceList');
  if (buildingListEl) buildingListEl.innerHTML = '';
  if (outsideListEl) outsideListEl.innerHTML = '';

  for (const [, b] of buildingsMap) {
    const item = document.createElement('div');
    item.className = 'sidebar-item';
    const isOutsideSpace = b.type === 'park';
    const typeIcons = { office: '🏢', home: '🏠', store: '🏪', park: '🌳' };
    const typeLabel = isOutsideSpace ? 'outside space' : (b.type || 'office');
    const typeIcon = typeIcons[b.type] || (isOutsideSpace ? '🌳' : '🏢');
    const occupants = getBuildingOccupants(b);
    const isExpanded = expandedBuildingOccupants.has(b.id);
    item.classList.toggle('building-list-expanded', isExpanded);
    item.innerHTML = `
      <div class="building-list-main">
        <div class="building-list-text">
          <div class="item-name">${typeIcon} ${escapeHtml(b.name || 'Building')}</div>
          <div class="item-detail">${escapeHtml(typeLabel)} · ${b.widthTiles}×${b.heightTiles}</div>
        </div>
        <button class="building-occupants-toggle" title="${isExpanded ? 'Hide' : 'Show'} occupants" aria-expanded="${isExpanded}">
          <span>${occupants.length}</span> 👥 ${isExpanded ? '▴' : '▾'}
        </button>
      </div>
      ${isExpanded ? `<div class="building-occupants-panel">${renderBuildingOccupantsList(b)}</div>` : ''}
    `;
    item.querySelector('.building-occupants-toggle')?.addEventListener('click', (e) => {
      e.stopPropagation();
      if (expandedBuildingOccupants.has(b.id)) expandedBuildingOccupants.delete(b.id);
      else expandedBuildingOccupants.add(b.id);
      updateBuildingList();
    });
    item.addEventListener('click', (e) => {
      if (e.target.closest('.building-occupants-toggle, .building-occupants-panel')) return;
      const bounds = getBuildingFootprintBounds(b, 0);
      const bw = bounds.width;
      const bd = bounds.depth;
      flyCameraTo(new THREE.Vector3(bounds.centerX, 0, bounds.centerZ), Math.max(15, Math.sqrt(bw * bw + bd * bd) * 0.8));
      showToast(`${isOutsideSpace ? '🌳' : '🏗️'} ${b.name}`, 'info');
    });
    if (isOutsideSpace) outsideListEl?.appendChild(item);
    else buildingListEl?.appendChild(item);
  }
}

setInterval(() => {
  if (expandedBuildingOccupants.size > 0) updateBuildingList();
}, 2500);

function updateAgentList() {
  const l = document.getElementById('agentList');
  if (!l) return;
  const previousValue = l.value || '';
  l.innerHTML = '<option value="">Choose an agent…</option>';
  agentsList.forEach(a => {
    const sc = getPresenceStateIcon(a.status);
    const option = document.createElement('option');
    option.value = a.id;
    option.textContent = `${a.emoji || '🤖'} ${a.name || a.id} ${sc} — ${a.status || 'offline'}`;
    l.appendChild(option);
  });
  if (previousValue && agentsList.some(a => a.id === previousValue)) l.value = previousValue;
  else selectedAgentId = null;

  if (!l.dataset.boundAgentSelect) {
    l.dataset.boundAgentSelect = 'true';
    l.addEventListener('change', () => {
      if (l.value) openAgentPanel(l.value);
      else {
        selectedAgentId = null;
        const panel = document.getElementById('agentPanel');
        if (panel) panel.style.display = 'none';
      }
    });
  }

  if (selectedAgentId && l.value === selectedAgentId) openAgentPanel(selectedAgentId, { preserveCamera: true });
}

function closeAgentEditor() {
  selectedAgentId = null;
  const agentSelect = document.getElementById('agentList');
  if (agentSelect) agentSelect.value = '';
  const panel = document.getElementById('agentPanel');
  if (panel) panel.style.display = 'none';
  if (_agentFollowTransparentBldId) {
    setBuildingTransparent(_agentFollowTransparentBldId, false);
    _agentFollowTransparentBldId = null;
  }
}

window.closeAgentEditor = closeAgentEditor;

// ═══════════════════════════════════════════════════════════════
// BUILDING MODAL & PLACEMENT
// ═══════════════════════════════════════════════════════════════
function applyBuildingTemplatePreset(templateId) {
  const record = templateId ? BUILDING_TEMPLATE_REGISTRY.get(templateId) : null;
  const template = record?.template || null;
  const nameEl = document.getElementById('bld-name');
  const typeEl = document.getElementById('bld-type');
  const themeEl = document.getElementById('bld-theme');
  const roofEl = document.getElementById('bld-roofColor');
  const wallEl = document.getElementById('bld-wallColor');
  const widthEl = document.getElementById('bld-width');
  const heightEl = document.getElementById('bld-height');
  const hintEl = document.getElementById('bld-templateHint');
  if (!template) {
    if (hintEl) hintEl.textContent = 'Template suggestions reference completed existing assets only.';
    return;
  }
  if (nameEl) nameEl.value = template.name;
  if (typeEl && template.buildingType && BUILDING_TYPES[template.buildingType]) {
    typeEl.value = template.buildingType;
    widthEl.value = BUILDING_TYPES[template.buildingType].w;
    heightEl.value = BUILDING_TYPES[template.buildingType].h;
  }
  if (themeEl && template.exteriorStyle && BUILDING_THEMES[template.exteriorStyle]) themeEl.value = template.exteriorStyle;
  if (roofEl && template.colors?.roofColor) roofEl.value = template.colors.roofColor;
  if (wallEl && template.colors?.wallColor) wallEl.value = template.colors.wallColor;
  _selectedTemplateSuggestionId = template.id;
  setupFurnitureCatalog();
  const connection = getTemplateSuggestionConnection(template.id);
  if (hintEl) {
    hintEl.textContent = connection
      ? `${connection.suggestedAssets.length} completed asset suggestions connected; ${connection.skippedAssets.length} future/incomplete references skipped.`
      : 'No completed suggestions connected for this template yet.';
  }
}

function setupBuildingModal() {
  const templateSelect = document.getElementById('bld-template');
  if (templateSelect) {
    templateSelect.innerHTML = '<option value="">Blank / custom</option>' + BUILDING_TEMPLATE_REGISTRY.entries
      .map(record => `<option value="${record.id}">${record.name}</option>`)
      .join('');
    templateSelect.addEventListener('change', () => applyBuildingTemplatePreset(templateSelect.value));
  }

  const typeSelect = document.getElementById('bld-type');
  if (typeSelect) {
    typeSelect.addEventListener('change', () => {
      const bt = BUILDING_TYPES[typeSelect.value];
      if (bt) {
        document.getElementById('bld-width').value = bt.w;
        document.getElementById('bld-height').value = bt.h;
      }
    });
  }

  const outsideTypeSelect = document.getElementById('outside-type');
  if (outsideTypeSelect) {
    outsideTypeSelect.addEventListener('change', () => {
      const ot = OUTSIDE_SPACE_TYPES[outsideTypeSelect.value];
      if (ot) {
        document.getElementById('outside-width').value = ot.w;
        document.getElementById('outside-height').value = ot.h;
      }
    });
  }

  // Theme dropdown: apply theme colors when changed
  const themeSelect = document.getElementById('bld-theme');
  if (themeSelect) {
    // Populate options
    themeSelect.innerHTML = Object.entries(BUILDING_THEMES)
      .map(([k, v]) => `<option value="${k}">${v.label}</option>`)
      .join('');
    themeSelect.addEventListener('change', () => {
      const theme = BUILDING_THEMES[themeSelect.value];
      if (!theme) return;
      const roofEl = document.getElementById('bld-roofColor');
      const wallEl = document.getElementById('bld-wallColor');
      if (roofEl) roofEl.value = theme.roofColor;
      if (wallEl) wallEl.value = theme.wallColor;
    });
  }

  document.getElementById('btn-createBuilding')?.addEventListener('click', () => {
    const name = document.getElementById('bld-name').value || 'New Building';
    const type = document.getElementById('bld-type').value || 'office';
    const w = parseInt(document.getElementById('bld-width').value) || 25;
    const h = parseInt(document.getElementById('bld-height').value) || 17;
    const roofColor = document.getElementById('bld-roofColor').value || '#546e7a';
    const wallColor = document.getElementById('bld-wallColor').value || '#78909c';
    const templateId = document.getElementById('bld-template')?.value || null;
    closeBuildingModal();
    startPlacement({ name, type, widthTiles: w, heightTiles: h,
      templateId,
      templateSuggestionIds: Object.freeze([...(getTemplateSuggestionConnection(templateId)?.suggestedAssetIds || [])]),
      exterior: { roofColor, wallColor } });
  });

  document.getElementById('btn-createOutsideSpace')?.addEventListener('click', () => {
    const name = document.getElementById('outside-name').value || 'New Outside Space';
    const type = document.getElementById('outside-type').value || 'park';
    const w = parseInt(document.getElementById('outside-width').value) || 20;
    const h = parseInt(document.getElementById('outside-height').value) || 20;
    closeOutsideSpaceModal();
    startPlacement({ name, type, widthTiles: w, heightTiles: h, category: 'outside-space' });
  });

  document.getElementById('btn-newInteriorWall')?.addEventListener('click', startInteriorWallPlacement);
  document.getElementById('btn-newInteriorOpening')?.addEventListener('click', startInteriorWallOpeningPlacement);
  document.getElementById('btn-cancelInteriorWall')?.addEventListener('click', cancelInteriorWallPlacement);
  document.getElementById('btn-deleteInteriorWall')?.addEventListener('click', deleteSelectedInteriorWall);
}

// Track whether placement ghost is currently colliding
let _placementColliding = false;


// Helper: strip Three.js objects before saving building to server
function _buildingPayload(b) {
  if (b?.type === 'park') ensureParkGeneratedTrees(b);
  ensureBuildingPlacedObjectActionTargets(b);
  const p = { ...b };
  if (b?.interior) {
    p.interior = {
      ...b.interior,
      furniture: JSON.parse(JSON.stringify(b.interior.furniture || [])),
      walls: JSON.parse(JSON.stringify(b.interior.walls || [])),
    };
  }
  if (b?.outdoorArea) p.outdoorArea = JSON.parse(JSON.stringify(b.outdoorArea));
  if (b?.outdoorNodes) p.outdoorNodes = JSON.parse(JSON.stringify(b.outdoorNodes));
  clearBuildingTransientObjectAssignments(p);
  p.doorSpec = b?.doorSpec || b?._doorSpec || null;
  delete p._group; delete p._badgeSprite; delete p._lastBadgeCount;
  delete p._signGroup; delete p._roof; delete p._interiorCanvas;
  delete p._interiorSprite; delete p._voEngine; delete p._occupantInterval;
  delete p._moveColliding; delete p._pendingX; delete p._pendingZ; delete p._pendingY;
  delete p._snapped; delete p._currentTheme; delete p._doorSpec;
  return p;
}

function startPlacement(data) {
  if (!ensureEditorUnlocked(data?.category === 'outside-space' ? 'Outside space editing' : 'Building editing')) return;
  placementMode = 'building';
  placementData = data;
  _placementColliding = false;
  showToast('Click to place building. Red = overlapping!', 'warning');

  // Ghost preview — uses a unique material so we can change color per-frame
  const bw = data.widthTiles * T;
  const bd = data.heightTiles * T;
  placementGhost = new THREE.Group();
  const ghostMat = new THREE.MeshLambertMaterial({ color: 0x4caf50, transparent: true, opacity: 0.35, flatShading: true });
  const preview = new THREE.Mesh(_boxGeo, ghostMat);
  preview.scale.set(bw, 1, bd);
  preview.position.set(bw / 2, 0.5, bd / 2);
  preview.name = 'ghostBox';
  placementGhost.add(preview);

  // Wireframe outline for visibility
  const outlineMat = new THREE.MeshBasicMaterial({ color: 0x4caf50, wireframe: true, transparent: true, opacity: 0.7 });
  const outline = new THREE.Mesh(_boxGeo, outlineMat);
  outline.scale.set(bw + 0.2, 1.2, bd + 0.2);
  outline.position.set(bw / 2, 0.5, bd / 2);
  outline.name = 'ghostOutline';
  placementGhost.add(outline);

  scene.add(placementGhost);
}

/**
 * Check if any natural ground items (rocks, trees, placed decorations) exist in a tile area.
 * Used to turn the placement ghost red when natural items are present.
 */
function hasNaturalItemsInArea(wx, wz, widthTiles, heightTiles) {
  // Check procedural trees and rocks in the area
  for (let tz = wz; tz < wz + heightTiles; tz++) {
    for (let tx = wx; tx < wx + widthTiles; tx++) {
      const cx = Math.floor(tx / CHUNK);
      const cz = Math.floor(tz / CHUNK);
      const ltx = ((tx % CHUNK) + CHUNK) % CHUNK;
      const ltz = ((tz % CHUNK) + CHUNK) % CHUNK;
      const chunk = loadedChunks.get(chunkKey(cx, cz));
      if (!chunk) continue;
      const tileType = chunk.terrain[ltz * CHUNK + ltx];
      if (tileType !== TERRAIN.GRASS) continue;
      // Skip tiles already inside another building footprint (decorations are suppressed there)
      if (isInsideBuildingFootprint(tx, tz, 1)) continue;
      // Check procedural tree (same RNG as buildChunkDecorations)
      const seed = cx * 1000 + cz;
      const rng = pseudoRandom(seed + ltx * 31 + ltz * 97);
      if (rng < 0.006) return true; // tree here
      // Check procedural rock
      const rng2 = pseudoRandom(seed + ltx * 53 + ltz * 139);
      if (rng2 > 0.995) return true; // rock here
    }
  }
  // Check user-placed decorations
  const cx1 = Math.floor(wx / CHUNK), cz1 = Math.floor(wz / CHUNK);
  const cx2 = Math.floor((wx + widthTiles - 1) / CHUNK), cz2 = Math.floor((wz + heightTiles - 1) / CHUNK);
  for (let ccx = cx1; ccx <= cx2; ccx++) {
    for (let ccz = cz1; ccz <= cz2; ccz++) {
      const placed = placedDecorations.get(chunkDecorationKey(ccx, ccz)) || [];
      for (const pd of placed) {
        if (pd.wx >= wx && pd.wx < wx + widthTiles && pd.wz >= wz && pd.wz < wz + heightTiles) {
          if (pd.type === 'tree' || pd.type === 'rock' || pd.type === 'flower' || pd.type === 'bush') return true;
        }
      }
    }
  }
  return false;
}

/**
 * Remove user-placed natural decorations (trees, rocks, flowers, etc.) within a building footprint.
 * Procedural trees/rocks are already hidden by isInsideBuildingFootprint() during chunk rebuild.
 */
function _removeNaturalDecorationsInArea(wx, wz, widthTiles, heightTiles) {
  const cx1 = Math.floor(wx / CHUNK), cz1 = Math.floor(wz / CHUNK);
  const cx2 = Math.floor((wx + widthTiles - 1) / CHUNK), cz2 = Math.floor((wz + heightTiles - 1) / CHUNK);
  for (let ccx = cx1; ccx <= cx2; ccx++) {
    for (let ccz = cz1; ccz <= cz2; ccz++) {
      const key = chunkDecorationKey(ccx, ccz);
      const placed = placedDecorations.get(key);
      if (!placed || placed.length === 0) continue;
      const kept = [];
      for (const pd of placed) {
        const inArea = pd.wx >= wx && pd.wx < wx + widthTiles && pd.wz >= wz && pd.wz < wz + heightTiles;
        if (inArea && (pd.type === 'tree' || pd.type === 'rock' || pd.type === 'flower' || pd.type === 'bush')) {
          // Remove physics collider using the standard naming convention
          removeBody(`pdecor_${ccx}_${ccz}_${pd.wx}_${pd.wz}`);
        } else {
          kept.push(pd);
        }
      }
      if (kept.length !== placed.length) {
        placedDecorations.set(key, kept);
        debounceSavePlacedDecorations();
      }
    }
  }
}

function snapBuildingFootprintToStreet(gx, gz, bw, bd) {
  // Use actual street mesh geometry, not terrain tiles, so move + new placement
  // both align to the same visible sidewalk edge.
  let snappedZ = false, snappedX = false;
  const backDist = Math.ceil(ST.HALF_W); // tiles from road center to back of sidewalk

  function findNearestStreet(px, pz, maxDist) {
    let best = null;
    let bestD = maxDist + 1;
    for (const seg of _streetSegments) {
      if (seg.type) continue; // skip intersections
      const isH = Math.abs(seg.x2 - seg.x1) >= Math.abs(seg.z2 - seg.z1);
      if (isH) {
        const cz = seg.z1;
        const minX = Math.min(seg.x1, seg.x2) - backDist;
        const maxX = Math.max(seg.x1, seg.x2) + backDist;
        if (px >= minX && px <= maxX) {
          const d = Math.abs(pz - cz);
          if (d < bestD) {
            bestD = d;
            best = { centerX: px, centerZ: cz, isH: true, dist: d };
          }
        }
      } else {
        const cx = seg.x1;
        const minZ = Math.min(seg.z1, seg.z2) - backDist;
        const maxZ = Math.max(seg.z1, seg.z2) + backDist;
        if (pz >= minZ && pz <= maxZ) {
          const d = Math.abs(px - cx);
          if (d < bestD) {
            bestD = d;
            best = { centerX: cx, centerZ: pz, isH: false, dist: d };
          }
        }
      }
    }
    return best;
  }

  const midX = gx + bw / 2;
  const midZ = gz + bd / 2;
  let bestSouthGz = null;
  let bestNorthGz = null;
  let bestEastGx = null;
  let bestWestGx = null;

  const southStreet = findNearestStreet(midX, gz + bd + backDist, backDist + SNAP_RANGE);
  if (southStreet?.isH) {
    const backNorthZ = southStreet.centerZ - backDist;
    const backSouthZ = southStreet.centerZ + backDist;
    if (midZ < southStreet.centerZ) {
      bestSouthGz = backNorthZ - bd;
    } else {
      bestSouthGz = backSouthZ + 1 - bd;
    }
  }

  const northStreet = findNearestStreet(midX, gz - backDist, backDist + SNAP_RANGE);
  if (northStreet?.isH) {
    if (midZ > northStreet.centerZ) {
      bestNorthGz = northStreet.centerZ + backDist + 1;
    } else {
      bestNorthGz = northStreet.centerZ - backDist;
    }
  }

  if (bestSouthGz !== null || bestNorthGz !== null) {
    const dS = bestSouthGz !== null ? Math.abs(bestSouthGz - gz) : Infinity;
    const dN = bestNorthGz !== null ? Math.abs(bestNorthGz - gz) : Infinity;
    gz = dS <= dN ? bestSouthGz : bestNorthGz;
    snappedZ = true;
  }

  const eastStreet = findNearestStreet(gx + bw + backDist, midZ, backDist + SNAP_RANGE);
  if (eastStreet && !eastStreet.isH) {
    if (midX < eastStreet.centerX) {
      bestEastGx = eastStreet.centerX - backDist - bw;
    } else {
      bestEastGx = eastStreet.centerX + backDist + 1 - bw;
    }
  }

  const westStreet = findNearestStreet(gx - backDist, midZ, backDist + SNAP_RANGE);
  if (westStreet && !westStreet.isH) {
    if (midX > westStreet.centerX) {
      bestWestGx = westStreet.centerX + backDist + 1;
    } else {
      bestWestGx = westStreet.centerX - backDist;
    }
  }

  if (bestEastGx !== null || bestWestGx !== null) {
    const dE = bestEastGx !== null ? Math.abs(bestEastGx - gx) : Infinity;
    const dW = bestWestGx !== null ? Math.abs(bestWestGx - gx) : Infinity;
    gx = dE <= dW ? bestEastGx : bestWestGx;
    snappedX = true;
  }

  const snapped = snappedX || snappedZ;
  return {
    x: gx,
    z: gz,
    snapped,
    elevY: snapped ? (ST.BASE + ST.SIDEWALK_H - 0.15) : 0,
  };
}

function beginBuildingMovePreview(b) {
  if (!b?._group) return;
  b._group.traverse((c) => {
    if (!c.isMesh || !c.material || c.userData._movePreviewMaterials) return;
    const originalMaterials = Array.isArray(c.material) ? c.material : [c.material];
    const previewMaterials = originalMaterials.map((mat) => {
      if (!mat?.clone) return mat;
      const preview = mat.clone();
      preview.transparent = true;
      preview.opacity = 0.4;
      preview.needsUpdate = true;
      return preview;
    });
    c.userData._movePreviewOriginalMaterials = originalMaterials;
    c.userData._movePreviewMaterials = previewMaterials;
    c.material = Array.isArray(c.material) ? previewMaterials : previewMaterials[0];
  });
}

function updateBuildingMovePreviewState(b, colliding) {
  if (!b?._group) return;
  const collisionColor = new THREE.Color(0xf44336);
  b._group.traverse((c) => {
    if (!c.isMesh) return;
    const previewMaterials = c.userData._movePreviewMaterials;
    const originalMaterials = c.userData._movePreviewOriginalMaterials;
    if (!previewMaterials || !originalMaterials) return;
    previewMaterials.forEach((preview, idx) => {
      const original = originalMaterials[idx];
      if (!preview) return;
      preview.transparent = true;
      preview.opacity = colliding ? 0.5 : 0.4;
      if (preview.color && original?.color) {
        if (colliding) preview.color.copy(collisionColor);
        else preview.color.copy(original.color);
      }
      preview.needsUpdate = true;
    });
  });
}

/**
 * Check if a building footprint at (wx, wz) with given tile dimensions
 * overlaps any existing building or decoration. 
 * Uses Rapier physics intersection test when available, falls back to AABB.
 */
function checkBuildingCollision(wx, wz, widthTiles, heightTiles, excludeId) {
  // Use AABB check against buildings only — natural items (trees/rocks) are auto-removed on placement
  // Physics-based test is not used here because it catches decorations (trees, lampposts, etc.)
  for (const [id, b] of buildingsMap) {
    if (id === excludeId) continue;
    const isSwapped = (b._rotation === 90 || b._rotation === 270);
    const bw = isSwapped ? (b.heightTiles || 17) : (b.widthTiles || 25);
    const bd = isSwapped ? (b.widthTiles || 25) : (b.heightTiles || 17);
    const bx = b.worldX || 0;
    const bz = b.worldY || 0;
    if (wx < bx + bw && wx + widthTiles > bx &&
        wz < bz + bd && wz + heightTiles > bz) {
      return true;
    }
  }
  return false;
}

function finalizePlacement(e) {
  if (!placementMode || !placementData) return;

  const bd = placementData.heightTiles || 17;
  const bw = placementData.widthTiles || 25;

  // Use pre-snapped coordinates from ghost preview (already snapped in mousemove)
  let wx, wz, elevY;
  if (placementData._snappedGx !== undefined) {
    wx = placementData._snappedGx;
    wz = placementData._snappedGz;
    elevY = placementData._snappedElev || 0;
  } else {
    const hit = raycastGround(e);
    if (!hit) return;
    wx = Math.floor(hit.x / T);
    wz = Math.floor(hit.z / T);
    elevY = 0;
  }

  // Block placement if overlapping another building
  if (checkBuildingCollision(wx, wz, bw, bd)) {
    showToast('❌ Cannot place here — overlaps another building!', 'error');
    return;
  }

  // Auto-remove user-placed natural decorations (trees, rocks, etc.) under the building footprint
  _removeNaturalDecorationsInArea(wx, wz, bw, bd);

  const id = 'bld_' + Date.now();
  const building = {
    id,
    name: placementData.name,
    type: placementData.type,
    worldX: wx,
    worldY: wz,
    widthTiles: placementData.widthTiles,
    heightTiles: placementData.heightTiles,
    exterior: placementData.exterior,
    _elevationY: elevY,
  };
  // If this is a copy, bring interior data along too
  if (placementData._copyInterior) {
    building.interior = JSON.parse(JSON.stringify(placementData._copyInterior));
  } else if (placementData._copyFurniture) {
    // Backward compatibility for older copy payloads
    building.interior = { furniture: placementData._copyFurniture };
  }

  try {
    buildingsMap.set(id, building);
    createBuilding3D(building);
    updateBuildingList();

    // Push undo for building creation
    pushUndo({ type: 'buildingCreate', buildingId: id });

    // Save to server
    fetch('/api/buildings', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(_buildingPayload(building)),
    }).catch(() => {});

    // Rebuild chunks under the new building so terrain is cleared
    const bx1 = Math.floor(wx / CHUNK);
    const bz1 = Math.floor(wz / CHUNK);
    const bx2 = Math.floor((wx + building.widthTiles) / CHUNK);
    const bz2 = Math.floor((wz + building.heightTiles) / CHUNK);
    for (let ccx = bx1; ccx <= bx2; ccx++) {
      for (let ccz = bz1; ccz <= bz2; ccz++) {
        const chunk = loadedChunks.get(chunkKey(ccx, ccz));
        if (chunk) rebuildChunk(chunk);
      }
    }

    cancelPlacement();
    const snapMsg = elevY > 0 ? ' (snapped to street!)' : '';
    showToast(`🏗️ Built: ${building.name}${snapMsg}`, 'success');
  } catch (err) {
    // Roll back if 3D creation failed
    buildingsMap.delete(id);
    cancelPlacement();
    showToast('❌ Failed to create building', 'error');
  }
}

function cancelPlacement() {
  placementMode = null;
  if (placementData) {
    delete placementData._snappedGx;
    delete placementData._snappedGz;
    delete placementData._snappedElev;
  }
  placementData = null;
  if (placementGhost) { scene.remove(placementGhost); placementGhost = null; }
}

// ═══════════════════════════════════════════════════════════════
// UNDO  (typed undo stack — max 30)
// ═══════════════════════════════════════════════════════════════
const MAX_UNDO = 30;

function pushUndo(entry) {
  undoStack.push(entry);
  if (undoStack.length > MAX_UNDO) undoStack.shift();
  redoStack.length = 0; // clear redo stack on new action
}

function snapshotBuildingForUndo(building) {
  return JSON.parse(JSON.stringify(_buildingPayload(building)));
}

function restoreBuildingFromUndoSnapshot(snapshot) {
  if (!snapshot?.id) return;
  const current = buildingsMap.get(snapshot.id);
  const oldX = current?.worldX || snapshot.worldX || 0;
  const oldZ = current?.worldY || snapshot.worldY || 0;
  const oldR = Math.max(current?.widthTiles || 25, current?.heightTiles || 17) + 3;
  const restored = JSON.parse(JSON.stringify(snapshot));
  clearSelectedBuildingHelper();
  clearSelectedBuildingResizeHandles();
  if (current?._group) buildingGroup.remove(current._group);
  if (current?._signGroup) buildingGroup.remove(current._signGroup);
  buildingsMap.set(restored.id, restored);
  createBuilding3D(restored);
  _rebuildNearChunks(oldX, oldZ, oldR);
  _rebuildNearChunks(restored.worldX || 0, restored.worldY || 0, Math.max(restored.widthTiles || 25, restored.heightTiles || 17) + 3);
  if (selectedBuildingId === restored.id) {
    selectBuilding(restored.id);
  } else {
    updateBuildingEditPanel(selectedBuildingId ? buildingsMap.get(selectedBuildingId) : null);
  }
  updateBuildingList();
  persistBuilding(restored);
}

function _applyUndoEntry(u, isRedo) {
  const prefix = isRedo ? '↪️ Redo' : '↩️ Undo';

  if (u.type === 'terrain') {
    const chunk = loadedChunks.get(u.key);
    if (chunk) {
      chunk.terrain[u.idx] = isRedo ? u.newType : u.oldType;
      chunk.dirty = true;
      rebuildChunk(chunk);
    }
    showToast(`${prefix} terrain`, 'warning');

  } else if (u.type === 'buildingDelete') {
    if (isRedo) {
      // Redo a delete = delete again
      const b = buildingsMap.get(u.buildingData.id);
      if (b) {
        if (b._group) buildingGroup.remove(b._group);
        buildingsMap.delete(u.buildingData.id);
        updateBuildingList();
        fetch(`/api/building/${u.buildingData.id}`, { method: 'DELETE' }).catch(() => {});
      }
      showToast(`${prefix} delete ${u.buildingData.name}`, 'warning');
    } else {
      const b = u.buildingData;
      buildingsMap.set(b.id, b);
      createBuilding3D(b);
      updateBuildingList();
      fetch('/api/buildings', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(_buildingPayload(b)),
      }).catch(() => {});
      showToast(`${prefix} — restored ${b.name}`, 'warning');
    }

  } else if (u.type === 'streets') {
    // Save current state for reverse operation
    const currentSnapshot = _snapshotStreets();
    _restoreStreets(isRedo ? u.redoSnapshot : u.snapshot);
    if (isRedo) u.snapshot = currentSnapshot;
    else u.redoSnapshot = currentSnapshot;
    showToast(`${prefix} street change`, 'warning');

  } else if (u.type === 'interiorWalls') {
    const b = buildingsMap.get(u.buildingId);
    if (b) {
      if (!b.interior) b.interior = {};
      b.interior.walls = JSON.parse(JSON.stringify(isRedo ? u.after : u.before));
      rebuildInteriorWalls(b);
      persistBuilding(b);
    }
    showToast(`${prefix} interior walls`, 'warning');

  } else if (u.type === 'furniture') {
    const b = buildingsMap.get(u.buildingId);
    if (b) {
      if (!b.interior) b.interior = {};
      b.interior.furniture = JSON.parse(JSON.stringify(isRedo ? u.after : u.before));
      createBuilding3D(b);
      if (selectedBuildingId === b.id) updateBuildingEditPanel(b);
      persistBuilding(b);
    }
    showToast(`${prefix} furniture`, 'warning');

  } else if (u.type === 'buildingCreate') {
    if (isRedo) {
      // Redo a create = re-create (we stored the data)
      if (u.buildingData) {
        const b = u.buildingData;
        buildingsMap.set(b.id, b);
        createBuilding3D(b);
        updateBuildingList();
        fetch('/api/buildings', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(_buildingPayload(b)),
        }).catch(() => {});
      }
      showToast(`${prefix} building creation`, 'warning');
    } else {
      const b = buildingsMap.get(u.buildingId);
      if (b) {
        // Save building data for redo
        u.buildingData = JSON.parse(JSON.stringify(b, (k, v) => k.startsWith('_') ? undefined : v));
        if (b._group) buildingGroup.remove(b._group);
        buildingsMap.delete(u.buildingId);
        updateBuildingList();
        fetch(`/api/building/${u.buildingId}`, { method: 'DELETE' }).catch(() => {});
      }
      showToast(`${prefix} building creation`, 'warning');
    }

  } else if (u.type === 'buildingUpdate') {
    restoreBuildingFromUndoSnapshot(isRedo ? u.after : u.before);
    showToast(`${prefix} ${u.label || 'building change'}`, 'warning');

  } else {
    const chunk = loadedChunks.get(u.key);
    if (chunk && u.terrain) {
      chunk.terrain = u.terrain;
      chunk.dirty = true;
      rebuildChunk(chunk);
    }
    showToast(`${prefix}`, 'warning');
  }
}

function doUndo() {
  if (!ensureEditorUnlocked('Undo')) return;
  if (undoStack.length === 0) { showToast('Nothing to undo', 'warning'); return; }
  const u = undoStack.pop();
  _applyUndoEntry(u, false);
  redoStack.push(u);
}

function doRedo() {
  if (!ensureEditorUnlocked('Redo')) return;
  if (redoStack.length === 0) { showToast('Nothing to redo', 'warning'); return; }
  const u = redoStack.pop();
  _applyUndoEntry(u, true);
  undoStack.push(u);
}

// ═══════════════════════════════════════════════════════════════
// MINI-MAP
// ═══════════════════════════════════════════════════════════════
function setupMiniMap() {
  const canvas = document.getElementById('miniMapCanvas');
  if (canvas) miniMapCtx = canvas.getContext('2d');
}

function updateMiniMap() {
  if (!miniMapCtx) return;
  const ctx = miniMapCtx;
  const cw = 200, ch = 200;

  // Green terrain background
  ctx.fillStyle = '#3a7d34';
  ctx.fillRect(0, 0, cw, ch);

  const mapScale = 0.15;
  const ox = cw / 2 - camTarget.x * mapScale;
  const oz = ch / 2 - camTarget.z * mapScale;

  // Draw chunks — show road tiles as dark lines, water as blue
  for (const [, c] of loadedChunks) {
    const chunkPxX = c.cx * CHUNK_W * mapScale + ox;
    const chunkPxZ = c.cz * CHUNK_W * mapScale + oz;
    // Chunk base
    ctx.fillStyle = '#4a9a42';
    ctx.fillRect(chunkPxX, chunkPxZ, CHUNK_W * mapScale, CHUNK_W * mapScale);
    // Draw road/water tiles
    const tilePx = T * mapScale;
    if (tilePx >= 0.5) { // only draw if tiles are visible
      for (let tz2 = 0; tz2 < CHUNK; tz2++) {
        for (let tx2 = 0; tx2 < CHUNK; tx2++) {
          const type = c.terrain[tz2 * CHUNK + tx2];
          let col = null;
          if (type === TERRAIN.ROAD) col = '#333333';
          else if (type === TERRAIN.SIDEWALK) col = '#888888';
          else if (type === TERRAIN.WATER) col = '#2196f3';
          else if (type === TERRAIN.SAND) col = '#c8b560';
          else if (type === TERRAIN.PARKING) col = '#4a4a4a';
          if (col) {
            ctx.fillStyle = col;
            ctx.fillRect(
              chunkPxX + tx2 * tilePx, chunkPxZ + tz2 * tilePx,
              Math.max(tilePx, 0.5), Math.max(tilePx, 0.5)
            );
          }
        }
      }
    }
  }

  // Draw buildings as colored rectangles
  for (const [, b] of buildingsMap) {
    const bounds = getBuildingFootprintBounds(b, 0);
    const bx = bounds.minX * mapScale + ox;
    const bz = bounds.minZ * mapScale + oz;
    const bw = bounds.width * mapScale;
    const bd = bounds.depth * mapScale;
    // Color by type
    const btype = b.type || 'office';
    const typeColors = { office: '#78909c', home: '#ef9a9a', store: '#ffcc80', park: '#a5d6a7' };
    ctx.fillStyle = typeColors[btype] || '#78909c';
    ctx.fillRect(bx, bz, Math.max(bw, 2), Math.max(bd, 2));
    ctx.strokeStyle = 'rgba(0,0,0,0.4)';
    ctx.lineWidth = 0.5;
    ctx.strokeRect(bx, bz, Math.max(bw, 2), Math.max(bd, 2));
  }

  // Draw agents as tiny colored dots
  const scale = T / API_TILE;
  agentsList.forEach(a => {
    const ax = a.x * scale * mapScale + ox;
    const az = a.y * scale * mapScale + oz;
    ctx.fillStyle = isWorkPresenceStatus(a.status) ? '#00e676' : a.status === 'idle' ? '#ffd740' : '#bdbdbd';
    ctx.beginPath();
    ctx.arc(ax, az, 2.5, 0, Math.PI * 2);
    ctx.fill();
    // White outline for visibility
    ctx.strokeStyle = 'rgba(255,255,255,0.6)';
    ctx.lineWidth = 0.5;
    ctx.stroke();
  });

  // Camera viewport indicator based on the real render viewport.
  const viewport = getCameraViewportMetrics();
  const viewW = viewport.worldWidth * mapScale;
  const viewH = viewport.worldHeight * mapScale;
  ctx.strokeStyle = '#ffd600';
  ctx.lineWidth = 1.5;
  ctx.strokeRect(cw / 2 - viewW / 2, ch / 2 - viewH / 2, viewW, viewH);
  // Center crosshair dot
  ctx.fillStyle = '#ffd600';
  ctx.beginPath();
  ctx.arc(cw / 2, ch / 2, 2, 0, Math.PI * 2);
  ctx.fill();
}

// ═══════════════════════════════════════════════════════════════
// API / BACKEND
// ═══════════════════════════════════════════════════════════════
let _worldMetaCache = null;

function setMiniMapVisible(visible) {
  const isVisible = visible !== false;
  const mm = document.getElementById('miniMap');
  if (mm) mm.style.display = isVisible ? '' : 'none';
  const input = document.getElementById('setting-showMinimap');
  if (input) input.checked = isVisible;
}

function setDayNightCycleEnabled(enabled) {
  _dayNightCycleEnabled = enabled !== false;
  const input = document.getElementById('setting-enableDayNightCycle');
  if (input) input.checked = _dayNightCycleEnabled;

  if (_dayNightCycleEnabled) {
    _gameTimeLast = null;
  } else {
    applyDayNightState(12);
  }
}

function setWeatherEnabled(enabled) {
  _weatherEnabled = enabled !== false;
  const input = document.getElementById('setting-enableWeather');
  if (input) input.checked = _weatherEnabled;

  if (!_weatherEnabled && _rainInScene && _rainParticles) {
    scene.remove(_rainParticles);
    _rainInScene = false;
  }
}

function getMovementDebugOverlayFlags() {
  return {
    avoidance: !!OBSTACLE_AVOIDANCE.debug,
    interior: !!DYNAMIC_INTERIOR_ROUTING.debug,
    exterior: !!DYNAMIC_EXTERIOR_ROUTING.debug,
  };
}

function loadMovementDebugOverlayPreference() {
  try {
    const raw = localStorage.getItem(MOVEMENT_DEBUG_OVERLAYS_KEY);
    if (raw == null) return null;
    return raw === '1' || raw === 'true';
  } catch {
    return null;
  }
}

function hideExistingAvoidanceDebugOverlays() {
  if (!scene) return;
  scene.traverse((obj) => {
    if (obj?.name && String(obj.name).startsWith('avoidanceDebug_')) {
      obj.visible = false;
    }
  });
}

function syncMovementDebugOverlayUi() {
  const toggle = document.getElementById('setting-movementDebugOverlays');
  const status = document.getElementById('movementDebugOverlaysStatus');
  const flags = getMovementDebugOverlayFlags();
  const enabledCount = Object.values(flags).filter(Boolean).length;

  if (toggle) {
    toggle.checked = enabledCount === 3;
    toggle.indeterminate = enabledCount > 0 && enabledCount < 3;
  }

  if (status) {
    if (enabledCount === 3) {
      status.textContent = 'Collision, avoidance, interior routing, and exterior routing overlays are on.';
    } else if (enabledCount === 0) {
      status.textContent = 'Movement debug overlays are off.';
    } else {
      status.textContent = 'Movement debug overlays are mixed. Flip the toggle to force all on or all off.';
    }
  }
}

function setMovementDebugOverlaysEnabled(enabled, options = {}) {
  const next = !!enabled;
  const persist = options.persist !== false;
  OBSTACLE_AVOIDANCE.debug = next;
  DYNAMIC_INTERIOR_ROUTING.debug = next;
  DYNAMIC_EXTERIOR_ROUTING.debug = next;

  if (!next) {
    hideExistingAvoidanceDebugOverlays();
    clearDynamicInteriorRoutingDebug();
    clearDynamicExteriorRoutingDebug();
  }

  if (persist) {
    try {
      localStorage.setItem(MOVEMENT_DEBUG_OVERLAYS_KEY, next ? 'true' : 'false');
    } catch {
      // ignore localStorage failures
    }
  }

  syncMovementDebugOverlayUi();
  return next;
}

function applySavedMovementDebugOverlayPreference() {
  const saved = loadMovementDebugOverlayPreference();
  if (saved == null) {
    syncMovementDebugOverlayUi();
    return;
  }
  setMovementDebugOverlaysEnabled(saved, { persist: false });
}

function loadObjectActionPointDebugPreference() {
  try {
    const raw = localStorage.getItem(OBJECT_ACTION_POINT_DEBUG_KEY);
    if (raw == null) return null;
    return raw === '1' || raw === 'true';
  } catch {
    return null;
  }
}

function syncObjectActionPointDebugUi() {
  const toggle = document.getElementById('setting-objectActionPointDebug');
  const status = document.getElementById('objectActionPointDebugStatus');
  if (toggle) toggle.checked = _objectActionPointDebugEnabled;
  if (status) status.textContent = _objectActionPointDebugEnabled
    ? 'Object action point markers are on. Gray queue numbers are visual-only; red queue numbers are active.'
    : 'Object action point markers are off.';
}

function rebuildObjectActionPointDebugOverlays() {
  for (const building of buildingsMap.values()) {
    if (building?._group) addObjectActionPointDebugOverlays(building._group, building);
  }
}

let _objectActionPointDebugRefreshHandle = null;
function requestObjectActionPointDebugOverlayRefresh() {
  if (!_objectActionPointDebugEnabled || _objectActionPointDebugRefreshHandle != null) return;
  const run = () => {
    _objectActionPointDebugRefreshHandle = null;
    rebuildObjectActionPointDebugOverlays();
  };
  if (typeof requestAnimationFrame === 'function') {
    _objectActionPointDebugRefreshHandle = requestAnimationFrame(run);
  } else {
    _objectActionPointDebugRefreshHandle = setTimeout(run, 0);
  }
}

function setObjectActionPointDebugEnabled(enabled, options = {}) {
  _objectActionPointDebugEnabled = !!enabled;
  const persist = options.persist !== false;
  if (persist) {
    try {
      localStorage.setItem(OBJECT_ACTION_POINT_DEBUG_KEY, _objectActionPointDebugEnabled ? 'true' : 'false');
    } catch {
      // ignore localStorage failures
    }
  }
  rebuildObjectActionPointDebugOverlays();
  syncObjectActionPointDebugUi();
  return _objectActionPointDebugEnabled;
}

function applySavedObjectActionPointDebugPreference() {
  const saved = loadObjectActionPointDebugPreference();
  if (saved == null) {
    syncObjectActionPointDebugUi();
    return;
  }
  setObjectActionPointDebugEnabled(saved, { persist: false });
}

function applyWorldMetaSettings(meta = {}) {
  setMiniMapVisible(meta.showMinimap !== false);
  setDayNightCycleEnabled(meta.dayNightCycleEnabled !== false);
  setWeatherEnabled(meta.weatherEnabled !== false);
}

async function loadWorldMeta() {
  try {
    const r = await fetch('/api/meta');
    const m = await r.json();
    _worldMetaCache = m;
    if (m.name) {
      const displayName = m.name === 'Virtual World' ? 'My Virtual World' : m.name;
      setWorldTitleName(displayName);
      document.getElementById('setting-worldName').value = displayName;
      if (displayName !== m.name) {
        fetch('/api/meta', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ name: displayName }),
        }).catch(() => {});
      }
    }
    applyWorldMetaSettings(m);
  } catch (e) { /* silent */ }
}

async function fetchChunk(cx, cz) {
  try { return await (await fetch(`/api/chunk/${cx}/${cz}`)).json(); }
  catch (e) { return null; }
}

async function loadStreets() {
  try {
    const r = await fetch('/api/streets');
    const data = await r.json();
    if (!Array.isArray(data)) return;
    for (const s of data) {
      if (s.type) {
        // Intersection/turn piece
        _addRawIntersection(s.x1, s.z1, s.type, s.rotation || 0, s.openEdges || undefined);
      } else {
        _addRawSegment(s.x1, s.z1, s.x2, s.z2);
      }
    }
    for (const s of data) {
      _rebuildNearChunks(s.x1, s.z1, 5);
      if (s.x1 !== s.x2 || s.z1 !== s.z2) _rebuildNearChunks(s.x2, s.z2, 5);
    }
    // Rebuild light poles and traffic lights after all streets loaded
    _rebuildStreetLightPoles();
    _rebuildTrafficLights();
  } catch (e) { console.warn('Failed to load streets:', e); }
}

async function loadBuildings() {
  try {
    const r = await fetch('/api/buildings');
    const list = await r.json();
    for (const s of list) {
      if (buildingsMap.has(s.id)) continue;
      try {
        const f = await (await fetch(`/api/building/${s.id}`)).json();
        const parkTreeMigrationChanged = f?.type === 'park' ? ensureParkGeneratedTrees(f) : false;
        const actionTargetMigrationChanged = ensureBuildingPlacedObjectActionTargets(f);
        const transientAssignmentCleanupChanged = clearBuildingTransientObjectAssignments(f);
        buildingsMap.set(f.id, f);
        createBuilding3D(f);
        if (parkTreeMigrationChanged || actionTargetMigrationChanged || transientAssignmentCleanupChanged) persistBuilding(f);
      } catch (e) { console.error('Building create error for', s.id, e); buildingsMap.set(s.id, s); try { createBuilding3D(s); } catch(e2) { console.error('Fallback create error', s.id, e2); } }
    }
    updateBuildingList();
  } catch (e) { console.error('Building load error:', e); showToast('⚠️ Could not load buildings from server', 'warning'); }
}

async function loadAgents() {
  try {
    const list = await fetchAgentRosterWithLiveStatus();
    const cols = Math.max(1, Math.ceil(Math.sqrt(list.length)));
    const sp = API_TILE * 4;

    // Work building assignment: distribute agents evenly across non-park buildings
    const bArr = Array.from(buildingsMap.values());
    const workBuildings = bArr.filter(b => b.type !== 'park');
    const n = list.length;

    agentsList = list.map((a, i) => {
      // Get appearance from VO engine if available
      let appearance = {};
      if (typeof window.voGetDefaultAppearance === 'function') {
        appearance = window.voGetDefaultAppearance(a.statusKey || a.id, a.gender || 'M');
      }
      // Determine work/home buildings, prefer saved assignments over auto-distribution
      const savedWorkBuilding = a.workBuilding ? (buildingsMap.get(a.workBuilding) || null) : null;
      const savedHomeBuilding = a.homeBuilding ? (buildingsMap.get(a.homeBuilding) || null) : null;
      let workBuilding = savedWorkBuilding;
      let agentRole = 'wanderer';
      if (!workBuilding && workBuildings.length > 0) {
        workBuilding = workBuildings[i % workBuildings.length];
        agentRole = 'worker' + (i % workBuildings.length);
      } else if (workBuilding) {
        const roleIndex = Math.max(0, workBuildings.findIndex(b => b.id === workBuilding.id));
        agentRole = 'worker' + roleIndex;
      }

      const anchorBuilding = workBuilding || savedHomeBuilding;

      let initialDeskSpot = null;
      if (workBuilding) {
        const deskEntries = getDeskFurnitureEntries(workBuilding);
        const assignedDeskEntry = deskEntries.find(entry => doesDeskAssignmentMatchAgent(a, entry.furniture.assignedTo));
        const fallbackDeskEntry = assignedDeskEntry || (deskEntries.length > 0 ? deskEntries[i % deskEntries.length] : null);
        if (fallbackDeskEntry) {
          initialDeskSpot = getFurnitureActionSpot(fallbackDeskEntry.building, fallbackDeskEntry.furniture);
        }
      }

      // Start agents at their desk work location for testing, otherwise near their assigned work/home building
      let startX, startY, homeX, homeY;
      if (initialDeskSpot) {
        startX = initialDeskSpot.apiX;
        startY = initialDeskSpot.apiZ;
        const homeAnchor = savedHomeBuilding || anchorBuilding;
        if (homeAnchor) {
          const homeDoorPos = getBuildingDoorPosAPI(homeAnchor);
          const homeDoorDir = getBuildingDoorDirection(homeAnchor);
          const homeDoorTangent = { x: -homeDoorDir.z, z: homeDoorDir.x };
          const hx = homeDoorPos.x + homeDoorDir.x * API_TILE * 2;
          const hy = homeDoorPos.y + homeDoorDir.z * API_TILE * 2;
          homeX = hx + homeDoorDir.x * API_TILE * 5 + homeDoorTangent.x * (i % 5 - 2) * API_TILE * 3;
          homeY = hy + homeDoorDir.z * API_TILE * 5 + homeDoorTangent.z * (i % 5 - 2) * API_TILE * 3 + Math.floor(i / 5) * API_TILE * 2;
        } else {
          homeX = startX;
          homeY = startY;
        }
      } else if (anchorBuilding) {
        const doorPos = getBuildingDoorPosAPI(anchorBuilding);
        const doorDir = getBuildingDoorDirection(anchorBuilding);
        const doorTangent = { x: -doorDir.z, z: doorDir.x };
        const bx = doorPos.x + doorDir.x * API_TILE * 2;
        const by = doorPos.y + doorDir.z * API_TILE * 2;
        const _scale = T / API_TILE;
        const stx = Math.round(bx * _scale);
        const stz = Math.round(by * _scale);
        const startSW = _findRandomSidewalkNear(stx, stz, 15);
        if (startSW) {
          startX = startSW.x / _scale;
          startY = startSW.z / _scale;
        } else {
          startX = bx + (Math.random() - 0.5) * API_TILE * 2;
          startY = by + (Math.random() - 0.5) * API_TILE * 2;
        }
        homeX = bx + doorDir.x * API_TILE * 5 + doorTangent.x * (i % 5 - 2) * API_TILE * 3;
        homeY = by + doorDir.z * API_TILE * 5 + doorTangent.z * (i % 5 - 2) * API_TILE * 3 + Math.floor(i / 5) * API_TILE * 2;
      } else {
        startX = -(cols * sp) / 2 + (i % cols) * sp + (Math.random() - 0.5) * 80;
        startY = 120 + Math.floor(i / cols) * sp + (Math.random() - 0.5) * 80;
        homeX = startX;
        homeY = startY;
      }

      return {
        ...a,
        name: a.name || a.id,
        emoji: a.emoji || '🤖',
        _appearance: { ...appearance, ...(a.appearance || {}) },
        x: startX,
        y: startY,
        homeX: homeX,
        homeY: homeY,
        _tick: Math.floor(Math.random() * 1000),
        _wanderTimer: Math.random() * 3000,
        _wanderTarget: null,
        _workBuilding: workBuilding,
        _homeBuilding: savedHomeBuilding,
        _agentRole: agentRole,
        _atDesk: !!(initialDeskSpot && isWorkPresenceStatus(a.status)),
        _workPresenceHoldUntil: isWorkPresenceStatus(a.status) ? performance.now() + WORK_PRESENCE_CLIENT_HOLD_MS : 0,
        _floor: initialDeskSpot?.floor || 1,
        _targetFloor: initialDeskSpot?.floor || 1,
        _deskFacingAngle: initialDeskSpot?.faceAngle ?? null,
        _activeWorkSpot: initialDeskSpot,
      };
    });

    agentsList.forEach(a => {
      createAgent3D(a);
      _agentLastStatus.set(a.id, a.status || 'offline'); // seed initial status
    });
    updateAgentList();
    window.agents = agentsList; // re-export after population

    // Seed initial activity log entries
    agentsList.forEach(a => {
      if (normalizeLiveAgentStatus(a.status) === 'working') {
        addActivityLog(`${a.emoji || '🤖'} ${a.name || a.id} started working`);
      } else if (a.status === 'finishing') {
        addActivityLog(`${a.emoji || '🤖'} ${a.name || a.id} is finishing up`);
      } else if (a.status === 'meeting') {
        addActivityLog(`📊 ${a.name || a.id} is in a meeting`);
      } else if (a.status === 'idle') {
        addActivityLog(`${a.emoji || '🤖'} ${a.name || a.id} is idle`);
      } else if (a.status === 'break') {
        addActivityLog(`${a.emoji || '🤖'} ${a.name || a.id} is on break`);
      }
    });
    addActivityLog('🌍 My Virtual World loaded');

    // Poll live agent status every 5s, using /api/status as the authoritative source.
    setInterval(async () => {
      try {
        const [statusResponse, rosterResponse] = await Promise.all([
          fetch('/api/status'),
          fetch('/api/agents').catch(() => null),
        ]);
        const liveStatusMap = await statusResponse.json();
        const liveRoster = rosterResponse?.ok ? await rosterResponse.json() : [];

        agentsList.forEach(a => {
          const snapshot = getLiveStatusSnapshotForAgent(a, liveStatusMap);
          const rosterMatch = liveRoster.find(entry => {
            const entryKeys = getAgentIdentityKeys(entry);
            for (const key of getAgentIdentityKeys(a)) {
              if (entryKeys.has(key)) return true;
            }
            return false;
          }) || null;
          const prevStatus = _agentLastStatus.get(a.id);
          const meeting = getLiveMeetingForAgent(a, liveStatusMap);
          const rawStatus = meeting ? 'meeting' : (normalizeLiveAgentStatus(
            snapshot?.state ?? snapshot?.status ?? rosterMatch?.status ?? a.status
          ) || 'offline');
          const newStatus = meeting ? rawStatus : applyWorkPresenceClientHold(a, rawStatus, snapshot, rosterMatch);

          if (prevStatus !== undefined && prevStatus !== newStatus &&
              (isWorkPresenceStatus(newStatus) || isIdlePresenceStatus(newStatus)) &&
              (isWorkPresenceStatus(prevStatus) || isIdlePresenceStatus(prevStatus))) {
            triggerDeskNotification(a);
          }

          if (prevStatus !== undefined && prevStatus !== newStatus) {
            const emoji = a.emoji || '🤖';
            const name = a.name || a.id;
            if (newStatus === 'working') addActivityLog(`${emoji} ${name} started working`);
            else if (newStatus === 'finishing') addActivityLog(`${emoji} ${name} is finishing up`);
            else if (newStatus === 'meeting') addActivityLog(`📊 ${name} joined a meeting`);
            else if (newStatus === 'idle') addActivityLog(`${emoji} ${name} went idle`);
            else if (newStatus === 'break') addActivityLog(`${emoji} ${name} went on break`);
            else if (!newStatus || newStatus === 'offline') addActivityLog(`⚫ ${name} went offline`);

            clearAgentTransientMovement(a);
            a._stayTimer = 0;
            a._wanderTimer = 0;
          }

          _agentLastStatus.set(a.id, newStatus);
          a.status = newStatus;
          if (snapshot && typeof snapshot.task === 'string') a.task = snapshot.task;
          else if (rosterMatch && typeof rosterMatch.task === 'string') a.task = rosterMatch.task;
          if (meeting?.topic && newStatus === 'meeting') a.task = meeting.topic;

          if (rosterMatch && (a.workBuilding !== rosterMatch.workBuilding || a.homeBuilding !== rosterMatch.homeBuilding)) {
            applyAgentAssignment(a, rosterMatch.workBuilding, rosterMatch.homeBuilding);
          }

          // Sync saved personality from the roster profile (server-authoritative).
          if (rosterMatch && rosterMatch.personality && JSON.stringify(rosterMatch.personality) !== JSON.stringify(a.personality || null)) {
            a.personality = rosterMatch.personality;
            setAgentPersonality(a, rosterMatch.personality);
          }
        });
        updateAgentList();
      } catch (e) { /* silent */ }
    }, 5000);
  } catch (e) {
    showToast('⚠️ Agents offline — world still active', 'warning');
    agentsList = [];
    updateAgentList();
  }
}

// ── Desk Notification: flash + "!" icon ─────────────────────────────
function findDeskMesh(entry) {
  if (!entry?.building?._group) return null;
  let found = null;
  entry.building._group.traverse(obj => {
    if (found || !obj.userData?.furniture || obj.userData?.furnitureType !== 'desk') return;
    if (obj.userData.buildingId === entry.building.id && obj.userData.furnitureIndex === entry.index) {
      found = obj;
    }
  });
  return found;
}

function triggerDeskNotification(agent) {
  const deskEntry = getAgentAssignedDesk(agent);
  const deskMesh = findDeskMesh(deskEntry);
  if (!deskEntry || !deskMesh) return;

  const deskKey = `${deskEntry.building.id}:${deskEntry.index}`;
  const flashCol = isWorkPresenceStatus(agent.status) ? 0x00ff88 : 0xffaa00;

  const origMats = [];
  deskMesh.traverse(child => {
    if (child.isMesh && child.material) {
      origMats.push({ mesh: child, color: child.material.color.getHex() });
      child.material = child.material.clone();
      child.material.color.setHex(flashCol);
    }
  });
  setTimeout(() => {
    origMats.forEach(({ mesh, color }) => {
      if (mesh.material) mesh.material.color.setHex(color);
    });
  }, 600);

  if (_deskFlashes.has(deskKey)) {
    clearTimeout(_deskFlashes.get(deskKey).timer);
    const old = _deskFlashes.get(deskKey);
    if (old.icon3d) scene.remove(old.icon3d);
  }

  const canvas = document.createElement('canvas');
  canvas.width = 64; canvas.height = 64;
  const ctx2 = canvas.getContext('2d');
  ctx2.font = 'bold 48px Arial';
  ctx2.textAlign = 'center';
  ctx2.textBaseline = 'middle';
  ctx2.fillStyle = isWorkPresenceStatus(agent.status) ? '#00ff88' : '#ffaa00';
  ctx2.fillText('!', 32, 32);
  const tex = new THREE.CanvasTexture(canvas);
  const sprite = new THREE.Sprite(new THREE.SpriteMaterial({ map: tex, transparent: true, depthTest: false }));
  const deskPos = new THREE.Vector3();
  deskMesh.getWorldPosition(deskPos);
  sprite.position.set(deskPos.x, deskPos.y + 1.8, deskPos.z);
  sprite.scale.set(1.2, 1.2, 1);
  scene.add(sprite);

  const timer = setTimeout(() => {
    scene.remove(sprite);
    tex.dispose();
    _deskFlashes.delete(deskKey);
  }, 3000);
  _deskFlashes.set(deskKey, { timer, icon3d: sprite });
}

async function saveAll() {
  if (!ensureEditorUnlocked('Saving edits')) return;
  // Visual indicator: pulse the save button
  const saveBtn = document.getElementById('btn-save');
  if (saveBtn) saveBtn.classList.add('saving-pulse');
  showToast('💾 Saving...', 'warning');

  let savedChunks = 0;
  let savedBuildings = 0;
  let savedDecorations = 0;

  // 1. Save all dirty chunks
  for (const [, c] of loadedChunks) {
    if (c.dirty) {
      try {
        await fetch(`/api/chunk/${c.cx}/${c.cz}`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ cx: c.cx, cz: c.cz, terrain: c.terrain }),
        });
        c.dirty = false;
        savedChunks++;
      } catch (e) {
        // Keep c.dirty = true so it retries on next save
      }
    }
  }

  // 2. Save all buildings to server
  for (const [, b] of buildingsMap) {
    try {
      const payload = { ...b };
      delete payload._group;
      delete payload._badgeSprite;
      delete payload._lastBadgeCount;
      await fetch('/api/buildings', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      });
      savedBuildings++;
    } catch (e) { /* silent */ }
  }

  // 3. Save streets
  try {
    const streetData = _streetSegments.map(s => ({
      x1: s.x1, z1: s.z1, x2: s.x2, z2: s.z2,
      type: s.type || null, rotation: s.rotation || 0,
      openEdges: s.openEdges || null,
    }));
    await fetch('/api/streets', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(streetData),
    });
  } catch (e) { /* silent */ }

  // 4. Save world meta (world name)
  try {
    const name = getWorldTitleName();
    await fetch('/api/meta', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ name }),
    });
  } catch (e) { /* silent */ }

  // 5. Save placed terrain decorations
  try {
    const decorations = serializePlacedDecorations();
    await fetch('/api/decorations', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(decorations),
    });
    savedDecorations = decorations.length;
  } catch (e) { /* silent */ }

  // Done
  if (saveBtn) saveBtn.classList.remove('saving-pulse');
  showToast(`✅ World saved! (${savedChunks} chunks, ${savedBuildings} buildings, ${_streetSegments.length} streets, ${savedDecorations} decorations)`, 'success');
}

// ═══════════════════════════════════════════════════════════════
// HELPERS
// ═══════════════════════════════════════════════════════════════
function parseColor(hex) {
  return parseInt((hex || '#888888').replace('#', ''), 16);
}

function makeTextSprite(text, maxWidth) {
  const canvas = document.createElement('canvas');
  canvas.width = 512;
  canvas.height = 48;
  const ctx = canvas.getContext('2d');
  ctx.font = 'bold 20px "Press Start 2P", monospace';
  ctx.textAlign = 'center';
  ctx.strokeStyle = '#000';
  ctx.lineWidth = 4;
  ctx.strokeText(text, 256, 32);
  ctx.fillStyle = '#ffd600';
  ctx.fillText(text, 256, 32);
  const tex = new THREE.CanvasTexture(canvas);
  const sprite = new THREE.Sprite(new THREE.SpriteMaterial({ map: tex, transparent: true }));
  const aspect = 512 / 48;
  const w = Math.min(maxWidth * 0.6, 6);
  sprite.scale.set(w, w / aspect, 1);
  return sprite;
}

// Feature 4: Agent count badge sprite for buildings
function makeBadgeSprite(count) {
  const canvas = document.createElement('canvas');
  canvas.width = 64;
  canvas.height = 64;
  const ctx = canvas.getContext('2d');
  ctx.clearRect(0, 0, 64, 64);
  if (count > 0) {
    ctx.fillStyle = count > 0 ? '#e94560' : 'rgba(0,0,0,0)';
    ctx.beginPath();
    ctx.arc(32, 32, 28, 0, Math.PI * 2);
    ctx.fill();
    ctx.strokeStyle = '#fff';
    ctx.lineWidth = 3;
    ctx.stroke();
    ctx.fillStyle = '#fff';
    ctx.font = 'bold 26px sans-serif';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText(count > 9 ? '9+' : String(count), 32, 34);
  }
  const tex = new THREE.CanvasTexture(canvas);
  const mat = new THREE.SpriteMaterial({ map: tex, transparent: true, depthTest: false });
  const sprite = new THREE.Sprite(mat);
  sprite.scale.set(1.2, 1.2, 1);
  return sprite;
}

function updateBadgeSprite(sprite, count) {
  if (!sprite || !sprite.material || !sprite.material.map) return;
  const canvas = sprite.material.map.image;
  const ctx = canvas.getContext('2d');
  ctx.clearRect(0, 0, 64, 64);
  if (count > 0) {
    ctx.fillStyle = '#e94560';
    ctx.beginPath();
    ctx.arc(32, 32, 28, 0, Math.PI * 2);
    ctx.fill();
    ctx.strokeStyle = '#fff';
    ctx.lineWidth = 3;
    ctx.stroke();
    ctx.fillStyle = '#fff';
    ctx.font = 'bold 26px sans-serif';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText(count > 9 ? '9+' : String(count), 32, 34);
  }
  sprite.material.map.needsUpdate = true;
}

function makeTaskBubble(text) {
  const cw = 256, ch = 80;
  const canvas = document.createElement('canvas');
  canvas.width = cw;
  canvas.height = ch;
  const ctx = canvas.getContext('2d');
  // Bubble background
  ctx.fillStyle = 'rgba(255,255,255,0.92)';
  const r = 14;
  ctx.beginPath();
  ctx.moveTo(r, 0); ctx.lineTo(cw - r, 0);
  ctx.quadraticCurveTo(cw, 0, cw, r);
  ctx.lineTo(cw, ch - r - 12);
  ctx.quadraticCurveTo(cw, ch - 12, cw - r, ch - 12);
  ctx.lineTo(20, ch - 12);
  ctx.lineTo(10, ch);      // tail
  ctx.lineTo(36, ch - 12);
  ctx.lineTo(r, ch - 12);
  ctx.quadraticCurveTo(0, ch - 12, 0, ch - r - 12);
  ctx.lineTo(0, r);
  ctx.quadraticCurveTo(0, 0, r, 0);
  ctx.closePath();
  ctx.fill();
  ctx.strokeStyle = '#aaa';
  ctx.lineWidth = 2;
  ctx.stroke();
  // Text
  ctx.fillStyle = '#222';
  ctx.font = 'bold 14px sans-serif';
  ctx.textAlign = 'center';
  ctx.fillText(text || '', cw / 2, 38);
  const tex = new THREE.CanvasTexture(canvas);
  const sprite = new THREE.Sprite(new THREE.SpriteMaterial({ map: tex, transparent: true }));
  sprite.scale.set(2.2, 0.8, 1);
  return sprite;
}

function onResize() {
  const c = document.getElementById('pixiContainer');
  renderer.setSize(c.clientWidth, c.clientHeight);
  renderer.setPixelRatio(Math.min(window.devicePixelRatio || 1, 2));
  updateCamera();
  updateChatBubblePositions();
}

const MAX_VISIBLE_TOASTS = 3;

function showToast(msg, type = '') {
  const c = document.getElementById('toastContainer');
  if (!c) return;
  const t = document.createElement('div');
  t.className = 'toast' + (type ? ' ' + type : '');
  t.textContent = msg;
  c.appendChild(t);

  // Fade out excess toasts beyond MAX_VISIBLE_TOASTS
  const toasts = c.querySelectorAll('.toast');
  if (toasts.length > MAX_VISIBLE_TOASTS) {
    // Fade out older toasts (those beyond the limit)
    for (let i = 0; i < toasts.length - MAX_VISIBLE_TOASTS; i++) {
      const old = toasts[i];
      if (old.style.opacity !== '0') {
        old.style.transition = 'opacity 0.3s ease';
        old.style.opacity = '0';
        setTimeout(() => old.remove(), 300);
      }
    }
  }

  // Auto-remove after 3 seconds
  setTimeout(() => {
    t.style.transition = 'opacity 0.3s ease';
    t.style.opacity = '0';
    setTimeout(() => t.remove(), 300);
  }, 3000);
}

// ═══════════════════════════════════════════════════════════════
// WORLD SEARCH
// ═══════════════════════════════════════════════════════════════
function setupWorldSearch() {
  const input = document.getElementById('worldSearch');
  const dropdown = document.getElementById('worldSearchDropdown');
  if (!input || !dropdown) return;

  input.addEventListener('input', () => {
    const q = input.value.toLowerCase().trim();
    dropdown.innerHTML = '';
    if (!q) { dropdown.style.display = 'none'; return; }

    const results = [];
    for (const [, b] of buildingsMap) {
      if (b.name && b.name.toLowerCase().includes(q)) {
        results.push({ label: '🏢 ' + b.name, fly: () => {
          const bounds = getBuildingFootprintBounds(b, 0);
          flyCameraTo(new THREE.Vector3(bounds.centerX, 0, bounds.centerZ), 30);
        }});
      }
    }
    for (const a of agentsList) {
      if (a.name && a.name.toLowerCase().includes(q)) {
        results.push({ label: '🤖 ' + a.name, fly: () => {
          const scale = T / API_TILE;
          flyCameraTo(new THREE.Vector3(a.x * scale, 0, a.y * scale), 20);
        }});
      }
    }

    if (results.length === 0) {
      dropdown.style.display = 'none';
      return;
    }
    results.slice(0, 8).forEach(r => {
      const item = document.createElement('div');
      item.className = 'search-result-item';
      item.textContent = r.label;
      item.addEventListener('mousedown', e => {
        e.preventDefault();
        r.fly();
        input.value = '';
        dropdown.style.display = 'none';
      });
      dropdown.appendChild(item);
    });
    dropdown.style.display = 'block';
  });

  input.addEventListener('blur', () => {
    setTimeout(() => { dropdown.style.display = 'none'; }, 150);
  });
}

// ═══════════════════════════════════════════════════════════════
// AUTO-GENERATE DEFAULT WORLD
// ═══════════════════════════════════════════════════════════════
async function autoGenerateDefaultWorld() {
  showToast('🌍 Creating starter world…', 'info');

  const starterBuildings = cloneStarterMapBuildings();
  const starterStreets = cloneStarterMapStreets();

  for (const building of starterBuildings) {
    buildingsMap.set(building.id, building);
    createBuilding3D(building);
    try {
      await fetch('/api/buildings', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(_buildingPayload(building)),
      });
    } catch (e) { /* offline */ }
  }

  _restoreStreets(starterStreets);

  // Rebuild all chunks after street creation
  for (const [, chunk] of loadedChunks) {
    if (chunk.dirty) rebuildChunk(chunk);
  }

  try {
    await fetch('/api/streets', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(starterStreets),
    });
    for (const [, chunk] of loadedChunks) {
      if (!chunk.dirty) continue;
      await fetch(`/api/chunk/${chunk.cx}/${chunk.cz}`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ cx: chunk.cx, cz: chunk.cz, terrain: chunk.terrain }),
      });
      chunk.dirty = false;
    }
  } catch (e) { /* offline — demo lock only allows this before initialization */ }

  // Mark world as initialized so default buildings are never re-created after user deletes them
  try {
    await fetch('/api/meta', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ initialized: true, name: STARTER_MAP_NAME, starterMap: 'desktop-8590-2026-06-13' }),
    });
    if (_worldMetaCache) {
      _worldMetaCache.initialized = true;
      _worldMetaCache.name = STARTER_MAP_NAME;
      _worldMetaCache.starterMap = 'desktop-8590-2026-06-13';
    }
  } catch (e) { /* offline — will be set next save */ }

  updateBuildingList();
  showToast('🏗️ Starter world created!', 'success');
}

function _paintRoadLine(x1, z1, x2, z2) {
  const steps = Math.max(Math.abs(x2 - x1), Math.abs(z2 - z1)) + 1;
  for (let i = 0; i <= steps; i++) {
    const t = steps === 0 ? 0 : i / steps;
    const wx = Math.round(x1 + (x2 - x1) * t);
    const wz = Math.round(z1 + (z2 - z1) * t);
    _setWorldTile(wx, wz, TERRAIN.ROAD);
    // Add sidewalks on sides
    _setWorldTileIfGrass(wx + 1, wz, TERRAIN.SIDEWALK);
    _setWorldTileIfGrass(wx - 1, wz, TERRAIN.SIDEWALK);
    _setWorldTileIfGrass(wx, wz + 1, TERRAIN.SIDEWALK);
    _setWorldTileIfGrass(wx, wz - 1, TERRAIN.SIDEWALK);
  }
}

function _setWorldTile(wx, wz, tileType) {
  const cx = Math.floor(wx / CHUNK);
  const cz = Math.floor(wz / CHUNK);
  const chunk = loadedChunks.get(chunkKey(cx, cz));
  if (!chunk) return;
  const lx = ((wx % CHUNK) + CHUNK) % CHUNK;
  const lz = ((wz % CHUNK) + CHUNK) % CHUNK;
  chunk.terrain[lz * CHUNK + lx] = tileType;
  chunk.dirty = true;
  // Remove user-placed decorations on non-grass tiles (e.g. roads painted over trees)
  if (tileType !== TERRAIN.GRASS && tileType !== TERRAIN.DIRT) {
    const pdKey = chunkDecorationKey(cx, cz);
    const pdList = placedDecorations.get(pdKey);
    if (pdList) {
      const filtered = pdList.filter(pd => {
        const ptx = Math.floor((pd.wx - cx * CHUNK_W) / T);
        const ptz = Math.floor((pd.wz - cz * CHUNK_W) / T);
        return ptx !== lx || ptz !== lz;
      });
      if (filtered.length !== pdList.length) {
        placedDecorations.set(pdKey, filtered);
        debounceSavePlacedDecorations();
      }
    }
  }
}

function _setWorldTileIfGrass(wx, wz, tileType) {
  const cx = Math.floor(wx / CHUNK);
  const cz = Math.floor(wz / CHUNK);
  const chunk = loadedChunks.get(chunkKey(cx, cz));
  if (!chunk) return;
  const lx = ((wx % CHUNK) + CHUNK) % CHUNK;
  const lz = ((wz % CHUNK) + CHUNK) % CHUNK;
  const idx = lz * CHUNK + lx;
  if (chunk.terrain[idx] === TERRAIN.GRASS || chunk.terrain[idx] === TERRAIN.DIRT) {
    chunk.terrain[idx] = tileType;
    chunk.dirty = true;
  }
}

// ═══════════════════════════════════════════════════════════════
// WELCOME TOUR
// ═══════════════════════════════════════════════════════════════
function startWelcomeTour() {
  if (localStorage.getItem('vw_welcomed')) return;
  localStorage.setItem('vw_welcomed', '1');

  const messages = [
    'Welcome to My Virtual World! 🌍',
    'Click buildings to enter them',
    'Use 🌍🛣️🏗️ to edit the world',
    'Press ? for keyboard shortcuts',
  ];

  messages.forEach((msg, i) => {
    setTimeout(() => showToast(msg, 'info'), i * 4000);
  });
}

// ═══════════════════════════════════════════════════════════════
// GLOBAL EXPORTS (for HTML event handlers)
// ═══════════════════════════════════════════════════════════════
window.closeBuildingModal = () => { document.getElementById('buildingModal').style.display = 'none'; };
window.closeOutsideSpaceModal = () => { document.getElementById('outsideSpaceModal').style.display = 'none'; };
window.startBuildingPlacement = (data) => startPlacement(data); // alias for external callers
window.closeSettingsModal = () => { document.getElementById('settingsModal').style.display = 'none'; };
window.saveSettings = () => {
  const name = document.getElementById('setting-worldName')?.value;
  const showMinimap = document.getElementById('setting-showMinimap')?.checked !== false;
  const dayNightCycleEnabled = document.getElementById('setting-enableDayNightCycle')?.checked !== false;
  const weatherEnabled = document.getElementById('setting-enableWeather')?.checked !== false;
  const movementDebugOverlaysEnabled = document.getElementById('setting-movementDebugOverlays')?.checked !== false;
  const objectActionPointDebugEnabled = document.getElementById('setting-objectActionPointDebug')?.checked === true;

  if (name) {
    setWorldTitleName(name);
  }

  setMiniMapVisible(showMinimap);
  setDayNightCycleEnabled(dayNightCycleEnabled);
  setWeatherEnabled(weatherEnabled);
  setMovementDebugOverlaysEnabled(movementDebugOverlaysEnabled);
  setObjectActionPointDebugEnabled(objectActionPointDebugEnabled);

  const metaPatch = { name, showMinimap, dayNightCycleEnabled, weatherEnabled };
  _worldMetaCache = { ...(_worldMetaCache || {}), ...metaPatch };
  fetch('/api/meta', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(metaPatch),
  }).catch(() => {});

  window.closeSettingsModal();
  showToast('Settings saved', 'success');
};
window._renameBld = (id) => {
  if (!ensureEditorUnlocked('Building editing')) return;
  const b = buildingsMap.get(id);
  if (!b) return;
  const n = (prompt('Rename building:', b.name) || '').trim();
  if (n && n !== b.name) {
    b.name = n;
    // Rebuild 3D (updates label sprite + street sign)
    createBuilding3D(b);
    // Update the sidebar building list
    updateBuildingList();
    // If this building is currently selected in the edit panel, refresh it
    if (selectedBuildingId === id) updateBuildingEditPanel(b);
    // Persist to server
    const payload = { ...b };
    delete payload._group; delete payload._badgeSprite; delete payload._lastBadgeCount;
    fetch('/api/buildings', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
    }).catch(() => {});
    showToast(`✏️ Renamed to "${n}"`, 'success');
  }
};
window._deleteBld = (id) => {
  if (!ensureEditorUnlocked('Building editing')) return;
  const b = buildingsMap.get(id);
  if (!b) return;
  if (!confirm(`Delete ${b.name}?`)) return;
  // Push undo for building deletion (deep copy without 3D references)
  const buildingData = JSON.parse(JSON.stringify({ ...b, _group: undefined, _badgeSprite: undefined }));
  delete buildingData._group;
  delete buildingData._badgeSprite;
  delete buildingData._lastBadgeCount;
  pushUndo({ type: 'buildingDelete', buildingData });
  if (b._group) buildingGroup.remove(b._group);
  // Physics: remove building collider (and park furniture colliders)
  if (isPhysicsReady()) {
    removeBody(id);
    for (let i = 0; i < 128; i++) removeBody(`${id}_iwall_${i}`);
    // Remove park furniture colliders
    if (b.type === 'park') {
      removeBody(`${id}_fountain`);
      for (let i = 0; i < 4; i++) removeBody(`${id}_bench_${i}`);
    }
    // Remove outdoor bench colliders
    for (let i = 0; i < 3; i++) removeBody(`${id}_outdoor_bench_${i}`);
    clearManualFurnitureColliders(id);
  }
  buildingsMap.delete(id);
  // Clear selection outline if this building was selected
  if (selectedBuildingId === id) {
    clearSelectedBuildingHelper();
    clearSelectedBuildingResizeHandles();
    selectedBuildingId = null;
    updateFloorControlPanel();
    const content = document.getElementById('buildingEditContent');
    if (content) content.innerHTML = '';
  }
  // If inside this building, exit first
  if (insideBuildingId === id) {
    insideBuildingId = null;
    flyCameraTo(camTarget.clone(), _prevCamDist);
  }
  // Rebuild chunks under the deleted building so trees/rocks reappear
  _rebuildNearChunks(b.worldX || 0, b.worldY || 0, Math.max(b.widthTiles || 25, b.heightTiles || 17) + 2);
  updateBuildingList();
  fetch(`/api/building/${id}`, { method: 'DELETE' }).catch(() => {});
  showToast(`Deleted ${b.name}`, 'error');
};
