function clearManualFurnitureColliders(buildingId, max = 128) {
  if (!isPhysicsReady()) return;
  for (let i = 0; i < max; i++) removeBody(`${buildingId}_mfurn_${i}`);
  for (let floor = 1; floor <= 12; floor++) {
    ['back', 'left', 'right'].forEach(part => removeBody(`${buildingId}_elevator_f${floor}_${part}`));
  }
  ['back', 'left', 'right'].forEach(part => removeBody(`${buildingId}_elevator_${part}`));
}

function syncManualFurnitureColliders(building) {
  if (!isPhysicsReady() || !building?.id) return;
  clearManualFurnitureColliders(building.id);
  const furniture = building.interior?.furniture || [];
  furniture.forEach((f, index) => {
    const collision = resolvePlacedCollisionBounds({
      item: f,
      building,
      index,
      halfSizes: FURNITURE_HALF_SIZES,
      registry: COLLISION_REGISTRY,
      coordinateSpace: 'building-local',
    });
    // Interior Door is solid while closed so agents route around it like other
    // furniture. During explicit open/pass-through interactions, temporarily
    // suppress the physical collider so the front→center→back action-location
    // route can actually cross the doorway.
    if (f.type === 'interiorDoor' && (f.doorState?.open === true || f.activeUse?.mode === 'passing-through' || f.activeUse?.mode === 'open')) return;
    if (!collision.physics?.createStaticCollider) return;
    const bound = collision.bounds.find(candidate => candidate.shape === 'rect');
    if (!bound || bound.halfW <= 0 || bound.halfD <= 0) return;
    const furnitureFloor = getFurnitureFloor(f);
    const floorY = getInteriorFloorSurfaceY(building, furnitureFloor);
    const world = getBuildingWorldPoint(building, bound.offset.x, bound.offset.z);
    addBoxCollider(
      `${building.id}_mfurn_${index}`,
      world.x,
      world.z,
      bound.halfW * T,
      bound.halfD * T,
      1.4,
      bound.rotationDeg,
      floorY + 0.7,
    );
  });

  const e = building.elevator;
  if (e && getBuildingFloorCount(building) > 1) {
    const rot = building._rotation || 0;
    const wallH = 1.4;
    const wallT = 0.08;
    const addElevatorWallCollider = (floor, part, localX, localZ, halfW, halfD) => {
      const world = getBuildingWorldPoint(building, localX, localZ);
      addBoxCollider(`${building.id}_elevator_f${floor}_${part}`, world.x, world.z, halfW, halfD, wallH, rot, getRenderedFloorY(building, floor) + wallH / 2);
    };
    for (let floor = 1; floor <= getBuildingFloorCount(building); floor++) {
      addElevatorWallCollider(floor, 'back', e.x, e.z - e.depth / 2, e.width / 2, wallT);
      addElevatorWallCollider(floor, 'left', e.x - e.width / 2, e.z, wallT, e.depth / 2);
      addElevatorWallCollider(floor, 'right', e.x + e.width / 2, e.z, wallT, e.depth / 2);
    }
  }
}

/**
 * Check if shrinking a building would cause any manually-placed furniture
 * to fall outside the new footprint.
 *
 * Returns { blocked: boolean, conflicting: number[] } where conflicting
 * is the indices into building.interior.furniture of items that collide.
 */
function checkResizeFurnitureCollision(building, newWidthTiles, newDepthTiles, sides = {}) {
  const furniture = building.interior?.furniture;
  if (!furniture || furniture.length === 0) return { blocked: false, conflicting: [] };

  const newBW = newWidthTiles * T;
  const newBD = newDepthTiles * T;
  const margin = Math.max(INTERIOR_WALL_THICKNESS / 2, T * 0.04);
  const conflicting = [];
  const checkAllSides = !sides.minX && !sides.maxX && !sides.minZ && !sides.maxZ;

  for (let i = 0; i < furniture.length; i++) {
    const f = furniture[i];
    const [halfW, halfD] = getFurnitureFootprintHalfSizes(f.type, f.rotation || f.rotationDeg || 0);
    const fMinX = f.x - halfW;
    const fMaxX = f.x + halfW;
    const fMinZ = f.z - halfD;
    const fMaxZ = f.z + halfD;

    const hitsMinX = (checkAllSides || sides.minX) && fMinX < margin;
    const hitsMaxX = (checkAllSides || sides.maxX) && fMaxX > newBW - margin;
    const hitsMinZ = (checkAllSides || sides.minZ) && fMinZ < margin;
    const hitsMaxZ = (checkAllSides || sides.maxZ) && fMaxZ > newBD - margin;

    if (hitsMinX || hitsMaxX || hitsMinZ || hitsMaxZ) {
      conflicting.push(i);
    }
  }

  return { blocked: conflicting.length > 0, conflicting };
}

/**
 * Temporarily highlight conflicting furniture items with a red glow.
 */
function highlightConflictingFurniture(building, conflictingIndices, duration = 2500) {
  if (!building._group) return;
  const furniture = building.interior?.furniture || [];
  const furnMeshes = [];
  building._group.traverse(obj => { if (obj.isMesh && obj.userData.furniture) furnMeshes.push(obj); });

  const tinted = [];
  for (const idx of conflictingIndices) {
    const f = furniture[idx];
    if (!f) continue;
    for (const mesh of furnMeshes) {
      const fGroup = mesh.parent?.userData?.buildingId ? mesh : mesh.parent || mesh;
      const pos = fGroup.position || mesh.position;
      const dx = Math.abs(pos.x - f.x);
      const dz = Math.abs(pos.z - f.z);
      if (dx < T * 1.5 && dz < T * 1.5) {
        const origColor = mesh.material?.color?.getHex();
        if (mesh.material && mesh.material.color) {
          mesh.material = mesh.material.clone();
          mesh.material.color.setHex(0xff1744);
          mesh.material.emissive = new THREE.Color(0xff1744);
          mesh.material.emissiveIntensity = 0.6;
          tinted.push({ mesh, origColor });
        }
      }
    }
  }

  if (tinted.length > 0) {
    setTimeout(() => {
      for (const { mesh, origColor } of tinted) {
        if (mesh.material) {
          mesh.material.color.setHex(origColor);
          mesh.material.emissive = new THREE.Color(0x000000);
          mesh.material.emissiveIntensity = 0;
        }
      }
    }, duration);
  }
}

// Resize building
window._resizeBld = (id, dw, dd) => {
  const b = buildingsMap.get(id);
  if (!b) return;
  const oldW = b.widthTiles || 25;
  const oldD = b.heightTiles || 17;
  const newW = Math.max(5, oldW + dw * 3);
  const newD = Math.max(5, oldD + dd * 3);
  applyBuildingResizeFootprint(b, {
    left: 0,
    top: 0,
    right: newW,
    bottom: newD,
    widthTiles: newW,
    heightTiles: newD,
    offsetX: 0,
    offsetZ: 0,
  });
};

// Change building color theme
window._changeTheme = (id, themeName) => {
  const b = buildingsMap.get(id);
  if (!b) return;
  const theme = BUILDING_THEMES[themeName];
  if (!theme) return;
  b.exterior = b.exterior || {};
  b.exterior.wallColor = theme.wallColor;
  b.exterior.roofColor = theme.roofColor;
  b._currentTheme = themeName;
  // Rebuild the building with new colors
  createBuilding3D(b);
  // Rebuild affected chunks
  const themeBounds = getBuildingFootprintBounds(b, 0);
  const bx1 = Math.floor(themeBounds.minX / CHUNK);
  const bz1 = Math.floor(themeBounds.minZ / CHUNK);
  const bx2 = Math.floor(themeBounds.maxX / CHUNK);
  const bz2 = Math.floor(themeBounds.maxZ / CHUNK);
  for (let ccx = bx1; ccx <= bx2; ccx++) {
    for (let ccz = bz1; ccz <= bz2; ccz++) {
      const chunk = loadedChunks.get(chunkKey(ccx, ccz));
      if (chunk) rebuildChunk(chunk);
    }
  }
  // Save to server
  fetch(`/api/building/${id}`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(_buildingPayload(b)),
  }).catch(() => {});
  showToast(`🎨 Theme: ${theme.label}`, 'success');
};

// Rotate building 90° clockwise
window._rotateBld = (id) => {
  const b = buildingsMap.get(id);
  if (!b) return;
  // Track rotation (0, 90, 180, 270)
  b._rotation = ((b._rotation || 0) + 90) % 360;
  // Rebuild so visuals, colliders, doors, furniture, and outdoor props all stay in sync.
  createBuilding3D(b);
  if (insideBuildingId === id) {
    applyBuildingViewMode(b, 'xray');
  }
  // Refresh terrain/decor suppression around rotated footprint
  _rebuildNearChunks(b.worldX || 0, b.worldY || 0, Math.max(b.widthTiles || 25, b.heightTiles || 17) + 3);
  // Save
  fetch(`/api/building/${id}`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(_buildingPayload(b)),
  }).catch(() => {});
  selectBuilding(id); // refresh selection outline
  showToast(`🔄 Rotated: ${b._rotation}°`, 'success');
};

// ═══════════════════════════════════════════════════════════════
// BUILDING MOVE — Drag to reposition with sidewalk-to-street snap
// ═══════════════════════════════════════════════════════════════
let _movingBuildingId = null;
let _moveGhost = null;
const SNAP_RANGE = 4; // tiles — how close building sidewalk must be to street sidewalk to snap

window._moveBld = (id) => {
  const b = buildingsMap.get(id);
  if (!b || !b._group) return;
  _movingBuildingId = id;

  beginBuildingMovePreview(b);
  updateBuildingMovePreviewState(b, false);

  showToast('📦 Click to place building. Sidewalks snap to streets.', 'info');
};

function updateBuildingMove(e) {
  if (!_movingBuildingId) return;
  const b = buildingsMap.get(_movingBuildingId);
  if (!b || !b._group) { _movingBuildingId = null; return; }

  const hit = raycastGround(e);
  if (!hit) return;

  let newX = Math.floor(hit.x / T);
  let newZ = Math.floor(hit.z / T);
  // Swap width/depth for 90°/270° rotations so move preview matches rotated footprint
  const isSwapped = (b._rotation === 90 || b._rotation === 270);
  const bw = isSwapped ? (b.heightTiles || 17) : (b.widthTiles || 25);
  const bd = isSwapped ? (b.widthTiles || 25) : (b.heightTiles || 17);

  // Center on cursor
  newX -= Math.floor(bw / 2);
  newZ -= Math.floor(bd / 2);

  const snap = snapBuildingFootprintToStreet(newX, newZ, bw, bd);
  newX = snap.x;
  newZ = snap.z;
  const elevY = snap.elevY;
  const snapped = snap.snapped;

  // Move the 3D group to preview position using the same transform as final placement
  applyBuildingGroupTransform(b._group, b, newX, newZ, elevY);
  // Store pending world position (pre-rotation, for data storage)
  b._pendingX = newX;
  b._pendingZ = newZ;
  b._pendingY = elevY;
  b._snapped = snapped;

  // Collision check — tint red if overlapping another building
  const moveColliding = checkBuildingCollision(newX, newZ, bw, bd, _movingBuildingId);
  b._moveColliding = moveColliding;
  updateBuildingMovePreviewState(b, moveColliding);
}

function confirmBuildingMove() {
  if (!_movingBuildingId) return;
  const b = buildingsMap.get(_movingBuildingId);
  if (!b) { _movingBuildingId = null; return; }

  // Block move if colliding
  if (b._moveColliding) {
    showToast('❌ Cannot place here — overlaps another building!', 'error');
    return; // Keep in move mode so user can pick another spot
  }

  const newX = b._pendingX ?? b.worldX;
  const newZ = b._pendingZ ?? b.worldY;
  const oldX = b.worldX ?? newX;
  const oldZ = b.worldY ?? newZ;
  const before = snapshotBuildingForUndo(b);
  const isSwapped = (b._rotation === 90 || b._rotation === 270);
  const moveBw = isSwapped ? (b.heightTiles || 17) : (b.widthTiles || 25);
  const moveBd = isSwapped ? (b.widthTiles || 25) : (b.heightTiles || 17);

  // Auto-remove natural decorations (trees, rocks, etc.) under the new building footprint
  _removeNaturalDecorationsInArea(newX, newZ, moveBw, moveBd);

  // Update building data
  b.worldX = newX;
  b.worldY = newZ;
  b._elevationY = b._pendingY || 0; // store elevation for snapped buildings

  // Rebuild the building fresh (restores materials)
  createBuilding3D(b);

  // Rebuild chunks around old and new position
  _rebuildNearChunks(oldX, oldZ, 5);
  _rebuildNearChunks(newX, newZ, 5);

  // Save to server
  fetch(`/api/building/${b.id}`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(_buildingPayload(b)),
  }).catch(() => {});

  // Update selection
  selectBuilding(b.id);
  updateBuildingList();
  pushUndo({
    type: 'buildingUpdate',
    buildingId: b.id,
    label: 'building move',
    before,
    after: snapshotBuildingForUndo(b),
  });

  const snapMsg = b._snapped ? ' (snapped to street!)' : '';
  showToast(`📦 Moved: ${b.name}${snapMsg}`, 'success');

  delete b._pendingX;
  delete b._pendingZ;
  delete b._pendingY;
  delete b._moveColliding;
  delete b._snapped;
  _movingBuildingId = null;
}

function cancelBuildingMove() {
  if (!_movingBuildingId) return;
  const b = buildingsMap.get(_movingBuildingId);
  if (b) {
    delete b._pendingX;
    delete b._pendingZ;
    delete b._pendingY;
    delete b._moveColliding;
    delete b._snapped;
    // Restore to original position
    createBuilding3D(b);
  }
  _movingBuildingId = null;
  showToast('📦 Move cancelled', 'warning');
}

// ═══════════════════════════════════════════════════════════════
// BUILDING TRANSPARENCY / LAYER CONTROL
// ═══════════════════════════════════════════════════════════════
// Modes: 'solid' | 'no-roof' | 'active-walls' | 'xray'
// 'active-walls' = camera-relative: hides walls facing the camera, keeps walls behind
// 'entered' = temporary inside-building shell-open view, hides exterior shell but keeps interior walls visible
let _buildingViewMode = 'solid';

function getEffectiveBuildingViewMode(building, requestedMode = _buildingViewMode) {
  if (building && insideBuildingId === building.id && requestedMode !== 'xray') {
    return 'entered';
  }
  return requestedMode;
}

function setBuildingViewMode(mode) {
  _buildingViewMode = mode;
  for (const [, b] of buildingsMap) {
    applyBuildingViewMode(b, getEffectiveBuildingViewMode(b, mode));
  }
  document.querySelectorAll('.view-mode-btn').forEach(btn => {
    btn.classList.toggle('active', btn.dataset.mode === mode);
  });
}

/**
 * Determine which walls face the camera based on camAngle.
 * Returns { front, back, left, right } — true = facing camera (should hide in active-walls mode)
 */
function getCameraFacingWalls() {
  // camAngle is the horizontal rotation angle around Y axis
  // Normalize to 0-2PI
  const a = ((camAngle % (Math.PI * 2)) + Math.PI * 2) % (Math.PI * 2);
  // Camera looks from angle toward center. Walls facing the camera should be hidden.
  // Default isometric: camAngle ≈ π/4 → camera is in the +X +Z quadrant → front (south/+Z) and right (east/+X) walls face camera
  return {
    front: (a >= 0 && a < Math.PI),           // south wall faces camera when cam is in south half
    back:  (a >= Math.PI && a < Math.PI * 2),  // north wall
    right: (a >= Math.PI * 0.5 && a < Math.PI * 1.5), // east wall
    left:  (a < Math.PI * 0.5 || a >= Math.PI * 1.5), // west wall
  };
}

function applyBuildingViewMode(building, mode) {
  if (!building._group || building.type === 'park') return;
  const facing = (mode === 'active-walls') ? getCameraFacingWalls() : null;

  building._group.traverse(child => {
    if (!child.isMesh && !child.isSprite) return;
    if (child.userData?.pingPongRuntimeVisual) {
      return;
    }
    const n = child.name || '';
    const isExteriorStructure = n === 'roof' || n.startsWith('wall-') || n === 'window';
    const isExteriorWall = n.startsWith('wall-');
    const isInteriorWall = n === 'interior-wall';

    if (isBuildingFloorFocusActive(building)) {
      if (n === 'roof') {
        child.visible = false;
        return;
      }
      if (isInteriorWall && Math.max(1, Number(child.userData?.floor || 1) || 1) !== getActiveBuildingFloor(building)) {
        child.visible = false;
        return;
      }
    }

    if (mode === 'solid') {
      child.visible = true;
      if (isExteriorStructure) {
        if (child.material) {
          child.material.transparent = false;
          child.material.opacity = 1.0;
          child.material.needsUpdate = true;
        }
      }
    } else if (mode === 'no-roof') {
      if (n === 'roof') {
        child.visible = false;
      } else {
        child.visible = true;
        if (isExteriorStructure) {
          if (child.material) {
            child.material.transparent = false;
            child.material.opacity = 1.0;
            child.material.needsUpdate = true;
          }
        }
      }
    } else if (mode === 'active-walls') {
      // Camera-relative: hide roof + walls facing camera, keep walls behind
      if (n === 'roof') {
        child.visible = false;
      } else if (n.startsWith('wall-front')) {
        child.visible = !facing.front;
      } else if (n.startsWith('wall-back')) {
        child.visible = !facing.back;
      } else if (n.startsWith('wall-left')) {
        child.visible = !facing.left;
      } else if (n.startsWith('wall-right')) {
        child.visible = !facing.right;
      } else if (n === 'window') {
        // Hide windows on walls that face camera
        child.visible = false; // simplify: hide all windows in this mode
      } else {
        child.visible = true;
      }
    } else if (mode === 'entered') {
      if (isExteriorStructure) {
        const wallFloor = Math.max(1, Number(child.userData?.floor || 1) || 1);
        // Keep lower-floor exterior bands visible/clickable while focused on an
        // upper floor. Hide the active floor shell so the current interior stays open.
        child.visible = isExteriorWall && wallFloor < getActiveBuildingFloor(building);
      } else {
        child.visible = true;
      }
    } else if (mode === 'xray') {
      if (isExteriorStructure || isInteriorWall) {
        child.visible = false;
      } else {
        child.visible = true;
      }
    }
  });
}

// Called when camera rotates — update active walls if in that mode
function updateActiveWalls() {
  if (_buildingViewMode === 'active-walls') {
    for (const [, b] of buildingsMap) {
      if (b.id !== _agentFollowTransparentBldId) {
        applyBuildingViewMode(b, getEffectiveBuildingViewMode(b, 'active-walls'));
      }
    }
  }
}

// Apply transparency to a specific building (for agent-follow)
function setBuildingTransparent(buildingId, transparent) {
  const b = buildingsMap.get(buildingId);
  if (!b) return;
  if (transparent) {
    applyBuildingViewMode(b, 'xray');
  } else {
    applyBuildingViewMode(b, _buildingViewMode);
  }
}

// Setup the view mode buttons
function setupViewModeButtons() {
  const container = document.getElementById('viewModeButtons');
  if (!container) return;
  const modes = [
    { id: 'solid',        label: '🏢', title: 'Solid — Full building' },
    { id: 'no-roof',      label: '🔲', title: 'No Roof — Hides roof only' },
    { id: 'active-walls', label: '🔳', title: 'Active Walls — Hides walls facing camera' },
    { id: 'xray',         label: '👁️', title: 'X-Ray — Floor + furniture only' },
  ];
  container.innerHTML = '';
  modes.forEach(m => {
    const btn = document.createElement('button');
    btn.className = 'view-mode-btn toolbar-btn' + (m.id === _buildingViewMode ? ' active' : '');
    btn.dataset.mode = m.id;
    btn.title = m.title;
    btn.textContent = m.label;
    btn.addEventListener('click', () => setBuildingViewMode(m.id));
    container.appendChild(btn);
  });
}

