function showContextMenu(e) {
  const menu = document.getElementById('contextMenu');
  if (!menu) return;

  // Raycast to find what was right-clicked
  const rect = renderer.domElement.getBoundingClientRect();
  const mx = ((e.clientX - rect.left) / rect.width) * 2 - 1;
  const my = -((e.clientY - rect.top) / rect.height) * 2 + 1;
  const ray = new THREE.Raycaster();
  ray.setFromCamera(new THREE.Vector2(mx, my), camera);

  // Check agents first
  const agentMeshes = [];
  agentsList.forEach(a => { if (a._group3d) agentMeshes.push(...a._group3d.children.filter(c => c.isMesh)); });
  const agentHits = ray.intersectObjects(agentMeshes, false);
  if (agentHits.length > 0) {
    for (const agent of agentsList) {
      if (!agent._group3d) continue;
      const owned = agent._group3d.children.some(c => c === agentHits[0].object);
      if (owned) {
        buildContextMenu(menu, 'agent', agent.id);
        positionContextMenu(menu, e.clientX, e.clientY);
        return;
      }
    }
  }

  // Check placed objects before generic building surfaces. The target resolver
  // validates the hit against the persisted interior furniture/outdoor node
  // stores and skips deleted/hidden/disabled records, so menus never open for
  // unknown meshes or stale object tags.
  const objectContext = resolveObjectContextTargetFromRay(ray);
  if (objectContext.target) {
    registerActiveContextTarget(objectContext.target);
    buildContextMenu(menu, objectContext.target.menuType, objectContext.target.targetId);
    positionContextMenu(menu, e.clientX, e.clientY);
    return;
  }
  if (objectContext.blocked) {
    registerActiveContextTarget(null);
    hideContextMenu();
    return;
  }

  // Check buildings
  const hit = raycastGround(e);
  if (hit) {
    for (const [id, bld] of buildingsMap) {
      const bounds = getBuildingFootprintBounds(bld, 0);
      if (hit.x >= bounds.minX && hit.x <= bounds.maxX && hit.z >= bounds.minZ && hit.z <= bounds.maxZ) {
        buildContextMenu(menu, 'building', id);
        positionContextMenu(menu, e.clientX, e.clientY);
        return;
      }
    }
  }

  hideContextMenu();
}

function getContextSubjectForObjectTarget(contextTarget = {}) {
  const roles = ['participant'];
  if ((contextTarget.assignedRoles || []).some(role => String(role).toLowerCase() === 'medical-staff')) roles.push('medical-staff');
  return {
    agentId: 'nearest-agent',
    roles,
  };
}

function getContextTargetActionSnapshot(contextTarget = {}, rawObject = {}) {
  return {
    objectInstanceId: contextTarget.objectInstanceId || contextTarget.objectId || rawObject.id || rawObject.instanceId || 'object-instance-pending',
    catalogId: contextTarget.catalogKey || contextTarget.catalogId || rawObject.catalogId || rawObject.type,
    objectCatalogId: contextTarget.objectCatalogId || rawObject.objectCatalogId || null,
    state: rawObject.activeUse || rawObject.state || rawObject.lifecycle || null,
    status: rawObject.status || rawObject.state?.status || rawObject.lifecycle?.status || null,
    disabled: isPlacedObjectContextDisabled(rawObject),
    reservation: rawObject.reservation || null,
    reservations: Array.isArray(rawObject.reservations) ? rawObject.reservations : [],
    assignedAgentIds: rawObject.assignedAgentIds || rawObject.permissions?.assignedAgentIds || [],
    assignedRoles: rawObject.assignedRoles || rawObject.permissions?.assignedRoles || [],
    ownerAgentId: rawObject.ownerAgentId || rawObject.permissions?.ownerAgentId || null,
  };
}

function objectCapabilitySupportsAction(contextTarget = {}, action = {}) {
  const actionTag = normalizeCapabilityTag(action.worldAction?.capabilityTag);
  if (!actionTag) return false;
  const targetTags = new Set((contextTarget.capabilityTags || []).map(tag => normalizeCapabilityTag(tag)).filter(Boolean));
  if (!targetTags.size) return true;
  return targetTags.has(actionTag);
}

function getAgentPickerSubject(agent, contextTarget = {}) {
  const roles = new Set(['participant']);
  if (Array.isArray(agent?.roles)) agent.roles.forEach(role => roles.add(String(role).toLowerCase()));
  if (Array.isArray(agent?.capabilityRoles)) agent.capabilityRoles.forEach(role => roles.add(String(role).toLowerCase()));
  if ((contextTarget.assignedAgentIds || []).includes(agent?.id)) roles.add('assigned-agent');
  // Preserve Task 3's medical-staff compatibility behavior until agent profile roles are first-class.
  if ((contextTarget.assignedRoles || []).some(role => String(role).toLowerCase() === 'medical-staff')) roles.add('medical-staff');
  return { agentId: agent?.id || 'missing-agent', roles: [...roles].filter(Boolean) };
}

function getAgentLocationContext(agent) {
  if (!agent) return 'Missing from roster';
  const building = getMovementInteriorBuildingAt(agent.x, agent.y) || agent._currentBuilding || agent._targetBuilding || null;
  if (building?.name) return `At ${building.name}${getAgentFloor(agent, building) > 1 ? ` · floor ${getAgentFloor(agent, building)}` : ''}`;
  if (agent._wanderTarget?.targetKind === 'outdoor-area-node') return 'Outside · heading to outdoor object';
  if (agent._wanderTarget?.targetKind === 'placed-object') return 'Heading to object';
  return 'Outside / wandering';
}

function getAgentBusyReason(agent) {
  if (!agent) return 'Agent is missing from the loaded roster';
  const status = normalizeLiveAgentStatus(agent.status) || 'offline';
  if (status === 'offline') return 'Agent is offline';
  if (normalizeLiveAgentStatus(status) === 'working') return agent.task ? `Busy: ${agent.task}` : 'Busy working';
  if (status === 'meeting' || agent._meetingId) return 'Busy in a meeting';
  if (agent._tagState?.playing) return 'Busy playing tag';
  if (agent._atDesk) return 'Busy at desk';
  if (agent._idleActivity?.phase === 'approach' || agent._idleActivity?.phase === 'using') return 'Already assigned to another object action';
  return null;
}

function getActionDisabledReasonForAgent(action, contextTarget, rawObject, agent) {
  if (!action || action.disabled) return action?.disabledReason || 'action_unavailable';
  const targetSnapshot = getContextTargetActionSnapshot(contextTarget, rawObject);
  const subject = getAgentPickerSubject(agent, contextTarget);
  const resolved = resolveContextMenuActions({
    registry: CONTEXT_MENU_ACTION_REGISTRY,
    target: targetSnapshot,
    subject,
    context: {
      agentAvailable: true,
      source: { kind: 'user-agent-picker' },
      permissionContext: {
        assignedAgentIds: targetSnapshot.assignedAgentIds,
        assignedRoles: targetSnapshot.assignedRoles,
        ownerAgentId: targetSnapshot.ownerAgentId,
      },
    },
  }).find(candidate => (candidate.worldAction?.actionType || candidate.apiActionId || candidate.uiActionId) === (action.worldAction?.actionType || action.apiActionId || action.uiActionId));
  return resolved?.disabled ? (resolved.disabledReason || 'action_unavailable') : null;
}

function makeSelectedAgentWorldActionContext({ agent, action, contextTarget, rawObject, buildingId, furnitureIndex, approach }) {
  const subject = getAgentPickerSubject(agent, contextTarget);
  const targetSnapshot = getContextTargetActionSnapshot(contextTarget, rawObject);
  const requestNonce = `${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;
  const basePayload = makeContextMenuWorldActionPayload(action, {
    target: targetSnapshot,
    subject,
    agentId: agent.id,
    id: `user-${agent.id}-${stableContextActionToken(action)}-${requestNonce}`,
    source: {
      kind: 'user',
      requestedBy: 'user',
      requestId: `context-menu-${requestNonce}`,
      surface: 'context-menu',
      roles: subject.roles,
    },
    now: new Date().toISOString(),
    params: {
      buildingId,
      furnitureIndex,
      sourceSurface: 'context-menu-agent-picker',
      uiActionId: action.uiActionId || null,
      apiActionId: action.apiActionId || action.worldAction?.actionType || null,
      actionParams: action.worldAction?.params || {},
    },
  });
  const payload = {
    ...basePayload,
    source: {
      ...basePayload.source,
      kind: 'user',
      requestedBy: 'user',
      surface: 'context-menu',
      roles: subject.roles,
    },
    target: {
      ...basePayload.target,
      buildingId,
      furnitureIndex,
      floor: approach?.floor || contextTarget?.floor || 1,
      objectInstanceId: contextTarget?.objectInstanceId || targetSnapshot.objectInstanceId,
      catalogId: contextTarget?.objectCatalogId || targetSnapshot.objectCatalogId || targetSnapshot.catalogId,
      interactionSpotId: approach?.spotId || basePayload.target.interactionSpotId || 'default',
    },
    uiContext: {
      surface: 'context-menu',
      selectedAgentId: agent.id,
      contextTargetStableId: contextTarget?.stableId || null,
      targetLabel: contextTarget?.label || null,
      menuActionId: action.id || null,
      routeOwner: 'main3d.js#setAgentTarget -> dynamic-interior-routing.js',
    },
    route: {
      state: 'route_pending',
      target: approach ? { apiX: approach.apiX, apiY: approach.apiZ, floor: approach.floor || 1 } : null,
      setAgentTarget: true,
      handoff: 'main3d.js#setAgentTarget -> dynamic-interior-routing.js',
    },
  };
  return { agentId: agent.id, actionId: payload.actionType, capabilityTag: payload.capabilityTag, payload };
}

function stableContextActionToken(action = {}) {
  return String(action.worldAction?.actionType || action.apiActionId || action.uiActionId || action.id || 'action')
    .replace(/[^a-zA-Z0-9_-]+/g, '-')
    .replace(/^-+|-+$/g, '') || 'action';
}

function formatWorldActionApiError(data, fallbackStatus = 0) {
  const error = data?.error || data || {};
  const code = error.code || data?.code || (fallbackStatus ? `http_${fallbackStatus}` : 'network_error');
  const message = error.message || data?.message || 'World action could not be created.';
  const details = error.details || data?.details || null;
  const detailText = Array.isArray(details)
    ? details.join('; ')
    : (details && typeof details === 'object'
      ? Object.values(details).filter(value => typeof value === 'string').join('; ')
      : (typeof details === 'string' ? details : ''));
  return { code, message: detailText ? `${message} ${detailText}` : message, details };
}

async function createWorldActionFromContextSelection(selected, { action, contextTarget, routeTarget } = {}) {
  const request = selected?.payload || null;
  if (!request?.target?.objectInstanceId) {
    const error = { code: 'target_missing', message: 'Missing object target for world action.' };
    window.__VWLastWorldActionCreate = { state: 'error', request, error, actionId: null };
    showToast('Missing target: right-click a real placed object first.', 'error');
    return { ok: false, error };
  }
  if (!request?.agentId) {
    const error = { code: 'agent_missing', message: 'Missing selected agent for world action.' };
    window.__VWLastWorldActionCreate = { state: 'error', request, error, actionId: null };
    showToast('Missing selected agent for this action.', 'error');
    return { ok: false, error };
  }
  window.__VWLastWorldActionCreate = { state: 'pending', request, actionId: request.id || null, contextTarget, menuAction: action || null };
  showToast(`⏳ Creating ${action?.label || request.actionType || 'world action'} reservation…`, 'info');
  addActivityLog(`⏳ World action pending: ${request.actionType} for ${request.agentId}`);
  try {
    const response = await fetch('/api/world-actions', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(request),
    });
    const data = await response.json().catch(() => ({}));
    if (!response.ok || !data?.ok) {
      const error = formatWorldActionApiError(data, response.status);
      window.__VWLastWorldActionCreate = { state: 'error', request, response: data, error, actionId: request.id || null, contextTarget, menuAction: action || null };
      const conflictHint = error.code === 'object_reserved' || error.code === 'duplicate_action' ? 'Reservation conflict: ' : '';
      showToast(`${conflictHint}${error.message}`, error.code === 'object_reserved' || error.code === 'duplicate_action' ? 'warning' : 'error');
      addActivityLog(`⚠️ World action failed: ${error.code}`);
      return { ok: false, error, response: data };
    }
    const created = data.action || null;
    const actionId = created?.id || request.id || null;
    window.__VWLastWorldActionCreate = {
      state: created?.reservation?.state || created?.status || 'reserved',
      request,
      response: data,
      action: created,
      actionId,
      reservation: created?.reservation || null,
      routeHandoff: data.routeHandoff || created?.route || null,
      contextTarget,
      menuAction: action || null,
      routeTarget,
    };
    showToast(`✅ Reserved action ${actionId || ''}`.trim(), 'success');
    addActivityLog(`✅ Reserved world action ${actionId || request.actionType}`);
    return { ok: true, action: created, actionId, response: data };
  } catch (err) {
    const error = { code: 'network_error', message: err?.message || 'Network/server failure while creating world action.' };
    window.__VWLastWorldActionCreate = { state: 'error', request, error, actionId: request.id || null, contextTarget, menuAction: action || null };
    showToast(`Server/network failure: ${error.message}`, 'error');
    addActivityLog(`⚠️ World action network failure: ${request.actionType}`);
    return { ok: false, error };
  }
}

function buildAgentPickerOptions({ action, contextTarget, rawObject, building, approach }) {
  return (agentsList || []).map(agent => {
    const busyReason = getAgentBusyReason(agent);
    const actionReason = getActionDisabledReasonForAgent(action, contextTarget, rawObject, agent);
    const distance = approach ? Math.hypot((agent.x || 0) - approach.apiX, (agent.y || 0) - approach.apiZ) : 0;
    const inSameBuilding = Boolean(building && (getMovementInteriorBuildingAt(agent.x, agent.y)?.id === building.id || isPointInsideBuildingInterior(building, agent.x, agent.y, -0.15)));
    const disabledReason = busyReason || actionReason || null;
    return {
      agent,
      enabled: !disabledReason,
      disabledReason,
      status: normalizeLiveAgentStatus(agent?.status) || 'offline',
      location: getAgentLocationContext(agent),
      subject: getAgentPickerSubject(agent, contextTarget),
      distance,
      inSameBuilding,
    };
  }).sort((a, b) => Number(b.enabled) - Number(a.enabled) || Number(b.inSameBuilding) - Number(a.inSameBuilding) || a.distance - b.distance || String(a.agent?.name || '').localeCompare(String(b.agent?.name || '')));
}

function ensureAgentPickerModal() {
  let modal = document.getElementById('agentPickerModal');
  if (modal) return modal;
  modal = document.createElement('div');
  modal.id = 'agentPickerModal';
  modal.className = 'modal agent-picker-modal';
  modal.style.display = 'none';
  modal.innerHTML = `
    <div class="modal-content agent-picker-content">
      <div class="modal-header">
        <h2 id="agentPickerTitle">👤 Choose Agent</h2>
        <button class="modal-close" id="agentPickerCancelX">✕</button>
      </div>
      <div class="agent-picker-summary" id="agentPickerSummary"></div>
      <div class="agent-picker-list" id="agentPickerList"></div>
      <div class="agent-picker-footer">
        <button class="btn-secondary" id="agentPickerCancel">Cancel</button>
        <button class="btn-primary" id="agentPickerConfirm" disabled>Assign selected agent</button>
      </div>
    </div>`;
  document.body.appendChild(modal);
  return modal;
}

function openAgentPicker({ action, contextTarget, rawObject, building, approach, buildingId, furnitureIndex }) {
  const modal = ensureAgentPickerModal();
  const summary = modal.querySelector('#agentPickerSummary');
  const list = modal.querySelector('#agentPickerList');
  const confirm = modal.querySelector('#agentPickerConfirm');
  const title = modal.querySelector('#agentPickerTitle');
  const options = buildAgentPickerOptions({ action, contextTarget, rawObject, building, approach });
  let selectedId = options.find(option => option.enabled)?.agent?.id || null;
  const capability = getContextMenuCapabilityPresentation(action?.worldAction?.capabilityTag);

  return new Promise(resolve => {
    const close = result => {
      modal.style.display = 'none';
      modal.onkeydown = null;
      resolve(result || null);
    };
    const render = () => {
      const eligibleCount = options.filter(option => option.enabled).length;
      title.textContent = `${action?.icon || capability.icon || '👤'} Choose Agent`;
      summary.innerHTML = `
        <div><strong>${escapeHtml(action?.label || 'Object action')}</strong> · ${escapeHtml(capability.label || 'Capability')}</div>
        <div>${eligibleCount} eligible of ${options.length} loaded agents · route handoff: <code>setAgentTarget()</code></div>`;
      list.innerHTML = options.length ? options.map(option => {
        const agent = option.agent || {};
        const checked = selectedId === agent.id ? ' checked' : '';
        const disabled = option.enabled ? '' : ' disabled';
        const capabilityText = `${capability.label || 'Capability'} · ${action?.permission?.level || 'public'}`;
        return `<label class="agent-picker-row ${option.enabled ? 'eligible' : 'blocked'} ${checked ? 'selected' : ''}" data-agent-id="${escapeAttr(agent.id || '')}" title="${escapeAttr(option.disabledReason || 'Eligible')}">
          <input type="radio" name="agentPickerChoice" value="${escapeAttr(agent.id || '')}"${checked}${disabled}>
          <span class="agent-picker-avatar">${escapeHtml(agent.emoji || '🤖')}</span>
          <span class="agent-picker-main">
            <span class="agent-picker-name">${escapeHtml(agent.name || agent.id || 'Missing agent')}</span>
            <span class="agent-picker-meta">${escapeHtml(option.location)} · ${option.inSameBuilding ? 'same building' : 'nearest route OK'}</span>
            <span class="agent-picker-capability">${escapeHtml(capabilityText)} · roles: ${escapeHtml(option.subject.roles.join(', '))}</span>
          </span>
          <span class="agent-picker-state ${option.enabled ? 'available' : 'unavailable'}">${escapeHtml(option.enabled ? `Available · ${option.status}` : option.disabledReason)}</span>
        </label>`;
      }).join('') : '<div class="agent-picker-empty">No agents are loaded. The action cannot be assigned.</div>';
      confirm.disabled = !selectedId || !options.some(option => option.enabled && option.agent?.id === selectedId);
      confirm.textContent = eligibleCount ? 'Assign selected agent' : 'No eligible agents';
      list.querySelectorAll('input[name="agentPickerChoice"]').forEach(input => {
        input.addEventListener('change', () => { selectedId = input.value; render(); });
      });
    };
    modal.querySelector('#agentPickerCancelX').onclick = () => close(null);
    modal.querySelector('#agentPickerCancel').onclick = () => close(null);
    confirm.onclick = () => {
      const option = options.find(candidate => candidate.enabled && candidate.agent?.id === selectedId);
      if (!option) return;
      close(makeSelectedAgentWorldActionContext({ agent: option.agent, action, contextTarget, rawObject, buildingId, furnitureIndex, approach }));
    };
    modal.onkeydown = event => { if (event.key === 'Escape') close(null); };
    render();
    modal.style.display = 'flex';
    modal.focus?.();
  });
}

function resolveCapabilityContextActions(contextTarget = {}, rawObject = {}, { includeDisabled = true } = {}) {
  if (!contextTarget) return [];
  const subject = getContextSubjectForObjectTarget(contextTarget);
  const actionTarget = getContextTargetActionSnapshot(contextTarget, rawObject);
  return resolveContextMenuActions({
    registry: CONTEXT_MENU_ACTION_REGISTRY,
    target: actionTarget,
    subject,
    context: {
      agentAvailable: agentsList.some(agent => agent && agent.status !== 'working' && !agent._atDesk && !agent._tagState?.playing),
      source: { kind: 'user-context-menu' },
      permissionContext: {
        assignedAgentIds: actionTarget.assignedAgentIds,
        assignedRoles: actionTarget.assignedRoles,
        ownerAgentId: actionTarget.ownerAgentId,
      },
    },
  }).filter(action => includeDisabled || !action.disabled);
}

function getContextRouteSpotForAction(building, furniture, action = {}) {
  const preferredSpotId = action.target?.interactionSpotId || action.worldActionPayload?.target?.interactionSpotId || null;
  return getFurnitureActionSpot(building, furniture, preferredSpotId) || getFurnitureActionSpot(building, furniture);
}

async function routeAgentToCapabilityFurnitureAction(buildingId, furnitureIndex, action) {
  const building = buildingsMap.get(buildingId);
  const furniture = building?.interior?.furniture?.[furnitureIndex];
  const approach = getContextRouteSpotForAction(building, furniture, action);
  if (!building || !furniture || !approach) {
    showToast('Action target is unavailable for this object', 'warning');
    return null;
  }
  if (action?.disabled) {
    showToast(`Action unavailable: ${action.disabledReason || 'not available'}`, 'warning');
    return null;
  }
  const contextTarget = resolveFurnitureContextTarget(buildingId, furnitureIndex) || _activeContextTarget;
  if (isHairEditorAction(action) && !contextTargetSupportsHairEdit(contextTarget, furniture, action)) {
    showToast('Hair editing must start from a real Barber Chair edit-hair object.', 'warning');
    window.__VWLastHairEditorBlocked = { reason: 'not_barber_chair', buildingId, furnitureIndex, catalogKey: contextTarget?.catalogKey || furniture?.type || null, actionId: action?.worldAction?.actionType || action?.apiActionId || null };
    return null;
  }
  if (isWhiteboardPlanningAction(action) && !contextTargetSupportsWhiteboardPlanning(contextTarget, furniture, action)) {
    showToast('Planning/teaching must start from a real Whiteboard with planning or classroom capability.', 'warning');
    window.__VWLastWhiteboardPlanningBlocked = { reason: 'not_whiteboard_planning_object', buildingId, furnitureIndex, catalogKey: contextTarget?.catalogKey || furniture?.type || null, actionId: action?.worldAction?.actionType || action?.apiActionId || null };
    return null;
  }
  if (isClinicBedDocsAction(action) && !contextTargetSupportsClinicBedDocs(contextTarget, furniture, action)) {
    showToast('Agent docs review must start from a real Clinic Bed with medical and maintenance/review capability tags.', 'warning');
    window.__VWLastClinicBedDocsBlocked = { reason: 'not_clinic_bed_docs_object', buildingId, furnitureIndex, catalogKey: contextTarget?.catalogKey || furniture?.type || null, actionId: action?.worldAction?.actionType || action?.apiActionId || null };
    return null;
  }
  const secondWaveSupport = contextTargetSupportsSecondWaveObjectAction(contextTarget, furniture, action);
  if (getSecondWaveObjectActionConfig(action, contextTarget, furniture) && !secondWaveSupport) {
    showToast('Second-wave action requires a real placed object with matching tags and interaction spot.', 'warning');
    window.__VWLastSecondWaveActionBlocked = { reason: 'missing_real_second_wave_target_tags_or_spot', buildingId, furnitureIndex, catalogKey: contextTarget?.catalogKey || furniture?.type || null, actionId: action?.worldAction?.actionType || action?.apiActionId || null };
    return null;
  }
  const isBarberHairAction = isHairEditorAction(action) && contextTargetSupportsHairEdit(contextTarget, furniture, action);
  const barberSeatSpot = isBarberHairAction ? (getFurnitureActionSpot(building, furniture, 'seat') || approach) : null;
  const barberSeatFaceAngle = isBarberHairAction ? (getBarberChairSeatFacingAngle(building, furniture, barberSeatSpot) ?? barberSeatSpot?.faceAngle ?? approach?.faceAngle) : null;
  const routeApproach = isBarberHairAction ? (getFurnitureActionSpot(building, furniture, 'approach-front') || getFurnitureActionSpot(building, furniture, 'stylist') || approach) : approach;
  const selected = await openAgentPicker({ action, contextTarget, rawObject: furniture, building, approach: routeApproach, buildingId, furnitureIndex });
  if (isBarberHairAction && selected?.payload) {
    selected.payload.target = { ...selected.payload.target, interactionSpotId: barberSeatSpot?.spotId || 'seat' };
    if (selected.payload.reservation) selected.payload.reservation = { ...selected.payload.reservation, spotId: barberSeatSpot?.spotId || 'seat' };
  }
  if (!selected?.agentId) {
    showToast('Agent selection cancelled', 'info');
    window.__VWLastAgentPickerCancellation = { buildingId, furnitureIndex, actionId: action.worldAction?.actionType || action.apiActionId || action.uiActionId, reason: 'cancelled_or_no_eligible_agent' };
    return null;
  }
  const agent = agentsList.find(candidate => candidate?.id === selected.agentId);
  if (!agent) {
    showToast('Selected agent is no longer available', 'warning');
    return null;
  }
  const routeTarget = {
    x: routeApproach.apiX,
    y: routeApproach.apiZ,
    floor: routeApproach.floor,
    targetKind: 'placed-object',
    objectInstanceId: contextTarget?.objectInstanceId || `${buildingId}-${furniture.type}-${furnitureIndex}`,
    objectId: contextTarget?.objectId || `${buildingId}-${furniture.type}-${furnitureIndex}`,
    catalogKey: contextTarget?.catalogKey || furniture.type,
    buildingId,
    furnitureIndex,
    scope: 'indoor',
    interactionSpotId: isBarberHairAction ? (barberSeatSpot?.spotId || 'seat') : (routeApproach.spotId || action.target?.interactionSpotId || 'default'),
    activationSpotId: isBarberHairAction ? (barberSeatSpot?.spotId || 'seat') : undefined,
    routeSpotId: routeApproach.spotId || null,
    actionId: action.worldAction?.actionType || routeApproach.action || null,
    capabilityTag: action.worldAction?.capabilityTag || null,
    routeOwner: 'main3d.js#setAgentTarget -> dynamic-interior-routing.js',
  };
  const created = await createWorldActionFromContextSelection(selected, { action, contextTarget, routeTarget });
  if (!created.ok) return null;
  routeTarget.worldActionId = created.actionId;
  routeTarget.reservationId = created.action?.reservation?.id || null;
  routeTarget.routeHandoff = created.action?.route || created.response?.routeHandoff || null;
  // Phase 3 Task 8 legacy verifier marker: setAgentTarget(agent, routeTarget, building, approach.floor)
  // Runtime uses the explicit object-intent wrapper so linked UI keeps priority ownership without changing route executors.
  // Phase 3 verifier marker: setAgentTarget(agent, routeTarget, building, approach.floor);
  const explicitRoute = setAgentTargetForExplicitObjectAction(agent, routeTarget, building, routeApproach.floor, {
    owner: 'object-action',
    sourceFamily: 'context-menu',
    sourceFunction: 'routeAgentToCapabilityFurnitureAction',
    actionId: routeTarget.actionId,
    worldActionId: created.actionId,
    reservationId: routeTarget.reservationId,
    furnitureIndex,
    objectType: furniture.type,
    spotId: routeTarget.interactionSpotId,
    behaviorSourceKind: 'user',
    behaviorMode: 'manual-object-assignment',
    behaviorAuthority: AGENT_INTENT_PRIORITY['explicit-object'],
  });
  if (explicitRoute?.accepted === false) {
    await fetch(`/api/world-actions/${encodeURIComponent(created.actionId)}/cancel`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ actor: 'main3d.js#routeAgentToCapabilityFurnitureAction', source: 'route-admission-rejected', result: { reason: explicitRoute.reason || 'route_admission_rejected', activeIntentId: explicitRoute.activeIntent?.id || null } }),
    }).catch(() => null);
    window.__VWLastCapabilityContextAction = { ok: false, agentId: agent.id, buildingId, furnitureIndex, actionId: routeTarget.actionId, rejected: explicitRoute, worldActionId: created.actionId };
    showToast(`${agent.name || agent.id} is already committed to another higher-priority task.`, 'warning');
    return null;
  }
  const isWhiteboardAction = isWhiteboardPlanningAction(action) && contextTargetSupportsWhiteboardPlanning(contextTarget, furniture, action);
  const isClinicDocsAction = isClinicBedDocsAction(action) && contextTargetSupportsClinicBedDocs(contextTarget, furniture, action);
  const secondWaveResolved = secondWaveSupport || contextTargetSupportsSecondWaveObjectAction(contextTarget, furniture, action);
  const secondWaveKey = secondWaveResolved?.assetKey || null;
  const secondWaveConfig = secondWaveResolved?.config || null;
  const secondWaveProfile = secondWaveKey ? IDLE_ACTIVITY_PROFILES[secondWaveKey] : null;
  const whiteboardMode = action.uiActionId === 'teaching-session' || action.worldAction?.actionType === 'training.teachAtWhiteboard' ? 'teach' : 'planning';
  const clinicMode = action.uiActionId === 'repair-restore-agent-state' || action.worldAction?.actionType === 'maintenance.repairAgentState' ? 'repair' : 'review';
  if (isBarberHairAction) {
    furniture.reservation = { agentId: agent.id, actionId: routeTarget.actionId, spotId: barberSeatSpot?.spotId || 'seat', worldActionId: created.actionId, reservationId: routeTarget.reservationId, status: 'held' };
    furniture.activeUse = { state: 'reserved', mode: 'hair', actionId: routeTarget.actionId, agentId: agent.id || null, worldActionId: created.actionId, serviceSpotId: routeTarget.routeSpotId || null };
    furniture.serviceState = { ...(furniture.serviceState || {}), customer: agent.id || null, stylist: null, mode: 'hair' };
  } else if (isWhiteboardAction) {
    furniture.reservation = { agentId: agent.id, actionId: routeTarget.actionId, spotId: routeTarget.interactionSpotId, worldActionId: created.actionId, reservationId: routeTarget.reservationId, status: 'held' };
    furniture.activeUse = { state: 'reserved', mode: whiteboardMode, actionId: routeTarget.actionId, agentId: agent.id || null, worldActionId: created.actionId, session: whiteboardMode === 'teach' ? 'Teaching' : 'Planning' };
    furniture.boardSession = { ...(furniture.boardSession || {}), active: true, mode: whiteboardMode, topic: action.worldAction?.params?.topic || furniture.boardSession?.topic || 'Planning / teaching session', context: action.worldAction?.params?.context || furniture.boardSession?.context || null, actionId: routeTarget.actionId, agentId: agent.id || null, objectInstanceId: routeTarget.objectInstanceId, worldActionId: created.actionId };
  } else if (isClinicDocsAction) {
    furniture.reservation = { agentId: agent.id, actionId: routeTarget.actionId, spotId: routeTarget.interactionSpotId, worldActionId: created.actionId, reservationId: routeTarget.reservationId, status: 'held' };
    furniture.activeUse = { state: 'reserved', mode: clinicMode, actionId: routeTarget.actionId, agentId: agent.id || null, worldActionId: created.actionId, editor: 'agent-docs' };
    furniture.clinicDocReview = { ...(furniture.clinicDocReview || {}), active: true, mode: clinicMode, actionId: routeTarget.actionId, agentId: agent.id || null, objectInstanceId: routeTarget.objectInstanceId, worldActionId: created.actionId, status: 'reserved', updatedAt: new Date().toISOString() };
  } else if (secondWaveKey) {
    furniture.reservation = { agentId: agent.id, actionId: routeTarget.actionId, spotId: routeTarget.interactionSpotId, worldActionId: created.actionId, reservationId: routeTarget.reservationId, status: 'held' };
    furniture.activeUse = { state: 'reserved', mode: secondWaveConfig.mode, actionId: routeTarget.actionId, agentId: agent.id || null, worldActionId: created.actionId, targetRequired: true };
    furniture.state = { ...(furniture.state || {}), status: 'reserved', activeAction: routeTarget.actionId, updatedAt: new Date().toISOString() };
    persistBuilding(building);
  }
  agent._idleActivity = {
    // Task 8 base form preserved: kind: isWhiteboardAction ? `whiteboard-${whiteboardMode}` : `capability-${contextTarget?.catalogKey || furniture.type}`
    // Task 10 second-wave actions are promoted to existing recognized idle prefixes.
    kind: isBarberHairAction ? 'barber-chair-hair' : (isWhiteboardAction ? `whiteboard-${whiteboardMode}` : (isClinicDocsAction ? `bed-clinic-${clinicMode}` : (secondWaveKey === 'bed' ? 'bed-sleep' : (secondWaveProfile?.kind || `capability-${contextTarget?.catalogKey || furniture.type}`)))),
    phase: 'approach',
    approachStartedAt: performance.now(),
    buildingId,
    furnitureIndex,
    furnitureType: furniture.type,
    capabilityTag: action.worldAction?.capabilityTag || null,
    actionId: routeTarget.actionId,
    interactionSpotId: routeTarget.interactionSpotId,
    stayMs: isBarberHairAction ? 15000 : (secondWaveProfile?.stayMs ? (secondWaveProfile.stayMs[0] + Math.random() * (secondWaveProfile.stayMs[1] - secondWaveProfile.stayMs[0])) : 12000),
    faceAngle: isBarberHairAction ? barberSeatFaceAngle : routeApproach.faceAngle,
    dockTarget: isBarberHairAction ? { x: barberSeatSpot?.apiX ?? routeApproach.apiX, y: barberSeatSpot?.apiZ ?? routeApproach.apiZ } : { x: routeApproach.apiX, y: routeApproach.apiZ },
    routeApproachTarget: isBarberHairAction ? { x: routeApproach.apiX, y: routeApproach.apiZ, floor: routeApproach.floor, spotId: routeApproach.spotId || 'stylist' } : undefined,
    dockSnapRadius: isBarberHairAction ? 12 : (secondWaveProfile?.dockSnapRadius || 8),
    routeMetadata: routeTarget,
    worldActionId: created.actionId,
    reservationId: routeTarget.reservationId,
    action: routeTarget.actionId,
    agentId: agent.id || null,
    objectInstanceId: routeTarget.objectInstanceId,
    spotId: routeTarget.interactionSpotId,
    mode: secondWaveConfig?.mode || (isClinicDocsAction ? clinicMode : undefined),
    topic: isWhiteboardAction ? furniture.boardSession?.topic || null : undefined,
    context: isWhiteboardAction ? furniture.boardSession?.context || null : undefined,
    clinicRole: isClinicDocsAction ? (clinicMode === 'review' ? 'service' : 'patient') : undefined,
    animationId: isBarberHairAction ? 'sit' : (isWhiteboardAction ? 'write-teach' : (isClinicDocsAction ? (clinicMode === 'review' ? 'service-checkup' : 'bed-rest') : (secondWaveProfile?.animationId || undefined))),
  };
  window.__VWLastAgentPickerSelection = selected;
  window.__VWLastCapabilityContextAction = { agentId: agent.id, buildingId, furnitureIndex, actionId: routeTarget.actionId, capabilityTag: routeTarget.capabilityTag, target: routeTarget, actionContext: selected, worldActionId: created.actionId, reservation: created.action?.reservation || null };
  showToast(`${action.icon || '✨'} ${agent.name || agent.id} routing: ${action.label}`, 'success');
  invokeLinkedCapabilityUi(buildingId, furnitureIndex, action, { agent, routeTarget, worldActionId: created.actionId, reservation: created.action?.reservation || null });
  return window.__VWLastCapabilityContextAction;
}

function getLinkedUiPendingKey(context = {}) {
  return [context.agentId || 'agent', context.objectInstanceId || 'object', context.actionId || context.uiActionId || 'action'].join('::');
}

function startLinkedUiDeferredWatcher() {
  if (_linkedUiDeferredTimer) return;
  _linkedUiDeferredTimer = setInterval(processPendingLinkedUiOpens, 500);
}

function stopLinkedUiDeferredWatcherIfIdle() {
  if (_pendingLinkedUiOpens.size || !_linkedUiDeferredTimer) return;
  clearInterval(_linkedUiDeferredTimer);
  _linkedUiDeferredTimer = null;
}

function queueDeferredLinkedUiOpen(record) {
  const key = getLinkedUiPendingKey(record.context);
  _pendingLinkedUiOpens.set(key, record);
  startLinkedUiDeferredWatcher();
  window.__VWLastLinkedUiDeferred = { state: 'queued', key, context: { ...record.context }, policy: record.policy };
  return key;
}

function processPendingLinkedUiOpens() {
  const opened = [];
  for (const [key, record] of [..._pendingLinkedUiOpens.entries()]) {
    if (!isLinkedUiLifecycleReady(record.context)) continue;
    _pendingLinkedUiOpens.delete(key);
    const didOpen = openLinkedUiPanel(record.buildingId, record.furnitureIndex, record.action, record.policy, record.context, record.routeContext, { deferred: true });
    opened.push({ key, opened: didOpen, context: { ...record.context } });
  }
  if (opened.length) window.__VWLastLinkedUiDeferred = { state: 'opened', opened };
  stopLinkedUiDeferredWatcherIfIdle();
  return opened;
}

function ensureLinkedObjectPanel() {
  let panel = document.getElementById('linkedObjectPanel');
  if (panel) return panel;
  panel = document.createElement('div');
  panel.id = 'linkedObjectPanel';
  panel.className = 'linked-object-panel';
  panel.hidden = true;
  panel.innerHTML = `
    <div class="linked-object-panel-header">
      <div>
        <h3 id="linkedObjectPanelTitle">Object Action</h3>
        <p id="linkedObjectPanelSubtitle"></p>
      </div>
      <button id="linkedObjectPanelClose" class="modal-close">✕</button>
    </div>
    <div id="linkedObjectPanelRoute" class="linked-ui-route-status"></div>
    <dl class="linked-object-panel-meta">
      <div><dt>Agent</dt><dd id="linkedObjectPanelAgent">—</dd></div>
      <div><dt>Object</dt><dd id="linkedObjectPanelObject">—</dd></div>
      <div><dt>Action</dt><dd id="linkedObjectPanelAction">—</dd></div>
    </dl>
    <div class="linked-object-panel-actions">
      <button id="linkedObjectPanelApply" class="btn-primary">Apply</button>
      <button id="linkedObjectPanelCancel" class="btn-secondary">Cancel action</button>
      <button id="linkedObjectPanelFail" class="btn-secondary">Mark failed</button>
      <span id="linkedObjectPanelGate" class="linked-ui-save-gate"></span>
    </div>`;
  document.body.appendChild(panel);
  panel.querySelector('#linkedObjectPanelClose')?.addEventListener('click', () => {
    const context = panel.__linkedUiContext;
    panel.hidden = true;
    if (context) finalizeLinkedObjectAction(context, 'cancelled', { reason: 'panel_closed', source: 'linked-object-panel' });
  });
  return panel;
}

function getAgentDocs(agent = {}) {
  const docs = agent?.docs && typeof agent.docs === 'object' ? agent.docs : (agent?._docs && typeof agent._docs === 'object' ? agent._docs : null);
  return docs ? { ...docs } : { reviewSummary: '', maintenanceNotes: '', carePlan: '', lastReviewedAt: null, source: 'missing-docs-stub' };
}

function ensureAgentDocsEditorModal() {
  let modal = document.getElementById('agentDocsEditorModal');
  if (modal) return modal;
  modal = document.createElement('div');
  modal.id = 'agentDocsEditorModal';
  modal.className = 'modal agent-docs-editor-modal';
  modal.style.display = 'none';
  modal.innerHTML = `
    <div class="modal-content agent-docs-editor-content">
      <div class="modal-header">
        <h2 id="agentDocsEditorTitle">🏥 Agent Docs</h2>
        <button class="modal-close" id="agentDocsCancelX">✕</button>
      </div>
      <div class="linked-ui-route-status" id="agentDocsRouteStatus"></div>
      <div class="agent-docs-editor-body">
        <div class="agent-docs-warning" id="agentDocsMissingWarning" hidden>Docs are missing for this agent. Saving will create them through the normal profile save path.</div>
        <label>Name<input id="agentDocsName" maxlength="60"></label>
        <label>Emoji<input id="agentDocsEmoji" maxlength="8"></label>
        <label>Review summary<textarea id="agentDocsSummary" rows="4" maxlength="1200"></textarea></label>
        <label>Maintenance notes<textarea id="agentDocsMaintenance" rows="4" maxlength="1200"></textarea></label>
        <label>Care / follow-up plan<textarea id="agentDocsCarePlan" rows="4" maxlength="1200"></textarea></label>
      </div>
      <div class="modal-actions">
        <button id="agentDocsSave" class="btn-primary">Approve & Save Docs</button>
        <span id="agentDocsGate" class="linked-ui-save-gate"></span>
        <button id="agentDocsCancel" class="btn-secondary">Cancel</button>
        <button id="agentDocsFail" class="btn-secondary">Mark failed</button>
      </div>
    </div>`;
  document.body.appendChild(modal);
  modal.querySelector('#agentDocsCancel')?.addEventListener('click', closeAgentDocsEditor);
  modal.querySelector('#agentDocsCancelX')?.addEventListener('click', closeAgentDocsEditor);
  modal.querySelector('#agentDocsFail')?.addEventListener('click', async () => {
    const context = modal.__linkedUiContext;
    if (context) await finalizeLinkedObjectAction(context, 'failed', { failureReason: 'docs_review_failed', reason: 'agent_docs_editor_failed', source: 'agent-docs-editor' });
    modal.style.display = 'none';
  });
  modal.querySelector('#agentDocsSave')?.addEventListener('click', saveAgentDocsEditor);
  return modal;
}

function openAgentDocsEditor(agentId, linkedUiContext = null) {
  const agent = agentsList.find(a => a.id === agentId);
  if (!agent) {
    showToast('Selected agent docs are unavailable.', 'warning');
    window.__VWLastAgentDocsEditorBlocked = { reason: 'missing_agent', agentId };
    return false;
  }
  const modal = ensureAgentDocsEditorModal();
  const docs = getAgentDocs(agent);
  modal.__linkedUiContext = linkedUiContext ? { ...linkedUiContext } : null;
  modal.__agentId = agent.id;
  modal.querySelector('#agentDocsEditorTitle').textContent = `${agent.emoji || '🤖'} Review / Edit Agent Docs`;
  modal.querySelector('#agentDocsName').value = agent.name || '';
  modal.querySelector('#agentDocsEmoji').value = agent.emoji || '🤖';
  modal.querySelector('#agentDocsSummary').value = docs.reviewSummary || '';
  modal.querySelector('#agentDocsMaintenance').value = docs.maintenanceNotes || '';
  modal.querySelector('#agentDocsCarePlan').value = docs.carePlan || '';
  const missing = docs.source === 'missing-docs-stub';
  const missingWarning = modal.querySelector('#agentDocsMissingWarning');
  if (missingWarning) missingWarning.hidden = !missing;
  modal.dataset.missingDocs = missing ? 'true' : 'false';
  modal.style.display = 'flex';
  updateAgentDocsLifecycleGate();
  window.__VWLastAgentDocsEditorOpen = { opened: true, agentId: agent.id, missingDocs: missing, context: linkedUiContext ? { ...linkedUiContext } : null };
  return true;
}

function updateAgentDocsLifecycleGate() {
  const modal = document.getElementById('agentDocsEditorModal');
  const context = modal?.__linkedUiContext;
  if (!modal || !context) return;
  const ready = isLinkedUiLifecycleReady(context);
  const status = modal.querySelector('#agentDocsRouteStatus');
  const save = modal.querySelector('#agentDocsSave');
  const gate = modal.querySelector('#agentDocsGate');
  if (status) {
    status.dataset.routeState = ready ? 'ready' : 'routing';
    status.textContent = getLinkedUiRouteStatusText(context);
  }
  if (save) save.disabled = !ready;
  if (gate) gate.textContent = ready ? '' : `Save locked until ${context.agentName || 'agent'} reaches required state.`;
  window.__VWLastAgentDocsGate = { ready, context: { ...context } };
}

async function saveAgentDocsEditor() {
  const modal = ensureAgentDocsEditorModal();
  const context = modal.__linkedUiContext;
  if (context && !isLinkedUiLifecycleReady(context)) {
    updateAgentDocsLifecycleGate();
    showToast(`Wait for ${context.agentName || 'the agent'} to ${describeLinkedUiLifecycleRequirement(context.saveRequires)} before saving docs.`, 'warning');
    return;
  }
  const agent = agentsList.find(a => a.id === modal.__agentId);
  if (!agent) return showToast('Selected agent is no longer available.', 'error');
  const docs = {
    reviewSummary: modal.querySelector('#agentDocsSummary')?.value?.trim?.() || '',
    maintenanceNotes: modal.querySelector('#agentDocsMaintenance')?.value?.trim?.() || '',
    carePlan: modal.querySelector('#agentDocsCarePlan')?.value?.trim?.() || '',
    lastReviewedAt: new Date().toISOString(),
    reviewedVia: 'clinic-bed',
  };
  const name = modal.querySelector('#agentDocsName')?.value?.trim?.() || agent.name || agent.id;
  const emoji = modal.querySelector('#agentDocsEmoji')?.value?.trim?.() || agent.emoji || '🤖';
  try {
    await persistAgentProfile(agent, { name, emoji, docs });
    agent.name = name;
    agent.emoji = emoji;
    agent.docs = { ...docs };
    agent._docs = { ...docs };
    refreshAgentCharacter(agent);
    await finalizeLinkedObjectAction(context, 'completed', { reason: 'agent_docs_saved', source: 'agent-docs-editor', docsSaved: true });
    modal.style.display = 'none';
    showToast('Agent docs saved', 'success');
    window.__VWLastAgentDocsSave = { ok: true, agentId: agent.id, docs, context: context ? { ...context } : null };
  } catch (error) {
    await finalizeLinkedObjectAction(context, 'failed', { failureReason: 'agent_docs_profile_save_failed', message: error?.message || 'Could not save docs.', source: 'agent-docs-editor' });
    modal.style.display = 'none';
    showToast('Could not save agent docs', 'error');
    window.__VWLastAgentDocsSave = { ok: false, agentId: agent.id, error: error?.message || 'save failed' };
  }
}

function closeAgentDocsEditor(options = {}) {
  const modal = document.getElementById('agentDocsEditorModal');
  const context = modal?.__linkedUiContext;
  if (modal) modal.style.display = 'none';
  if (!options.skipLinkedActionFinalize && context) finalizeLinkedObjectAction(context, 'cancelled', { reason: options.reason || 'agent_docs_editor_cancelled', source: 'agent-docs-editor' });
}

function updateLinkedObjectPanel(context = {}, policy = {}) {
  const panel = ensureLinkedObjectPanel();
  const ready = isLinkedUiLifecycleReady(context);
  panel.hidden = false;
  panel.dataset.agentId = context.agentId || '';
  panel.dataset.objectInstanceId = context.objectInstanceId || '';
  panel.dataset.actionId = context.actionId || '';
  panel.dataset.uiActionId = context.uiActionId || '';
  panel.dataset.routeState = ready ? 'ready' : 'routing';
  panel.dataset.worldActionId = context.worldActionId || '';
  panel.dataset.topic = context.topic || context.currentTopic || '';
  panel.__linkedUiContext = { ...context };
  panel.querySelector('#linkedObjectPanelTitle').textContent = policy.label || 'Object action';
  panel.querySelector('#linkedObjectPanelSubtitle').textContent = context.topic || context.currentTopic
    ? `${policy.openTiming === 'immediate' ? 'Opened while the agent routes' : 'Opened after the required lifecycle state'} · Topic: ${context.topic || context.currentTopic}`
    : (policy.openTiming === 'immediate' ? 'Opened while the agent routes.' : 'Opened after the required lifecycle state.');
  const route = panel.querySelector('#linkedObjectPanelRoute');
  if (route) {
    route.dataset.routeState = ready ? 'ready' : 'routing';
    route.textContent = getLinkedUiRouteStatusText(context);
  }
  panel.querySelector('#linkedObjectPanelAgent').textContent = context.agentName || context.agentId || '—';
  panel.querySelector('#linkedObjectPanelObject').textContent = context.objectInstanceId || context.objectLabel || '—';
  panel.querySelector('#linkedObjectPanelAction').textContent = context.actionId || context.uiActionId || '—';
  const apply = panel.querySelector('#linkedObjectPanelApply');
  const cancel = panel.querySelector('#linkedObjectPanelCancel');
  const fail = panel.querySelector('#linkedObjectPanelFail');
  const gate = panel.querySelector('#linkedObjectPanelGate');
  if (apply) apply.disabled = !ready && policy.saveRequires !== 'none';
  if (apply) apply.onclick = async () => {
    if (!isLinkedUiLifecycleReady(panel.__linkedUiContext || context)) return updateLinkedObjectPanel(context, policy);
    await finalizeLinkedObjectAction(panel.__linkedUiContext || context, 'completed', { reason: 'linked_object_panel_apply', source: 'linked-object-panel' });
    panel.hidden = true;
  };
  if (cancel) cancel.onclick = async () => {
    await finalizeLinkedObjectAction(panel.__linkedUiContext || context, 'cancelled', { reason: 'cancelled_by_user', source: 'linked-object-panel' });
    panel.hidden = true;
  };
  if (fail) fail.onclick = async () => {
    await finalizeLinkedObjectAction(panel.__linkedUiContext || context, 'failed', { failureReason: 'runtime_error', reason: 'linked_object_panel_failed', source: 'linked-object-panel' });
    panel.hidden = true;
  };
  if (gate) gate.textContent = (!ready && policy.saveRequires !== 'none') ? `Apply locked until ${describeLinkedUiLifecycleRequirement(policy.saveRequires)}.` : '';
  return panel;
}

function openLinkedUiPanel(buildingId, furnitureIndex, action, policy, linkedUiContext, routeContext = {}, { deferred = false } = {}) {
  const building = buildingsMap.get(buildingId);
  const furniture = building?.interior?.furniture?.[furnitureIndex];
  let mesh = findFurnitureMesh(buildingId, furnitureIndex);
  if (!mesh && building) {
    selectBuilding(buildingId);
    enterBuilding(buildingId, linkedUiContext.floor || furniture?.floor || furniture?.buildingFloor || 1);
    setEditMode('buildings');
    mesh = findFurnitureMesh(buildingId, furnitureIndex);
  }
  if (mesh) _selectFurniture(buildingId, furnitureIndex, mesh, { showActions: false });
  const agent = routeContext.agent || agentsList.find(candidate => candidate?.id === linkedUiContext.agentId) || null;
  if (policy.panel === 'appearance-editor') {
    openAgentPanel(agent?.id || linkedUiContext.agentId, { preserveCamera: true });
    openAppearanceEditor(agent?.id || linkedUiContext.agentId, linkedUiContext);
  } else if (policy.panel === 'object-panel') {
    updateLinkedObjectPanel(linkedUiContext, policy);
  } else if (policy.panel === 'agent-docs-editor') {
    openAgentPanel(agent?.id || linkedUiContext.agentId, { preserveCamera: true });
    openAgentDocsEditor(agent?.id || linkedUiContext.agentId, linkedUiContext);
  } else if (policy.panel === 'agent-panel') {
    openAgentPanel(agent?.id || linkedUiContext.agentId, { preserveCamera: true });
  }
  const result = { opened: true, deferred, policy, context: linkedUiContext, movementVisible: Boolean(agent?._wanderTarget), routeFeedback: getLinkedUiRouteStatusText(linkedUiContext), panelElementId: policy.panel === 'object-panel' ? 'linkedObjectPanel' : (policy.panel === 'appearance-editor' ? 'appearanceEditorModal' : (policy.panel === 'agent-docs-editor' ? 'agentDocsEditorModal' : 'agentPanel')) };
  window.__VWLastLinkedUiOpen = result;
  showToast(`${deferred ? '✅' : '🧭'} ${policy.label || 'Panel'} ${deferred ? 'opened after arrival' : 'opened while routing'}.`, deferred ? 'success' : 'info');
  addActivityLog(`🧭 Linked UI open: ${policy.label || action?.label || 'Object action'} for ${linkedUiContext.objectInstanceId}`);
  return true;
}

function invokeLinkedCapabilityUi(buildingId, furnitureIndex, action, routeContext = {}) {
  const policy = getLinkedUiActionPolicy(action);
  const furniture = buildingsMap.get(buildingId)?.interior?.furniture?.[furnitureIndex];
  const contextTarget = resolveFurnitureContextTarget(buildingId, furnitureIndex) || null;
  if (isHairEditorAction(action) && !contextTargetSupportsHairEdit(contextTarget, furniture, action)) {
    window.__VWLastLinkedUiOpen = { opened: false, reason: 'hair_editor_requires_barber_chair', policy, context: { buildingId, furnitureIndex, catalogKey: contextTarget?.catalogKey || furniture?.type || null } };
    showToast('Hair editor requires a Barber Chair with edit hair capability.', 'warning');
    return false;
  }
  if (isClinicBedDocsAction(action) && !contextTargetSupportsClinicBedDocs(contextTarget, furniture, action)) {
    window.__VWLastLinkedUiOpen = { opened: false, reason: 'agent_docs_requires_clinic_bed', policy, context: { buildingId, furnitureIndex, catalogKey: contextTarget?.catalogKey || furniture?.type || null } };
    showToast('Agent docs editor requires a real Clinic Bed with medical and maintenance tags.', 'warning');
    return false;
  }
  const uiActionId = action?.uiActionId;
  const agent = routeContext.agent || agentsList.find(candidate => candidate?.id === routeContext.agentId) || null;
  const routeTarget = routeContext.routeTarget || null;
  const linkedUiContext = {
    agentId: agent?.id || routeContext.agentId || null,
    agentName: agent?.name || routeContext.agentId || null,
    objectInstanceId: routeTarget?.objectInstanceId || furniture?.id || `${buildingId}-${furniture?.type || 'object'}-${furnitureIndex}`,
    objectId: routeTarget?.objectId || null,
    objectLabel: furniture?.type || routeTarget?.catalogKey || 'object',
    buildingId,
    furnitureIndex,
    floor: routeTarget?.floor || furniture?.floor || furniture?.buildingFloor || 1,
    actionId: routeTarget?.actionId || action?.worldAction?.actionType || action?.apiActionId || null,
    uiActionId,
    worldActionId: routeContext.worldActionId || routeTarget?.worldActionId || null,
    reservationId: routeContext.reservation?.id || routeTarget?.reservationId || null,
    currentTopic: routeContext.topic || routeTarget?.topic || furniture?.boardSession?.topic || action?.worldAction?.params?.topic || null,
    topic: routeContext.topic || routeTarget?.topic || furniture?.boardSession?.topic || action?.worldAction?.params?.topic || null,
    context: routeContext.context || routeTarget?.context || furniture?.boardSession?.context || action?.worldAction?.params?.context || null,
    saveRequires: policy?.saveRequires || 'none',
    openTiming: policy?.openTiming || 'none',
    panel: policy?.panel || null,
  };
  const readyNow = isLinkedUiLifecycleReady(linkedUiContext);
  const canOpenNow = policy?.openTiming === 'immediate'
    || (policy?.openTiming === 'arrival' && readyNow)
    || (policy?.openTiming === 'in-progress' && readyNow);
  window.__VWLastLinkedUiOpen = { opened: false, reason: policy ? 'waiting_for_lifecycle' : 'no_policy', policy, context: linkedUiContext };
  if (!policy) return false;
  if (!canOpenNow) {
    const requirement = describeLinkedUiLifecycleRequirement(policy.openTiming === 'in-progress' ? 'in-progress' : 'arrival');
    const pendingKey = queueDeferredLinkedUiOpen({ buildingId, furnitureIndex, action, policy, context: linkedUiContext, routeContext });
    showToast(`${policy.label || 'Panel'} will open after ${agent?.name || 'the agent'} ${requirement}.`, 'info');
    window.__VWLastLinkedUiOpen = { opened: false, reason: 'queued_until_lifecycle', pendingKey, policy, context: linkedUiContext };
    return false;
  }
  return openLinkedUiPanel(buildingId, furnitureIndex, action, policy, linkedUiContext, routeContext);
}

let _barberChairWorldActionSyncTimer = null;

function resolveAgentForWorldAction(action = {}) {
  const wanted = String(action.agentId || action.agent || '').trim();
  if (!wanted) return null;
  return agentsList.find(agent => agent && (agent.id === wanted || agent.statusKey === wanted)) || null;
}

function parseFurnitureIndexFromObjectInstanceId(objectInstanceId) {
  const text = String(objectInstanceId || '').trim();
  const match = text.match(/[:\-](\d+)$/);
  return match ? Number(match[1]) : null;
}

function routeBarberChairWorldAction(action = {}) {
  const target = action.target || {};
  const buildingId = target.buildingId;
  const building = buildingsMap.get(buildingId);
  const index = Number.isInteger(Number(target.furnitureIndex))
    ? Number(target.furnitureIndex)
    : parseFurnitureIndexFromObjectInstanceId(target.objectInstanceId);
  const chair = building?.interior?.furniture?.[index];
  const catalogKey = normalizeObjectCatalogId(target.catalogId || chair?.catalogId || chair?.objectCatalogId || chair?.type);
  if (!building || !chair || chair.type !== 'barberChair' || !isBarberChairCatalogKey(catalogKey || chair.type)) return false;
  const agent = resolveAgentForWorldAction(action);
  if (!agent) return false;
  const actionType = String(action.actionType || action.actionId || '').trim();
  if (!['appearance.editHair', 'appearance.editAppearance'].includes(actionType)) return false;
  const seatSpot = getFurnitureActionSpot(building, chair, 'seat') || getFurnitureActionSpot(building, chair);
  const approachSpot = getFurnitureActionSpot(building, chair, 'approach-front') || getFurnitureActionSpot(building, chair, 'stylist') || seatSpot;
  const seatFaceAngle = getBarberChairSeatFacingAngle(building, chair, seatSpot) ?? seatSpot?.faceAngle;
  if (!seatSpot || !approachSpot) return false;
  const routeTarget = {
    x: approachSpot.apiX,
    y: approachSpot.apiZ,
    floor: approachSpot.floor,
    targetKind: 'placed-object',
    objectInstanceId: target.objectInstanceId || chair.id || chair.instanceId || `${buildingId}:${index}`,
    objectId: target.objectInstanceId || chair.id || chair.instanceId || `${buildingId}:${index}`,
    catalogKey: 'barberChair',
    buildingId,
    furnitureIndex: index,
    scope: 'indoor',
    interactionSpotId: seatSpot.spotId || 'seat',
    activationSpotId: seatSpot.spotId || 'seat',
    routeSpotId: approachSpot.spotId || 'approach-front',
    actionId: actionType,
    capabilityTag: action.capabilityTag || 'appearance.customize',
    routeOwner: 'main3d.js#setAgentTarget -> dynamic-interior-routing.js',
    worldActionId: action.id || null,
    reservationId: action.reservation?.id || null,
  };
  const alreadyRouting = agent._wanderTarget?.objectInstanceId === routeTarget.objectInstanceId && agent._wanderTarget?.actionId === actionType;
  const alreadyUsing = agent._idleActivity?.worldActionId === action.id || (
    String(agent._idleActivity?.kind || '').startsWith('barber-chair-') &&
    agent._idleActivity?.objectInstanceId === routeTarget.objectInstanceId &&
    agent._idleActivity?.action === actionType
  );
  if (alreadyUsing && alreadyRouting) return true;
  if (!alreadyRouting) {
    const routeAdmission = setAgentTargetForExplicitObjectAction(agent, routeTarget, building, approachSpot.floor, {
      owner: 'world-action',
      sourceFamily: 'world-action-sync',
      sourceFunction: 'routeBarberChairWorldAction',
      actionId: actionType,
    worldActionId: action.id || null,
    reservationId: action.reservation?.id || null,
    furnitureIndex: index,
      objectType: chair.type,
      spotId: seatSpot.spotId || 'seat',
    });
    if (routeAdmission?.accepted === false) {
      window.__VWLastBarberChairWorldActionSync = { ok: false, reason: 'route_admission_rejected', actionId: action.id || null, agentId: agent.id, routeAdmission };
      return false;
    }
  }
  chair.reservation = { agentId: agent.id, actionId: actionType, spotId: seatSpot.spotId || 'seat', worldActionId: action.id || null, reservationId: action.reservation?.id || null, status: 'held' };
  chair.activeUse = { state: 'reserved', mode: actionType === 'appearance.editHair' ? 'hair' : 'appearance', actionId: actionType, agentId: agent.id || null, worldActionId: action.id || null, serviceSpotId: approachSpot.spotId || null };
  chair.serviceState = { ...(chair.serviceState || {}), customer: agent.id || null, stylist: null, mode: actionType === 'appearance.editHair' ? 'hair' : 'appearance' };
  agent._idleActivity = {
    kind: actionType === 'appearance.editHair' ? 'barber-chair-hair' : 'barber-chair-appearance',
    phase: 'approach',
    approachStartedAt: performance.now(),
    buildingId,
    furnitureIndex: index,
    spotId: seatSpot.spotId || 'seat',
    interactionSpotId: seatSpot.spotId || 'seat',
    serviceSpotId: approachSpot.spotId || 'approach-front',
    stayMs: actionType === 'appearance.editHair' ? 15000 : 17000,
    faceAngle: seatFaceAngle,
    dockTarget: { x: seatSpot.apiX, y: seatSpot.apiZ },
    routeApproachTarget: { x: approachSpot.apiX, y: approachSpot.apiZ, floor: approachSpot.floor, spotId: approachSpot.spotId || 'approach-front' },
    dockSnapRadius: 12,
    furnitureType: 'barberChair',
    barberRole: 'customer',
    action: actionType,
    actionId: actionType,
    objectInstanceId: routeTarget.objectInstanceId,
    routeMetadata: routeTarget,
    worldActionId: action.id || null,
    reservationId: action.reservation?.id || null,
    animationId: 'sit',
    stationary: true,
    carryable: false,
    temporary: false,
  };
  window.__VWLastBarberChairWorldActionSync = { ok: true, actionId: action.id || null, agentId: agent.id, routeTarget, seat: { x: seatSpot.apiX, y: seatSpot.apiZ }, approach: { x: approachSpot.apiX, y: approachSpot.apiZ } };
  return true;
}

async function syncActiveBarberChairWorldActions() {
  try {
    const response = await fetch('/api/world-actions/active');
    if (!response.ok) return false;
    const actions = await response.json();
    if (!Array.isArray(actions)) return false;
    let routed = 0;
    for (const action of actions) {
      const status = String(action?.status || '').toLowerCase();
      if (!['requested', 'created', 'reserved', 'route_pending', 'routing'].includes(status)) continue;
      if (routeBarberChairWorldAction(action)) routed++;
    }
    if (routed) window.__VWLastBarberChairWorldActionSync = { ...(window.__VWLastBarberChairWorldActionSync || {}), routed, checkedAt: new Date().toISOString() };
    return routed > 0;
  } catch (error) {
    window.__VWLastBarberChairWorldActionSync = { ok: false, error: error?.message || String(error) };
    return false;
  }
}

function startBarberChairWorldActionSync() {
  if (_barberChairWorldActionSyncTimer) return;
  _barberChairWorldActionSyncTimer = setInterval(syncActiveBarberChairWorldActions, 1500);
  syncActiveBarberChairWorldActions();
}

startBarberChairWorldActionSync();
window.__VWSyncActiveBarberChairWorldActions = syncActiveBarberChairWorldActions;

function makeCapabilityContextMenuItem({ buildingId, furnitureIndex, action }) {
  const presentation = getContextMenuCapabilityPresentation(action.worldAction?.capabilityTag);
  const disabled = Boolean(action.disabled);
  return {
    icon: action.icon || presentation.icon,
    label: action.label || presentation.label,
    group: action.group || { id: presentation.groupId, label: presentation.groupLabel, icon: presentation.groupIcon },
    title: disabled
      ? `Unavailable: ${action.disabledReason || 'not available'} · ${presentation.groupLabel}`
      : `${presentation.groupLabel} · ${action.worldAction?.capabilityTag || 'capability action'} · routes through setAgentTarget()`,
    disabled,
    actionId: action.worldAction?.actionType || action.apiActionId || action.uiActionId,
    capabilityTag: action.worldAction?.capabilityTag || null,
    disabledReason: action.disabledReason || null,
    action: async () => routeAgentToCapabilityFurnitureAction(buildingId, furnitureIndex, action),
  };
}

function buildContextMenu(menu, type, targetId) {
  menu.innerHTML = '';
  menu.dataset.type = type;
  menu.dataset.targetId = targetId;
  const contextTarget = (type === 'furniture' || type === 'outdoor-node')
    ? registerActiveContextTarget(_activeContextTarget?.targetId === targetId ? _activeContextTarget : resolveContextTargetFromLegacyArgs(type, targetId))
    : registerActiveContextTarget(null);
  if (contextTarget) {
    menu.dataset.contextTargetId = contextTarget.stableId;
    menu.dataset.objectId = contextTarget.objectId;
    menu.dataset.catalogKey = contextTarget.catalogKey;
    menu.dataset.buildingId = contextTarget.buildingId || '';
    menu.dataset.floor = String(contextTarget.floor || 1);
    menu.dataset.scope = contextTarget.scope?.kind || '';
  } else {
    delete menu.dataset.contextTargetId;
    delete menu.dataset.objectId;
    delete menu.dataset.catalogKey;
    delete menu.dataset.buildingId;
    delete menu.dataset.floor;
    delete menu.dataset.scope;
  }

  if (type === 'building') {
    const b = buildingsMap.get(targetId);
    const isOutsideSpace = isOutsideSpaceBuilding(b);
    const title = document.createElement('div');
    title.style.cssText = 'padding:6px 16px;font-size:11px;font-weight:700;color:var(--accent-gold);border-bottom:1px solid var(--border);margin-bottom:4px';
    title.textContent = b ? `${isOutsideSpace ? '🌳' : '🏢'} ${b.name}` : '🏢 Building';
    menu.appendChild(title);
    const items = [
      ...(isOutsideSpace ? [] : [{ icon: '🚪', label: 'Enter', action: () => enterBuilding(targetId) }]),
      { icon: '✏️', label: 'Edit', action: () => openBuildingEditorForBuilding(targetId) },
      { icon: '📝', label: 'Rename', action: () => window._renameBld(targetId) },
      { icon: '🗑️', label: 'Delete', action: () => window._deleteBld(targetId) },
    ];
    items.forEach(item => {
      const el = document.createElement('div');
      el.className = 'ctx-item';
      el.innerHTML = `${item.icon} ${item.label}`;
      el.addEventListener('click', () => { item.action(); hideContextMenu(); });
      menu.appendChild(el);
    });
  } else if (type === 'agent') {
    const agent = agentsList.find(a => a.id === targetId);
    const title = document.createElement('div');
    title.style.cssText = 'padding:6px 16px;font-size:11px;font-weight:700;color:var(--accent-gold);border-bottom:1px solid var(--border);margin-bottom:4px';
    title.textContent = agent ? `${agent.emoji || '🤖'} ${agent.name}` : '🤖 Agent';
    menu.appendChild(title);
    const items = [
      { icon: '👤', label: 'View Info', action: () => openAgentPanel(targetId) },
      { icon: '🏢', label: 'Assign to Building', action: () => { openAgentPanel(targetId); } },
      { icon: '📊', label: 'Start Meeting With...', action: () => {
        const other = agentsList.find(a => a.id !== targetId);
        if (other) startMeeting([targetId, other.id], 'Quick Sync');
        else showToast('Need at least 2 agents for a meeting', 'error');
      }},
    ];
    items.forEach(item => {
      const el = document.createElement('div');
      el.className = 'ctx-item';
      el.innerHTML = `${item.icon} ${item.label}`;
      el.addEventListener('click', () => { item.action(); hideContextMenu(); });
      menu.appendChild(el);
    });
  } else if (type === 'outdoor-node') {
    const { buildingId, nodeId } = parseOutdoorNodeTargetId(targetId);
    const building = buildingsMap.get(buildingId);
    const node = getOutdoorNodeById(building, nodeId);
    const mesh = findOutdoorNodeMesh(buildingId, node?.id || nodeId);
    if (!contextTarget || !building || !node) { hideContextMenu(); return; }
    const title = document.createElement('div');
    title.style.cssText = 'padding:6px 16px;font-size:11px;font-weight:700;color:var(--accent-gold);border-bottom:1px solid var(--border);margin-bottom:4px';
    title.textContent = `🌳 ${contextTarget.label} · ${contextTarget.catalogKey}`;
    title.title = `Object ${contextTarget.objectId} · building ${contextTarget.buildingId} · floor ${contextTarget.floor}`;
    menu.appendChild(title);
    const nodeIndex = Number.isInteger(Number(mesh?.userData?.outdoorNodeIndex)) ? Number(mesh.userData.outdoorNodeIndex) : undefined;
    if (mesh) _selectOutdoorNode(buildingId, node.id, nodeIndex, mesh);
    const actions = getOutdoorNodeContextActions(building, node);
    if (actions.length === 0) {
      const empty = document.createElement('div');
      empty.className = 'ctx-item';
      empty.style.opacity = '0.58';
      empty.title = 'Unavailable actions are hidden when node roles, occupancy, or targets are missing';
      empty.textContent = 'No available outdoor actions';
      menu.appendChild(empty);
    }
    actions.forEach(item => {
      const el = document.createElement('div');
      el.className = 'ctx-item';
      el.dataset.actionId = item.actionId;
      el.dataset.nodeId = node.id;
      el.title = item.title || '';
      el.innerHTML = `${item.icon} ${item.label}`;
      el.addEventListener('click', () => { item.action(); hideContextMenu(); });
      menu.appendChild(el);
    });
    const deleteEl = document.createElement('div');
    deleteEl.className = 'ctx-item';
    deleteEl.style.color = '#ff8a80';
    deleteEl.innerHTML = '🗑️ Delete outdoor object';
    deleteEl.title = 'Remove this individual park/outdoor node. Auto-generated park trees stay deleted.';
    deleteEl.addEventListener('click', () => { deleteOutdoorNode(buildingId, node.id || nodeId); hideContextMenu(); });
    menu.appendChild(deleteEl);
  } else if (type === 'furniture') {
    renderFurnitureContextRoot(menu, targetId, contextTarget);
  }
}

function getFurnitureContextRecord(targetId, contextTarget = null) {
  const [buildingId, indexText] = String(targetId || '').split(':');
  const furnitureIndex = Number(indexText);
  const building = buildingsMap.get(buildingId);
  const furniture = building?.interior?.furniture?.[furnitureIndex];
  if (!contextTarget || !building || !furniture) return null;
  const mvpAsset = AGENT_LIFE_MVP_VERTICAL_SLICE.getAsset(furniture?.type);
  return { buildingId, furnitureIndex, building, furniture, mvpAsset, title: mvpAsset ? `${mvpAsset.label} · ${contextTarget.catalogKey}` : `🧩 ${contextTarget.label || furniture.type}` };
}

function renderContextMenuShell(menu, { title, subtitle = '', back = null, close = true } = {}) {
  menu.innerHTML = '';
  menu.classList.add('object-context-menu');
  const header = document.createElement('div');
  header.className = 'ctx-header';
  header.innerHTML = `
    ${back ? `<button class="ctx-icon-btn ctx-back" type="button" title="Back">‹</button>` : '<span class="ctx-header-spacer"></span>'}
    <div class="ctx-title-wrap"><div class="ctx-title">${escapeHtml(title || 'Object')}</div>${subtitle ? `<div class="ctx-subtitle">${escapeHtml(subtitle)}</div>` : ''}</div>
    ${close ? `<button class="ctx-icon-btn ctx-close" type="button" title="Close">×</button>` : '<span class="ctx-header-spacer"></span>'}
  `;
  menu.appendChild(header);
  if (back) header.querySelector('.ctx-back')?.addEventListener('click', (event) => { event.stopPropagation(); back(); });
  header.querySelector('.ctx-close')?.addEventListener('click', (event) => {
    event.stopPropagation();
    hideContextMenu();
    if (_selectedFurniture) _deselectFurniture();
    else if (_selectedOutdoorNode) _deselectOutdoorNodeAndHideActions();
  });
  const body = document.createElement('div');
  body.className = 'ctx-body';
  menu.appendChild(body);
  return body;
}

function renderFurnitureContextRoot(menu, targetId, contextTarget) {
  const record = getFurnitureContextRecord(targetId, contextTarget);
  if (!record) { hideContextMenu(); return; }
  menu.dataset.contextView = 'root';
  const body = renderContextMenuShell(menu, { title: record.title, subtitle: 'Choose what you want to do' });
  const interact = document.createElement('button');
  interact.className = 'ctx-card-action';
  interact.innerHTML = '<strong>✨ Interact</strong><span>Use this object with an agent</span>';
  interact.addEventListener('click', (event) => { event.stopPropagation(); renderFurnitureContextInteract(menu, targetId, contextTarget); });
  const edit = document.createElement('button');
  edit.className = 'ctx-card-action';
  edit.innerHTML = '<strong>✏️ Edit object</strong><span>Rotate, delete, or adjust object settings</span>';
  edit.addEventListener('click', (event) => { event.stopPropagation(); renderFurnitureContextEdit(menu, targetId, contextTarget); });
  body.append(interact, edit);
}

