    menuBoard: _buildMenuBoardActionButtons, teachingPodium: _buildTeachingPodiumActionButtons, dresser: _buildDresserActionButtons, wardrobe: _buildWardrobeActionButtons,
    nightstand: _buildNightstandActionButtons, sideTable: _buildSideTableActionButtons, tvStand: _buildTvStandActionButtons, clothingRack: _buildClothingRackActionButtons,
    displayMannequin: _buildDisplayMannequinActionButtons, accessoryDisplayStand: _buildAccessoryDisplayStandActionButtons, displayCase: _buildDisplayCaseActionButtons,
    shopShelf: _buildShopShelfActionButtons, pantryShelf: _buildPantryShelfActionButtons, standingDesk: _buildStandingDeskActionButtons, draftingTable: _buildDraftingTableActionButtons,
    treadmill: _buildTreadmillActionButtons, trainingMat: _buildTrainingMatActionButtons, dumbbellRack: _buildDumbbellRackActionButtons, gymBench: _buildGymBenchActionButtons,
    outdoorExerciseStation: _buildOutdoorExerciseStationActionButtons, playgroundSlide: _buildPlaygroundSlideActionButtons, playgroundSwing: _buildPlaygroundSwingActionButtons,
