function renderFurnitureContextInteract(menu, targetId, contextTarget) {
  const record = getFurnitureContextRecord(targetId, contextTarget);
  if (!record) { hideContextMenu(); return; }
  const { buildingId, furnitureIndex, building, furniture } = record;
  menu.dataset.contextView = 'interact';
  const mesh = findFurnitureMesh(buildingId, furnitureIndex);
  if (mesh) _selectFurniture(buildingId, furnitureIndex, mesh, { showActions: false });
  document.getElementById('furnitureActionBar')?.style && (document.getElementById('furnitureActionBar').style.display = 'none');
  const body = renderContextMenuShell(menu, { title: 'Interact', subtitle: record.title, back: () => renderFurnitureContextRoot(menu, targetId, contextTarget) });
  const inline = getInlineFurnitureActionHtml(buildingId, furnitureIndex, furniture);
  const capabilityActions = resolveCapabilityContextActions(contextTarget, furniture);
  // Capability actions remain registered for verifiers/API compatibility, but this UI intentionally
  // renders only the compact per-object controls with their inline agent dropdown to avoid duplicate
  // "More interactions" rows and the separate agent-picker modal.
  void capabilityActions;
  if (inline) {
    const inlineWrap = document.createElement('div');
    inlineWrap.className = 'ctx-inline-actions';
    inlineWrap.innerHTML = inline;
    body.appendChild(inlineWrap);
  }
  if (!inline) {
    const empty = document.createElement('div');
    empty.className = 'ctx-empty';
    empty.textContent = 'No interactions available for this object yet.';
    body.appendChild(empty);
  }
}

function renderFurnitureContextEdit(menu, targetId, contextTarget) {
  const record = getFurnitureContextRecord(targetId, contextTarget);
  if (!record) { hideContextMenu(); return; }
  const { buildingId, furnitureIndex } = record;
  menu.dataset.contextView = 'edit';
  const mesh = findFurnitureMesh(buildingId, furnitureIndex);
  if (mesh) _selectFurniture(buildingId, furnitureIndex, mesh, { showActions: false });
  document.getElementById('furnitureActionBar')?.style && (document.getElementById('furnitureActionBar').style.display = 'none');
  const body = renderContextMenuShell(menu, { title: 'Edit object', subtitle: record.title, back: () => renderFurnitureContextRoot(menu, targetId, contextTarget) });
  const rotate = document.createElement('button');
  rotate.className = 'ctx-list-action';
  rotate.innerHTML = '<span>🔄</span><strong>Rotate</strong><small>Turn 90° clockwise</small>';
  rotate.addEventListener('click', (event) => { event.stopPropagation(); window._rotateFurniture(1); renderFurnitureContextEdit(menu, targetId, contextTarget); });
  const del = document.createElement('button');
  del.className = 'ctx-list-action danger';
  del.innerHTML = '<span>🗑️</span><strong>Delete object</strong><small>Remove this item from the room</small>';
  del.addEventListener('click', (event) => { event.stopPropagation(); window._deleteFurniture(); hideContextMenu(); });
  body.append(rotate, del);
}

function positionContextMenu(menu, x, y) {
  menu.style.display = 'block';
  const vw = window.innerWidth, vh = window.innerHeight;
  const mw = Math.max(220, menu.offsetWidth || 220);
  const mh = Math.max(120, menu.offsetHeight || 120);
  menu.style.left = Math.max(8, Math.min(x, vw - mw - 8)) + 'px';
  menu.style.top = Math.max(8, Math.min(y, vh - mh - 8)) + 'px';
}

function hideContextMenu() {
  const menu = document.getElementById('contextMenu');
  if (menu) {
    menu.style.display = 'none';
    menu.classList.remove('object-context-menu');
    delete menu.dataset.contextView;
  }
}

// Close context menu on click outside
document.addEventListener('click', (e) => {
  const menu = document.getElementById('contextMenu');
  if (menu && !menu.contains(e.target)) hideContextMenu();
});

