          floor: approach.floor,
          targetKind: 'placed-object',
          objectInstanceId: 'qc-whiteboard-1',
          catalogKey: whiteboardTarget.catalogKey,
          buildingId: tempIndoorId,
          furnitureIndex: 1,
          interactionSpotId: approach.spotId,
          capabilityTag: 'planning.brainstorm',
