      routingOwners: Object.freeze({ moveIntentOwner: 'main3d.js#setAgentTarget(agent, target, building, floor)', interiorPlanner: 'dynamic-interior-routing.js', exteriorPlanner: 'dynamic-exterior-routing.js', noParallelRouterAdded: true }),
      apiRequestShape,
      selectedContext: selected,
      validation: Object.freeze({ valid: validation.valid, errors: Object.freeze(validation.errors || []) }),
      feedback: Object.freeze({ pendingStateStored: true, reservedStateStored: true, errorCode: errorFeedback.code, errorMessage: errorFeedback.message }),
      routeSmoke: Object.freeze(routeSmoke),
      ok: apiRequestShape
