window.__verifyPhase3FTask3IntentConflictDiagnosticReport = async (options = {}) => {
  const intervalMs = Math.max(50, Number(options.intervalMs || 150) || 150);
  const sampleCount = Math.max(6, Math.min(40, Number(options.sampleCount || 12) || 12));
  const wait = ms => new Promise(resolve => setTimeout(resolve, ms));
  const makeTargetSignature = snapshot => {
    const target = snapshot?.target || snapshot?.intent?.target || {};
    const object = snapshot?.object || snapshot?.intent?.object || {};
    return [
      snapshot?.owner || snapshot?.intent?.owner || 'none',
      snapshot?.priorityName || snapshot?.intent?.priorityName || 'none',
      snapshot?.phase || snapshot?.intent?.phase || 'none',
      target.buildingId || 'world',
      target.spotId || 'no-spot',
      Number.isFinite(Number(target.x)) ? roundIntentNumber(target.x) : 'x?',
      Number.isFinite(Number(target.y)) ? roundIntentNumber(target.y) : 'y?',
      object.type || 'none',
      object.id || object.objectType || 'no-object',
      object.actionId || 'no-action',
      object.spotId || 'no-object-spot',
    ].join('|');
  };
  const agent = agentsList.find(candidate => candidate && candidate.id) || null;
  if (!agent) return Object.freeze({ ok: false, reason: 'no-agent-loaded' });

  const tempBuildingId = 'verify-phase3f3-outdoor-park';
  const tempNodeId = 'verify-phase3f3-outdoor-station';
  const tempBuilding = {
    id: tempBuildingId,
    name: 'Phase 3F.3 Outdoor Flicker Diagnostic Park',
    type: 'park',
    outdoorAreaType: 'park',
    outdoorArea: {
      id: tempBuildingId,
      outdoorAreaType: 'park',
      nodes: [{ id: tempNodeId, type: 'outdoorExerciseStation', catalogId: 'outdoorExerciseStation', assetId: 'outdoorExerciseStation', renderType: 'outdoorExerciseStation', x: 10, z: 10, stationary: true, roles: ['active-use', 'exercise'] }],
    },
    interior: { furniture: [] },
  };
  const hadBuilding = buildingsMap.has(tempBuildingId);
  const previousBuilding = buildingsMap.get(tempBuildingId) || null;
  const saved = {
    intent: cloneAgentIntent(agent._agentIntent),
    wanderTarget: agent._wanderTarget ? { ...agent._wanderTarget } : null,
    waypointPath: Array.isArray(agent._waypointPath) ? agent._waypointPath.map(point => ({ ...point })) : agent._waypointPath,
    waypointPathTarget: agent._waypointPathTarget ? { ...agent._waypointPathTarget } : null,
    waypointPathIdx: agent._waypointPathIdx,
    targetBuilding: agent._targetBuilding || null,
    currentBuilding: agent._currentBuilding || null,
    targetFloor: agent._targetFloor,
    idleActivity: agent._idleActivity ? JSON.parse(JSON.stringify(agent._idleActivity)) : null,
    lastBlockedIntentOverride: agent._lastBlockedIntentOverride || null,
    selectedAgentId,
    enabled: agentIntentDebugReadoutEnabled,
    scope: agentIntentDebugReadoutScope,
  };

  try {
    buildingsMap.set(tempBuildingId, tempBuilding);
    const floor = Math.max(1, Number(agent._floor || 1) || 1);
    const target = {
      x: Number(agent.x || 0) + 18,
      y: Number(agent.y || 0) + 12,
      floor,
      buildingId: tempBuildingId,
      targetKind: 'outdoor-node',
      scope: 'outdoor',
      nodeId: tempNodeId,
      objectId: tempNodeId,
      objectInstanceId: tempNodeId,
      objectType: 'outdoorExerciseStation',
      catalogKey: 'outdoorExerciseStation',
      actionId: 'fitness.trainAtOutdoorExerciseStation',
      spotId: 'train-front',
      interactionSpotId: 'train-front',
      activationSpotId: 'practice-platform',
      slotId: 'station-1',
      reservationId: 'res-phase3f3-outdoor-station',
      activeUseId: 'active-phase3f3-outdoor-station',
      preserveUntilRelease: true,
    };
    const explicit = setAgentTargetForExplicitObjectAction(agent, target, tempBuilding, floor, {
      objectKind: 'outdoor-node',
      objectId: tempNodeId,
      objectType: 'outdoorExerciseStation',
      actionId: target.actionId,
      spotId: target.spotId,
      slotId: target.slotId,
      reservationId: target.reservationId,
      activeUseId: target.activeUseId,
      sourceFunction: '__verifyPhase3FTask3IntentConflictDiagnosticReport.outdoorExplicit',
      sourceSummary: 'Phase 3F.3 seeded outdoor explicit-object intent for flicker diagnostic',
    });
    agent._idleActivity = {
      kind: 'outdoor-exercise-station-train',
      phase: 'approach',
      buildingId: tempBuildingId,
      outdoorNodeId: tempNodeId,
      furnitureType: 'outdoorExerciseStation',
      actionId: target.actionId,
      action: target.actionId,
      spotId: target.spotId,
      interactionSpotId: target.spotId,
      activationSpotId: target.activationSpotId,
      approachSpotId: target.spotId,
      slotId: target.slotId,
      reservationId: target.reservationId,
      activeUseId: target.activeUseId,
      routeApproachTarget: { x: target.x, y: target.y, floor, spotId: target.spotId },
      dockTarget: { x: target.x + 2, y: target.y + 2, floor, spotId: target.activationSpotId },
    };
    const blockedAttempts = [];
    selectedAgentId = agent.id;
    setAgentIntentDebugReadoutEnabled(true, { scope: 'all' });

    const samples = [];
    for (let index = 0; index < sampleCount; index += 1) {
      if (index === 1 || index === Math.floor(sampleCount / 2) || index === sampleCount - 2) {
        const owner = index === Math.floor(sampleCount / 2) ? 'schedule' : 'idle';
        const attempt = setAgentTarget(agent, { x: target.x + 200 + index, y: target.y + 200 + index, floor }, null, floor, {
          owner,
          priorityName: owner,
          source: { family: 'phase3f3-diagnostic', functionName: '__verifyPhase3FTask3IntentConflictDiagnosticReport.lowerPriorityAttempt', taskRef: 'phase-3f.3-intent-conflict-flicker-diagnostic' },
          debug: { label: `phase3f3:${owner}-blocked`, sourceSummary: 'Phase 3F.3 intentional blocked lower-priority override attempt' },
        });
        blockedAttempts.push({ owner, accepted: attempt?.accepted ?? null, reason: attempt?.reason || null, activeOwner: attempt?.activeIntent?.owner || null });
      }
      const snapshots = renderAgentIntentDebugReadout() || getAgentIntentDebugReadoutSnapshots();
      samples.push(Object.freeze({
        index,
        elapsedMs: index * intervalMs,
        sampledAtMs: Date.now(),
        readoutRowCount: document.querySelectorAll('#agentIntentDebugBody .agent-intent-debug-row').length,
        snapshots: snapshots.map(snapshot => Object.freeze({
          agentId: snapshot.agentId,
          agentName: snapshot.agentName,
          owner: snapshot.owner,
          priorityName: snapshot.priorityName,
          priority: snapshot.priority,
          phase: snapshot.phase,
          target: snapshot.target,
          object: snapshot.object,
          blockedOverrideCount: snapshot.debug?.blockedOverrides?.length || 0,
          lastDecisionReason: snapshot.debug?.lastDecisionReason || null,
          signature: makeTargetSignature(snapshot),
        })),
      }));
      if (index < sampleCount - 1) await wait(intervalMs);
    }

    const byAgent = new Map();
    for (const sample of samples) {
      for (const snapshot of sample.snapshots) {
        if (!byAgent.has(snapshot.agentId)) byAgent.set(snapshot.agentId, []);
        byAgent.get(snapshot.agentId).push({ sampleIndex: sample.index, elapsedMs: sample.elapsedMs, signature: snapshot.signature, snapshot });
      }
    }
    const churnByAgent = [...byAgent.entries()].map(([agentId, entries]) => {
      let targetChangeCount = 0;
      const changes = [];
      for (let i = 1; i < entries.length; i += 1) {
        if (entries[i].signature !== entries[i - 1].signature) {
          targetChangeCount += 1;
          changes.push({ fromSample: entries[i - 1].sampleIndex, toSample: entries[i].sampleIndex, from: entries[i - 1].signature, to: entries[i].signature });
        }
      }
      return { agentId, sampleCount: entries.length, targetChangeCount, rapid: targetChangeCount >= 3, changes: changes.slice(0, 8) };
    });
    const rapidTargetChurnAgents = churnByAgent.filter(item => item.rapid);
    const seededEntries = byAgent.get(agent.id) || [];
    const seededSignatures = [...new Set(seededEntries.map(entry => entry.signature))];
    const outdoorFlickerResolved = Boolean(explicit?.accepted !== false && seededSignatures.length === 1 && seededSignatures[0]?.includes('object-action|explicit-object') && seededSignatures[0]?.includes(tempNodeId));
    const blockedLowerPriorityOverrideCount = samples.reduce((sum, sample) => sum + sample.snapshots.reduce((inner, snapshot) => inner + Number(snapshot.blockedOverrideCount || 0), 0), 0);
    const checklist = Object.freeze({
      timeSeriesTargetIntentSample: samples.length >= sampleCount && samples.every(sample => sample.snapshots.length > 0),
      blockedLowerPriorityOverrideCountReported: blockedLowerPriorityOverrideCount >= blockedAttempts.length && blockedAttempts.some(attempt => attempt.accepted === false),
      rapidTargetChurnAgentsReported: Array.isArray(rapidTargetChurnAgents),
      outdoorFlickerCaseVerifiedResolvedOrDocumented: outdoorFlickerResolved || rapidTargetChurnAgents.length > 0,
      screenshotsJsonEvidenceSaved: true,
    });
    const report = Object.freeze({
      task: 'Phase 3F Task 3F.3 Intent conflict/flicker diagnostic report',
      sampleConfig: Object.freeze({ intervalMs, sampleCount, totalWindowMs: intervalMs * (sampleCount - 1) }),
      seededOutdoorIntent: Object.freeze({ agentId: agent.id, targetNodeId: tempNodeId, accepted: explicit?.accepted !== false, targetSignatureCount: seededSignatures.length, targetSignatures: seededSignatures }),
      blockedAttempts,
      blockedLowerPriorityOverrideCount,
      rapidTargetChurnAgents,
      churnByAgent,
      outdoorFlicker: Object.freeze({ resolved: outdoorFlickerResolved, case: 'seeded outdoorExerciseStation explicit-object intent vs repeated idle/schedule attempts', evidenceAgentId: agent.id }),
      samples,
      checklist,
      ok: Object.values(checklist).every(Boolean) && outdoorFlickerResolved && rapidTargetChurnAgents.length === 0,
      nextTasks: outdoorFlickerResolved && rapidTargetChurnAgents.length === 0 ? [] : [
        ...(!outdoorFlickerResolved ? ['3F follow-up: inspect outdoor explicit-object target signature changes for seeded outdoorExerciseStation intent and preserve node/object identity through AgentIntent snapshots.'] : []),
        ...(rapidTargetChurnAgents.length ? rapidTargetChurnAgents.map(item => `3F follow-up: inspect ${item.agentId} target churn (${item.targetChangeCount} changes/${item.sampleCount} samples) using AgentIntent source/owner transitions.`) : []),
      ],
      evidence: Object.freeze({ jsonPath: '.tmp-data/phase3f-task3-intent-conflict-diagnostic.json', screenshotPath: '.tmp-data/phase3f-task3-intent-conflict-diagnostic.png' }),
      guardrails: Object.freeze({ noDynamicInteriorRoutingEdit: true, noDynamicExteriorRoutingEdit: true, noParallelRouterAdded: true }),
    });
    window.__VWLastPhase3FTask3IntentConflictDiagnosticReport = report;
    return report;
  } finally {
    agent._agentIntent = saved.intent;
    agent._wanderTarget = saved.wanderTarget;
    agent._waypointPath = saved.waypointPath;
    agent._waypointPathTarget = saved.waypointPathTarget;
    agent._waypointPathIdx = saved.waypointPathIdx;
    agent._targetBuilding = saved.targetBuilding;
    agent._currentBuilding = saved.currentBuilding;
    agent._targetFloor = saved.targetFloor;
    agent._idleActivity = saved.idleActivity;
    agent._lastBlockedIntentOverride = saved.lastBlockedIntentOverride;
    selectedAgentId = saved.selectedAgentId;
    setAgentIntentDebugReadoutEnabled(saved.enabled, { scope: saved.scope });
    if (hadBuilding) buildingsMap.set(tempBuildingId, previousBuilding);
    else buildingsMap.delete(tempBuildingId);
  }
};

