      placedFurniture.lifecycle.routing = { seatSpotId: 'seat-use', approachSpotId: 'approach-front', clearanceSpotId: 'swing-clearance', interaction: 'route-to-safe-swing-approach-through-setAgentTarget-existing-dynamic-routing-only' };
