function getBarberChairOccupancyState(buildingId, index) {
  const building = buildingsMap.get(buildingId);
  const chair = building?.interior?.furniture?.[index];
  if (!building || !chair || chair.type !== 'barberChair') return { customer: null, stylist: null, reservedAgentId: null, mode: 'unavailable', label: 'Unavailable' };
  const seatSpot = getFurnitureActionSpot(building, chair, 'seat') || getFurnitureActionSpot(building, chair);
  const stylistSpot = getFurnitureActionSpot(building, chair, 'approach-front') || getFurnitureActionSpot(building, chair, 'stylist') || seatSpot;
  let customer = null;
  let stylist = null;
  for (const agent of agentsList) {
    if (!agent) continue;
    const activity = agent._idleActivity || null;
    const matches = activity && String(activity.kind || '').startsWith('barber-chair-') && activity.buildingId === buildingId && Number(activity.furnitureIndex) === Number(index);
    const activeBarberIntent = agent._agentIntent?.object?.objectType === 'barberChair' &&
      agent._agentIntent?.object?.buildingId === buildingId && Number(agent._agentIntent?.object?.furnitureIndex) === Number(index) &&
      isAgentIntentActive(agent._agentIntent);
    if (matches && activity.barberRole === 'stylist') stylist = agent;
    else if (matches) customer = agent;
    if (!matches && activeBarberIntent && seatSpot && !customer && Math.hypot((agent.x || 0) - seatSpot.apiX, (agent.y || 0) - seatSpot.apiZ) <= API_TILE * 0.75) customer = agent;
    if (!matches && activeBarberIntent && stylistSpot && !stylist && Math.hypot((agent.x || 0) - stylistSpot.apiX, (agent.y || 0) - stylistSpot.apiZ) <= API_TILE * 0.75) stylist = agent;
  }
  const reservedAgentId = chair.reservation?.agentId || chair.state?.reservation?.agentId || null;
  const mode = chair.activeUse?.mode || 'open-chair';
  const label = customer
    ? `Customer: ${customer.name || customer.id}${stylist ? ` • Stylist: ${stylist.name || stylist.id}` : ''}`
    : (reservedAgentId ? `Reserved for ${reservedAgentId}` : `Open service chair, ${mode}`);
  return { customer, stylist, reservedAgentId, mode, label };
}

function _buildBarberChairActionButtons(buildingId, index) {
  const state = getBarberChairOccupancyState(buildingId, index);
  const hasCustomerAssignment = Boolean(state.customer || state.reservedAgentId);
  const stateColor = state.customer || state.stylist || state.reservedAgentId ? '#ffca28' : '#fca5a5';
  const pickerId = `barberChairAgentSelect-${buildingId}-${index}`.replace(/[^a-zA-Z0-9_-]/g, '-');
  const agentOptions = (agentsList || []).map(agent => {
    if (!agent) return '';
    const busy = getAgentBusyReason(agent) || (agent._idleActivity && String(agent._idleActivity.kind || '').startsWith('barber-chair-') ? 'Already using a barber chair' : null);
    return `<option value="${escapeAttr(agent.id || '')}"${busy ? ' disabled' : ''}>${escapeHtml(agent.emoji || '🤖')} ${escapeHtml(agent.name || agent.id || 'Agent')}${busy ? ` — ${escapeHtml(busy)}` : ''}</option>`;
  }).join('');
  return `
    <span style="padding:4px 10px;border:1px solid rgba(248,113,113,0.58);border-radius:4px;color:${stateColor};background:rgba(127,29,29,0.24)" title="Barber chair occupancy/reservation; stationary persistent, non-carryable salon service furniture">💈 ${state.label}</span>
    <label style="display:inline-flex;align-items:center;gap:6px;padding:4px 8px;border:1px solid rgba(248,113,113,0.35);border-radius:4px;background:rgba(15,23,42,0.45);color:#fecaca" title="Choose exactly which loaded agent to route through AgentIntent/ObjectUse reservation handoff">Agent <select id="${pickerId}" data-barber-chair-agent-picker="true" style="max-width:160px;background:#111827;color:#fff;border:1px solid #7f1d1d;border-radius:4px;padding:3px 6px">${agentOptions || '<option value="">No agents</option>'}</select></label>
    <button onclick="window._useBarberChairFurniture('hair', document.getElementById('${pickerId}')?.value)" style="padding:4px 12px;background:rgba(185,28,28,0.34);border:1px solid #f87171;color:#fff;border-radius:4px;cursor:pointer" title="Route the chosen agent to the clear approach-front point, reserve the barber-chair seat, then dock into the seated edit-hair loop">💇 Edit Hair</button>
    <button onclick="window._useBarberChairFurniture('appearance', document.getElementById('${pickerId}')?.value)" style="padding:4px 12px;background:rgba(219,39,119,0.30);border:1px solid #f472b6;color:#fff;border-radius:4px;cursor:pointer" title="Route the chosen agent to the clear approach-front point for appearance customization">✨ Edit Appearance</button>
    ${hasCustomerAssignment ? `<button onclick="window._cancelBarberChairCustomer('${escapeAttr(buildingId)}', ${Number(index) || 0})" style="padding:4px 12px;background:rgba(75,85,99,0.42);border:1px solid #d1d5db;color:#fff;border-radius:4px;cursor:pointer" title="Manually cancel the current barber-chair customer, release local assignment, and cancel any active world-action reservation so refresh will not send them back">✖ Cancel Customer</button>` : ''}
  `;
}

async function cancelActiveBarberChairWorldActions({ buildingId, index, chair, agentId = null, actionId = null } = {}) {
  try {
    const response = await fetch('/api/world-actions/active');
    if (!response.ok) return { ok: false, reason: `active_fetch_${response.status}`, cancelled: 0 };
    const actions = await response.json().catch(() => []);
    if (!Array.isArray(actions)) return { ok: false, reason: 'active_not_array', cancelled: 0 };
    const objectIds = new Set([chair?.id, chair?.instanceId, `${buildingId}:${index}`, `${buildingId}-${chair?.type || 'barberChair'}-${index}`].filter(Boolean).map(String));
    let cancelled = 0;
    for (const action of actions) {
      const target = action?.target || {};
      const targetIndex = Number.isInteger(Number(target.furnitureIndex)) ? Number(target.furnitureIndex) : parseFurnitureIndexFromObjectInstanceId(target.objectInstanceId);
      const targetObjectId = target.objectInstanceId || target.objectId || null;
      const matchesObject = target.buildingId === buildingId && (Number(targetIndex) === Number(index) || (targetObjectId && objectIds.has(String(targetObjectId))));
      const matchesAgent = !agentId || action.agentId === agentId || action.agent === agentId || action.reservation?.agentId === agentId;
      const matchesAction = !actionId || action.actionType === actionId || action.actionId === actionId || String(action.actionType || '').startsWith('appearance.');
      if (!matchesObject || !matchesAgent || !matchesAction) continue;
      const cancelResponse = await fetch(`/api/world-actions/${encodeURIComponent(action.id)}/cancel`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ actor: 'main3d.js#cancelBarberChairCustomer', source: 'manual-barber-chair-cancel', result: { reason: 'manual_customer_cancel', buildingId, furnitureIndex: index, agentId } }),
      });
      if (cancelResponse.ok) cancelled += 1;
    }
    return { ok: true, cancelled };
  } catch (error) {
    return { ok: false, reason: error?.message || String(error), cancelled: 0 };
  }
}

window._cancelBarberChairCustomer = async (buildingId, index) => {
  const building = buildingsMap.get(buildingId);
  const chair = building?.interior?.furniture?.[index];
  if (!building || !chair || chair.type !== 'barberChair') return { ok: false, reason: 'barber-chair-not-found' };
  const occupancy = getBarberChairOccupancyState(buildingId, index);
  const agentId = occupancy.customer?.id || chair.reservation?.agentId || chair.activeUse?.agentId || chair.serviceState?.customer || null;
  const actionId = chair.activeUse?.actionId || chair.reservation?.actionId || BARBER_CHAIR_HAIR_ACTION_TYPE;
  const context = {
    agentId,
    actionId,
    objectInstanceId: chair.id || chair.instanceId || `${buildingId}:${index}`,
    objectId: chair.id || chair.instanceId || `${buildingId}:${index}`,
    objectLabel: 'barberChair',
    buildingId,
    furnitureIndex: index,
    worldActionId: chair.activeUse?.worldActionId || chair.reservation?.worldActionId || null,
    reservationId: chair.reservation?.reservationId || null,
    source: 'manual-barber-chair-cancel',
  };
  const localReleased = markLinkedFurnitureActionTerminal(context, 'cancelled', 'manual_customer_cancel');
  for (const [key, record] of [..._pendingLinkedUiOpens.entries()]) {
    if (record?.context?.buildingId === buildingId && Number(record?.context?.furnitureIndex) === Number(index) && (!agentId || record?.context?.agentId === agentId)) _pendingLinkedUiOpens.delete(key);
  }
  stopLinkedUiDeferredWatcherIfIdle();
  if (_appearanceEditorState?.linkedUiContext?.buildingId === buildingId && Number(_appearanceEditorState.linkedUiContext.furnitureIndex) === Number(index)) closeAppearanceEditor({ skipLinkedActionFinalize: true });
  const worldActions = await cancelActiveBarberChairWorldActions({ buildingId, index, chair, agentId, actionId });
  _showFurnitureActions(buildingId, index);
  showToast(`💈 Barber chair customer cancelled${worldActions.cancelled ? `; ${worldActions.cancelled} pending action cancelled` : ''}`, 'success');
  window.__VWLastBarberChairCustomerCancel = { ok: true, buildingId, index, agentId, actionId, localReleased, worldActions };
  return window.__VWLastBarberChairCustomerCancel;
};

function getSalonMirrorStationState(buildingId, index) {
  const building = buildingsMap.get(buildingId);
  const station = building?.interior?.furniture?.[index];
  if (!building || !station || station.type !== 'salonMirrorStation') return { active: null, service: null, reservedAgentId: null, mode: 'unavailable', label: 'Unavailable' };
  let active = null;
  let service = null;
  for (const agent of agentsList) {
    if (!agent) continue;
    const activity = agent._idleActivity || null;
    const matches = activity && String(activity.kind || '').startsWith('salon-mirror-station-') && activity.buildingId === buildingId && Number(activity.furnitureIndex) === Number(index);
    if (!matches) continue;
    if (activity.mirrorRole === 'stylist' || activity.kind === 'salon-mirror-station-service') service = agent;
    else active = agent;
  }
  const reservedAgentId = station.reservation?.agentId || station.state?.reservation?.agentId || null;
  const mode = station.activeUse?.mode || 'mirror-ready';
  const label = active
    ? `${active.name || active.id} previewing${service ? ` • Stylist: ${service.name || service.id}` : ''}`
    : (service ? `Stylist: ${service.name || service.id}` : (reservedAgentId ? `Reserved for ${reservedAgentId}` : `Ready, ${mode}`));
  return { active, service, reservedAgentId, mode, label };
}

function _buildSalonMirrorStationActionButtons(buildingId, index) {
  const state = getSalonMirrorStationState(buildingId, index);
  const stateColor = state.active || state.service || state.reservedAgentId ? '#ffca28' : '#bfdbfe';
  return `
    <span style="padding:4px 10px;border:1px solid rgba(125,211,252,0.58);border-radius:4px;color:${stateColor};background:rgba(30,41,59,0.32)" title="Salon mirror station state; stationary persistent, non-carryable, non-temporary appearance service furniture">🪞 ${state.label}</span>
    <button onclick="window._useSalonMirrorStationFurniture('inspect')" style="padding:4px 12px;background:rgba(14,165,233,0.30);border:1px solid #7dd3fc;color:#fff;border-radius:4px;cursor:pointer" title="Route an idle agent to the front mirror inspect waypoint for a stand/turn preview pose">🪞 Inspect Mirror</button>
    <button onclick="window._useSalonMirrorStationFurniture('preview')" style="padding:4px 12px;background:rgba(219,39,119,0.28);border:1px solid #f472b6;color:#fff;border-radius:4px;cursor:pointer" title="Preview appearance at the mirror station without spawning temporary items">✨ Preview Appearance</button>
    <button onclick="window._useSalonMirrorStationFurniture('service')" style="padding:4px 12px;background:rgba(168,85,247,0.28);border:1px solid #c084fc;color:#fff;border-radius:4px;cursor:pointer" title="Optional stylist service pose at the mirror-side service waypoint">🧑‍🎨 Service Pose</button>
  `;
}

function getMirrorState(buildingId, index) {
  const building = buildingsMap.get(buildingId);
  const mirror = building?.interior?.furniture?.[index];
  if (!building || !mirror || mirror.type !== 'mirror') return { active: null, reservedAgentId: null, mode: 'unavailable', label: 'Unavailable' };
  let active = null;
  for (const agent of agentsList) {
    if (!agent) continue;
    const activity = agent._idleActivity || null;
    const matches = activity && String(activity.kind || '').startsWith('mirror-') && activity.buildingId === buildingId && Number(activity.furnitureIndex) === Number(index);
    if (matches) { active = agent; break; }
  }
  const reservedAgentId = mirror.reservation?.agentId || mirror.state?.reservation?.agentId || null;
  const mode = mirror.activeUse?.mode || 'mirror-ready';
  const label = active
    ? `${active.name || active.id} inspecting appearance`
    : (reservedAgentId ? `Reserved for ${reservedAgentId}` : `Ready, ${mode}`);
  return { active, reservedAgentId, mode, label };
}

function _buildMirrorActionButtons(buildingId, index) {
  const state = getMirrorState(buildingId, index);
  const stateColor = state.active || state.reservedAgentId ? '#ffca28' : '#bfdbfe';
  return `
    <span style="padding:4px 10px;border:1px solid rgba(125,211,252,0.58);border-radius:4px;color:${stateColor};background:rgba(30,41,59,0.32)" title="Mirror state; stationary persistent, non-carryable, non-temporary appearance inspection furniture">🪞 ${state.label}</span>
    <button onclick="window._useMirrorFurniture('inspect')" style="padding:4px 12px;background:rgba(14,165,233,0.30);border:1px solid #7dd3fc;color:#fff;border-radius:4px;cursor:pointer" title="Route an idle agent to the front mirror inspect waypoint for a standing inspect/turn pose">🪞 Inspect Mirror</button>
    <button onclick="window._useMirrorFurniture('preview')" style="padding:4px 12px;background:rgba(219,39,119,0.28);border:1px solid #f472b6;color:#fff;border-radius:4px;cursor:pointer" title="Preview appearance at this standalone mirror; no temporary item is spawned">✨ Preview Appearance</button>
  `;
}

function getBedOccupancyState(buildingId, index) {
  const building = buildingsMap.get(buildingId);
  const bed = building?.interior?.furniture?.[index];
  if (!building || !bed || bed.type !== 'bed') return { occupied: false, agent: null, label: 'Available' };
  const sleepSpot = getFurnitureActionSpot(building, bed, 'lie-sleep') || getFurnitureActionSpot(building, bed);
  let best = null;
  let bestDist = Infinity;
  for (const agent of agentsList) {
    if (!agent) continue;
    const activity = agent._idleActivity || null;
    const activityMatches = activity && String(activity.kind || '').startsWith('bed-') &&
      activity.buildingId === buildingId && Number(activity.furnitureIndex) === Number(index);
    const nearSleepSpot = sleepSpot && Math.hypot((agent.x || 0) - sleepSpot.apiX, (agent.y || 0) - sleepSpot.apiZ) <= API_TILE * 1.2;
    if (!activityMatches && !nearSleepSpot) continue;
    const dist = sleepSpot ? Math.hypot((agent.x || 0) - sleepSpot.apiX, (agent.y || 0) - sleepSpot.apiZ) : 0;
    if (dist < bestDist) { best = agent; bestDist = dist; }
  }
  return best
    ? { occupied: true, agent: best, label: `Occupied by ${best.name || best.id}` }
    : { occupied: false, agent: null, label: 'Available' };
}

function _buildBedActionButtons(buildingId, index) {
  const occupancy = getBedOccupancyState(buildingId, index);
  const occColor = occupancy.occupied ? '#ffca28' : '#80cbc4';
  return `
    <span style="padding:4px 10px;border:1px solid rgba(128,203,196,0.5);border-radius:4px;color:${occColor};background:rgba(128,203,196,0.10)" title="Sleep pod occupancy">🧍 ${occupancy.label}</span>
    <button onclick="window._useBedFurniture('sleep')" style="padding:4px 12px;background:rgba(103,58,183,0.3);border:1px solid #9575cd;color:#fff;border-radius:4px;cursor:pointer" title="Send a nearby idle agent to lie down and sleep">💤 Sleep</button>
    <button onclick="window._useBedFurniture('dream')" style="padding:4px 12px;background:rgba(63,81,181,0.3);border:1px solid #7986cb;color:#fff;border-radius:4px;cursor:pointer" title="Start a short dream/rest loop with dream effect">✨ Dream</button>
    <button onclick="window._useBedFurniture('rest')" style="padding:4px 12px;background:rgba(0,150,136,0.3);border:1px solid #4db6ac;color:#fff;border-radius:4px;cursor:pointer" title="Rest at this persistent, non-carryable bed">🛌 Rest</button>
  `;
}

