  agent._lastDrinkDeskRoute = { kind: 'vending', accepted: route?.accepted !== false, reason: route?.reason || null, release, target: { x: target.x, y: target.y, floor: target.floor || workArrival?.floor || 1, buildingId: target.buildingId || targetBuilding?.id || null, furnitureIndex: target.furnitureIndex ?? null, spotId: target.spotId || target.interactionSpotId || null } };
