function getOutdoorCafeTableState(buildingId, index) {
  const building = buildingsMap.get(buildingId);
  const table = building?.interior?.furniture?.[index];
  if (!building || !table || table.type !== 'outdoorCafeTable') return { occupants: [], mode: 'unavailable', label: 'Unavailable' };
  const occupants = agentsList.filter(agent => agent?._idleActivity?.buildingId === buildingId && Number(agent._idleActivity?.furnitureIndex) === Number(index) && String(agent._idleActivity?.kind || '').startsWith('outdoor-cafe-table-'));
  const surfaceItems = Math.max(0, Number(table.tableState?.surfaceItems ?? table.tableState?.temporaryItemSurfaceCount ?? 0));
  const reservedSeatIds = [...getActiveTableSeatReservationSeatIds(table, buildingId, index, 'outdoorCafeTable')].sort();
  const reserved = reservedSeatIds.length ? `Reserved seats: ${reservedSeatIds.join(', ')}` : (table.reservation?.agentId ? `Reserved by ${table.reservation.agentId}` : null);
  const mode = table.activeUse?.mode || 'open-outdoor-cafe-table';
  const occupantNames = occupants.map(agent => agent.name || agent.id).join(', ');
  const label = occupants.length
    ? `${occupants.length}/4 seated: ${occupantNames}`
    : (reserved || `Open outdoor cafe table • ${surfaceItems}/2 tabletop items`);
  return { occupants, mode, label, surfaceItems, reservedAgentId: table.reservation?.agentId || null, reservedSeatIds, capacity: 4, openSeats: Math.max(0, 4 - occupants.length - reservedSeatIds.length) };
}

