function getSupplyCabinetState(buildingId, index) {
  const building = buildingsMap.get(buildingId);
  const cabinet = building?.interior?.furniture?.[index];
  if (!building || !cabinet || cabinet.type !== 'supplyCabinet') return { active: null, reservedAgentId: null, mode: 'unavailable', label: 'Unavailable' };
  let active = null;
  for (const agent of agentsList) {
    const activity = agent?._idleActivity;
    if (!activity || !String(activity.kind || '').startsWith('supply-cabinet-') || activity.buildingId !== buildingId || Number(activity.furnitureIndex) !== Number(index)) continue;
    active = agent;
    break;
  }
  const reservedAgentId = cabinet.reservation?.agentId || cabinet.state?.reservation?.agentId || null;
  const mode = cabinet.supplyCabinetState?.status || cabinet.activeUse?.mode || (active ? 'active' : 'stocked');
  const stockLevel = cabinet.supplyCabinetState?.stockLevel || 'full';
  const label = active
    ? `${active.name || active.id} browsing office supplies`
    : (reservedAgentId ? `Reserved for ${reservedAgentId}` : `Stocked (${stockLevel}), ${mode}`);
  return { active, reservedAgentId, mode, stockLevel, label };
}

