window._rotateFurniture = (dir) => {
  if (!_selectedFurniture) return;
  const { buildingId, index, mesh } = _selectedFurniture;
  const b = buildingsMap.get(buildingId);
  if (!b || !b.interior?.furniture?.[index]) return;
  const before = JSON.parse(JSON.stringify(b.interior.furniture || []));
  const f = b.interior.furniture[index];
  const prevRotation = f.rotation || 0;
  const nextRotation = ((prevRotation + dir * 90) % 360 + 360) % 360;
  const [halfW, halfD] = getFurnitureFootprintHalfSizes(f.type, nextRotation);
  const clamped = clampFurnitureToBuilding(b, f.x, f.z, halfW, halfD);
  if (doesFurnitureIntersectWalls(b, clamped.x, clamped.z, halfW, halfD)) {
    showToast('🚫 Rotation blocked by wall', 'error');
    return;
  }
  f.rotation = nextRotation;
  if (f.surfaceMount?.parentFurnitureIndex != null) {
    const parent = b.interior.furniture[Number(f.surfaceMount.parentFurnitureIndex)];
    f.surfaceMount.relativeRotation = normalizeFurnitureRotationDeg(nextRotation - Number(parent?.rotation || 0));
  }
  f.x = clamped.x;
  f.z = clamped.z;
  if (f.type === 'counter') syncMountedFurnitureToCounter(b, index);
  mesh.position.set(f.x, mesh.position.y || 0, f.z);
  alignObjectBottomToY(mesh, getFurnitureBottomY(b, getFurnitureFloor(f), f));
  mesh.rotation.y = (f.rotation * Math.PI) / 180;
  // Update selection helper
  const helper = mesh.getObjectByName('_furnitureSelectHelper');
  if (helper) updateFurnitureSelectionHelper(helper, mesh);
  const after = JSON.parse(JSON.stringify(b.interior.furniture || []));
  pushUndo({ type: 'furniture', buildingId: b.id, before, after });
  syncManualFurnitureColliders(b);
  if (f.type === 'counter') {
    createBuilding3D(b);
    const rebuilt = findFurnitureMesh(b.id, index);
    if (rebuilt) _selectFurniture(b.id, index, rebuilt);
  }
  if (f.type === 'desk') clearAgentWorkSpotForDesk(b.id, index);
  // Save
  persistBuilding(b);
  showToast(`🔄 Rotated to ${f.rotation}°`, 'success');
};

function getFurnitureDeleteIndexSetWithMountedChildren(furniture = [], index) {
  const deleteSet = new Set([index]);
  let changed = true;
  while (changed) {
    changed = false;
    furniture.forEach((item, itemIndex) => {
      const parentIndex = item?.surfaceMount?.parentFurnitureIndex;
      if (deleteSet.has(itemIndex) || parentIndex == null || !deleteSet.has(parentIndex)) return;
      deleteSet.add(itemIndex);
      changed = true;
    });
  }
  return deleteSet;
}

function reindexSurfaceMountParentsAfterFurnitureDelete(furniture = [], deletedIndices = new Set()) {
  furniture.forEach((item) => {
    const parentIndex = item?.surfaceMount?.parentFurnitureIndex;
    if (parentIndex == null) return;
    let shift = 0;
    deletedIndices.forEach(deletedIndex => {
      if (deletedIndex < parentIndex) shift++;
    });
    item.surfaceMount.parentFurnitureIndex = parentIndex - shift;
  });
}

window._deleteFurniture = () => {
  if (!_selectedFurniture) return;
  const { buildingId, index, mesh } = _selectedFurniture;
  const b = buildingsMap.get(buildingId);
  if (!b || !b.interior?.furniture) return;
  ensurePlacedObjectActionTargets(b, b.interior.furniture[index], { collection: 'furniture', index, assetType: b.interior.furniture[index]?.type });
  const deletedFurniture = JSON.parse(JSON.stringify(b.interior.furniture[index] || {}));
  delete b.interior.furniture[index].actionLocations;
  delete b.interior.furniture[index].actionLocationIds;
  const before = JSON.parse(JSON.stringify(b.interior.furniture || []));
  const deleteSet = getFurnitureDeleteIndexSetWithMountedChildren(b.interior.furniture, index);
  const deletedCount = deleteSet.size;
  // Remove from data. Counter-mounted children are owned by the counter and are removed with it.
  b.interior.furniture = b.interior.furniture.filter((_, itemIndex) => !deleteSet.has(itemIndex));
  reindexSurfaceMountParentsAfterFurnitureDelete(b.interior.furniture, deleteSet);
  syncAllCounterMountedFurniture(b);
  ensureBuildingPlacedObjectActionTargets(b);
  const after = JSON.parse(JSON.stringify(b.interior.furniture || []));
  pushUndo({ type: 'furniture', buildingId: b.id, before, after });
  // Remove from 3D
  if (mesh.parent) mesh.parent.remove(mesh);
  createBuilding3D(b);
  syncManualFurnitureColliders(b);
  _deselectFurniture();
  // Save and force server-side reconciliation so active world actions cannot keep ghost targets.
  persistBuilding(b);
  reconcileWorldActionsAfterObjectDeletion(deletedFurniture, b);
  showToast(deletedCount > 1 ? `🗑️ Removed counter and ${deletedCount - 1} mounted object${deletedCount === 2 ? '' : 's'}` : '🗑️ Furniture and action targets removed', 'warning');
};

