  chair.reservation = { agentId: agent.id, actionId, spotId: seatSpot.spotId, status: 'held' };
  chair.activeUse = { state: 'reserved', mode, actionId, serviceSpotId: stylistSpot.spotId || 'approach-front', agentId: agent.id || null };
