window._useWhiteboardFurniture = (mode = 'planning') => {
  if (!_selectedFurniture) return;
  const { buildingId, index } = _selectedFurniture;
  const building = buildingsMap.get(buildingId);
  const board = building?.interior?.furniture?.[index];
  if (!building || !board || board.type !== 'whiteboard') return;
  const state = getWhiteboardState(buildingId, index);
  if (state.active) {
    showToast(`🧠 ${state.label}`, 'warning');
    _showFurnitureActions(buildingId, index);
    return;
  }
  const spot = getFurnitureActionSpot(building, board, 'presenter') || getFurnitureActionSpot(building, board);
  if (!spot) return;
  const sameBuildingAgents = agentsList.filter(agent => {
    if (!agent || isWorkPresenceStatus(agent.status) || agent._atDesk || agent._tagState?.playing) return false;
    if (agent._idleActivity && String(agent._idleActivity.kind || '').startsWith('whiteboard-')) return false;
    const currentBuilding = getMovementInteriorBuildingAt(agent.x, agent.y) || agent._currentBuilding || null;
    return currentBuilding?.id === buildingId || isPointInsideBuildingInterior(building, agent.x, agent.y, -0.15);
  });
  const agent = sameBuildingAgents.sort((a, b) =>
    Math.hypot((a.x || 0) - spot.apiX, (a.y || 0) - spot.apiZ) -
    Math.hypot((b.x || 0) - spot.apiX, (b.y || 0) - spot.apiZ)
  )[0] || agentsList.find(candidate => candidate && candidate.status !== 'working');
  if (!agent) {
    showToast('No idle agent available for whiteboard use', 'warning');
    return;
  }
  const actionId = mode === 'teach' ? 'training.teachAtWhiteboard' : 'planning.brainstorm';
  const actionLabel = mode === 'teach' ? 'teaching at the whiteboard' : 'planning at the whiteboard';
  const standingUse = reserveReadInspectStandingUse(board, { building, furnitureIndex: index, agent, spotId: spot.spotId, actionId, mode, animationId: 'write-teach' });
  if (!standingUse?.ok) {
    showToast('Whiteboard presenter spot is already reserved', 'warning');
    return;
  }
  const routeResult = setAgentTargetForExplicitObjectAction(agent, { x: spot.apiX, y: spot.apiZ, floor: spot.floor }, building, spot.floor);
  if (routeResult?.accepted === false) {
    releaseReadInspectStandingUse(board, { reservationId: standingUse.reservation?.id, activeUseSlotId: standingUse.slotId, spotId: spot.spotId, actionId, mode }, agent, 'intent-rejected');
    showToast('Whiteboard route was blocked by a higher-priority intent', 'warning');
    return;
  }
  board.activeUse = { ...(board.activeUse || {}), state: 'reserved', mode, actionId, agentId: agent.id || null, session: mode === 'teach' ? 'Teaching' : 'Planning' };
  board.boardSession = { mode, active: true, actionId, agentId: agent.id || null };
  agent._idleActivity = {
    kind: `whiteboard-${mode}`,
    phase: 'approach',
    buildingId,
    furnitureIndex: index,
    spotId: spot.spotId,
    stayMs: mode === 'teach' ? 13000 : 11500,
    faceAngle: spot.faceAngle,
    dockTarget: { x: spot.apiX, y: spot.apiZ },
    dockSnapRadius: 6,
    furnitureType: 'whiteboard',
    activationSpotId: spot.spotId,
    approachSpotId: spot.spotId,
    activeUseSlotId: standingUse.slotId,
    reservationId: standingUse.reservation?.id || board.reservation?.id || null,
    capacityKey: standingUse.capacityKey,
    action: actionId,
    actionId,
    animationId: 'write-teach',
    stationary: true,
    carryable: false,
    temporary: false,
  };
  agent._wanderTimer = 150;
  agent._stayTimer = 0;
  showToast(`🧠 ${agent.name || agent.id} is ${actionLabel}`, 'success');
  setTimeout(() => _showFurnitureActions(buildingId, index), 80);
};

