function beginUtilityServiceStandingUse({ object, building, buildingId, index, agent, spot, furnitureType, configOverrides = {} }) {
  const baseConfig = getStandingUseMachineConfig(furnitureType);
  if (!object || !building || !agent || !spot || !baseConfig) return null;
  const config = { ...baseConfig, slotId: spot.spotId || configOverrides.slotId || baseConfig.slotId, ...configOverrides };
  const standingUse = reserveStandingUseMachineForAgent(object, building, index, agent, config, spot);
  return { ...standingUse, config };
}

function applyUtilityServiceStandingUseActivity(agent, standingUse, activity) {
  if (!agent || !standingUse || !activity) return activity;
  const nextActivity = {
    ...activity,
    activationSpotId: activity.activationSpotId || standingUse.slotId || activity.spotId,
    approachSpotId: activity.approachSpotId || standingUse.slotId || activity.spotId,
    activeUseSlotId: standingUse.slotId || activity.spotId,
    reservationId: standingUse.reservation?.id || null,
    capacityKey: standingUse.capacityKey || null,
    actionId: activity.actionId || activity.action,
    animationId: activity.animationId || standingUse.config?.animationId,
    lifecycle: { ...(activity.lifecycle || {}), stationary: true, carryable: false, temporary: false, persistsUntilDeleted: true, standingUse: true, utilityServiceObject: true, releaseOnCompletion: true },
  };
  agent._idleActivity = nextActivity;
  return nextActivity;
}

