window._useSmallCafeTableFurniture = (mode = 'eat') => {
  if (!_selectedFurniture) return;
  const { buildingId, index } = _selectedFurniture;
  const building = buildingsMap.get(buildingId);
  const table = building?.interior?.furniture?.[index];
  if (!building || !table || table.type !== 'smallCafeTable') return;
  const state = getSmallCafeTableState(buildingId, index);
  if (state.occupants.length >= 4 && mode !== 'setdown') {
    showToast(`☕ ${state.label}`, 'warning');
    _showFurnitureActions(buildingId, index);
    return;
  }
  const occupiedSpotIds = new Set([...state.occupants.map(agent => agent._idleActivity?.spotId).filter(Boolean), ...(state.reservedSeatIds || [])]);
  const orderedSeats = mode === 'work'
    ? ['seat-east', 'seat-south', 'seat-west', 'seat-north']
    : (mode === 'talk' ? ['seat-west', 'seat-south', 'seat-east', 'seat-north'] : ['seat-south', 'seat-north', 'seat-east', 'seat-west']);
  const preferredSeatId = mode === 'setdown' ? null : orderedSeats.find(id => !occupiedSpotIds.has(id));
  const spotId = mode === 'setdown' ? 'dropoff-surface' : preferredSeatId;
  const spot = getFurnitureActionSpot(building, table, spotId) || getFurnitureActionSpot(building, table);
  if (!spot) return;
  const sameBuildingAgents = agentsList.filter(agent => {
    if (!agent || isWorkPresenceStatus(agent.status) || agent._atDesk || agent._tagState?.playing) return false;
    if (agent._idleActivity && String(agent._idleActivity.kind || '').startsWith('small-cafe-table-')) return false;
    const currentBuilding = getMovementInteriorBuildingAt(agent.x, agent.y) || agent._currentBuilding || null;
    return currentBuilding?.id === buildingId || isPointInsideBuildingInterior(building, agent.x, agent.y, -0.15);
  });
  const agent = sameBuildingAgents.sort((a, b) =>
    Math.hypot((a.x || 0) - spot.apiX, (a.y || 0) - spot.apiZ) -
    Math.hypot((b.x || 0) - spot.apiX, (b.y || 0) - spot.apiZ)
  )[0] || agentsList.find(candidate => candidate && candidate.status !== 'working');
  if (!agent) {
    showToast('No idle agent available for small cafe table use', 'warning');
    return;
  }
  const actionByMode = {
    eat: 'life.eatDrinkAtSmallCafeTable',
    work: 'life.workAtSmallCafeTable',
    talk: 'life.talkAtSmallCafeTable',
    setdown: 'life.dropOffAtSmallCafeTable',
  };
  const actionId = actionByMode[mode] || actionByMode.eat;
  let reservationResult = null;
  let selectedSeat = null;
  if (mode !== 'setdown') {
    const store = getSmallCafeTableObjectUseSeatStore(table);
    const candidates = getTableSeatCandidates(building, table, index, { actionId }).filter(candidate => !preferredSeatId || candidate.seatId === preferredSeatId || !occupiedSpotIds.has(candidate.seatId));
    reservationResult = chooseAndReserveObjectUseSeat(store, candidates, { agentId: agent.id || agent.name || 'agent', agentPosition: { x: agent.x || 0, z: agent.y || 0 }, occupiedSeatIds: occupiedSpotIds, actionId });
    if (!reservationResult.ok) {
      showToast('No free small cafe table seat available', 'warning');
      _showFurnitureActions(buildingId, index);
      return;
    }
    selectedSeat = reservationResult.seat;
  }
  const reservedSpotId = selectedSeat?.seatId || spot.spotId;
  table.reservation = { id: reservationResult?.reservation?.id || null, agentId: agent.id || agent.name || 'agent', actionId, spotId: reservedSpotId, seatId: selectedSeat?.seatId || null, activationSpotId: selectedSeat?.activationSpotId || reservedSpotId, approachSpotId: selectedSeat?.approachSpotId || reservedSpotId, capacityKey: reservationResult?.reservation?.capacityKey || null, status: 'held' };
  table.activeUse = { state: 'reserved', mode, actionId, agentId: agent.id || null, reservedSeatId: selectedSeat?.seatId || null };
  table.tableState = { ...(table.tableState || {}), seats: 4, acceptsTemporary: ['Coffee Drink', 'Heated Snack', 'Microwave Food', 'Popcorn', 'Pizza Slice', 'Sandwich'], lastAction: actionId };
  setAgentTargetForExplicitObjectAction(agent, { x: spot.apiX, y: spot.apiZ, floor: spot.floor }, building, spot.floor);
  agent._idleActivity = {
    kind: `small-cafe-table-${mode}`,
    phase: 'approach',
    buildingId,
    furnitureIndex: index,
    stayMs: mode === 'work' ? 16000 : (mode === 'talk' ? 14000 : 11000),
    faceAngle: spot.faceAngle,
    dockTarget: { x: spot.apiX, y: spot.apiZ },
    dockSnapRadius: 7,
    furnitureType: 'smallCafeTable',
    spotId: reservedSpotId,
    seatId: selectedSeat?.seatId || null,
    activationSpotId: selectedSeat?.activationSpotId || reservedSpotId,
    approachSpotId: selectedSeat?.approachSpotId || reservedSpotId,
    reservationId: reservationResult?.reservation?.id || null,
    objectKey: reservationResult?.reservation?.objectKey || null,
    capacityKey: reservationResult?.reservation?.capacityKey || null,
    mode,
    action: actionId,
    animationId: mode === 'work' ? 'sit-work' : (mode === 'talk' ? 'gather-talk' : (mode === 'setdown' ? 'stand-pickup-setdown' : 'sit-eat-drink')),
    lifecycle: { stationary: true, carryable: false, temporary: false, persistsUntilDeleted: true },
  };
  agent._wanderTimer = 150;
  agent._stayTimer = 0;
  persistBuilding(building);
  const labelByMode = { eat: 'eating/drinking at the small cafe table', work: 'working at the small cafe table', talk: 'talking at the small cafe table', setdown: 'setting an item down at the small cafe table' };
  showToast(`☕ ${agent.name || agent.id} is ${labelByMode[mode] || labelByMode.eat}`, 'success');
  setTimeout(() => _showFurnitureActions(buildingId, index), 80);
};

