window._useTrashBinFurniture = (mode = 'dispose') => {
  if (!_selectedFurniture) return;
  const { buildingId, index } = _selectedFurniture;
  const building = buildingsMap.get(buildingId);
  const bin = building?.interior?.furniture?.[index];
  if (!building || !bin || (bin.type !== 'trashBin' && bin.type !== 'outdoorTrashCan')) return;
  const state = getTrashBinState(buildingId, index);
  if (state.active) {
    showToast(`🗑️ ${state.label}`, 'warning');
    _showFurnitureActions(buildingId, index);
    return;
  }
  const spot = getFurnitureActionSpot(building, bin, 'dispose-front') || getFurnitureActionSpot(building, bin);
  if (!spot) return;
  const sameBuildingAgents = agentsList.filter(agent => {
    if (!agent || isWorkPresenceStatus(agent.status) || agent._atDesk || agent._tagState?.playing) return false;
    if (!agentCarriesTemporaryForDisposal(agent)) return false;
    if (agent._idleActivity && (String(agent._idleActivity.kind || '').startsWith('trash-bin-') || String(agent._idleActivity.kind || '').startsWith('outdoor-trash-can-'))) return false;
    const currentBuilding = getMovementInteriorBuildingAt(agent.x, agent.y) || agent._currentBuilding || null;
    return currentBuilding?.id === buildingId || isPointInsideBuildingInterior(building, agent.x, agent.y, -0.15);
  });
  const agent = sameBuildingAgents.sort((a, b) =>
    Math.hypot((a.x || 0) - spot.apiX, (a.y || 0) - spot.apiZ) -
    Math.hypot((b.x || 0) - spot.apiX, (b.y || 0) - spot.apiZ)
  )[0] || agentsList.find(agentCarriesTemporaryForDisposal);
  if (!agent) {
    showToast('No agent is carrying a temporary item to dispose', 'warning');
    return;
  }
  const actionId = 'maintenance.disposeWaste';
  bin.reservation = { agentId: agent.id || agent.name || 'agent', actionId, spotId: spot.spotId, status: 'held' };
  bin.activeUse = { state: 'reserved', mode, actionId, agentId: agent.id || null };
  bin.serviceState = { ...(bin.serviceState || {}), mode, lastAction: 'dispose', disposedCount: Number(bin.serviceState?.disposedCount || bin.state?.disposedCount || 0) };
  setAgentTargetForExplicitObjectAction(agent, { x: spot.apiX, y: spot.apiZ, floor: spot.floor }, building, spot.floor);
  const isOutdoorTrashCan = bin.type === 'outdoorTrashCan';
  agent._idleActivity = {
    kind: isOutdoorTrashCan ? 'outdoor-trash-can-dispose' : 'trash-bin-dispose',
    phase: 'approach',
    buildingId,
    furnitureIndex: index,
    stayMs: 7000,
    faceAngle: spot.faceAngle,
    dockTarget: { x: spot.apiX, y: spot.apiZ },
    dockSnapRadius: 6,
    furnitureType: bin.type,
    spotId: spot.spotId,
    mode,
    action: actionId,
    animationId: 'dispose',
    lifecycle: { stationary: true, carryable: false, temporary: false, persistsUntilDeleted: true, acceptsTemporary: true },
  };
  agent._wanderTimer = 150;
  agent._stayTimer = 0;
  persistBuilding(building);
  showToast(`🗑️ ${agent.name || agent.id} is disposing a temporary item`, 'success');
  setTimeout(() => _showFurnitureActions(buildingId, index), 80);
};

