window._useInteriorDoorFurniture = (mode = 'pass') => {
  if (!_selectedFurniture) return;
  const { buildingId, index } = _selectedFurniture;
  const building = buildingsMap.get(buildingId);
  const door = building?.interior?.furniture?.[index];
  if (!building || !door || door.type !== 'interiorDoor') return;

  if (mode === 'open' || mode === 'close') {
    const open = mode === 'open';
    door.reservation = null;
    door.activeUse = { state: 'idle', mode: open ? 'open' : 'closed', lastAction: open ? 'world.openInteriorDoor' : 'world.closeInteriorDoor' };
    door.doorState = { ...(door.doorState || {}), open, locked: false, lastAction: door.activeUse.lastAction, persistentFurniture: true, approachSpotIds: ['approach-front', 'approach-back'], passThroughSpotId: 'pass-through' };
    persistBuilding(building);
    createBuilding3D(building);
    syncManualFurnitureColliders(building);
    showToast(open ? '🚪 Interior door opened' : '🚪 Interior door closed', 'success');
    setTimeout(() => _showFurnitureActions(buildingId, index), 80);
    return;
  }

  const state = getInteriorDoorState(buildingId, index);
  if (state.active) {
    showToast(`🚪 ${state.label}`, 'warning');
    _showFurnitureActions(buildingId, index);
    return;
  }
  const front = getFurnitureActionSpot(building, door, 'approach-front') || getFurnitureActionSpot(building, door);
  const back = getFurnitureActionSpot(building, door, 'approach-back') || front;
  const pass = getFurnitureActionSpot(building, door, 'pass-through') || front;
  if (!front || !back || !pass) return;
  const sameBuildingAgents = agentsList.filter(agent => {
    if (!agent || isWorkPresenceStatus(agent.status) || agent._atDesk || agent._tagState?.playing) return false;
    if (agent._idleActivity && String(agent._idleActivity.kind || '').startsWith('interior-door-')) return false;
    const currentBuilding = getMovementInteriorBuildingAt(agent.x, agent.y) || agent._currentBuilding || null;
    return currentBuilding?.id === buildingId || isPointInsideBuildingInterior(building, agent.x, agent.y, -0.15);
  });
  const agent = sameBuildingAgents.sort((a, b) =>
    Math.min(Math.hypot((a.x || 0) - front.apiX, (a.y || 0) - front.apiZ), Math.hypot((a.x || 0) - back.apiX, (a.y || 0) - back.apiZ)) -
    Math.min(Math.hypot((b.x || 0) - front.apiX, (b.y || 0) - front.apiZ), Math.hypot((b.x || 0) - back.apiX, (b.y || 0) - back.apiZ))
  )[0] || agentsList.find(candidate => candidate && candidate.status !== 'working');
  if (!agent) {
    showToast('No idle agent available for interior door use', 'warning');
    return;
  }
  const frontDist = Math.hypot((agent.x || 0) - front.apiX, (agent.y || 0) - front.apiZ);
  const backDist = Math.hypot((agent.x || 0) - back.apiX, (agent.y || 0) - back.apiZ);
  const entry = frontDist <= backDist ? front : back;
  const exit = entry === front ? back : front;
  const actionId = 'world.passThroughInteriorDoor';
  const routeWaypoints = [
    { spotId: entry.spotId, x: entry.apiX, y: entry.apiZ, floor: entry.floor, role: 'approach', action: entry.action || 'world.openInteriorDoor' },
    { spotId: pass.spotId, x: pass.apiX, y: pass.apiZ, floor: pass.floor, role: 'pass-through', action: pass.action || 'world.passThroughInteriorDoor' },
    { spotId: exit.spotId, x: exit.apiX, y: exit.apiZ, floor: exit.floor, role: 'approach', action: exit.action || 'world.openInteriorDoor' },
  ];
  door.reservation = { agentId: agent.id || agent.name || 'agent', actionId, spotId: entry.spotId, status: 'held' };
  door.activeUse = { state: 'reserved', mode: 'passing-through', actionId, agentId: agent.id || null };
  door.doorState = { ...(door.doorState || {}), open: true, locked: false, lastAction: actionId, persistentFurniture: true, approachSpotIds: ['approach-front', 'approach-back'], passThroughSpotId: 'pass-through', activeRouteWaypoints: routeWaypoints.map(point => ({ spotId: point.spotId, role: point.role, action: point.action })) };
  setAgentTargetForExplicitObjectAction(agent, { x: routeWaypoints[0].x, y: routeWaypoints[0].y, floor: routeWaypoints[0].floor }, building, routeWaypoints[0].floor);
  agent._idleActivity = {
    kind: 'interior-door-pass-through',
    phase: 'approach',
    buildingId,
    furnitureIndex: index,
    stayMs: 2600,
    faceAngle: entry.faceAngle,
    dockTarget: { x: exit.apiX, y: exit.apiZ },
    dockSnapRadius: 6,
    furnitureType: 'interiorDoor',
    spotId: entry.spotId,
    mode: 'pass-through',
    action: actionId,
    animationId: 'interior-door-pass-through',
    routeWaypoints,
    routeWaypointIndex: 0,
    currentRouteSpotId: routeWaypoints[0].spotId,
    lifecycle: { stationary: true, carryable: false, temporary: false, persistsUntilDeleted: true, transitionBehavior: 'open-step-through-close' },
  };
  agent._wanderTimer = 150;
  agent._stayTimer = 0;
  persistBuilding(building);
  createBuilding3D(building);
  syncManualFurnitureColliders(building);
  showToast(`🚪 ${agent.name || agent.id} is passing through the interior door`, 'success');
  setTimeout(() => _showFurnitureActions(buildingId, index), 80);
};

