window._useKitchenIslandFurniture = (mode = 'prep') => {
  if (!_selectedFurniture) return;
  const { buildingId, index } = _selectedFurniture;
  const building = buildingsMap.get(buildingId);
  const island = building?.interior?.furniture?.[index];
  if (!building || !island || island.type !== 'kitchenIsland') return;
  const state = getKitchenIslandState(buildingId, index);
  if (state.active) {
    showToast(`🍽️ ${state.label}`, 'warning');
    _showFurnitureActions(buildingId, index);
    return;
  }
  const preferred = mode === 'cook' ? ['prep-west', 'prep-north', 'prep-south', 'prep-east'] : (mode === 'eat' ? ['prep-east', 'prep-south', 'prep-north', 'prep-west'] : ['prep-south', 'prep-north', 'prep-east', 'prep-west']);
  const usableSpots = preferred.map(spotId => getFurnitureActionSpot(building, island, spotId)).filter(Boolean);
  const approach = getFurnitureActionSpot(building, island, 'clearance-south') || usableSpots[0] || getFurnitureActionSpot(building, island);
  if (!approach || usableSpots.length === 0) return;
  const sameBuildingAgents = agentsList.filter(agent => {
    if (!agent || isWorkPresenceStatus(agent.status) || agent._atDesk || agent._tagState?.playing) return false;
    if (agent._idleActivity && String(agent._idleActivity.kind || '').startsWith('kitchen-island-')) return false;
    const currentBuilding = getMovementInteriorBuildingAt(agent.x, agent.y) || agent._currentBuilding || null;
    return currentBuilding?.id === buildingId || isPointInsideBuildingInterior(building, agent.x, agent.y, -0.15);
  });
  const agent = sameBuildingAgents.sort((a, b) =>
    Math.hypot((a.x || 0) - approach.apiX, (a.y || 0) - approach.apiZ) -
    Math.hypot((b.x || 0) - approach.apiX, (b.y || 0) - approach.apiZ)
  )[0] || agentsList.find(candidate => candidate && candidate.status !== 'working');
  if (!agent) {
    showToast('No idle agent available for kitchen island use', 'warning');
    return;
  }
  const targetSpot = usableSpots.sort((a, b) =>
    Math.hypot((agent.x || 0) - a.apiX, (agent.y || 0) - a.apiZ) -
    Math.hypot((agent.x || 0) - b.apiX, (agent.y || 0) - b.apiZ)
  )[0] || approach;
  const actionId = mode === 'cook' ? 'life.cookAtKitchenIsland' : (mode === 'eat' ? 'life.eatAtKitchenIsland' : 'life.prepAtKitchenIsland');
  const routeWaypoints = approach.spotId === targetSpot.spotId ? null : [
    { spotId: approach.spotId, x: approach.apiX, y: approach.apiZ, floor: approach.floor, role: 'approach', action: approach.action || 'planning.schedule' },
    { spotId: targetSpot.spotId, x: targetSpot.apiX, y: targetSpot.apiZ, floor: targetSpot.floor, role: 'use', action: actionId },
  ];
  const animationId = mode === 'eat' ? 'order-food-drink' : 'kitchen-island-prep';
  const standingUse = reserveServiceSurfaceStandingUse(island, { building, surfaceId: index, surfaceType: 'kitchenIsland', agent, spotId: targetSpot.spotId, actionId, mode: `use-${mode}`, animationId });
  if (!standingUse?.ok) {
    showToast('Kitchen island side is already reserved', 'warning');
    return;
  }
  island.kitchenIslandState = { ...(island.kitchenIslandState || {}), status: 'reserved', lastAction: actionId, persistentFurniture: true, selectedUseSpotId: targetSpot.spotId, approachSpotId: approach.spotId, reservedSlotIds: [standingUse.slotId] };
  const routeResult = setAgentTargetForExplicitObjectAction(agent, { x: approach.apiX, y: approach.apiZ, floor: approach.floor }, building, approach.floor);
  if (routeResult?.accepted === false) {
    releaseServiceSurfaceStandingUse(island, { reservationId: standingUse.reservation?.id, activeUseSlotId: standingUse.slotId, spotId: targetSpot.spotId, actionId, mode }, agent, 'intent-rejected');
    showToast('Kitchen island route was blocked by a higher-priority intent', 'warning');
    return;
  }
  agent._idleActivity = {
    kind: `kitchen-island-${mode}`,
    phase: 'approach',
    buildingId,
    furnitureIndex: index,
    stayMs: mode === 'cook' ? 15000 : (mode === 'eat' ? 12000 : 13000),
    faceAngle: targetSpot.faceAngle,
    dockTarget: { x: targetSpot.apiX, y: targetSpot.apiZ },
    dockSnapRadius: 6,
    furnitureType: 'kitchenIsland',
    spotId: targetSpot.spotId,
    activationSpotId: targetSpot.spotId,
    approachSpotId: approach.spotId,
    activeUseSlotId: standingUse.slotId,
    reservationId: standingUse.reservation?.id || island.reservation?.id || null,
    capacityKey: standingUse.capacityKey,
    mode,
    action: actionId,
    actionId,
    animationId,
    routeWaypoints,
    routeWaypointIndex: 0,
    currentRouteSpotId: routeWaypoints?.[0]?.spotId || targetSpot.spotId,
    lifecycle: { stationary: true, carryable: false, temporary: false, persistsUntilDeleted: true, standingUse: true, serviceSurface: true, releaseOnCompletion: true },
  };
  agent._wanderTimer = 150;
  agent._stayTimer = 0;
  persistBuilding(building);
  const verb = mode === 'cook' ? 'cooking at' : (mode === 'eat' ? 'eating at' : 'prepping at');
  showToast(`🍽️ ${agent.name || agent.id} is ${verb} the kitchen island`, 'success');
  setTimeout(() => _showFurnitureActions(buildingId, index), 80);
};

