window._useArcadeMachineFurniture = (mode = 'play', selectedAgentId = null) => {
  if (!_selectedFurniture) return;
  const { buildingId, index } = _selectedFurniture;
  const building = buildingsMap.get(buildingId);
  const machine = building?.interior?.furniture?.[index];
  if (!building || !machine || machine.type !== 'arcadeMachine') return;
  reconcileArcadeMachineRuntimeUseState(buildingId, index, machine, 'manual-arcade-retry');
  const state = getArcadeMachineState(buildingId, index);
  if (state.active || state.reservedAgentId) {
    showToast(`🕹️ ${state.label}`, 'warning');
    _showFurnitureActions(buildingId, index);
    return;
  }
  const approachSpot = getFurnitureActionSpot(building, machine, 'approach-front') || getFurnitureActionSpot(building, machine);
  const activationSpot = getFurnitureActionSpot(building, machine, 'play-front') || approachSpot;
  if (!approachSpot || !activationSpot) return;
  const pickerValue = selectedAgentId || document.getElementById('arcadeMachineAgentSelect')?.value || null;
  const assignableAgents = getArcadeMachineAssignableAgents(building);
  const agent = (pickerValue ? (assignableAgents.find(candidate => candidate?.id === pickerValue) || agentsList.find(candidate => candidate?.id === pickerValue) || null) : null) || assignableAgents.sort((a, b) =>
    Math.hypot((a.x || 0) - approachSpot.apiX, (a.y || 0) - approachSpot.apiZ) -
    Math.hypot((b.x || 0) - approachSpot.apiX, (b.y || 0) - approachSpot.apiZ)
  )[0] || null;
  if (!agent) {
    showToast('No idle agent available for arcade machine play', 'warning');
    return;
  }
  const actionId = 'life.playArcade';
  const activeCandidate = getArcadeMachineActiveUseCandidate(building, machine, index, actionId);
  const reservationResult = activeCandidate ? chooseAndReserveObjectUseActiveSlot(getArcadeMachineObjectUseActiveStore(machine), [activeCandidate], {
    agentId: agent.id || agent.name || 'agent',
    agentPosition: { x: agent.x || 0, z: agent.y || 0 },
    actionId,
    reservationId: `manual:${getArcadeMachineObjectKey(buildingId, index)}:${agent.id || agent.name || 'agent'}:${Date.now()}`,
  }) : null;
  if (!reservationResult?.ok) {
    showToast('Arcade machine play spot is already reserved', 'warning');
    return;
  }
  machine.reservation = { id: reservationResult.reservation.id, agentId: agent.id || agent.name || 'agent', actionId, spotId: 'play-front', activationSpotId: 'play-front', approachSpotId: 'approach-front', activeUseSlotId: reservationResult.reservation.slotId || 'player-1', status: 'held', capacityKey: reservationResult.reservation.capacityKey };
  machine.activeUse = { state: 'reserved', mode, actionId, agentId: agent.id || null, interactionSpotId: 'play-front', approachSpotId: 'approach-front' };
  machine.playMode = 'reserved';
  machine.arcadeMachineState = { ...(machine.arcadeMachineState || {}), status: 'reserved', screenMode: 'ready', buttonPulse: false, joystickActive: false, reservedSlotIds: [reservationResult.reservation.slotId || 'player-1'], lastAction: actionId, persistentFurniture: true };
  const routeResult = setAgentTargetForExplicitObjectAction(agent, {
    x: approachSpot.apiX,
    y: approachSpot.apiZ,
    floor: approachSpot.floor,
    targetKind: 'placed-object',
    interactionSpotId: 'play-front',
    approachSpotId: 'approach-front',
    activationSpotId: 'play-front',
    objectInstanceId: machine.id || `${buildingId}-arcadeMachine-${index}`,
    buildingId,
    furnitureIndex: index,
    actionId,
    slotId: reservationResult.reservation.slotId || 'player-1',
    reservationId: reservationResult.reservation.id,
    preserveUntilRelease: true,
    routeOwner: 'main3d.js#setAgentTarget -> dynamic-interior-routing.js',
  }, building, approachSpot.floor, {
    owner: 'manual',
    priorityName: 'manual',
    sourceFunction: '_useArcadeMachineFurniture',
    behaviorSourceKind: 'user',
    behaviorMode: 'user-directed-override',
    behaviorAuthority: 'user',
    objectType: 'arcadeMachine',
    actionId,
    spotId: 'play-front',
    slotId: reservationResult.reservation.slotId || 'player-1',
    reservationId: reservationResult.reservation.id,
    release: { policy: 'on-object-complete', releaseObjectReservation: true, releaseActiveUse: true, allowedBy: AGENT_INTENT_RELEASE_ALLOWED_BY['explicit-object'] },
  });
  if (routeResult?.accepted === false) {
    releaseObjectUseActiveReservation(getArcadeMachineObjectUseActiveStore(machine), { reservationId: reservationResult.reservation.id, agentId: agent.id || agent.name || 'agent', slotId: reservationResult.reservation.slotId || 'player-1', terminalState: 'cancelled', reason: 'intent-rejected' });
    machine.reservation = null;
    machine.activeUse = { state: 'complete', mode: 'attract', lastAgentId: agent.id || null, lastAction: actionId };
    machine.playMode = 'ready';
    showToast('Arcade machine route was blocked by a higher-priority intent', 'warning');
    return;
  }
  agent._idleActivity = {
    kind: 'arcade-machine-play',
    phase: 'approach',
    buildingId,
    furnitureIndex: index,
    stayMs: 14000,
    faceAngle: activationSpot.faceAngle,
    dockTarget: { x: activationSpot.apiX, y: activationSpot.apiZ },
    routeApproachTarget: { x: approachSpot.apiX, y: approachSpot.apiZ, floor: approachSpot.floor, spotId: approachSpot.spotId },
    dockSnapRadius: 7,
    furnitureType: 'arcadeMachine',
    spotId: 'play-front',
    activationSpotId: 'play-front',
    approachSpotId: 'approach-front',
    activeUseSlotId: reservationResult.reservation.slotId || 'player-1',
    reservationId: reservationResult.reservation.id,
    capacityKey: reservationResult.reservation.capacityKey,
    mode,
    action: actionId,
    actionId,
    animationId: 'play-game',
    lifecycle: { stationary: true, carryable: false, temporary: false, persistsUntilDeleted: true, activeUse: true, releaseOnCompletion: true },
  };
  agent._wanderTimer = 150;
  agent._stayTimer = 0;
  persistBuilding(building);
  showToast(`🕹️ ${agent.name || agent.id} is playing the arcade machine`, 'success');
  setTimeout(() => _showFurnitureActions(buildingId, index), 80);
};

window.__verifyArcadeMachineInterruptedAssignmentRelease = () => {
  const building = { id: 'verify-arcade-interrupt-building', x: 10, z: 12, width: 8, depth: 8, rotation: 0, interior: { floors: 1, furniture: [] } };
  const machine = { id: 'verify-arcade-interrupt-machine', type: 'arcadeMachine', x: 4, z: 3, rotation: 0 };
  const agent = { id: 'verify-arcade-interrupt-agent', name: 'Verify Arcade Agent', status: 'idle', x: 120, y: 120, _tagState: {} };
  building.interior.furniture.push(machine);
  const existingBuilding = buildingsMap.get(building.id);
  const previousAgentIndex = agentsList.findIndex(item => item?.id === agent.id);
  const previousAgent = previousAgentIndex >= 0 ? agentsList[previousAgentIndex] : null;
  if (previousAgentIndex >= 0) agentsList.splice(previousAgentIndex, 1);
  buildingsMap.set(building.id, building);
  agentsList.push(agent);
  try {
    const actionId = 'life.playArcade';
    const candidate = getArcadeMachineActiveUseCandidate(building, machine, 0, actionId);
    const reservationResult = chooseAndReserveObjectUseActiveSlot(getArcadeMachineObjectUseActiveStore(machine), [candidate], {
      agentId: agent.id,
      agentPosition: { x: agent.x, z: agent.y },
      actionId,
      reservationId: 'verify-arcade-interrupted-reservation',
    });
    const slotId = reservationResult.reservation?.slotId || 'player-1';
    machine.reservation = { id: reservationResult.reservation.id, agentId: agent.id, actionId, spotId: 'play-front', activationSpotId: 'play-front', approachSpotId: 'approach-front', activeUseSlotId: slotId, status: 'held' };
    machine.activeUse = { state: 'reserved', mode: 'play', actionId, agentId: agent.id, interactionSpotId: 'play-front', activeUseSlotId: slotId };
    machine.playMode = 'reserved';
    machine.arcadeMachineState = { status: 'reserved', reservedSlotIds: [slotId], persistentFurniture: true };
    agent._idleActivity = { kind: 'arcade-machine-play', phase: 'approach', buildingId: building.id, furnitureIndex: 0, furnitureType: 'arcadeMachine', reservationId: reservationResult.reservation.id, activeUseSlotId: slotId, spotId: 'play-front', activationSpotId: 'play-front', approachSpotId: 'approach-front', actionId, action: actionId };
    setAgentTargetForExplicitObjectAction(agent, { x: 100, y: 100, floor: 1, buildingId: building.id, furnitureIndex: 0, objectType: 'arcadeMachine', actionId, spotId: 'play-front', interactionSpotId: 'play-front', slotId, reservationId: reservationResult.reservation.id, preserveUntilRelease: true }, building, 1, { owner: 'manual', priorityName: 'manual', objectType: 'arcadeMachine', actionId, spotId: 'play-front', slotId, reservationId: reservationResult.reservation.id, release: { policy: 'on-object-complete', releaseObjectReservation: true, releaseActiveUse: true, allowedBy: AGENT_INTENT_RELEASE_ALLOWED_BY['explicit-object'] } });
    clearAgentTransientMovement(agent);
    const afterDragState = getArcadeMachineState(building.id, 0);
    const releasedReservationState = getArcadeMachineObjectUseActiveStore(machine).reservations.find(item => item.id === reservationResult.reservation.id)?.state || null;

    getArcadeMachineObjectUseActiveStore(machine).reservations.push({ id: 'verify-arcade-stale-held', agentId: 'missing-agent', slotId: 'player-1', actionId, state: 'held' });
    machine.reservation = { id: 'verify-arcade-stale-held', agentId: 'missing-agent', activeUseSlotId: 'player-1', status: 'held' };
    machine.activeUse = { state: 'reserved', mode: 'play', agentId: 'missing-agent', reservationId: 'verify-arcade-stale-held', activeUseSlotId: 'player-1', interactionSpotId: 'play-front', activeSlots: { 'player-1': { agentId: 'missing-agent', reservationId: 'verify-arcade-stale-held', interactionSpotId: 'play-front' } } };
    const staleReconcile = reconcileArcadeMachineRuntimeUseState(building.id, 0, machine, 'verify-arcade-stale-reconcile');
    const staleReservationState = getArcadeMachineObjectUseActiveStore(machine).reservations.find(item => item.id === 'verify-arcade-stale-held')?.state || null;
    const ok = reservationResult.ok && releasedReservationState === 'released' && !machine.reservation && String(machine.activeUse?.state || '').toLowerCase() === 'idle' && !agent._idleActivity && afterDragState.reservedAgentId === null && staleReconcile.changed && staleReservationState === 'released' && getArcadeMachineState(building.id, 0).reservedAgentId === null;
    return { ok, reservationOk: reservationResult.ok, releasedReservationState, afterDragState, staleReconcile, staleReservationState, finalState: getArcadeMachineState(building.id, 0), idleActivityCleared: !agent._idleActivity };
  } finally {
    const idx = agentsList.findIndex(item => item?.id === agent.id);
    if (idx >= 0) agentsList.splice(idx, 1);
    if (previousAgent) agentsList.splice(previousAgentIndex, 0, previousAgent);
    if (existingBuilding) buildingsMap.set(building.id, existingBuilding);
    else buildingsMap.delete(building.id);
  }
};

